  {'n': '21', 'v': "يَٰٓأَيُّهَا ٱلنَّاسُ ٱعْبُدُوا۟ رَبَّكُمُ ٱلَّذِى خَلَقَكُمْ وَٱلَّذِينَ مِن قَبْلِكُمْ لَعَلَّكُمْ تَتَّقُونَ", 't': "«يا أيُّها الناس» أي أهل مكة «اعبدوا» وحِّدوا «ربَّكم الذي خلقكم» أنشأكم ولم تكونوا شيئاً «و» خلق «الذين من قبلكم لعلكم تتقون» بعبادته عقابَه، ولعل: في الأصل للترجي، وفي كلامه تعالى للتحقيق."},
  {'n': '22', 'v': "ٱلَّذِى جَعَلَ لَكُمُ ٱلْأَرْضَ فِرَٰشًۭا وَٱلسَّمَآءَ بِنَآءًۭ وَأَنزَلَ مِنَ ٱلسَّمَآءِ مَآءًۭ فَأَخْرَجَ بِهِۦ مِنَ ٱلثَّمَرَٰتِ رِزْقًۭا لَّكُمْ ۖ فَلَا تَجْعَلُوا۟ لِلَّهِ أَندَادًۭا وَأَنتُمْ تَعْلَمُونَ", 't': "«الذي جعل» خلق «لكم الأرض فراشا» حال بساطا يفترش لا غاية في الصلابة أو الليونة فلا يمكن الاستقرار عليها «والسماء بناءً» سقفاً «وأنزل من السماء ماءً فأخرج به من» أنواع «الثمرات رزقاً لكم» تأكلونه وتعلفون دوابكم «فلا تجعلوا لله أنداداً» شركاء في العبادة «وأنتم تعلمون» أنه الخالق ولا تخلقون، ولا يكون إلهاً إلا من يخلق."},
  {'n': '23', 'v': "وَإِن كُنتُمْ فِى رَيْبٍۢ مِّمَّا نَزَّلْنَا عَلَىٰ عَبْدِنَا فَأْتُوا۟ بِسُورَةٍۢ مِّن مِّثْلِهِۦ وَٱدْعُوا۟ شُهَدَآءَكُم مِّن دُونِ ٱللَّهِ إِن كُنتُمْ صَٰدِقِينَ", 't': "«وإن كنتم في ريب» شك «مما نزلنا على عبدنا» محمد من القرآن أنه من عند الله «فأتوا بسورة من مثله» أي المنزل ومن للبيان أي هي مثله في البلاغة وحسن النظم والإخبار عن الغيب. والسورة قطعة لها أول وآخر أقلها ثلاث آيات «وادعوا شهداءكم\" آلهتكم التي تعبدونها» من دون الله» أي غيره لتعينكم «إن كنتم صادقين» في أن محمدا قاله من عند نفسه فافعلوا ذلك فإنكم عربيون فصحاء مثله ولما عجزوا عن ذلك قال تعالى:"},
  {'n': '24', 'v': "فَإِن لَّمْ تَفْعَلُوا۟ وَلَن تَفْعَلُوا۟ فَٱتَّقُوا۟ ٱلنَّارَ ٱلَّتِى وَقُودُهَا ٱلنَّاسُ وَٱلْحِجَارَةُ ۖ أُعِدَّتْ لِلْكَٰفِرِينَ", 't': "«فإن لم تفعلوا» ما ذكر لعجزكم «ولن تفعلوا» ذلك أبداً لظهور إعجازه- اعتراض «فاتقوا» بالإيمان بالله وانه ليس من كلام البشر «النارَ التي وقودها الناس» الكفار «والحجارة» كأصنامهم منها، يعني أنها مفرطة الحرارة تتقد بما ذكر، لا كنار الدنيا تتقد بالحطب ونحوه «أعدَّت» هُيئت «للكافرين» يعذَّبون بها، جملة مستأنفة أو حال لازمة."},
  {'n': '25', 'v': "وَبَشِّرِ ٱلَّذِينَ ءَامَنُوا۟ وَعَمِلُوا۟ ٱلصَّٰلِحَٰتِ أَنَّ لَهُمْ جَنَّٰتٍۢ تَجْرِى مِن تَحْتِهَا ٱلْأَنْهَٰرُ ۖ كُلَّمَا رُزِقُوا۟ مِنْهَا مِن ثَمَرَةٍۢ رِّزْقًۭا ۙ قَالُوا۟ هَٰذَا ٱلَّذِى رُزِقْنَا مِن قَبْلُ ۖ وَأُتُوا۟ بِهِۦ مُتَشَٰبِهًۭا ۖ وَلَهُمْ فِيهَآ أَزْوَٰجٌۭ مُّطَهَّرَةٌۭ ۖ وَهُمْ فِيهَا خَٰلِدُونَ", 't': "«وَبَشِّر» أخبر «الذين آمنوا» صَّدقوا بالله «وعملوا الصالحات» من الفروض والنوافل «أن» أي بأن «لهم جناتِ» حدائق ذات أشجار ومساكن «تجري من تحتها» أي تحت أشجارها وقصورها «الأنهار» أي المياه فيها، والنهر الموضع الذي يجري فيه الماء لأن الماء ينهره أي يحفره وإسناد الجري إليه مجاز «كلما رزقوا منها» أطعموا من تلك الجنات. «من ثمرة رزقاً قالوا هذا الذي» أي مثل ما «رزقنا من قبل» أي قبله في الجنة لتشابه ثمارها بقرينة «وأُتوا به» أي جيئوا بالرزق «متشابهاً» يشبه بعضه بعضا لونا ويختلف طعما «ولهم فيها أزواج» من الحور وغيرها «مطهَّرة» من الحيض وكل قذر «وهم فيها خالدون» ماكثون أبداً لا يفنون ولا يخرجون. ونزل رداً لقول اليهود لما ضرب الله المثل بالذباب في قوله: (وإن يسلبهم الذباب شيئاً) والعنكبوت في قوله (كمثل العنكبوت) ما أراد الله بذكر هذه الأشياء؟ الخسيسة فأنزل الله."},
  {'n': '26', 'v': "۞ إِنَّ ٱللَّهَ لَا يَسْتَحْىِۦٓ أَن يَضْرِبَ مَثَلًۭا مَّا بَعُوضَةًۭ فَمَا فَوْقَهَا ۚ فَأَمَّا ٱلَّذِينَ ءَامَنُوا۟ فَيَعْلَمُونَ أَنَّهُ ٱلْحَقُّ مِن رَّبِّهِمْ ۖ وَأَمَّا ٱلَّذِينَ كَفَرُوا۟ فَيَقُولُونَ مَاذَآ أَرَادَ ٱللَّهُ بِهَٰذَا مَثَلًۭا ۘ يُضِلُّ بِهِۦ كَثِيرًۭا وَيَهْدِى بِهِۦ كَثِيرًۭا ۚ وَمَا يُضِلُّ بِهِۦٓ إِلَّا ٱلْفَٰسِقِينَ", 't': "«إن الله لا يستحيي أن يضرب» يجعل «مثلا» مفعول أول «ما» نكرة موصوفة بما بعدها مفعول ثان أيَّ مثل كان أو زائدة لتأكيد الخسة فما بعدها المفعول الثاني «بعوضة» مفرد البعوض وهو صغار البق «فما فوقها» أي أكبر منها أي لا يترك بيانه لما فيه من الحكم «فأما الذين آمنوا فيعلمون أنه» أي المثل «الحق» الثابت الواقع موقعه «من ربِّهم وأما الذين كفروا فيقولون ماذا أراد الله بهذا مثلاً» تمييز أي بهذا المثل، وما استفهام إنكار مبتدأ، وذا بمعنى الذي بصلته خبره أي: أيّ فائدة فيه قال الله تعالى في جوابهم «يضل به» أي بهذا المثل «كثيراً» عن الحق لكفرهم به «ويهدي به كثيراً» من المؤمنين لتصديقهم به «وما يضل به إلا الفاسقين» الخارجين عن طاعته."},
  {'n': '27', 'v': "ٱلَّذِينَ يَنقُضُونَ عَهْدَ ٱللَّهِ مِنۢ بَعْدِ مِيثَٰقِهِۦ وَيَقْطَعُونَ مَآ أَمَرَ ٱللَّهُ بِهِۦٓ أَن يُوصَلَ وَيُفْسِدُونَ فِى ٱلْأَرْضِ ۚ أُو۟لَٰٓئِكَ هُمُ ٱلْخَٰسِرُونَ", 't': "«الذين» نعت «ينقضون عهد الله» ما عهده إليهم في الكتب من الإيمان بمحمد * «من بعد ميثاقه» توكيده عليهم «ويقطعون ما أمر الله به أن يوُصل» من الإيمان بالنبي والرحم وغير ذلك وأن بدل من ضمير به «ويفسدون في الأرض» بالمعاصي والتعويق عن الإيمان «أولئك» الموصوفون بما ذكر «هم الخاسرون» لمصيرهم إلى النار المؤبدة عليهم."},
  {'n': '28', 'v': "كَيْفَ تَكْفُرُونَ بِٱللَّهِ وَكُنتُمْ أَمْوَٰتًۭا فَأَحْيَٰكُمْ ۖ ثُمَّ يُمِيتُكُمْ ثُمَّ يُحْيِيكُمْ ثُمَّ إِلَيْهِ تُرْجَعُونَ", 't': "«كيف تكفرون» يا أهل مكة «بالله و» قد «كنتم أمواتاً» نطفاً في الأصلاب «فأحياكم» في الأرحام والدنيا بنفخ الروح فيكم، والاستفهام للتعجيب من كفرهم مع قيام البرهان أو للتوبيْخ «ثم يميتكم» عند انتهاء آجالكم «ثم يحييكم» بالبعث «ثم إليه ترجعون» تردون بعد البعث فيجازيكم بأعمالكم. وقال دليلا على البعث لما أنكروه."},
  {'n': '29', 'v': "هُوَ ٱلَّذِى خَلَقَ لَكُم مَّا فِى ٱلْأَرْضِ جَمِيعًۭا ثُمَّ ٱسْتَوَىٰٓ إِلَى ٱلسَّمَآءِ فَسَوَّىٰهُنَّ سَبْعَ سَمَٰوَٰتٍۢ ۚ وَهُوَ بِكُلِّ شَىْءٍ عَلِيمٌۭ", 't': "«هو الذي خلق لكم ما في الأرض» أي الأرض وما فيها «جميعاً» لتنتفعوا به وتعتبروا «ثم استوى» بعد خلق الأرض أي قصد «إلى السماء فسواهن» الضمير يرجع إلى السماء لأنها في معنى الجمع الآيلة إليه: أي صيَّرها كما في آية أخرى (فقضاهن) «سبع سماوات وهو بكل شيء عليم» مجملا ومفصلا أفلا تعتبرون أن القادر على خلق ذلك ابتداءً وهو أعظم منكم قادر على إعادتكم."},
  {'n': '30', 'v': "وَإِذْ قَالَ رَبُّكَ لِلْمَلَٰٓئِكَةِ إِنِّى جَاعِلٌۭ فِى ٱلْأَرْضِ خَلِيفَةًۭ ۖ قَالُوٓا۟ أَتَجْعَلُ فِيهَا مَن يُفْسِدُ فِيهَا وَيَسْفِكُ ٱلدِّمَآءَ وَنَحْنُ نُسَبِّحُ بِحَمْدِكَ وَنُقَدِّسُ لَكَ ۖ قَالَ إِنِّىٓ أَعْلَمُ مَا لَا تَعْلَمُونَ", 't': "«و» اذكر يا محمد «إذ قال ربُّك للملائكة إني جاعل في الأرض خليفة» يخلفني في تنفيذ أحكامي فيها وهو آدم «قالوا أتجعل فيها من يفسد فيها» بالمعاصي «ويسفك الدماء» يريقها بالقتل كما فعل بنو الجان وكانوا فيها فلما أفسدوا أرسل الله عليهم الملائكة فطردوهم إلى الجزائر والجبال «ونحن نسبِّح» متلبسين «بحمدك» أي نقول سبحان الله وبحمده «ونقِّدس لك» ننزهك عمالا يليق بك فاللام زائدة والجملة حال أي فنحن أحق بالاستخلاف «قال» تعالى «إني أعلم ما لا تعلمون» من المصلحة في استخلاف آدم، وأن ذريته فيهم المطيع والعاصي فيظهر العدل بينهم فقالوا لن يخلق ربنا خلقاً أكرم عليه منا ولا أعلم لسبقنا له ورؤيتنا ما لم يره فخلق الله تعالى آدم من أديم الأرض أي وجهها، بأن قبض منها قبضة من جميع ألوانها وعجنت بالمياه المختلفة وسوَّاهُ ونفخ فيه الروح فصار حيواناً حسَّاساً بعد أن كان جماداً."},
  {'n': '31', 'v': "وَعَلَّمَ ءَادَمَ ٱلْأَسْمَآءَ كُلَّهَا ثُمَّ عَرَضَهُمْ عَلَى ٱلْمَلَٰٓئِكَةِ فَقَالَ أَنۢبِـُٔونِى بِأَسْمَآءِ هَٰٓؤُلَآءِ إِن كُنتُمْ صَٰدِقِينَ", 't': "«وعلَّم آدم الأسماء» أي أسماء المسميات «كلها» بأن ألقى في قلبه علمها «ثم عرضهم» أي المسميات وفيه تغليب العقلاء «على الملائكة فقال» لهم تبكيتاً «أنبئوني» أخبروني «بأسماء هؤلاء» المسميات «إن كنتم صادقين» في أني لا أخلق أعلم منكم أو أنكم أحق بالخلافة، وجواب الشرط دل عليه ما قبله."},
  {'n': '32', 'v': "قَالُوا۟ سُبْحَٰنَكَ لَا عِلْمَ لَنَآ إِلَّا مَا عَلَّمْتَنَآ ۖ إِنَّكَ أَنتَ ٱلْعَلِيمُ ٱلْحَكِيمُ", 't': "«قالوا سبحانك» تنزيهاً لك عن الاعتراض عليك «لا علم لنا إلا ما علمَّتنا» إياه «إنَّك أنت» تأكيد للكاف «العليم الحكيم» الذي لا يخرج شيء عن علمه وحكمته."},
  {'n': '33', 'v': "قَالَ يَٰٓـَٔادَمُ أَنۢبِئْهُم بِأَسْمَآئِهِمْ ۖ فَلَمَّآ أَنۢبَأَهُم بِأَسْمَآئِهِمْ قَالَ أَلَمْ أَقُل لَّكُمْ إِنِّىٓ أَعْلَمُ غَيْبَ ٱلسَّمَٰوَٰتِ وَٱلْأَرْضِ وَأَعْلَمُ مَا تُبْدُونَ وَمَا كُنتُمْ تَكْتُمُونَ", 't': "«قال» تعالى «يا آدم أنبئهم» أي الملائكة «بأسمائهم» المسميات فسمى كل شيء باسمه وذكر حكمته التي خلق لها «فلما أنبأهم بأسمائهم قال» تعالى لهم موبخاً «ألم أقل لكم إنَّي أعلم غيب السماوات والأرض» ما غاب فيهما «وأعلم ما تبدون» ما تظهرون من قولكم أتجعل فيها الخ «وما كنتم تكتمون» تسرون من قولكم لن يخلق الله أكرم عليه منا ولا أعلم."},
  {'n': '34', 'v': "وَإِذْ قُلْنَا لِلْمَلَٰٓئِكَةِ ٱسْجُدُوا۟ لِءَادَمَ فَسَجَدُوٓا۟ إِلَّآ إِبْلِيسَ أَبَىٰ وَٱسْتَكْبَرَ وَكَانَ مِنَ ٱلْكَٰفِرِينَ", 't': "«و» اذكر «إذ قلنا للملائكة اسجدوا لآدم» سجود تحية بالانحناء «فسجدوا إلا إبليس» هو أبو الجن كان بين الملائكة «أبى» امتنع من السجود «واستكبر» تكبَّر عنه وقال: أنا خير منه «وكان من الكافرين» في علم الله."},
  {'n': '35', 'v': "وَقُلْنَا يَٰٓـَٔادَمُ ٱسْكُنْ أَنتَ وَزَوْجُكَ ٱلْجَنَّةَ وَكُلَا مِنْهَا رَغَدًا حَيْثُ شِئْتُمَا وَلَا تَقْرَبَا هَٰذِهِ ٱلشَّجَرَةَ فَتَكُونَا مِنَ ٱلظَّٰلِمِينَ", 't': "«وقلنا يا آدم اسكن أنت» تأكيد للضمير المستتر ليعطف عليه «وزوجك» حواء بالمد وكان خلقها من ضلعه الأيسر «الجنة وكلا منها» أكلاً «رغداً» واسعا لاحجر فيه «حيث شئتما ولا تقربا هذه الشجرة» بالأكل منها وهى الحنطة أو الكرم أو غيرهما «فتكونا» فتصيرا «من الظالمين» العاصين."},
  {'n': '36', 'v': "فَأَزَلَّهُمَا ٱلشَّيْطَٰنُ عَنْهَا فَأَخْرَجَهُمَا مِمَّا كَانَا فِيهِ ۖ وَقُلْنَا ٱهْبِطُوا۟ بَعْضُكُمْ لِبَعْضٍ عَدُوٌّۭ ۖ وَلَكُمْ فِى ٱلْأَرْضِ مُسْتَقَرٌّۭ وَمَتَٰعٌ إِلَىٰ حِينٍۢ", 't': "«فأزلَّهما الشيطان» إبليس أذهبهما، وفي قراءة ـ فأزالهما ـ نحَّاهما «عنها» أي الجنة بأن قال لهما: هل أدلُّكما على شجرة الخلد وقاسمهما بالله إنه لهما لمن الناصحين فأكلا منها «فأخرجهما مما كانا فيه» من النعيم «وقلنا اهبطوا» إلى الأرض أي أنتما بما اشتملتما عليه من ذريتكما «بعضكم» بعض الذرية «لبعض عدوُّ» من ظلم بعضكم بعضاً «ولكم في الأرض مستقرُّ» موضع قرار «ومتاع» ما تتمتعون به من نباتها «إلى حين» وقت انقضاء آجالكم."},
  {'n': '37', 'v': "فَتَلَقَّىٰٓ ءَادَمُ مِن رَّبِّهِۦ كَلِمَٰتٍۢ فَتَابَ عَلَيْهِ ۚ إِنَّهُۥ هُوَ ٱلتَّوَّابُ ٱلرَّحِيمُ", 't': "«فتلقى آدمُ من ربِّه كلماتٍ» ألهمه إياها وفي قراءة بنصب آدم ورفع كلمات، أي جاءه وهى (ربَّنا ظلمنا أنفسا) الآية فدعا بها «فتاب عليه» قبل توبته «إنه هو التواب» على عباده «الرحيم» بهم."},
  {'n': '38', 'v': "قُلْنَا ٱهْبِطُوا۟ مِنْهَا جَمِيعًۭا ۖ فَإِمَّا يَأْتِيَنَّكُم مِّنِّى هُدًۭى فَمَن تَبِعَ هُدَاىَ فَلَا خَوْفٌ عَلَيْهِمْ وَلَا هُمْ يَحْزَنُونَ", 't': "«قلنا اهبطوا منها» من الجنة «جميعاً» كرره ليعطف عليه «فإما» فيه إدغام نون إن الشرطية في ما الزائدة «يأتينكم مني هدىً» كتاب ورسول «فمن تبع هداي» فآمن بي وعمل بطاعتي «فلا خوف عليهم ولا هم يحزنون» في الآخرة بأن يدخلوا الجنة."},
  {'n': '39', 'v': "وَٱلَّذِينَ كَفَرُوا۟ وَكَذَّبُوا۟ بِـَٔايَٰتِنَآ أُو۟لَٰٓئِكَ أَصْحَٰبُ ٱلنَّارِ ۖ هُمْ فِيهَا خَٰلِدُونَ", 't': "«والذين كفروا وكذبوا بآياتنا» كتبنا «أولئك أصحاب النار هم فيها خالدون» ماكثون أبداً لا يفنون ولا يخرجون."},
  {'n': '40', 'v': "يَٰبَنِىٓ إِسْرَٰٓءِيلَ ٱذْكُرُوا۟ نِعْمَتِىَ ٱلَّتِىٓ أَنْعَمْتُ عَلَيْكُمْ وَأَوْفُوا۟ بِعَهْدِىٓ أُوفِ بِعَهْدِكُمْ وَإِيَّٰىَ فَٱرْهَبُونِ", 't': "«يا بنى إسرائيل» أولاد يعقوب «اذكروا نعمتي التي أنعمت عليكم» أي على آبائكم من الإنجاء من فرعون وفلق البحر وتظليل الغمام وغير ذلك بأن تشكروها بطاعتي «وأوفوا بعهدي» الذي عهدته إليكم من الإيمان بمحمد «أوف بعهدكم» الذي عهدت إليكم من الثواب عليه بدخول الجنة «وإياي فارهبون» خافونِ في ترك الوفاء به دون غيري."},
  {'n': '41', 'v': "وَءَامِنُوا۟ بِمَآ أَنزَلْتُ مُصَدِّقًۭا لِّمَا مَعَكُمْ وَلَا تَكُونُوٓا۟ أَوَّلَ كَافِرٍۭ بِهِۦ ۖ وَلَا تَشْتَرُوا۟ بِـَٔايَٰتِى ثَمَنًۭا قَلِيلًۭا وَإِيَّٰىَ فَٱتَّقُونِ", 't': "«وآمنوا بما أنزلت» من القرآن «مصدِّقاً لما معكم» من التوراة بموافقته له في التوحيد والنبوة «ولا تكونوا أوَّل كافر به» من أهل الكتاب لأنَّ خلفكم تبع لكم فإثمهم عليكم «ولا تشتروا» تستبدلوا «بآياتي» التي في كتابكم من نعت محمد «ثمناً قليلا» عوضاً يسيرا من الدنيا أي لا تكتموها خوف فوات ما تأخذونه من سفلتكم «وإياي فاتقون» خافون في ذلك دون غيري."},
  {'n': '42', 'v': "وَلَا تَلْبِسُوا۟ ٱلْحَقَّ بِٱلْبَٰطِلِ وَتَكْتُمُوا۟ ٱلْحَقَّ وَأَنتُمْ تَعْلَمُونَ", 't': "«ولا تلبسوا» تخلطوا «الحق» الذي أنزلت عليكم «بالباطل» الذي تفترونه «و» لا «تكتموا الحق» نعت محمد «وأنتم تعلمون» أنه حق."},
  {'n': '43', 'v': "وَأَقِيمُوا۟ ٱلصَّلَوٰةَ وَءَاتُوا۟ ٱلزَّكَوٰةَ وَٱرْكَعُوا۟ مَعَ ٱلرَّٰكِعِينَ", 't': "«وأقيموا الصلاة وآتوا الزكاة واركعوا مع الراكعين» صلوا مع المصلين محمد وأصحابه، ونزل في علمائهم وكانوا يقولون لأقربائهم المسلمين اثبتوا على دين محمد فإنه الحق."},
  {'n': '44', 'v': "۞ أَتَأْمُرُونَ ٱلنَّاسَ بِٱلْبِرِّ وَتَنسَوْنَ أَنفُسَكُمْ وَأَنتُمْ تَتْلُونَ ٱلْكِتَٰبَ ۚ أَفَلَا تَعْقِلُونَ", 't': "«أتأمرون الناس بالبر» بالإيمان بمحمد «وتنسون أنفسكم» تتركونها فلا تأمرونها به «وأنتم تتلون الكتاب» التوراة وفيها الوعيد على مخالفة القول العمل «أفلا تعقلون» سوء فعلكم فترجعون، فجملة النسيان محل الاستفهام الإنكاري."},
  {'n': '45', 'v': "وَٱسْتَعِينُوا۟ بِٱلصَّبْرِ وَٱلصَّلَوٰةِ ۚ وَإِنَّهَا لَكَبِيرَةٌ إِلَّا عَلَى ٱلْخَٰشِعِينَ", 't': "«واستعينوا» اطلبوا المعونة على أموركم «بالصبر» الحبس للنفس على ما تكره «والصلاة» أفردها بالذكر تعظيما لشأنها وفي الحديث (كان صلى الله عليه وسلم إذا حزبه أمر بادر إلى الصلاة) وقيل الخطاب لليهود لما عاقهم عن الإيمان الشره وحب الرياسة فأمروا بالصبر وهو الصوم لأنه يكسر الشهوة والصلاة لأنها تورث الخشوع وتنفي الكبر «وإنها» أي الصلاة «لكبيرة» ثقيلة «إلا على الخاشعين» الساكنين إلى الطاعة."},
  {'n': '46', 'v': "ٱلَّذِينَ يَظُنُّونَ أَنَّهُم مُّلَٰقُوا۟ رَبِّهِمْ وَأَنَّهُمْ إِلَيْهِ رَٰجِعُونَ", 't': "«الَّذين يظنون» يوقنون «أنهم ملاقو ربِّهم» بالبعث «وأنهم إليه راجعون» في الآخرة فيجازيهم."},
  {'n': '47', 'v': "يَٰبَنِىٓ إِسْرَٰٓءِيلَ ٱذْكُرُوا۟ نِعْمَتِىَ ٱلَّتِىٓ أَنْعَمْتُ عَلَيْكُمْ وَأَنِّى فَضَّلْتُكُمْ عَلَى ٱلْعَٰلَمِينَ", 't': "«يا بني إسرائيل اذكروا نعمتي التي أنعمت عليكم» بالشكر عليها بطاعتي «وأني فضَّلتكم» أي آباءكم «على العالمين» عالمي زمانهم."},
  {'n': '48', 'v': "وَٱتَّقُوا۟ يَوْمًۭا لَّا تَجْزِى نَفْسٌ عَن نَّفْسٍۢ شَيْـًۭٔا وَلَا يُقْبَلُ مِنْهَا شَفَٰعَةٌۭ وَلَا يُؤْخَذُ مِنْهَا عَدْلٌۭ وَلَا هُمْ يُنصَرُونَ", 't': "«واتقوا» خافوا «يوما لا تجزي» فيه «نفس عن نفسٍ شيئاً» وهو يوم القيامة «ولا تُقبل» بالتاء والياء «منها شفاعة» أي ليس لها شفاعة فتقبل (فما لنا من شافعين) «ولا يؤخذ منها عدل» فداء «ولا هم ينصرون» يمنعون من عذاب الله."},
  {'n': '49', 'v': "وَإِذْ نَجَّيْنَٰكُم مِّنْ ءَالِ فِرْعَوْنَ يَسُومُونَكُمْ سُوٓءَ ٱلْعَذَابِ يُذَبِّحُونَ أَبْنَآءَكُمْ وَيَسْتَحْيُونَ نِسَآءَكُمْ ۚ وَفِى ذَٰلِكُم بَلَآءٌۭ مِّن رَّبِّكُمْ عَظِيمٌۭ", 't': "«و» اذكروا «إذ نجيناكم» أي آباءكم، والخطاب به وبما بعده للموجودين في زمن نبينا بما أنعم الله على آبائهم تذكيراً لهم بنعمة الله تعالى ليؤمنوا «من آل فرعون يسومونكم» يذيقونكم «سوء العذاب» أشده والجملة حال من ضمير نجيناكم «يُذبّحون» بيان لما قبله «أبناءكم» المولودين «ويستحيون» يستبقون «نساءكم» لقول بعض الكهنة له إن مولوداً يولد في بني إسرائيل يكون سبباً لذهاب ملكك «وفي ذلكم» العذاب أو الإنجاء «بلاء» ابتلاء أو إنعام «من ربكم عظيمْ»."},
  {'n': '50', 'v': "وَإِذْ فَرَقْنَا بِكُمُ ٱلْبَحْرَ فَأَنجَيْنَٰكُمْ وَأَغْرَقْنَآ ءَالَ فِرْعَوْنَ وَأَنتُمْ تَنظُرُونَ", 't': "«و» اذكروا «إذا فرقنا» فلقنا «بكم» بسببكم «البحر» حتى دخلتموه هاربين من عدوكم «فأنجيناكم» من الغرق «وأغرقنا آل فرعون» قومه معه «وأنتم تنظرون» إلى انطباق البحر عليهم"},
  {'n': '51', 'v': "وَإِذْ وَٰعَدْنَا مُوسَىٰٓ أَرْبَعِينَ لَيْلَةًۭ ثُمَّ ٱتَّخَذْتُمُ ٱلْعِجْلَ مِنۢ بَعْدِهِۦ وَأَنتُمْ ظَٰلِمُونَ", 't': "«وإذا واعدنا» بألف ودونها «موسى أربعين ليلة» نعطيه عند انقضائها التوراة لتعلموا بها «ثم اتخذتم العجل» الذي صاغه لكم السامري إلهاً «من بعده» أي بعد ذهابه إلى ميعادنا «وأنتم ظالمون» باتخاذه لوضعكم العبادة في غير محلها."},
  {'n': '52', 'v': "ثُمَّ عَفَوْنَا عَنكُم مِّنۢ بَعْدِ ذَٰلِكَ لَعَلَّكُمْ تَشْكُرُونَ", 't': "«ثم عفونا عنكم» محونا ذنوبكم «من بعد ذلك» الاتخاذ «لعلّكم تشكرون» نعمتنا عليكم"},
  {'n': '53', 'v': "وَإِذْ ءَاتَيْنَا مُوسَى ٱلْكِتَٰبَ وَٱلْفُرْقَانَ لَعَلَّكُمْ تَهْتَدُونَ", 't': "«وإذ آتينا موسى الكتاب» التوراة «والفرقان» عطف تفسير، أي الفارق بين الحق والباطل والحلال والحرام «لعلكم تهتدون» به من الضلال."},
  {'n': '54', 'v': "وَإِذْ قَالَ مُوسَىٰ لِقَوْمِهِۦ يَٰقَوْمِ إِنَّكُمْ ظَلَمْتُمْ أَنفُسَكُم بِٱتِّخَاذِكُمُ ٱلْعِجْلَ فَتُوبُوٓا۟ إِلَىٰ بَارِئِكُمْ فَٱقْتُلُوٓا۟ أَنفُسَكُمْ ذَٰلِكُمْ خَيْرٌۭ لَّكُمْ عِندَ بَارِئِكُمْ فَتَابَ عَلَيْكُمْ ۚ إِنَّهُۥ هُوَ ٱلتَّوَّابُ ٱلرَّحِيمُ", 't': "«وإذ قال موسى لقومه» الذين عبدوا العجل «يا قوم إنكم ظلمتم أنفسكم باتخاذكم العجل» إلهاً «فتوبوا إلى بارئكم» خالقكم من عبادته «فاقتلوا أنفسكم» أي ليقتل البريءُ منكم المجرم «ذلكم» القتل «خير لكم عند بارئكم» فوفقكم لفعل ذلك وأرسل عليكم سحابة سوداء لئلا يبصر بعضكم بعضا فيرحمه حتى قتل منكم نحو سبعين ألفا «فتاب عليكم» قبل توبتكم «أنه هو التواب الرحيم»."},
  {'n': '55', 'v': "وَإِذْ قُلْتُمْ يَٰمُوسَىٰ لَن نُّؤْمِنَ لَكَ حَتَّىٰ نَرَى ٱللَّهَ جَهْرَةًۭ فَأَخَذَتْكُمُ ٱلصَّٰعِقَةُ وَأَنتُمْ تَنظُرُونَ", 't': "«وإذ قلتم» وقد خرجتم مع موسى لتعتذروا إلى الله من عبادة العجل وسمعتم كلامه «يا موسى لن نؤمن لك حتى نرى الله جهرة» عيانا «فأخذتكم الصاعقة» الصيحة فمتم «وأنتم تنظرون» ما حل بكم."},
  {'n': '56', 'v': "ثُمَّ بَعَثْنَٰكُم مِّنۢ بَعْدِ مَوْتِكُمْ لَعَلَّكُمْ تَشْكُرُونَ", 't': "«ثم بعثناكم» أحييناكم «من بعد موتكم لعلكم تشكرون» نعمتنا بذلك."},
  {'n': '57', 'v': "وَظَلَّلْنَا عَلَيْكُمُ ٱلْغَمَامَ وَأَنزَلْنَا عَلَيْكُمُ ٱلْمَنَّ وَٱلسَّلْوَىٰ ۖ كُلُوا۟ مِن طَيِّبَٰتِ مَا رَزَقْنَٰكُمْ ۖ وَمَا ظَلَمُونَا وَلَٰكِن كَانُوٓا۟ أَنفُسَهُمْ يَظْلِمُونَ", 't': "«وظلَّلنا عليكم الغمام» سترناكم بالسحاب الرقيق من حر الشمس في التيه «وأنزلنا عليكم» فيه «المن والسلوى» هما الترنجبين والطير السماني بتخفيف الميم والقصر، وقلنا: «كلوا من طيبات ما رزقناكم» ولا تدَّخروا، فكفروا النعمة وادخروا فقطع عنهم «وما ظلمونا» بذلك «ولكن كانوا أنفسهم يظلمون» لأن وباله عليهم."},
  {'n': '58', 'v': "وَإِذْ قُلْنَا ٱدْخُلُوا۟ هَٰذِهِ ٱلْقَرْيَةَ فَكُلُوا۟ مِنْهَا حَيْثُ شِئْتُمْ رَغَدًۭا وَٱدْخُلُوا۟ ٱلْبَابَ سُجَّدًۭا وَقُولُوا۟ حِطَّةٌۭ نَّغْفِرْ لَكُمْ خَطَٰيَٰكُمْ ۚ وَسَنَزِيدُ ٱلْمُحْسِنِينَ", 't': "«وإذ قلنا» لهم بعد خروجهم من التيه «ادخلوا هذه القرية» بيت المقدس أو أريحا «فكلوا منها حيث شئتم رغدا» واسعا لاَ حَجْرَ فيه «وادخلوا الباب» أي بابها «سجداً» منحنين «وقولوا» مسألتنا «حطة» أي أن تحط عنا خطايانا «نغفر» وفي قراءة بالياء والتاء مبنياً للمفعول فيهما «لكم خطاياكم وسنزيد المحسنين» بالطاعة ثواباً."},
  {'n': '59', 'v': "فَبَدَّلَ ٱلَّذِينَ ظَلَمُوا۟ قَوْلًا غَيْرَ ٱلَّذِى قِيلَ لَهُمْ فَأَنزَلْنَا عَلَى ٱلَّذِينَ ظَلَمُوا۟ رِجْزًۭا مِّنَ ٱلسَّمَآءِ بِمَا كَانُوا۟ يَفْسُقُونَ", 't': "«فبدل الذين ظلموا» منهم «قولا غير الذي قيل لهم» فقالوا: حبة في شعرة ودخلوا يزحفون على أستاههم «فأنزلنا على الذين ظلموا» فيه وضع الظاهر موضع المضمر مبالغة في تقبيح شأنهم «رجزاً» عذاباً طاعوناً «من السماء بما كانوا يفسقون» بسب فسقهم أي خروجهم عن الطاعة فهلك منهم في ساعة سبعون ألفاً أو أقل."},
  {'n': '60', 'v': "۞ وَإِذِ ٱسْتَسْقَىٰ مُوسَىٰ لِقَوْمِهِۦ فَقُلْنَا ٱضْرِب بِّعَصَاكَ ٱلْحَجَرَ ۖ فَٱنفَجَرَتْ مِنْهُ ٱثْنَتَا عَشْرَةَ عَيْنًۭا ۖ قَدْ عَلِمَ كُلُّ أُنَاسٍۢ مَّشْرَبَهُمْ ۖ كُلُوا۟ وَٱشْرَبُوا۟ مِن رِّزْقِ ٱللَّهِ وَلَا تَعْثَوْا۟ فِى ٱلْأَرْضِ مُفْسِدِينَ", 't': "«و» اذكر «إذ استسقى موسى» أي طلب السقيا «لقومه» وقد عطشوا في التيه «فقلنا اضرب بعصاك الحجر» وهو الذي فر بثوبه خفيف مربع كرأس الرجل رخام أو كذان فضربه «فانفجرت» انشقت وسالت «منه اثنتا عشرة عيناً» بعدد الأسباط «قد علم كل أناس» سبط منهم «مشربهم» موضع شربهم فلا يشركهم فيه غيرهم وقلنا لهم «كلوا واشربوا من رزق الله ولا تعثوا في الأرض مفسدين» حال مؤكدة لعاملها من عثى بكسر المثلثة أفسد."},
  {'n': '61', 'v': "وَإِذْ قُلْتُمْ يَٰمُوسَىٰ لَن نَّصْبِرَ عَلَىٰ طَعَامٍۢ وَٰحِدٍۢ فَٱدْعُ لَنَا رَبَّكَ يُخْرِجْ لَنَا مِمَّا تُنۢبِتُ ٱلْأَرْضُ مِنۢ بَقْلِهَا وَقِثَّآئِهَا وَفُومِهَا وَعَدَسِهَا وَبَصَلِهَا ۖ قَالَ أَتَسْتَبْدِلُونَ ٱلَّذِى هُوَ أَدْنَىٰ بِٱلَّذِى هُوَ خَيْرٌ ۚ ٱهْبِطُوا۟ مِصْرًۭا فَإِنَّ لَكُم مَّا سَأَلْتُمْ ۗ وَضُرِبَتْ عَلَيْهِمُ ٱلذِّلَّةُ وَٱلْمَسْكَنَةُ وَبَآءُو بِغَضَبٍۢ مِّنَ ٱللَّهِ ۗ ذَٰلِكَ بِأَنَّهُمْ كَانُوا۟ يَكْفُرُونَ بِـَٔايَٰتِ ٱللَّهِ وَيَقْتُلُونَ ٱلنَّبِيِّۦنَ بِغَيْرِ ٱلْحَقِّ ۗ ذَٰلِكَ بِمَا عَصَوا۟ وَّكَانُوا۟ يَعْتَدُونَ", 't': "«وإذا قلتم يا موسى لن نصبر على طعام» أي نوع منه «واحد» وهو المن والسلوى «فادع لنا ربَّك يُخرج لنا» شيئاً «مما تنبت الأرض من» للبيان «بقلها وقثائها وفومها» حنطتها «وعدسها وبصلها قال» لهم موسى «أتستبدلون الذي هو أدنى» أخس «بالذي هو خير» أشرف أي أتأخذونه بدله، والهمزة للإنكار فأبوا أن يرجعوا فدعا الله تعالى فقال تعالى «اهبطوا» انزلوا «مصراً» من الأمصار «فإن لكم» فيه «ما سألتم» من النبات «وضُربت» جعلت «عليهم الذلة» الذل والهوان «والمسكنة» أي أثر الفقر من السكون والخزي فهي لازمة لهم، وإن كانوا أغنياء لزوم الدرهم المضروب لسكته «وباءُوا» رجعوا «بغضب من الله ذلك» أي الضرب والغضب «بأنهم» أي بسبب أنهم «كانوا يكفرون بآيات الله ويقتلون النبيين» كزكريا ويحيى «بغير الحق» أي ظلماً «ذلك بما عصوا وكانوا يعتدون» يتجاوزون الحد في المعاصي وكرره للتأكيد."},
  {'n': '62', 'v': "إِنَّ ٱلَّذِينَ ءَامَنُوا۟ وَٱلَّذِينَ هَادُوا۟ وَٱلنَّصَٰرَىٰ وَٱلصَّٰبِـِٔينَ مَنْ ءَامَنَ بِٱللَّهِ وَٱلْيَوْمِ ٱلْءَاخِرِ وَعَمِلَ صَٰلِحًۭا فَلَهُمْ أَجْرُهُمْ عِندَ رَبِّهِمْ وَلَا خَوْفٌ عَلَيْهِمْ وَلَا هُمْ يَحْزَنُونَ", 't': "«إن الذين آمنوا» بالأنبياء من قبل «والذين هادوا» هم اليهود «والنصارى والصابئين» طائفة من اليهود أو النصارى «من آمن» منهم «بالله واليوم الآخر» في زمن نبينا «وعمل صالحاً» بشريعته «فلهم أجرهم» أي ثواب أعمالهم «عند ربهم ولا خوف عليهم ولا هم يحزنون» رُوعي في ضمير آمن وعمل لفظ من وفيما بعده معناها."},
  {'n': '63', 'v': "وَإِذْ أَخَذْنَا مِيثَٰقَكُمْ وَرَفَعْنَا فَوْقَكُمُ ٱلطُّورَ خُذُوا۟ مَآ ءَاتَيْنَٰكُم بِقُوَّةٍۢ وَٱذْكُرُوا۟ مَا فِيهِ لَعَلَّكُمْ تَتَّقُونَ", 't': "«و» اذكر «إذ أخذنا ميثاقكم» عهدكم بالعمل بما في التوراة «و» قد «رفعنا فوقكم الطور» الجبل اقتلعناه من أصله عليكم لما أبيتم قبولها وقلنا «خذوا ما آتيناكم بقوة» بجد واجتهاد «واذكروا ما فيه» بالعمل به «لعلكم تتقون» النار أو المعاصي."},
  {'n': '64', 'v': "ثُمَّ تَوَلَّيْتُم مِّنۢ بَعْدِ ذَٰلِكَ ۖ فَلَوْلَا فَضْلُ ٱللَّهِ عَلَيْكُمْ وَرَحْمَتُهُۥ لَكُنتُم مِّنَ ٱلْخَٰسِرِينَ", 't': "«ثم توليتم» أعرضتم «من بعد ذلك» الميثاق عن الطاعة «فلولا فضل الله عليكم ورحمته» لكم بالتوبة أو تأخير العذاب «لكنتم من الخاسرين» الهالكين."},
  {'n': '65', 'v': "وَلَقَدْ عَلِمْتُمُ ٱلَّذِينَ ٱعْتَدَوْا۟ مِنكُمْ فِى ٱلسَّبْتِ فَقُلْنَا لَهُمْ كُونُوا۟ قِرَدَةً خَٰسِـِٔينَ", 't': "«ولقد» لام قسم «علمتم» عرفتم «الذين اعتدوا» تجاوزوا الحد «منكم في السبت» بصيد السمك وقد نهيناهم عنه وهم أهل آيلة «فقلنا لهم كونوا قردة خاسئين» مبعدين فكانوا وهلكوا بعد ثلاثة أيام."},
  {'n': '66', 'v': "فَجَعَلْنَٰهَا نَكَٰلًۭا لِّمَا بَيْنَ يَدَيْهَا وَمَا خَلْفَهَا وَمَوْعِظَةًۭ لِّلْمُتَّقِينَ", 't': "«فجعلناها» أي تلك العقوبة «نكالاً» عبرة مانعة من ارتكاب مثل ما عملوا «لما بين يديها وما خلفها» أي للأمم التي في زمانها وبعدها «وموعظة للمتقين» الله وخصوا بالذكر لأنهم المنتفعون بخلاف غيرهم."},
  {'n': '67', 'v': "وَإِذْ قَالَ مُوسَىٰ لِقَوْمِهِۦٓ إِنَّ ٱللَّهَ يَأْمُرُكُمْ أَن تَذْبَحُوا۟ بَقَرَةًۭ ۖ قَالُوٓا۟ أَتَتَّخِذُنَا هُزُوًۭا ۖ قَالَ أَعُوذُ بِٱللَّهِ أَنْ أَكُونَ مِنَ ٱلْجَٰهِلِينَ", 't': "«و» اذكر «إذ قال موسى لقومه» وقد قُتل لهم قتيل لا يُدرى قاتله وسألوه أن يدعو الله أن يبينه لهم فدعاه «إن الله يأمركم أن تذبحوا بقرة قالوا أتتخذنا هزواً» مهزوءاً بنا حيث تجيبنا بمثل ذلك «قال أعوذ» أمتنع «بالله أن أكون من الجاهلين» المستهزئين."},
  {'n': '68', 'v': "قَالُوا۟ ٱدْعُ لَنَا رَبَّكَ يُبَيِّن لَّنَا مَا هِىَ ۚ قَالَ إِنَّهُۥ يَقُولُ إِنَّهَا بَقَرَةٌۭ لَّا فَارِضٌۭ وَلَا بِكْرٌ عَوَانٌۢ بَيْنَ ذَٰلِكَ ۖ فَٱفْعَلُوا۟ مَا تُؤْمَرُونَ", 't': "فلما علموا أنه عزم «قالوا ادع لنا ربك يبيّن لنا ما هي» أي ما سنها «قال» موسى «إنه» أي الله «يقول إنها بقرة لا فارضٌ» مسنة «ولا بكرٌ» صغيرة «عوانٌ» نصف «بين ذلك» المذكور من السنين «فافعلوا ما تؤمرون» به من ذبحها."},
  {'n': '69', 'v': "قَالُوا۟ ٱدْعُ لَنَا رَبَّكَ يُبَيِّن لَّنَا مَا لَوْنُهَا ۚ قَالَ إِنَّهُۥ يَقُولُ إِنَّهَا بَقَرَةٌۭ صَفْرَآءُ فَاقِعٌۭ لَّوْنُهَا تَسُرُّ ٱلنَّٰظِرِينَ", 't': "«قالوا ادع لنا ربك يبين لنا ما لونها قال إنه يقول إنها بقرة صفراء فاقع لونها» شديد الصفرة، «تسر الناظرين» إليها بحسنها أي تعجبهم."},
  {'n': '70', 'v': "قَالُوا۟ ٱدْعُ لَنَا رَبَّكَ يُبَيِّن لَّنَا مَا هِىَ إِنَّ ٱلْبَقَرَ تَشَٰبَهَ عَلَيْنَا وَإِنَّآ إِن شَآءَ ٱللَّهُ لَمُهْتَدُونَ", 't': "«قالوا ادع لنا ربك يبين لنا ما هي» أسائمة أم عاملة «إن البقر» أي جنسه المنعوت بما ذكر «تشابه علينا» لكثرته فلم نهتد إلى المقصودة «وإنا إن شاء الله لمهتدون» إليها وفي الحديث (لو لم يستثنوا لما بينت لهم لآخر الأبد)."},
  {'n': '71', 'v': "قَالَ إِنَّهُۥ يَقُولُ إِنَّهَا بَقَرَةٌۭ لَّا ذَلُولٌۭ تُثِيرُ ٱلْأَرْضَ وَلَا تَسْقِى ٱلْحَرْثَ مُسَلَّمَةٌۭ لَّا شِيَةَ فِيهَا ۚ قَالُوا۟ ٱلْـَٰٔنَ جِئْتَ بِٱلْحَقِّ ۚ فَذَبَحُوهَا وَمَا كَادُوا۟ يَفْعَلُونَ", 't': "«قال إنه يقول إنها بقرة لا ذلول» غير مذللة بالعمل «تثير الأرض» تقلبها للزراعة والجملة صفة ذلول داخلة في النهي «ولا تسقي الحرث» الأرض المهيأة للزراعة «مسلمة» من العيوب وآثار العمل «لا شية» لون «فيها» غير لونها «قالوا الآن جئت بالحق» نطقت بالبيان التام فطلبوها فوجدوها عند الفتى البار بأمه فاشتروها بملء مسكها ذهبا «فذبحوها وما كادوا يفعلون» لغلاء ثمنها وفي الحديث: (لو ذبحوا أي بقرة كانت لأجزأتهم ولكن شددوا على أنفسهم فشدد الله عليهم)."},
  {'n': '72', 'v': "وَإِذْ قَتَلْتُمْ نَفْسًۭا فَٱدَّٰرَْٰٔتُمْ فِيهَا ۖ وَٱللَّهُ مُخْرِجٌۭ مَّا كُنتُمْ تَكْتُمُونَ", 't': "«وإذا قتلتم نفساً فأدّارأتم» فيه إدغام التاء في الأصل في الدال أي تخاصمتم وتدافعتم «فيها والله مخرج» مظهر «ما كنتم تكتمون» من أمرها وهذا اعتراض وهو أول القصة."},
  {'n': '73', 'v': "فَقُلْنَا ٱضْرِبُوهُ بِبَعْضِهَا ۚ كَذَٰلِكَ يُحْىِ ٱللَّهُ ٱلْمَوْتَىٰ وَيُرِيكُمْ ءَايَٰتِهِۦ لَعَلَّكُمْ تَعْقِلُونَ", 't': "«فقلنا اضربوه» أي القتيل «ببعضها» فضرب بلسانها أو عَجْب ذنبها فحييَ وقال: قتلني فلان وفلان لاِبْنيْ عمه ومات فحرما الميراث وقتلا، قال تعالى: «كذلك» الإحياء «يحيي الله الموتى ويريكم آياته» دلائل قدرته «لعلكم تعقلون» تتدبرون فتعلمون أن القادر على إحياء نفس واحدة قادر على إحياء نفوس كثيرة فتؤمنون."},
  {'n': '74', 'v': "ثُمَّ قَسَتْ قُلُوبُكُم مِّنۢ بَعْدِ ذَٰلِكَ فَهِىَ كَٱلْحِجَارَةِ أَوْ أَشَدُّ قَسْوَةًۭ ۚ وَإِنَّ مِنَ ٱلْحِجَارَةِ لَمَا يَتَفَجَّرُ مِنْهُ ٱلْأَنْهَٰرُ ۚ وَإِنَّ مِنْهَا لَمَا يَشَّقَّقُ فَيَخْرُجُ مِنْهُ ٱلْمَآءُ ۚ وَإِنَّ مِنْهَا لَمَا يَهْبِطُ مِنْ خَشْيَةِ ٱللَّهِ ۗ وَمَا ٱللَّهُ بِغَٰفِلٍ عَمَّا تَعْمَلُونَ", 't': "«ثم قست قلوبكم» أيها اليهود صلبت عن قبول الحق «من بعد ذلك» المذكور من إحياء القتيل وما قبله من الآيات «فهي كالحجارة» في القسوة «أو أشد قسوة» منها «وإن من الحجارة لما يتفجَّر منه الأنهار وإن منها لما يشقق» فيه إدغام التاء في الأصل في الشين «فيخرج منه الماء وإن منها لما يهبط» ينزل من علو إلى أسفل «من خشية الله» وقلوبكم لا تتأثر ولا تلين ولا تخشع «وما الله بغافل عما تعلمون» وإنما يؤخركم لوقتكم وفي قراءة بالتحتانية وفيه التفات عن الخطاب."},
  {'n': '75', 'v': "۞ أَفَتَطْمَعُونَ أَن يُؤْمِنُوا۟ لَكُمْ وَقَدْ كَانَ فَرِيقٌۭ مِّنْهُمْ يَسْمَعُونَ كَلَٰمَ ٱللَّهِ ثُمَّ يُحَرِّفُونَهُۥ مِنۢ بَعْدِ مَا عَقَلُوهُ وَهُمْ يَعْلَمُونَ", 't': "«أفتطعمون» أيها المؤمنون «أن يؤمنوا لكم» أي اليهود لكم. «وقد كان فريق» طائفة «منهم» أحبارهم «يسمعون كلام الله» في التوراة «ثم يحرّفونه» يغيرونه «من بعد ما عقلوه» فهموه «وهم يعلمون» أنهم مفترون والهمزة للإنكار أي لا تطمعوا فلهم سابقة بالكفر."},
  {'n': '76', 'v': "وَإِذَا لَقُوا۟ ٱلَّذِينَ ءَامَنُوا۟ قَالُوٓا۟ ءَامَنَّا وَإِذَا خَلَا بَعْضُهُمْ إِلَىٰ بَعْضٍۢ قَالُوٓا۟ أَتُحَدِّثُونَهُم بِمَا فَتَحَ ٱللَّهُ عَلَيْكُمْ لِيُحَآجُّوكُم بِهِۦ عِندَ رَبِّكُمْ ۚ أَفَلَا تَعْقِلُونَ", 't': "«وإذا لقوا» أي منافقوا اليهود «الذين آمنوا قالوا آمنا» بأن محمداً نبي وهو المبشر به في كتابنا «وإذا خلا» رجع «بعضهم إلى بعض قالوا» أي رؤساؤهم الذين لم ينافقوا لمن نافق «أتحدثونهم» أي المؤمنين «بما فتح الله عليكم» أي عرَّفكم في التوراة من نعت محمد * «ليحاجوكم» ليخاصموكم واللامُ للصيرورة «به عند ربكم» في الآخرة ويقيموا عليكم الحجة في ترك اتِّباعه مع علمكم بصدقه «أفلا تعقلون» أنهم يحاجونكم إذا حدثتموهم فتنتهوا."},
  {'n': '77', 'v': "أَوَلَا يَعْلَمُونَ أَنَّ ٱللَّهَ يَعْلَمُ مَا يُسِرُّونَ وَمَا يُعْلِنُونَ", 't': "قال تعالى «أو لا يعلمون» الاستفهام للتقرير والواو الداخلة عليها للعطف «أن الله يعلم ما يسرون وما يعلنون» ما يخفون وما يظهرون من ذلك وغيره فيرعَوُوا عن ذلك."},
  {'n': '78', 'v': "وَمِنْهُمْ أُمِّيُّونَ لَا يَعْلَمُونَ ٱلْكِتَٰبَ إِلَّآ أَمَانِىَّ وَإِنْ هُمْ إِلَّا يَظُنُّونَ", 't': "«ومنهم» أي اليهود «أميون» عوام «لا يعلمون الكتاب» التوراة «إلا» لكن «أمانيَّ» أكاذيب تلقَّوْها من رؤسائهم فاعتمدوها «وإن» ما «هم» في جحد نبوة النبي وغيره مما يختلقونه «‌إلا يظنون» ظناً ولا علم لهم."},
  {'n': '79', 'v': "فَوَيْلٌۭ لِّلَّذِينَ يَكْتُبُونَ ٱلْكِتَٰبَ بِأَيْدِيهِمْ ثُمَّ يَقُولُونَ هَٰذَا مِنْ عِندِ ٱللَّهِ لِيَشْتَرُوا۟ بِهِۦ ثَمَنًۭا قَلِيلًۭا ۖ فَوَيْلٌۭ لَّهُم مِّمَّا كَتَبَتْ أَيْدِيهِمْ وَوَيْلٌۭ لَّهُم مِّمَّا يَكْسِبُونَ", 't': "«فويل» شدة عذاب «للذين يكتبون الكتاب بأيديهم» أي مختلقاً من عندهم «ثم يقولون هذا من عند الله ليشتروا به ثمناً قليلا» من الدنيا وهم اليهود غيَّروا صفة النبي في التوراة وآية الرجم وغيرها وكتبوها على خلاف ما أنزل «فويل لهم مما كتبت أيديهم» من المختلق «وويل لهم مما يكسبون» من الرشا جمع رشوة."},
  {'n': '80', 'v': "وَقَالُوا۟ لَن تَمَسَّنَا ٱلنَّارُ إِلَّآ أَيَّامًۭا مَّعْدُودَةًۭ ۚ قُلْ أَتَّخَذْتُمْ عِندَ ٱللَّهِ عَهْدًۭا فَلَن يُخْلِفَ ٱللَّهُ عَهْدَهُۥٓ ۖ أَمْ تَقُولُونَ عَلَى ٱللَّهِ مَا لَا تَعْلَمُونَ", 't': "«وقالوا» لما وعدهم النبيُّ النار «لن تمسَّنا» تصيبنا «النار إلا أياماً معدودة» قليلة أربعين يوماً مدة عبادة آبائهم العجل ثم تزول «قل» لهم يا محمد «أتخذتم» حذفت منه همزة الوصل استغناءً بهمزة الاستفهام «عند الله عهداً» ميثاقاً منه بذلك «فلن يُخلف الله عهده» به؟ لا «أم» بل «تقولون على الله ما لا تعلمون»."},
  {'n': '81', 'v': "بَلَىٰ مَن كَسَبَ سَيِّئَةًۭ وَأَحَٰطَتْ بِهِۦ خَطِيٓـَٔتُهُۥ فَأُو۟لَٰٓئِكَ أَصْحَٰبُ ٱلنَّارِ ۖ هُمْ فِيهَا خَٰلِدُونَ", 't': "«بلى» تمسكم وتخلدون فيها «من كسب سيئة» شركاً «وأحاطت به خطيئته» بالإفراد والجمع أي استولت عليه وأحدقت به من كل جانب بأن مات مشركاً «فأولئك أصحاب النار هم فيها خالدون» روعي فيه معنى من."},
  {'n': '82', 'v': "وَٱلَّذِينَ ءَامَنُوا۟ وَعَمِلُوا۟ ٱلصَّٰلِحَٰتِ أُو۟لَٰٓئِكَ أَصْحَٰبُ ٱلْجَنَّةِ ۖ هُمْ فِيهَا خَٰلِدُونَ", 't': "«والذين آمنوا وعملوا الصالحات أولئك أصحاب الجنة هم فيها خالدون»."},
  {'n': '83', 'v': "وَإِذْ أَخَذْنَا مِيثَٰقَ بَنِىٓ إِسْرَٰٓءِيلَ لَا تَعْبُدُونَ إِلَّا ٱللَّهَ وَبِٱلْوَٰلِدَيْنِ إِحْسَانًۭا وَذِى ٱلْقُرْبَىٰ وَٱلْيَتَٰمَىٰ وَٱلْمَسَٰكِينِ وَقُولُوا۟ لِلنَّاسِ حُسْنًۭا وَأَقِيمُوا۟ ٱلصَّلَوٰةَ وَءَاتُوا۟ ٱلزَّكَوٰةَ ثُمَّ تَوَلَّيْتُمْ إِلَّا قَلِيلًۭا مِّنكُمْ وَأَنتُم مُّعْرِضُونَ", 't': "«و» اذكر «إذ أخذنا ميثاق بني إسرائيل» في التوراة وقلنا «لا تعبدون» بالتاء والياء «إلا الله» خبر بمعنى النهي، وقرئ: لا تعبدوا «و» أحسنوا «بالوالدين إحساناً» براً «وذي القربى» القرابة عطف على الوالدين «واليتامى والمساكين وقولوا للناس» قولا «حسناً» من الأمر بالمعروف والنهي عن المنكر والصدق في شأن محمد والرفق بهم، وفي قراءة بضم الحاء وسكون السين مصدر وصف به مبالغة «وأقيموا الصلاة وآتوا الزكاة» فقبلتم ذلك «ثم تولَّيتم» أعرضتم عن الوفاء به، فيه التفات عن الغيبة والمراد آباؤهم «إلا قليلا منكم وأنتم معرضون» عنه كآبائكم."},
  {'n': '84', 'v': "وَإِذْ أَخَذْنَا مِيثَٰقَكُمْ لَا تَسْفِكُونَ دِمَآءَكُمْ وَلَا تُخْرِجُونَ أَنفُسَكُم مِّن دِيَٰرِكُمْ ثُمَّ أَقْرَرْتُمْ وَأَنتُمْ تَشْهَدُونَ", 't': "«وإذ أخذنا ميثاقكم» وقلنا «لا تسفكون دماءكم» تريقونها بقتل بعضكم بعضاً «ولا تخرجون أنفسكم من دياركم» لا يخرج بعضكم بعضا من داره «ثم أقررتم» قبلتم ذلك الميثاق «وأنتم تشهدون» على أنفسكم."},
  {'n': '85', 'v': "ثُمَّ أَنتُمْ هَٰٓؤُلَآءِ تَقْتُلُونَ أَنفُسَكُمْ وَتُخْرِجُونَ فَرِيقًۭا مِّنكُم مِّن دِيَٰرِهِمْ تَظَٰهَرُونَ عَلَيْهِم بِٱلْإِثْمِ وَٱلْعُدْوَٰنِ وَإِن يَأْتُوكُمْ أُسَٰرَىٰ تُفَٰدُوهُمْ وَهُوَ مُحَرَّمٌ عَلَيْكُمْ إِخْرَاجُهُمْ ۚ أَفَتُؤْمِنُونَ بِبَعْضِ ٱلْكِتَٰبِ وَتَكْفُرُونَ بِبَعْضٍۢ ۚ فَمَا جَزَآءُ مَن يَفْعَلُ ذَٰلِكَ مِنكُمْ إِلَّا خِزْىٌۭ فِى ٱلْحَيَوٰةِ ٱلدُّنْيَا ۖ وَيَوْمَ ٱلْقِيَٰمَةِ يُرَدُّونَ إِلَىٰٓ أَشَدِّ ٱلْعَذَابِ ۗ وَمَا ٱللَّهُ بِغَٰفِلٍ عَمَّا تَعْمَلُونَ", 't': "«ثم أنتم» يا «هؤلاء تقتلون أنفسكم» بقتل بعضكم بعضا «وتخرجون فريقا منكم من ديارهم تَظَّاهَرُونَ» فيه إدغام التاء في الأصل في الظاء، وفي قراءة بالتخفيف على حذفها تتعاونون «عليهم بالإثم» بالمعصية «والعدوان» الظلم «وإن يأتوكم أسارى» وفي قراءة أسرى «تَفْدُوهُمْ» وفي قراءة «تُفَادُوهُمْ» تنقذوهم من الأسر بالمال أو غيره وهو مما عهد إليهم «وهو» أي الشأن «محرَّم عليكم إخراجهم» متصل بقوله وتخرجون والجملة بينهما اعتراض: أي كما حرم ترك الفداء، وكانت قريظةُ حالفوا الأوسَ، والنضيرُ الخزرجَ فكان كل فريق يقاتل مع حلفائه ويخرب ديارهم ويخرجهم فإذا أسروا فدوهم، وكانوا إذا سئلوا لم تقاتلونهم وتفدونهم؟ قالوا أمرنا بالفداء فيقال فَلِمَ تقاتلونهم؟ فيقولون حياء أن تستذل حلفاؤنا. قال تعالى: «أفتؤمنون ببعض الكتاب» وهو الفداء «وتكفرون ببعض» وهو ترك القتل والإخراج والمظاهرة «فما جزاء من يفعل ذلك منكم إلا خزيٌ» هوان وذلّ «في الحياة الدنيا» وقد خزوا بقتل قريظة ونفي النضير إلى الشام وضرب الجزية «ويوم القيامة يردون إلى أشد العذاب وما الله بغافلِ عما يعملون» بالياء والتاء."},
  {'n': '86', 'v': "أُو۟لَٰٓئِكَ ٱلَّذِينَ ٱشْتَرَوُا۟ ٱلْحَيَوٰةَ ٱلدُّنْيَا بِٱلْءَاخِرَةِ ۖ فَلَا يُخَفَّفُ عَنْهُمُ ٱلْعَذَابُ وَلَا هُمْ يُنصَرُونَ", 't': "«أولئك الذين اشتروا الحياة الدنيا بالآخرة» بأن آثروها عليها «فلا يخفَّف عنهم العذاب ولا هم يُنصرون» يمنعون منه."},
  {'n': '87', 'v': "وَلَقَدْ ءَاتَيْنَا مُوسَى ٱلْكِتَٰبَ وَقَفَّيْنَا مِنۢ بَعْدِهِۦ بِٱلرُّسُلِ ۖ وَءَاتَيْنَا عِيسَى ٱبْنَ مَرْيَمَ ٱلْبَيِّنَٰتِ وَأَيَّدْنَٰهُ بِرُوحِ ٱلْقُدُسِ ۗ أَفَكُلَّمَا جَآءَكُمْ رَسُولٌۢ بِمَا لَا تَهْوَىٰٓ أَنفُسُكُمُ ٱسْتَكْبَرْتُمْ فَفَرِيقًۭا كَذَّبْتُمْ وَفَرِيقًۭا تَقْتُلُونَ", 't': "«ولقد آتينا موسى الكتاب» التوراة «وقفيَّنا من بعده بالرسل» أي اتبعناهم رسولا في إثر رسول «وآتينا عيسى ابن مريم البينات» المعجزات كإحياء الموتى وإبراء الأكمه والأبرص «وأيدناه» قويناه «بروح القدس» من إضافة الموصوف إلى الصفة أي الروح المقدسة جبريل لطهارته يسير معه حيث سار فلم تستقيموا «أفكلما جاءكم رسول بما لا تهوى» تحب «أنفسُكم» من الحق «استكبرتم» تكبرتم عن إتباعه جواب كلما وهو محل الاستفهام، والمراد به التوبيخ «ففريقا» منهم «كذبتم» كعيسى «وفريقاً تقتلون» المضارع لحكاية الحال الماضية: أي قتلتم كزكريا ويحيى."},
  {'n': '88', 'v': "وَقَالُوا۟ قُلُوبُنَا غُلْفٌۢ ۚ بَل لَّعَنَهُمُ ٱللَّهُ بِكُفْرِهِمْ فَقَلِيلًۭا مَّا يُؤْمِنُونَ", 't': "«وقالوا» للنبي استهزاء «قلوبنا غُلْفٌ» جمع أغلف أي مغشاة بأغطية فلا تعي ما تقول قال تعالى: «بل» للإضراب «لعنهم الله» أبعدهم من رحمته وخذلهم عن القبول «بكفرهم» وليس عدم قبولهم لخلل في قلوبهم «فقليلا ما يؤمنون» ما زائدة لتأكيد القلة أي: إيمانهم قليل جداً."},
  {'n': '89', 'v': "وَلَمَّا جَآءَهُمْ كِتَٰبٌۭ مِّنْ عِندِ ٱللَّهِ مُصَدِّقٌۭ لِّمَا مَعَهُمْ وَكَانُوا۟ مِن قَبْلُ يَسْتَفْتِحُونَ عَلَى ٱلَّذِينَ كَفَرُوا۟ فَلَمَّا جَآءَهُم مَّا عَرَفُوا۟ كَفَرُوا۟ بِهِۦ ۚ فَلَعْنَةُ ٱللَّهِ عَلَى ٱلْكَٰفِرِينَ", 't': "«ولما جاءهم كتاب من عند الله مصدق لما معهم» من التوراة: هو القرآن «وكانوا من قبل» قبل مجيئه «يستفتحون» يستنصرون «على الذين كفروا» يقولون اللهم انصرنا عليهم بالنبي المبعوث آخر الزمان «فلما جاءهم ما عرفوا» من الحق وهو بعثة النبي «كفروا به» جحداً وخوفاً على الرياسة وجوابُ لما الأولى دل عليه جواب الثانية «فلعنة الله على الكافرين»."},
  {'n': '90', 'v': "بِئْسَمَا ٱشْتَرَوْا۟ بِهِۦٓ أَنفُسَهُمْ أَن يَكْفُرُوا۟ بِمَآ أَنزَلَ ٱللَّهُ بَغْيًا أَن يُنَزِّلَ ٱللَّهُ مِن فَضْلِهِۦ عَلَىٰ مَن يَشَآءُ مِنْ عِبَادِهِۦ ۖ فَبَآءُو بِغَضَبٍ عَلَىٰ غَضَبٍۢ ۚ وَلِلْكَٰفِرِينَ عَذَابٌۭ مُّهِينٌۭ", 't': "«بئسما اشتروا» باعوا «به أنفسهم» أي حظها من الثواب، وما: نكرة بمعنى شيئاً تمييز لفاعل بئس والمخصوص بالذم «أن يكفروا» أي كفرهم «بما أنزل الله» من القرآن «بغياً» مفعول له ليكفروا: أي حسداً على «أن ينزل الله» بالتخفيف والتشديد «من فضله» الوحي «على من يشاء» للرسالة «من عباده فباءوا» رجعوا «بغضب» من الله بكفرهم بما أنزل والتنكيرُ للتعظيم «على غضب» استحقوه من قبل بتضييع التوراة والكفر بعيسى «وللكافرين عذاب مُهين» ذو إهانة."},
  {'n': '91', 'v': "وَإِذَا قِيلَ لَهُمْ ءَامِنُوا۟ بِمَآ أَنزَلَ ٱللَّهُ قَالُوا۟ نُؤْمِنُ بِمَآ أُنزِلَ عَلَيْنَا وَيَكْفُرُونَ بِمَا وَرَآءَهُۥ وَهُوَ ٱلْحَقُّ مُصَدِّقًۭا لِّمَا مَعَهُمْ ۗ قُلْ فَلِمَ تَقْتُلُونَ أَنۢبِيَآءَ ٱللَّهِ مِن قَبْلُ إِن كُنتُم مُّؤْمِنِينَ", 't': "«وإذا قيل لهم آمِنوا بما أنزل الله» القرآن وغيره «قالوا نؤمن بما أنزل علينا» أي التوراة قال تعالى: «ويكفرون» الواو للحال «بما وراءه» سواه أو بعده من القرآن «وهو الحق» حال «مصدقاً» حال ثانية مؤكدة «لما معهم قل» لهم «فلم تقتلون» أي قتلتم «أنبياء الله من قبل إن كنتم مؤمنين» بالتوراة وقد نهيتم فيها عن قتلهم والخطاب للموجودين في زمن نبينا بما فعل آباؤهم لرضاهم به."},
  {'n': '92', 'v': "۞ وَلَقَدْ جَآءَكُم مُّوسَىٰ بِٱلْبَيِّنَٰتِ ثُمَّ ٱتَّخَذْتُمُ ٱلْعِجْلَ مِنۢ بَعْدِهِۦ وَأَنتُمْ ظَٰلِمُونَ", 't': "«ولقد جاءكم موسى بالبينات» بالمعجزات كالعصا واليد وفلق البحر «ثم اتخذتم العجل» إلَهاً «من بعده» من بعد ذهابه إلى الميقات، «وأنتم ظالمون» باتخاذه."},
  {'n': '93', 'v': "وَإِذْ أَخَذْنَا مِيثَٰقَكُمْ وَرَفَعْنَا فَوْقَكُمُ ٱلطُّورَ خُذُوا۟ مَآ ءَاتَيْنَٰكُم بِقُوَّةٍۢ وَٱسْمَعُوا۟ ۖ قَالُوا۟ سَمِعْنَا وَعَصَيْنَا وَأُشْرِبُوا۟ فِى قُلُوبِهِمُ ٱلْعِجْلَ بِكُفْرِهِمْ ۚ قُلْ بِئْسَمَا يَأْمُرُكُم بِهِۦٓ إِيمَٰنُكُمْ إِن كُنتُم مُّؤْمِنِينَ", 't': "«وإذ أخذنا ميثاقكم» على العمل بما في التوراة «و» قد «رفعنا فوقكم الطور» الجبل حين امتنعتم من قبولها ليسقط عليكم وقلنا «خذوا ما آتيناكم بقوة» بجد واجتهاد «واسمعوا» ما تؤمرون به سماع قبول «قالوا سمعنا» قولك «وعصينا» أمرك «وأشربوا في قلوبهم العجل» أي خالط حبه قلوبهم كما يخالط الشراب «بكفرهم، قل» لهم «بئسما» شيئا «يأمركم به إيمانكم» بالتوراة عبادة العجل «إن كنتم مؤمنين» بها كما زعمتم. المعنى لستم بمؤمنين لأن الإيمان لا يأمر بعبادة العجل، والمراد آباؤهم: أي فكذلك أنتم لستم بمؤمنين بالتوراة وقد كذَّبتم محمداً والإيمان بها لا يأمر بتكذيبه."},
  {'n': '94', 'v': "قُلْ إِن كَانَتْ لَكُمُ ٱلدَّارُ ٱلْءَاخِرَةُ عِندَ ٱللَّهِ خَالِصَةًۭ مِّن دُونِ ٱلنَّاسِ فَتَمَنَّوُا۟ ٱلْمَوْتَ إِن كُنتُمْ صَٰدِقِينَ", 't': "«قل» لهم «إن كانت لكم الدار الآخرة» أي الجنة «عند الله خالصة» خاصة «من دون الناس» كما زعمتم «فتمنوا الموت إن كنتم صادقين» تعلق بتمنوا الشرطان على أن الأول قيد في الثاني أي إن صدقتم في زعمكم أنها لكم ومن كانت له يؤثرها والموصل إليها الموت فتمنوه."},
  {'n': '95', 'v': "وَلَن يَتَمَنَّوْهُ أَبَدًۢا بِمَا قَدَّمَتْ أَيْدِيهِمْ ۗ وَٱللَّهُ عَلِيمٌۢ بِٱلظَّٰلِمِينَ", 't': "«ولن يتمنَّوه أبداً بما قدمت أيديهم» من كفرهم بالنبي المستلزم لكذبهم «والله عليم بالظالمين» الكافرين فيجازيهم."},
  {'n': '96', 'v': "وَلَتَجِدَنَّهُمْ أَحْرَصَ ٱلنَّاسِ عَلَىٰ حَيَوٰةٍۢ وَمِنَ ٱلَّذِينَ أَشْرَكُوا۟ ۚ يَوَدُّ أَحَدُهُمْ لَوْ يُعَمَّرُ أَلْفَ سَنَةٍۢ وَمَا هُوَ بِمُزَحْزِحِهِۦ مِنَ ٱلْعَذَابِ أَن يُعَمَّرَ ۗ وَٱللَّهُ بَصِيرٌۢ بِمَا يَعْمَلُونَ", 't': "«ولتجدنهم» لام قسم «أحرص الناس على حياة و» أحرص «من الذين أشركوا» المنكرين للبعث عليها لعلمهم بأن مصيرهم النار دون المشركين لإنكارهم له «يودُّ» يتمنى «أحدهم لو يعمر ألف سنة» لو مصدرية بمعنى أن وهي بصلتها في تأويل مصدر مفعول يود «وما هو» أي أحدهم «بمزحزحه» مبعده «من العذاب» النار «أن يعمَّر» فاعل مزحزحه أي تعميره «والله بصير بما يعملون» بالياء والتاء فيجازيهم وسأل ابن صوريا النبي أو عمر عمن يأتي بالوحي من الملائكة فقال جبريل فقال هو عدونا يأتي بالعذاب ولو كان ميكائيل لآمنا لأنه يأتي بالخصب والسلم فنزل:"},
  {'n': '97', 'v': "قُلْ مَن كَانَ عَدُوًّۭا لِّجِبْرِيلَ فَإِنَّهُۥ نَزَّلَهُۥ عَلَىٰ قَلْبِكَ بِإِذْنِ ٱللَّهِ مُصَدِّقًۭا لِّمَا بَيْنَ يَدَيْهِ وَهُدًۭى وَبُشْرَىٰ لِلْمُؤْمِنِينَ", 't': "«قل» لهم «من كان عدوّاً لجبريل» فليمت غيظاً «فإنه نزَّله» أي القرآن «على قلبك بإذن» بأمر «الله مصدقاً لما بين يديه» قلبه من الكتب «وهدىً» من الضلالة «وبشرى» بالجنة «للمؤمنين»."},
  {'n': '98', 'v': "مَن كَانَ عَدُوًّۭا لِّلَّهِ وَمَلَٰٓئِكَتِهِۦ وَرُسُلِهِۦ وَجِبْرِيلَ وَمِيكَىٰلَ فَإِنَّ ٱللَّهَ عَدُوٌّۭ لِّلْكَٰفِرِينَ", 't': "«من كان عدواً لله وملائكته ورسله وجبريل» بكسر الجيم وفتحها بلا همز وبه بياء ودونها «وميكال» عطف على الملائكة من عطف الخاص على العام وفي قراءة ميكائيل بهمزة وياء وفي أخرى بلا ياء «فإن الله عدوٌ للكافرين» وأوقعه موقع لهم بياناً لحالهم."},
  {'n': '99', 'v': "وَلَقَدْ أَنزَلْنَآ إِلَيْكَ ءَايَٰتٍۭ بَيِّنَٰتٍۢ ۖ وَمَا يَكْفُرُ بِهَآ إِلَّا ٱلْفَٰسِقُونَ", 't': "«ولقد أنزلنا إليك» يا محمد «آيات بينات» أي واضحات حال، رد لقول ابن صوريا للنبي ما جئتنا بشيء «وما يكفر بها إلا الفاسقون» كفروا بها."},
  {'n': '100', 'v': "أَوَكُلَّمَا عَٰهَدُوا۟ عَهْدًۭا نَّبَذَهُۥ فَرِيقٌۭ مِّنْهُم ۚ بَلْ أَكْثَرُهُمْ لَا يُؤْمِنُونَ", 't': "«أو كلما عاهدوا» الله «عهداً» على الإيمان بالنبي إن خرج، أو النبيَّ أن لا يعاونوا عليه المشركين «نبذه» طرحه «فريق منهم» بنقضه، جواب كلما وهو محل الاستفهام الإنكاري «بل» للانتقال «أكثرهم لا يؤمنون»."},
  {'n': '101', 'v': "وَلَمَّا جَآءَهُمْ رَسُولٌۭ مِّنْ عِندِ ٱللَّهِ مُصَدِّقٌۭ لِّمَا مَعَهُمْ نَبَذَ فَرِيقٌۭ مِّنَ ٱلَّذِينَ أُوتُوا۟ ٱلْكِتَٰبَ كِتَٰبَ ٱللَّهِ وَرَآءَ ظُهُورِهِمْ كَأَنَّهُمْ لَا يَعْلَمُونَ", 't': "«ولما جاءهم رسول من عند الله» محمد «مصدق لما معهم نبذ فريق من الذين أوتوا الكتاب كتاب الله» أي التوراة «وراء ظهورهم» أي لم يعملوا بما فيها من الإيمان بالرسول وغيره «كأنهم لا يعلمون» ما فيها من أنه نبي حق أو أنها كتاب الله."},
  {'n': '102', 'v': "وَٱتَّبَعُوا۟ مَا تَتْلُوا۟ ٱلشَّيَٰطِينُ عَلَىٰ مُلْكِ سُلَيْمَٰنَ ۖ وَمَا كَفَرَ سُلَيْمَٰنُ وَلَٰكِنَّ ٱلشَّيَٰطِينَ كَفَرُوا۟ يُعَلِّمُونَ ٱلنَّاسَ ٱلسِّحْرَ وَمَآ أُنزِلَ عَلَى ٱلْمَلَكَيْنِ بِبَابِلَ هَٰرُوتَ وَمَٰرُوتَ ۚ وَمَا يُعَلِّمَانِ مِنْ أَحَدٍ حَتَّىٰ يَقُولَآ إِنَّمَا نَحْنُ فِتْنَةٌۭ فَلَا تَكْفُرْ ۖ فَيَتَعَلَّمُونَ مِنْهُمَا مَا يُفَرِّقُونَ بِهِۦ بَيْنَ ٱلْمَرْءِ وَزَوْجِهِۦ ۚ وَمَا هُم بِضَآرِّينَ بِهِۦ مِنْ أَحَدٍ إِلَّا بِإِذْنِ ٱللَّهِ ۚ وَيَتَعَلَّمُونَ مَا يَضُرُّهُمْ وَلَا يَنفَعُهُمْ ۚ وَلَقَدْ عَلِمُوا۟ لَمَنِ ٱشْتَرَىٰهُ مَا لَهُۥ فِى ٱلْءَاخِرَةِ مِنْ خَلَٰقٍۢ ۚ وَلَبِئْسَ مَا شَرَوْا۟ بِهِۦٓ أَنفُسَهُمْ ۚ لَوْ كَانُوا۟ يَعْلَمُونَ", 't': "«واتبعوا» عطف على نبذ «ما تتلوا» أي تلت «الشياطين على» عهد «ملك سليمان» من السحر وكانت دفنته تحت كرسيه لما نزع ملكه أو كانت تسترق السمع وتضم إليه أكاذيب وتلقيه إلى الكهنة فيدونونه وفشا ذلك وشاع أن الجن تعلم الغيب فجمع سليمان الكتب ودفنها فلما مات دلت الشياطين عليها الناس فاستخرجوها فوجدوا فيها السحر فقالوا إنما ملككم بهذا فتعلموه فرفضوا كتب أنبيائهم قال تعالى تبرئه لسليمان ورداً على اليهود في قولهم انظروا إلى محمد يذكر سليمان في الأنبياء وما كان إلا ساحراً: «وما كفر سليمان» أي لم يعمل السحر لأنه كفر «ولكن» بالتشديد والتخفيف «الشياطين كفروا يعلمون الناس السحر» الجملة حال من ضمير كفروا «و» يعلمونهم «ما أنزل على الملكين» أي ألهماه من السحر وقرئ بكسر اللام الكائنين «ببابل» بلد في سواد العراق «هاروت وماروت» بدل أو عطف بيان للملكين قال ابن عباس هما ساحران كانا يعلمان السحر وقيل ملكان أنزلا لتعليمه ابتلاء من الله للناس «وما يعلمان من» زائدة «أحد حتى يقولا» له نصحاً «إنما نحن فتنة» بلية من الله إلى الناس ليمتحنهم بتعليمه فمن تعلمه كفر ومن تركه فهو مؤمن «فلا تكفر» بتعلمه فإن أبى إلا التعليم علماه «فيتعلمون منهما ما يفرقون به بين المرء وزوجه» بأن يبغض كلا إلى الآخر «وما هم» أي السحرة «بضارين به» بالسحر «من» زائدة «أحد إلا بإذن الله» بإرادته «ويتعلمون ما يضرهم» في الآخرة «ولا ينفعهم» وهو السحر «ولقد» لام قسم «علموا» أي اليهود «لمن» لام ابتداء معلقة لما قبلها ومن موصلة «اشتراه» اختاره أو استبدله بكتاب الله «ماله في الآخرة من خلاق» نصيب في الجنة «ولبئس ما» شيئاً «شروا» باعوا «به أنفسهم» أي الشارين: أي حظها من الآخرة إن تعلموه حيث أوجب لهم النار «لو كانوا يعلمون» حقيقة ما يصيرون إليه من العذاب ما تعلَّموه."},
  {'n': '103', 'v': "وَلَوْ أَنَّهُمْ ءَامَنُوا۟ وَٱتَّقَوْا۟ لَمَثُوبَةٌۭ مِّنْ عِندِ ٱللَّهِ خَيْرٌۭ ۖ لَّوْ كَانُوا۟ يَعْلَمُونَ", 't': "«ولو أنهم» أي اليهود «آمنوا» بالنبي والقرآن «واتقوا» عقاب الله بترك معاصيه كالسحر، وجوابُ لو محذوف: أي لأثيبوا دل عليه «لمثوبة» ثواب وهو مبتدأ واللام فيه للقسم «من عند الله خير» خبره مما شروا به أنفسهم «لو كانوا يعلمون» أنه خير لما آثروه عليه."},
  {'n': '104', 'v': "يَٰٓأَيُّهَا ٱلَّذِينَ ءَامَنُوا۟ لَا تَقُولُوا۟ رَٰعِنَا وَقُولُوا۟ ٱنظُرْنَا وَٱسْمَعُوا۟ ۗ وَلِلْكَٰفِرِينَ عَذَابٌ أَلِيمٌۭ", 't': "«يا أيها الذين أمنوا لا تقولوا» للنبي «راعنا» أمر من المراعاة وكانوا يقولون له ذلك وهي بلغة اليهود سب من الرعونة فسُرُّوا بذلك وخاطبوا بها النبي فنُهى المؤمنون عنها «وقولوا» بدلها «انظرنا» أي انظر إلينا «واسمعوا» ما تؤمرون به سماع قبول «وللكافرين عذاب أليم» مؤلم هو النار."},
  {'n': '105', 'v': "مَّا يَوَدُّ ٱلَّذِينَ كَفَرُوا۟ مِنْ أَهْلِ ٱلْكِتَٰبِ وَلَا ٱلْمُشْرِكِينَ أَن يُنَزَّلَ عَلَيْكُم مِّنْ خَيْرٍۢ مِّن رَّبِّكُمْ ۗ وَٱللَّهُ يَخْتَصُّ بِرَحْمَتِهِۦ مَن يَشَآءُ ۚ وَٱللَّهُ ذُو ٱلْفَضْلِ ٱلْعَظِيمِ", 't': "«ما يود الذين كفروا من أهل الكتاب ولا المشركين» من العرب عطف على أهل الكتاب ومن للبيان «أن يُنَزَّلَ عليكم من» زائدة «خير» وحي «من ربكم» حسداً لكم «والله يختص برحمته» نبوته «من يشاء والله ذو الفضل العظيم»"},
  {'n': '106', 'v': "۞ مَا نَنسَخْ مِنْ ءَايَةٍ أَوْ نُنسِهَا نَأْتِ بِخَيْرٍۢ مِّنْهَآ أَوْ مِثْلِهَآ ۗ أَلَمْ تَعْلَمْ أَنَّ ٱللَّهَ عَلَىٰ كُلِّ شَىْءٍۢ قَدِيرٌ", 't': "ولما طعن الكفار في النسخ وقالوا إن محمداً يأمر أصحابه اليوم بأمر وينهى عنه غداً نزل: «ما» شرطية «ننسخ من أية» أي ننزل حكمها: إما مع لفظها أو لا وفي قراءة بضم النون من أنسخ: أي نأمرك أو جبريل بنسخها «أو ننسها» نؤخرها، فلا ننزل حكمها ونرفع تلاوتها أو نؤخرها في اللوح المحفوظ وفي قراءة بلا همز من النسيان أي ننسها، أي نمحها من قلبك وجواب الشرط «نأت بخير منها» أنفع للعباد في السهولة أو كثرة الأجر «أو مثلها» في التكليف والثواب «ألم تعلم أن الله على كل شئ قدير» ومنه النسخ والتبديل، والاستفهام للتقرير."},
  {'n': '107', 'v': "أَلَمْ تَعْلَمْ أَنَّ ٱللَّهَ لَهُۥ مُلْكُ ٱلسَّمَٰوَٰتِ وَٱلْأَرْضِ ۗ وَمَا لَكُم مِّن دُونِ ٱللَّهِ مِن وَلِىٍّۢ وَلَا نَصِيرٍ", 't': "«ألم تعلم أن الله له ملك السموات والأرض» يفعل ما يشاء «وما لكم من دون الله» أي غيره «من» زائدة «وليٌ» يحفظكم «ولا نصير» يمنع عنكم عذابه إن أتاكم، ونزل لما سأله أهل مكة أن يوسعها ويجعل الصفا ذهباً."},
  {'n': '108', 'v': "أَمْ تُرِيدُونَ أَن تَسْـَٔلُوا۟ رَسُولَكُمْ كَمَا سُئِلَ مُوسَىٰ مِن قَبْلُ ۗ وَمَن يَتَبَدَّلِ ٱلْكُفْرَ بِٱلْإِيمَٰنِ فَقَدْ ضَلَّ سَوَآءَ ٱلسَّبِيلِ", 't': "«أم» بل «تريدون أن تسألوا رسولكم كما سئل موسى» أي سأله قومه «من قبل» من قولهم: أرنا الله جهرة وغير ذلك «ومن يتبدل الكفر بالإيمان» أي يأخذ بدله بترك النظر في الآيات البينات واقتراح غيرها «فقد ضل سواء السبيل» أخطأ الطريق الحق والسواءُ في الأصل الوسط."},
  {'n': '109', 'v': "وَدَّ كَثِيرٌۭ مِّنْ أَهْلِ ٱلْكِتَٰبِ لَوْ يَرُدُّونَكُم مِّنۢ بَعْدِ إِيمَٰنِكُمْ كُفَّارًا حَسَدًۭا مِّنْ عِندِ أَنفُسِهِم مِّنۢ بَعْدِ مَا تَبَيَّنَ لَهُمُ ٱلْحَقُّ ۖ فَٱعْفُوا۟ وَٱصْفَحُوا۟ حَتَّىٰ يَأْتِىَ ٱللَّهُ بِأَمْرِهِۦٓ ۗ إِنَّ ٱللَّهَ عَلَىٰ كُلِّ شَىْءٍۢ قَدِيرٌۭ", 't': "«ودَّ كثير من أهل الكتاب لو» مصدرية «يردونكم من بعد إيمانكم كفارا حسدا» مفعول له كائنا «من عند أنفسهم» أي حملتهم عليه أنفسهم الخبيثة «من بعد ما تبين لهم» في التوراة «الحق» في شأن النبي «فاعفوا» عنهم أي اتركوهم «واصفحوا» أعرضوا فلا تجازوهم «حتى يأتي الله بأمره» فيهم من القتال «إن الله على كل شئ قدير»."},
  {'n': '110', 'v': "وَأَقِيمُوا۟ ٱلصَّلَوٰةَ وَءَاتُوا۟ ٱلزَّكَوٰةَ ۚ وَمَا تُقَدِّمُوا۟ لِأَنفُسِكُم مِّنْ خَيْرٍۢ تَجِدُوهُ عِندَ ٱللَّهِ ۗ إِنَّ ٱللَّهَ بِمَا تَعْمَلُونَ بَصِيرٌۭ", 't': "«وأقيموا الصلاة وآتوا الزكاة وما تقدموا لأنفسكم من خير» طاعة كصلة وصدقة «تجدوه» أي ثوابه «عند الله إن الله بما تعملون بصير» فيجازيكم به."},
  {'n': '111', 'v': "وَقَالُوا۟ لَن يَدْخُلَ ٱلْجَنَّةَ إِلَّا مَن كَانَ هُودًا أَوْ نَصَٰرَىٰ ۗ تِلْكَ أَمَانِيُّهُمْ ۗ قُلْ هَاتُوا۟ بُرْهَٰنَكُمْ إِن كُنتُمْ صَٰدِقِينَ", 't': "«وقالوا لن يدخل الجنة إلا من كان هوداً» جمع هائد «أو نصارى» قال ذلك يهود المدينة ونصارى نجران لما تناظروا بين يدي النبي أي قال اليهود لن يدخلها إلا اليهود وقال النصارى لن يدخلها إلا النصارى «تلك» القولة «أمانيهم» شهواتهم الباطلة «قل» لهم «هاتوا برهانكم» حجتكم على ذلك «إن كنتم صادقين» فيه."},
  {'n': '112', 'v': "بَلَىٰ مَنْ أَسْلَمَ وَجْهَهُۥ لِلَّهِ وَهُوَ مُحْسِنٌۭ فَلَهُۥٓ أَجْرُهُۥ عِندَ رَبِّهِۦ وَلَا خَوْفٌ عَلَيْهِمْ وَلَا هُمْ يَحْزَنُونَ", 't': "«بلى» يدخل الجنة غيرهم «من أسلم وجهه لله» أي انقاد لأمره. وخص الوجه لأنه أشرف الأعضاء فغيره أولى «وهو محسن» موحد «فله أجره عند ربِّه» أي ثواب عمله الجنة «ولا خوف عليهم ولا هم يحزنون» في الآخرة."},
  {'n': '113', 'v': "وَقَالَتِ ٱلْيَهُودُ لَيْسَتِ ٱلنَّصَٰرَىٰ عَلَىٰ شَىْءٍۢ وَقَالَتِ ٱلنَّصَٰرَىٰ لَيْسَتِ ٱلْيَهُودُ عَلَىٰ شَىْءٍۢ وَهُمْ يَتْلُونَ ٱلْكِتَٰبَ ۗ كَذَٰلِكَ قَالَ ٱلَّذِينَ لَا يَعْلَمُونَ مِثْلَ قَوْلِهِمْ ۚ فَٱللَّهُ يَحْكُمُ بَيْنَهُمْ يَوْمَ ٱلْقِيَٰمَةِ فِيمَا كَانُوا۟ فِيهِ يَخْتَلِفُونَ", 't': "«وقالت اليهود ليست النصارى على شئ» معتد به وكفرت بعيسى «وقالت النصارى ليست اليهود على شئ» معتد به وكفرت بموسى «وهم» أي الفريقان «يتلون الكتاب» المنزل عليهم، وفي كتاب اليهود تصديق عيسى، وفي كتاب النصارى تصديق موسى والجملة حال «كذلك» كما قال هؤلاء «قال الذين لا يعلمون» أي المشركون من العرب وغيرهم «مثل قولهم» بيان لمعنى ذلك: أي قالوا لكل ذي دين ليسوا على شئ «فالله يحكم بينهم يوم القيامة فيما كانوا فيه يختلفون» من أمر الدين فيدخل المحقُّ الجنة والمبطل النار."},
  {'n': '114', 'v': "وَمَنْ أَظْلَمُ مِمَّن مَّنَعَ مَسَٰجِدَ ٱللَّهِ أَن يُذْكَرَ فِيهَا ٱسْمُهُۥ وَسَعَىٰ فِى خَرَابِهَآ ۚ أُو۟لَٰٓئِكَ مَا كَانَ لَهُمْ أَن يَدْخُلُوهَآ إِلَّا خَآئِفِينَ ۚ لَهُمْ فِى ٱلدُّنْيَا خِزْىٌۭ وَلَهُمْ فِى ٱلْءَاخِرَةِ عَذَابٌ عَظِيمٌۭ", 't': "«ومن أظلم» أي لا أحد أظلم «ممن منع مساجد الله أن يذكر فيها اسمه» بالصلاة والتسبيح «وسعى في خرابها» بالهدم أو التعطيل، نزلت إخباراً عن الروم الذين خربوا بيت المقدس أو في المشركين لما صدوا النبي عام الحديبية عن البيت «أولئك ما كان لهم أن يدخلوها إلا خائفين» خبر بمعنى الأمر أي أخيفوهم بالجهاد فلا يدخلها أحد آمناً. «لهم في الدنيا خزي» هوان بالقتل والسبي والجزية «ولهم في الآخرة عذاب عظيم» هو النار."},
  {'n': '115', 'v': "وَلِلَّهِ ٱلْمَشْرِقُ وَٱلْمَغْرِبُ ۚ فَأَيْنَمَا تُوَلُّوا۟ فَثَمَّ وَجْهُ ٱللَّهِ ۚ إِنَّ ٱللَّهَ وَٰسِعٌ عَلِيمٌۭ", 't': "ونزل لما طعن اليهود في نسخ القبلة أو في صلاة النافلة على الراحلة في السفر حيثما توجهت «ولله المشرق والمغرب» أي الأرض كلها لأنهما ناحيتها «فأينما تولوا» وجوهكم في الصلاة بأمره «فثمَّ» هناك «وجه الله» قبلته التي رضيها «إن الله واسع» يسع فضله كل شئ «عليم» بتدبير خلقه."},
  {'n': '116', 'v': "وَقَالُوا۟ ٱتَّخَذَ ٱللَّهُ وَلَدًۭا ۗ سُبْحَٰنَهُۥ ۖ بَل لَّهُۥ مَا فِى ٱلسَّمَٰوَٰتِ وَٱلْأَرْضِ ۖ كُلٌّۭ لَّهُۥ قَٰنِتُونَ", 't': "«وقالوا» بواو وبدونها اليهود والنصارى ومن زعم أن الملائكة بنات الله «اتخذ الله ولداً» قال تعالى «سبحانه» تنزيها له عنه «بل له ما في السماوات والأرض» ملكا وخلقا وعبيدا والملكية تنافي الولادة وعبر بما تغليبا لما لا يعقل «كل له قانتون» مطيعون كل بما يراد منه وفيه تغليب العاقل."},
  {'n': '117', 'v': "بَدِيعُ ٱلسَّمَٰوَٰتِ وَٱلْأَرْضِ ۖ وَإِذَا قَضَىٰٓ أَمْرًۭا فَإِنَّمَا يَقُولُ لَهُۥ كُن فَيَكُونُ", 't': "«بديع السماوات والأرض» موجدهم لا على مثال سبق «وإذا قضى» أراد «أمرا» أي إيجاده «فإنما يقول له كن فيكون» أي فهو يكون وفى قراءة بالنصب جوابا للأمر."},
  {'n': '118', 'v': "وَقَالَ ٱلَّذِينَ لَا يَعْلَمُونَ لَوْلَا يُكَلِّمُنَا ٱللَّهُ أَوْ تَأْتِينَآ ءَايَةٌۭ ۗ كَذَٰلِكَ قَالَ ٱلَّذِينَ مِن قَبْلِهِم مِّثْلَ قَوْلِهِمْ ۘ تَشَٰبَهَتْ قُلُوبُهُمْ ۗ قَدْ بَيَّنَّا ٱلْءَايَٰتِ لِقَوْمٍۢ يُوقِنُونَ", 't': "«وقال الذين لا يعلمون» أي كفار مكة للنبي «لولا» هلا «يكلمنا الله» بأنك رسوله «أو تأتينا آية» مما اقترحناه على صدقك «كذلك» كما قال هؤلاء «قال الذين من قبلهم» من كفار الأمم الماضية لأنبيائهم «مثل قولهم» من التعنت وطلب الآيات «تشابهت قلوبهم» في الكفر والعناد، فيه تسلية للنبي «قد بينا الآيات لقوم يوقنون» يعلمون أنها آيات فيؤمنون فاقتراحُ آية معها تعنُّت."},
  {'n': '119', 'v': "إِنَّآ أَرْسَلْنَٰكَ بِٱلْحَقِّ بَشِيرًۭا وَنَذِيرًۭا ۖ وَلَا تُسْـَٔلُ عَنْ أَصْحَٰبِ ٱلْجَحِيمِ", 't': "«إنا أرسلناك» يا محمد «بالحق» بالهدى «بشيرا» من أجاب إليه بالجنة «ونذيرا» من لم يجب إليه بالنار «ولا تُسأل عن أصحاب الجحيم» النار، أي الكفار ما لهم لم يؤمنوا إنما عليك البلاغ، وفي قراءة بجزم تسأل نهيا."},
  {'n': '120', 'v': "وَلَن تَرْضَىٰ عَنكَ ٱلْيَهُودُ وَلَا ٱلنَّصَٰرَىٰ حَتَّىٰ تَتَّبِعَ مِلَّتَهُمْ ۗ قُلْ إِنَّ هُدَى ٱللَّهِ هُوَ ٱلْهُدَىٰ ۗ وَلَئِنِ ٱتَّبَعْتَ أَهْوَآءَهُم بَعْدَ ٱلَّذِى جَآءَكَ مِنَ ٱلْعِلْمِ ۙ مَا لَكَ مِنَ ٱللَّهِ مِن وَلِىٍّۢ وَلَا نَصِيرٍ", 't': "«ولن ترضى عنك اليهود ولا النصارى حتى تتبع ملَّتهم» دينهم «قل إن هدى الله» أي الإسلام «هو الهدى» وما عداه ضلال «ولئن» لام قسم «اتبعت أهواءهم» التي يدعونك إليها فرضاً «بعد الذي جاءك من العلم» الوحي من الله «مالك من الله من ولي» يحفظك «ولا نصير» يمنعك منه."},
  {'n': '121', 'v': "ٱلَّذِينَ ءَاتَيْنَٰهُمُ ٱلْكِتَٰبَ يَتْلُونَهُۥ حَقَّ تِلَاوَتِهِۦٓ أُو۟لَٰٓئِكَ يُؤْمِنُونَ بِهِۦ ۗ وَمَن يَكْفُرْ بِهِۦ فَأُو۟لَٰٓئِكَ هُمُ ٱلْخَٰسِرُونَ", 't': "«الذين آتيناهم الكتاب» مبتدأً «يتلونه حق تلاوته» أي يقرؤونه كما أنزل والجملة حال وحق نصب على المصدر والخبر «أولئك يؤمنون به» نزلت في جماعة قدموا من الحبشة وأسلموا «ومن يكفر به» أي بالكتاب المؤتى بأن يحرفه «فأولئك هم الخاسرون» لمصيرهم إلى النار المؤبدة عليهم."},
  {'n': '122', 'v': "يَٰبَنِىٓ إِسْرَٰٓءِيلَ ٱذْكُرُوا۟ نِعْمَتِىَ ٱلَّتِىٓ أَنْعَمْتُ عَلَيْكُمْ وَأَنِّى فَضَّلْتُكُمْ عَلَى ٱلْعَٰلَمِينَ", 't': "«يابني إسرائيل اذكروا نعمتي التي أنعمت عليكم و أني فضَّلتكم على العالمين» تقدم مثله."},
  {'n': '123', 'v': "وَٱتَّقُوا۟ يَوْمًۭا لَّا تَجْزِى نَفْسٌ عَن نَّفْسٍۢ شَيْـًۭٔا وَلَا يُقْبَلُ مِنْهَا عَدْلٌۭ وَلَا تَنفَعُهَا شَفَٰعَةٌۭ وَلَا هُمْ يُنصَرُونَ", 't': "«واتقوا» خافوا «يوما لا تجزي» تغني «نفس عن نفس» فيه «شيئا ولا يُقبل منها عدل» فداء «ولا تنفعها شفاعة ولا هم يُنصرون» يمنعون من عذاب الله."},
  {'n': '124', 'v': "۞ وَإِذِ ٱبْتَلَىٰٓ إِبْرَٰهِۦمَ رَبُّهُۥ بِكَلِمَٰتٍۢ فَأَتَمَّهُنَّ ۖ قَالَ إِنِّى جَاعِلُكَ لِلنَّاسِ إِمَامًۭا ۖ قَالَ وَمِن ذُرِّيَّتِى ۖ قَالَ لَا يَنَالُ عَهْدِى ٱلظَّٰلِمِينَ", 't': "«و» اذكر «إذا ابتلى» اختبر «إبراهيم» وفي قراءة إبراهام. «ربُّه بكلمات» بأوامر ونواه كلَّفه بها، قيل هي مناسك الحج، وقيل المضمضة والاستنشاق والسواك وقص الشارب وفرق الرأس وقلم الأظافر ونتف الإبط وحلق العانة والختان والاستنجاء «فأتمهن» أداهن تامات «قال» تعالى له «إني جاعلك للناس إماما» قدوة في الدين «قال ومن ذرِّيتي» أولادي اجعل أئمة «قال لا ينال عهدي» بالإمامة «الظالمين» الكافرين منهم دل على أنه ينال غير الظالم."},
  {'n': '125', 'v': "وَإِذْ جَعَلْنَا ٱلْبَيْتَ مَثَابَةًۭ لِّلنَّاسِ وَأَمْنًۭا وَٱتَّخِذُوا۟ مِن مَّقَامِ إِبْرَٰهِۦمَ مُصَلًّۭى ۖ وَعَهِدْنَآ إِلَىٰٓ إِبْرَٰهِۦمَ وَإِسْمَٰعِيلَ أَن طَهِّرَا بَيْتِىَ لِلطَّآئِفِينَ وَٱلْعَٰكِفِينَ وَٱلرُّكَّعِ ٱلسُّجُودِ", 't': "«وإذ جعلنا البيت» الكعبة «مثابة للناس» مرجعا يثبون إليه من كل جانب «وأمنا» مأمنا لهم من الظلم والإغارات الواقعة في غيره، كان الرجل يلقى قاتل أبيه فيه فلا يهيجه «واتخذوا» أيها الناس «من مقام إبراهيم» هو الحجر الذي قام عليه عند بناء البيت «مصلى» مكان صلاة بأن تصلوا خلفه ركعتي الطواف، وفي قراءة بفتح الخاء خبر «وعهدنا إلى إبراهيم وإسماعيل» أمرناهما «أن» أي بأن «طهِّرا بيتي» من الأوثان «للطائفين والعاكفين» المقيمين فيه «والركع السجود» جمع راكع وساجد المصلين."},
  {'n': '126', 'v': "وَإِذْ قَالَ إِبْرَٰهِۦمُ رَبِّ ٱجْعَلْ هَٰذَا بَلَدًا ءَامِنًۭا وَٱرْزُقْ أَهْلَهُۥ مِنَ ٱلثَّمَرَٰتِ مَنْ ءَامَنَ مِنْهُم بِٱللَّهِ وَٱلْيَوْمِ ٱلْءَاخِرِ ۖ قَالَ وَمَن كَفَرَ فَأُمَتِّعُهُۥ قَلِيلًۭا ثُمَّ أَضْطَرُّهُۥٓ إِلَىٰ عَذَابِ ٱلنَّارِ ۖ وَبِئْسَ ٱلْمَصِيرُ", 't': "«وإذا قال إبراهيم رب اجعل هذا» المكان «بلدا آمنا» ذا أمن وقد أجاب الله دعاءه فجعله حرما لا يسفك فيه دم إنسان ولا يظلم فيه أحد ولا يصاد صيده ولا يختلي خلاه «وارزق أهله من الثمرات» وقد فعل بنقل الطائف من الشام إليه وكان أقفر لا زرع فيه ولا ماء «من آمن منهم بالله واليوم الآخر» بدل من أهله وخصهم بالدعاء لهم موافقة لقوله لا ينال عهدي الظالمين «قال» تعالى «و» ارزق «من كفر فَأُمَتِّعُهُ» بالتشديد والتخفيف في الدنيا بالرزق «قليلا» مدة حياته «ثم أضطره» ألجئه في الآخرة «إلى عذاب النار» فلا يجد عنها محيص «وبئس المصير» المرجع هي."},
  {'n': '127', 'v': "وَإِذْ يَرْفَعُ إِبْرَٰهِۦمُ ٱلْقَوَاعِدَ مِنَ ٱلْبَيْتِ وَإِسْمَٰعِيلُ رَبَّنَا تَقَبَّلْ مِنَّآ ۖ إِنَّكَ أَنتَ ٱلسَّمِيعُ ٱلْعَلِيمُ", 't': "«و» اذكر «إذ يرفع إبراهيم القواعد» الأسس أو الجدر «من البيت» يبنيه متعلق بيرفع «وإسماعيل» عطف على إبراهيم يقولان «ربنا تقبل منا» بناءنا «إنك أنت السميع» للقول «العليم» بالفعل."},
  {'n': '128', 'v': "رَبَّنَا وَٱجْعَلْنَا مُسْلِمَيْنِ لَكَ وَمِن ذُرِّيَّتِنَآ أُمَّةًۭ مُّسْلِمَةًۭ لَّكَ وَأَرِنَا مَنَاسِكَنَا وَتُبْ عَلَيْنَآ ۖ إِنَّكَ أَنتَ ٱلتَّوَّابُ ٱلرَّحِيمُ", 't': "«ربنا واجعلنا مسلمَيْن» منقادين «لك و» اجعل «من ذرِّيتنا» أولادنا «أمة» جماعة «مسلمة لك» ومن للتبعيض وأتى به لتقدم قوله لا ينال عهدي الظالمين «وأرنا» علِّمنا «مناسكنا» شرائع عبادتنا أو حجنا «وتب علينا إنك أنت التواب الرحيم» سألاه التوبة مع عصمتهما تواضعا وتعليما لذريتهما."},
  {'n': '129', 'v': "رَبَّنَا وَٱبْعَثْ فِيهِمْ رَسُولًۭا مِّنْهُمْ يَتْلُوا۟ عَلَيْهِمْ ءَايَٰتِكَ وَيُعَلِّمُهُمُ ٱلْكِتَٰبَ وَٱلْحِكْمَةَ وَيُزَكِّيهِمْ ۚ إِنَّكَ أَنتَ ٱلْعَزِيزُ ٱلْحَكِيمُ", 't': "«ربنا وابعث فيهم» أي أهل البيت «رسولا منهم» من أنفسهم وقد أجاب الله دعاءه بمحمد «يتلو عليهم آياتك» القرآن «ويعلمهم الكتاب» القرآن «والحكمة» أي ما فيه من الأحكام «ويزكيهم» يطهرهم من الشرك «إنك أنت العزيز» الغالب «الحكيم» في صنعه."},
  {'n': '130', 'v': "وَمَن يَرْغَبُ عَن مِّلَّةِ إِبْرَٰهِۦمَ إِلَّا مَن سَفِهَ نَفْسَهُۥ ۚ وَلَقَدِ ٱصْطَفَيْنَٰهُ فِى ٱلدُّنْيَا ۖ وَإِنَّهُۥ فِى ٱلْءَاخِرَةِ لَمِنَ ٱلصَّٰلِحِينَ", 't': "«ومن» أي لا «يرغب عن ملة إبراهيم» فيتركها «إلا من سفه نفسه» جهل أنها مخلوقة لله يجب عليها عبادته أو استخف بها وامتهنها «ولقد اصطفيناه» اخترناه «في الدنيا» بالرسالة والخلة «وإنه في الآخرة لمن الصالحين» الذين لهم الدرجات العلى."},
  {'n': '131', 'v': "إِذْ قَالَ لَهُۥ رَبُّهُۥٓ أَسْلِمْ ۖ قَالَ أَسْلَمْتُ لِرَبِّ ٱلْعَٰلَمِينَ", 't': "واذكر «إذ قال له ربه أسلمْ» انقد لله وأخلص له دينك «قال أسلمت لرب العالمين»."},
  {'n': '132', 'v': "وَوَصَّىٰ بِهَآ إِبْرَٰهِۦمُ بَنِيهِ وَيَعْقُوبُ يَٰبَنِىَّ إِنَّ ٱللَّهَ ٱصْطَفَىٰ لَكُمُ ٱلدِّينَ فَلَا تَمُوتُنَّ إِلَّا وَأَنتُم مُّسْلِمُونَ", 't': "«ووصَّى» وفي قراءة أوصى «بها» بالملة «إبراهيم بنيه ويعقوب» بنيه قال: «يا بني إن الله اصطفى لكم الدين» دين الإسلام «فلا تموتنَّ إلا وأنتم مسلمون» نهى عن ترك الإسلام وأمر بالثبات عليه إلى مصادفة الموت."},
  {'n': '133', 'v': "أَمْ كُنتُمْ شُهَدَآءَ إِذْ حَضَرَ يَعْقُوبَ ٱلْمَوْتُ إِذْ قَالَ لِبَنِيهِ مَا تَعْبُدُونَ مِنۢ بَعْدِى قَالُوا۟ نَعْبُدُ إِلَٰهَكَ وَإِلَٰهَ ءَابَآئِكَ إِبْرَٰهِۦمَ وَإِسْمَٰعِيلَ وَإِسْحَٰقَ إِلَٰهًۭا وَٰحِدًۭا وَنَحْنُ لَهُۥ مُسْلِمُونَ", 't': "ولما قال اليهود للنبي ألست تعلم أن يعقوب يوم مات أوصى بنيه باليهودية نزل: «أم كنتم شهداء» حضورا «إذ حضر يعقوب الموتُ إذ» بدل من إذ قبله «قال لبنيه ما تعبدون من بعدي» بعد موتي «قالوا نعبد إلهك وإله آبائك إبراهيم وإسماعيل وإسحاق» جد إسماعيل من الآباء تغليب ولأن العم بمنزلة الأب «إلها واحدا» بدل من إلهك «ونحن له مسلمون» وأم بمعنى همزة الإنكار أي لم تحضروه وقت موته فكيف تنسبون إليه ما لا يليق به."},
  {'n': '134', 'v': "تِلْكَ أُمَّةٌۭ قَدْ خَلَتْ ۖ لَهَا مَا كَسَبَتْ وَلَكُم مَّا كَسَبْتُمْ ۖ وَلَا تُسْـَٔلُونَ عَمَّا كَانُوا۟ يَعْمَلُونَ", 't': "«تلك» مبتدأ والإشارة إلى إبراهيم ويعقوب وبينهما وأُنِّث لتأنيث خبره «أمة قد خلت» سلفت «لها ما كسبت» من العمل أي جزاؤه استئناف «ولكم» الخطاب لليهود «ما كسبتم ولا تُسألون عما كانوا يعلمون» كما لا يسألون عن عملكم والجملة تأكيد لما قبلها."},
  {'n': '135', 'v': "وَقَالُوا۟ كُونُوا۟ هُودًا أَوْ نَصَٰرَىٰ تَهْتَدُوا۟ ۗ قُلْ بَلْ مِلَّةَ إِبْرَٰهِۦمَ حَنِيفًۭا ۖ وَمَا كَانَ مِنَ ٱلْمُشْرِكِينَ", 't': "«وقالوا كونوا هودا أو نصارى تهتدوا» أو للتفضيل وقائل الأول يهود المدينة والثاني نصارى نجران «قل» لهم «بل» نتبع «ملة إبراهيم حنيفا» حال من إبراهيم مائلا عن الأديان كلها إلى الدين القيّم «وما كان من المشركين»."},
  {'n': '136', 'v': "قُولُوٓا۟ ءَامَنَّا بِٱللَّهِ وَمَآ أُنزِلَ إِلَيْنَا وَمَآ أُنزِلَ إِلَىٰٓ إِبْرَٰهِۦمَ وَإِسْمَٰعِيلَ وَإِسْحَٰقَ وَيَعْقُوبَ وَٱلْأَسْبَاطِ وَمَآ أُوتِىَ مُوسَىٰ وَعِيسَىٰ وَمَآ أُوتِىَ ٱلنَّبِيُّونَ مِن رَّبِّهِمْ لَا نُفَرِّقُ بَيْنَ أَحَدٍۢ مِّنْهُمْ وَنَحْنُ لَهُۥ مُسْلِمُونَ", 't': "«قولوا» خطاب للمؤمنين «آمنا بالله وما أنزل إلينا» من القرآن «وما أنزل إلى إبراهيم» من الصحف العشر «وإسماعيل وإسحاق ويعقوب والأسباط» أولاده «وما أوتي موسى» من التوراة «وعيسى» من الإنجيل «وما أوتي النبيُّون من ربهم» من الكتب والآيات «لا نُفرِّق بين أحد منهم» فنؤمن ببعض ونكفر ببعض كاليهود والنصارى «ونحن له مسلمون»."},
  {'n': '137', 'v': "فَإِنْ ءَامَنُوا۟ بِمِثْلِ مَآ ءَامَنتُم بِهِۦ فَقَدِ ٱهْتَدَوا۟ ۖ وَّإِن تَوَلَّوْا۟ فَإِنَّمَا هُمْ فِى شِقَاقٍۢ ۖ فَسَيَكْفِيكَهُمُ ٱللَّهُ ۚ وَهُوَ ٱلسَّمِيعُ ٱلْعَلِيمُ", 't': "«فإن آمنوا» أي اليهود والنصارى «بمثل» زائدة «ما آمنتم به فقد اهتدوا وإن تولوا» عن الإيمان به «فإنما هم في شقاق» خلاف معكم «فسيكفيكهم الله» يا محمد شقاقهم «وهو السميع» لأقوالهم «العليم» بأحوالهم وقد كفاه إياهم بقتل قريظة، ونفي النضير وضرب الجزية عليهم."},
  {'n': '138', 'v': "صِبْغَةَ ٱللَّهِ ۖ وَمَنْ أَحْسَنُ مِنَ ٱللَّهِ صِبْغَةًۭ ۖ وَنَحْنُ لَهُۥ عَٰبِدُونَ", 't': "«صِبْغَةَ الله» مصدر مؤكد لآمنا ونصبه بفعل مقدر، أي صبغنا الله والمراد بها دينه الذي فطر الناس عليه لظهور أثره على صاحبه كالصبغ في الثوب «ومن» أي لا أحد «أحسن من الله صبغة» تمييز «ونحن له عابدون» قال اليهود للمسلمين نحن أهل الكتاب الأول وقبلتنا أقدم ولم تكن الأنبياء من العرب ولو كان محمد نبيا لكان منا فنزل."},
  {'n': '139', 'v': "قُلْ أَتُحَآجُّونَنَا فِى ٱللَّهِ وَهُوَ رَبُّنَا وَرَبُّكُمْ وَلَنَآ أَعْمَٰلُنَا وَلَكُمْ أَعْمَٰلُكُمْ وَنَحْنُ لَهُۥ مُخْلِصُونَ", 't': "«قل» لهم «أتحاجوننا» تخاصموننا «في الله» أن اصطفى نبيا من العرب «وهو ربنا وربكم» فله أن يصطفي من عباده ما يشاء «ولنا أعمالنا» نجازى بها «ولكم أعمالكم» تجازون بها فلا يبعد أن يكون في أعمالنا ما نستحق به الإكرام «ونحن له مخلصون» الدين والعمل دونكم فنحن أولى بالاصطفاء، والهمزة للإنكار والجمل الثلاث أحوال."},
  {'n': '140', 'v': "أَمْ تَقُولُونَ إِنَّ إِبْرَٰهِۦمَ وَإِسْمَٰعِيلَ وَإِسْحَٰقَ وَيَعْقُوبَ وَٱلْأَسْبَاطَ كَانُوا۟ هُودًا أَوْ نَصَٰرَىٰ ۗ قُلْ ءَأَنتُمْ أَعْلَمُ أَمِ ٱللَّهُ ۗ وَمَنْ أَظْلَمُ مِمَّن كَتَمَ شَهَٰدَةً عِندَهُۥ مِنَ ٱللَّهِ ۗ وَمَا ٱللَّهُ بِغَٰفِلٍ عَمَّا تَعْمَلُونَ", 't': "«أم» بل «تقولون» بالتاء والياء «إنَّ إبراهيم وإسماعيل وإسحاق ويعقوب والأسباط كانوا هودا أو نصارى قل» لهم «أأنتم أعلم أم الله» أي الله أعلم وقد برأ منهما إبراهيم بقوله (ما كان إبراهيم يهوديا ولا نصرانيا) والمذكورون معه تبع له «ومن أظم ممن كتم» أخفى عن الناس «شهادة عنده» كائنة «من الله» أي لا أحد أظلم منه وهم اليهود كتموا شهادة الله في التوراة إبراهيم بالحنيفية «وما الله بغافل عما تعملون» تهديد لهم."},
  {'n': '141', 'v': "تِلْكَ أُمَّةٌۭ قَدْ خَلَتْ ۖ لَهَا مَا كَسَبَتْ وَلَكُم مَّا كَسَبْتُمْ ۖ وَلَا تُسْـَٔلُونَ عَمَّا كَانُوا۟ يَعْمَلُونَ", 't': "«تلك أمة قد خلت لها ما كسبت ولكم ما كسبتم ولا تُسألون عما كانوا يعملون» تقدم مثله."},
  {'n': '142', 'v': "۞ سَيَقُولُ ٱلسُّفَهَآءُ مِنَ ٱلنَّاسِ مَا وَلَّىٰهُمْ عَن قِبْلَتِهِمُ ٱلَّتِى كَانُوا۟ عَلَيْهَا ۚ قُل لِّلَّهِ ٱلْمَشْرِقُ وَٱلْمَغْرِبُ ۚ يَهْدِى مَن يَشَآءُ إِلَىٰ صِرَٰطٍۢ مُّسْتَقِيمٍۢ", 't': "«سيقول السفهاء» الجهال «من الناس» اليهود والمشركين «ما ولاّهم» أي شيء، صرف النبي والمؤمنين «عن قبلتهم التي كانوا عليها» على استقبالها في الصلاة وهي بيت المقدس، والإتيان بالسين الدالة على الاستقبال من الإخبار بالغيب «قل لله المشرق والمغرب» أي الجهات كلها فيأمر بالتوجه إلى أي جهة شاء لا اعتراض عليه «يهدي من يشاء» هدايته «إلى صراط» طريق «مستقيم» دين الإسلام أي ومنهم أنتم دل على هذا."},
  {'n': '143', 'v': "وَكَذَٰلِكَ جَعَلْنَٰكُمْ أُمَّةًۭ وَسَطًۭا لِّتَكُونُوا۟ شُهَدَآءَ عَلَى ٱلنَّاسِ وَيَكُونَ ٱلرَّسُولُ عَلَيْكُمْ شَهِيدًۭا ۗ وَمَا جَعَلْنَا ٱلْقِبْلَةَ ٱلَّتِى كُنتَ عَلَيْهَآ إِلَّا لِنَعْلَمَ مَن يَتَّبِعُ ٱلرَّسُولَ مِمَّن يَنقَلِبُ عَلَىٰ عَقِبَيْهِ ۚ وَإِن كَانَتْ لَكَبِيرَةً إِلَّا عَلَى ٱلَّذِينَ هَدَى ٱللَّهُ ۗ وَمَا كَانَ ٱللَّهُ لِيُضِيعَ إِيمَٰنَكُمْ ۚ إِنَّ ٱللَّهَ بِٱلنَّاسِ لَرَءُوفٌۭ رَّحِيمٌۭ", 't': "«وكذلك» كما هديناكم إليه «جعلناكم» يا أمة محمد «أمة وسطا» خيارا عدولا «لتكونوا شهداء على الناس» يوم القيامة أنَّ رسلهم بلَّغتهم «ويكون الرسول عليكم شهيدا» أنه بلغكم «وما جعلنا» صيرنا «القبلة» لك الآن الجهة «التي كنت عليها» أولا وهي الكعبة وكان يصلى إليها فلما هاجر أمر باستقبال بيت المقدس تألُّفا لليهود فصلى إليه ستة أو سبعة عشر شهرا ثم حول «إلا لنعلم» علم ظهور «من يتبع الرسول» فيصدقه «ممن ينقلب على عقبيه» أي يرجع إلى الكفر شكا في الدين وظنا أن النبي في حيرة من أمره وقد ارتد لذلك جماعة «وإن» مخففة من الثقيلة واسمها محذوف أي وإنها «كانت» أي التولية إليها «لكبيرة» شاقة على الناس «إلا على الذين هدى الله» منهم «وما كان الله ليضيع إيمانكم» أي صلاتكم إلى بيت المقدس بل يثيبكم عليه لأن سبب نزولها السؤال عمن مات قبل التحويل «إن الله بالناس» المؤمنين «لرؤوف رحيم» في عدم إضاعة أعمالهم، والرأفةُ شدة الرحمة وقدَّم الأبلغ للفاصلة."},
  {'n': '144', 'v': "قَدْ نَرَىٰ تَقَلُّبَ وَجْهِكَ فِى ٱلسَّمَآءِ ۖ فَلَنُوَلِّيَنَّكَ قِبْلَةًۭ تَرْضَىٰهَا ۚ فَوَلِّ وَجْهَكَ شَطْرَ ٱلْمَسْجِدِ ٱلْحَرَامِ ۚ وَحَيْثُ مَا كُنتُمْ فَوَلُّوا۟ وُجُوهَكُمْ شَطْرَهُۥ ۗ وَإِنَّ ٱلَّذِينَ أُوتُوا۟ ٱلْكِتَٰبَ لَيَعْلَمُونَ أَنَّهُ ٱلْحَقُّ مِن رَّبِّهِمْ ۗ وَمَا ٱللَّهُ بِغَٰفِلٍ عَمَّا يَعْمَلُونَ", 't': "«قد» للتحقيق «نرى تقلُّب» تصرف «وجهك في» جهة «السماء» متطلعا إلى الوحي ومتشوقا للأمر باستقبال الكعبة وكان يود ذلك لأنها قبلة إبراهيم ولأنه دعى إلى إسلام العرب «فلنولينك» نحولنك «قبلة ترضاها» تحبها «فولِّ وجهك» استقبل في الصلاة «شطر» نحو «المسجد الحرام» أي الكعبة «وحيثما كنتم» خطاب للأمة «فولُّوا وجوهكم» في الصلاة «شطره وإن الذين أوتوا الكتاب ليعلمون أنه» أي التولي إلى الكعبة «الحق» الثابت «من ربهم» لما في كتبهم من نعت النبي من أنه يتحول إليها «وما الله بغافل عما تعملون» بالتاء أيها المؤمنون من امتثال أمره وبالياء أي اليهود من إنكار أمر القبلة."},
  {'n': '145', 'v': "وَلَئِنْ أَتَيْتَ ٱلَّذِينَ أُوتُوا۟ ٱلْكِتَٰبَ بِكُلِّ ءَايَةٍۢ مَّا تَبِعُوا۟ قِبْلَتَكَ ۚ وَمَآ أَنتَ بِتَابِعٍۢ قِبْلَتَهُمْ ۚ وَمَا بَعْضُهُم بِتَابِعٍۢ قِبْلَةَ بَعْضٍۢ ۚ وَلَئِنِ ٱتَّبَعْتَ أَهْوَآءَهُم مِّنۢ بَعْدِ مَا جَآءَكَ مِنَ ٱلْعِلْمِ ۙ إِنَّكَ إِذًۭا لَّمِنَ ٱلظَّٰلِمِينَ", 't': "«ولإن» لام قسم «أتيت الذين أوتوا الكتاب بكل آية» على صدقك في أمر القبلة «ما تبعوا» أي لا يتبعون «قبلتك» عناداً «وما أنت بتابع قبلتهم» قطع لطمعه في إسلامهم وطمعهم في عوده إليها «وما بعضهم بتابع قبلة بعض» أي اليهود قبلة النصارى وبالعكس «ولإن اتبعت أهواءهم» التي يدعونك إليها «من بعد ما جاءك من العلم» الوحي «إنك إذا» إن تبعتهم فرضا «لمن الظالمين»."},
  {'n': '146', 'v': "ٱلَّذِينَ ءَاتَيْنَٰهُمُ ٱلْكِتَٰبَ يَعْرِفُونَهُۥ كَمَا يَعْرِفُونَ أَبْنَآءَهُمْ ۖ وَإِنَّ فَرِيقًۭا مِّنْهُمْ لَيَكْتُمُونَ ٱلْحَقَّ وَهُمْ يَعْلَمُونَ", 't': "«الذين آتيناهم الكتاب يعرفونه» أي محمداً «كما يعرفون أبناءهم» بنعته في كتبهم قال ابن سلام: لقد عرفته حين رأيته كما أعرف ابني ومعرفتي لمحمد أشد «وإن فريقا منهم ليكتمون الحق» نعته «وهم يعلمون» هذا الذي أنت عليه."},
  {'n': '147', 'v': "ٱلْحَقُّ مِن رَّبِّكَ ۖ فَلَا تَكُونَنَّ مِنَ ٱلْمُمْتَرِينَ", 't': "«الحق» كائنا «من ربك فلا تكوننَّ من الممترين» الشاكين فيه أي من هذا النوع فهو أبلغ من أن لا تمتر."},
  {'n': '148', 'v': "وَلِكُلٍّۢ وِجْهَةٌ هُوَ مُوَلِّيهَا ۖ فَٱسْتَبِقُوا۟ ٱلْخَيْرَٰتِ ۚ أَيْنَ مَا تَكُونُوا۟ يَأْتِ بِكُمُ ٱللَّهُ جَمِيعًا ۚ إِنَّ ٱللَّهَ عَلَىٰ كُلِّ شَىْءٍۢ قَدِيرٌۭ", 't': "«ولكل» من الأمم «وجهة» قبلة «هو موليها» وجهه في صلاته وفي قراءة مُوَلاَّهَا «فاستبقوا الخيرات» بادروا إلى الطاعات وقبولها «أينما تكونوا يأت بكم الله جميعا» يجعلكم يوم القيامة فيجازيكم بأعمالكم «إن الله على كل شيء قدير»."},
  {'n': '149', 'v': "وَمِنْ حَيْثُ خَرَجْتَ فَوَلِّ وَجْهَكَ شَطْرَ ٱلْمَسْجِدِ ٱلْحَرَامِ ۖ وَإِنَّهُۥ لَلْحَقُّ مِن رَّبِّكَ ۗ وَمَا ٱللَّهُ بِغَٰفِلٍ عَمَّا تَعْمَلُونَ", 't': "«ومن حيث خرجت» لسفر «فولِّ وجهك شطر المسجد الحرام وإنه للحق من ربك وما الله بغافل عما تعلمون» بالياء والتاء تقدم مثله وكرره لبيان تساوي حكم السفر وغيره."},
  {'n': '150', 'v': "وَمِنْ حَيْثُ خَرَجْتَ فَوَلِّ وَجْهَكَ شَطْرَ ٱلْمَسْجِدِ ٱلْحَرَامِ ۚ وَحَيْثُ مَا كُنتُمْ فَوَلُّوا۟ وُجُوهَكُمْ شَطْرَهُۥ لِئَلَّا يَكُونَ لِلنَّاسِ عَلَيْكُمْ حُجَّةٌ إِلَّا ٱلَّذِينَ ظَلَمُوا۟ مِنْهُمْ فَلَا تَخْشَوْهُمْ وَٱخْشَوْنِى وَلِأُتِمَّ نِعْمَتِى عَلَيْكُمْ وَلَعَلَّكُمْ تَهْتَدُونَ", 't': "«ومن حيث خرجت فولِّ وجهك شطر المسجد الحرام وحيثما كنتم فولوا وجوهكم شطره» كرره للتأكيد «لئلا يكون للناس» اليهود أو المشركين «عليكم حجة» أي مجادلة في التولي إلى غيره أي لتنتفي مجادلتهم لكم من قول اليهود يجحد ديننا ويتبع قبلتنا وقول المشركين يدعي ملة إبراهيم ويخالف قبلته «إلا الذين ظلموا منهم» بالعناد فإنهم يقولون ما تحول إليها إلا ميلا إلى دين آبائه والاستثناء متصل والمعنى: لا يكون لأحد عليكم كلام إلا كلام هؤلاء «فلا تخشوهم» تخافوا جدالهم في التولي إليها «واخشوني» بامتثال أمري «ولأتم» عطف علي لئلا يكون «نعمتي عليكم» بالهداية إلى معالم دينكم «ولعلكم تهتدون» إلى الحق."},
  {'n': '151', 'v': "كَمَآ أَرْسَلْنَا فِيكُمْ رَسُولًۭا مِّنكُمْ يَتْلُوا۟ عَلَيْكُمْ ءَايَٰتِنَا وَيُزَكِّيكُمْ وَيُعَلِّمُكُمُ ٱلْكِتَٰبَ وَٱلْحِكْمَةَ وَيُعَلِّمُكُم مَّا لَمْ تَكُونُوا۟ تَعْلَمُونَ", 't': "«كما أرسلنا» متعلق بأتم أي إتماما كإتمامها بإرسالنا «فيكم رسولا منكم» محمد «يتلو عليكم آياتنا» القرآن «ويزكيكم» يطهركم من الشرك «ويعلمكم الكتاب» القرآن «والحكمة» ما فيه من الأحكام «ويعلمكم ما لم تكونوا تعلمون»."},
  {'n': '152', 'v': "فَٱذْكُرُونِىٓ أَذْكُرْكُمْ وَٱشْكُرُوا۟ لِى وَلَا تَكْفُرُونِ", 't': "«فاذكروني» بالصلاة والتسبيح ونحوه «أذكركم» قيل معناه أجازيكم وفي الحديث عن الله (من ذكرني في نفسه ذكرته في نفسي ومن ذكرني في ملأ ذكرته في ملأ خير من ملئه) «واشكروا لي» نعمتي بالطاعة «ولا تكفرون» بالمعصية."},
  {'n': '153', 'v': "يَٰٓأَيُّهَا ٱلَّذِينَ ءَامَنُوا۟ ٱسْتَعِينُوا۟ بِٱلصَّبْرِ وَٱلصَّلَوٰةِ ۚ إِنَّ ٱللَّهَ مَعَ ٱلصَّٰبِرِينَ", 't': "«يا أيها الذين آمنوا استعينوا» على الآخرة «بالصبر» على الطاعة والبلاء «والصلاة» خصها بالذكر لتكررها وعظمها «إن الله مع الصابرين» بالعون."},
  {'n': '154', 'v': "وَلَا تَقُولُوا۟ لِمَن يُقْتَلُ فِى سَبِيلِ ٱللَّهِ أَمْوَٰتٌۢ ۚ بَلْ أَحْيَآءٌۭ وَلَٰكِن لَّا تَشْعُرُونَ", 't': "«ولا تقولوا لمن يقتل في سبيل الله» هم «أموات بل» هم «أحياء» أرواحهم في حواصل طيور خضر تسرح في الجنة حيث شاءت لحديث بذلك «ولكن لا تشعرون» تعلمون ما هم فيه."},
  {'n': '155', 'v': "وَلَنَبْلُوَنَّكُم بِشَىْءٍۢ مِّنَ ٱلْخَوْفِ وَٱلْجُوعِ وَنَقْصٍۢ مِّنَ ٱلْأَمْوَٰلِ وَٱلْأَنفُسِ وَٱلثَّمَرَٰتِ ۗ وَبَشِّرِ ٱلصَّٰبِرِينَ", 't': "«ولنبلونكم بشيء من الخوف» للعدو «والجوع» القحط «ونقص من الأموال» بالهلاك «والأنفس» بالقتل والموت والأمراض «والثمرات» بالحوائج أي لنختبرنكم فننظر أتصبرون أم لا «وبشر الصابرين» على البلاء بالجنة."},
  {'n': '156', 'v': "ٱلَّذِينَ إِذَآ أَصَٰبَتْهُم مُّصِيبَةٌۭ قَالُوٓا۟ إِنَّا لِلَّهِ وَإِنَّآ إِلَيْهِ رَٰجِعُونَ", 't': "هم «الذين إذا أصابتهم مصيبة» بلاء «قالوا إنا لله» ملكا وعبيدا يفعل بنا ما يشاء «وإنا إليه راجعون» في الآخرة فيجازينا وفي الحديث (من استرجع عند المصيبة أجره الله فيها وأخلف الله عليه خيرا) وفيه أن مصباح النبي صلى الله عليه وسلم طفئ فاسترجع فقالت عائشة: إنما هذا مصباح فقال: (كل ما أساء المؤمن فهو مصيبة) رواه أبو داود في مراسيله."},
  {'n': '157', 'v': "أُو۟لَٰٓئِكَ عَلَيْهِمْ صَلَوَٰتٌۭ مِّن رَّبِّهِمْ وَرَحْمَةٌۭ ۖ وَأُو۟لَٰٓئِكَ هُمُ ٱلْمُهْتَدُونَ", 't': "«أولئك عليهم صلوات» مغفرة «من ربهم ورحمة» نعمة «وأولئك هم المهتدون» إلى الصواب."},
  {'n': '158', 'v': "۞ إِنَّ ٱلصَّفَا وَٱلْمَرْوَةَ مِن شَعَآئِرِ ٱللَّهِ ۖ فَمَنْ حَجَّ ٱلْبَيْتَ أَوِ ٱعْتَمَرَ فَلَا جُنَاحَ عَلَيْهِ أَن يَطَّوَّفَ بِهِمَا ۚ وَمَن تَطَوَّعَ خَيْرًۭا فَإِنَّ ٱللَّهَ شَاكِرٌ عَلِيمٌ", 't': "(إن الصفا والمروة) جبلان بمكة (من شعائر الله) أعلام دينه جمع شعيرة (فمن حج البيت أو اعتمر) أي تلبس بالحج أو العمرة وأصلهما القصد والزيارة (فلا جناح عليه) إثم عليه (أن يطوف) فيه إدغام التاء في الأصل في الطاء (بهما) بأن يسعى بينهما سبعا، نزلت لما كره المسلمون ذلك لأن أهل الجاهلية كانوا يطوفون بهما وعليهما صنمان يمسحونهما، وعن ابن عباس أن السعي غير فرض لما أفاده رفع الإثم من التخيير وقال الشافعي وغيره ركن، وبين صلى الله عليه وسلم فرضيته بقوله \"\" إن الله كتب عليكم السعي \"\" رواه البيهقي وغيره \"\" وقال ابدءوا بما بدأ الله به \"\" يعني الصفا رواه مسلم (ومن تطوع) وفي قراءة بالتحتية وتشديد الطاء مجزوما وفيه إدغام التاء فيها (خيرا) أي بخير أي عمل ما لم يجب عليه من طواف وغيره (فإن الله شاكر) لعمله بالإثابة عليه (عليم) به."},
  {'n': '159', 'v': "إِنَّ ٱلَّذِينَ يَكْتُمُونَ مَآ أَنزَلْنَا مِنَ ٱلْبَيِّنَٰتِ وَٱلْهُدَىٰ مِنۢ بَعْدِ مَا بَيَّنَّٰهُ لِلنَّاسِ فِى ٱلْكِتَٰبِ ۙ أُو۟لَٰٓئِكَ يَلْعَنُهُمُ ٱللَّهُ وَيَلْعَنُهُمُ ٱللَّٰعِنُونَ", 't': "ونزل في اليهود: «إن الذين يكتمون» الناس «ما أنزلنا من البينات والهدى» كآية الرجم ونعت محمد «من بعد ما بيَّناه للناس في الكتاب» التوراة «أولئك يلعنهم الله» يبعدهم من رحمته «ويلعنهم اللاعنون» الملائكة والمؤمنون أو كل شيء بالدعاء عليهم باللعنة."},
  {'n': '160', 'v': "إِلَّا ٱلَّذِينَ تَابُوا۟ وَأَصْلَحُوا۟ وَبَيَّنُوا۟ فَأُو۟لَٰٓئِكَ أَتُوبُ عَلَيْهِمْ ۚ وَأَنَا ٱلتَّوَّابُ ٱلرَّحِيمُ", 't': "«إلا الذين تابوا» رجعوا عن ذلك «وأصلحوا» عملهم «وبيَّنوا» ما كتموا «فأولئك أتوب عليهم» أقبل توبتهم «وأنا التواب الرحيم» بالمؤمنين."},
  {'n': '161', 'v': "إِنَّ ٱلَّذِينَ كَفَرُوا۟ وَمَاتُوا۟ وَهُمْ كُفَّارٌ أُو۟لَٰٓئِكَ عَلَيْهِمْ لَعْنَةُ ٱللَّهِ وَٱلْمَلَٰٓئِكَةِ وَٱلنَّاسِ أَجْمَعِينَ", 't': "«إن الذين كفروا وماتوا وهم كفار» حال «أولئك عليهم لعنة الله والملائكة والناس أجمعين» أي هم مستحقون ذلك في الدنيا والآخرة. والناس قيل: عام. وقيل: المؤمنون."},
  {'n': '162', 'v': "خَٰلِدِينَ فِيهَا ۖ لَا يُخَفَّفُ عَنْهُمُ ٱلْعَذَابُ وَلَا هُمْ يُنظَرُونَ", 't': "«خالدين فيها» أي اللعنة والنار المدلول بها عليها «لا يخفف عنهم العذاب» طرفة عين «ولا هم ينظرون» يمهلون لتوبة أو معذرة."},
  {'n': '163', 'v': "وَإِلَٰهُكُمْ إِلَٰهٌۭ وَٰحِدٌۭ ۖ لَّآ إِلَٰهَ إِلَّا هُوَ ٱلرَّحْمَٰنُ ٱلرَّحِيمُ", 't': "ونزل لما قالوا صف لنا ربك: «وإلهكم» المستحق للعبادة منكم «إِلهٌ واحد» لا نظير له في ذاته ولا في صفاته «لا إلهَ إلا هو» هو «الرحمن الرحيم» وطلبوا آيه على ذلك فنزل."},
  {'n': '164', 'v': "إِنَّ فِى خَلْقِ ٱلسَّمَٰوَٰتِ وَٱلْأَرْضِ وَٱخْتِلَٰفِ ٱلَّيْلِ وَٱلنَّهَارِ وَٱلْفُلْكِ ٱلَّتِى تَجْرِى فِى ٱلْبَحْرِ بِمَا يَنفَعُ ٱلنَّاسَ وَمَآ أَنزَلَ ٱللَّهُ مِنَ ٱلسَّمَآءِ مِن مَّآءٍۢ فَأَحْيَا بِهِ ٱلْأَرْضَ بَعْدَ مَوْتِهَا وَبَثَّ فِيهَا مِن كُلِّ دَآبَّةٍۢ وَتَصْرِيفِ ٱلرِّيَٰحِ وَٱلسَّحَابِ ٱلْمُسَخَّرِ بَيْنَ ٱلسَّمَآءِ وَٱلْأَرْضِ لَءَايَٰتٍۢ لِّقَوْمٍۢ يَعْقِلُونَ", 't': "إن في خلق السماوات والأرض» وما فيهما من العجائب «واختلاف الليل والنهار» بالذهاب والمجيء والزيادة والنقصان «والفلك» السفن «التي تجري في البحر» ولا ترسب موقرة «بما ينفع الناس» من التجارات والحمل «وما أنزل الله من السماء من ماء» مطر «فأحيا به الأرض» بالنبات «بعد موتها» يبسها «وبث» فرق ونشربه «فيها من كل دابة» لأنهم ينمون بالخصب الكائن عنه «وتصريف الرياح» تقليبها جنوبا وشمالا حارة وباردة «والسحاب» الغيم «المسخَّر» المذلَّل بأمر الله تعالى يسير إلى حيث شاء الله «بين السماء والأرض» بلا علاقة «لآيات» دالاّت على وحدانيته تعالى «لقوم يعقلون» يتدبرون."},
  {'n': '165', 'v': "وَمِنَ ٱلنَّاسِ مَن يَتَّخِذُ مِن دُونِ ٱللَّهِ أَندَادًۭا يُحِبُّونَهُمْ كَحُبِّ ٱللَّهِ ۖ وَٱلَّذِينَ ءَامَنُوٓا۟ أَشَدُّ حُبًّۭا لِّلَّهِ ۗ وَلَوْ يَرَى ٱلَّذِينَ ظَلَمُوٓا۟ إِذْ يَرَوْنَ ٱلْعَذَابَ أَنَّ ٱلْقُوَّةَ لِلَّهِ جَمِيعًۭا وَأَنَّ ٱللَّهَ شَدِيدُ ٱلْعَذَابِ", 't': "«ومن الناس من يتخذ من دون الله» أي غيره «أندادا» أصناما «يحبونهم» بالتعظيم والخضوع «كحب الله» أي كحبهم له «والذين آمنوا أشد حبا لله» من حبهم للأنداد لأنهم لا يعدلون عنه بحال ما، والكفار يعدلون في الشدة إلى الله «ولو يرى» تبصر يا محمد «الذين ظلموا» باتخاذ الأنداد «إذ يرون» بالبناء للفاعل والمفعول به يبصرون «العذاب» لرأيت أمرا عظيما وإذا بمعني إذا «أن» أي لأن «القوة» القدرة والغلبة «لله جميعا» حال «وأن الله شديد العذاب» وفي قراءة ترى والفاعل ضمير السامع، وقيل الذين ظلموا وهي بمعني يعلم وأن وما بعدها سدت مسد المفعولين وجواب لو محذوف والمعنى لو علموا في الدنيا شدة عذاب الله وأن القدرة لله وحده وقت معاينتهم له وهو يوم القيامة لما اتخذوا من دونه أندادا."},
  {'n': '166', 'v': "إِذْ تَبَرَّأَ ٱلَّذِينَ ٱتُّبِعُوا۟ مِنَ ٱلَّذِينَ ٱتَّبَعُوا۟ وَرَأَوُا۟ ٱلْعَذَابَ وَتَقَطَّعَتْ بِهِمُ ٱلْأَسْبَابُ", 't': "«إذ» بدل من إذ قبله «تبرَّأ الذين اتُبعوا» أي الرؤساء «من الذين اتَّبعوا» أي أنكروا إضلالهم «و» قد «رأوا العذاب وتقطعت» عطف تبرأ «بهم» عنهم «الأسباب» الوصل التي كانت بينهم في الدنيا من الأرحام والمودة."},
  {'n': '167', 'v': "وَقَالَ ٱلَّذِينَ ٱتَّبَعُوا۟ لَوْ أَنَّ لَنَا كَرَّةًۭ فَنَتَبَرَّأَ مِنْهُمْ كَمَا تَبَرَّءُوا۟ مِنَّا ۗ كَذَٰلِكَ يُرِيهِمُ ٱللَّهُ أَعْمَٰلَهُمْ حَسَرَٰتٍ عَلَيْهِمْ ۖ وَمَا هُم بِخَٰرِجِينَ مِنَ ٱلنَّارِ", 't': "«وقال الذين اتَّبعوا لو أن لنا كرَّة» رجعة إلى الدنيا «فنتبرَّأ منهم» أي المتبوعين «كما تبرءوا منا» اليوم ولو للتمني ونتبرأ جوابه «كذلك» أي كما أراهم شدة عذابه وتبرأ بعضهم من بعض «يريهم الله أعمالهم» السيئة «حسرات» حال ندامات «عليهم وما هم بخارجين من النار» بعد دخولها."},
  {'n': '168', 'v': "يَٰٓأَيُّهَا ٱلنَّاسُ كُلُوا۟ مِمَّا فِى ٱلْأَرْضِ حَلَٰلًۭا طَيِّبًۭا وَلَا تَتَّبِعُوا۟ خُطُوَٰتِ ٱلشَّيْطَٰنِ ۚ إِنَّهُۥ لَكُمْ عَدُوٌّۭ مُّبِينٌ", 't': "ونزل فيمن حرَّم السوائب ونحوها: «يا أيها الناس كلوا مما في الأرض حلالا» حال «طيبا» صفة مؤكدة أي مستلذاً «ولا تتبعوا خطوات» طرق «الشيطان» أي تزيينه «إنه لكم عدو مبين» بَيِّنُ العداوة."},
  {'n': '169', 'v': "إِنَّمَا يَأْمُرُكُم بِٱلسُّوٓءِ وَٱلْفَحْشَآءِ وَأَن تَقُولُوا۟ عَلَى ٱللَّهِ مَا لَا تَعْلَمُونَ", 't': "«إنما يأمركم بالسوء» الإثم «والفحشاء» القبيح شرعا «وأن تقولوا على الله ما لا تعلمون» من تحريم ما لم يحرم وغيره."},
  {'n': '170', 'v': "وَإِذَا قِيلَ لَهُمُ ٱتَّبِعُوا۟ مَآ أَنزَلَ ٱللَّهُ قَالُوا۟ بَلْ نَتَّبِعُ مَآ أَلْفَيْنَا عَلَيْهِ ءَابَآءَنَآ ۗ أَوَلَوْ كَانَ ءَابَآؤُهُمْ لَا يَعْقِلُونَ شَيْـًۭٔا وَلَا يَهْتَدُونَ", 't': "«وإذا قيل لهم» أي الكفار «اتبعوا ما أنزل الله» من التوحيد وتحليل الطيبات «قالوا» لا «بل نتبع ما ألفينا» وجدنا «عليه آباءنا» من عبادة الأصنام وتحريم السوائب والبحائر قال تعالى: «أ» يتبعونهم «وَلو كان آباؤهم لا يعقلون شيئا» من أمر الدين «ولا يهتدون» إلى الحق والهمزةُ للإنكار."},
  {'n': '171', 'v': "وَمَثَلُ ٱلَّذِينَ كَفَرُوا۟ كَمَثَلِ ٱلَّذِى يَنْعِقُ بِمَا لَا يَسْمَعُ إِلَّا دُعَآءًۭ وَنِدَآءًۭ ۚ صُمٌّۢ بُكْمٌ عُمْىٌۭ فَهُمْ لَا يَعْقِلُونَ", 't': "«ومثل» صفة «الذين كفروا» ومن يدعوهم إلى الهدي «كمثل الذي ينعق» يصوت «بما لا يسمع إلا دعاءً ونداءً» أي صوتا ولا يفهم معناه أي في سماع الموعظة وعدم تدبرها كالبهائم تسمع صوت راعيها ولا تفهمه، هم «صمٌ بكمٌ عميٌ فهم لا يعقلون» الموعظة."},
  {'n': '172', 'v': "يَٰٓأَيُّهَا ٱلَّذِينَ ءَامَنُوا۟ كُلُوا۟ مِن طَيِّبَٰتِ مَا رَزَقْنَٰكُمْ وَٱشْكُرُوا۟ لِلَّهِ إِن كُنتُمْ إِيَّاهُ تَعْبُدُونَ", 't': "«يا أيها الذين آمنوا كلوا من طيِّبات» حلالات «ما رزقناكم واشكروا لله» على ما أحل لكم «إن كنتم إياه تعبدون»."},
  {'n': '173', 'v': "إِنَّمَا حَرَّمَ عَلَيْكُمُ ٱلْمَيْتَةَ وَٱلدَّمَ وَلَحْمَ ٱلْخِنزِيرِ وَمَآ أُهِلَّ بِهِۦ لِغَيْرِ ٱللَّهِ ۖ فَمَنِ ٱضْطُرَّ غَيْرَ بَاغٍۢ وَلَا عَادٍۢ فَلَآ إِثْمَ عَلَيْهِ ۚ إِنَّ ٱللَّهَ غَفُورٌۭ رَّحِيمٌ", 't': "«إنما حرم عليكم الميتة» أي أكلها إذا الكلام فيه وكذا ما بعدها وهي ما لم يذك شرعا، وألحق بها بالسنة ما أبين من حيِّ وخُص منها السمك والجراد «والدم» أي المسفوح كما في الأنعام «ولحم الخنزير» خص اللحم لأنه معظم المقصود وغيره تبع له «وما أهل به لغير الله» أي ذبح على اسم غيره والإهلال رفع الصوت وكانوا يرفعونه عند الذبح لآلهتهم «فمن اضطر» أي ألجأته الضرورة إلى أكل شيء مما ذكر فأكله «غير باغ» خارج على المسلمين «ولا عاد» متعد عليهم بقطع الطريق «فلا إثم عليه» في أكله «إن الله غفور» لأوليائه «رحيم» بأهل طاعته حيث وسع لهم في ذلك وخرج الباغي والعادي ويلحق بهما كل عاص بسفره كالآبق والماكس فلا يحل لهم أكل شيء من ذلك ما لم يتوبوا وعليه الشافعي."},
  {'n': '174', 'v': "إِنَّ ٱلَّذِينَ يَكْتُمُونَ مَآ أَنزَلَ ٱللَّهُ مِنَ ٱلْكِتَٰبِ وَيَشْتَرُونَ بِهِۦ ثَمَنًۭا قَلِيلًا ۙ أُو۟لَٰٓئِكَ مَا يَأْكُلُونَ فِى بُطُونِهِمْ إِلَّا ٱلنَّارَ وَلَا يُكَلِّمُهُمُ ٱللَّهُ يَوْمَ ٱلْقِيَٰمَةِ وَلَا يُزَكِّيهِمْ وَلَهُمْ عَذَابٌ أَلِيمٌ", 't': "«إن الذين يكتمون ما أنزل الله من الكتاب» المشتمل على نعت محمد صلى الله عليه وسلم وهم اليهود «ويشترون به ثمنا قليلا» من الدنيا يأخذونه بدله من سفلتهم فلا يظهرونه خوف فوته عليهم «أولئك ما يأكلون في بطونهم إلا النار» لأنها مآلهم «ولا يكلمهم الله يوم القيامة» غضبا عليهم «ولا يزكيهم» يطهرهم من دنس الذنوب «ولهم عذاب اليم» مؤلم هو النار."},
  {'n': '175', 'v': "أُو۟لَٰٓئِكَ ٱلَّذِينَ ٱشْتَرَوُا۟ ٱلضَّلَٰلَةَ بِٱلْهُدَىٰ وَٱلْعَذَابَ بِٱلْمَغْفِرَةِ ۚ فَمَآ أَصْبَرَهُمْ عَلَى ٱلنَّارِ", 't': "«أولئك الذين اشتروا الضلالة بالهدى» آخذوها بدله في الدنيا «والعذاب بالمغفرة» المعدة لهم في الآخرة لو لم يكتموا «فما أصبرهم على النار» أي ما أشد صبرهم وهو تعجب للمؤمنين من ارتكابهم موجباتها من غير مبالاة وإلا فأيُّ صبر لهم."},
  {'n': '176', 'v': "ذَٰلِكَ بِأَنَّ ٱللَّهَ نَزَّلَ ٱلْكِتَٰبَ بِٱلْحَقِّ ۗ وَإِنَّ ٱلَّذِينَ ٱخْتَلَفُوا۟ فِى ٱلْكِتَٰبِ لَفِى شِقَاقٍۭ بَعِيدٍۢ", 't': "«ذلك» الذي ذكر من أكلهم النار وما بعده «بأن» بسبب أن «الله نزَّل الكتاب بالحق» متعلق بنزل فاختلفوا فيه حيث آمنوا ببعضه وكفروا ببعضه بكتمه «وإن الذين اختلفوا في الكتاب» بذلك وهم اليهود وقيل المشركون في القرآن حيث قال بعضهم شعر وبعضهم سحر وبعضهم كهانة «لفي شقاق» خلاف «بعيد» عن الحق."},
  {'n': '177', 'v': "۞ لَّيْسَ ٱلْبِرَّ أَن تُوَلُّوا۟ وُجُوهَكُمْ قِبَلَ ٱلْمَشْرِقِ وَٱلْمَغْرِبِ وَلَٰكِنَّ ٱلْبِرَّ مَنْ ءَامَنَ بِٱللَّهِ وَٱلْيَوْمِ ٱلْءَاخِرِ وَٱلْمَلَٰٓئِكَةِ وَٱلْكِتَٰبِ وَٱلنَّبِيِّۦنَ وَءَاتَى ٱلْمَالَ عَلَىٰ حُبِّهِۦ ذَوِى ٱلْقُرْبَىٰ وَٱلْيَتَٰمَىٰ وَٱلْمَسَٰكِينَ وَٱبْنَ ٱلسَّبِيلِ وَٱلسَّآئِلِينَ وَفِى ٱلرِّقَابِ وَأَقَامَ ٱلصَّلَوٰةَ وَءَاتَى ٱلزَّكَوٰةَ وَٱلْمُوفُونَ بِعَهْدِهِمْ إِذَا عَٰهَدُوا۟ ۖ وَٱلصَّٰبِرِينَ فِى ٱلْبَأْسَآءِ وَٱلضَّرَّآءِ وَحِينَ ٱلْبَأْسِ ۗ أُو۟لَٰٓئِكَ ٱلَّذِينَ صَدَقُوا۟ ۖ وَأُو۟لَٰٓئِكَ هُمُ ٱلْمُتَّقُونَ", 't': "«ليس البر أن تولوا وجوهكم» في الصلاة «قبل المشرق والمغرب» نزل ردا على اليهود والنصارى حيث زعموا ذلك «ولكن البرَّ» أي ذا البر وقرئ بفتح الباء أي البار «من آمن بالله واليوم الآخر والملائكة والكتاب» أي الكتب «والنبيين و آتى المال على» مع «حبه» له «ذوي القربى» القرابة «واليتامى والمساكين وابن السبيل» المسافر «والسائلين» الطالبين «وفي» فك «الرقاب» المكاتبين والأسرى «وأقام الصلاة وآتى الزكاة» المفروضة وما قبله في التطوع «والموفون بعهدهم إذا عاهدوا» الله أو الناس «والصابرين» نصب على المدح «في البأساء» شدة الفقر «والضراء» المرض «وحين البأس» وقت شدة القتال في سبيل الله «أولئك» الموصوفون بما ذكر «الذين صدقوا» في إيمانهم أو ادعاء البر «وأولئك هم المتقون» الله."},
  {'n': '178', 'v': "يَٰٓأَيُّهَا ٱلَّذِينَ ءَامَنُوا۟ كُتِبَ عَلَيْكُمُ ٱلْقِصَاصُ فِى ٱلْقَتْلَى ۖ ٱلْحُرُّ بِٱلْحُرِّ وَٱلْعَبْدُ بِٱلْعَبْدِ وَٱلْأُنثَىٰ بِٱلْأُنثَىٰ ۚ فَمَنْ عُفِىَ لَهُۥ مِنْ أَخِيهِ شَىْءٌۭ فَٱتِّبَاعٌۢ بِٱلْمَعْرُوفِ وَأَدَآءٌ إِلَيْهِ بِإِحْسَٰنٍۢ ۗ ذَٰلِكَ تَخْفِيفٌۭ مِّن رَّبِّكُمْ وَرَحْمَةٌۭ ۗ فَمَنِ ٱعْتَدَىٰ بَعْدَ ذَٰلِكَ فَلَهُۥ عَذَابٌ أَلِيمٌۭ", 't': "«يا أيها الذين منوا كُتب» فرض «عليكم القصاص» المماثلة «في القتلى» وصفا وفعلا «الحر» ولا يقتل بالعبد «والعبد بالعبد والأنثى بالأنثى» وبيَّنت السنة أن الذكر يقتل بها وأنه تعتبر المماثلة في الدين فلا يقتل مسلم ولو عبدا بكافر ولو حرا «فمن عفي له» من القاتلين «من» دم «أخيه» المقتول «شيء» بأن ترك القصاص منه، وتنكيرُ شيء يفيد سقوط القصاص بالعفو عن بعضه ومن بعض الورثة وفي ذكر أخيه تعطُّف داع إلى العفو وإيذان بأن القتل لا يقطع أخوة الإيمان ومن مبتدأ شرطية أو موصولة والخبر «فاتِّباع» أي فعل العافي إتباع للقاتل «بالمعروف» بأن يطالبه بالدية بلا عنف، وترتيب الإتباع على العفو يفيد أن الواجب أحدهما وهو أحد قولي الشافعي والثاني الواجب القصاص والدية بدل عنه فلو عفا ولم يسمها فلا شيء ورجح «و» على القاتل «أداء» الدية «إليه» أي العافي وهو الوارث «بإحسان» بلا مطل ولا بخس «ذلك» الحكم المذكور من جواز القصاص والعفو عنه على الدية «تخفيف» تسهيل «من ربكم» عليكم «ورحمة» بكم حيث وسَّع في ذلك ولم يحتم واحدا منهما كما حتم على اليهود القصاص وعلى النصارى الدية «فمن اعتدى» ظلم القاتل بأن قتله «بعد ذلك» أي العفو «فله عذاب أليم» مؤلم في الآخرة بالنار أو في الدنيا بالقتل."},
  {'n': '179', 'v': "وَلَكُمْ فِى ٱلْقِصَاصِ حَيَوٰةٌۭ يَٰٓأُو۟لِى ٱلْأَلْبَٰبِ لَعَلَّكُمْ تَتَّقُونَ", 't': "«ولكم في القصاص حياة» أي بقاء عظيم «يا أولي الألباب» ذوي العقول لأن القاتل إذا علم أنه يُقتل ارتدع فأحيا نفسه ومن أراد قتله فشرع «لعلكم تتقون» القتل مخافة القود."},
  {'n': '180', 'v': "كُتِبَ عَلَيْكُمْ إِذَا حَضَرَ أَحَدَكُمُ ٱلْمَوْتُ إِن تَرَكَ خَيْرًا ٱلْوَصِيَّةُ لِلْوَٰلِدَيْنِ وَٱلْأَقْرَبِينَ بِٱلْمَعْرُوفِ ۖ حَقًّا عَلَى ٱلْمُتَّقِينَ", 't': "«كتب» فرض «عليكم إذا حضر أحدكم الموت» أي أسبابه «إن ترك خيرا» مالا «الوصية» مرفوع بكتب ومتعلق بإذا إن كانت ظرفية ودال على جوابها إن كانت شرطية وجواب إن أي فليوص «للوالدين والأقربين بالمعروف» بالعدل بأن لا يزيد على الثلث ولا يفضل الغني «حقا» مصدر مؤكد لمضمون الجملة قبله «على المتقين» الله وهذا منسوخ بآية الميراث وبحديث: (لا وصية لوارث رواه الترمذي)."},
  {'n': '181', 'v': "فَمَنۢ بَدَّلَهُۥ بَعْدَمَا سَمِعَهُۥ فَإِنَّمَآ إِثْمُهُۥ عَلَى ٱلَّذِينَ يُبَدِّلُونَهُۥٓ ۚ إِنَّ ٱللَّهَ سَمِيعٌ عَلِيمٌۭ", 't': "«فمن بدَّله» أي الإيصاء من شاهد ووصي «بعد ما سمعه» علمه «فإنما إثمه» أي الإيصاء المبدل «على الذين يبدلونه» فيه إقامة الظاهر مقام المضمر «إن الله سميع» لقول الموصي «عليم» بفعل الوصي فمجاز عليه."},
  {'n': '182', 'v': "فَمَنْ خَافَ مِن مُّوصٍۢ جَنَفًا أَوْ إِثْمًۭا فَأَصْلَحَ بَيْنَهُمْ فَلَآ إِثْمَ عَلَيْهِ ۚ إِنَّ ٱللَّهَ غَفُورٌۭ رَّحِيمٌۭ", 't': "«فمن خاف من موص» مخففا ومثقلا «جنفا» ميلا عن الحق خطأ «أو إثما» بأن تعمَّد ذلك بالزيادة على الثلث أو تخصيص غني مثلا «فأصلح بينهم» بين الموصي والموصى له بالأمر بالعدل «فلا إثم عليه» في ذلك «إن الله غفور رحيم»."},
  {'n': '183', 'v': "يَٰٓأَيُّهَا ٱلَّذِينَ ءَامَنُوا۟ كُتِبَ عَلَيْكُمُ ٱلصِّيَامُ كَمَا كُتِبَ عَلَى ٱلَّذِينَ مِن قَبْلِكُمْ لَعَلَّكُمْ تَتَّقُونَ", 't': "«يا أيها الذين أمنوا كُتب» فرض «عليكم الصيام كما كتب على الذين من قبلكم» من الأمم «لعلكم تتقون» المعاصي فإنه يكسر الشهوة التي هي مبدؤها."},
  {'n': '184', 'v': "أَيَّامًۭا مَّعْدُودَٰتٍۢ ۚ فَمَن كَانَ مِنكُم مَّرِيضًا أَوْ عَلَىٰ سَفَرٍۢ فَعِدَّةٌۭ مِّنْ أَيَّامٍ أُخَرَ ۚ وَعَلَى ٱلَّذِينَ يُطِيقُونَهُۥ فِدْيَةٌۭ طَعَامُ مِسْكِينٍۢ ۖ فَمَن تَطَوَّعَ خَيْرًۭا فَهُوَ خَيْرٌۭ لَّهُۥ ۚ وَأَن تَصُومُوا۟ خَيْرٌۭ لَّكُمْ ۖ إِن كُنتُمْ تَعْلَمُونَ", 't': "«أيَّاما» نصب بالصيام أو يصوموا مقدرا «معدودات» أي قلائل أو مؤقتات بعدد معلوم وهي رمضان كما سيأتي وقلَّله تسهيلا على المكلفين «فمن كان منكم» حين شهوده «مريضا أو على سفر» أي مسافرا سفر القصر وأجهده الصوم في الحالين فأفطر «فعدَّة» فعليه عدة ما أفطر «من أيام أخر» يصومها بدله «وعلى الذين» لا «يطيقونه» لكبر أو مرض لا يرجى برؤه «فدية» هي «طعام مسكين» أي قدر ما يأكله في يومه وهو مدٌ من غالب قوت البلد لكل يوم، وفي قراءة بإضافة فدية وهي للبيان وقيل لا غير مقدرة وكانوا مخيرين في صدر الإسلام بين الصوم والفدية ثم نسخ بتعيين الصوم بقوله من شهد منكم الشهر فليصمه، قال ابن عباس: إلا الحامل والمرضع إذا أفطرتا خوفا على الولد فإنها باقية بلا نسخ في حقهما «فمن تطوع خيرا» بالزيادة على القدر المذكور في الفدية «فهو» أي التطوع «خير له، وأن تصوموا» مبتدأ خبره «خير لكم» من الإفطار والفدية «إن كنتم تعلمون» أنه خير لكم فافعلوه."},
  {'n': '185', 'v': "شَهْرُ رَمَضَانَ ٱلَّذِىٓ أُنزِلَ فِيهِ ٱلْقُرْءَانُ هُدًۭى لِّلنَّاسِ وَبَيِّنَٰتٍۢ مِّنَ ٱلْهُدَىٰ وَٱلْفُرْقَانِ ۚ فَمَن شَهِدَ مِنكُمُ ٱلشَّهْرَ فَلْيَصُمْهُ ۖ وَمَن كَانَ مَرِيضًا أَوْ عَلَىٰ سَفَرٍۢ فَعِدَّةٌۭ مِّنْ أَيَّامٍ أُخَرَ ۗ يُرِيدُ ٱللَّهُ بِكُمُ ٱلْيُسْرَ وَلَا يُرِيدُ بِكُمُ ٱلْعُسْرَ وَلِتُكْمِلُوا۟ ٱلْعِدَّةَ وَلِتُكَبِّرُوا۟ ٱللَّهَ عَلَىٰ مَا هَدَىٰكُمْ وَلَعَلَّكُمْ تَشْكُرُونَ", 't': "تلك الأيام «شهر رمضان الذي أنزل فيه القرآن» من اللوح المحفوظ إلى السماء الدنيا في ليلة القدر منه «هدى» حال هاديا من الضلالة «للناس وبينات» آيات واضحات «من الهدى» بما يهدي إلى الحق من الأحكام «و» من «الفرقان» مما يفرق بين الحق والباطل «فمن شهد» حضر «منكم الشهر فليصمه ومن كان مريضا أو على سفر فعدة من أيام أخر» تقدم مثله وكرر لئلا يتوهم نسخه بتعميم من شهد «يريد الله بكم اليسر ولا يريد بكم العسر» ولذا أباح لكم الفطر في المرض والسفر ولكون ذلك في معنى العلة أيضا للأمر بالصوم عطف عليه «ولتكملوا» بالتخفيف والتشديد «العدة» أي عدة صوم رمضان «ولتكبروا الله» عند إكمالها «على ما هداكم» أرشدكم لمعالم دينه «ولعلكم تشكرون» الله على ذلك."},
  {'n': '186', 'v': "وَإِذَا سَأَلَكَ عِبَادِى عَنِّى فَإِنِّى قَرِيبٌ ۖ أُجِيبُ دَعْوَةَ ٱلدَّاعِ إِذَا دَعَانِ ۖ فَلْيَسْتَجِيبُوا۟ لِى وَلْيُؤْمِنُوا۟ بِى لَعَلَّهُمْ يَرْشُدُونَ", 't': "وسأل جماعة النبي محمد صلى الله عليه وسلم أقريب ربُّنا فنناجيه أم بعيد فنناديه: فنزل «وإذا سألك عبادي عني فإني قريب» منهم بعلمي فأخبرهم بذلك «أجيب دعوة الداع إذا دعان» بإنالته ما سأل «فليستجيبوا لي» دعائي بالطاعة «وليؤمنوا» يداوموا على الإيمان «بي لعلهم يرشدون» يهتدون."},
  {'n': '187', 'v': "أُحِلَّ لَكُمْ لَيْلَةَ ٱلصِّيَامِ ٱلرَّفَثُ إِلَىٰ نِسَآئِكُمْ ۚ هُنَّ لِبَاسٌۭ لَّكُمْ وَأَنتُمْ لِبَاسٌۭ لَّهُنَّ ۗ عَلِمَ ٱللَّهُ أَنَّكُمْ كُنتُمْ تَخْتَانُونَ أَنفُسَكُمْ فَتَابَ عَلَيْكُمْ وَعَفَا عَنكُمْ ۖ فَٱلْـَٰٔنَ بَٰشِرُوهُنَّ وَٱبْتَغُوا۟ مَا كَتَبَ ٱللَّهُ لَكُمْ ۚ وَكُلُوا۟ وَٱشْرَبُوا۟ حَتَّىٰ يَتَبَيَّنَ لَكُمُ ٱلْخَيْطُ ٱلْأَبْيَضُ مِنَ ٱلْخَيْطِ ٱلْأَسْوَدِ مِنَ ٱلْفَجْرِ ۖ ثُمَّ أَتِمُّوا۟ ٱلصِّيَامَ إِلَى ٱلَّيْلِ ۚ وَلَا تُبَٰشِرُوهُنَّ وَأَنتُمْ عَٰكِفُونَ فِى ٱلْمَسَٰجِدِ ۗ تِلْكَ حُدُودُ ٱللَّهِ فَلَا تَقْرَبُوهَا ۗ كَذَٰلِكَ يُبَيِّنُ ٱللَّهُ ءَايَٰتِهِۦ لِلنَّاسِ لَعَلَّهُمْ يَتَّقُونَ", 't': "«أُحلَّ لكم ليلة الصيام الرفث» بمعنى الإفضاء «إلى نسائكم» بالجماع، نزل نسخا لما كان في صدر الإسلام على تحريمه وتحريم الأكل والشرب بعد العشاء «هن لباس لكم وأنتم لباس لهن» كناية عن تعانقهما أو احتياج كل منهما إلى صاحبه «علم الله أنكم كنتم تختانون» تخونون «أنفسكم» بالجماع ليلة الصيام وقع ذلك لعمر وغيره واعتذروا إلى النبي صلى الله عليه وسلم «فتاب عليكم» قبل توبتكم «وعفا عنكم فالآن» إذ أحل لكم «باشروهن» جامعوهن «وابتغوا» اطلبوا «ما كتب الله لكم» أي أباحه من الجماع أو قدره من الولد «وكلوا واشربوا» الليل كله «حتى يتبيَّن» يظهر «لكم الخيط الأبيض من الخيط الأسود من الفجر» أي الصادق بيان للخيط الأبيض وبيان الأسود محذوف أي من الليل شبه ما يبدو من البياض وما يمتد معه من الغبش بخيطين أبيض وأسود في الامتداد «ثم أتُّموا الصيام» من الفجر «إلى الليل» أي إلى دخوله بغروب الشمس «ولا تباشروهن» أي نساءكم «وأنتم عاكفون» مقيمون بنية الاعتكاف «في المساجد» متعلق بعاكفون نهيٌ لمن كان يخرج وهو معتكف فيجامع امرأته ويعود «تلك» الأحكام المذكورة «حدود الله» حدَّها لعباده ليقفوا عندها «فلا تقربوها» أبلغ من لا تعتدوها المعبر به في آية أخرى «كذلك» كما بيَّن لكم ما ذكر «يُبيِّن الله آياته للناس لعلهم يتقون» محارمه."},
  {'n': '188', 'v': "وَلَا تَأْكُلُوٓا۟ أَمْوَٰلَكُم بَيْنَكُم بِٱلْبَٰطِلِ وَتُدْلُوا۟ بِهَآ إِلَى ٱلْحُكَّامِ لِتَأْكُلُوا۟ فَرِيقًۭا مِّنْ أَمْوَٰلِ ٱلنَّاسِ بِٱلْإِثْمِ وَأَنتُمْ تَعْلَمُونَ", 't': "«ولا تأكلوا أموالكم بينكم» أي يأكل بعضكم مال بعض «بالباطل» الحرام شرعا كالسرقة والغصب «و» لا «تُدلوا» تلقوا «بها» أي بحكومتها أو بالأموال رشوة «إلى الحكام لتأكلوا» بالتحاكم «فريقا» طائفة «من أموال الناس» متلبسين «بالإثم وأنتم تعلمون» أنكم مبطلون."},
  {'n': '189', 'v': "۞ يَسْـَٔلُونَكَ عَنِ ٱلْأَهِلَّةِ ۖ قُلْ هِىَ مَوَٰقِيتُ لِلنَّاسِ وَٱلْحَجِّ ۗ وَلَيْسَ ٱلْبِرُّ بِأَن تَأْتُوا۟ ٱلْبُيُوتَ مِن ظُهُورِهَا وَلَٰكِنَّ ٱلْبِرَّ مَنِ ٱتَّقَىٰ ۗ وَأْتُوا۟ ٱلْبُيُوتَ مِنْ أَبْوَٰبِهَا ۚ وَٱتَّقُوا۟ ٱللَّهَ لَعَلَّكُمْ تُفْلِحُونَ", 't': "«يسألونك» يا محمد «عن الأهلة» جمع هلال لمَ تبدو دقيقة ثم تزيد حتى تمتلئ نورا ثم تعود كما بدت ولا تكون على حالة واحدة كالشمس «قل» لهم «هي مواقيت» جمع ميقات «للناس» يعلمون بها أوقات زرعهم ومتاجرهم وعُدد نسائهم وصيامهم وإفطارهم «والحج» عطف على الناس أي يعلم بها وقته فلو استمرت على حالة لم يعرف ذلك «وليس البر بأن تأتوا البيوت من ظهورها» في الإحرام كغيره بأن تنقبوا فيها نقبا تدخلون منه وتخرجون وتتركوا الباب وكانوا يفعلون ذلك ويزعمونه برّا «ولكنَّ البرَّ» أي ذا البِر «من اتقى» الله بترك مخالفته «وأتوا البيوت من أبوابها» في الإحرام «واتقوا الله لعلكم تفلحون» تفوزون."},
  {'n': '190', 'v': "وَقَٰتِلُوا۟ فِى سَبِيلِ ٱللَّهِ ٱلَّذِينَ يُقَٰتِلُونَكُمْ وَلَا تَعْتَدُوٓا۟ ۚ إِنَّ ٱللَّهَ لَا يُحِبُّ ٱلْمُعْتَدِينَ", 't': "ولما صُدَّ محمد صلى الله عليه وسلم عن البيت عام الحديبية وصالح الكفار على أن يعود العام القابل ويُخلوا له مكة ثلاثة أيام وتجهز لعمرة القضاء وخافوا أن لا تفي قريش ويقاتلوهم وكره المسلمون قتالهم في الحرم والإحرام والشهر الحرام نزل «وقاتلوا في سبيل الله» أي لإعلاء دينه «الذين يقاتلونكم» الكفار «ولا تعتدوا» عليهم بالابتداء بالقتال «إن الله لا يحب المعتدين» المتجاوزين ما حد لهم وهذا منسوخ بآية براءة أو بقوله."},
  {'n': '191', 'v': "وَٱقْتُلُوهُمْ حَيْثُ ثَقِفْتُمُوهُمْ وَأَخْرِجُوهُم مِّنْ حَيْثُ أَخْرَجُوكُمْ ۚ وَٱلْفِتْنَةُ أَشَدُّ مِنَ ٱلْقَتْلِ ۚ وَلَا تُقَٰتِلُوهُمْ عِندَ ٱلْمَسْجِدِ ٱلْحَرَامِ حَتَّىٰ يُقَٰتِلُوكُمْ فِيهِ ۖ فَإِن قَٰتَلُوكُمْ فَٱقْتُلُوهُمْ ۗ كَذَٰلِكَ جَزَآءُ ٱلْكَٰفِرِينَ", 't': "«واقتلوهم حيث ثقفتموهم» وجدتموهم «وأخرجوهم من حيث أخرجوكم» أي من مكة وقد فعل بهم ذلك عام الفتح «والفتنة» الشرك منهم «أشد» أعظم «من القتل» لهم في الحرم أو الإحرام والذي استعظمتموه «ولا تقاتلوهم عند المسجد الحرام» أي في الحرم «حتى يقاتلوكم فيه فإن قاتلوكم» فيه «فاقتلوهم» فيه، وفي قراءة بلا ألف في الأفعال الثلاثة «كذلك» القتل والإخراج «جزاء الكافرين»."},
  {'n': '192', 'v': "فَإِنِ ٱنتَهَوْا۟ فَإِنَّ ٱللَّهَ غَفُورٌۭ رَّحِيمٌۭ", 't': "«فإن انتهوا» عن الكفر وأسلموا «فإن الله غفور» لهم «رحيم» بهم."},
  {'n': '193', 'v': "وَقَٰتِلُوهُمْ حَتَّىٰ لَا تَكُونَ فِتْنَةٌۭ وَيَكُونَ ٱلدِّينُ لِلَّهِ ۖ فَإِنِ ٱنتَهَوْا۟ فَلَا عُدْوَٰنَ إِلَّا عَلَى ٱلظَّٰلِمِينَ", 't': "«وقاتلوهم حتى لا تكون» توجد «فتنة» شرك «ويكون الدين» العبادة «لله» وحده لا يعبد سواه «فإن انتهوا» عن الشرك فلا تعتدوا عليهم دل على هذا «فلا عدوان» اعتداء بقتل أو غيره «إلا على الظالمين» ومن انتهى فليس بظالم فلا عدوان عليه."},
  {'n': '194', 'v': "ٱلشَّهْرُ ٱلْحَرَامُ بِٱلشَّهْرِ ٱلْحَرَامِ وَٱلْحُرُمَٰتُ قِصَاصٌۭ ۚ فَمَنِ ٱعْتَدَىٰ عَلَيْكُمْ فَٱعْتَدُوا۟ عَلَيْهِ بِمِثْلِ مَا ٱعْتَدَىٰ عَلَيْكُمْ ۚ وَٱتَّقُوا۟ ٱللَّهَ وَٱعْلَمُوٓا۟ أَنَّ ٱللَّهَ مَعَ ٱلْمُتَّقِينَ", 't': "«الشهر الحرام» المحرم مقابل «بالشهر الحرام» فكلما قاتلوكم فيه فاقتلوهم في مثله رد لاستعظام المسلمين ذلك «والحرمات» جمع حرمة ما يجب احترامه «قصاص» أي يقتص بمثلها إذا انتهكت «فمن اعتدى عليكم» بالقتال في الحرم أو الإحرام أو الشهر الحرام «فاعتدوا عليه بمثل ما اعتدى عليكم» سمى مقابلته اعتداء لشبهها بالمقابل به في الصورة «واتقوا الله» في الانتصار وترك الاعتداء «واعلموا أن الله مع المتقين» بالعون والنصر."},
  {'n': '195', 'v': "وَأَنفِقُوا۟ فِى سَبِيلِ ٱللَّهِ وَلَا تُلْقُوا۟ بِأَيْدِيكُمْ إِلَى ٱلتَّهْلُكَةِ ۛ وَأَحْسِنُوٓا۟ ۛ إِنَّ ٱللَّهَ يُحِبُّ ٱلْمُحْسِنِينَ", 't': "«وأنفقوا في سبيل الله» طاعته بالجهاد وغيره «ولا تلقوا بأيديكم» أي أنفسكم والباء زائدة «إلى التهلكة» الهلاك بالإمساك عن النفقة في الجهاد أو تركه لأنه يقوي العدو عليكم «وأحسنوا» بالنفقة وغيرها «إن الله يحب المحسنين» أي يثيبهم."},
  {'n': '196', 'v': "وَأَتِمُّوا۟ ٱلْحَجَّ وَٱلْعُمْرَةَ لِلَّهِ ۚ فَإِنْ أُحْصِرْتُمْ فَمَا ٱسْتَيْسَرَ مِنَ ٱلْهَدْىِ ۖ وَلَا تَحْلِقُوا۟ رُءُوسَكُمْ حَتَّىٰ يَبْلُغَ ٱلْهَدْىُ مَحِلَّهُۥ ۚ فَمَن كَانَ مِنكُم مَّرِيضًا أَوْ بِهِۦٓ أَذًۭى مِّن رَّأْسِهِۦ فَفِدْيَةٌۭ مِّن صِيَامٍ أَوْ صَدَقَةٍ أَوْ نُسُكٍۢ ۚ فَإِذَآ أَمِنتُمْ فَمَن تَمَتَّعَ بِٱلْعُمْرَةِ إِلَى ٱلْحَجِّ فَمَا ٱسْتَيْسَرَ مِنَ ٱلْهَدْىِ ۚ فَمَن لَّمْ يَجِدْ فَصِيَامُ ثَلَٰثَةِ أَيَّامٍۢ فِى ٱلْحَجِّ وَسَبْعَةٍ إِذَا رَجَعْتُمْ ۗ تِلْكَ عَشَرَةٌۭ كَامِلَةٌۭ ۗ ذَٰلِكَ لِمَن لَّمْ يَكُنْ أَهْلُهُۥ حَاضِرِى ٱلْمَسْجِدِ ٱلْحَرَامِ ۚ وَٱتَّقُوا۟ ٱللَّهَ وَٱعْلَمُوٓا۟ أَنَّ ٱللَّهَ شَدِيدُ ٱلْعِقَابِ", 't': "«وأتموا الحج والعمرة لله» أدُّوهما بحقوقهما «فإن أُحصرتم» مُنعتم عن إتمامها بعدوِّ «فما استيسر» تيسَّر «من الهدي» عليكم وهو شاة «ولا تحلقوا رؤوسكم» أي لا تتحللوا «حتى يبلغ الهدي» المذكور «محله» حيث يحل ذبحه وهو مكان الإحصار عند الشافعي فيذبح فيه بنية التحلل ويفرَّق على مساكينه ويحلق وبه يحصل التحلل «فمن كان منكم مريضا أو به أذى من رأسه» كقمل وصداع فحلق في الإحرام «ففدية» عليه «من صيام» ثلاثة أيام «أو صدقة» بثلاثة أصوع من غالب قوت البلد على ستة مساكين «أونسك» أي ذبح شاة وأو للتخيير وألحق به من حلق لغير عذر أنه أولى بالكفارة وكذا من استمتع بغير الحلق كالطيب واللبس والدهن لعذر أو غيره «فإذا أمنتم» العدو بأن ذهب أو لم يكن «فمن تمتع» استمتع «بالعمرة» أي بسبب فراغه منها بمحظورات الإحرام «إلى الحج» أي إلى الإحرام به بأن يكون أحرم بها في أشهره «فما استيسر» تيسر «من الهدي» عليه وهو شاة يذبحها بعد الإحرام به والأفضل يوم النحر «فمن لم يجد» الهدي لفقده أو فقد ثمنه «فصيامُ» أي فعليه صيام «ثلاثة أيام في الحج» أي في حال الإحرام به فيجب حينئذ أن يُحْرمَ قبل السابع من ذي الحجة والأفضل قبل السادس لكراهة صوم يوم عرفة ولا يجوز صومها أيام التشريق على أصح قولي الشافعي «وسبعة إذا رجعتم» إلى وطنكم مكة أو غيرها وقيل إذا فرغتم من أعمال الحج وفيه التفات عن الغيبة «تلك عشرة كاملة» جملة تأكيد لما قبلها «ذلك» الحكم المذكور من وجوب الهدي أو الصيام على من تمتع «لمن لم يكن أهله حاضري المسجد الحرام» بأن لم يكونوا على دون مرحلتين من الحرم عند الشافعي فإن كان فلا دم عليه ولا صيام وإن تمتع فعليه ذلك وهو أحد وجهين عند الشافعي والثاني لا والأهل كناية عن النفس وألحق بالتمتع فيما ذكر بالسنة القارن وهو من أحرم بالعمرة والحج معا أو يدخل الحج عليها قبل الطواف «واتقوا الله» فيما يأمركم به وينهاكم عنه «واعلموا أن الله شديد العقاب» لمن خالفه."},
  {'n': '197', 'v': "ٱلْحَجُّ أَشْهُرٌۭ مَّعْلُومَٰتٌۭ ۚ فَمَن فَرَضَ فِيهِنَّ ٱلْحَجَّ فَلَا رَفَثَ وَلَا فُسُوقَ وَلَا جِدَالَ فِى ٱلْحَجِّ ۗ وَمَا تَفْعَلُوا۟ مِنْ خَيْرٍۢ يَعْلَمْهُ ٱللَّهُ ۗ وَتَزَوَّدُوا۟ فَإِنَّ خَيْرَ ٱلزَّادِ ٱلتَّقْوَىٰ ۚ وَٱتَّقُونِ يَٰٓأُو۟لِى ٱلْأَلْبَٰبِ", 't': "«الحج» وقته «أشهر معلومات» شوال وذو القعدة وعشر ليال من ذي الحجة وقيل كله «فمن فرض» على نفسه «فيهن الحج» بالإحرام به «فلا رفث» جماع فيه «ولا فسوق» معاص «ولا جدالَ» خصام «في الحج» وفي قراءة بفتح الأولين والمراد في الثلاثة النهي «وما تفعلوا من خير» كصدقة «يعلمه الله» فيجازيكم به، ونزل في أهل اليمن وكانوا يحجون بلا زاد فيكون كلاًّ على الناس: «وتزودوا» ما يبلغكم لسفركم «فإن خير الزاد التقوى» ما يُتَّقى به سؤال الناس وغيره «واتقون يا أولي الألباب» ذوي العقول."},
  {'n': '198', 'v': "لَيْسَ عَلَيْكُمْ جُنَاحٌ أَن تَبْتَغُوا۟ فَضْلًۭا مِّن رَّبِّكُمْ ۚ فَإِذَآ أَفَضْتُم مِّنْ عَرَفَٰتٍۢ فَٱذْكُرُوا۟ ٱللَّهَ عِندَ ٱلْمَشْعَرِ ٱلْحَرَامِ ۖ وَٱذْكُرُوهُ كَمَا هَدَىٰكُمْ وَإِن كُنتُم مِّن قَبْلِهِۦ لَمِنَ ٱلضَّآلِّينَ", 't': "«ليس عليكم جناح» في «أن تبتغوا» تطلبوا «فضلا» رزقا «من ربكم» بالتجارة في الحج نزل ردا لكراهيتهم ذلك «فإذا أفضتم» دفعتم «من عرفات» بعد الوقوف بها «فاذكروا الله» بعد المبيت بمزدلفة بالتلبية والتهليل والدعاء «عند المشعر الحرام» هو جبل في آخر المزدلفة يقال له قزح وفي الحديث أنه صلى الله عليه وسلم وقف به يذكر الله ويدعو حتى أسفر جدا رواه مسلم «واذكروه كما هداكم» لمعالم دينه ومناسك حجه والكاف للتعليل «وإن» مخففة «كنتم من قبله» قبل هداه «لمن الضالين»."},
  {'n': '199', 'v': "ثُمَّ أَفِيضُوا۟ مِنْ حَيْثُ أَفَاضَ ٱلنَّاسُ وَٱسْتَغْفِرُوا۟ ٱللَّهَ ۚ إِنَّ ٱللَّهَ غَفُورٌۭ رَّحِيمٌۭ", 't': "«ثم أفيضوا» يا قريش «من حيث أفاض الناس» أي من عرفة بأن تقفوا بها معهم وكانوا يقفون بالمزدلفه ترفعا عن الوقوف معهم وثم للترتيب في الذكر «واستغفروا الله» من ذنوبكم إن الله غفور» للمؤمنين «رحيم» بهم."},
  {'n': '200', 'v': "فَإِذَا قَضَيْتُم مَّنَٰسِكَكُمْ فَٱذْكُرُوا۟ ٱللَّهَ كَذِكْرِكُمْ ءَابَآءَكُمْ أَوْ أَشَدَّ ذِكْرًۭا ۗ فَمِنَ ٱلنَّاسِ مَن يَقُولُ رَبَّنَآ ءَاتِنَا فِى ٱلدُّنْيَا وَمَا لَهُۥ فِى ٱلْءَاخِرَةِ مِنْ خَلَٰقٍۢ", 't': "«فإذا قضيتم» أدَّيتم «مناسككم» عبادات حجكم بأن رميتم جمرة العقبة وطفتم واستقررتم بمنى «فاذكروا الله» بالتكبير والثناء «كذكركم آباءكم» كما كنتم تذكرونهم عند فراغ حجكم بالمفاخرة «أو أشد ذكرا» من ذكركم إياهم ونصب أشد على الحال من ذكر المنصوب باذكروا إذ لو تأخر عنه لكان صفة له «فمن الناس من يقول ربنا آتنا» نصيبا «في الدنيا» فيؤتاه فيها «وماله في الآخرة من خلاق» نصيب."},
  {'n': '201', 'v': "وَمِنْهُم مَّن يَقُولُ رَبَّنَآ ءَاتِنَا فِى ٱلدُّنْيَا حَسَنَةًۭ وَفِى ٱلْءَاخِرَةِ حَسَنَةًۭ وَقِنَا عَذَابَ ٱلنَّارِ", 't': "«ومنهم من يقول ربنا آتنا في الدنيا حسنة» نعمة «وفي الآخرة حسنة» هي الجنة «وقنا عذاب النار» بعدم دخولها وهذا بيان لما كان عليه المشركون ولحال المؤمنين والقصد به الحث على طلب خير الدارين كما وعد بالثواب عليه بقوله."},
  {'n': '202', 'v': "أُو۟لَٰٓئِكَ لَهُمْ نَصِيبٌۭ مِّمَّا كَسَبُوا۟ ۚ وَٱللَّهُ سَرِيعُ ٱلْحِسَابِ", 't': "«أولئك لهم نصيب» ثواب «مـ» من أجل «ما كسبوا» عملوا من الحج والدعاء «والله سريع الحساب» يحاسب الخلق كلهم في قدر نصف نهار من أيام الدنيا لحديث بذلك."},
  {'n': '203', 'v': "۞ وَٱذْكُرُوا۟ ٱللَّهَ فِىٓ أَيَّامٍۢ مَّعْدُودَٰتٍۢ ۚ فَمَن تَعَجَّلَ فِى يَوْمَيْنِ فَلَآ إِثْمَ عَلَيْهِ وَمَن تَأَخَّرَ فَلَآ إِثْمَ عَلَيْهِ ۚ لِمَنِ ٱتَّقَىٰ ۗ وَٱتَّقُوا۟ ٱللَّهَ وَٱعْلَمُوٓا۟ أَنَّكُمْ إِلَيْهِ تُحْشَرُونَ", 't': "«واذكروا الله» بالتكبير عند رمي الجمرات «في أيام معدودات» أي أيام التشريق الثلاثة «فمن تعجل» أي استعجل بالنفر من منى «في يومين» أي في ثاني أيام التشريق بعد رمي جماره «فلا إثم عليه» بالتعجيل «ومن تأخر» بها حتى بات ليلة الثالث ورمى جماره «فلا إثم عليه» بذلك أي هم مخيَّرون في ذلك ونفي الإثم «لمن اتقى» الله في حجه لأنه الحاج في الحقيقة «واتقوا الله واعلموا أنكم إليه تحشرون» في الآخرة فيجازيكم بأعمالكم."},
  {'n': '204', 'v': "وَمِنَ ٱلنَّاسِ مَن يُعْجِبُكَ قَوْلُهُۥ فِى ٱلْحَيَوٰةِ ٱلدُّنْيَا وَيُشْهِدُ ٱللَّهَ عَلَىٰ مَا فِى قَلْبِهِۦ وَهُوَ أَلَدُّ ٱلْخِصَامِ", 't': "«ومن الناس من يعجبك قوله في الحياة الدنيا» ولا يعجبك في الآخرة مخالفته لاعتقاده «ويُشهد الله على ما في قلبه» أنه موافق لقوله «وهو ألدُّ الخصام» شديد الخصومة لك ولأتباعك لعداوته لك وهو الأخنس بن شريق كان منافقاً حلو الكلام للنبي صلى الله عليه وسلم يحلف أنه مؤمن به ومحب له فيدنى مجلسه فأكذبه الله في ذلك ومر بزرع وَحُمُر لبعض المسلمين فأحرقه وعقرها ليلا كما قال تعالى."},
  {'n': '205', 'v': "وَإِذَا تَوَلَّىٰ سَعَىٰ فِى ٱلْأَرْضِ لِيُفْسِدَ فِيهَا وَيُهْلِكَ ٱلْحَرْثَ وَٱلنَّسْلَ ۗ وَٱللَّهُ لَا يُحِبُّ ٱلْفَسَادَ", 't': "«وإذا تولى» انصرف عنك «سعى» مشى «في الأرض ليفسد فيها ويهلك الحرث والنسل» من جملة الفساد «والله لا يحب الفساد» أي لا يرضى به."},
  {'n': '206', 'v': "وَإِذَا قِيلَ لَهُ ٱتَّقِ ٱللَّهَ أَخَذَتْهُ ٱلْعِزَّةُ بِٱلْإِثْمِ ۚ فَحَسْبُهُۥ جَهَنَّمُ ۚ وَلَبِئْسَ ٱلْمِهَادُ", 't': "«وإذا قيل له اتق الله» في فعلك «أخذته العزة» حملته الأنفة والحمية على العمل «بالإثم» الذي أُمر باتقائه «فحسبه» كافيه «جهنم ولبئس المهاد» الفراش هي."},
  {'n': '207', 'v': "وَمِنَ ٱلنَّاسِ مَن يَشْرِى نَفْسَهُ ٱبْتِغَآءَ مَرْضَاتِ ٱللَّهِ ۗ وَٱللَّهُ رَءُوفٌۢ بِٱلْعِبَادِ", 't': "«ومن الناس من يشري» يبيع «نفسه» أي يبذلها في طاعة الله «ابتغاء» طلب «مرضات الله» رضاه، وهو صهيب لما آذاه المشركون هاجر إلى المدينة وترك لهم ماله «والله رءووف بالعباد» حيث أرشدهم لما فيه رضاه."},
  {'n': '208', 'v': "يَٰٓأَيُّهَا ٱلَّذِينَ ءَامَنُوا۟ ٱدْخُلُوا۟ فِى ٱلسِّلْمِ كَآفَّةًۭ وَلَا تَتَّبِعُوا۟ خُطُوَٰتِ ٱلشَّيْطَٰنِ ۚ إِنَّهُۥ لَكُمْ عَدُوٌّۭ مُّبِينٌۭ", 't': "ونزل في عبد الله بن سلام وأصحابه لما عظموا السبت وكرهوا الإبل بعد الإسلام «يا أيها الذين آمنوا ادخلوا في السَّلم» بفتح السين وكسرها الإسلام «كافة» حال من السلم أي في جميع شرائعه «ولا تتبعوا خطوات» طرق «الشيطان» أي تزيينه بالتفريق «إنه لكم عدو مبين» بيِّن العداوة."},
  {'n': '209', 'v': "فَإِن زَلَلْتُم مِّنۢ بَعْدِ مَا جَآءَتْكُمُ ٱلْبَيِّنَٰتُ فَٱعْلَمُوٓا۟ أَنَّ ٱللَّهَ عَزِيزٌ حَكِيمٌ", 't': "«فإن زللتم» ملتم عن الدخول في جميعه «من بعد ما جاءتكم البينات» الحجج الظاهرة على أنه حق «فاعلموا أن الله عزيز» لا يعجزه شيء عن انتقامه منكم «حكيم» في صنعه."},
  {'n': '210', 'v': "هَلْ يَنظُرُونَ إِلَّآ أَن يَأْتِيَهُمُ ٱللَّهُ فِى ظُلَلٍۢ مِّنَ ٱلْغَمَامِ وَٱلْمَلَٰٓئِكَةُ وَقُضِىَ ٱلْأَمْرُ ۚ وَإِلَى ٱللَّهِ تُرْجَعُ ٱلْأُمُورُ", 't': "«هل» ما «ينظرون» ينتظر التاركون الدخول فيه «إلا أن يأتيهم الله» أي أمره كقوله أو يأتي أمر ربك أي عذابه «في ظلل» جمع ظلة «من الغمام» السحاب «والملائكةُ وقضي الأمر» تم أمر هلاكهم «وإلى الله ترجع الأمور» بالبناء للمفعول والفاعل في الآخرة فيجازي كلا بعمله."},
  {'n': '211', 'v': "سَلْ بَنِىٓ إِسْرَٰٓءِيلَ كَمْ ءَاتَيْنَٰهُم مِّنْ ءَايَةٍۭ بَيِّنَةٍۢ ۗ وَمَن يُبَدِّلْ نِعْمَةَ ٱللَّهِ مِنۢ بَعْدِ مَا جَآءَتْهُ فَإِنَّ ٱللَّهَ شَدِيدُ ٱلْعِقَابِ", 't': "«سل» يا محمد «بني إسرائيل» تبكيتا «كم آتيناهم» كم استفهامية معلقة سل عن المفعول الثاني وهي ثاني مفعول آتينا ومميزها «من آية بينة» ظاهرة كفلق البحر وإنزال المن والسلوى فبدَّلوها كفرا «ومن يبدِّل نعمه الله» أي ما أنعم به عليه من الآيات لأنها سبب الهداية «من بعد ما جاءته» كفرا «فإن الله شديد العقاب» له."},
  {'n': '212', 'v': "زُيِّنَ لِلَّذِينَ كَفَرُوا۟ ٱلْحَيَوٰةُ ٱلدُّنْيَا وَيَسْخَرُونَ مِنَ ٱلَّذِينَ ءَامَنُوا۟ ۘ وَٱلَّذِينَ ٱتَّقَوْا۟ فَوْقَهُمْ يَوْمَ ٱلْقِيَٰمَةِ ۗ وَٱللَّهُ يَرْزُقُ مَن يَشَآءُ بِغَيْرِ حِسَابٍۢ", 't': "«زُيِّن للَّذين كفروا» من أهل مكة «الحياة الدنيا» بالتمويه فأحبوها «و» هم «يسخرون من الذين آمنوا» لفقرهم كبلال وعمَّار وصهيب أي يستهزءون بهم ويتعالوْن عليهم بالمال «والذين اتقوا» الشرك وهم هؤلاء «فوقهم يوم القيامة والله يرزق من يشاء بغير حساب» أي رزقا واسعا في الآخرة أو الدنيا بأن يملك المسخور منهم أموال الساخرين ورقابهم."},
  {'n': '213', 'v': "كَانَ ٱلنَّاسُ أُمَّةًۭ وَٰحِدَةًۭ فَبَعَثَ ٱللَّهُ ٱلنَّبِيِّۦنَ مُبَشِّرِينَ وَمُنذِرِينَ وَأَنزَلَ مَعَهُمُ ٱلْكِتَٰبَ بِٱلْحَقِّ لِيَحْكُمَ بَيْنَ ٱلنَّاسِ فِيمَا ٱخْتَلَفُوا۟ فِيهِ ۚ وَمَا ٱخْتَلَفَ فِيهِ إِلَّا ٱلَّذِينَ أُوتُوهُ مِنۢ بَعْدِ مَا جَآءَتْهُمُ ٱلْبَيِّنَٰتُ بَغْيًۢا بَيْنَهُمْ ۖ فَهَدَى ٱللَّهُ ٱلَّذِينَ ءَامَنُوا۟ لِمَا ٱخْتَلَفُوا۟ فِيهِ مِنَ ٱلْحَقِّ بِإِذْنِهِۦ ۗ وَٱللَّهُ يَهْدِى مَن يَشَآءُ إِلَىٰ صِرَٰطٍۢ مُّسْتَقِيمٍ", 't': "«كان الناس أمة واحدة» على الإيمان فاختلفوا بأن آمن بعض وكفر بعض «فبعث الله النبيين» إليهم «مبشِّرين» من آمن بالجنة «ومنذرين» من كفر بالنار «وأنزل معهم الكتاب» بمعنى الكتب «بالحق» متعلق بأنزل «ليحكم» به «بين الناس فيما اختلفوا فيه» من الدين «وما اختلف فيه» أي الدين «إلا الذين أوتوه» أي الكتاب فآمن بعض وكفر بعض «من بعد ما جاءتهم البينات» الحجج الظاهرة على التوحيد ومن متعلقة باختلاف وهي وما بعدها مقدم على الاستثناء في المعنى «بغيا» من الكافرين «بينهم فهدى الله الذين آمنوا لما اختلفوا فيه من» للبيان «الحق بإذنه» بإرادته «والله يهدي من يشاء» هدايته «إلى صراط مستقيم» طريق الحق."},
  {'n': '214', 'v': "أَمْ حَسِبْتُمْ أَن تَدْخُلُوا۟ ٱلْجَنَّةَ وَلَمَّا يَأْتِكُم مَّثَلُ ٱلَّذِينَ خَلَوْا۟ مِن قَبْلِكُم ۖ مَّسَّتْهُمُ ٱلْبَأْسَآءُ وَٱلضَّرَّآءُ وَزُلْزِلُوا۟ حَتَّىٰ يَقُولَ ٱلرَّسُولُ وَٱلَّذِينَ ءَامَنُوا۟ مَعَهُۥ مَتَىٰ نَصْرُ ٱللَّهِ ۗ أَلَآ إِنَّ نَصْرَ ٱللَّهِ قَرِيبٌۭ", 't': "ونزل في جهد أصاب المسلمين «أم» بل أ «حسبتم أن تدخلوا الجنة ولَّما» لم «يأتكم مثل» شبه ما أتى «الذين خلوا من قبلكم» من المؤمنين من المحن فتصبروا كما صبروا «مسَّتهم» جملة مستأنفة مبينة ما قبلها «البأساء» شدة الفقر «والضراء» المرض «وزُلزلوا» أزعجوا بأنواع البلاء «حتى يقول» بالنصب والرفع أي قال «الرسول والذين آمنوا معه» استبطاء للنصر لتناهي الشدة عليهم «متى» يأتي «نصر الله» الذي وعدنا فأجيبوا من قِبَل الله «ألا إن نصر الله قريب» إتيانه."},
  {'n': '215', 'v': "يَسْـَٔلُونَكَ مَاذَا يُنفِقُونَ ۖ قُلْ مَآ أَنفَقْتُم مِّنْ خَيْرٍۢ فَلِلْوَٰلِدَيْنِ وَٱلْأَقْرَبِينَ وَٱلْيَتَٰمَىٰ وَٱلْمَسَٰكِينِ وَٱبْنِ ٱلسَّبِيلِ ۗ وَمَا تَفْعَلُوا۟ مِنْ خَيْرٍۢ فَإِنَّ ٱللَّهَ بِهِۦ عَلِيمٌۭ", 't': "«يسألونك» يا محمد «ماذا ينفقون» أي الذي ينفقونه والسائل عمرو بن الجموح وكان شيخاً ذا مال فسأل النبي صلى الله عليه وسلم عما ينفق وعلى من ينفق «قل» لهم «ما أنفقتم من خير» بيان لما شامل للقليل والكثير وفيه بيان المنفق الذي هو أحد شقي السؤال وأجاب عن المصرف الذي هو الشق الآخر بقوله: «فللوالدين والأقربين واليتامى والمساكين وابن السبيل» أي هم أولى به «وما تفعلوا من خير» إنفاق أو غيره «فإن الله به عليم» فمجاز عليه."},
  {'n': '216', 'v': "كُتِبَ عَلَيْكُمُ ٱلْقِتَالُ وَهُوَ كُرْهٌۭ لَّكُمْ ۖ وَعَسَىٰٓ أَن تَكْرَهُوا۟ شَيْـًۭٔا وَهُوَ خَيْرٌۭ لَّكُمْ ۖ وَعَسَىٰٓ أَن تُحِبُّوا۟ شَيْـًۭٔا وَهُوَ شَرٌّۭ لَّكُمْ ۗ وَٱللَّهُ يَعْلَمُ وَأَنتُمْ لَا تَعْلَمُونَ", 't': "«كُتِب» فرض «عليكم القتال» للكفار «وهو كُرْهٌ» مكروه «لكم» طبعا لمشقته «وعسى أن تكرهوا شيئا وهو خير لكم وعسى أن تحبوا شيئا وهو شر لكم» لميل النفس إلى الشهوات الموجبة لهلاكها ونفورها عن التكليفات الموجبة لسعادتها فلعل لكم في القتال وإن كرهتموه خيرا لأن فيه إما الظفر والغنيمة أو الشهادة والأجر وفي تركه وإن أحببتموه شرا لأن فيه الذل والفقر وحرمان الأجر «والله يعلم» ما هو خير لكم «وأنتم لا تعلمون» ذلك فبادروا إلى ما يأمركم به."},
  {'n': '217', 'v': "يَسْـَٔلُونَكَ عَنِ ٱلشَّهْرِ ٱلْحَرَامِ قِتَالٍۢ فِيهِ ۖ قُلْ قِتَالٌۭ فِيهِ كَبِيرٌۭ ۖ وَصَدٌّ عَن سَبِيلِ ٱللَّهِ وَكُفْرٌۢ بِهِۦ وَٱلْمَسْجِدِ ٱلْحَرَامِ وَإِخْرَاجُ أَهْلِهِۦ مِنْهُ أَكْبَرُ عِندَ ٱللَّهِ ۚ وَٱلْفِتْنَةُ أَكْبَرُ مِنَ ٱلْقَتْلِ ۗ وَلَا يَزَالُونَ يُقَٰتِلُونَكُمْ حَتَّىٰ يَرُدُّوكُمْ عَن دِينِكُمْ إِنِ ٱسْتَطَٰعُوا۟ ۚ وَمَن يَرْتَدِدْ مِنكُمْ عَن دِينِهِۦ فَيَمُتْ وَهُوَ كَافِرٌۭ فَأُو۟لَٰٓئِكَ حَبِطَتْ أَعْمَٰلُهُمْ فِى ٱلدُّنْيَا وَٱلْءَاخِرَةِ ۖ وَأُو۟لَٰٓئِكَ أَصْحَٰبُ ٱلنَّارِ ۖ هُمْ فِيهَا خَٰلِدُونَ", 't': "وأرسل النبي صلى الله عليه وسلم أول سراياه وعليها عبد الله بن جحش فقاتلوا المشركين وقتلوا ابن الحضرمي آخر يوم من جمادى الآخرة والتبس عليهم برجب فعيرهم الكفار باستحلاله فنزل: «يسألونك عن الشهر الحرام» المحرم «قتال فيه» بدل اشتمال «قل» لهم «قتال فيه كبير» عظيم وزرا مبتدأ وخبر «وصد» مبتدأ منع للناس «عن سبيل الله» دينه «وكفر به» بالله «و» صد عن «المسجد الحرام» أي مكة «وإخراج أهله منه» وهم النبي صلى الله عليه وسلم والمؤمنون وخبر المبتدأ «أكبر» أعظم وزرا «عند الله» من القتال فيه «والفتنة» الشرك منكم «أكبر من القتل» لكم فيه «ولا يزالون» أي الكفار «يقاتلونكم» أيها المؤمنون «حتى» كي «يردوكم» إلى الكفر «إن استطاعوا ومن يرتدِد منكم عن دينه فيمت وهو كافر فأولئك حبطت» بطلت «أعمالهم» الصالحة «في الدنيا والآخرة» فلا اعتداد بها ولا ثواب عليها والتقيد بالموت عليه يفيد أنه لو رجع إلى الإسلام لم يبطل عمله فيثاب عليه ولا يعيده كالحج مثلا وعليه الشافعي «وأولئك أصحاب النار هم فيها خالدون»."},
  {'n': '218', 'v': "إِنَّ ٱلَّذِينَ ءَامَنُوا۟ وَٱلَّذِينَ هَاجَرُوا۟ وَجَٰهَدُوا۟ فِى سَبِيلِ ٱللَّهِ أُو۟لَٰٓئِكَ يَرْجُونَ رَحْمَتَ ٱللَّهِ ۚ وَٱللَّهُ غَفُورٌۭ رَّحِيمٌۭ", 't': "ولما ظن السرية أنهم إن سلموا من الإثم فلا يحصل لهم أجر نزل «إن الذين آمنوا والذين هاجروا» فارقوا أوطانهم «وجاهدوا في سبيل الله» لإعلاء دينه «أولئك يرجون رَحْمَتَ الله» ثوابه «والله غفور» للمؤمنين «رحيم» بهم."},
  {'n': '219', 'v': "۞ يَسْـَٔلُونَكَ عَنِ ٱلْخَمْرِ وَٱلْمَيْسِرِ ۖ قُلْ فِيهِمَآ إِثْمٌۭ كَبِيرٌۭ وَمَنَٰفِعُ لِلنَّاسِ وَإِثْمُهُمَآ أَكْبَرُ مِن نَّفْعِهِمَا ۗ وَيَسْـَٔلُونَكَ مَاذَا يُنفِقُونَ قُلِ ٱلْعَفْوَ ۗ كَذَٰلِكَ يُبَيِّنُ ٱللَّهُ لَكُمُ ٱلْءَايَٰتِ لَعَلَّكُمْ تَتَفَكَّرُونَ", 't': "«يسألونك عن الخمر والميسر» القمار ما حكمهما «قل» لهم «فيهما» أي في تعاطيهما «إثم كبير» عظيم وفي قراءة بالمثلثة لما يحصل بسببهما من المخاصمة والمشاتمة وقول الفحش «ومنافع للناس» باللذة والفرح في الخمر وإصابة المال بلا كد في الميسر «وإثمهما» أي ما ينشأ عنهما من المفاسد «أكبر» أعظم «من نفعهما» ولما نزلت شربها قوم وامتنع عنها آخرون إلى أن حرمتها آية المائدة «ويسألونك ماذا ينفقون» أي ما قدره «قل» أنفقوا «العفو» أي الفاضل عن الحاجة ولا تنفقوا ما تحتاجون إليه وتضيعوا أنفسكم وفي قراءة بالرفع بتقدير هو «كذلك» أي كما بين لكم ما ذكر «يبين الله لكم الآيات لعلكم تتفكرون»."},
  {'n': '220', 'v': "فِى ٱلدُّنْيَا وَٱلْءَاخِرَةِ ۗ وَيَسْـَٔلُونَكَ عَنِ ٱلْيَتَٰمَىٰ ۖ قُلْ إِصْلَاحٌۭ لَّهُمْ خَيْرٌۭ ۖ وَإِن تُخَالِطُوهُمْ فَإِخْوَٰنُكُمْ ۚ وَٱللَّهُ يَعْلَمُ ٱلْمُفْسِدَ مِنَ ٱلْمُصْلِحِ ۚ وَلَوْ شَآءَ ٱللَّهُ لَأَعْنَتَكُمْ ۚ إِنَّ ٱللَّهَ عَزِيزٌ حَكِيمٌۭ", 't': "«في» أمر «الدنيا والآخرة» فتأخذون بالأصلح لكم فيهما «ويسألونك عن اليتامى» وما يلقونه من الحرج في شأنهم فإن واكلوهم يأثموا وإن عزلوا ما لهم من أموالهم وصنعوا لهم طعاما وحدهم فحرج «قل إصلاح لهم» في أموالهم بتنميتها ومداخلتكم «خير» من ترك ذلك «وإن تخالطوهم» أي تخلطوا نفقتكم بنفقتهم «فإخوانكم» أي فهم إخوانكم في الدين ومن شأن الأخ أن يخالط أخاه أي فلكم ذلك «والله يعلم المفسد» لأموالهم بمخالطته «من المصلح» بها فيجازي كلا منهما «ولو شاء الله لأعنتكم» لضيق عليكم بتحريم المخالطة «أن الله عزيز» غالب على أمره «حكيم» في صنعه."},
  {'n': '221', 'v': "وَلَا تَنكِحُوا۟ ٱلْمُشْرِكَٰتِ حَتَّىٰ يُؤْمِنَّ ۚ وَلَأَمَةٌۭ مُّؤْمِنَةٌ خَيْرٌۭ مِّن مُّشْرِكَةٍۢ وَلَوْ أَعْجَبَتْكُمْ ۗ وَلَا تُنكِحُوا۟ ٱلْمُشْرِكِينَ حَتَّىٰ يُؤْمِنُوا۟ ۚ وَلَعَبْدٌۭ مُّؤْمِنٌ خَيْرٌۭ مِّن مُّشْرِكٍۢ وَلَوْ أَعْجَبَكُمْ ۗ أُو۟لَٰٓئِكَ يَدْعُونَ إِلَى ٱلنَّارِ ۖ وَٱللَّهُ يَدْعُوٓا۟ إِلَى ٱلْجَنَّةِ وَٱلْمَغْفِرَةِ بِإِذْنِهِۦ ۖ وَيُبَيِّنُ ءَايَٰتِهِۦ لِلنَّاسِ لَعَلَّهُمْ يَتَذَكَّرُونَ", 't': "«ولا تنكحوا» تتزوجوا أيها المسلمون «المشركات» أي الكافرات «حتى يؤمنّ ولأمة مؤمنة خير من مشركة» حرة لأن سبب نزولها العيب على من تزوج أمة وترغيبه في نكاح حرة مشركة «ولو أعجبتكم» لجمالها ومالها وهذا مخصوص بغير الكتابيات بآية (والمحصنات من الذين أوتوا الكتاب) «ولا تُنكحوا» تُزوجوا «المشركين» أي الكفار المؤمنات «حتى يؤمنوا ولعبد مؤمن خير من مشرك ولو أعجبكم» لماله وجماله «أولئك» أي أهل الشرك «يدعون إلى النار» بدعائهم إلى العمل الموجب لها فلا تليق مناكحهم «والله يدعو» على لسان رسله «إلى الجنة والمغفرة» أي العمل الموجب لهما «بإذنه» بإرادته فتجب إجابته بتزويج أوليائه «ويبن آياته للناس لعلهم يتذكرون» يتعظون."},
  {'n': '222', 'v': "وَيَسْـَٔلُونَكَ عَنِ ٱلْمَحِيضِ ۖ قُلْ هُوَ أَذًۭى فَٱعْتَزِلُوا۟ ٱلنِّسَآءَ فِى ٱلْمَحِيضِ ۖ وَلَا تَقْرَبُوهُنَّ حَتَّىٰ يَطْهُرْنَ ۖ فَإِذَا تَطَهَّرْنَ فَأْتُوهُنَّ مِنْ حَيْثُ أَمَرَكُمُ ٱللَّهُ ۚ إِنَّ ٱللَّهَ يُحِبُّ ٱلتَّوَّٰبِينَ وَيُحِبُّ ٱلْمُتَطَهِّرِينَ", 't': "«ويسألونك عن المحيض» أي الحيض أو مكانه ماذا يفعل بالنساء فيه «قل هو أذى» قذر أو محله «فاعتزلوا النساء» اتركوا وطأهن «في المحيض» أي وقته أو مكانه «ولا تقربوهن» بالجماع «حتى يَطْهُرن» بسكون الطاء وتشديدها والهاء وفيه إدغام التاء في الأصل في الطاء أي يغتسلن بعد انقطاعه «فإذا تطهرن فأتوهن» بالجماع «من حيث أمركم الله» بتجنبه في الحيض وهو القبل ولا تعدوه إلى غيره «إن الله يحب» يثيب ويكرم «التوابين» من الذنوب «ويحب المتطهرين» من الأقذار."},
  {'n': '223', 'v': "نِسَآؤُكُمْ حَرْثٌۭ لَّكُمْ فَأْتُوا۟ حَرْثَكُمْ أَنَّىٰ شِئْتُمْ ۖ وَقَدِّمُوا۟ لِأَنفُسِكُمْ ۚ وَٱتَّقُوا۟ ٱللَّهَ وَٱعْلَمُوٓا۟ أَنَّكُم مُّلَٰقُوهُ ۗ وَبَشِّرِ ٱلْمُؤْمِنِينَ", 't': "«نساؤكم حرث لكم» أي محل زرعكم الولد «فأتوا حرثكم» أي محله وهو القبل «أنَّى» كيف «شئتم» من قيام وقعود واضطجاع وإقبال وإدبار، نزل ردا لقول اليهود: من أتى امرأته في قبلها أي من جهة دبرها جاء الولد أحول «وقدموا لأنفسكم» العمل الصالح كالتسمية عند الجماع «واتقوا الله» في أمره ونهيه «واعلموا أنكم ملاقوه» بالبعث فيجازيكم بأعمالكم «وبشر المؤمنين» الذين اتقوه بالجنة."},
  {'n': '224', 'v': "وَلَا تَجْعَلُوا۟ ٱللَّهَ عُرْضَةًۭ لِّأَيْمَٰنِكُمْ أَن تَبَرُّوا۟ وَتَتَّقُوا۟ وَتُصْلِحُوا۟ بَيْنَ ٱلنَّاسِ ۗ وَٱللَّهُ سَمِيعٌ عَلِيمٌۭ", 't': "«ولا تجعلوا الله» أي الحلف به «عرضة» علة مانعة «لأيمانكم» أي نصيبا لها بأن تكثروا الحلف به «أن» لا «تبروا وتتقوا» فتكره اليمين على ذلك ويسن فيه الحنث ويكفِّر بخلافها على فعل. البر ونحوه فهي طاعة «وتصلحوا بين الناس» المعنى لا تمتنعوا من فعل ما ذكر من البر ونحوه إذا حلفتم عليه بل ائتوه وكفِّروا لأن سبب نزولها الامتناع من ذلك «والله سميع» لأقوالكم «عليم» بأحوالكم."},
  {'n': '225', 'v': "لَّا يُؤَاخِذُكُمُ ٱللَّهُ بِٱللَّغْوِ فِىٓ أَيْمَٰنِكُمْ وَلَٰكِن يُؤَاخِذُكُم بِمَا كَسَبَتْ قُلُوبُكُمْ ۗ وَٱللَّهُ غَفُورٌ حَلِيمٌۭ", 't': "«لا يؤاخذكم الله باللغو» الكائن «في أيمانكم» وهو ما يسبق إليه اللسان من غير قصد الحلف نحو ألا والله، وبلى و الله فلا إثم فيه ولا كفارة «ولكن يؤاخذكم بما كسبت قلوبكم» أي قصدته من الأيمان إذا حنثتم «والله غفور» لما كان من اللغو «حليم» بتأخير العقوبة عن مستحقها."},
  {'n': '226', 'v': "لِّلَّذِينَ يُؤْلُونَ مِن نِّسَآئِهِمْ تَرَبُّصُ أَرْبَعَةِ أَشْهُرٍۢ ۖ فَإِن فَآءُو فَإِنَّ ٱللَّهَ غَفُورٌۭ رَّحِيمٌۭ", 't': "«للذين يؤلون من نسائهم» أي يحلفون أن لا يجامعوهن «تربص» انتظار «أربعة أشهر فإن فاءُوا» رجعوا فيها أو بعدها عن اليمين إلى الوطء «فإن الله غفور» لهم ما أتوه من ضرر المرأة بالحلف «رحيم» بهم."},
  {'n': '227', 'v': "وَإِنْ عَزَمُوا۟ ٱلطَّلَٰقَ فَإِنَّ ٱللَّهَ سَمِيعٌ عَلِيمٌۭ", 't': "«وإن عزموا الطلاق» أي عليه بأن لا يفيئوا فليوقعوه «فإن الله سميع» لقولهم «عليم» بعزمهم المعنى ليس لهم بعد تربص ما ذكر إلا الفيئة أو الطلاق."},
  {'n': '228', 'v': "وَٱلْمُطَلَّقَٰتُ يَتَرَبَّصْنَ بِأَنفُسِهِنَّ ثَلَٰثَةَ قُرُوٓءٍۢ ۚ وَلَا يَحِلُّ لَهُنَّ أَن يَكْتُمْنَ مَا خَلَقَ ٱللَّهُ فِىٓ أَرْحَامِهِنَّ إِن كُنَّ يُؤْمِنَّ بِٱللَّهِ وَٱلْيَوْمِ ٱلْءَاخِرِ ۚ وَبُعُولَتُهُنَّ أَحَقُّ بِرَدِّهِنَّ فِى ذَٰلِكَ إِنْ أَرَادُوٓا۟ إِصْلَٰحًۭا ۚ وَلَهُنَّ مِثْلُ ٱلَّذِى عَلَيْهِنَّ بِٱلْمَعْرُوفِ ۚ وَلِلرِّجَالِ عَلَيْهِنَّ دَرَجَةٌۭ ۗ وَٱللَّهُ عَزِيزٌ حَكِيمٌ", 't': "«والمطلقات يتربصن» أي لينتظرن «بأنفسهن» عن النكاح «ثلاثة قروءٍ» تمضي من حين الطلاق، جمع قرء بفتح القاف وهو الطهر أو الحيض قولان وهذا في المدخول بهن أما غيرهن فلا عدة عليهن لقوله: «فما لكم عليهن من عدة» وفي غير الآيسة والصغيرة فعدتهن ثلاثة أشهر والحوامل فعدتهن أن يضعن حملهن كما في سورة الطلاق والإماء فعدتهن قَرءان بالسُّنة «ولا يحل لهن أن يكتمن ما خلق الله في أرحامهن» من الولد والحيض «إن كنّ يؤمن بالله واليوم الآخر وبعولتهن» أزواجهن «أحق بردهن» بمراجعتهن ولو أبين «في ذلك» أي في زمن التربص «إن أرادوا إصلاحا» بينهما لإضرار المرأة وهو تحريض على قصده لا شرط لجواز الرجعة وهذا في الطلاق الرجعي وأحق لا تفضيل فيه إذ لا حق لغيرهم في نكاحهن في العدة «ولهن» على الأزواج «مثل الذي» لهم «عليهن» من الحقوق «بالمعروف» شرعا من حسن العشرة وترك الضرار ونحو ذلك «وللرجال عليهن درجة» فضيلة في الحق من وجوب طاعتهن لهم لما ساقوه من المهر والانفاق «والله عزيز» في ملكه «حكيم» فيما دبره لخلقه."},
  {'n': '229', 'v': "ٱلطَّلَٰقُ مَرَّتَانِ ۖ فَإِمْسَاكٌۢ بِمَعْرُوفٍ أَوْ تَسْرِيحٌۢ بِإِحْسَٰنٍۢ ۗ وَلَا يَحِلُّ لَكُمْ أَن تَأْخُذُوا۟ مِمَّآ ءَاتَيْتُمُوهُنَّ شَيْـًٔا إِلَّآ أَن يَخَافَآ أَلَّا يُقِيمَا حُدُودَ ٱللَّهِ ۖ فَإِنْ خِفْتُمْ أَلَّا يُقِيمَا حُدُودَ ٱللَّهِ فَلَا جُنَاحَ عَلَيْهِمَا فِيمَا ٱفْتَدَتْ بِهِۦ ۗ تِلْكَ حُدُودُ ٱللَّهِ فَلَا تَعْتَدُوهَا ۚ وَمَن يَتَعَدَّ حُدُودَ ٱللَّهِ فَأُو۟لَٰٓئِكَ هُمُ ٱلظَّٰلِمُونَ", 't': "«الطلاق» أي التطليق الذي يراجع بعده «مرتان» أي اثنتان «فإمساك» أي فعليكم إمساكهن بعده بأن تراجعوهن «بمعروف» من غير ضرار «أو تسريح» أي إرسالهن «بإحسان ولا يحل لكم» أيها الأزواج «أن تأخذوا مما آتيتموهن» من المهور «شيئا» إذا طلقتموهن «إلا أن يخافا» أي الزوجان «أ» ن «لا يقيما حدود الله» أي لا يأتيا بما حده لهما من الحقوق وفي قراءة يخافا بالبناء للمفعول فأن لا يقيما بدل اشتمال من الضمير فيه وقرئ بالفوقانية في الفعلين «فإن خفتم أ» ن «لا يقيما حدود الله فلا جناح عليهما» «فيما افتدت به» نفسها من المال ليطلقها أي لا حرج على الزوج في أخذه ولا الزوجة في بذله «تلك» الأحكام المذكورة «حدود الله فلا تعتدوها ومن يتعدَّ حدود الله فأولئك هم الظالمون»."},
  {'n': '230', 'v': "فَإِن طَلَّقَهَا فَلَا تَحِلُّ لَهُۥ مِنۢ بَعْدُ حَتَّىٰ تَنكِحَ زَوْجًا غَيْرَهُۥ ۗ فَإِن طَلَّقَهَا فَلَا جُنَاحَ عَلَيْهِمَآ أَن يَتَرَاجَعَآ إِن ظَنَّآ أَن يُقِيمَا حُدُودَ ٱللَّهِ ۗ وَتِلْكَ حُدُودُ ٱللَّهِ يُبَيِّنُهَا لِقَوْمٍۢ يَعْلَمُونَ", 't': "«فإن طلقها» الزوج بعد الثنتين «فلا تحل له من بعد» بعد الطلقة الثالثة «حتى تنكح» تتزوج «زوجا غيره» ويطأها كما في الحديث رواه الشيخان «فإن طلقها» أي الزوج الثاني «فلا جناح عليهما» أي الزوجة والزوج الأول «أن يتراجعا» إلى النكاح بعد انقضاء العدة «إن ظنا أن يقيما حدود الله وتلك» المذكورات «حدود الله يُبَيِّنها لقوم يعلمون» يتدبرون."},
  {'n': '231', 'v': "وَإِذَا طَلَّقْتُمُ ٱلنِّسَآءَ فَبَلَغْنَ أَجَلَهُنَّ فَأَمْسِكُوهُنَّ بِمَعْرُوفٍ أَوْ سَرِّحُوهُنَّ بِمَعْرُوفٍۢ ۚ وَلَا تُمْسِكُوهُنَّ ضِرَارًۭا لِّتَعْتَدُوا۟ ۚ وَمَن يَفْعَلْ ذَٰلِكَ فَقَدْ ظَلَمَ نَفْسَهُۥ ۚ وَلَا تَتَّخِذُوٓا۟ ءَايَٰتِ ٱللَّهِ هُزُوًۭا ۚ وَٱذْكُرُوا۟ نِعْمَتَ ٱللَّهِ عَلَيْكُمْ وَمَآ أَنزَلَ عَلَيْكُم مِّنَ ٱلْكِتَٰبِ وَٱلْحِكْمَةِ يَعِظُكُم بِهِۦ ۚ وَٱتَّقُوا۟ ٱللَّهَ وَٱعْلَمُوٓا۟ أَنَّ ٱللَّهَ بِكُلِّ شَىْءٍ عَلِيمٌۭ", 't': "«وإذا طلقتم النساء فبلغن أجلهن» قاربن انقضاء عدتهن «فأمسكوهن» بأن تراجعوهن «بمعروف» من غير ضرر «أو سرحوهن بمعروف» اتركوهن حتى تنقضي عدتهن «ولا تمسكوهن» بالرجعة «ضرارا» مفعول لأجله «لتعتدوا» عليهن بالإلجاء إلى الافتداء والتطليق وتطويل الحبس «ومن يفعل ذلك فقد ظلم نفسه» بتعريضها إلى عذاب الله «ولا تتخذوا آيات الله هزوا» مهزوءا بها بمخالفتها «واذكروا نعمت الله عليكم» بالإسلام «وما أنزل عليكم من الكتاب» القرآن «والحكمة» ما فيه من الأحكام «يعظكم به» بأن تشكروها بالعمل به «واتقوا الله واعلموا أن الله بكل شيء عليم» ولا يخفى عليه شيء."},
  {'n': '232', 'v': "وَإِذَا طَلَّقْتُمُ ٱلنِّسَآءَ فَبَلَغْنَ أَجَلَهُنَّ فَلَا تَعْضُلُوهُنَّ أَن يَنكِحْنَ أَزْوَٰجَهُنَّ إِذَا تَرَٰضَوْا۟ بَيْنَهُم بِٱلْمَعْرُوفِ ۗ ذَٰلِكَ يُوعَظُ بِهِۦ مَن كَانَ مِنكُمْ يُؤْمِنُ بِٱللَّهِ وَٱلْيَوْمِ ٱلْءَاخِرِ ۗ ذَٰلِكُمْ أَزْكَىٰ لَكُمْ وَأَطْهَرُ ۗ وَٱللَّهُ يَعْلَمُ وَأَنتُمْ لَا تَعْلَمُونَ", 't': "«وإذا طلقتم النساء فبلغن أجلهن» انقضت عدتهن «فلا تعضلوهن» خطاب للأولياء أي تمنعوهن من «أن ينكحن أزواجهن» المطلقين لهن لأن سبب نزولها أن أخت معقل بن يسار طلقها زوجها فأراد أن يراجعها فمنعها معقل بن يسار كما رواه الحاكم «إذا تراضوا» أي الأزواج والنساء «بينهم بالمعروف» شرعا «ذلك» النهي عن العضل «يوعظ به من كان منكم يؤمن بالله واليوم الآخر» لأنه المنتفع به «ذلكم» أي ترك العضل «أزكى» خير «لكم وأطهر» لكم ولهم لما يُخشى على الزوجين من الريبة بسبب العلاقة بينهما «والله يعلم» ما فيه المصلحة «وأنتم لا تعلمون» ذلك فاتَّبعوا أوامره."},
  {'n': '233', 'v': "۞ وَٱلْوَٰلِدَٰتُ يُرْضِعْنَ أَوْلَٰدَهُنَّ حَوْلَيْنِ كَامِلَيْنِ ۖ لِمَنْ أَرَادَ أَن يُتِمَّ ٱلرَّضَاعَةَ ۚ وَعَلَى ٱلْمَوْلُودِ لَهُۥ رِزْقُهُنَّ وَكِسْوَتُهُنَّ بِٱلْمَعْرُوفِ ۚ لَا تُكَلَّفُ نَفْسٌ إِلَّا وُسْعَهَا ۚ لَا تُضَآرَّ وَٰلِدَةٌۢ بِوَلَدِهَا وَلَا مَوْلُودٌۭ لَّهُۥ بِوَلَدِهِۦ ۚ وَعَلَى ٱلْوَارِثِ مِثْلُ ذَٰلِكَ ۗ فَإِنْ أَرَادَا فِصَالًا عَن تَرَاضٍۢ مِّنْهُمَا وَتَشَاوُرٍۢ فَلَا جُنَاحَ عَلَيْهِمَا ۗ وَإِنْ أَرَدتُّمْ أَن تَسْتَرْضِعُوٓا۟ أَوْلَٰدَكُمْ فَلَا جُنَاحَ عَلَيْكُمْ إِذَا سَلَّمْتُم مَّآ ءَاتَيْتُم بِٱلْمَعْرُوفِ ۗ وَٱتَّقُوا۟ ٱللَّهَ وَٱعْلَمُوٓا۟ أَنَّ ٱللَّهَ بِمَا تَعْمَلُونَ بَصِيرٌۭ", 't': "«والوالدات يرضعن» أي ليرضعن «أولادهن حولين» عامين «كاملين» صفة مؤكدة، ذلك «لمن أراد أن يتم الرضاعة» ولا زيادة عليه «وعلى المولود له» أي الأب «رزقهن» إطعام الوالدات «وكسوتهن» على الإرضاع إذا كن مطلقات «بالمعروف» بقدر طاقته «لا تُكلَّفُ نفس إلا وسعها» طاقتها «لا تضار والدة بولدها» أي بسببه بأن تكره على إرضاعه إذا امتنعت «ولا» يضار «مولود له بولده» أي بسببه بأن يكلف فوق طاقته وإضافة الولد إلى كل منهما في الموضعين للاستعطاف «وعلى الوارث» أي وارث الأب وهو الصبي أي على وليه في ماله «مثل ذلك» الذي على الأب للوالدة من الرزق و الكسوة «فأن أرادا» أي الوالدان «فصالا» فطاما له قبل الحولين صادرا «عن تراض» اتفاق «منهما وتشاور» بينهما لتظهر مصلحة الصبي فيه «فلا جناح عليهما» في ذلك «وإن أردتم» خطاب للآباء «أن تسترضعوا أولادكم» مراضع غير الوالدات «فلا جناح عليكم» فيه «إذا سلّمتم» إليهن «ما آتيتم» أي أردتم إيتاءه لهن من الأجرة «بالمعروف» بالجميل كطيب النفس «واتقوا الله واعلموا أن الله بما تعملون بصير» لا يخفى عليه شيء منه."},
  {'n': '234', 'v': "وَٱلَّذِينَ يُتَوَفَّوْنَ مِنكُمْ وَيَذَرُونَ أَزْوَٰجًۭا يَتَرَبَّصْنَ بِأَنفُسِهِنَّ أَرْبَعَةَ أَشْهُرٍۢ وَعَشْرًۭا ۖ فَإِذَا بَلَغْنَ أَجَلَهُنَّ فَلَا جُنَاحَ عَلَيْكُمْ فِيمَا فَعَلْنَ فِىٓ أَنفُسِهِنَّ بِٱلْمَعْرُوفِ ۗ وَٱللَّهُ بِمَا تَعْمَلُونَ خَبِيرٌۭ", 't': "«والذين يتوفون» يموتون «منكم ويذرون» يتركون «أزواجا يتربصن» أي ليتربصن «بأنفسهن» بعدهم عن النكاح «أربعة أشهر وعشرا» من الليالي وهذا في غير الحوامل أما الحوامل فعدتهن أن يضعن حملهن بآية الطلاق والأمة على النصف من ذلك بالسنة «فإذا بلغن أجلهن» انقضت مدة تربصهن «فلا جناح عليكم» أيها الاولياء «فيما فعلن في أنفسهن» من التزين والتعرض للخطاب «بالمعروف» شرعا «والله بما تعملون خبير» عالم بباطنه كظاهره."},
  {'n': '235', 'v': "وَلَا جُنَاحَ عَلَيْكُمْ فِيمَا عَرَّضْتُم بِهِۦ مِنْ خِطْبَةِ ٱلنِّسَآءِ أَوْ أَكْنَنتُمْ فِىٓ أَنفُسِكُمْ ۚ عَلِمَ ٱللَّهُ أَنَّكُمْ سَتَذْكُرُونَهُنَّ وَلَٰكِن لَّا تُوَاعِدُوهُنَّ سِرًّا إِلَّآ أَن تَقُولُوا۟ قَوْلًۭا مَّعْرُوفًۭا ۚ وَلَا تَعْزِمُوا۟ عُقْدَةَ ٱلنِّكَاحِ حَتَّىٰ يَبْلُغَ ٱلْكِتَٰبُ أَجَلَهُۥ ۚ وَٱعْلَمُوٓا۟ أَنَّ ٱللَّهَ يَعْلَمُ مَا فِىٓ أَنفُسِكُمْ فَٱحْذَرُوهُ ۚ وَٱعْلَمُوٓا۟ أَنَّ ٱللَّهَ غَفُورٌ حَلِيمٌۭ", 't': "«ولا جُناح عليكم فيما عَرَّضتم» لوحتم «به من خطبة النساء» المتوفى عنهن أزواجهن في العدة كقول الإنسان: مثلا إنك لجميلة ومن يجد مثلك ورب راغب فيك «أو أكننتم» أضمرتم «في أنفسكم» من قصد نكاحهن «علم الله أنكم ستذكرونهن» بالخطبة ولا تصبرون عنهن فأباح لكم التعريض «ولكن لا تواعدوهن سرّاً» أي نكاحاً «إلا» لكن «أن تقولوا قولاً معروفا» أي ما عرف لكم شرعا من التعريض فلكم ذلك «ولا تعزموا عقدة النكاح» أي على عقده «حتى يبلغ الكتاب» أي المكتوب من العدة «أجله» بأن ينتهي «واعلموا أن الله يعلم ما في أنفسكم» من العزم وغيره «فاحذروه» أن يعاقبكم إذا عزمتم «واعلموا أن الله غفور» لمن يحذره «حليم» بتأخير العقوبة عن مستحقها."},
  {'n': '236', 'v': "لَّا جُنَاحَ عَلَيْكُمْ إِن طَلَّقْتُمُ ٱلنِّسَآءَ مَا لَمْ تَمَسُّوهُنَّ أَوْ تَفْرِضُوا۟ لَهُنَّ فَرِيضَةًۭ ۚ وَمَتِّعُوهُنَّ عَلَى ٱلْمُوسِعِ قَدَرُهُۥ وَعَلَى ٱلْمُقْتِرِ قَدَرُهُۥ مَتَٰعًۢا بِٱلْمَعْرُوفِ ۖ حَقًّا عَلَى ٱلْمُحْسِنِينَ", 't': "«لا جُناح عليكم إن طلقتم النساء ما لم تمسوهن» وفي قراءة «تُماسُّوهُنَّ» أي تجامعوهن «أو» لم «تفرضوا لهن فريضة» مهرا وما مصدرية ظرفية أي لا تبعة عليكم في الطلاق زمن عدم المسيس والفرض بإثم ولا مهر فطلقوهن «ومتعوهن» أعطوهن ما يتمنعن به «على الموسع» الغني منكم «قدره وعلى المقتر» الضيِّق الرزق «قدره» يفيد أنه لا نظر إلى قدر الزوجة «متاعا» تمتيعا «بالمعروف» شرعا صفة متاعا «حقا» صفة ثانية أو مصدر مؤكد «على المحسنين» المطيعين."},
  {'n': '237', 'v': "وَإِن طَلَّقْتُمُوهُنَّ مِن قَبْلِ أَن تَمَسُّوهُنَّ وَقَدْ فَرَضْتُمْ لَهُنَّ فَرِيضَةًۭ فَنِصْفُ مَا فَرَضْتُمْ إِلَّآ أَن يَعْفُونَ أَوْ يَعْفُوَا۟ ٱلَّذِى بِيَدِهِۦ عُقْدَةُ ٱلنِّكَاحِ ۚ وَأَن تَعْفُوٓا۟ أَقْرَبُ لِلتَّقْوَىٰ ۚ وَلَا تَنسَوُا۟ ٱلْفَضْلَ بَيْنَكُمْ ۚ إِنَّ ٱللَّهَ بِمَا تَعْمَلُونَ بَصِيرٌ", 't': "«وإن طلقتموهن من قبل أن تمسوهن وقد فرضتم لهن فريضة فنصف ما فرضتم» يجب لهن ويرجع لكم النصف «إلا» لكن «أن يعفون» أي الزوجات فيتركنه «أو يعفو الذي بيده عقدة النكاح» وهو الزوج فيترك لها الكل، وعن ابن عباس: الولي إذا كانت محجورة فلا حرج في ذلك «وأن تعفوا» مبتدأ خبره «أقرب للتقوى ولا تنسوا الفضل بينكم» أي أن يتفضل بعضكم على بعض «إن الله بما تعملون بصير» فيجازيكم به."},
  {'n': '238', 'v': "حَٰفِظُوا۟ عَلَى ٱلصَّلَوَٰتِ وَٱلصَّلَوٰةِ ٱلْوُسْطَىٰ وَقُومُوا۟ لِلَّهِ قَٰنِتِينَ", 't': "«حافظوا على الصلوات» الخمس بأدائها في أوقاتها «والصلاة الوسطى» هي العصر أو الصبح أو الظهر أو غيرها أقوال وأفردها بالذكر لفضلها «وقوموا لله» في الصلاة «قانتين» قيل مطيعين لقوله صلى الله عليه وسلم: كل قنوت في القرآن فهو طاعة، رواه أحمد وغيره، وقيل ساكتين لحديث زيد بن أرقم: كنا نتكلم في الصلاة حتى نزلت فأمرنا بالسكوت ونُهينا عن الكلام رواه الشيخان."},
  {'n': '239', 'v': "فَإِنْ خِفْتُمْ فَرِجَالًا أَوْ رُكْبَانًۭا ۖ فَإِذَآ أَمِنتُمْ فَٱذْكُرُوا۟ ٱللَّهَ كَمَا عَلَّمَكُم مَّا لَمْ تَكُونُوا۟ تَعْلَمُونَ", 't': "«فإن خفتم» من عدو أو سيل أو سبع «فرجالا» جمع راجل أي مشاة صلوا «أو ركبانا» جمع راكب أي كيف أمكن مستقبلي القبلة أو غيرها ويومئ بالركوع والسجود «فإذا أمنتم» من الخوف «فاذكروا الله» أي صلّوا «كما علمكم ما لم تكونوا تعلمون» قبل تعليمه من فرائضها وحقوقها والكاف بمعنى مثل وما مصدرية أو موصولة."},
  {'n': '240', 'v': "وَٱلَّذِينَ يُتَوَفَّوْنَ مِنكُمْ وَيَذَرُونَ أَزْوَٰجًۭا وَصِيَّةًۭ لِّأَزْوَٰجِهِم مَّتَٰعًا إِلَى ٱلْحَوْلِ غَيْرَ إِخْرَاجٍۢ ۚ فَإِنْ خَرَجْنَ فَلَا جُنَاحَ عَلَيْكُمْ فِى مَا فَعَلْنَ فِىٓ أَنفُسِهِنَّ مِن مَّعْرُوفٍۢ ۗ وَٱللَّهُ عَزِيزٌ حَكِيمٌۭ", 't': "«والذين يُتوفون منكم ويذرون أزواجا» فليوصوا «وصيةً» وفي قراءة بالرفع أي عليهم «لأزواجهم» وليعطوهن «متاعا» ما يتمتعن به من النفقة والكسوة «إلى» تمام «الحول غير إخراج» حال أي غير مخرجات من مسكنهن «فإن خرجن» بأنفسهن «فلا جناح عليكم» يا أولياء الميت «في ما فعلن في أنفسهن من معروف» شرعا كالتزين وترك الإحداد وقطع النفقة عنها «والله عزيز» في ملكه «حكيم» في صنعه والوصية المذكورة منسوخة بآية الميراث وتربص الحول بآية أربعة أشهر وعشرا السابقة المتأخرة في النزول والسكنى ثابتة لها عند الشافعي رحمه الله."},
  {'n': '241', 'v': "وَلِلْمُطَلَّقَٰتِ مَتَٰعٌۢ بِٱلْمَعْرُوفِ ۖ حَقًّا عَلَى ٱلْمُتَّقِينَ", 't': "«وللمطلّقات متاع» يعطينه «بالمعروف» بقدر الإمكان «حقّا» نصب بفعله المقدر «على المتقين» الله تعالى كرره ليعم الممسوسة أيضا إذ الآية السابقة في غيرها."},
  {'n': '242', 'v': "كَذَٰلِكَ يُبَيِّنُ ٱللَّهُ لَكُمْ ءَايَٰتِهِۦ لَعَلَّكُمْ تَعْقِلُونَ", 't': "«كذلك» كما يبين لكم ما ذكر «يبين الله لكم آياته لعلكم تعقلون» تتدبرون."},
  {'n': '243', 'v': "۞ أَلَمْ تَرَ إِلَى ٱلَّذِينَ خَرَجُوا۟ مِن دِيَٰرِهِمْ وَهُمْ أُلُوفٌ حَذَرَ ٱلْمَوْتِ فَقَالَ لَهُمُ ٱللَّهُ مُوتُوا۟ ثُمَّ أَحْيَٰهُمْ ۚ إِنَّ ٱللَّهَ لَذُو فَضْلٍ عَلَى ٱلنَّاسِ وَلَٰكِنَّ أَكْثَرَ ٱلنَّاسِ لَا يَشْكُرُونَ", 't': "«ألم تر» استفهام تعجيب وتشويق إلى استماع ما بعده أي ينته علمك «إلى الذين خرجوا من ديارهم وهم ألوف» أربعة أو ثمانية أو عشرة أو ثلاثون أو أربعون أو سبعون ألفا «حذر الموت» مفعول له وهم قوم من بني إسرائيل وقع الطاعون ببلادهم ففروا «فقال لهم الله موتوا» فماتوا «ثم أحياهم» بعد ثمانية أيام أو أكثر بدعاء نبيهم حزقيل بكسر المهملة والقاف وسكون الزاي فعاشوا دهرا عليهم أثر الموت لا يلبسون ثوبا إلا عاد كالكفن واستمرت في أسباطهم «إن الله لذو فضل على الناس» ومنه إحياء هؤلاء «ولكن أكثر الناس» وهم الكفار «لا يشكرون» والقصد من ذكر خبر هؤلاء تشجيع المؤمنين على القتال ولذا عطف عليه."},
  {'n': '244', 'v': "وَقَٰتِلُوا۟ فِى سَبِيلِ ٱللَّهِ وَٱعْلَمُوٓا۟ أَنَّ ٱللَّهَ سَمِيعٌ عَلِيمٌۭ", 't': "«وقاتلوا في سبيل الله» أي لإعلاء دينه «واعلموا أن الله سميع» لأقوالكم «عليم» بأحوالكم فمجازيكم."},
  {'n': '245', 'v': "مَّن ذَا ٱلَّذِى يُقْرِضُ ٱللَّهَ قَرْضًا حَسَنًۭا فَيُضَٰعِفَهُۥ لَهُۥٓ أَضْعَافًۭا كَثِيرَةًۭ ۚ وَٱللَّهُ يَقْبِضُ وَيَبْصُۜطُ وَإِلَيْهِ تُرْجَعُونَ", 't': "«من ذا الذي يقرض الله» بإنفاق ماله في سبيل الله «قرضا حسنا» بأن ينفقه لله عز وجل عن طيب قلب «فيضاعفه» وفي قراءة فيضعفه بالتشديد «له أضعافا كثيرة» من عشر إلى أكثر من سبعمائة كما سيأتي «والله يقبض» يمسك الرزق عمن يشاء ابتلاء «ويبسط» يوسعه لمن يشاء امتحانا «وإليه ترجعون» في الآخرة بالبعث فيجازيكم بأعمالكم."},
  {'n': '246', 'v': "أَلَمْ تَرَ إِلَى ٱلْمَلَإِ مِنۢ بَنِىٓ إِسْرَٰٓءِيلَ مِنۢ بَعْدِ مُوسَىٰٓ إِذْ قَالُوا۟ لِنَبِىٍّۢ لَّهُمُ ٱبْعَثْ لَنَا مَلِكًۭا نُّقَٰتِلْ فِى سَبِيلِ ٱللَّهِ ۖ قَالَ هَلْ عَسَيْتُمْ إِن كُتِبَ عَلَيْكُمُ ٱلْقِتَالُ أَلَّا تُقَٰتِلُوا۟ ۖ قَالُوا۟ وَمَا لَنَآ أَلَّا نُقَٰتِلَ فِى سَبِيلِ ٱللَّهِ وَقَدْ أُخْرِجْنَا مِن دِيَٰرِنَا وَأَبْنَآئِنَا ۖ فَلَمَّا كُتِبَ عَلَيْهِمُ ٱلْقِتَالُ تَوَلَّوْا۟ إِلَّا قَلِيلًۭا مِّنْهُمْ ۗ وَٱللَّهُ عَلِيمٌۢ بِٱلظَّٰلِمِينَ", 't': "«ألم تر إلى الملأ» الجماعة «من بني إسرائيل من بعد» موت «موسى» أي إلى قصتهم وخبرهم «إذ قالوا لنبي لهم» هو شمويل «ابعث» أقم «لنا ملكا نقاتل» معه «في سبيل الله» تنتظم به كلمتنا ونرجع إليه «قال» النبي لهم «هل عسَيتم» بالفتح والكسر «إن كتب عليكم القتال أ» ن «لا تقاتلوا» خبر عسى والاستفهام لتقرير التوقع بها «قالوا وما لنا أ» ن «لا نقاتل في سبيل الله وقد أُخرجنا من ديارنا وأبنائنا» بسبيهم وقتلهم وقد فعل بهم ذلك قوم جالوت أي لا مانع لنا منه مع وجود مقتضيه قال تعالى: «فلما كُتب عليهم القتال تولوا» عنه وجبنوا «إلا قليلا منهم» وهم الذين عبروا النهر مع طالوت كما سيأتي «والله عليم بالظالمين» فمجازيهم وسأل النبي إرسال ملك فأجابه إلى إرسال طالوت."},
  {'n': '247', 'v': "وَقَالَ لَهُمْ نَبِيُّهُمْ إِنَّ ٱللَّهَ قَدْ بَعَثَ لَكُمْ طَالُوتَ مَلِكًۭا ۚ قَالُوٓا۟ أَنَّىٰ يَكُونُ لَهُ ٱلْمُلْكُ عَلَيْنَا وَنَحْنُ أَحَقُّ بِٱلْمُلْكِ مِنْهُ وَلَمْ يُؤْتَ سَعَةًۭ مِّنَ ٱلْمَالِ ۚ قَالَ إِنَّ ٱللَّهَ ٱصْطَفَىٰهُ عَلَيْكُمْ وَزَادَهُۥ بَسْطَةًۭ فِى ٱلْعِلْمِ وَٱلْجِسْمِ ۖ وَٱللَّهُ يُؤْتِى مُلْكَهُۥ مَن يَشَآءُ ۚ وَٱللَّهُ وَٰسِعٌ عَلِيمٌۭ", 't': "«وقال لهم نبيهم إن الله قد بعث لكم طالوت ملكا قالوا أنَى» كيف «يكون له الملك علينا ونحن أحق بالملك منه» لأنه ليس من سبط المملكة ولا النبوة وكان دباغا أو راعيا «ولم يؤت سعة من المال» يستعين بها على إقامة الملك «قال» النبي لهم «إن الله اصطفاه» اختاره للملك «عليكم وزاده بسطة» سعة «في العلم والجسم» وكان أعلم بني إسرائيل يومئذ وأجملهم وأتمهم خلقا «والله يؤتي ملكه من يشاء» إيتاءه لا اعتراض عليه «والله واسع» فضله «عليم» بمن هو أهل له."},
  {'n': '248', 'v': "وَقَالَ لَهُمْ نَبِيُّهُمْ إِنَّ ءَايَةَ مُلْكِهِۦٓ أَن يَأْتِيَكُمُ ٱلتَّابُوتُ فِيهِ سَكِينَةٌۭ مِّن رَّبِّكُمْ وَبَقِيَّةٌۭ مِّمَّا تَرَكَ ءَالُ مُوسَىٰ وَءَالُ هَٰرُونَ تَحْمِلُهُ ٱلْمَلَٰٓئِكَةُ ۚ إِنَّ فِى ذَٰلِكَ لَءَايَةًۭ لَّكُمْ إِن كُنتُم مُّؤْمِنِينَ", 't': "«وقال لهم نبيهم» لما طلبوا منه آية على ملكه «إن آية ملكه أن يأتيكم التابوت» الصندوق كان فيه صور الأنبياء أنزله الله على آدم واستمر إليهم فغلبهم العمالقة عليه وأخذوه وكانوا يستفتحون به على عدوهم ويقدمونه في القتال ويسكنون إليه كما قال تعالى «فيه سكينة» طمأنينة لقلوبكم «من ربكم وبقية مما ترك آل موسى وآل هارون» أي تركاه هما، وهي نعلا موسى وعصاه وعمامة هارون وقفيز من المن الذي كان ينزل عليهم ورضاض من الألواح «تحمله الملائكة» حال من فاعل يأتيكم «إن في ذلك لآية لكم» على ملكه «إن كنتم مؤمنين» فحملته الملائكة بين السماء والأرض وهم ينظرون إليه حتى وضعته عند طالوت فأقروا بملكه وتسارعوا إلى الجهاد فاختار من شبابهم سبعين ألفاً."},
  {'n': '249', 'v': "فَلَمَّا فَصَلَ طَالُوتُ بِٱلْجُنُودِ قَالَ إِنَّ ٱللَّهَ مُبْتَلِيكُم بِنَهَرٍۢ فَمَن شَرِبَ مِنْهُ فَلَيْسَ مِنِّى وَمَن لَّمْ يَطْعَمْهُ فَإِنَّهُۥ مِنِّىٓ إِلَّا مَنِ ٱغْتَرَفَ غُرْفَةًۢ بِيَدِهِۦ ۚ فَشَرِبُوا۟ مِنْهُ إِلَّا قَلِيلًۭا مِّنْهُمْ ۚ فَلَمَّا جَاوَزَهُۥ هُوَ وَٱلَّذِينَ ءَامَنُوا۟ مَعَهُۥ قَالُوا۟ لَا طَاقَةَ لَنَا ٱلْيَوْمَ بِجَالُوتَ وَجُنُودِهِۦ ۚ قَالَ ٱلَّذِينَ يَظُنُّونَ أَنَّهُم مُّلَٰقُوا۟ ٱللَّهِ كَم مِّن فِئَةٍۢ قَلِيلَةٍ غَلَبَتْ فِئَةًۭ كَثِيرَةًۢ بِإِذْنِ ٱللَّهِ ۗ وَٱللَّهُ مَعَ ٱلصَّٰبِرِينَ", 't': "«فلمَّا فصل» خرج «طالوت بالجنود» من بيت المقدس وكان الحر شديدا وطلبوا منه الماء «قال إن الله مبتليكم» مختبركم «بنهر» ليظهر المطيع منكم والعاصي وهو بين الأردن وفلسطين «فمن شرب منه» أي من مائه «فليس مني» أي من أتباعي «ومن لم يطعمه» يذقه «فإنه مني إلا من اغترف غرفة» بالفتح والضم «بيده» فاكتفى بها ولم يزد عليها فإنه مني «فشربوا منه» لما وافوه بكثرة «إلا قليلا منهم» فاقتصروا على الغرفة روي أنها كفتهم لشربهم ودوابهم وكانوا ثلاثمائة وبضعة عشر رجلا «فلما جاوزه هو والذين آمنوا معه» وهم الذين اقتصروا على الغرفة «قالوا» أي الذين شربوا «لا طاقة» قوة «لنا اليوم بجالوت وجنوده» أي بقتالهم وجبنوا ولم يجاوزوه «قال الذين يظنون» يوقنون «أنهم ملاقوا الله» بالبعث وهم الذين جاوزوه «كم» خبرية بمعني كثير «من فئة» جماعة «قليلة غلبت فئة كثيرة بإذن الله» بإرادته «والله مع الصابرين» بالعون والنصر."},
  {'n': '250', 'v': "وَلَمَّا بَرَزُوا۟ لِجَالُوتَ وَجُنُودِهِۦ قَالُوا۟ رَبَّنَآ أَفْرِغْ عَلَيْنَا صَبْرًۭا وَثَبِّتْ أَقْدَامَنَا وَٱنصُرْنَا عَلَى ٱلْقَوْمِ ٱلْكَٰفِرِينَ", 't': "«ولما برزوا لجالوت وجنوده» أي ظهروا لقتالهم وتصافّوا «قالوا ربنا أفرغ» أصبب «علينا صبرا وثبت أقدامنا» بتقوية قلوبنا على الجهاد «وانصرنا على القوم الكافرين»."},
  {'n': '251', 'v': "فَهَزَمُوهُم بِإِذْنِ ٱللَّهِ وَقَتَلَ دَاوُۥدُ جَالُوتَ وَءَاتَىٰهُ ٱللَّهُ ٱلْمُلْكَ وَٱلْحِكْمَةَ وَعَلَّمَهُۥ مِمَّا يَشَآءُ ۗ وَلَوْلَا دَفْعُ ٱللَّهِ ٱلنَّاسَ بَعْضَهُم بِبَعْضٍۢ لَّفَسَدَتِ ٱلْأَرْضُ وَلَٰكِنَّ ٱللَّهَ ذُو فَضْلٍ عَلَى ٱلْعَٰلَمِينَ", 't': "«فهزموهم» كسروهم «بإذن الله» بإرادته «وقتل داود» وكان في عسكر طالوت «جالوت وآتاه» أي داود «الله الملك» في بني إسرائيل «والحكمة» النبوة بعد موت شمويل وطالوت ولم يجتمعا لأحد قبله «وعلّمه مما يشاء» كصنعة الدروع ومنطق الطير «ولولا دفع الله الناس بعضهم» بدل بعض من الناس «ببعض لفسدت الأرض» بغلبة المشركين وقتل المسلمين وتخريب المساجد «ولكنّ الله ذو فضل على العالمين» فدفع بعضهم ببعض."},
  {'n': '252', 'v': "تِلْكَ ءَايَٰتُ ٱللَّهِ نَتْلُوهَا عَلَيْكَ بِٱلْحَقِّ ۚ وَإِنَّكَ لَمِنَ ٱلْمُرْسَلِينَ", 't': "«تلك» هذه الآيات «آيات الله نتلوها» نقصها «عليك» يا محمد «بالحق» بالصدق «وإنك لمن المرسلين» التأكيد بأن وغيرها ردٌ لقول الكفار له لست مرسلا."},
  {'n': '253', 'v': "۞ تِلْكَ ٱلرُّسُلُ فَضَّلْنَا بَعْضَهُمْ عَلَىٰ بَعْضٍۢ ۘ مِّنْهُم مَّن كَلَّمَ ٱللَّهُ ۖ وَرَفَعَ بَعْضَهُمْ دَرَجَٰتٍۢ ۚ وَءَاتَيْنَا عِيسَى ٱبْنَ مَرْيَمَ ٱلْبَيِّنَٰتِ وَأَيَّدْنَٰهُ بِرُوحِ ٱلْقُدُسِ ۗ وَلَوْ شَآءَ ٱللَّهُ مَا ٱقْتَتَلَ ٱلَّذِينَ مِنۢ بَعْدِهِم مِّنۢ بَعْدِ مَا جَآءَتْهُمُ ٱلْبَيِّنَٰتُ وَلَٰكِنِ ٱخْتَلَفُوا۟ فَمِنْهُم مَّنْ ءَامَنَ وَمِنْهُم مَّن كَفَرَ ۚ وَلَوْ شَآءَ ٱللَّهُ مَا ٱقْتَتَلُوا۟ وَلَٰكِنَّ ٱللَّهَ يَفْعَلُ مَا يُرِيدُ", 't': "«تلك» مبتدأ «الرسل» نعت أو عطف بيان والخبر «فضلنا بعضهم على بعض» بتخصيصه بمنقبة ليست لغيره «منهم من كلّم الله» كموسى «ورفع بعضهم» أي محمد صلى الله عليه وسلم «درجات» على غيره بعموم الدعوة وختم النبوة وتفضيل أمته على سائر الأمم والمعجزات المتكاثرة والخصائص العديدة «وآتينا عيسى بن مريم البينات وأيدناه» قويناه «بروح القدس» جبريل يسير معه حيث سار «ولو شاء الله» هدى الناس جميعا «ما اقتتل الذين من بعدهم» بعد الرسل أي أممهم «من بعد ما جاءتهم البينات» لاختلافهم وتضليل بعضهم بعضا «ولكن اختلفوا» لمشيئته ذلك «فمنهم من آمن» ثبت على إيمانه «ومنهم من كفر» كالنصارى بعد المسيح «ولو شاء الله ما اقتتلوا» تأكيد «ولكن الله يفعل ما يريد» من توفيق من شاء وخذلان من شاء."},
  {'n': '254', 'v': "يَٰٓأَيُّهَا ٱلَّذِينَ ءَامَنُوٓا۟ أَنفِقُوا۟ مِمَّا رَزَقْنَٰكُم مِّن قَبْلِ أَن يَأْتِىَ يَوْمٌۭ لَّا بَيْعٌۭ فِيهِ وَلَا خُلَّةٌۭ وَلَا شَفَٰعَةٌۭ ۗ وَٱلْكَٰفِرُونَ هُمُ ٱلظَّٰلِمُونَ", 't': "«يا أيها الذين آمنوا أنفقوا مما رزقناكم» زكاته «من قبل أن يأتي يوم لا بيْعٌ» فداء «فيه ولا خُلَّة» صداقة تنفع «ولا شَفَاعَةَ» بغير إذنه وهو يوم القيامة وفي قراءة برفع الثلاثة «والكافرون» بالله أو بما فرض عليهم «هم الظالمون» لوضعهم أمر الله في غير محله."},
  {'n': '255', 'v': "ٱللَّهُ لَآ إِلَٰهَ إِلَّا هُوَ ٱلْحَىُّ ٱلْقَيُّومُ ۚ لَا تَأْخُذُهُۥ سِنَةٌۭ وَلَا نَوْمٌۭ ۚ لَّهُۥ مَا فِى ٱلسَّمَٰوَٰتِ وَمَا فِى ٱلْأَرْضِ ۗ مَن ذَا ٱلَّذِى يَشْفَعُ عِندَهُۥٓ إِلَّا بِإِذْنِهِۦ ۚ يَعْلَمُ مَا بَيْنَ أَيْدِيهِمْ وَمَا خَلْفَهُمْ ۖ وَلَا يُحِيطُونَ بِشَىْءٍۢ مِّنْ عِلْمِهِۦٓ إِلَّا بِمَا شَآءَ ۚ وَسِعَ كُرْسِيُّهُ ٱلسَّمَٰوَٰتِ وَٱلْأَرْضَ ۖ وَلَا يَـُٔودُهُۥ حِفْظُهُمَا ۚ وَهُوَ ٱلْعَلِىُّ ٱلْعَظِيمُ", 't': "«الله لا إله» أي لا معبود بحق في الوجود «إلا هو الحيُّ» الدائم بالبقاء «القيوم» المبالغ في القيام بتدبير خلقه «لاتأخذه سنة» نعاس «ولا نوم له ما في السماوات وما في الأرض» ملكا وخلقا وعبيدا «من ذا الذي» أي لا أحد «يشفع عنده إلا بإذنه» له فيها «يعلم ما بين أيديهم» أي الخلق «وما خلفهم» أي من أمر الدنيا والآخرة «ولا يحيطون بشيء من علمه» أي لا يعلمون شيئا من معلوماته «إلا بما شاء» أن يعلمهم به منها بأخبار الرسل «وسع كرسيه السماوات والأرض» قيل أحاط علمه بهما وقيل ملكه وقيل الكرسي نفسه مشتمل عليهما لعظمته، لحديث: ما السماوات السبع في الكرسى إلا كدارهم سبعة ألقيت في ترس «ولا يئوده» يثقله «حفظهما» أي السماوات والأرض «وهو العلي» فوق خلقه بالقهر «العظيم» الكبير."},
  {'n': '256', 'v': "لَآ إِكْرَاهَ فِى ٱلدِّينِ ۖ قَد تَّبَيَّنَ ٱلرُّشْدُ مِنَ ٱلْغَىِّ ۚ فَمَن يَكْفُرْ بِٱلطَّٰغُوتِ وَيُؤْمِنۢ بِٱللَّهِ فَقَدِ ٱسْتَمْسَكَ بِٱلْعُرْوَةِ ٱلْوُثْقَىٰ لَا ٱنفِصَامَ لَهَا ۗ وَٱللَّهُ سَمِيعٌ عَلِيمٌ", 't': "«لا إكراه في الدين» على الدخول فيه «قد تبين الرشد من الغي» أي ظهر بالآيات البينات أن الايمان رشد والكفر غي نزلت فيمن كان له من الأنصار اولاد أراد أن يكرههم علي الإسلام «فمن يكفر بالطاغوت» الشيطان أو الأصنام وهو يطلق على المفرد والجمع «ويؤمن بالله فقد استمسك» تمسك «بالعروة الوثقى» بالعقد المحكم «لا انفصام» انقطاع «لها والله سميع» لما يقال «عليم» بما يفعل."},
  {'n': '257', 'v': "ٱللَّهُ وَلِىُّ ٱلَّذِينَ ءَامَنُوا۟ يُخْرِجُهُم مِّنَ ٱلظُّلُمَٰتِ إِلَى ٱلنُّورِ ۖ وَٱلَّذِينَ كَفَرُوٓا۟ أَوْلِيَآؤُهُمُ ٱلطَّٰغُوتُ يُخْرِجُونَهُم مِّنَ ٱلنُّورِ إِلَى ٱلظُّلُمَٰتِ ۗ أُو۟لَٰٓئِكَ أَصْحَٰبُ ٱلنَّارِ ۖ هُمْ فِيهَا خَٰلِدُونَ", 't': "«الله ولي» ناصر «الذين آمنوا يخرجهم من الظلمات» الكفر «إلى النور» الإيمان «والذين كفروا أولياؤهم الطاغوت يخرجونهم من النور إلى الظلمات» ذكر الإخراج إما في مقابلة قوله يخرجهم من الظلمات أو في كل من آمن بالنبي قبل بعثته من اليهود ثم كفر به «أولئك أصحاب النار هم فيها خالدون»."},
  {'n': '258', 'v': "أَلَمْ تَرَ إِلَى ٱلَّذِى حَآجَّ إِبْرَٰهِۦمَ فِى رَبِّهِۦٓ أَنْ ءَاتَىٰهُ ٱللَّهُ ٱلْمُلْكَ إِذْ قَالَ إِبْرَٰهِۦمُ رَبِّىَ ٱلَّذِى يُحْىِۦ وَيُمِيتُ قَالَ أَنَا۠ أُحْىِۦ وَأُمِيتُ ۖ قَالَ إِبْرَٰهِۦمُ فَإِنَّ ٱللَّهَ يَأْتِى بِٱلشَّمْسِ مِنَ ٱلْمَشْرِقِ فَأْتِ بِهَا مِنَ ٱلْمَغْرِبِ فَبُهِتَ ٱلَّذِى كَفَرَ ۗ وَٱللَّهُ لَا يَهْدِى ٱلْقَوْمَ ٱلظَّٰلِمِينَ", 't': "«ألم ترَ إلى الذي حَاًجَّ» جادل «إبراهيم في ربّه» ل «أن آتاه الله الملك» أي حمله بطره بنعمة الله على ذلك وهو نمرود «إذ» بدل من حاج «قال إبراهيم» لما قال له من ربُّك الذي تدعونا إليه: «ربي الذي يحيي ويميت» أي يخلق الحياة والموت في الأجساد «قال» هو «أنا أحيي وأميت» بالقتل والعفو عنه ودعا برجلين فقتل أحدهما وترك الآخر فلما رآه غبيا «قال إبراهيم» منتقلا إلى حجة أوضح منها «فإن الله يأتي بالشمس من المشرق فأت بها» أنت «من المغرب فَبُهت الذي كفر» تحيَّر ودُهش «والله لا يهدي القوم الظالمين» بالكفر إلى محجَّة الاحتجاج."},
  {'n': '259', 'v': "أَوْ كَٱلَّذِى مَرَّ عَلَىٰ قَرْيَةٍۢ وَهِىَ خَاوِيَةٌ عَلَىٰ عُرُوشِهَا قَالَ أَنَّىٰ يُحْىِۦ هَٰذِهِ ٱللَّهُ بَعْدَ مَوْتِهَا ۖ فَأَمَاتَهُ ٱللَّهُ مِا۟ئَةَ عَامٍۢ ثُمَّ بَعَثَهُۥ ۖ قَالَ كَمْ لَبِثْتَ ۖ قَالَ لَبِثْتُ يَوْمًا أَوْ بَعْضَ يَوْمٍۢ ۖ قَالَ بَل لَّبِثْتَ مِا۟ئَةَ عَامٍۢ فَٱنظُرْ إِلَىٰ طَعَامِكَ وَشَرَابِكَ لَمْ يَتَسَنَّهْ ۖ وَٱنظُرْ إِلَىٰ حِمَارِكَ وَلِنَجْعَلَكَ ءَايَةًۭ لِّلنَّاسِ ۖ وَٱنظُرْ إِلَى ٱلْعِظَامِ كَيْفَ نُنشِزُهَا ثُمَّ نَكْسُوهَا لَحْمًۭا ۚ فَلَمَّا تَبَيَّنَ لَهُۥ قَالَ أَعْلَمُ أَنَّ ٱللَّهَ عَلَىٰ كُلِّ شَىْءٍۢ قَدِيرٌۭ", 't': "«أو» رأيت «كالذي» الكاف زائدة «مرَّ على قرية» هي بيت المقدس راكبا على حمار ومعه سلة تين وقدح عصير وهوعزيز «وهي خاوية» ساقطة «على عروشها» سقوطها لما خرَّبها بختنصر «قال أنَّى» كيف «يحيي هذه الله بعد موتها» استعظاما لقدرته تعالى «فأماته الله» وألبثه «مائه عام ثم بعثه» أحياء ليريه كيفية ذلك «قال» تعالى له «كم لبثت» مكثت هنا «قال لبثت يوما أو بعض يوم» لأنه نام أول النهار فقبض وأحيي عند الغروب فظن أنه يوم النوم «قال بل لبثت مائة عام فانظر إلى طعامك» التين «وشرابك» العصير «لم يتسنَّه» لم يتغير مع طول الزمان، والهاء قيل أصل من سانهت وقيل للسكت من سانيت وفي قراءة بحذفها «وانظر إلى حمارك» كيف هو فرآه ميتا وعظامه بيض تلوح فعلْنا ذلك لتعلم «ولنجعلك آية» على البعث «للناس وانظر إلى العظام» من حمارك «كيف ننشزها» نحييها بضم النون وقرئ بفتحها من أنشز ونشز - لغتان - وفي قراءة بضمها والزاي- نحركها ونرفعها- «ثم نكسوها لحما» فنظر إليه وقد تركبت وكسيت لحما ونفخ فيه الروح ونهق «فلما تبيَّن له» ذلك بالمشاهدة «قال أعلم» علم مشاهدة «أن الله على كل شيء قدير» وفي قراءة إعْلَمْ أمر من الله له."},
  {'n': '260', 'v': "وَإِذْ قَالَ إِبْرَٰهِۦمُ رَبِّ أَرِنِى كَيْفَ تُحْىِ ٱلْمَوْتَىٰ ۖ قَالَ أَوَلَمْ تُؤْمِن ۖ قَالَ بَلَىٰ وَلَٰكِن لِّيَطْمَئِنَّ قَلْبِى ۖ قَالَ فَخُذْ أَرْبَعَةًۭ مِّنَ ٱلطَّيْرِ فَصُرْهُنَّ إِلَيْكَ ثُمَّ ٱجْعَلْ عَلَىٰ كُلِّ جَبَلٍۢ مِّنْهُنَّ جُزْءًۭا ثُمَّ ٱدْعُهُنَّ يَأْتِينَكَ سَعْيًۭا ۚ وَٱعْلَمْ أَنَّ ٱللَّهَ عَزِيزٌ حَكِيمٌۭ", 't': "«و» اذكر «إذ قال إبراهيم ربَّ أرني كيف تحيي الموتى قال» تعالى له «أولم تؤمن» بقدرتي على الإحياء سأله مع علمه بإيمانه بذلك ليجيبه بما سأل فيعلم السامعون غرضه «قال بلى» آمنت «ولكن» سألتك «ليطمئن» يسكن «قلبي» بالمعاينة المضمومة إلى الاستدلال «قال فخذ أربعة من الطير فّصُرْهُنَّ إليك» بكسر الصاد وضمها أملهن إليك وقطعهن واخلط لحمهن وريشهن «ثم اجعل على كل جبل» من جبال أرضك «منهن جزءاً ثم ادعهن» إليك «يأتينك سعيا» سريعا «واعلم أن الله عزيز» لا يعجزه شيء «حكيم» في صنعه فأخذ طاووسا ونسرا وغرابا وديكا وفعل بهن ما ذكر وأمسك رءوسهن عنده ودعاهن فتطايرت الأجزاء إلى بعضها حتى تكاملت ثم أقبلت إلى رءوسها."},
  {'n': '261', 'v': "مَّثَلُ ٱلَّذِينَ يُنفِقُونَ أَمْوَٰلَهُمْ فِى سَبِيلِ ٱللَّهِ كَمَثَلِ حَبَّةٍ أَنۢبَتَتْ سَبْعَ سَنَابِلَ فِى كُلِّ سُنۢبُلَةٍۢ مِّا۟ئَةُ حَبَّةٍۢ ۗ وَٱللَّهُ يُضَٰعِفُ لِمَن يَشَآءُ ۗ وَٱللَّهُ وَٰسِعٌ عَلِيمٌ", 't': "«مثل» صفة نفقات «الذين ينفقون أموالهم في سبيل لله» أي طاعته «كمَثل حبة أنبتت سبع سنابل في كل سنبلة مائة حبة» فكذلك نفقاتهم تضاعفت لسبعمائة ضعف «والله يضاعف» أكثر من ذلك «لمن يشاء والله واسع» فضله «عليم» بمن يستحق المضاعفة."},
  {'n': '262', 'v': "ٱلَّذِينَ يُنفِقُونَ أَمْوَٰلَهُمْ فِى سَبِيلِ ٱللَّهِ ثُمَّ لَا يُتْبِعُونَ مَآ أَنفَقُوا۟ مَنًّۭا وَلَآ أَذًۭى ۙ لَّهُمْ أَجْرُهُمْ عِندَ رَبِّهِمْ وَلَا خَوْفٌ عَلَيْهِمْ وَلَا هُمْ يَحْزَنُونَ", 't': "«الذين ينفقون أموالهم في سبيل الله ثم لا يُتبِعون ما أنفقوا مَنًّا» على المنفق عليه بقولهم مثلا: قد أحسنت إليه وجبرت حاله «ولا أذًى» له بذكر ذلك إلى من لا يجب وقوفه عليه ونحو «لهم أجرهم» ثواب إنفاقهم «عند ربهم ولا خوف عليهم ولا هم يحزنون» في الآخرة."},
  {'n': '263', 'v': "۞ قَوْلٌۭ مَّعْرُوفٌۭ وَمَغْفِرَةٌ خَيْرٌۭ مِّن صَدَقَةٍۢ يَتْبَعُهَآ أَذًۭى ۗ وَٱللَّهُ غَنِىٌّ حَلِيمٌۭ", 't': "«قول معروف» كلام حسن ورد على السائل جميل «ومغفرة» له في إلحاحه «خير من صدقة يتبعها أذًى» بالمن وتعيير له بالسؤال «والله غني» عن صدقة العباد «حليم» بتأخير العقوبة عن المانّ والمؤذي."},
  {'n': '264', 'v': "يَٰٓأَيُّهَا ٱلَّذِينَ ءَامَنُوا۟ لَا تُبْطِلُوا۟ صَدَقَٰتِكُم بِٱلْمَنِّ وَٱلْأَذَىٰ كَٱلَّذِى يُنفِقُ مَالَهُۥ رِئَآءَ ٱلنَّاسِ وَلَا يُؤْمِنُ بِٱللَّهِ وَٱلْيَوْمِ ٱلْءَاخِرِ ۖ فَمَثَلُهُۥ كَمَثَلِ صَفْوَانٍ عَلَيْهِ تُرَابٌۭ فَأَصَابَهُۥ وَابِلٌۭ فَتَرَكَهُۥ صَلْدًۭا ۖ لَّا يَقْدِرُونَ عَلَىٰ شَىْءٍۢ مِّمَّا كَسَبُوا۟ ۗ وَٱللَّهُ لَا يَهْدِى ٱلْقَوْمَ ٱلْكَٰفِرِينَ", 't': "«يأيها الذين آمنوا لا تبطلوا صدقاتكم» أي أجورها «بالمن والأذى» إبطالا «كالذي» أي كإبطال نفقة الذي «ينفق ماله رئاء الناس» مرائيا لهم «ولا يؤمن بالله واليوم الآخر» هو المنافق «فمثله كمثل صفوان» حجر أملس «عليه تراب فأصابه وابل» مطر شديد «فتركه صلدا» صلبا أملس لا شيء عليه «لا يقدرون» استئناف لبيان مثل المنافق المنفق رئاء الناس وجمع الضمير باعتبار معنى الذي «على شيء مما كسبوا» عملوا أي لا يجدون له ثوابا في الآخرة كما لا يوجد على الصفوان شئ من التراب الذي كان عليه لإذهاب المطر له «والله لا يهدى القوم الكافرين»."},
  {'n': '265', 'v': "وَمَثَلُ ٱلَّذِينَ يُنفِقُونَ أَمْوَٰلَهُمُ ٱبْتِغَآءَ مَرْضَاتِ ٱللَّهِ وَتَثْبِيتًۭا مِّنْ أَنفُسِهِمْ كَمَثَلِ جَنَّةٍۭ بِرَبْوَةٍ أَصَابَهَا وَابِلٌۭ فَـَٔاتَتْ أُكُلَهَا ضِعْفَيْنِ فَإِن لَّمْ يُصِبْهَا وَابِلٌۭ فَطَلٌّۭ ۗ وَٱللَّهُ بِمَا تَعْمَلُونَ بَصِيرٌ", 't': "«ومثل» نفقات «الذين ينفقون أموالهم ابتغاء» طلب «مرضات الله وتثبيتا من أنفسهم» أي تحقيقا للثواب عليه بخلاف المنافقين الذين لا يرجونه لإنكارهم له ومَن ابتدائية «كمثل جنة» بستان «بِرُبْوَةٍ» بضم الراء وفتحتها مكان مرتفع مستو «أصابها وابل فآتت» أعطت «أكلَها» بضم الكاف وسكونها ثمرها «ضعفين» مثلَيْ ما يثمر غيرها «فإن لم يصبها وابل فطلٌ» مطر خفيف يصيبها ويكفيها لارتفاعها، المعنى: تثمر وتزكو كثر المطر أم قل فكذلك نفقات من ذكر تزكو عند الله كثرت أم قلت «والله بما تعلمون بصير» فيجازيكم به."},
  {'n': '266', 'v': "أَيَوَدُّ أَحَدُكُمْ أَن تَكُونَ لَهُۥ جَنَّةٌۭ مِّن نَّخِيلٍۢ وَأَعْنَابٍۢ تَجْرِى مِن تَحْتِهَا ٱلْأَنْهَٰرُ لَهُۥ فِيهَا مِن كُلِّ ٱلثَّمَرَٰتِ وَأَصَابَهُ ٱلْكِبَرُ وَلَهُۥ ذُرِّيَّةٌۭ ضُعَفَآءُ فَأَصَابَهَآ إِعْصَارٌۭ فِيهِ نَارٌۭ فَٱحْتَرَقَتْ ۗ كَذَٰلِكَ يُبَيِّنُ ٱللَّهُ لَكُمُ ٱلْءَايَٰتِ لَعَلَّكُمْ تَتَفَكَّرُونَ", 't': "«أيَوَدُّ» أيحب «أحدكم أن تكون له جنة» بستان «من نخيل وأعناب تجري من تحتها الأنهار له فيها» ثمر «من كل الثمرات و» قد «أصابه الكبر» فضعف من الكبر عن الكسب «وله ذُرِّيةٌ ضعفاء» أولاد صغار لا يقدرون عليه «فأصابها إعصار» ريح شديدة «فيه نار فاحترقت» ففقدها أحوج ما كان إليها وبقي هو وأولاده عجزة متحيرين لا حيلة لهم وهذا تمثيل لنفقة المرائي والمانّ في ذهابها وعدم نفعها أحوج ما يكون إليها في الآخرة والاستفهام بمعنى النفي، وعن ابن عباس هو الرجل عمل بالطاعات ثم بعث له الشيطان فعمل بالمعاصي حتى أحرق أعماله «كذلك» كما بين ما ذكر «يبين الله لكم الآيات لعلكم تتفكرون» فتعتبرون."},
  {'n': '267', 'v': "يَٰٓأَيُّهَا ٱلَّذِينَ ءَامَنُوٓا۟ أَنفِقُوا۟ مِن طَيِّبَٰتِ مَا كَسَبْتُمْ وَمِمَّآ أَخْرَجْنَا لَكُم مِّنَ ٱلْأَرْضِ ۖ وَلَا تَيَمَّمُوا۟ ٱلْخَبِيثَ مِنْهُ تُنفِقُونَ وَلَسْتُم بِـَٔاخِذِيهِ إِلَّآ أَن تُغْمِضُوا۟ فِيهِ ۚ وَٱعْلَمُوٓا۟ أَنَّ ٱللَّهَ غَنِىٌّ حَمِيدٌ", 't': "«يا أيها الذين آمنوا أنفقوا» أي زكوا «من طيبات» جياد «ما كسبتم» من المال «ومـ» ـن طيبات «ما أخرجنا لكم من الأرض» من الحبوب والثمار «ولا تيمموا» تقصدوا «الخبيث» الرديء «منه» أي من المذكور «تنفقونـ» ـه في الزكاة حال من ضمير تيمموا «ولستم بآخذيه» أي الخبيث لو أعطيتموه في حقوقكم «إلا أن تغمضوا فيه» بالتساهل وغض البصر فكيف تؤدون منه حق الله «واعلموا أن الله غني» عن نفقاتكم «حميد» محمود على كل حال."},
  {'n': '268', 'v': "ٱلشَّيْطَٰنُ يَعِدُكُمُ ٱلْفَقْرَ وَيَأْمُرُكُم بِٱلْفَحْشَآءِ ۖ وَٱللَّهُ يَعِدُكُم مَّغْفِرَةًۭ مِّنْهُ وَفَضْلًۭا ۗ وَٱللَّهُ وَٰسِعٌ عَلِيمٌۭ", 't': "«الشيطان يعدكم الفقر» يخوفكم به إن تصدقتم فتمسكوا «ويأمركم بالفحشاء» البخل ومنع الزكاة «والله يعدكم» على الإنفاق «مغفرة منه» لذنوبكم «وفضلا» رزقا خلفا منه «والله واسع» فضله «عليم» بالمنفق."},
  {'n': '269', 'v': "يُؤْتِى ٱلْحِكْمَةَ مَن يَشَآءُ ۚ وَمَن يُؤْتَ ٱلْحِكْمَةَ فَقَدْ أُوتِىَ خَيْرًۭا كَثِيرًۭا ۗ وَمَا يَذَّكَّرُ إِلَّآ أُو۟لُوا۟ ٱلْأَلْبَٰبِ", 't': "«يؤتي الحكمة» أي العلم النافع المؤدي إلى العمل «من يشاء ومن يُؤت الحكمة فقد أوتي خيرا كثيرا» لمصيره إلى السعادة الأبدية «وما يذَّكَّر» فيه إدغام التاء في الأصل في الذال يتعظ «إلا أولوا الألباب» أصحاب العقول."},
  {'n': '270', 'v': "وَمَآ أَنفَقْتُم مِّن نَّفَقَةٍ أَوْ نَذَرْتُم مِّن نَّذْرٍۢ فَإِنَّ ٱللَّهَ يَعْلَمُهُۥ ۗ وَمَا لِلظَّٰلِمِينَ مِنْ أَنصَارٍ", 't': "«وما أنفقتم من نفقة» أديتم من زكاة أو صدقة «أو نذرتم من نذر» فوفيتم به «فإن الله يعلمه» فيجازيكم عليه «وما للظالمين» بمنع الزكاة والنذر أو بوضع الإنفاق في غير محله من معاصي الله «من أنصار» مانعين لهم من عذابه."},
  {'n': '271', 'v': "إِن تُبْدُوا۟ ٱلصَّدَقَٰتِ فَنِعِمَّا هِىَ ۖ وَإِن تُخْفُوهَا وَتُؤْتُوهَا ٱلْفُقَرَآءَ فَهُوَ خَيْرٌۭ لَّكُمْ ۚ وَيُكَفِّرُ عَنكُم مِّن سَيِّـَٔاتِكُمْ ۗ وَٱللَّهُ بِمَا تَعْمَلُونَ خَبِيرٌۭ", 't': "«إن تبدوا» تظهروا «الصدقات» أي النوافل «فَنعمَّا هي» أي نعم شيئاً إبداؤها «وإن تخفوها» تسروها «وتؤتوها الفقراء فهو خير لكم» من إبدائها وإيتائها الأغنياء أما صدقة الفرض فالأفضل إظهارها ليقتدي به ولئلا يتهم، وإيتاؤها الفقراء متعين «ويكَفِّر» بالياء والنون مجزوما بالعطف على محل فهو ومرفوعا على الاستئناف «عنكم من» بعض «سيئاتكم والله بما تعملون خبير» عالم بباطنه كظاهره لا يخفى عليه شيء منه."},
  {'n': '272', 'v': "۞ لَّيْسَ عَلَيْكَ هُدَىٰهُمْ وَلَٰكِنَّ ٱللَّهَ يَهْدِى مَن يَشَآءُ ۗ وَمَا تُنفِقُوا۟ مِنْ خَيْرٍۢ فَلِأَنفُسِكُمْ ۚ وَمَا تُنفِقُونَ إِلَّا ٱبْتِغَآءَ وَجْهِ ٱللَّهِ ۚ وَمَا تُنفِقُوا۟ مِنْ خَيْرٍۢ يُوَفَّ إِلَيْكُمْ وَأَنتُمْ لَا تُظْلَمُونَ", 't': "ولما منع صلى الله عليه وسلم من التصدق على المشركين ليسلموا نزل: «ليس عليك هداهم» أي الناس إلى الدخول في الإسلام إنما عليك البلاغ «ولكن الله يهدي من يشاء» هدايته إلى الدخول فيه «وما تنفقوا من خير» مال «فلأنفسكم» لأن ثوابه لها «وما تنفقون إلا ابتغاء وجه الله» أي ثوابه لاغيره من أعراض الدنيا خبر بمعنى النهي «وما تنفقوا من خير يوفَّ إليكم» جزاؤه «وأنتم لا تُظلمون» تنقصون منه شيئاً والجملتان تأكيد للأولى."},
  {'n': '273', 'v': "لِلْفُقَرَآءِ ٱلَّذِينَ أُحْصِرُوا۟ فِى سَبِيلِ ٱللَّهِ لَا يَسْتَطِيعُونَ ضَرْبًۭا فِى ٱلْأَرْضِ يَحْسَبُهُمُ ٱلْجَاهِلُ أَغْنِيَآءَ مِنَ ٱلتَّعَفُّفِ تَعْرِفُهُم بِسِيمَٰهُمْ لَا يَسْـَٔلُونَ ٱلنَّاسَ إِلْحَافًۭا ۗ وَمَا تُنفِقُوا۟ مِنْ خَيْرٍۢ فَإِنَّ ٱللَّهَ بِهِۦ عَلِيمٌ", 't': "«للفقراء» خبر مبتدأ محذوف أي الصدقات «الذين أحصروا في سبيل الله» أي حبسوا أنفسهم على الجهاد، نزلت في أهل الصُّفَّةِ وهم أربعمائة من المهاجرين أرصدوا لتعلم القرآن والخروج مع السرايا «لا يستطيعون ضربا» سفرا «في الأرض» للتجارة والمعاش لشغلهم عنه بالجهاد «يحسبهم الجاهل» بحالهم «أغنياء من التعفف» أي لتعففهم عن السؤال وتركه «تعرفهم» يا مخاطب «بسيماهم» علامتهم من التواضع وأثر الجهد «لا يسألون الناس» شيئا فيلحفون «إلحافا» أي لا سؤال لهم أصلا فلا يقع منهم إلحاف وهو الإلحاح «وما تنفقوا من خير فإن الله به عليم» فمجاز عليه."},
  {'n': '274', 'v': "ٱلَّذِينَ يُنفِقُونَ أَمْوَٰلَهُم بِٱلَّيْلِ وَٱلنَّهَارِ سِرًّۭا وَعَلَانِيَةًۭ فَلَهُمْ أَجْرُهُمْ عِندَ رَبِّهِمْ وَلَا خَوْفٌ عَلَيْهِمْ وَلَا هُمْ يَحْزَنُونَ", 't': "«الذين ينفقون أموالهم بالليل والنهار سرا وعلانية فلهم أجرهم عند ربَّهم ولا خوف عليهم ولا هم يحزنون»."},
  {'n': '275', 'v': "ٱلَّذِينَ يَأْكُلُونَ ٱلرِّبَوٰا۟ لَا يَقُومُونَ إِلَّا كَمَا يَقُومُ ٱلَّذِى يَتَخَبَّطُهُ ٱلشَّيْطَٰنُ مِنَ ٱلْمَسِّ ۚ ذَٰلِكَ بِأَنَّهُمْ قَالُوٓا۟ إِنَّمَا ٱلْبَيْعُ مِثْلُ ٱلرِّبَوٰا۟ ۗ وَأَحَلَّ ٱللَّهُ ٱلْبَيْعَ وَحَرَّمَ ٱلرِّبَوٰا۟ ۚ فَمَن جَآءَهُۥ مَوْعِظَةٌۭ مِّن رَّبِّهِۦ فَٱنتَهَىٰ فَلَهُۥ مَا سَلَفَ وَأَمْرُهُۥٓ إِلَى ٱللَّهِ ۖ وَمَنْ عَادَ فَأُو۟لَٰٓئِكَ أَصْحَٰبُ ٱلنَّارِ ۖ هُمْ فِيهَا خَٰلِدُونَ", 't': "«الذين يأكلون الربا» أي ياخذونه وهو الزيادة في المعاملة بالنقود والمطعومات في القدر أو الأجل «لا يقومون» من قبورهم «إلا» قياما «كما يقوم الذي يتخبطه» يصرعه «الشيطان من المس» الجنون، متعلق بيقومون «ذلك» الذي نزل بهم «بأنهم» بسبب أنهم «قالوا إنما البيع مثل الربا» في الجواز وهذا من عكس التشبيه مبالغة فقال تعالى ردا عليهم: «وأحل الله البيع وحرم الربا فمن جاءه» بلغه «موعظة» وعظ «من ربِّه فانتهى» عن أكله «فله ما سلف» قبل النهي أي لا يسترد منه «وأمره» في العفو عنه «إلى الله ومن عاد» إلى أكله مشبها له بالبيع في الحلِّ «فأولئك أصحاب النار هم فيها خالدون»."},
  {'n': '276', 'v': "يَمْحَقُ ٱللَّهُ ٱلرِّبَوٰا۟ وَيُرْبِى ٱلصَّدَقَٰتِ ۗ وَٱللَّهُ لَا يُحِبُّ كُلَّ كَفَّارٍ أَثِيمٍ", 't': "«يمحق الله الربا» ينقصه ويذهب بركته «ويربي الصدقات» يزيدها وينميها ويضاعف ثوابها «والله لا يحب كل كفَّار» بتحليل الربا «أثيم» فاجر بأكله أي يعاقبه."},
  {'n': '277', 'v': "إِنَّ ٱلَّذِينَ ءَامَنُوا۟ وَعَمِلُوا۟ ٱلصَّٰلِحَٰتِ وَأَقَامُوا۟ ٱلصَّلَوٰةَ وَءَاتَوُا۟ ٱلزَّكَوٰةَ لَهُمْ أَجْرُهُمْ عِندَ رَبِّهِمْ وَلَا خَوْفٌ عَلَيْهِمْ وَلَا هُمْ يَحْزَنُونَ", 't': "«إن الذين آمنوا وعملوا الصالحات وأقاموا الصلاة وآتوا الزكاة لهم أجرهم عند ربهم ولا خوف عليهم ولا هم يحزنون»."},
  {'n': '278', 'v': "يَٰٓأَيُّهَا ٱلَّذِينَ ءَامَنُوا۟ ٱتَّقُوا۟ ٱللَّهَ وَذَرُوا۟ مَا بَقِىَ مِنَ ٱلرِّبَوٰٓا۟ إِن كُنتُم مُّؤْمِنِينَ", 't': "«يا أيها الذين آمنوا اتقوا الله وذروا» اتركوا «ما بقي من الربا إن كنتم مؤمنين» صادقين في إيمانكم فإن من شأن المؤمن امتثال أمر الله تعالى، نزلت لما طالب بعض الصحابة بعد النهي بربا كان لهم من قبل."},
  {'n': '279', 'v': "فَإِن لَّمْ تَفْعَلُوا۟ فَأْذَنُوا۟ بِحَرْبٍۢ مِّنَ ٱللَّهِ وَرَسُولِهِۦ ۖ وَإِن تُبْتُمْ فَلَكُمْ رُءُوسُ أَمْوَٰلِكُمْ لَا تَظْلِمُونَ وَلَا تُظْلَمُونَ", 't': "«فإن لم تفعلوا» ما أمرتم به «فأذنوا» اعلمَوا «بحرب من الله ورسوله» لكم فيه تهديد شديد لهم ولما نزلت قالوا لا بد لنا بحربه «وإن تبتم» رجعتم عنه «فلكم رءوس» أصول «أموالكم لاتَظلمون» بزيادة «ولا تُظلمون» بنقص."},
  {'n': '280', 'v': "وَإِن كَانَ ذُو عُسْرَةٍۢ فَنَظِرَةٌ إِلَىٰ مَيْسَرَةٍۢ ۚ وَأَن تَصَدَّقُوا۟ خَيْرٌۭ لَّكُمْ ۖ إِن كُنتُمْ تَعْلَمُونَ", 't': "(وإن كان) وقع غريم (ذو عسرة فنظرة) له أي عليكم تأخيره (إلى ميسرة) بفتح السين وضمها أي وقت يسر (وأن تصدقوا) بالتشديد على إدغام التاء في الأصل في الصاد وبالتخفيف على حذفها أي تتصدقوا على المعسر بالإبراء (خير لكم إن كنتم تعلمون) أنه خير فافعلوه وفي الحديث \"\" من أنظر معسرا أو وضع عنه أظله الله في ظله يوم لا ظل إلا ظله \"\" رواه مسلم."},
  {'n': '281', 'v': "وَٱتَّقُوا۟ يَوْمًۭا تُرْجَعُونَ فِيهِ إِلَى ٱللَّهِ ۖ ثُمَّ تُوَفَّىٰ كُلُّ نَفْسٍۢ مَّا كَسَبَتْ وَهُمْ لَا يُظْلَمُونَ", 't': "«واتقوا يوما تُرجعون» بالبناء للمفعول تردون وللفاعل تصيرون «فيه إلى الله» هو يوم القيامة «ثم توفَّى» فيه «كل نفس» جزاء «ما كسبت» عملت من خير وشر «وهم لا يُظلمون» بنقص حسنة أو زيادة سيْئة."},
  {'n': '282', 'v': "يَٰٓأَيُّهَا ٱلَّذِينَ ءَامَنُوٓا۟ إِذَا تَدَايَنتُم بِدَيْنٍ إِلَىٰٓ أَجَلٍۢ مُّسَمًّۭى فَٱكْتُبُوهُ ۚ وَلْيَكْتُب بَّيْنَكُمْ كَاتِبٌۢ بِٱلْعَدْلِ ۚ وَلَا يَأْبَ كَاتِبٌ أَن يَكْتُبَ كَمَا عَلَّمَهُ ٱللَّهُ ۚ فَلْيَكْتُبْ وَلْيُمْلِلِ ٱلَّذِى عَلَيْهِ ٱلْحَقُّ وَلْيَتَّقِ ٱللَّهَ رَبَّهُۥ وَلَا يَبْخَسْ مِنْهُ شَيْـًۭٔا ۚ فَإِن كَانَ ٱلَّذِى عَلَيْهِ ٱلْحَقُّ سَفِيهًا أَوْ ضَعِيفًا أَوْ لَا يَسْتَطِيعُ أَن يُمِلَّ هُوَ فَلْيُمْلِلْ وَلِيُّهُۥ بِٱلْعَدْلِ ۚ وَٱسْتَشْهِدُوا۟ شَهِيدَيْنِ مِن رِّجَالِكُمْ ۖ فَإِن لَّمْ يَكُونَا رَجُلَيْنِ فَرَجُلٌۭ وَٱمْرَأَتَانِ مِمَّن تَرْضَوْنَ مِنَ ٱلشُّهَدَآءِ أَن تَضِلَّ إِحْدَىٰهُمَا فَتُذَكِّرَ إِحْدَىٰهُمَا ٱلْأُخْرَىٰ ۚ وَلَا يَأْبَ ٱلشُّهَدَآءُ إِذَا مَا دُعُوا۟ ۚ وَلَا تَسْـَٔمُوٓا۟ أَن تَكْتُبُوهُ صَغِيرًا أَوْ كَبِيرًا إِلَىٰٓ أَجَلِهِۦ ۚ ذَٰلِكُمْ أَقْسَطُ عِندَ ٱللَّهِ وَأَقْوَمُ لِلشَّهَٰدَةِ وَأَدْنَىٰٓ أَلَّا تَرْتَابُوٓا۟ ۖ إِلَّآ أَن تَكُونَ تِجَٰرَةً حَاضِرَةًۭ تُدِيرُونَهَا بَيْنَكُمْ فَلَيْسَ عَلَيْكُمْ جُنَاحٌ أَلَّا تَكْتُبُوهَا ۗ وَأَشْهِدُوٓا۟ إِذَا تَبَايَعْتُمْ ۚ وَلَا يُضَآرَّ كَاتِبٌۭ وَلَا شَهِيدٌۭ ۚ وَإِن تَفْعَلُوا۟ فَإِنَّهُۥ فُسُوقٌۢ بِكُمْ ۗ وَٱتَّقُوا۟ ٱللَّهَ ۖ وَيُعَلِّمُكُمُ ٱللَّهُ ۗ وَٱللَّهُ بِكُلِّ شَىْءٍ عَلِيمٌۭ", 't': "«يا أيها الذين آمنوا إذا تداينتم» تعاملتم «بدين» كسلم وقرض «إلى أجل مسمى» معلوم «فاكتبوه» استيثاقا ودفعا للنزاع «وليكتب» كتاب الدين «بينكم كاتب بالعدل» بالحق في كتابته لا يزيد في المال والأجل ولا ينقص «ولا يأب» يمتنع «كاتب» من «أن يكتب» إذا دُعي إليها «كما علَّمه الله» أي فضله بالكتابة فلا يبخل بها والكاف متعلقة بيأب «فليكتب» تأكيد «وليملل» على الكاتب «الذي عليه الحق» الدين لأنه المشهود عليه فيقر ليعلم ما عليه «وليتق الله ربه» في إملائه «ولا يبخس» ينقص «منه» أي الحق «شيئا فإن كان الذي عليه الحق سفيها» مبذرا «أو ضعيفا» عن الإملاء لصغر أو كبر «أو لا يستطيع أن يُملَّ هو» لخرس أو جهل باللغة أو نحو ذلك «فَلْيُمْلِلْ وليُّه» متولي أمره من والد ووصي وقيِّم ومترجم «بالعدل واستشهدوا» أشهدوا على الدَّين «شهيدين» شاهدين «من رجالكم» أي بالغي المسلمين الأحرار «فإن لم يكونا» أي الشهيدان «رجلين فرجل وامرأتان» يشهدون «ممن ترضون من الشهداء» لدينه وعدالته وتعدد النساء لأجل «أن تضل» تنسى «إحداهما» الشهادة لنقص عقلهن وضبطهن «فَتُذكِّرَ» بالتخفيف والتشديد «إحداهما» الذاكرة «الأخرى» الناسية وجملة الإذكار محل العلة أي لتذكر أن ضلت ودخلت على الضلال لأنه سببه وفي قراءة بكسر أن شرطية ورفع تذكر استئناف جوابه «ولا يأب الشهداء إذا ما» زائدة «دُعوا» إلى تحمل الشهادة وأدائها «ولا تسأموا» تملوا من «أن تكتبوه» أي ما شهدتم عليه من الحق لكثرة وقوع ذلك «صغيرا» كان «أو كبيرا» قليلا أو كثيرا «إلى أجله» وقت حلوله حال من الهاء في تكتبوه «ذلكم» أي الكتب «أقسط» أعدل «عند الله وأقوم للشهادة» أي أعون على إقامتها لأنه يذكرها «وأدنى» اقرب إلى «أ» ن «لا ترتابوا» تشكوا في قدر الحق والأجل «إلا أن تكون» تقع «تجارةٌ حاضرةٌ» وفي قراءة بالنصب فتكون ناقصة واسمها ضمير التجارة «تديرونها بينكم» أي تقبضونها ولا أجل فيها «فليس عليكم جُناح» في «ألا تكتبوها» والمراد بها المتجر فيه «وأشهدوا إذا تبايعتم» عليه فأنه أدفع للاختلاف وهذا وما قبله أمر ندب «ولا يُضارّ كاتب ولا شهيد» صاحب الحق ومن عليه بتحريف أو امتناع من الشهادة أو الكتابة ولا يضرهما صاحب الحق بتكليفها ما لا يليق في الكتابة والشهادة «وإن تفعلوا» ما نُهيتم عنه «فإنه فسوق» خروج عن الطاعة لاحق «بكم واتقوا الله» في أمره ونهيه «ويعلمكم الله» مصالح أموركم حال مقدرة أو مستأنف «والله بكل شيء عليم»."},
  {'n': '283', 'v': "۞ وَإِن كُنتُمْ عَلَىٰ سَفَرٍۢ وَلَمْ تَجِدُوا۟ كَاتِبًۭا فَرِهَٰنٌۭ مَّقْبُوضَةٌۭ ۖ فَإِنْ أَمِنَ بَعْضُكُم بَعْضًۭا فَلْيُؤَدِّ ٱلَّذِى ٱؤْتُمِنَ أَمَٰنَتَهُۥ وَلْيَتَّقِ ٱللَّهَ رَبَّهُۥ ۗ وَلَا تَكْتُمُوا۟ ٱلشَّهَٰدَةَ ۚ وَمَن يَكْتُمْهَا فَإِنَّهُۥٓ ءَاثِمٌۭ قَلْبُهُۥ ۗ وَٱللَّهُ بِمَا تَعْمَلُونَ عَلِيمٌۭ", 't': "«وإن كنتم على سفر» أي مسافرين وتداينتم «ولم تجدوا كاتبا فَرِهاَنٌ» وفي قراءة فَرهُنٌ جمع رهن «مقبوضة» تستوثقون بها وبينت السنة جواز الرهن في الحضر ووجود الكاتب فالتقيد بما ذكر لأن التوثيق فيه أشد وأفاد قوله مقبوضة اشتراط القبض في الرهن والاكتفاء به من المرتهن ووكيله «فإن أمن بعضكم بعضا» أي الدائن المدين على حقه فلم يرتهن «فليؤد الذي أؤتمن» أي المدين «أمانته» دينه «وليتق الله ربَّه» في أدائه «ولا تكتموا الشهادة» إذا دُعيتم لإقامتها «ومن يكتمها فإنه آثم قلبه» خص بالذكر لأنه محل الشهادة ولأنه إذا أثم تبعه غيره فيعاقب عليه معاقبة الآثمين «والله بما تعلمون عليم» لا يخفَى عليه شيء منه."},
  {'n': '284', 'v': "لِّلَّهِ مَا فِى ٱلسَّمَٰوَٰتِ وَمَا فِى ٱلْأَرْضِ ۗ وَإِن تُبْدُوا۟ مَا فِىٓ أَنفُسِكُمْ أَوْ تُخْفُوهُ يُحَاسِبْكُم بِهِ ٱللَّهُ ۖ فَيَغْفِرُ لِمَن يَشَآءُ وَيُعَذِّبُ مَن يَشَآءُ ۗ وَٱللَّهُ عَلَىٰ كُلِّ شَىْءٍۢ قَدِيرٌ", 't': "«لله ما في السماوات وما في الأرض وإن تبدوا» تظهروا «ما في أنفسكم» من السوء والعزم عليه «أو تخفوه» تسروه «يحاسبكم» يخبركم «به الله» يوم القيامة «فيغفرْ لمن يشاء» المغفرة له «ويعذبْ من يشاء» تعذيبه والفعلان بالجزم عطف على جواب الشرط والرفع أي فهو «والله على كل شيء قدير» ومنه محاسبتكم وجزاؤكم."},
  {'n': '285', 'v': "ءَامَنَ ٱلرَّسُولُ بِمَآ أُنزِلَ إِلَيْهِ مِن رَّبِّهِۦ وَٱلْمُؤْمِنُونَ ۚ كُلٌّ ءَامَنَ بِٱللَّهِ وَمَلَٰٓئِكَتِهِۦ وَكُتُبِهِۦ وَرُسُلِهِۦ لَا نُفَرِّقُ بَيْنَ أَحَدٍۢ مِّن رُّسُلِهِۦ ۚ وَقَالُوا۟ سَمِعْنَا وَأَطَعْنَا ۖ غُفْرَانَكَ رَبَّنَا وَإِلَيْكَ ٱلْمَصِيرُ", 't': "«آمن» صدق «الرسول» محمد صلى الله عليه وسلم «بما أنزل إليه من ربه» من القرآن «والمؤمنون» عطف عليه «كل» تنوين عوض من المضاف إليه «آمن بالله وملائكته وكتبه» بالجمع والإفراد «ورسله» يقولون «لا نفرق بين أحد من رسله» فنؤمن ببعض ونكفر ببعض كما فعل اليهود والنصارى «وقالوا سمعنا» أي ما أمرنا به سماع قبول «وأطعنا» نسألك «غفرانك ربنا وإليك المصير» المرجع بالبعث، ولما نزلت الآية التي قبلها شكا المؤمنون من الوسوسة وشق عليهم المحاسبة بها فنزل."},
  {'n': '286', 'v': "لَا يُكَلِّفُ ٱللَّهُ نَفْسًا إِلَّا وُسْعَهَا ۚ لَهَا مَا كَسَبَتْ وَعَلَيْهَا مَا ٱكْتَسَبَتْ ۗ رَبَّنَا لَا تُؤَاخِذْنَآ إِن نَّسِينَآ أَوْ أَخْطَأْنَا ۚ رَبَّنَا وَلَا تَحْمِلْ عَلَيْنَآ إِصْرًۭا كَمَا حَمَلْتَهُۥ عَلَى ٱلَّذِينَ مِن قَبْلِنَا ۚ رَبَّنَا وَلَا تُحَمِّلْنَا مَا لَا طَاقَةَ لَنَا بِهِۦ ۖ وَٱعْفُ عَنَّا وَٱغْفِرْ لَنَا وَٱرْحَمْنَآ ۚ أَنتَ مَوْلَىٰنَا فَٱنصُرْنَا عَلَى ٱلْقَوْمِ ٱلْكَٰفِرِينَ", 't': "(لا يكلف الله نفساً إلا وسعها) أي ما تسعه قدرتها (لها ما كسبت) من الخير أي ثوابه (وعليها ما اكتسبت) من الشر أي وزره ولا يؤاخذ أحد بذنب أحد ولا بما لم يكسبه مما وسوست به نفسه، قولوا (ربنا لا تؤاخذنا) بالعقاب (إن نسينا أو أخطأنا) تركنا الصواب لا عن عمد كما أخذت به من قبلنا وقد رفع الله ذلك عن هذه الأمة كما ورد في الحديث فسؤاله اعتراف بنعمة الله (ربنا ولا تحمل علينا إصراً) أمرا يثقل علينا حمله (كما حملته على الذين من قبلنا) أي بني إسرائيل من قتل النفس في التوبة وإخراج ربع المال في الزكاة وقرض موضع النجاسة (ربنا ولا تحملنا ما لا طاقة) قوة (لنا به) من التكاليف والبلاء (واعف عنا) امح ذنوبنا (واغفر لنا وارحمنا) في الرحمة زيادة على المغفرة (أنت مولانا) سيدنا ومتولي أمورنا (فانصرنا على القوم الكافرين) بإقامة الحجة والغلبة في قتالهم فإن من شأن المولى أن ينصر مواليه على الأعداء، وفي الحديث \"\" لما نزلت هذه الآية فقرأها صلى الله عليه وسلم قيل له عقب كل كلمة قد فعلت \"\"."},
