  {'n': '5', 'v': "إِنَّ ٱللَّهَ لَا يَخْفَىٰ عَلَيْهِ شَىْءٌۭ فِى ٱلْأَرْضِ وَلَا فِى ٱلسَّمَآءِ", 't': "«إن الله لا يخفى عليه شيء» كائن «في الأرض ولا في السماء» لعلمه بما يقع في العالم من كلَّي وجزئي وخصمهما بالذكر لأن الحس لا يتجاوزهما."},
  {'n': '6', 'v': "هُوَ ٱلَّذِى يُصَوِّرُكُمْ فِى ٱلْأَرْحَامِ كَيْفَ يَشَآءُ ۚ لَآ إِلَٰهَ إِلَّا هُوَ ٱلْعَزِيزُ ٱلْحَكِيمُ", 't': "«هو الذي يصوّركم في الأرحام كيف يشاء» من ذكورة وأنوثة وبياض وسواد وغير ذلك «لا إله إلا هو العزيز» في ملكه «الحكيم» في صنعه."},
  {'n': '7', 'v': "هُوَ ٱلَّذِىٓ أَنزَلَ عَلَيْكَ ٱلْكِتَٰبَ مِنْهُ ءَايَٰتٌۭ مُّحْكَمَٰتٌ هُنَّ أُمُّ ٱلْكِتَٰبِ وَأُخَرُ مُتَشَٰبِهَٰتٌۭ ۖ فَأَمَّا ٱلَّذِينَ فِى قُلُوبِهِمْ زَيْغٌۭ فَيَتَّبِعُونَ مَا تَشَٰبَهَ مِنْهُ ٱبْتِغَآءَ ٱلْفِتْنَةِ وَٱبْتِغَآءَ تَأْوِيلِهِۦ ۗ وَمَا يَعْلَمُ تَأْوِيلَهُۥٓ إِلَّا ٱللَّهُ ۗ وَٱلرَّٰسِخُونَ فِى ٱلْعِلْمِ يَقُولُونَ ءَامَنَّا بِهِۦ كُلٌّۭ مِّنْ عِندِ رَبِّنَا ۗ وَمَا يَذَّكَّرُ إِلَّآ أُو۟لُوا۟ ٱلْأَلْبَٰبِ", 't': "(هو الذي أنزل عليك الكتاب منه آيات محكمات) واضحات الدلالة (هن أم الكتاب) أصله المعتمد عليه في الأحكام (و أخر متشابهات) لا تفهم معانيها كأوائل السور وجعله كله محكما في قوله \"\" أحكمت آياته \"\" بمعنى أنه ليس فيه عيب، ومتشابهًا في قوله (كتابا متشابهًا) بمعنى أنه يشبه بعضه بعضا في الحسن والصدق (فأما الذين في قلوبهم زيغ) ميل عن الحق (فيتبعون ما تشابه منه ابتغاء) طلب (الفتنة) لجهالهم بوقوعهم في الشبهات واللبس (وابتغاء تأويله) تفسيره (وما يعلم تأويله) تفسيره (إلا الله) وحده (والراسخون) الثابتون المتمكنون (في العلم) مبتدأ خبره (يقولون آمنا به) أي بالمتشابه أنه من عند الله ولا نعلم معناه (كل) من المحكم والمتشابه (من عند ربنا وما يذكر) بادغام التاء في الأصل في الذال أي يتعظ (إلا أولوا الألباب) أصحاب العقول ويقولون أيضا إذا رأوا من يتبعه."},
  {'n': '8', 'v': "رَبَّنَا لَا تُزِغْ قُلُوبَنَا بَعْدَ إِذْ هَدَيْتَنَا وَهَبْ لَنَا مِن لَّدُنكَ رَحْمَةً ۚ إِنَّكَ أَنتَ ٱلْوَهَّابُ", 't': "«ربنا لا تُزغ قلوبنا» تملها عن الحق بابتغاء تأويله الذي لا يليق بنا كما أزغت قلوب أولئك «بعد إذ هديتنا» أرشدتنا إليه «وهب لنا من لَدنك» من عندك «رحمة» تثبيتا «إنك أنت الوهاب»."},
  {'n': '9', 'v': "رَبَّنَآ إِنَّكَ جَامِعُ ٱلنَّاسِ لِيَوْمٍۢ لَّا رَيْبَ فِيهِ ۚ إِنَّ ٱللَّهَ لَا يُخْلِفُ ٱلْمِيعَادَ", 't': "يا «ربنا إنك جامع الناس» تجمعهم «ليوم» أي في يوم «لا ريب» لا شك «فيه» هو يوم القيامة فتجازيهم بأعمالهم كما وعدت بذلك «إن الله لا يخلف الميعاد» موعده بالبعث فيه التفات عن الخطاب ويحتمل أن يكون من كلامه تعالى والغرض من الدعاء بذلك بيان أن همهم أمر الآخرة ولذلك سألوا الثبات على الهداية لينالوا ثوابها روى الشيخان عن عائشة رضي الله عنها قالت: (تلا رسول الله صلى الله عليه وسلم هذه الآية هو الذي أنزل عليك الكتاب منه آيات محكمات إلى آخرها وقال: فإذا رأيت الذين يتبعون ما تشابه منه فأولئك الذين سمى الله فاحذروهم) وروى الطبراني في الكبير عن أبي موسى الأشعري أنه سمع النبي صلى الله عليه وسلم يقول: (ما أخاف على أمتي إلا ثلاث خلال وذكر منها أن يفتح لهم الكتاب فيأخذه المؤمن يبتغي تأويله وليس يعلم تأويله إلا الله والراسخون في العلم يقولون آمنا به كل من عند ربنا وما يذكر إلا أولو الألباب) الحديث."},
  {'n': '10', 'v': "إِنَّ ٱلَّذِينَ كَفَرُوا۟ لَن تُغْنِىَ عَنْهُمْ أَمْوَٰلُهُمْ وَلَآ أَوْلَٰدُهُم مِّنَ ٱللَّهِ شَيْـًۭٔا ۖ وَأُو۟لَٰٓئِكَ هُمْ وَقُودُ ٱلنَّارِ", 't': "«إن الذين كفروا لن تُغنيَ» تدفع «عنهم أموالهم ولا أولادهم من الله» أي عذابه «شيئا وأولئك هم وقود النار» بفتح الواو ما توقد به."},
  {'n': '11', 'v': "كَدَأْبِ ءَالِ فِرْعَوْنَ وَٱلَّذِينَ مِن قَبْلِهِمْ ۚ كَذَّبُوا۟ بِـَٔايَٰتِنَا فَأَخَذَهُمُ ٱللَّهُ بِذُنُوبِهِمْ ۗ وَٱللَّهُ شَدِيدُ ٱلْعِقَابِ", 't': "دأبُهم «كدأب» كعادة «آل فرعون والذين من قبلهم» من الأمم كعاد وثمود «كذبوا بآياتنا فأخذهم الله» أهلكم «بذنوبهم» والجملة مفسرة لما قبلها «والله شديد العقاب» ونزل لما أمر النبي صلى الله عليه وسلم اليهودَ بالإسلام بعد مرجعه من بدر فقالوا لا يغرنك أن قتلت نفراً من قريش أغمارا لا يعرفون القتال."},
  {'n': '12', 'v': "قُل لِّلَّذِينَ كَفَرُوا۟ سَتُغْلَبُونَ وَتُحْشَرُونَ إِلَىٰ جَهَنَّمَ ۚ وَبِئْسَ ٱلْمِهَادُ", 't': "«قل» يا محمد «للذين كفروا» من اليهود «ستُغلبون» بالتاء والياء في الدنيا بالقتل والأسر وضرب الجزية وقد وقع ذلك «وتُحشرون» بالوجهين في الآخرة «إلى جهنم» فتدخلونها «وبئس المهاد» الفراش هي."},
  {'n': '13', 'v': "قَدْ كَانَ لَكُمْ ءَايَةٌۭ فِى فِئَتَيْنِ ٱلْتَقَتَا ۖ فِئَةٌۭ تُقَٰتِلُ فِى سَبِيلِ ٱللَّهِ وَأُخْرَىٰ كَافِرَةٌۭ يَرَوْنَهُم مِّثْلَيْهِمْ رَأْىَ ٱلْعَيْنِ ۚ وَٱللَّهُ يُؤَيِّدُ بِنَصْرِهِۦ مَن يَشَآءُ ۗ إِنَّ فِى ذَٰلِكَ لَعِبْرَةًۭ لِّأُو۟لِى ٱلْأَبْصَٰرِ", 't': "«قد كان لكم آية» عبرة وذكر الفعل للفصل «في فئتين» فرقتين «التقتا» يوم بدر للقتال «فئة تقاتل في سبيل الله» أي طاعته، وهم النبي وأصحابه وكانوا ثلاثمائة وثلاثة عشر رجلا معهم فرسَان وست أذرع وثمانية سيوف وأكثرهم رجالة «وأخرى كافرة يرونهم» أي الكفار «مثليهم» أي المسلمين أي أكثر منهم وكانوا نحو ألف «رأي العين» أي رؤية ظاهرة معاينة وقد نصرهم الله مع قلتهم «والله يؤيد» يقِّوي «بنصره من يشاء» نصره «إن في ذلك» المذكور «لعبرة لأولي الأبصار» لذوى البصائر أفلا تعتبرون بذلك فتؤمنون."},
  {'n': '14', 'v': "زُيِّنَ لِلنَّاسِ حُبُّ ٱلشَّهَوَٰتِ مِنَ ٱلنِّسَآءِ وَٱلْبَنِينَ وَٱلْقَنَٰطِيرِ ٱلْمُقَنطَرَةِ مِنَ ٱلذَّهَبِ وَٱلْفِضَّةِ وَٱلْخَيْلِ ٱلْمُسَوَّمَةِ وَٱلْأَنْعَٰمِ وَٱلْحَرْثِ ۗ ذَٰلِكَ مَتَٰعُ ٱلْحَيَوٰةِ ٱلدُّنْيَا ۖ وَٱللَّهُ عِندَهُۥ حُسْنُ ٱلْمَـَٔابِ", 't': "«زُيَّن للناس حبُّ الشهوات» ما تشتهيه النفس وتدعوا إليه زينها الله ابتلاءً أو الشيطانُ «من النساء والبنين والقناطير» الأموال الكثيرة «المقنطرة» المجمعة «من الذهب والفضة والخيل المسومة» الحسان «والأنعام» أي الإبل والبقر والغنم «والحرث» الزرع «ذلك» المذكور «متاع الحياة الدنيا» يتمتع به فيها ثم يفنى «والله عنده حسن المآب» المرجع وهو الجنة فينبغي الرغبة فيه دون غيره."},
  {'n': '15', 'v': "۞ قُلْ أَؤُنَبِّئُكُم بِخَيْرٍۢ مِّن ذَٰلِكُمْ ۚ لِلَّذِينَ ٱتَّقَوْا۟ عِندَ رَبِّهِمْ جَنَّٰتٌۭ تَجْرِى مِن تَحْتِهَا ٱلْأَنْهَٰرُ خَٰلِدِينَ فِيهَا وَأَزْوَٰجٌۭ مُّطَهَّرَةٌۭ وَرِضْوَٰنٌۭ مِّنَ ٱللَّهِ ۗ وَٱللَّهُ بَصِيرٌۢ بِٱلْعِبَادِ", 't': "«قل» يا محمد لقومك «أؤنبِّئكم» أخبركم «بخير من ذلكم» المذكور من الشهوات استفهام تقرير «للذين اتقوا» الشرك «عند ربهم» خبر مبتدأُه «جنات تجري من تحتها الأنهار خالدين» أي مقدرين الخلود «فيها» إذا دخلوها «وأزواج مطهرة» من الحيض وغيره مما يستقذر «ورضوان» بكسر أوله وضمه لغتان أي رضا كثير «من الله والله بصير» عالم «بالعباد» فيجازي كلاً منهم بعمله."},
  {'n': '16', 'v': "ٱلَّذِينَ يَقُولُونَ رَبَّنَآ إِنَّنَآ ءَامَنَّا فَٱغْفِرْ لَنَا ذُنُوبَنَا وَقِنَا عَذَابَ ٱلنَّارِ", 't': "«الذين» نعت أو بدل من الذين قبله «يقولون» يا «ربَّنا إننا آمنا» صدَّقنا بك وبرسولك «فاغفر لنا ذنوبنا وقنا عذاب النار»."},
  {'n': '17', 'v': "ٱلصَّٰبِرِينَ وَٱلصَّٰدِقِينَ وَٱلْقَٰنِتِينَ وَٱلْمُنفِقِينَ وَٱلْمُسْتَغْفِرِينَ بِٱلْأَسْحَارِ", 't': "«الصابرين» على الطاعة وعن المعصية نعت «والصادقين» في الإيمان «والقانتين» المطيعين لله «والمنفقين» المتصدقين «والمستغفرين» الله بأن يقولوا اللهم اغفر لنا «بالأسحار» أواخر الليل خُصت بالذكر لأنها وقت الغفلة ولذة النوم."},
  {'n': '18', 'v': "شَهِدَ ٱللَّهُ أَنَّهُۥ لَآ إِلَٰهَ إِلَّا هُوَ وَٱلْمَلَٰٓئِكَةُ وَأُو۟لُوا۟ ٱلْعِلْمِ قَآئِمًۢا بِٱلْقِسْطِ ۚ لَآ إِلَٰهَ إِلَّا هُوَ ٱلْعَزِيزُ ٱلْحَكِيمُ", 't': "«شهد الله» بيَّن لخلقه بالدلائل والآيات «أنه لا إله» أي لا معبود في الوجود بحق «إلا هو و» شهد بذلك «الملائكةُ» بالإقرار «وأولوا العلم» من الأنبياء والمؤمنين بالاعتقاد واللفظ «قائماً» بتدبير مصنوعاته ونصبه على الحال والعامل فيها معنى الجملة أي تفرد «بالقسط» بالعدل «لا إله إلا هو» كرره تأكيدا «العزيز» في ملكه «الحكيم» في صنعه."},
  {'n': '19', 'v': "إِنَّ ٱلدِّينَ عِندَ ٱللَّهِ ٱلْإِسْلَٰمُ ۗ وَمَا ٱخْتَلَفَ ٱلَّذِينَ أُوتُوا۟ ٱلْكِتَٰبَ إِلَّا مِنۢ بَعْدِ مَا جَآءَهُمُ ٱلْعِلْمُ بَغْيًۢا بَيْنَهُمْ ۗ وَمَن يَكْفُرْ بِـَٔايَٰتِ ٱللَّهِ فَإِنَّ ٱللَّهَ سَرِيعُ ٱلْحِسَابِ", 't': "«إن الدين» المرضي «عند الله» هو «الإسلام» أي الشرع المبعوث به الرسل المبنى على التوحيد وفي قراءة بفتح أن بدل من أنه الخ بدل اشتمال «وما اختلف الذين أوتوا الكتاب» اليهود والنصارى في الدين بأن وحَّد بعضٌ وكفر بعضٌ «إلا من بعد ما جاءهم العلم» بالتوحيد «بغيا» من الكافرين «بينهم ومن يكفر بآيات الله» «فإن الله سريع الحساب» أي المجازاة له."},
  {'n': '20', 'v': "فَإِنْ حَآجُّوكَ فَقُلْ أَسْلَمْتُ وَجْهِىَ لِلَّهِ وَمَنِ ٱتَّبَعَنِ ۗ وَقُل لِّلَّذِينَ أُوتُوا۟ ٱلْكِتَٰبَ وَٱلْأُمِّيِّۦنَ ءَأَسْلَمْتُمْ ۚ فَإِنْ أَسْلَمُوا۟ فَقَدِ ٱهْتَدَوا۟ ۖ وَّإِن تَوَلَّوْا۟ فَإِنَّمَا عَلَيْكَ ٱلْبَلَٰغُ ۗ وَٱللَّهُ بَصِيرٌۢ بِٱلْعِبَادِ", 't': "«فإن حاجوك» خاصمك الكفار يا محمد في الدين «فقل» لهم «أسلمت وجهي لله» أنقدت له أنا «ومن اتبعن» وخص الوجه بالذكر لشرفه فغيره أولى «وقل للذين أوتوا الكتاب» اليهود والنصارى و «الأميين» مشركي العرب «أأسلمتم» أي أسلموا «فإن أسلموا فقد اهتدوا» من الضلال «وإن تولوا» عن الإسلام «فإنما عليك البلاغ» أي التبليغ للرسالة «والله بصير بالعباد» فيجازيهم بأعمالهم وهذا قبل الأمر بالقتال"},
  {'n': '21', 'v': "إِنَّ ٱلَّذِينَ يَكْفُرُونَ بِـَٔايَٰتِ ٱللَّهِ وَيَقْتُلُونَ ٱلنَّبِيِّۦنَ بِغَيْرِ حَقٍّۢ وَيَقْتُلُونَ ٱلَّذِينَ يَأْمُرُونَ بِٱلْقِسْطِ مِنَ ٱلنَّاسِ فَبَشِّرْهُم بِعَذَابٍ أَلِيمٍ", 't': "«إن الذين يكفرون بآيات الله ويقتلون» وفي قراءة يقاتلون «النبيين بغير حق ويقتلون الذين يأمرون بالقسط» بالعدل «من الناس» وهم اليهود رُوى أنهم قتلوا ثلاثة وأربعين نبياً فنهاهم مائة وسبعون من عبَّادهم فقتلوهم من يومهم «فبشِّرهم» أعلمهم «بعذاب اليم» مؤلم وذكر البشارة تهكم بهم ودخلت الفاء في خبر إن لشبه اسمها الموصول بالشرط."},
  {'n': '22', 'v': "أُو۟لَٰٓئِكَ ٱلَّذِينَ حَبِطَتْ أَعْمَٰلُهُمْ فِى ٱلدُّنْيَا وَٱلْءَاخِرَةِ وَمَا لَهُم مِّن نَّٰصِرِينَ", 't': "«أولئك الذين حبطت» بطلت «أعمالهم» ما عملوا من خير كصدقة وصلة رحم «في الدنيا والآخرة» فلا اعتداد بها لعدم شرطها «وما لهم من ناصرين» مانعين من العذاب."},
  {'n': '23', 'v': "أَلَمْ تَرَ إِلَى ٱلَّذِينَ أُوتُوا۟ نَصِيبًۭا مِّنَ ٱلْكِتَٰبِ يُدْعَوْنَ إِلَىٰ كِتَٰبِ ٱللَّهِ لِيَحْكُمَ بَيْنَهُمْ ثُمَّ يَتَوَلَّىٰ فَرِيقٌۭ مِّنْهُمْ وَهُم مُّعْرِضُونَ", 't': "«ألم تر» تنظر «إلى الذين أوتوا نصيبا» حظاً «من الكتاب» التوراة «يُدْعَوْنَ» حال «إلى كتاب الله ليحكم بينهم ثم يتولى فريق منهم وهم معرضون» عن قبول حكمه نزلت في اليهود زنى منهم اثنان فتحاكموا إلى النبي صلى الله عليه وسلم فحكم عليهما بالرجم فغضبوا فجيء بالتوراة فوجدا فيها فرجما."},
  {'n': '24', 'v': "ذَٰلِكَ بِأَنَّهُمْ قَالُوا۟ لَن تَمَسَّنَا ٱلنَّارُ إِلَّآ أَيَّامًۭا مَّعْدُودَٰتٍۢ ۖ وَغَرَّهُمْ فِى دِينِهِم مَّا كَانُوا۟ يَفْتَرُونَ", 't': "«ذلك» التولي والإعراض «بأنهم قالوا» أي بسبب قولهم «لن تمسنا النار إلا أياما معدودات» أربعين يوما مدة عبادة آبائهم العجل ثم تزول عنهم «وغرَّهم في دينهم» متعلق بقوله «ما كانوا يفترون» من قولهم ذلك."},
  {'n': '25', 'v': "فَكَيْفَ إِذَا جَمَعْنَٰهُمْ لِيَوْمٍۢ لَّا رَيْبَ فِيهِ وَوُفِّيَتْ كُلُّ نَفْسٍۢ مَّا كَسَبَتْ وَهُمْ لَا يُظْلَمُونَ", 't': "«فكيف» حالهم «إذا جمعناهم ليوم» أي في يوم «لا ريب» لا شك «فيه» هو يوم القيامة «ووفِّيت كل نفس» من أهل الكتاب وغيرهم جزاء «ما كسبت» عملت من خير وشر «وهم» أي الناس «لا يُظلمون» بنقص حسنة أو زيادة سيئة."},
  {'n': '26', 'v': "قُلِ ٱللَّهُمَّ مَٰلِكَ ٱلْمُلْكِ تُؤْتِى ٱلْمُلْكَ مَن تَشَآءُ وَتَنزِعُ ٱلْمُلْكَ مِمَّن تَشَآءُ وَتُعِزُّ مَن تَشَآءُ وَتُذِلُّ مَن تَشَآءُ ۖ بِيَدِكَ ٱلْخَيْرُ ۖ إِنَّكَ عَلَىٰ كُلِّ شَىْءٍۢ قَدِيرٌۭ", 't': "ونزلت لما وعد صلى الله عليه وسلم أمته مُلك فارس والروم فقال المنافقون هيهات: «قل اللهم» يا الله «مالك الملك تؤتي» تعطي «الملك من تشاء» من خلقك «وتنزع الملك ممن تشاء وتعز من تشاء» بإيتائه «وتذل من تشاء» بنزعه منه «بيدك» بقدرتك «الخير» أي والشر «إنك على كل شيء قدير»."},
  {'n': '27', 'v': "تُولِجُ ٱلَّيْلَ فِى ٱلنَّهَارِ وَتُولِجُ ٱلنَّهَارَ فِى ٱلَّيْلِ ۖ وَتُخْرِجُ ٱلْحَىَّ مِنَ ٱلْمَيِّتِ وَتُخْرِجُ ٱلْمَيِّتَ مِنَ ٱلْحَىِّ ۖ وَتَرْزُقُ مَن تَشَآءُ بِغَيْرِ حِسَابٍۢ", 't': "«تولج» تدخل «الليل في النهار وتولج النهار» تدخله «في الليل» فيزيد كل منهما مما نقص من الآخر «وتخرج الحيَّ من الميت» كالإنسان والطائر من النطفة والبيضة «وتخرج الميت» كالنطفة والبيضة «من الحي وترزق من تشاء بغير حساب» أي رزقا واسعا."},
  {'n': '28', 'v': "لَّا يَتَّخِذِ ٱلْمُؤْمِنُونَ ٱلْكَٰفِرِينَ أَوْلِيَآءَ مِن دُونِ ٱلْمُؤْمِنِينَ ۖ وَمَن يَفْعَلْ ذَٰلِكَ فَلَيْسَ مِنَ ٱللَّهِ فِى شَىْءٍ إِلَّآ أَن تَتَّقُوا۟ مِنْهُمْ تُقَىٰةًۭ ۗ وَيُحَذِّرُكُمُ ٱللَّهُ نَفْسَهُۥ ۗ وَإِلَى ٱللَّهِ ٱلْمَصِيرُ", 't': "«لا يتخذ المؤمنون الكافرين أولياء» يوالونهم «من دون» أي غير «المؤمنين ومن يفعل ذلك» أي يواليهم «فليس من» دين «الله في شيء إلا أن تتقوا منهم تقاة» مصدر تقيته أي تخافوا مخافة فلكم موالاتهم باللسان دون القلب وهذا قبل عزَّة الإسلام ويجري فيمن هو في بلد ليس قويا فيها «ويحذركم» يخوفكم «الله نفسه» أن يغضب عليكم إن واليتموهم «وإلى الله المصير» المرجع فيجازيكم."},
  {'n': '29', 'v': "قُلْ إِن تُخْفُوا۟ مَا فِى صُدُورِكُمْ أَوْ تُبْدُوهُ يَعْلَمْهُ ٱللَّهُ ۗ وَيَعْلَمُ مَا فِى ٱلسَّمَٰوَٰتِ وَمَا فِى ٱلْأَرْضِ ۗ وَٱللَّهُ عَلَىٰ كُلِّ شَىْءٍۢ قَدِيرٌۭ", 't': "«قل» لهم «إن تخفوا ما في صدوركم» قلوبكم من موالاتهم «أو تبدوه» تظهروه «يعلمْه الله و» هو «يعلم ما في السماوات وما في الأرض والله على كل شيء قدير» ومنه تعذيب من والاهم."},
  {'n': '30', 'v': "يَوْمَ تَجِدُ كُلُّ نَفْسٍۢ مَّا عَمِلَتْ مِنْ خَيْرٍۢ مُّحْضَرًۭا وَمَا عَمِلَتْ مِن سُوٓءٍۢ تَوَدُّ لَوْ أَنَّ بَيْنَهَا وَبَيْنَهُۥٓ أَمَدًۢا بَعِيدًۭا ۗ وَيُحَذِّرُكُمُ ٱللَّهُ نَفْسَهُۥ ۗ وَٱللَّهُ رَءُوفٌۢ بِٱلْعِبَادِ", 't': "اذكر «يوم تجد كل نفس ما عملتـ» ـهُ «من خير محضرا وما عملتـ» ـهُ «من سوءٍ» مبتدأ خبره «تود لو أن بينها وبينه أمدا بعيدا» غاية في نهاية البعد فلا يصل إليها «ويحذركم الله نفسه» كرر للتأكيد «والله رؤوف بالعباد»."},
  {'n': '31', 'v': "قُلْ إِن كُنتُمْ تُحِبُّونَ ٱللَّهَ فَٱتَّبِعُونِى يُحْبِبْكُمُ ٱللَّهُ وَيَغْفِرْ لَكُمْ ذُنُوبَكُمْ ۗ وَٱللَّهُ غَفُورٌۭ رَّحِيمٌۭ", 't': "ونزل لما قالوا ما نعبد الأصنام إلا حبّا لله ليقربونا إليه «قل» لهم يا محمد «إن كنتم تحبون الله فاتبعوني يحببكم الله» بمعنى يثيبكم «ويغفر لكم ذنوبكم والله غفور» لمن اتبعني ما سلف من قبل ذلك «رحيم» به."},
  {'n': '32', 'v': "قُلْ أَطِيعُوا۟ ٱللَّهَ وَٱلرَّسُولَ ۖ فَإِن تَوَلَّوْا۟ فَإِنَّ ٱللَّهَ لَا يُحِبُّ ٱلْكَٰفِرِينَ", 't': "«قل» لهم «أطيعوا الله والرسول» فيما يأمركم به من التوحيد «فإن تولَّوا» أعرضوا عن الطاعة «فان الله لا يحب الكافرين» فيه إقامة الظاهر مقام المضمر أي لا يحبهم بمعني أنه يعاقبهم."},
  {'n': '33', 'v': "۞ إِنَّ ٱللَّهَ ٱصْطَفَىٰٓ ءَادَمَ وَنُوحًۭا وَءَالَ إِبْرَٰهِيمَ وَءَالَ عِمْرَٰنَ عَلَى ٱلْعَٰلَمِينَ", 't': "«إن الله اصطفى» اختار «آدم ونوحا وآل إبراهيم وآل عمران» بمعني أنفسهما «على العالمين» يجعل الأنبياء من نسلهم."},
  {'n': '34', 'v': "ذُرِّيَّةًۢ بَعْضُهَا مِنۢ بَعْضٍۢ ۗ وَٱللَّهُ سَمِيعٌ عَلِيمٌ", 't': "«ذرِّية بعضها من» ولد «بعض» منهم «والله سميع عليم»."},
  {'n': '35', 'v': "إِذْ قَالَتِ ٱمْرَأَتُ عِمْرَٰنَ رَبِّ إِنِّى نَذَرْتُ لَكَ مَا فِى بَطْنِى مُحَرَّرًۭا فَتَقَبَّلْ مِنِّىٓ ۖ إِنَّكَ أَنتَ ٱلسَّمِيعُ ٱلْعَلِيمُ", 't': "اذكر «إذ قالت امرأة عمران» حنة لما أسنت واشتاقت للولد فدعت الله وأحست بالحمل يا «رب إني نذرت» أن أجعل «لك ما في بطني محرَّرا» عتيقا خالصا من شواغل الدنيا لخدمة بيتك المقدس «فتقبَّل مني إنك أنت السميع» للدعاء «العليم» بالنيات، وهلك عمران وهي حامل."},
  {'n': '36', 'v': "فَلَمَّا وَضَعَتْهَا قَالَتْ رَبِّ إِنِّى وَضَعْتُهَآ أُنثَىٰ وَٱللَّهُ أَعْلَمُ بِمَا وَضَعَتْ وَلَيْسَ ٱلذَّكَرُ كَٱلْأُنثَىٰ ۖ وَإِنِّى سَمَّيْتُهَا مَرْيَمَ وَإِنِّىٓ أُعِيذُهَا بِكَ وَذُرِّيَّتَهَا مِنَ ٱلشَّيْطَٰنِ ٱلرَّجِيمِ", 't': "(فلما وضعتها) ولدتها جارية وكانت ترجو أن يكون غلامًا إذ لم يكن يحرر إلا الغلمان (قالت) معتذرة يا (رب إني وضعتها أنثى والله أعلم) أي عالم (بما وضعت) جملة اعتراض من كلامه تعالى وفي قراءة بضم التاء (وليس الذكر) الذي طلبت (كالأنثى) التي وهبت لأنه يقصد للخدمة وهي لا تصلح لضعفها وعورتها وما يعتريها من الحيض ونحوه (وإني سميتها مريم وإني أعيذها بك وذريتها) أولادها (من الشيطان الرجيم) المطرود في الحديث \"\" ما من مولود يولد إلا مسه الشيطان حين يولد فيستهل صارخًا إلا مريم وابنها \"\" رواه الشيخان."},
  {'n': '37', 'v': "فَتَقَبَّلَهَا رَبُّهَا بِقَبُولٍ حَسَنٍۢ وَأَنۢبَتَهَا نَبَاتًا حَسَنًۭا وَكَفَّلَهَا زَكَرِيَّا ۖ كُلَّمَا دَخَلَ عَلَيْهَا زَكَرِيَّا ٱلْمِحْرَابَ وَجَدَ عِندَهَا رِزْقًۭا ۖ قَالَ يَٰمَرْيَمُ أَنَّىٰ لَكِ هَٰذَا ۖ قَالَتْ هُوَ مِنْ عِندِ ٱللَّهِ ۖ إِنَّ ٱللَّهَ يَرْزُقُ مَن يَشَآءُ بِغَيْرِ حِسَابٍ", 't': "«فتقبلها ربها» أي قبل مريم من أمها «بقبول حسن وأنبتها نباتا حسنا» أنشأها بخلق حسن فكانت تنبت في اليوم كما ينبت المولود في العام وآتت بها أمها الأحبار سدنة بيت المقدس فقالت: دونكم هذه النذيرة فتنافسوا فيها أنها بنت إمامهم فقال زكريا أنا أحق بها لأن خالتها عندي فقالوا لا حتى نقترع فانطلقوا وهم تسعة وعشرون إلى نهر الأردن وألقوا أقلامهم على أن من ثبت قلمه في الماء وصعد فهو أولى بها فثبت قلم زكريا فأخذها وبنى لها غرفة في المسجد بسلم لا يصعد إليها غيره وكان يأتيها بأكلها وشربها ودهنها فيجد عندها فاكهة الصيف في الشتاء وفاكهة الشتاء في الصيف كما قال تعالى «وَكَفَلَهَا زَكَريَّاُ» ضمها إليه وفي قراءة بالتشديد ونصب زكريا ممدودا ومقصورا والفاعل الله «كلما دخل عليها زكريا المحراب» الغرفة وهي أشرف المجالس «وجد عندها رزقا قال يا مريم أنَّى» من أين «لك هذا قالت» وهي صغيرة «هو من عند الله» يأتيني به من الجنة «إن الله يرزق من يشاء بغير حساب» رزقا واسعا بلا تبعة."},
  {'n': '38', 'v': "هُنَالِكَ دَعَا زَكَرِيَّا رَبَّهُۥ ۖ قَالَ رَبِّ هَبْ لِى مِن لَّدُنكَ ذُرِّيَّةًۭ طَيِّبَةً ۖ إِنَّكَ سَمِيعُ ٱلدُّعَآءِ", 't': "«هنالك» أي لما رأى زكريَّا ذلك وعلم أن القادر على الإتيان بالشيء في غير حينه قادر على الإتيان بالولد على الكبر وكان أهل بيته انقرضوا «دعا زَكَريَّاُ ربَّه» لما دخل المحراب للصلاة جوف الليل «قال ربِّ هب لي من لدنك» من عندك «ذرية طيبة» ولدا صالحا «إنك سميع» مجيب «الدعاء»."},
  {'n': '39', 'v': "فَنَادَتْهُ ٱلْمَلَٰٓئِكَةُ وَهُوَ قَآئِمٌۭ يُصَلِّى فِى ٱلْمِحْرَابِ أَنَّ ٱللَّهَ يُبَشِّرُكَ بِيَحْيَىٰ مُصَدِّقًۢا بِكَلِمَةٍۢ مِّنَ ٱللَّهِ وَسَيِّدًۭا وَحَصُورًۭا وَنَبِيًّۭا مِّنَ ٱلصَّٰلِحِينَ", 't': "«فنادته الملائكة» أي جبريل «وهو قائم يصلي في المحراب» أي المسجد «أنَّ» أي بأن وفي قراءة بالكسر بتقدير القول «الله يُبشِّرك» مثقلا ومخففا «بيحيى مصدِّقاً بكلمة» كائنة «من الله» أي بعيسى أنه روح الله وسُمي كلمة لأنه خلق بكلمة كن «وسيِّدا» متبوعا «وحصورا» ممنوعا من النساء «ونبيا من الصالحين» رُوي أنه لم يعمل خطيئة ولم يهم بها."},
  {'n': '40', 'v': "قَالَ رَبِّ أَنَّىٰ يَكُونُ لِى غُلَٰمٌۭ وَقَدْ بَلَغَنِىَ ٱلْكِبَرُ وَٱمْرَأَتِى عَاقِرٌۭ ۖ قَالَ كَذَٰلِكَ ٱللَّهُ يَفْعَلُ مَا يَشَآءُ", 't': "«قال ربِّ أنَّى» كيف «يكون لي غلام» ولد «وقد بلغني الكبر» أي بلغت نهاية السن مائة وعشرين سنة «وامرأتي عاقر» بلغت ثمانية وتسعين سنة «قال» الأمر «كذلك» من خلق الله غلاما منكما «الله يفعل ما يشاء» لا يعجزه منه شيء ولإظهار هذه القدرة العظيمة ألهمه السؤال ليجاب بها ولما تاقت نفسه إلى سرعة المبشَر به."},
  {'n': '41', 'v': "قَالَ رَبِّ ٱجْعَل لِّىٓ ءَايَةًۭ ۖ قَالَ ءَايَتُكَ أَلَّا تُكَلِّمَ ٱلنَّاسَ ثَلَٰثَةَ أَيَّامٍ إِلَّا رَمْزًۭا ۗ وَٱذْكُر رَّبَّكَ كَثِيرًۭا وَسَبِّحْ بِٱلْعَشِىِّ وَٱلْإِبْكَٰرِ", 't': "«قال رب اجعل لي آية» أي علامة على حمل امرأتي «قال آيتك» علية «أ» ن «لا تكلم الناس» أي تمتنع من كلامهم بخلاف ذكر الله تعالى «ثلاثة أيام» أي بلياليها «إلا رمزا» إشارة «واذكر ربَّك كثيرا وسبِّح» صلِّ «بالعشي والإبكار» أواخر النهار وأوائله."},
  {'n': '42', 'v': "وَإِذْ قَالَتِ ٱلْمَلَٰٓئِكَةُ يَٰمَرْيَمُ إِنَّ ٱللَّهَ ٱصْطَفَىٰكِ وَطَهَّرَكِ وَٱصْطَفَىٰكِ عَلَىٰ نِسَآءِ ٱلْعَٰلَمِينَ", 't': "«و» اذكر «إذ قالت الملائكة» أي جبريل «يا مريم إن الله اصطفاك» اختارك «وطهرك» من مسيس الرجال «واصطفاك على نساء العالمين» أي أهل زمانك."},
  {'n': '43', 'v': "يَٰمَرْيَمُ ٱقْنُتِى لِرَبِّكِ وَٱسْجُدِى وَٱرْكَعِى مَعَ ٱلرَّٰكِعِينَ", 't': "«يا مريم اقنتي لربك» أطيعيه «واسجدي واركعي مع الراكعين» أي صلِّي مع المصلِّين."},
  {'n': '44', 'v': "ذَٰلِكَ مِنْ أَنۢبَآءِ ٱلْغَيْبِ نُوحِيهِ إِلَيْكَ ۚ وَمَا كُنتَ لَدَيْهِمْ إِذْ يُلْقُونَ أَقْلَٰمَهُمْ أَيُّهُمْ يَكْفُلُ مَرْيَمَ وَمَا كُنتَ لَدَيْهِمْ إِذْ يَخْتَصِمُونَ", 't': "«ذلك» المذكور من أمر زكريا ومريم «من أنباء الغيب» أخبار ما غاب عنك «نوحيه إليك» يا محمد «وما كنت لديهم إذ يُلْقُون أقلامهم» في الماء يقترعون ليطهر لهم «أيهم يكْفُلُ» يربي «مريم وما كنت لديهم إذ يختصون» في كفالتها فتعرف ذلك فتخبر به وإنما عرفته من جهة الوحي."},
  {'n': '45', 'v': "إِذْ قَالَتِ ٱلْمَلَٰٓئِكَةُ يَٰمَرْيَمُ إِنَّ ٱللَّهَ يُبَشِّرُكِ بِكَلِمَةٍۢ مِّنْهُ ٱسْمُهُ ٱلْمَسِيحُ عِيسَى ٱبْنُ مَرْيَمَ وَجِيهًۭا فِى ٱلدُّنْيَا وَٱلْءَاخِرَةِ وَمِنَ ٱلْمُقَرَّبِينَ", 't': "اذكر «إذ قالت الملائكة» أي جبريل «يا مريم أن الله يبشرك بكلمة منه» أي ولد «اسمه المسيح عيسى بن مريم» خاطبها بنسبته إليها تنبيها على أنها تلده بلا أب إذ عادة الرجال نسبتهم إلى آبائهم «وجيها» ذا جاه «في الدنيا» بالنبوة «والآخرة» بالشفاعة والدرجات العُلا «ومن المقرَّبين» عند الله."},
  {'n': '46', 'v': "وَيُكَلِّمُ ٱلنَّاسَ فِى ٱلْمَهْدِ وَكَهْلًۭا وَمِنَ ٱلصَّٰلِحِينَ", 't': "«ويكلِّم الناس في المهد» أي طفلا قبل وقت الكلام «وكهلا ومن الصالحين»."},
  {'n': '47', 'v': "قَالَتْ رَبِّ أَنَّىٰ يَكُونُ لِى وَلَدٌۭ وَلَمْ يَمْسَسْنِى بَشَرٌۭ ۖ قَالَ كَذَٰلِكِ ٱللَّهُ يَخْلُقُ مَا يَشَآءُ ۚ إِذَا قَضَىٰٓ أَمْرًۭا فَإِنَّمَا يَقُولُ لَهُۥ كُن فَيَكُونُ", 't': "«قالت ربِّ أنَّى» كيف «يكون لي ولد ولم يمسني بشر» بتزوج ولا غيره «قال» الأمر «كذلك» من خلق ولد منك بلا أب «الله يخلق ما يشاء إذا قضي أمرا» أراد خلقه «فإنما يقول له كن فيكون» أي فهو يكون."},
  {'n': '48', 'v': "وَيُعَلِّمُهُ ٱلْكِتَٰبَ وَٱلْحِكْمَةَ وَٱلتَّوْرَىٰةَ وَٱلْإِنجِيلَ", 't': "«وَنُعَلِّمُهُ» بالنون والياء «الكتاب» الخط «والحكمة والتوراة والإنجيل»."},
  {'n': '49', 'v': "وَرَسُولًا إِلَىٰ بَنِىٓ إِسْرَٰٓءِيلَ أَنِّى قَدْ جِئْتُكُم بِـَٔايَةٍۢ مِّن رَّبِّكُمْ ۖ أَنِّىٓ أَخْلُقُ لَكُم مِّنَ ٱلطِّينِ كَهَيْـَٔةِ ٱلطَّيْرِ فَأَنفُخُ فِيهِ فَيَكُونُ طَيْرًۢا بِإِذْنِ ٱللَّهِ ۖ وَأُبْرِئُ ٱلْأَكْمَهَ وَٱلْأَبْرَصَ وَأُحْىِ ٱلْمَوْتَىٰ بِإِذْنِ ٱللَّهِ ۖ وَأُنَبِّئُكُم بِمَا تَأْكُلُونَ وَمَا تَدَّخِرُونَ فِى بُيُوتِكُمْ ۚ إِنَّ فِى ذَٰلِكَ لَءَايَةًۭ لَّكُمْ إِن كُنتُم مُّؤْمِنِينَ", 't': "«و» يجعله «رسولا إلى بنى إسرائيل» في الصبا أو بعد البلوغ فنفخ جبريل في جيب درعها فحملت، وكان من أمرها ما ذكر في سورة مريم فلما بعثه الله إلى بني إسرائيل قال لهم إني رسول الله إليكم «إني» أي بأني «قد جئتكم بآية» علامة على صدقي «من ربكم» هي «أنِّي» وفي قراءة بالكسر استئنافا «أخلق» أصوِّر «لكم من الطين كهيئة الطير» مثل صورته فالكاف اسم مفعول «فأنفخ فيه» الضمير للكاف «فيكون طيرا» وفي قراءة طائرا «بإذن الله» بإرادته فخلق لهم الخفاش لأنه أكمل الطير خلقا فكان يطير وهم ينظرونه فإذا غاب عن أعينهم سقط ميتا «وأبرئ» أشفي «الأكمه» الذي وُلد أعمى «والأبرص» وخصا بالذكر لأنهما ذا إعياء وكان بعثه في زمن الطب فأبرأ في يوم خمسين ألفا بالدعاء بشرط الإيمان «وأحيي الموتى بإذن الله» كرره لنفي توهم الألوهية فيه فأحيا عازر صديقا له وابن العجوز وابنة العاشر فعاشوا وولد لهم، وسام بن نوح ومات في الحال «وأنبئكم بما تأكلون وما تدَّخرون» تخبئون «في بيوتكم» مما لم أعانيه فكان يخبر الشخص بما أكل وبما يأكل وبما يأكل بعد «إن في ذلك» المذكور «لآية لكم إن كنتم مؤمنين»."},
  {'n': '50', 'v': "وَمُصَدِّقًۭا لِّمَا بَيْنَ يَدَىَّ مِنَ ٱلتَّوْرَىٰةِ وَلِأُحِلَّ لَكُم بَعْضَ ٱلَّذِى حُرِّمَ عَلَيْكُمْ ۚ وَجِئْتُكُم بِـَٔايَةٍۢ مِّن رَّبِّكُمْ فَٱتَّقُوا۟ ٱللَّهَ وَأَطِيعُونِ", 't': "«و» جئتكم «مصدقاً لما بين يدي» قبلي «من التوراة ولأحلَّ لكم بعض الذي حرم عليكم» فيها فأحل لهم من السمك والطير مالا صيصة له وقيل أحل الجميع فبعض بمعنى كل «وجئتكم بآية من ربكم» كرره تأكيدا وليبنى عليه «فاتقوا الله وأطيعون» فيما آمركم به توحيد الله وطاعته."},
  {'n': '51', 'v': "إِنَّ ٱللَّهَ رَبِّى وَرَبُّكُمْ فَٱعْبُدُوهُ ۗ هَٰذَا صِرَٰطٌۭ مُّسْتَقِيمٌۭ", 't': "«إن الله ربي وربكم فاعبدوه هذا» الذي آمركم به «صراط» طريق «مستقيم» فكذبوه ولم يؤمنوا به."},
  {'n': '52', 'v': "۞ فَلَمَّآ أَحَسَّ عِيسَىٰ مِنْهُمُ ٱلْكُفْرَ قَالَ مَنْ أَنصَارِىٓ إِلَى ٱللَّهِ ۖ قَالَ ٱلْحَوَارِيُّونَ نَحْنُ أَنصَارُ ٱللَّهِ ءَامَنَّا بِٱللَّهِ وَٱشْهَدْ بِأَنَّا مُسْلِمُونَ", 't': "«فلمّا أحس» علم «عيسى منهم الكفر» وأرادوا قتله «قال مَنْ أنصاري» أعواني ذاهبا «إلى الله» لأنصر دينه «قال الحواريون نحن أنصار الله» أعوان دينه وهم أصفياء عيسى أول من آمن به وكانوا اثني عشر رجلا من الحور وهو البياض الخالص وقيل كانوا قصارين يحورون الثياب أي يبيضونها «آمنّا» صدقنا «بالله واشهد» يا عيسى «بأنّا مسلمون»."},
  {'n': '53', 'v': "رَبَّنَآ ءَامَنَّا بِمَآ أَنزَلْتَ وَٱتَّبَعْنَا ٱلرَّسُولَ فَٱكْتُبْنَا مَعَ ٱلشَّٰهِدِينَ", 't': "«ربنا آمنا بما أنزلت» من الإنجيل «واتَّبعنا الرسول» عيسى «فاكتبنا مع الشاهدين» لك بالوحدانية ولرسولك بالصدق."},
  {'n': '54', 'v': "وَمَكَرُوا۟ وَمَكَرَ ٱللَّهُ ۖ وَٱللَّهُ خَيْرُ ٱلْمَٰكِرِينَ", 't': "قال تعالى: «ومكروا» أي كفار بني إسرائيل بعيسى إذ وكلوا به من يقتله غيلة «ومكر الله» بهم بأن ألقى شبه عيسى على من قصد قتله فقتلوه ورفُع عيسى إلى السماء «والله خير الماكرين» أعلمهم به."},
  {'n': '55', 'v': "إِذْ قَالَ ٱللَّهُ يَٰعِيسَىٰٓ إِنِّى مُتَوَفِّيكَ وَرَافِعُكَ إِلَىَّ وَمُطَهِّرُكَ مِنَ ٱلَّذِينَ كَفَرُوا۟ وَجَاعِلُ ٱلَّذِينَ ٱتَّبَعُوكَ فَوْقَ ٱلَّذِينَ كَفَرُوٓا۟ إِلَىٰ يَوْمِ ٱلْقِيَٰمَةِ ۖ ثُمَّ إِلَىَّ مَرْجِعُكُمْ فَأَحْكُمُ بَيْنَكُمْ فِيمَا كُنتُمْ فِيهِ تَخْتَلِفُونَ", 't': "اذكر «إذ قال الله يا عيسى إني متوفيك» قابضك «ورافعك إليَّ» من الدنيا من غير موت «ومطهرك» مبعدك «من الذين كفروا وجاعل الذين اتبعوك» صدقوا بنبوتك من المسلمين والنصارى «فوق الذين كفروا» بك وهم اليهود يعلونهم بالحجة والسيف «إلى يوم القيامة ثم إليَّ مرجعكم فأحكم بينكم فيما كنتم فيه تختلفون» من أمر الدين."},
  {'n': '56', 'v': "فَأَمَّا ٱلَّذِينَ كَفَرُوا۟ فَأُعَذِّبُهُمْ عَذَابًۭا شَدِيدًۭا فِى ٱلدُّنْيَا وَٱلْءَاخِرَةِ وَمَا لَهُم مِّن نَّٰصِرِينَ", 't': "«فأما الذين كفروا فأعذبهم عذابا شديدا في الدنيا» بالقتل والسبي والجزية «والآخرة» بالنار «وما لهم من ناصرين» مانعين منه."},
  {'n': '57', 'v': "وَأَمَّا ٱلَّذِينَ ءَامَنُوا۟ وَعَمِلُوا۟ ٱلصَّٰلِحَٰتِ فَيُوَفِّيهِمْ أُجُورَهُمْ ۗ وَٱللَّهُ لَا يُحِبُّ ٱلظَّٰلِمِينَ", 't': "(وأما الذين أمنوا وعملوا الصالحات فيوفيهم) بالياء والنون (أجورهم والله لا يحب الظالمين) أي يعاقبهم، روي أن الله تعالى أرسل إليه سحابة فرفعته فتعلقت به أمه وبكت فقال لها إن القيامة تجمعنا وكان ذلك ليلة القدر ببيت المقدس وله ثلاث وثلاثون سنة وعاشت أمه بعده ست سنين وروى الشيخان حديث \"\" أنه ينزل قرب الساعة ويحكم بشريعة نبينا ويقتل الدجال والخنزير ويكسر الصليب ويضع الجزية \"\" وفي حديث مسلم أنه يمكث سبع سنين وفي حديث عن أبي دواد الطيالسي أربعين سنة ويتوفى ويصلى عليه فيحتمل أن المراد مجموع لبثه في الأرض قبل الرفع وبعده."},
  {'n': '58', 'v': "ذَٰلِكَ نَتْلُوهُ عَلَيْكَ مِنَ ٱلْءَايَٰتِ وَٱلذِّكْرِ ٱلْحَكِيمِ", 't': "«ذلك» المذكور من أمر عيسى «نتلوه» نقصه «عليك» يا محمد «من الآيات» حال من الهاء في نتلوه وعامله ما في ذلك من معنى الإشارة «والذكر الحكيم» المحكم أي القرآن."},
  {'n': '59', 'v': "إِنَّ مَثَلَ عِيسَىٰ عِندَ ٱللَّهِ كَمَثَلِ ءَادَمَ ۖ خَلَقَهُۥ مِن تُرَابٍۢ ثُمَّ قَالَ لَهُۥ كُن فَيَكُونُ", 't': "«إن مثل عيسى» شأنه الغريب «عند الله كمثل آدم» كشأنه في خلقه من غير أب وهو من تشبيه الغريب بالأغرب ليكون أقطع للخصم وأوقع في النفس «خلقه» أي آدم أي قالبه «من تراب ثم قال له كن» بشرا «فيكون» أي فكان وكذلك عيسى قال له كن من غير أب فكان."},
  {'n': '60', 'v': "ٱلْحَقُّ مِن رَّبِّكَ فَلَا تَكُن مِّنَ ٱلْمُمْتَرِينَ", 't': "«الحق من ربك» خبر مبتدأ محذوف أي أمر عيسى «فلا تكن من الممترين» الشاكين."},
  {'n': '61', 'v': "فَمَنْ حَآجَّكَ فِيهِ مِنۢ بَعْدِ مَا جَآءَكَ مِنَ ٱلْعِلْمِ فَقُلْ تَعَالَوْا۟ نَدْعُ أَبْنَآءَنَا وَأَبْنَآءَكُمْ وَنِسَآءَنَا وَنِسَآءَكُمْ وَأَنفُسَنَا وَأَنفُسَكُمْ ثُمَّ نَبْتَهِلْ فَنَجْعَل لَّعْنَتَ ٱللَّهِ عَلَى ٱلْكَٰذِبِينَ", 't': "«فمن حاجَّك» جادلك من النصارى «فيه من بعد ما جاءك من العلم» بأمره «فقل» لهم «تعالوا ندع أبناءنا وأبناءكم ونساءنا ونساءكم وأنفسنا وأنفسكم» فنجمعهم «ثم نبتهل» نتضرع في الدعاء «فنجعل لعنة الله على الكاذبين» بأن نقول: اللهم العن الكاذب في شأن عيسى وقد دعا النبي صلى الله عليه وسلم وفد نجران لذلك لما حاجُّوه به فقالوا: حتى ننظر في أمرنا ثم نأتيك فقال ذو رأيهم: لقد عرفتم نبوته وأنه ما بأهل قوم نبيا إلا هلكوا فودعوا الرجل وانصرفوا فأتوا الرسول صلى الله عليه وسلم وقد خرج معه الحسن والحسين وفاطمة وعلي وقال لهم: إذا دعوت فأمِّنوا فأبوا أن يلاعنوا وصالحوه على الجزية رواه أبو نُعَيْم، وعن ابن عباس: قال: لو خرج الذين يباهلون لرجعوا لا يجدون مالا ولا أهلا، ورُوي: لو خرجوا لاحترقوا."},
  {'n': '62', 'v': "إِنَّ هَٰذَا لَهُوَ ٱلْقَصَصُ ٱلْحَقُّ ۚ وَمَا مِنْ إِلَٰهٍ إِلَّا ٱللَّهُ ۚ وَإِنَّ ٱللَّهَ لَهُوَ ٱلْعَزِيزُ ٱلْحَكِيمُ", 't': "«إن هذا» المذكور «لهو القصص» الخبر «الحق» الذي لاشك فيه «وما من» زائدة «إله إلا الله وإن الله لهو العزيز» في ملكه «الحكيم» في صنعه."},
  {'n': '63', 'v': "فَإِن تَوَلَّوْا۟ فَإِنَّ ٱللَّهَ عَلِيمٌۢ بِٱلْمُفْسِدِينَ", 't': "«فإن تولَّوا» أعرضوا عن الإيمان «فإن الله عليم بالمفسدين» فيجازيهم وفيه وضع الظاهر موضع المضمر."},
  {'n': '64', 'v': "قُلْ يَٰٓأَهْلَ ٱلْكِتَٰبِ تَعَالَوْا۟ إِلَىٰ كَلِمَةٍۢ سَوَآءٍۭ بَيْنَنَا وَبَيْنَكُمْ أَلَّا نَعْبُدَ إِلَّا ٱللَّهَ وَلَا نُشْرِكَ بِهِۦ شَيْـًۭٔا وَلَا يَتَّخِذَ بَعْضُنَا بَعْضًا أَرْبَابًۭا مِّن دُونِ ٱللَّهِ ۚ فَإِن تَوَلَّوْا۟ فَقُولُوا۟ ٱشْهَدُوا۟ بِأَنَّا مُسْلِمُونَ", 't': "«قل يا أهل الكتاب» اليهود والنصارى «تعالوا إلى كلمة سواءٍ» مصدر بمعنى مستو أمرها «بيننا وبينكم» هي «أ» ن «لا نعبد إلا الله ولا نشرك به شيئا ولا يتخذ بعضنا أربابا من دون الله» كما اتخذتم الأحبار والرهبان «فإن تولَّوْا» أعرضوا عن التوحيد «فقولوا» أنتم لهم «اشهدوا بأنا مسلمون» موحدون."},
  {'n': '65', 'v': "يَٰٓأَهْلَ ٱلْكِتَٰبِ لِمَ تُحَآجُّونَ فِىٓ إِبْرَٰهِيمَ وَمَآ أُنزِلَتِ ٱلتَّوْرَىٰةُ وَٱلْإِنجِيلُ إِلَّا مِنۢ بَعْدِهِۦٓ ۚ أَفَلَا تَعْقِلُونَ", 't': "ونزل لما قال اليهود: إبراهيم يهودي ونحن على دينه، وقالت النصارى كذلك: «يا أهل الكتاب لِمَ تُحَاجُّونَ» تخاصمون «في إبراهيم» بزعمكم أنه على دينكم «وما أنزلت التوراة والإنجيل إلا من بعده» بزمن طويل وبعد نزولها حدثت اليهودية والنصرانية «أفلا تعقلون» بطلان قولكم."},
  {'n': '66', 'v': "هَٰٓأَنتُمْ هَٰٓؤُلَآءِ حَٰجَجْتُمْ فِيمَا لَكُم بِهِۦ عِلْمٌۭ فَلِمَ تُحَآجُّونَ فِيمَا لَيْسَ لَكُم بِهِۦ عِلْمٌۭ ۚ وَٱللَّهُ يَعْلَمُ وَأَنتُمْ لَا تَعْلَمُونَ", 't': "«ها» للتنبيه «أنتم» مبتدأ «هؤلاء» والخبرُ «حاججتم فيما لكم به علم» من أمر موسى وعيسى وزعمكم أنكم على دينهما «فلمَا تُحاجُّون فيما ليس لكم به علم» من شأن إبراهيم «والله يعلم» شأنه «وأنتم لا تعلمون» قال تعالى تبرئة لإبراهيم."},
  {'n': '67', 'v': "مَا كَانَ إِبْرَٰهِيمُ يَهُودِيًّۭا وَلَا نَصْرَانِيًّۭا وَلَٰكِن كَانَ حَنِيفًۭا مُّسْلِمًۭا وَمَا كَانَ مِنَ ٱلْمُشْرِكِينَ", 't': "«ما كان إبراهيم يهوديا ولا نصرانيا ولكن كان حنيفا» مائلا عن الأديان كلها إلى الدين القيِّم «مسلما» موحدا «وما كان من المشركين»."},
  {'n': '68', 'v': "إِنَّ أَوْلَى ٱلنَّاسِ بِإِبْرَٰهِيمَ لَلَّذِينَ ٱتَّبَعُوهُ وَهَٰذَا ٱلنَّبِىُّ وَٱلَّذِينَ ءَامَنُوا۟ ۗ وَٱللَّهُ وَلِىُّ ٱلْمُؤْمِنِينَ", 't': "«إنَّ أولى الناس» أحقهم «بإبراهيم للَّذِينَ اتبعوه» في زمانه «وهذا النبي» محمد لموافقته له في أكثر شرعه «والذين آمنوا» من أمته فهم الذين ينبغي أن يقولوا نحن على دينه لا أنتم «والله ولي المؤمنين» ناصرهم وحافظهم."},
  {'n': '69', 'v': "وَدَّت طَّآئِفَةٌۭ مِّنْ أَهْلِ ٱلْكِتَٰبِ لَوْ يُضِلُّونَكُمْ وَمَا يُضِلُّونَ إِلَّآ أَنفُسَهُمْ وَمَا يَشْعُرُونَ", 't': "ونزل لما دعا اليهود معاذا وحذيفة وعمارا إلى دينهم: «ودَّت طائفة من أهل الكتاب لو يضلونكم وما يضلون إلا أنفسهم» لأن إثم إضلالهم عليهم والمؤمنون لا يطيعونهم فيه «وما يشعرون» بذلك."},
  {'n': '70', 'v': "يَٰٓأَهْلَ ٱلْكِتَٰبِ لِمَ تَكْفُرُونَ بِـَٔايَٰتِ ٱللَّهِ وَأَنتُمْ تَشْهَدُونَ", 't': "«يا أهل الكتاب لِمَ تكفرون بآيات الله» القرآن المشتمل على نعت محمد صلى الله عليه وسلم «وأنتم تشهدون» تعلمون أنه الحق."},
  {'n': '71', 'v': "يَٰٓأَهْلَ ٱلْكِتَٰبِ لِمَ تَلْبِسُونَ ٱلْحَقَّ بِٱلْبَٰطِلِ وَتَكْتُمُونَ ٱلْحَقَّ وَأَنتُمْ تَعْلَمُونَ", 't': "«يا أهل الكتاب لِمَ تلبسون» تخلطون «الحق بالباطل» بالتحريف والتزوير «وتكتمون الحق» أي نعت النبي «وأنتم تعلمون» أنه الحق."},
  {'n': '72', 'v': "وَقَالَت طَّآئِفَةٌۭ مِّنْ أَهْلِ ٱلْكِتَٰبِ ءَامِنُوا۟ بِٱلَّذِىٓ أُنزِلَ عَلَى ٱلَّذِينَ ءَامَنُوا۟ وَجْهَ ٱلنَّهَارِ وَٱكْفُرُوٓا۟ ءَاخِرَهُۥ لَعَلَّهُمْ يَرْجِعُونَ", 't': "«وقالت طائفة من أهل الكتاب» اليهود لبعضهم «آمنوا بالذي أنزل على الذين آمنوا» أي القرآن «وجه النهار» أوله «واكفروا» به «آخره لعلهم» أي المؤمنين «يرجعون» عن دينهم إذ يقولون ما رجع هؤلاء عنه بعد دخولهم فيه وهم أولو علم إلا لعلمهم بطلانه."},
  {'n': '73', 'v': "وَلَا تُؤْمِنُوٓا۟ إِلَّا لِمَن تَبِعَ دِينَكُمْ قُلْ إِنَّ ٱلْهُدَىٰ هُدَى ٱللَّهِ أَن يُؤْتَىٰٓ أَحَدٌۭ مِّثْلَ مَآ أُوتِيتُمْ أَوْ يُحَآجُّوكُمْ عِندَ رَبِّكُمْ ۗ قُلْ إِنَّ ٱلْفَضْلَ بِيَدِ ٱللَّهِ يُؤْتِيهِ مَن يَشَآءُ ۗ وَٱللَّهُ وَٰسِعٌ عَلِيمٌۭ", 't': "وقالوا أيضاً «ولا تؤمنوا» تصدَّقوا «إلا لمن تبع» وافق «دينكم» قال تعالى: «قل» لهم يا محمد «إن الهدى هدى الله» الذي هو الإسلام وما عداه ضلال، والجملةُ اعتراض «أن» أي بأن «يؤتى أحدّ مثل ما أوتيتم» من الكتاب والحكمة والفصائل وأن مفعول تؤمنوا، والمستثنى منه أحد قدم عليه المستثنى المعنى: لا تقروا بأن أحدا يؤتى ذلك إلا لمن اتبع دينكم «أو» بأن «يحاجوكم» أي المؤمنون يغلبوكم «عند ربكم» يوم القيامة لأنكم أصح دينا، وفي قراءة: أأن بهمزة التوبيخ أي إيتاء أحد مثله تقرون به قال تعالى «قل إن الفضل بيد الله يؤتيه من يشاء» فمن أين لكم أنه لا يؤتى أحد مثل ما أوتيتم «والله واسع» كثير الفضل «عليم» بمن هو أهله."},
  {'n': '74', 'v': "يَخْتَصُّ بِرَحْمَتِهِۦ مَن يَشَآءُ ۗ وَٱللَّهُ ذُو ٱلْفَضْلِ ٱلْعَظِيمِ", 't': "«يختص برحمته من يشاء والله ذو الفضل العظيم»."},
  {'n': '75', 'v': "۞ وَمِنْ أَهْلِ ٱلْكِتَٰبِ مَنْ إِن تَأْمَنْهُ بِقِنطَارٍۢ يُؤَدِّهِۦٓ إِلَيْكَ وَمِنْهُم مَّنْ إِن تَأْمَنْهُ بِدِينَارٍۢ لَّا يُؤَدِّهِۦٓ إِلَيْكَ إِلَّا مَا دُمْتَ عَلَيْهِ قَآئِمًۭا ۗ ذَٰلِكَ بِأَنَّهُمْ قَالُوا۟ لَيْسَ عَلَيْنَا فِى ٱلْأُمِّيِّۦنَ سَبِيلٌۭ وَيَقُولُونَ عَلَى ٱللَّهِ ٱلْكَذِبَ وَهُمْ يَعْلَمُونَ", 't': "«ومن أهل الكتاب من إن تأمنه بقنطار» أي بمال كثير «يؤدَّه إليك» لأمانته كعبد الله بن سلام أودعه رجل ألفا ومائتي أوقية ذهبا فأعادها إليه «ومنهم من إن تأمنه بدينار لا يؤده إليك» لخيانته «إلا ما دمت عليه قائما» لا تفارقه فمتى فارقته أنكره ككعب بن الأشرف استودعه قرشي دينارا فجحده «ذلك» أي ترك الأداء «بأنهم قالوا» بسبب قولهم «ليس علينا في الأميين» أي العرب «سبيل» أي إثم لاستحلالهم ظلم من خالف دينهم ونسبوه إليه تعالى، قال تعالى «ويقولون على الله الكذب» في نسبة ذلك إليه «وهم يعلمون» أنهم كاذبون."},
  {'n': '76', 'v': "بَلَىٰ مَنْ أَوْفَىٰ بِعَهْدِهِۦ وَٱتَّقَىٰ فَإِنَّ ٱللَّهَ يُحِبُّ ٱلْمُتَّقِينَ", 't': "«بلى» عليهم فيهم سبيل «من أوفى بعهده» الذي عاهد الله عليه أو بعهد الله إليه من أداء الأمانة وغيره «واتقى» الله بترك المعاصي وعمل الطاعات «فإن الله يحب المتقين» فيه وضع الظاهر موضع المضمر أي يحبهم بمعنى يثيبهم."},
  {'n': '77', 'v': "إِنَّ ٱلَّذِينَ يَشْتَرُونَ بِعَهْدِ ٱللَّهِ وَأَيْمَٰنِهِمْ ثَمَنًۭا قَلِيلًا أُو۟لَٰٓئِكَ لَا خَلَٰقَ لَهُمْ فِى ٱلْءَاخِرَةِ وَلَا يُكَلِّمُهُمُ ٱللَّهُ وَلَا يَنظُرُ إِلَيْهِمْ يَوْمَ ٱلْقِيَٰمَةِ وَلَا يُزَكِّيهِمْ وَلَهُمْ عَذَابٌ أَلِيمٌۭ", 't': "ونزل في اليهود لما بدلوا نعت النبي صلى الله عليه وسلم وعهد الله إليهم في التوراة وفيمن حلف كاذبا في دعوى أو في بيع سلعة: «إن الذين يشترون» يستبدلون «بعهد الله» إليهم في الإيمان بالنبي وأداء الأمانة «وأيمانهم» حلفهم به تعالى كاذبين «ثمنا قليلا» من الدنيا «أولئك لا خَلاق» نصيب «لهم في الآخرة ولا يكلمهم الله» غضبا عليهم «ولا ينظر إليهم» يرحمهم «يوم القيامة ولا يزكِّيهم» يطهرهم «ولهم عذاب أليم» مؤلم."},
  {'n': '78', 'v': "وَإِنَّ مِنْهُمْ لَفَرِيقًۭا يَلْوُۥنَ أَلْسِنَتَهُم بِٱلْكِتَٰبِ لِتَحْسَبُوهُ مِنَ ٱلْكِتَٰبِ وَمَا هُوَ مِنَ ٱلْكِتَٰبِ وَيَقُولُونَ هُوَ مِنْ عِندِ ٱللَّهِ وَمَا هُوَ مِنْ عِندِ ٱللَّهِ وَيَقُولُونَ عَلَى ٱللَّهِ ٱلْكَذِبَ وَهُمْ يَعْلَمُونَ", 't': "«وإنَّ منهم» أي أهل الكتاب «لفريقا» طائفة ككعب بن الأشرف «يلوون ألسنتهم بالكتاب» أي يعطفونها بقراءته عن المنزل إلى ما حرفوه من نعت النبي صلى الله عليه وسلم ونحو «لتحسبوه» أي المحرف «من الكتاب» الذي أنزله الله «وما هو من الكتاب ويقولون هو من عند الله وما هو من عند الله ويقولون على الله الكذب وهم يعلمون» أنهم كاذبون."},
  {'n': '79', 'v': "مَا كَانَ لِبَشَرٍ أَن يُؤْتِيَهُ ٱللَّهُ ٱلْكِتَٰبَ وَٱلْحُكْمَ وَٱلنُّبُوَّةَ ثُمَّ يَقُولَ لِلنَّاسِ كُونُوا۟ عِبَادًۭا لِّى مِن دُونِ ٱللَّهِ وَلَٰكِن كُونُوا۟ رَبَّٰنِيِّۦنَ بِمَا كُنتُمْ تُعَلِّمُونَ ٱلْكِتَٰبَ وَبِمَا كُنتُمْ تَدْرُسُونَ", 't': "ونزل لما قال نصارى نجران إن عيسى أمرهم أن يتخذوه ربا ولما طلب بعض المسلمين السجود له صلى الله عليه وسلم «ما كان» ينبغي «لبشر أن يؤتيه الله الكتاب والحكم» أي الفهم للشريعة «والنبوة ثم يقول للناس كونوا عبادا لي من دون الله ولكن» يقول «كونوا ربانيين» علماء عاملين منسوبين إلى الرب بزيادة ألف ونون تفخيما «بما كنتم تَعْلمُونَ» بالتخفيف والتشديد «الكتاب وبما كنتم تدرسون» أي بسبب ذلك فإن فائدته أن تعملوا."},
  {'n': '80', 'v': "وَلَا يَأْمُرَكُمْ أَن تَتَّخِذُوا۟ ٱلْمَلَٰٓئِكَةَ وَٱلنَّبِيِّۦنَ أَرْبَابًا ۗ أَيَأْمُرُكُم بِٱلْكُفْرِ بَعْدَ إِذْ أَنتُم مُّسْلِمُونَ", 't': "«وَلا يأمُرُكُمْ» بالرفع استئنافا أي الله والنصب عطفا على يقول أي البشر «أن تتخذوا الملائكة والنبيين أربابا» كما اتخذت الصابئة الملائكة واليهود عُزيرا والنصارى عيسى «أيأمُرُكم بالكفر بعد إذ أنتم مسلمون» لا ينبغي له هذا."},
  {'n': '81', 'v': "وَإِذْ أَخَذَ ٱللَّهُ مِيثَٰقَ ٱلنَّبِيِّۦنَ لَمَآ ءَاتَيْتُكُم مِّن كِتَٰبٍۢ وَحِكْمَةٍۢ ثُمَّ جَآءَكُمْ رَسُولٌۭ مُّصَدِّقٌۭ لِّمَا مَعَكُمْ لَتُؤْمِنُنَّ بِهِۦ وَلَتَنصُرُنَّهُۥ ۚ قَالَ ءَأَقْرَرْتُمْ وَأَخَذْتُمْ عَلَىٰ ذَٰلِكُمْ إِصْرِى ۖ قَالُوٓا۟ أَقْرَرْنَا ۚ قَالَ فَٱشْهَدُوا۟ وَأَنَا۠ مَعَكُم مِّنَ ٱلشَّٰهِدِينَ", 't': "«و» اذكر «إذا» حين «أخذ الله ميثاق النبيين» عهدهم «لما» بفتح اللام للابتداء وتوكيد معنى القسم الذي في أخذ الميثاق وكسرها متعلقة بأخذ وما موصولة على الوجهين أي للذي «آتيتكم» إياه، وفي قراءة آتيناكم «من كتاب وحكمة ثم جاءكم رسول مصدق لما معكم» من الكتاب والحكمة وهو محمد صلى الله عليه وسلم «لتؤمنن به ولتنصرنه» جواب القسم إن أدركتموه وأممهم تبع لهم في ذلك «قال» تعالى لهم «أأقررتم» بذلك «وأخذتم» قبلتم «على ذلكم إصري» عهدي «قالوا أقررنا قال فاشهدوا» على أنفسكم وأتباعكم بذلك «وأنا معكم من الشاهدين» عليكم وعليهم."},
  {'n': '82', 'v': "فَمَن تَوَلَّىٰ بَعْدَ ذَٰلِكَ فَأُو۟لَٰٓئِكَ هُمُ ٱلْفَٰسِقُونَ", 't': "«فمن تولَّى» أعرض «بعد ذلك» الميثاق «فأولئك هم الفاسقون»."},
  {'n': '83', 'v': "أَفَغَيْرَ دِينِ ٱللَّهِ يَبْغُونَ وَلَهُۥٓ أَسْلَمَ مَن فِى ٱلسَّمَٰوَٰتِ وَٱلْأَرْضِ طَوْعًۭا وَكَرْهًۭا وَإِلَيْهِ يُرْجَعُونَ", 't': "«أفغير دين الله يبغون» بالياء والتاء أي المتولون «وله أسلم» إنقاذ «من في السماوات والأرض طوعا» بلا إباء «وكرها» بالسيف بمعاينة ما يلجأ إليه «وإليه يُرْجَعُون» بالتاء والياء والهمزة في أول الآية للإنكار."},
  {'n': '84', 'v': "قُلْ ءَامَنَّا بِٱللَّهِ وَمَآ أُنزِلَ عَلَيْنَا وَمَآ أُنزِلَ عَلَىٰٓ إِبْرَٰهِيمَ وَإِسْمَٰعِيلَ وَإِسْحَٰقَ وَيَعْقُوبَ وَٱلْأَسْبَاطِ وَمَآ أُوتِىَ مُوسَىٰ وَعِيسَىٰ وَٱلنَّبِيُّونَ مِن رَّبِّهِمْ لَا نُفَرِّقُ بَيْنَ أَحَدٍۢ مِّنْهُمْ وَنَحْنُ لَهُۥ مُسْلِمُونَ", 't': "«قل» لهم يا محمد «آمنا بالله وما أنزل علينا وما أنزل على إبراهيم وإسماعيل وإسحاق ويعقوب والأسباط» أولاده «وما أوتي موسى وعيسى والنبيون من ربهم لا نفرق بين أحد منهم» بالتصديق والتكذيب «ونحن له مسلمون» مخلصون في العبادة ونزل فيمن ارتد ولحق بالكفار."},
  {'n': '85', 'v': "وَمَن يَبْتَغِ غَيْرَ ٱلْإِسْلَٰمِ دِينًۭا فَلَن يُقْبَلَ مِنْهُ وَهُوَ فِى ٱلْءَاخِرَةِ مِنَ ٱلْخَٰسِرِينَ", 't': "«ومن يبتغ غير الإسلام دينا فلن يقبل منه وهو في الآخرة من الخاسرين» لمصيره إلى النار المؤبدة علية."},
  {'n': '86', 'v': "كَيْفَ يَهْدِى ٱللَّهُ قَوْمًۭا كَفَرُوا۟ بَعْدَ إِيمَٰنِهِمْ وَشَهِدُوٓا۟ أَنَّ ٱلرَّسُولَ حَقٌّۭ وَجَآءَهُمُ ٱلْبَيِّنَٰتُ ۚ وَٱللَّهُ لَا يَهْدِى ٱلْقَوْمَ ٱلظَّٰلِمِينَ", 't': "«كيف» أي لا «يهدي الله قوما كفروا بعد إيمانهم وشهدوا» أي شهادتهم «أن الرسول حق و» قد «جاءهم البينات» الحجج الظاهرات على صدق النبي «والله لا يهدي القوم الظالمين» أي الكافرين."},
  {'n': '87', 'v': "أُو۟لَٰٓئِكَ جَزَآؤُهُمْ أَنَّ عَلَيْهِمْ لَعْنَةَ ٱللَّهِ وَٱلْمَلَٰٓئِكَةِ وَٱلنَّاسِ أَجْمَعِينَ", 't': "«أولئك جزاؤهم أنَّ عليهم لعنة الله والملائكة والناس أجمعين»."},
  {'n': '88', 'v': "خَٰلِدِينَ فِيهَا لَا يُخَفَّفُ عَنْهُمُ ٱلْعَذَابُ وَلَا هُمْ يُنظَرُونَ", 't': "«خالدين فيها» أي اللعنة أو النار المدلول بها عليها «لا يخفف عنهم العذاب ولا هم يُنظرون» يمهلون."},
  {'n': '89', 'v': "إِلَّا ٱلَّذِينَ تَابُوا۟ مِنۢ بَعْدِ ذَٰلِكَ وَأَصْلَحُوا۟ فَإِنَّ ٱللَّهَ غَفُورٌۭ رَّحِيمٌ", 't': "«إلا الذين تابوا من بعد ذلك وأصلحوا» عملهم «فإن الله غفور» لهم «رحيم» بهم."},
  {'n': '90', 'v': "إِنَّ ٱلَّذِينَ كَفَرُوا۟ بَعْدَ إِيمَٰنِهِمْ ثُمَّ ٱزْدَادُوا۟ كُفْرًۭا لَّن تُقْبَلَ تَوْبَتُهُمْ وَأُو۟لَٰٓئِكَ هُمُ ٱلضَّآلُّونَ", 't': "ونزل في اليهود «إن الذين كفروا» بعيسى «بعد إيمانهم» بموسى «ثم ازدادوا كفرا» بمحمد «لن تُقبل توبتهم» إذا غرغروا أو ماتوا كفّارا «وأولئك هم الضالُّون»."},
  {'n': '91', 'v': "إِنَّ ٱلَّذِينَ كَفَرُوا۟ وَمَاتُوا۟ وَهُمْ كُفَّارٌۭ فَلَن يُقْبَلَ مِنْ أَحَدِهِم مِّلْءُ ٱلْأَرْضِ ذَهَبًۭا وَلَوِ ٱفْتَدَىٰ بِهِۦٓ ۗ أُو۟لَٰٓئِكَ لَهُمْ عَذَابٌ أَلِيمٌۭ وَمَا لَهُم مِّن نَّٰصِرِينَ", 't': "«إن الذين كفروا وماتوا وهم كفار فلن يقبل من أحدهم ملء الأرض» مقدار ما يملؤها «ذهبا ولو افتدى به» أدخل الفاء في خبر إن لشبه بالشرط وإيذانا بتسبب عدم القبول عن الموت على الكفر «أولئك لهم عذاب أليم» مؤلم «وما لهم من ناصرين» مانعين منه."},
  {'n': '92', 'v': "لَن تَنَالُوا۟ ٱلْبِرَّ حَتَّىٰ تُنفِقُوا۟ مِمَّا تُحِبُّونَ ۚ وَمَا تُنفِقُوا۟ مِن شَىْءٍۢ فَإِنَّ ٱللَّهَ بِهِۦ عَلِيمٌۭ", 't': "«لن تنالوا البرَّ» أي ثوابه وهو الجنَّةُ «حتى تنفقوا» تَصَّدَّقُوا «مما تحبون» من أموالكم «وما تنفقوا من شيء فإن الله به عليم» فيجازي عليه."},
  {'n': '93', 'v': "۞ كُلُّ ٱلطَّعَامِ كَانَ حِلًّۭا لِّبَنِىٓ إِسْرَٰٓءِيلَ إِلَّا مَا حَرَّمَ إِسْرَٰٓءِيلُ عَلَىٰ نَفْسِهِۦ مِن قَبْلِ أَن تُنَزَّلَ ٱلتَّوْرَىٰةُ ۗ قُلْ فَأْتُوا۟ بِٱلتَّوْرَىٰةِ فَٱتْلُوهَآ إِن كُنتُمْ صَٰدِقِينَ", 't': "ونزل لما قال اليهود إنك تزعم أنك على ملة إبراهيم وكان لا يأكل لحوم الإبل وألبانها: «كل الطعام كان حِلا» حلالا «لبني إسرائيل إلا ما حرم إسرائيل» يعقوب «على نفسه» وهو الإبل لما حصل له عرق النَّسا بالفتح والقصر فنذر إن شفي لا يأكلها فحرم عليه «من قبل أن تُنَزَّل التوراة» وذلك بعد إبراهيم ولم تكن على عهده حراما كما زعموا «قل» لهم «فأتوا بالتوراة فاتلوها» ليتبين صدق قولكم «إن كنتم صادقين» فيه فبهتوا ولم يأتوا بها قال تعالى."},
  {'n': '94', 'v': "فَمَنِ ٱفْتَرَىٰ عَلَى ٱللَّهِ ٱلْكَذِبَ مِنۢ بَعْدِ ذَٰلِكَ فَأُو۟لَٰٓئِكَ هُمُ ٱلظَّٰلِمُونَ", 't': "«فمن افترى على الله الكذب من بعد ذلك» أي ظهور الحجة بأن التحريم إنما كان من جهة يعقوب لا على عهد إبراهيم «فأولئك هم الظالمون» المتجاوزون الحق إلى الباطل."},
  {'n': '95', 'v': "قُلْ صَدَقَ ٱللَّهُ ۗ فَٱتَّبِعُوا۟ مِلَّةَ إِبْرَٰهِيمَ حَنِيفًۭا وَمَا كَانَ مِنَ ٱلْمُشْرِكِينَ", 't': "«قُل صدق الله» في هذا كجميع ما أخبر به «فاتبعوا ملة إبراهيم» التي أنا عليها «حنيفا» مائلا عن كل دين إلى الإسلام «وما كان من المشركين» به."},
  {'n': '96', 'v': "إِنَّ أَوَّلَ بَيْتٍۢ وُضِعَ لِلنَّاسِ لَلَّذِى بِبَكَّةَ مُبَارَكًۭا وَهُدًۭى لِّلْعَٰلَمِينَ", 't': "ونزل لما قالوا قبلتنا قبل قبلتكم (إن أول بيت وضع) متعبدا (للناس) في الأرض (للذي ببكة) بالباء لغة في مكة سميت بذلك لأنها تبك أعناق الجبابرة أي تدقها، بناه الملائكة قبل خلق آدم ووضع بعده الأقصى وبينهما أربعون سنة كما في حديث الصحيحين وفي حديث \"\" أنه أول ما ظهر على وجه الماء عند خلق السماوات والأرض زبدة بيضاء فدحيت الأرض من تحته \"\" (مباركا) حال من الذي أي ذا بركة (وهدى للعالمين) لأنه قبلتهم."},
  {'n': '97', 'v': "فِيهِ ءَايَٰتٌۢ بَيِّنَٰتٌۭ مَّقَامُ إِبْرَٰهِيمَ ۖ وَمَن دَخَلَهُۥ كَانَ ءَامِنًۭا ۗ وَلِلَّهِ عَلَى ٱلنَّاسِ حِجُّ ٱلْبَيْتِ مَنِ ٱسْتَطَاعَ إِلَيْهِ سَبِيلًۭا ۚ وَمَن كَفَرَ فَإِنَّ ٱللَّهَ غَنِىٌّ عَنِ ٱلْعَٰلَمِينَ", 't': "«فيه آيات بينات» منها «مقام إبراهيم» أي الحجر الذي قام عليه عند بناء البيت فأثر قدماه فيه وبقي إلى الآن مع تطاول الزمان وتداول الأيدي عليه ومنها تضعيف الحسنات فيه وأن الطير لا يعلوه «ومن دخله كان آمنا» لا يتعرض إليه بقتل أو ظلم أو غير ذلك «ولله على الناس حجُّ البيت» واجب بكسر الحاء وفتحها لغتان في مصدر حج بمعنى قصد ويبدل من الناس «من استطاع إليه سبيلا» طرقاً فسره بالزاد والراحلة رواه الحاكم وغيره «ومن كفر» بالله أو بما فرضه من الحج «فإن الله غني عن العالمين» الإنس والجن والملائكة وعن عبادتهم."},
  {'n': '98', 'v': "قُلْ يَٰٓأَهْلَ ٱلْكِتَٰبِ لِمَ تَكْفُرُونَ بِـَٔايَٰتِ ٱللَّهِ وَٱللَّهُ شَهِيدٌ عَلَىٰ مَا تَعْمَلُونَ", 't': "«قل يا أهل الكتاب لم تكفرون بآيات الله» القرآن «والله شهيد على ما تعملون» فيجازيكم عليه."},
  {'n': '99', 'v': "قُلْ يَٰٓأَهْلَ ٱلْكِتَٰبِ لِمَ تَصُدُّونَ عَن سَبِيلِ ٱللَّهِ مَنْ ءَامَنَ تَبْغُونَهَا عِوَجًۭا وَأَنتُمْ شُهَدَآءُ ۗ وَمَا ٱللَّهُ بِغَٰفِلٍ عَمَّا تَعْمَلُونَ", 't': "«قل يا أهل الكتاب لِمَ تصدون» تصرفون «عن سبيل الله» أي دينه «من آمن» بتكذيبكم النبي وكتم نعته «تبغونها» أي تطلبون السبيل «عوجا» مصدر بمعنى معوجة أي مائلة عن الحق «وأنتم شهداء» عالمون بأن الدين المرضي القيم هو دين الإسلام كما في كتابكم «وما الله بغافل عما تعملون» من الكفر والتكذيب وإنما يؤخركم إلى وقتكم ليجازيكم."},
  {'n': '100', 'v': "يَٰٓأَيُّهَا ٱلَّذِينَ ءَامَنُوٓا۟ إِن تُطِيعُوا۟ فَرِيقًۭا مِّنَ ٱلَّذِينَ أُوتُوا۟ ٱلْكِتَٰبَ يَرُدُّوكُم بَعْدَ إِيمَٰنِكُمْ كَٰفِرِينَ", 't': "ونزل لما مر بعض اليهود على الأوس والخزرج وغاظهم تألفهم فذكروهم بما كان بينهم في الجاهلية من الفتن فتشاجروا وكادوا يقتتلون: «يا أيها الذين آمنوا إن تطيعوا فريقا من الذين أوتوا الكتاب يردوكم بعد إيمانكم كافرين»."},
  {'n': '101', 'v': "وَكَيْفَ تَكْفُرُونَ وَأَنتُمْ تُتْلَىٰ عَلَيْكُمْ ءَايَٰتُ ٱللَّهِ وَفِيكُمْ رَسُولُهُۥ ۗ وَمَن يَعْتَصِم بِٱللَّهِ فَقَدْ هُدِىَ إِلَىٰ صِرَٰطٍۢ مُّسْتَقِيمٍۢ", 't': "«وكيف تكفرون» استفهام تعجب وتوبيخ «وأنتم تتلى عليكم آيات الله وفيكم رسوله ومن يعتصم» يتمسك «بالله فقد هدي إلى صراطِ مستقيم»."},
  {'n': '102', 'v': "يَٰٓأَيُّهَا ٱلَّذِينَ ءَامَنُوا۟ ٱتَّقُوا۟ ٱللَّهَ حَقَّ تُقَاتِهِۦ وَلَا تَمُوتُنَّ إِلَّا وَأَنتُم مُّسْلِمُونَ", 't': "(يا أيها الذين آمنوا اتقوا الله حق تقاته) بأن يطاع فلا يعصى ويشكر فلا يكفر ويذكر فلا ينسى فقالوا يا رسول الله ومن يقوى على هذا فنسخ بقوله تعالى \"\" فاتقوا الله ما استطتعم \"\" (ولا تموتن إلا وأنتم مسلمون) موحدون."},
  {'n': '103', 'v': "وَٱعْتَصِمُوا۟ بِحَبْلِ ٱللَّهِ جَمِيعًۭا وَلَا تَفَرَّقُوا۟ ۚ وَٱذْكُرُوا۟ نِعْمَتَ ٱللَّهِ عَلَيْكُمْ إِذْ كُنتُمْ أَعْدَآءًۭ فَأَلَّفَ بَيْنَ قُلُوبِكُمْ فَأَصْبَحْتُم بِنِعْمَتِهِۦٓ إِخْوَٰنًۭا وَكُنتُمْ عَلَىٰ شَفَا حُفْرَةٍۢ مِّنَ ٱلنَّارِ فَأَنقَذَكُم مِّنْهَا ۗ كَذَٰلِكَ يُبَيِّنُ ٱللَّهُ لَكُمْ ءَايَٰتِهِۦ لَعَلَّكُمْ تَهْتَدُونَ", 't': "«واعتصموا» تمسكوا «بحبل الله» أي دينه «جميعا ولا تفرقوا» بعد الإسلام «واذكروا نعمة الله» إنعامه «عليكم» يا معشر الأوس والخزرج «إذ كنتم» قبل الإسلام «أعداء فألَّف» جمع «بين قلوبكم» بالإسلام «فأصبحتم» فصرتم «بنعمته إخوانا» في الدين والولاية «وكنتم على شفا» طرف «حفرة من النار» ليس بينكم وبين الوقوع فيها إلا أن تموتوا كفارا «فأنقذكم منها» بالإيمان «كذلك» كما بيَّن لكم ما ذكر «يبين الله لكم آياته لعلكم تهتدون»."},
  {'n': '104', 'v': "وَلْتَكُن مِّنكُمْ أُمَّةٌۭ يَدْعُونَ إِلَى ٱلْخَيْرِ وَيَأْمُرُونَ بِٱلْمَعْرُوفِ وَيَنْهَوْنَ عَنِ ٱلْمُنكَرِ ۚ وَأُو۟لَٰٓئِكَ هُمُ ٱلْمُفْلِحُونَ", 't': "«ولتكن منكم أمة يدعون إلى الخير» الإسلام «ويأمرون بالمعروف وينهون عن المنكر وأولئك» الداعون الآمرون الناهون «هم المفلحون» الفائزون ومن للتبغيض لأن ما ذكر فرض كفاية لا يلزم كل الأمة ولا يليق بكل أحد كالجاهل وقيل زائدة أي لتكونوا أمه."},
  {'n': '105', 'v': "وَلَا تَكُونُوا۟ كَٱلَّذِينَ تَفَرَّقُوا۟ وَٱخْتَلَفُوا۟ مِنۢ بَعْدِ مَا جَآءَهُمُ ٱلْبَيِّنَٰتُ ۚ وَأُو۟لَٰٓئِكَ لَهُمْ عَذَابٌ عَظِيمٌۭ", 't': "«ولا تكونوا كالذين تفرقوا» عن دينهم «واختلفوا» فيه «من بعد ما جاءهم البينات» وهم اليهود والنصارى «وأولئك لهم عذاب عظيم»."},
  {'n': '106', 'v': "يَوْمَ تَبْيَضُّ وُجُوهٌۭ وَتَسْوَدُّ وُجُوهٌۭ ۚ فَأَمَّا ٱلَّذِينَ ٱسْوَدَّتْ وُجُوهُهُمْ أَكَفَرْتُم بَعْدَ إِيمَٰنِكُمْ فَذُوقُوا۟ ٱلْعَذَابَ بِمَا كُنتُمْ تَكْفُرُونَ", 't': "«يوم تبيض وجوه وتسودُّ وجوه» أي يوم القيامة «فأما الذين اسودَّت وجوههم» وهم الكافرون فيلقون في النار ويقال لهم توبيخا «أكفرتم بعد إيمانكم» يوم أخذ الميثاق «فذوقوا العذاب بما كنتم تكفرون»."},
  {'n': '107', 'v': "وَأَمَّا ٱلَّذِينَ ٱبْيَضَّتْ وُجُوهُهُمْ فَفِى رَحْمَةِ ٱللَّهِ هُمْ فِيهَا خَٰلِدُونَ", 't': "«وأما الذين ابيضَّت وجوههم» وهم المؤمنون «ففي رحمة الله» أي جنته «هم فيها خالدون»."},
  {'n': '108', 'v': "تِلْكَ ءَايَٰتُ ٱللَّهِ نَتْلُوهَا عَلَيْكَ بِٱلْحَقِّ ۗ وَمَا ٱللَّهُ يُرِيدُ ظُلْمًۭا لِّلْعَٰلَمِينَ", 't': "«تلك» أي هذه الآيات «آيات الله نتلوها عليك» يا محمد «بالحق وما الله يريد ظلما للعالمين» بأن يأخذهم بغير جرم."},
  {'n': '109', 'v': "وَلِلَّهِ مَا فِى ٱلسَّمَٰوَٰتِ وَمَا فِى ٱلْأَرْضِ ۚ وَإِلَى ٱللَّهِ تُرْجَعُ ٱلْأُمُورُ", 't': "«ولله ما في السماوات وما في الأرض» ملكا وخلقا وعبيدا «وإلى الله تُرجع» تصير «الأمور»."},
  {'n': '110', 'v': "كُنتُمْ خَيْرَ أُمَّةٍ أُخْرِجَتْ لِلنَّاسِ تَأْمُرُونَ بِٱلْمَعْرُوفِ وَتَنْهَوْنَ عَنِ ٱلْمُنكَرِ وَتُؤْمِنُونَ بِٱللَّهِ ۗ وَلَوْ ءَامَنَ أَهْلُ ٱلْكِتَٰبِ لَكَانَ خَيْرًۭا لَّهُم ۚ مِّنْهُمُ ٱلْمُؤْمِنُونَ وَأَكْثَرُهُمُ ٱلْفَٰسِقُونَ", 't': "«كنتم» يا أمة محمد في علم الله تعالى «خير أمة أخرجت» أظهرت «للناس تأمرون بالمعروف وتنهون عن المنكر وتؤمنون بالله ولو آمن أهل الكتاب لكان» الإيمان «خيرا لهم منهم المؤمنون» كعبد الله بن سلام رضي الله عنه وأصحابه «وأكثرهم الفاسقون» الكافرون."},
  {'n': '111', 'v': "لَن يَضُرُّوكُمْ إِلَّآ أَذًۭى ۖ وَإِن يُقَٰتِلُوكُمْ يُوَلُّوكُمُ ٱلْأَدْبَارَ ثُمَّ لَا يُنصَرُونَ", 't': "«لن يضروكم» أي اليهود يا معشر المسلمين بشيء «إلا أذًى» باللسان من سبِّ ووعيد «وإن يقاتلوكم يولوكم الأدبار» منهزمين «ثم لا ينصرون» عليكم بل لكم النصر عليهم."},
  {'n': '112', 'v': "ضُرِبَتْ عَلَيْهِمُ ٱلذِّلَّةُ أَيْنَ مَا ثُقِفُوٓا۟ إِلَّا بِحَبْلٍۢ مِّنَ ٱللَّهِ وَحَبْلٍۢ مِّنَ ٱلنَّاسِ وَبَآءُو بِغَضَبٍۢ مِّنَ ٱللَّهِ وَضُرِبَتْ عَلَيْهِمُ ٱلْمَسْكَنَةُ ۚ ذَٰلِكَ بِأَنَّهُمْ كَانُوا۟ يَكْفُرُونَ بِـَٔايَٰتِ ٱللَّهِ وَيَقْتُلُونَ ٱلْأَنۢبِيَآءَ بِغَيْرِ حَقٍّۢ ۚ ذَٰلِكَ بِمَا عَصَوا۟ وَّكَانُوا۟ يَعْتَدُونَ", 't': "«ضربت عليهم الذلة أين ما ثُقفوا» حيثما وجدوا فلا عز لهم ولا اعتصام «إلا» كائنين «بحبل من الله وحبل من الناس» المؤمنين وهو عهدهم إليهم بالأمان على أداء الجزية أي لا عصمة لهم غير ذلك «وباءُوا» رجعوا «بغضب من الله وضربت عليهم المسكنة ذلك بأنهم» أي بسبب أنهم «كانوا يكفرون بآيات الله ويقتلون الأنبياء بغير حق ذلك» تأكيد «بما عصوا» أمر الله «وكانوا يعتدون» يتجاوزون الحلال إلى الحرام."},
  {'n': '113', 'v': "۞ لَيْسُوا۟ سَوَآءًۭ ۗ مِّنْ أَهْلِ ٱلْكِتَٰبِ أُمَّةٌۭ قَآئِمَةٌۭ يَتْلُونَ ءَايَٰتِ ٱللَّهِ ءَانَآءَ ٱلَّيْلِ وَهُمْ يَسْجُدُونَ", 't': "«ليسوا» أي أهل الكتاب «سواءً» مستوين «من أهل الكتاب أمة قائمة» مستقيمة ثابتة على الحق كعبد الله بن سلام رضي الله عنه وأصحابه «يتلون آيات الله آناء الليل» أي في ساعاته «وهم يسجدون» يصلُّون، حال."},
  {'n': '114', 'v': "يُؤْمِنُونَ بِٱللَّهِ وَٱلْيَوْمِ ٱلْءَاخِرِ وَيَأْمُرُونَ بِٱلْمَعْرُوفِ وَيَنْهَوْنَ عَنِ ٱلْمُنكَرِ وَيُسَٰرِعُونَ فِى ٱلْخَيْرَٰتِ وَأُو۟لَٰٓئِكَ مِنَ ٱلصَّٰلِحِينَ", 't': "«يؤمنون بالله واليوم الآخر ويأمرون بالمعروف وينهون عن المنكر ويسارعون في الخيرات وأولئك» الموصوفون بما ذكر الله «من الصالحين» ومنهم من ليسوا كذلك وليسوا من الصالحين."},
  {'n': '115', 'v': "وَمَا يَفْعَلُوا۟ مِنْ خَيْرٍۢ فَلَن يُكْفَرُوهُ ۗ وَٱللَّهُ عَلِيمٌۢ بِٱلْمُتَّقِينَ", 't': "«وما تفعلوا» بالتاء أيها الأمة والياء أي الأمة القائمة «من خير فلن يُكفروه» بالوجهين أي تعدموا ثوابه بل تجازون عليه «والله عليم بالمتقين»."},
  {'n': '116', 'v': "إِنَّ ٱلَّذِينَ كَفَرُوا۟ لَن تُغْنِىَ عَنْهُمْ أَمْوَٰلُهُمْ وَلَآ أَوْلَٰدُهُم مِّنَ ٱللَّهِ شَيْـًۭٔا ۖ وَأُو۟لَٰٓئِكَ أَصْحَٰبُ ٱلنَّارِ ۚ هُمْ فِيهَا خَٰلِدُونَ", 't': "«إن الذين كفروا لن تغني» تدفع «عنهم أموالهم ولا أولادهم من الله» أي من عذابه «شيئا» وخصها بالذكر لأن الإنسان يدفع عن نفسه تارة بفداء المال وتارة بالاستعانة بالأولاد «وأولئك أصحاب النار هم فيها خالدون»."},
  {'n': '117', 'v': "مَثَلُ مَا يُنفِقُونَ فِى هَٰذِهِ ٱلْحَيَوٰةِ ٱلدُّنْيَا كَمَثَلِ رِيحٍۢ فِيهَا صِرٌّ أَصَابَتْ حَرْثَ قَوْمٍۢ ظَلَمُوٓا۟ أَنفُسَهُمْ فَأَهْلَكَتْهُ ۚ وَمَا ظَلَمَهُمُ ٱللَّهُ وَلَٰكِنْ أَنفُسَهُمْ يَظْلِمُونَ", 't': "«مثل» صفة «ما ينفقون» أي الكفار «في هذه الحياة الدنيا» في عداوة النبي أو صدقة ونحوها «كمثل ريح فيها صِرّ» حر أو برد شديد «أصابت حرث» زرع «قوم ظلموا أنفسهم» بالكفر والمعصية «فأهلكته» فلم ينتفعوا به فكذلك نفقاتهم ذاهبة لا ينتفعون بها «وما ظلمهم الله» بضياع نفقاتهم «ولكن أنفسهم يظلمون» بالكفر الموجب لضياعها."},
  {'n': '118', 'v': "يَٰٓأَيُّهَا ٱلَّذِينَ ءَامَنُوا۟ لَا تَتَّخِذُوا۟ بِطَانَةًۭ مِّن دُونِكُمْ لَا يَأْلُونَكُمْ خَبَالًۭا وَدُّوا۟ مَا عَنِتُّمْ قَدْ بَدَتِ ٱلْبَغْضَآءُ مِنْ أَفْوَٰهِهِمْ وَمَا تُخْفِى صُدُورُهُمْ أَكْبَرُ ۚ قَدْ بَيَّنَّا لَكُمُ ٱلْءَايَٰتِ ۖ إِن كُنتُمْ تَعْقِلُونَ", 't': "«يا أيها الذين آمنوا لا تتخذوا بطانة» أصفياء تطلعونهم على سرِّكم «من دونكم» أي غيركم من اليهود والنصارى والمنافقين «لا يألونكم خبالا» نصب بنزع الخافض أي لا يقصرون لكم في الفساد «ودُّوا» تمنَّوا «ما عنتم» أي عنتكم وهو شدة الضرر «قد بدت» ظهرت «البغضاء» العداوة لكم «من أفواههم» بالوقيعة فيكم وإطلاع المشركين على سركم «وما تخفي صدورهم» من العداوة «أكبر قد بينا لكم الآيات» على عدواتهم «إن كنتم تعقلون» ذلك فلا توالوهم."},
  {'n': '119', 'v': "هَٰٓأَنتُمْ أُو۟لَآءِ تُحِبُّونَهُمْ وَلَا يُحِبُّونَكُمْ وَتُؤْمِنُونَ بِٱلْكِتَٰبِ كُلِّهِۦ وَإِذَا لَقُوكُمْ قَالُوٓا۟ ءَامَنَّا وَإِذَا خَلَوْا۟ عَضُّوا۟ عَلَيْكُمُ ٱلْأَنَامِلَ مِنَ ٱلْغَيْظِ ۚ قُلْ مُوتُوا۟ بِغَيْظِكُمْ ۗ إِنَّ ٱللَّهَ عَلِيمٌۢ بِذَاتِ ٱلصُّدُورِ", 't': "«ها» للتنبيه «أنتم» يا «أولاء» المؤمنون «تحبونهم» لقرابتهم منكم وصداقتهم «ولا يحبونكم» لمخالفتهم لكم في الدين «وتؤمنون بالكتاب كله» أي بالكتب كلها ولا يؤمنون بكتابكم «وإذا لقوكم قالوا آمنا وإذا خلوا عضوا عليكم الأنامل» أطراف الأصابع «من الغيظ» شدة الغضب لما يرون من ائتلافكم ويعبر عن شدة الغضب بِعَضِّ الأنامل مجازا وإن لم يكن ثم عض «قل موتوا بغيظم» أي ابقوا عليه إلى الموت فلن تروا ما يسركم «إن الله عليم بذات الصدور» بما في القلوب ومنه ما يضمره هؤلاء."},
  {'n': '120', 'v': "إِن تَمْسَسْكُمْ حَسَنَةٌۭ تَسُؤْهُمْ وَإِن تُصِبْكُمْ سَيِّئَةٌۭ يَفْرَحُوا۟ بِهَا ۖ وَإِن تَصْبِرُوا۟ وَتَتَّقُوا۟ لَا يَضُرُّكُمْ كَيْدُهُمْ شَيْـًٔا ۗ إِنَّ ٱللَّهَ بِمَا يَعْمَلُونَ مُحِيطٌۭ", 't': "«إن تَمْسَسْكُمْ» تصبكم «حسنة» نعمة كنصر وغنيمة «تسؤهم» تحزنهم» «وإن تصبكم سيئة» كهزيمة وجدب «يفرحوا بها» وجملة الشرط متصلة بالشرط قبل وما بينهما اعتراض والمعنى أنهم متناهون في عداوتكم فلم توالوهم فاجتنبوهم «وإن تصبروا» على أذاهم «وتتقوا» الله في موالاتهم وغيرها «لا يضركمْ» بكسر الضاد وسكون الراء وضمها وتشديدها «كيدهم شيئا إن الله بما يعلمون» بالياء والتاء «محيط» عالم فيجازيهم به."},
  {'n': '121', 'v': "وَإِذْ غَدَوْتَ مِنْ أَهْلِكَ تُبَوِّئُ ٱلْمُؤْمِنِينَ مَقَٰعِدَ لِلْقِتَالِ ۗ وَٱللَّهُ سَمِيعٌ عَلِيمٌ", 't': "«و» اذكر يا محمد «إذ غدوت من أهلك» من المدينة «تبوئ» تنزل «المؤمنين مقاعد» مراكز يقفون فيها «للقتال والله سميع» لأقوالكم «عليم» بأحوالكم وهو يوم أحد خرج النبي صلى الله عليه وسلم بألف أو إلا خمسين رجلا والمشركون ثلاثة آلاف ونزل بالشعب يوم السبت سابع شوال سنة ثلاثٍ من الهجرة وجعل ظهره وعسكره إلى أحد وسوى صفوفهم وأجلس جيشا من الرماة وأمَّر عليهم عبد الله ابن جبير بسفح الجبل وقال: انضحوا عنا بالنبل لا يأتونا من ورائنا ولا تبرحوا غُلبنا أو نُصرنا."},
  {'n': '122', 'v': "إِذْ هَمَّت طَّآئِفَتَانِ مِنكُمْ أَن تَفْشَلَا وَٱللَّهُ وَلِيُّهُمَا ۗ وَعَلَى ٱللَّهِ فَلْيَتَوَكَّلِ ٱلْمُؤْمِنُونَ", 't': "«إذا» بدل من إذ قبله «همت طائفتان منكم» بنو سلمة وبنو حارثة جناحا العسكر «أن تفشلا» تجبنا عن القتال وترجعا لما رجع عبد الله بن أبيّ المنافقُ وأصحابه وقال: عَلام نقتلُ أنفسنا وأولادنا وقال لأبي جابر السمي القائل له أنشدكم الله في نبيكم وأنفسكم لو نعلم قتالا لا تبعناكم فثبتهما الله ولم ينصرفا «والله وليهما» ناصرهما «وعلى الله فليتوكل المؤمنون» ليثقوا به دون غيره."},
  {'n': '123', 'v': "وَلَقَدْ نَصَرَكُمُ ٱللَّهُ بِبَدْرٍۢ وَأَنتُمْ أَذِلَّةٌۭ ۖ فَٱتَّقُوا۟ ٱللَّهَ لَعَلَّكُمْ تَشْكُرُونَ", 't': "ونزل لما هزموا تذكيرا لهم بنعمة الله «ولقد نصركم الله ببدر» موضع بين مكة والمدينة «وأنتم أذلة» بقلة العدد والسلاح «فاتقوا الله لعلكم تشكرون» نعمه."},
  {'n': '124', 'v': "إِذْ تَقُولُ لِلْمُؤْمِنِينَ أَلَن يَكْفِيَكُمْ أَن يُمِدَّكُمْ رَبُّكُم بِثَلَٰثَةِ ءَالَٰفٍۢ مِّنَ ٱلْمَلَٰٓئِكَةِ مُنزَلِينَ", 't': "«إذ» ظرف لنصركم «تقول للمؤمنين» توعدهم تطمينا «ألن يكفيكم أن يمدّكم» يعينكم «ربكم بثلاثة آلافِ من الملائكة مُنْزَلينَ» بالتخفيف والتشديد."},
  {'n': '125', 'v': "بَلَىٰٓ ۚ إِن تَصْبِرُوا۟ وَتَتَّقُوا۟ وَيَأْتُوكُم مِّن فَوْرِهِمْ هَٰذَا يُمْدِدْكُمْ رَبُّكُم بِخَمْسَةِ ءَالَٰفٍۢ مِّنَ ٱلْمَلَٰٓئِكَةِ مُسَوِّمِينَ", 't': "«بلى» يكفيكم ذلك وفي الأنفال بألف لأنه أمدهم أولا بها ثم صارت ثلاثة ثم صارت خمسة كما قال تعالى «إن تصبروا» على لقاء العدو «وتتقوا» الله في المخالفة «ويأتوكم» أي المشركون «من فورهم» وقتهم «هذا يمددكم ربكم بخمسة آلاف من الملائكة مُسَوَّمينَ» بكسر الواو وفتحها أي معلمين وقد صبروا وأنجز الله وعده بأن قاتلت معهم الملائكة على خيل بلق عليهم عمائم صفر أو بيض أرسلوها بين أكتافهم."},
  {'n': '126', 'v': "وَمَا جَعَلَهُ ٱللَّهُ إِلَّا بُشْرَىٰ لَكُمْ وَلِتَطْمَئِنَّ قُلُوبُكُم بِهِۦ ۗ وَمَا ٱلنَّصْرُ إِلَّا مِنْ عِندِ ٱللَّهِ ٱلْعَزِيزِ ٱلْحَكِيمِ", 't': "«وما جعله الله» أي الإمداد «إلا بشرى لكم» بالنصر «ولتطمئن» تسكن «قلوبكم به» فلا تجزع من كثرة العدو وقلَّتكم «وما النصر إلا من عند الله العزيز الحكيم» يؤتيه من يشاء وليس بكثرة الجند."},
  {'n': '127', 'v': "لِيَقْطَعَ طَرَفًۭا مِّنَ ٱلَّذِينَ كَفَرُوٓا۟ أَوْ يَكْبِتَهُمْ فَيَنقَلِبُوا۟ خَآئِبِينَ", 't': "«ليقطع» متعلق ينصركم أي ليُهلك «طرفا من الذين كفروا» بالقتل والأسر «أو يكبتهم» يذلهم بالهزيمة «فينقلبوا» يرجعوا «خائبين» لم ينالوا ما راموه."},
  {'n': '128', 'v': "لَيْسَ لَكَ مِنَ ٱلْأَمْرِ شَىْءٌ أَوْ يَتُوبَ عَلَيْهِمْ أَوْ يُعَذِّبَهُمْ فَإِنَّهُمْ ظَٰلِمُونَ", 't': "ونزلت لما كسرت رباعيته صلى الله عليه وسلم وشج وجهه يوم أحد وقال: \"\" كيف يفلح قوم خضبوا وجه نبيهم بالدم \"\" (ليس لك من الأمر شيء) بل الأمر لله فاصبر (أو) بمعنى إلى أن (يتوب عليهم) بالإسلام (أو يعذبهم فإنهم ظالمون) بالكفر."},
  {'n': '129', 'v': "وَلِلَّهِ مَا فِى ٱلسَّمَٰوَٰتِ وَمَا فِى ٱلْأَرْضِ ۚ يَغْفِرُ لِمَن يَشَآءُ وَيُعَذِّبُ مَن يَشَآءُ ۚ وَٱللَّهُ غَفُورٌۭ رَّحِيمٌۭ", 't': "«ولله ما في السماوات وما في الأرض» ملكا وخلقا وعبيدا «يغفر لمن يشاء» المغفرة له «ويعذب من يشاء» تعذيبه «والله غفور» لأوليائه «رحيم» بأهل طاعته."},
  {'n': '130', 'v': "يَٰٓأَيُّهَا ٱلَّذِينَ ءَامَنُوا۟ لَا تَأْكُلُوا۟ ٱلرِّبَوٰٓا۟ أَضْعَٰفًۭا مُّضَٰعَفَةًۭ ۖ وَٱتَّقُوا۟ ٱللَّهَ لَعَلَّكُمْ تُفْلِحُونَ", 't': "«يا أيها الذين آمنوا لا تأكلوا الربا أضعافا مضاعفة» بألف ودونها بأن تزيدوا في المال عند حلول الأجل وتؤخروا الطلب «واتقوا الله» بتركه «لعلكم تفلحون» تفوزون."},
  {'n': '131', 'v': "وَٱتَّقُوا۟ ٱلنَّارَ ٱلَّتِىٓ أُعِدَّتْ لِلْكَٰفِرِينَ", 't': "«واتقوا النار التي أعدت للكافرين» أن تعذَّبوا بها."},
  {'n': '132', 'v': "وَأَطِيعُوا۟ ٱللَّهَ وَٱلرَّسُولَ لَعَلَّكُمْ تُرْحَمُونَ", 't': "«وأطيعوا الله والرسول لعلكم ترحمون»."},
  {'n': '133', 'v': "۞ وَسَارِعُوٓا۟ إِلَىٰ مَغْفِرَةٍۢ مِّن رَّبِّكُمْ وَجَنَّةٍ عَرْضُهَا ٱلسَّمَٰوَٰتُ وَٱلْأَرْضُ أُعِدَّتْ لِلْمُتَّقِينَ", 't': "«وسارعوا» بواو ودونها «إلى مغفرة من ربكم وجنة عرضها السماوات والأرض» أي كعرضهما لو وصلت إحداهما للأخرى، والعرضُ السعة «أعدت للمتقين» الله بعمل الطاعات وترك المعاصي."},
  {'n': '134', 'v': "ٱلَّذِينَ يُنفِقُونَ فِى ٱلسَّرَّآءِ وَٱلضَّرَّآءِ وَٱلْكَٰظِمِينَ ٱلْغَيْظَ وَٱلْعَافِينَ عَنِ ٱلنَّاسِ ۗ وَٱللَّهُ يُحِبُّ ٱلْمُحْسِنِينَ", 't': "«الذين ينفقون» في طاعة الله «في السراء والضراء» اليُسر والعسر «والكاظمين الغيظ» الكافين عن إمضائه مع القدرة «والعافين عن الناس» ممن ظلمهم أي التاركين عقوبتهم «والله يحب المحسنين» بهذه الأفعال، أي يثبهم."},
  {'n': '135', 'v': "وَٱلَّذِينَ إِذَا فَعَلُوا۟ فَٰحِشَةً أَوْ ظَلَمُوٓا۟ أَنفُسَهُمْ ذَكَرُوا۟ ٱللَّهَ فَٱسْتَغْفَرُوا۟ لِذُنُوبِهِمْ وَمَن يَغْفِرُ ٱلذُّنُوبَ إِلَّا ٱللَّهُ وَلَمْ يُصِرُّوا۟ عَلَىٰ مَا فَعَلُوا۟ وَهُمْ يَعْلَمُونَ", 't': "«والذين إذا فعلوا فاحشة» ذنبا قبيحا كالزنا «أو ظلموا أنفسهم» بدونه كالقُبلة «ذكروا الله» أي وعيده «فاستغفروا لذنوبهم ومن» أي لا «يغفر الذنوب إلا الله ولم يصروا» يداوموا «على ما فعلوا» بل أقلعوا عنه «وهم يعلمون» أن الذي أتوه معصية."},
  {'n': '136', 'v': "أُو۟لَٰٓئِكَ جَزَآؤُهُم مَّغْفِرَةٌۭ مِّن رَّبِّهِمْ وَجَنَّٰتٌۭ تَجْرِى مِن تَحْتِهَا ٱلْأَنْهَٰرُ خَٰلِدِينَ فِيهَا ۚ وَنِعْمَ أَجْرُ ٱلْعَٰمِلِينَ", 't': "«أولئك جزاؤهم مغفرة من ربهم وجنات تجري من تحتها الأنهار خالدين فيها» حال مقدرة، أي مقدرين الخلود فيها إذا دخلوها «ونعم أجر العاملين» بالطاعة هذا الأجر."},
  {'n': '137', 'v': "قَدْ خَلَتْ مِن قَبْلِكُمْ سُنَنٌۭ فَسِيرُوا۟ فِى ٱلْأَرْضِ فَٱنظُرُوا۟ كَيْفَ كَانَ عَٰقِبَةُ ٱلْمُكَذِّبِينَ", 't': "ونزل في هزيمة أحد «قد خلَت» مضت «من قبلكم سُنَن» طرائق في الكفار بإمهالهم ثم أخذهم «فسيروا» أيها المؤمنون «في الأرض فانظروا كيف كان عاقبة المكذبين» الرسل أي آخر أمرهم من الهلاك فلا تحزنوا لغلبتهم فإنا أمهلناهم لوقتهم."},
  {'n': '138', 'v': "هَٰذَا بَيَانٌۭ لِّلنَّاسِ وَهُدًۭى وَمَوْعِظَةٌۭ لِّلْمُتَّقِينَ", 't': "«هذا» القرآن «بيانٌ للناس» كلهم «وهدى» من الضلال «وموعظة للمتقين» منهم."},
  {'n': '139', 'v': "وَلَا تَهِنُوا۟ وَلَا تَحْزَنُوا۟ وَأَنتُمُ ٱلْأَعْلَوْنَ إِن كُنتُم مُّؤْمِنِينَ", 't': "«ولا تهنوا» تضعفوا عن قتال الكفار «ولا تحزنوا» على ما أصابكم بأحد «وأنتم الأعلون» بالغلبة عليهم «إن كنتم مؤمنين» حقا وجوابه دل عليه مجموع ما قبله."},
  {'n': '140', 'v': "إِن يَمْسَسْكُمْ قَرْحٌۭ فَقَدْ مَسَّ ٱلْقَوْمَ قَرْحٌۭ مِّثْلُهُۥ ۚ وَتِلْكَ ٱلْأَيَّامُ نُدَاوِلُهَا بَيْنَ ٱلنَّاسِ وَلِيَعْلَمَ ٱللَّهُ ٱلَّذِينَ ءَامَنُوا۟ وَيَتَّخِذَ مِنكُمْ شُهَدَآءَ ۗ وَٱللَّهُ لَا يُحِبُّ ٱلظَّٰلِمِينَ", 't': "«إن يمسَسْكم» يصبكم بأحد «قرح» بفتح القاف وضمها جهد من جرح ونحو «فقد مسَّ القومَ» الكفار «قرحٌ مثله» ببدر «وتلك الأيام نداولها» نصرِّفها «بين الناس» يوماً لفرقة ويوماً لأخرى ليتعظوا «وليعلم الله» علم ظهور «الذين آمنوا» أخلصوا في إيمانهم من غيرهم «ويتخذ منكم شهداء» يكرمهم بالشهادة «والله لا يحب الظالمين» الكافرين أي يعاقبهم وما ينعم به عليهم استدراج."},
  {'n': '141', 'v': "وَلِيُمَحِّصَ ٱللَّهُ ٱلَّذِينَ ءَامَنُوا۟ وَيَمْحَقَ ٱلْكَٰفِرِينَ", 't': "«وليمحِّص الله الذين آمنوا» يطهرهم من الذنوب بما يصيبهم «ويمحق» يهلك «الكافرين»."},
  {'n': '142', 'v': "أَمْ حَسِبْتُمْ أَن تَدْخُلُوا۟ ٱلْجَنَّةَ وَلَمَّا يَعْلَمِ ٱللَّهُ ٱلَّذِينَ جَٰهَدُوا۟ مِنكُمْ وَيَعْلَمَ ٱلصَّٰبِرِينَ", 't': "«أم» بل «حسبتم أن تدخلوا الجنة ولَما» لم «يعلم الله الذين جاهدوا منكم» علم ظهور «ويعلم الصابرين» في الشدائد."},
  {'n': '143', 'v': "وَلَقَدْ كُنتُمْ تَمَنَّوْنَ ٱلْمَوْتَ مِن قَبْلِ أَن تَلْقَوْهُ فَقَدْ رَأَيْتُمُوهُ وَأَنتُمْ تَنظُرُونَ", 't': "«ولقد كنتم تمنون» فيه حذف إحدى التاءين في الأصل «الموت من قبل أن تلقوه» حيث قلتم ليت لنا يوما كيوم بدر لننال ما نال شهداؤه «فقد رأيتموه» أي سببه الحرب «وأنتم تنظرون» أي بصراء تتأملون الحال كيف هي فلم انهزمتم؟ ونزل في هزيمتهم لما أشيع أن النبي قتل وقال لهم المنافقون إن كان قتل فارجعوا إلى دينكم."},
  {'n': '144', 'v': "وَمَا مُحَمَّدٌ إِلَّا رَسُولٌۭ قَدْ خَلَتْ مِن قَبْلِهِ ٱلرُّسُلُ ۚ أَفَإِي۟ن مَّاتَ أَوْ قُتِلَ ٱنقَلَبْتُمْ عَلَىٰٓ أَعْقَٰبِكُمْ ۚ وَمَن يَنقَلِبْ عَلَىٰ عَقِبَيْهِ فَلَن يَضُرَّ ٱللَّهَ شَيْـًۭٔا ۗ وَسَيَجْزِى ٱللَّهُ ٱلشَّٰكِرِينَ", 't': "«وما محمد إلا رسول قد خلت من قبله الرسل أفإن مات أو قُتل» كغيره «انقلبتم على أعقابكم» رجعتم إلى الكفر والجملة الأخيرة محل الاستفهام الإنكاري أي ما كان معبودا فترجعوا «ومن ينقلب على عقبيه فلن يضرَّ اللهَ شيئا» وإنما يضر نفسه «وسيجزى الله الشاكرين» نعمه بالثبات."},
  {'n': '145', 'v': "وَمَا كَانَ لِنَفْسٍ أَن تَمُوتَ إِلَّا بِإِذْنِ ٱللَّهِ كِتَٰبًۭا مُّؤَجَّلًۭا ۗ وَمَن يُرِدْ ثَوَابَ ٱلدُّنْيَا نُؤْتِهِۦ مِنْهَا وَمَن يُرِدْ ثَوَابَ ٱلْءَاخِرَةِ نُؤْتِهِۦ مِنْهَا ۚ وَسَنَجْزِى ٱلشَّٰكِرِينَ", 't': "«وما كان لنفس أن تموت إلا بإذن الله» بقضائه «كتابا» مصدر أي: كتب الله ذلك «مؤجَّلا» مؤقتا لا يتقدم ولا يتأخر فلم انهزمتم والهزيمة لا تدفع الموت والثبات لا يقطع الحياة «ومن يُرد» بعمله «ثواب الدنيا» أي جزاءه منها «نؤته منها» ما قسم له ولا حظَّ له في الآخرة «ومن يرد ثواب الآخرة نؤته منها» أي من ثوابها «وسنجري الشاكرين»."},
  {'n': '146', 'v': "وَكَأَيِّن مِّن نَّبِىٍّۢ قَٰتَلَ مَعَهُۥ رِبِّيُّونَ كَثِيرٌۭ فَمَا وَهَنُوا۟ لِمَآ أَصَابَهُمْ فِى سَبِيلِ ٱللَّهِ وَمَا ضَعُفُوا۟ وَمَا ٱسْتَكَانُوا۟ ۗ وَٱللَّهُ يُحِبُّ ٱلصَّٰبِرِينَ", 't': "«وكأيِّن» كم «من نبي قاتِلَ» وفي قراءة قَُتل والفاعل ضميره «معه» خبر مبتدؤه «ربِّيون كثير» جموعٌ كثيرة «فما وهَنوا» جبنوا «لما أصابهم في سبيل الله» من الجراح وقتل أنبيائهم وأصحابهم «وما ضعفوا» عن الجهاد «وما استكانوا» خضعوا لعدوهم كما فعلتم حين قبل قُتل النبي «والله يحب الصابرين» على البلاء أي يثيبهم."},
  {'n': '147', 'v': "وَمَا كَانَ قَوْلَهُمْ إِلَّآ أَن قَالُوا۟ رَبَّنَا ٱغْفِرْ لَنَا ذُنُوبَنَا وَإِسْرَافَنَا فِىٓ أَمْرِنَا وَثَبِّتْ أَقْدَامَنَا وَٱنصُرْنَا عَلَى ٱلْقَوْمِ ٱلْكَٰفِرِينَ", 't': "«وما كان قولَهم» عند قتل نبيهم مع ثباتهم وصبرهم «إلا أن قالوا ربنا اغفر لنا ذنوبنا وإسرافنا» تجاوزنا الحد «في أمرنا» إيذانا بأن ما أصابهم لسوء فعلهم وهضما لأنفسهم «وثبت أقدامنا» بالقوة على الجهاد «وانصرنا على القوم الكافرين»."},
  {'n': '148', 'v': "فَـَٔاتَىٰهُمُ ٱللَّهُ ثَوَابَ ٱلدُّنْيَا وَحُسْنَ ثَوَابِ ٱلْءَاخِرَةِ ۗ وَٱللَّهُ يُحِبُّ ٱلْمُحْسِنِينَ", 't': "«فآتاهم الله ثواب الدنيا» النصر والغنيمة «وحسن ثواب الآخرة» أي الجنة: التفضل فوق الاستحقاق «والله يحب المحسنين»."},
  {'n': '149', 'v': "يَٰٓأَيُّهَا ٱلَّذِينَ ءَامَنُوٓا۟ إِن تُطِيعُوا۟ ٱلَّذِينَ كَفَرُوا۟ يَرُدُّوكُمْ عَلَىٰٓ أَعْقَٰبِكُمْ فَتَنقَلِبُوا۟ خَٰسِرِينَ", 't': "«يا أيها الذين آمنوا إن تطيعوا الذين كفروا» فيما يأمرونكم به «يردوكم على أعقابكم» إلى الكفر «فتنقلبوا خاسرين»."},
  {'n': '150', 'v': "بَلِ ٱللَّهُ مَوْلَىٰكُمْ ۖ وَهُوَ خَيْرُ ٱلنَّٰصِرِينَ", 't': "«بل الله مولاكم» ناصركم «وهو خير الناصرين» فأطيعوه دونهم."},
  {'n': '151', 'v': "سَنُلْقِى فِى قُلُوبِ ٱلَّذِينَ كَفَرُوا۟ ٱلرُّعْبَ بِمَآ أَشْرَكُوا۟ بِٱللَّهِ مَا لَمْ يُنَزِّلْ بِهِۦ سُلْطَٰنًۭا ۖ وَمَأْوَىٰهُمُ ٱلنَّارُ ۚ وَبِئْسَ مَثْوَى ٱلظَّٰلِمِينَ", 't': "«سنلقى في قلوب الذين كفروا الرعب» بسكون العين وضمها الخوف، وقد عزموا بعد ارتحالهم من أُحد على العود واستئصال المسلمين فرعبوا ولم يرجعوا «بما أشركوا» بسبب إشراكهم «بالله ما لم ينزل به سلطانا» حجة على عبادته وهو الأصنام «ومأواهم النار وبئس مثوى» مأوى «الظالمين» الكافرين هي."},
  {'n': '152', 'v': "وَلَقَدْ صَدَقَكُمُ ٱللَّهُ وَعْدَهُۥٓ إِذْ تَحُسُّونَهُم بِإِذْنِهِۦ ۖ حَتَّىٰٓ إِذَا فَشِلْتُمْ وَتَنَٰزَعْتُمْ فِى ٱلْأَمْرِ وَعَصَيْتُم مِّنۢ بَعْدِ مَآ أَرَىٰكُم مَّا تُحِبُّونَ ۚ مِنكُم مَّن يُرِيدُ ٱلدُّنْيَا وَمِنكُم مَّن يُرِيدُ ٱلْءَاخِرَةَ ۚ ثُمَّ صَرَفَكُمْ عَنْهُمْ لِيَبْتَلِيَكُمْ ۖ وَلَقَدْ عَفَا عَنكُمْ ۗ وَٱللَّهُ ذُو فَضْلٍ عَلَى ٱلْمُؤْمِنِينَ", 't': "«ولقد صدقكم الله وعده» إياكم بالنصر «إذ تحسونهم» تقتلونهم «بإذنه» بإرادته «حتى إذا فَشِلْتُمْ» جبنتم عن القتال «وتنازعتم» اختلفتم «في الأمر» أي أمر النبي صلى الله عليه وسلم بالمقام في سفح الجبل للرمي فقال بعضكم: نذهب فقد نُصر أصحابنا وبعضكم: لا نخالف أمر النبي صلى الله عليه وسلم «وعصَيتم» أمره فتركتم المركز لطلب الغنيمة «من بعد ما أراكم» اللهُ «ما تحبون» من النصر وجواب إذا دل عليه ما قبله أي منعكم نصره «منكم من يريد الدنيا» فترك المركز للغنيمة «ومنكم من يريد الآخرة» فثبت به حتى قتل كعبد الله بن جبير و أصحابه «ثم صرفكم» عطف على جواب إذا المقدر ردَّكم للهزيمة «عنهم» أي الكفار «ليبتليكم» ليمنحنكم فيظهر المخلص من غيره «ولقد عفا عنكم» ما ارتكبتموه «والله ذو فضل على المؤمنين» بالعفو."},
  {'n': '153', 'v': "۞ إِذْ تُصْعِدُونَ وَلَا تَلْوُۥنَ عَلَىٰٓ أَحَدٍۢ وَٱلرَّسُولُ يَدْعُوكُمْ فِىٓ أُخْرَىٰكُمْ فَأَثَٰبَكُمْ غَمًّۢا بِغَمٍّۢ لِّكَيْلَا تَحْزَنُوا۟ عَلَىٰ مَا فَاتَكُمْ وَلَا مَآ أَصَٰبَكُمْ ۗ وَٱللَّهُ خَبِيرٌۢ بِمَا تَعْمَلُونَ", 't': "اذكروا «إذ تصعدون» تبعدون في الأرض هاربين «ولا تلوون» تعرجون «على أحد والرسولُ يدعوكم في أخراكم» أي من ورائكم يقول إليَّ عباد الله «فأثابكم» فجازاكم «غمّاً» بالهزيمة «بغمٍّ» بسبب غمِّكم للرسول بالمخالفة وقيل الباء بمعنى على، أي مضاعفا على غم فوت الغنيمة «لكيلا» متعلق بعفا أو بأثابكم فلا زائدة «تحزنوا على ما فاتكم» من الغنيمة «ولا ما أصابكم» من القتل والهزيمة «والله خبير بما تعملون»."},
  {'n': '154', 'v': "ثُمَّ أَنزَلَ عَلَيْكُم مِّنۢ بَعْدِ ٱلْغَمِّ أَمَنَةًۭ نُّعَاسًۭا يَغْشَىٰ طَآئِفَةًۭ مِّنكُمْ ۖ وَطَآئِفَةٌۭ قَدْ أَهَمَّتْهُمْ أَنفُسُهُمْ يَظُنُّونَ بِٱللَّهِ غَيْرَ ٱلْحَقِّ ظَنَّ ٱلْجَٰهِلِيَّةِ ۖ يَقُولُونَ هَل لَّنَا مِنَ ٱلْأَمْرِ مِن شَىْءٍۢ ۗ قُلْ إِنَّ ٱلْأَمْرَ كُلَّهُۥ لِلَّهِ ۗ يُخْفُونَ فِىٓ أَنفُسِهِم مَّا لَا يُبْدُونَ لَكَ ۖ يَقُولُونَ لَوْ كَانَ لَنَا مِنَ ٱلْأَمْرِ شَىْءٌۭ مَّا قُتِلْنَا هَٰهُنَا ۗ قُل لَّوْ كُنتُمْ فِى بُيُوتِكُمْ لَبَرَزَ ٱلَّذِينَ كُتِبَ عَلَيْهِمُ ٱلْقَتْلُ إِلَىٰ مَضَاجِعِهِمْ ۖ وَلِيَبْتَلِىَ ٱللَّهُ مَا فِى صُدُورِكُمْ وَلِيُمَحِّصَ مَا فِى قُلُوبِكُمْ ۗ وَٱللَّهُ عَلِيمٌۢ بِذَاتِ ٱلصُّدُورِ", 't': "«ثم أنزل عليكم من بعد الغم أمنة» أمنا «نعاسا» بدل «يغشى» بالياء والتاء «طائفة منكم» وهم المؤمنون فكانوا يميدون تحت الحجف وتسقط السيوف منهم «وطائفة قد أهمتهم أنفسهم» أي حملتهم على الهم فلا رغبة لهم إلا نجاتها دون النبي وأصحابه فلم يناموا وهم المنافقون «يظنون بالله» ظنا «غير» الظن «الحق ظَنَّ» أي كظن «الجاهلية» حيث اعتقدوا أن النبي قتل أولا ينصر «يقولون هل» ما «لنا من الأمر» أي النصر الذي وُعدناه «من شيء قل» لهم «إن الأمر كله» بالنصب توكيدا والرفع مبتدأ وخبره «لله» أي القضاء له بفعل ما يشاء «يخفون في أنفسهم ما لا يبدون» يظهرون «لك يقولون» بيان لما قبله «لو كان لنا من الأمر شيء ما قتلنا ههنا» أي لو كان الاختبار إلينا لم نخرج فلم نقتل لكن أخرجنا كرها «قل» لهم «لو كنتم في بيوتكم» وفيكم من كتب الله عليه القتل «لبرز» خرج «الذين كتب» قضي «عليهم القتل» منكم «إلى مضاجعهم» مصارعهم فيقتلوا ولم ينجهم وقعودهم لأن قضاءه تعالى كائن لا محالة «و» فعل ما فعل بأخذ «ليبتلي» يختبر «الله ما في صدوركم» قلوبكم من الإخلاص والنفاق «وليمحص» يميز «ما في قلوبكم والله عليم بذات الصدور» بما في القلوب لا يخفى عليه شيء وإنما يبتلي ليظهر للناس."},
  {'n': '155', 'v': "إِنَّ ٱلَّذِينَ تَوَلَّوْا۟ مِنكُمْ يَوْمَ ٱلْتَقَى ٱلْجَمْعَانِ إِنَّمَا ٱسْتَزَلَّهُمُ ٱلشَّيْطَٰنُ بِبَعْضِ مَا كَسَبُوا۟ ۖ وَلَقَدْ عَفَا ٱللَّهُ عَنْهُمْ ۗ إِنَّ ٱللَّهَ غَفُورٌ حَلِيمٌۭ", 't': "«إن الذين تَوَلَّوْا منكم» عن القتال «يوم التقى الجمعان» جمع المسلمين وجمع الكفار بأُحُد وهم المسلمون إلا اثنيْ عشر رجلا «إنما استزلَّهم» أزلهم «الشيطان» بوسوسته «ببعض ما كسبوا» من الذنوب وهو مخالفة أمر النبي «ولقد عفا اللهُ عنهم إن الله غفور» للمؤمنين «حليم» لا يعجل على العصاة."},
  {'n': '156', 'v': "يَٰٓأَيُّهَا ٱلَّذِينَ ءَامَنُوا۟ لَا تَكُونُوا۟ كَٱلَّذِينَ كَفَرُوا۟ وَقَالُوا۟ لِإِخْوَٰنِهِمْ إِذَا ضَرَبُوا۟ فِى ٱلْأَرْضِ أَوْ كَانُوا۟ غُزًّۭى لَّوْ كَانُوا۟ عِندَنَا مَا مَاتُوا۟ وَمَا قُتِلُوا۟ لِيَجْعَلَ ٱللَّهُ ذَٰلِكَ حَسْرَةًۭ فِى قُلُوبِهِمْ ۗ وَٱللَّهُ يُحْىِۦ وَيُمِيتُ ۗ وَٱللَّهُ بِمَا تَعْمَلُونَ بَصِيرٌۭ", 't': "«يا أيها الذين آمنوا لا تكونوا كالذين كفروا» أي المنافقين «وقالوا لإخوانهم» أي في شأنهم «إذا ضربوا» سافروا «في الأرض» فماتوا «أو كانوا غُزٌى» جمع غاز فقتلوا «لو كانوا عندنا ما ماتوا وما قتلوا» أي لا تقولوا كقولهم «ليجعل الله ذلك» القول في عاقبة أمرهم «حسرة في قلوبهم والله يحيي ويميت» فلا يمنع عن الموت قعود «والله بما تعملون» بالتاء والياء «بصير» فيجازيكم به."},
  {'n': '157', 'v': "وَلَئِن قُتِلْتُمْ فِى سَبِيلِ ٱللَّهِ أَوْ مُتُّمْ لَمَغْفِرَةٌۭ مِّنَ ٱللَّهِ وَرَحْمَةٌ خَيْرٌۭ مِّمَّا يَجْمَعُونَ", 't': "«ولئن» لام قسم «قُتِلْتُمْ في سبيل الله» أي الجهاد «أو مُتُّمْ» بضم الميم وكسرها من مات يموت أي أتاكم الموت فيه «لمغفرة» كائنة «من الله» لذنوبكم «ورحمة» منه لكم على ذلك واللام ومدخولها جواب القسم وهو في موضوع الفعل مبتدأ خبره «خير مما تجمعون» من الدنيا بالتاء والياء."},
  {'n': '158', 'v': "وَلَئِن مُّتُّمْ أَوْ قُتِلْتُمْ لَإِلَى ٱللَّهِ تُحْشَرُونَ", 't': "«ولئن» لام قسم «مُتُّمْ» بالوجهين «أو قُتلتم» في الجهاد وغيره «لإلى الله» لا إلى غيره «تُحشرون» في الآخرة فيجازيكم."},
  {'n': '159', 'v': "فَبِمَا رَحْمَةٍۢ مِّنَ ٱللَّهِ لِنتَ لَهُمْ ۖ وَلَوْ كُنتَ فَظًّا غَلِيظَ ٱلْقَلْبِ لَٱنفَضُّوا۟ مِنْ حَوْلِكَ ۖ فَٱعْفُ عَنْهُمْ وَٱسْتَغْفِرْ لَهُمْ وَشَاوِرْهُمْ فِى ٱلْأَمْرِ ۖ فَإِذَا عَزَمْتَ فَتَوَكَّلْ عَلَى ٱللَّهِ ۚ إِنَّ ٱللَّهَ يُحِبُّ ٱلْمُتَوَكِّلِينَ", 't': "«فبما رحمة من الله لِنْتَ» يا محمد «لهم» أي سهلت أخلاقك إذ خالفوك «ولو كنت فظا» سيء الخُلُق «غليظ القلب» جافيا فأغلظت لهم «لا نفضُّوا» تفرقوا «من حولك فاعف» تجاوز «عنهم» ما أتوه «واستغفر لهم» ذنوبهم حتى أغفر لهم «وشاورهم» استخرج آراءهم «في الأمر» أي شأنك من الحرب وغيرة تطيبيا لقلوبهم ولستن بك وكان صلى الله عليه وسلم كثير المشاورة لهم. (فإذا عزمت) على إمضاء ما تريد بعد المشاورة «فَتوكَّلْ على الله» ثق به لا بالمشاورة «إن الله يحب المتوكلين» عليه."},
  {'n': '160', 'v': "إِن يَنصُرْكُمُ ٱللَّهُ فَلَا غَالِبَ لَكُمْ ۖ وَإِن يَخْذُلْكُمْ فَمَن ذَا ٱلَّذِى يَنصُرُكُم مِّنۢ بَعْدِهِۦ ۗ وَعَلَى ٱللَّهِ فَلْيَتَوَكَّلِ ٱلْمُؤْمِنُونَ", 't': "«إن ينصركم الله» يُعنكم على عدوكم كيوم بدر «فلا غالب لكم وإن يخذلكم» يترك نصركم كيوم أُحد «فمن ذا الذي ينصركم من بعده» أي بعد خذلانه أي لا ناصر لكم «وعلى الله» لا غيره «فليتوكل» ليثق «المؤمنون»."},
  {'n': '161', 'v': "وَمَا كَانَ لِنَبِىٍّ أَن يَغُلَّ ۚ وَمَن يَغْلُلْ يَأْتِ بِمَا غَلَّ يَوْمَ ٱلْقِيَٰمَةِ ۚ ثُمَّ تُوَفَّىٰ كُلُّ نَفْسٍۢ مَّا كَسَبَتْ وَهُمْ لَا يُظْلَمُونَ", 't': "ونزلت لما فقدت قطيفة حمراء يوم أحد فقال بعض الناس: لعل النبي أخذها: «وما كان» ما ينبغي «لنبي أن يّغُلَّ» يخون في الغنيمة فلا تظنوا به ذلك، وفي قراءة بالبناء للمفعول أن ينسب إلى الغلول «ومن يغلُل يأت بما غلَّ يوم القيامة» حاملا له على عنقه «ثم تُوفَّى كل نفس» الغال وغيره جزاء «ما كسبت» عملت «وهم لا يُظلمون» شيئا."},
  {'n': '162', 'v': "أَفَمَنِ ٱتَّبَعَ رِضْوَٰنَ ٱللَّهِ كَمَنۢ بَآءَ بِسَخَطٍۢ مِّنَ ٱللَّهِ وَمَأْوَىٰهُ جَهَنَّمُ ۚ وَبِئْسَ ٱلْمَصِيرُ", 't': "«أفمن اتبع رضوان الله» فأطاع ولم يغل «كمن باء» رجع «بسخط من الله» لمعصيته وغلوله «ومأواه جهنم وبئس المصير» المرجع هي."},
  {'n': '163', 'v': "هُمْ دَرَجَٰتٌ عِندَ ٱللَّهِ ۗ وَٱللَّهُ بَصِيرٌۢ بِمَا يَعْمَلُونَ", 't': "«هم درجات» أي أصحاب درجات «عند الله» أي مختلفوا المنازل فلمن اتبع رضوانه الثواب ولمن باء بسخطه العقاب «والله بصير بما يعملون» فيجازيهم به."},
  {'n': '164', 'v': "لَقَدْ مَنَّ ٱللَّهُ عَلَى ٱلْمُؤْمِنِينَ إِذْ بَعَثَ فِيهِمْ رَسُولًۭا مِّنْ أَنفُسِهِمْ يَتْلُوا۟ عَلَيْهِمْ ءَايَٰتِهِۦ وَيُزَكِّيهِمْ وَيُعَلِّمُهُمُ ٱلْكِتَٰبَ وَٱلْحِكْمَةَ وَإِن كَانُوا۟ مِن قَبْلُ لَفِى ضَلَٰلٍۢ مُّبِينٍ", 't': "«لقد منَّ الله على المؤمنين إذ بعث فيهم رسولا من أنفسهم» أي عربيا مثلهم ليفهموا عنه ويشرُفوا به لا ملكا ولا عجميا «يتلو عليهم آياته» القرآن «ويُزكِّيهمْ» يطهرهم من الذنوب «ويعلمهم الكتاب» القرآن «والحكمة» السنة «وإن» مخففة أي إنهم «كانوا من قبلُ» أي قبل بعثه «لفى ضلال مبين» بيِّن."},
  {'n': '165', 'v': "أَوَلَمَّآ أَصَٰبَتْكُم مُّصِيبَةٌۭ قَدْ أَصَبْتُم مِّثْلَيْهَا قُلْتُمْ أَنَّىٰ هَٰذَا ۖ قُلْ هُوَ مِنْ عِندِ أَنفُسِكُمْ ۗ إِنَّ ٱللَّهَ عَلَىٰ كُلِّ شَىْءٍۢ قَدِيرٌۭ", 't': "«أولّما أصابتكم مصيبة» بأحد بقتل سبعين منكم «قد أصبتم مثليها» ببدر بقتل سبعين وأسر سبعين منهم «قلتم» متعجبين «أنَّى» من أين لنا «هذا» الخذلان ونحن مسلمون ورسولُ الله فينا والجملةُ الأخيرة محل للاستفهام الإنكارى «قل» لهم «هو من عند أنفسكم» لأنكم تركتم المركز فخُذلتم «إن الله على كل شيء قديرٌ» ومنه النصر وحده وقد جازاكم بخلافكم."},
  {'n': '166', 'v': "وَمَآ أَصَٰبَكُمْ يَوْمَ ٱلْتَقَى ٱلْجَمْعَانِ فَبِإِذْنِ ٱللَّهِ وَلِيَعْلَمَ ٱلْمُؤْمِنِينَ", 't': "«وما أصابكم يوم التقى الجمعان» بأحد «فبإذن الله» بإرادته «وليعلم» علم ظهور «المؤمنين» حقا."},
  {'n': '167', 'v': "وَلِيَعْلَمَ ٱلَّذِينَ نَافَقُوا۟ ۚ وَقِيلَ لَهُمْ تَعَالَوْا۟ قَٰتِلُوا۟ فِى سَبِيلِ ٱللَّهِ أَوِ ٱدْفَعُوا۟ ۖ قَالُوا۟ لَوْ نَعْلَمُ قِتَالًۭا لَّٱتَّبَعْنَٰكُمْ ۗ هُمْ لِلْكُفْرِ يَوْمَئِذٍ أَقْرَبُ مِنْهُمْ لِلْإِيمَٰنِ ۚ يَقُولُونَ بِأَفْوَٰهِهِم مَّا لَيْسَ فِى قُلُوبِهِمْ ۗ وَٱللَّهُ أَعْلَمُ بِمَا يَكْتُمُونَ", 't': "«وليعلم الذين نافقوا و» الذين «قيل لهم» لما انصرفوا عن القتال وهم عبد الله بن أبيّ وأصحابه «تعالوا قاتلوا في سبيل الله» أعداءه «أو ادفعوا» عنا القوم بتكثير سوادكم إن لم تقاتلوا «قالوا لو نَعْلَمُ» نحسن «قتالا لاتبعناكم» قال تعالى تكذيبا لهم: «هم للكفر يومئذ أقرب منهم للإيمان» بما أظهروا من خذلانهم للمؤمنين وكانوا قبل أقرب إلى الإيمان من حيث الظاهر «يقولون بأفواهم ما ليس في قلوبهم» ولو علموا قتالا لم يتبعوكم «والله أعلم بما يكتمون» من النفاق."},
  {'n': '168', 'v': "ٱلَّذِينَ قَالُوا۟ لِإِخْوَٰنِهِمْ وَقَعَدُوا۟ لَوْ أَطَاعُونَا مَا قُتِلُوا۟ ۗ قُلْ فَٱدْرَءُوا۟ عَنْ أَنفُسِكُمُ ٱلْمَوْتَ إِن كُنتُمْ صَٰدِقِينَ", 't': "«الذين» بدل من الذين قبله أو نعت «قالوا لإخوانهم» في الدين «و» قد «قعدوا» عن الجهاد «لو أطاعونا» أي شهداء أحد أو إخواننا في القعود «ماقتلوا قل» لهم «فادرَءُوا» ادفعوا «عن أنفسكم الموت إن كنتم صادقين» في أن القعود ينجي منه ونزل في الشهداء."},
  {'n': '169', 'v': "وَلَا تَحْسَبَنَّ ٱلَّذِينَ قُتِلُوا۟ فِى سَبِيلِ ٱللَّهِ أَمْوَٰتًۢا ۚ بَلْ أَحْيَآءٌ عِندَ رَبِّهِمْ يُرْزَقُونَ", 't': "«ولا تحسبن الذين قتلوا» بالتخفيف والتشديد «في سبيل الله» أي لأجل دينه «أمواتا بل» هم «أحياءٌ عند ربهم» أرواحهم في حواصل طيور خضر تسرح في الجنة حيث شاءت كما ورد في الحديث «يرزقون» يأكلون من ثمار الجنة."},
  {'n': '170', 'v': "فَرِحِينَ بِمَآ ءَاتَىٰهُمُ ٱللَّهُ مِن فَضْلِهِۦ وَيَسْتَبْشِرُونَ بِٱلَّذِينَ لَمْ يَلْحَقُوا۟ بِهِم مِّنْ خَلْفِهِمْ أَلَّا خَوْفٌ عَلَيْهِمْ وَلَا هُمْ يَحْزَنُونَ", 't': "«فرحين» حال من ضمير يُرزقون «بما آتاهم الله من فضله و» هم «يستبشرون» يفرحون «بالذين لم يلحقوا بهم من خلفهم» من إخوانهم المؤمنين ويبدل من الذين «أ» نْ أي بأن «لا خوف عليهم» أي الذين لم يلحقوا بهم «ولا هم يحزنون» في الآخرة المعنى يفرحون بأمنهم وفرحهم."},
  {'n': '171', 'v': "۞ يَسْتَبْشِرُونَ بِنِعْمَةٍۢ مِّنَ ٱللَّهِ وَفَضْلٍۢ وَأَنَّ ٱللَّهَ لَا يُضِيعُ أَجْرَ ٱلْمُؤْمِنِينَ", 't': "«يستبشرون بنعمة» ثوابٍ «من الله وفضل» زيادة عليه «وأنَّ» بالفتح عطفاً على نعمة وبالكسر استئنافا «الله لا يضيع أجر المؤمنين» بل يأجرهم."},
  {'n': '172', 'v': "ٱلَّذِينَ ٱسْتَجَابُوا۟ لِلَّهِ وَٱلرَّسُولِ مِنۢ بَعْدِ مَآ أَصَابَهُمُ ٱلْقَرْحُ ۚ لِلَّذِينَ أَحْسَنُوا۟ مِنْهُمْ وَٱتَّقَوْا۟ أَجْرٌ عَظِيمٌ", 't': "«الذين» مبتدأ «استجابوا لله والرسول» دعاءه لهم بالخروج للقتال لما أراد أبو سفيان وأصحابه العود تواعدوا مع النبي صلى الله عليه وسلم سوق بدر العام المقبل من يوم أحد «من بعد ما أصابهم القرح» بأحد وخبرُ المبتدأ «للذين أحسنوا منهم» بطاعته «واتقوا» مخالفته «أجر عظيم» هو الجنة."},
  {'n': '173', 'v': "ٱلَّذِينَ قَالَ لَهُمُ ٱلنَّاسُ إِنَّ ٱلنَّاسَ قَدْ جَمَعُوا۟ لَكُمْ فَٱخْشَوْهُمْ فَزَادَهُمْ إِيمَٰنًۭا وَقَالُوا۟ حَسْبُنَا ٱللَّهُ وَنِعْمَ ٱلْوَكِيلُ", 't': "«الذين» بدل من الذين قبله أو نعت «قال لهم الناس» أي نعيم بن مسعود الأشجعي «إن الناس» أبا سفيان وأصحابه «قد جمعوا لكم» الجموع ليستأصلوكم «فاخشوهم» ولا تأتوهم «فزادهم» ذلك القول «إيمانا» تصديقا بالله ويقينا «وقالوا حسبنا الله» كافينا أمرهم «ونعم الوكيل» المفوَّض إليه الأمر هو، وخرجوا مع النبي صلى الله عليه وسلم فوافوا سوق بدر وألقى الله الرعب في قلب أبي سفيان وأصحابه فلم يأتوا وكان معهم تجارات فباعوا وربحوا قال الله تعالى."},
  {'n': '174', 'v': "فَٱنقَلَبُوا۟ بِنِعْمَةٍۢ مِّنَ ٱللَّهِ وَفَضْلٍۢ لَّمْ يَمْسَسْهُمْ سُوٓءٌۭ وَٱتَّبَعُوا۟ رِضْوَٰنَ ٱللَّهِ ۗ وَٱللَّهُ ذُو فَضْلٍ عَظِيمٍ", 't': "«فانقلبوا» رجعوا من بدر «بنعمة من الله وفضل» بسلامة وربح «لم يَمْسَسهُمْ سوء» من قتل أو حرج «واتبعوا رضوان الله» بطاعته وطاعة رسوله في الخروج «والله ذو فضل عظيم» على أهل طاعته."},
  {'n': '175', 'v': "إِنَّمَا ذَٰلِكُمُ ٱلشَّيْطَٰنُ يُخَوِّفُ أَوْلِيَآءَهُۥ فَلَا تَخَافُوهُمْ وَخَافُونِ إِن كُنتُم مُّؤْمِنِينَ", 't': "«إنما ذلكم» أي القائل لكم إن الناس إلخ «الشيطان يخوِّفُ» ـكم «أولياءه» الكفار «فلا تخافوهم وخافون» في ترك أمري «إن كنتم مؤمنين» حقَّا."},
  {'n': '176', 'v': "وَلَا يَحْزُنكَ ٱلَّذِينَ يُسَٰرِعُونَ فِى ٱلْكُفْرِ ۚ إِنَّهُمْ لَن يَضُرُّوا۟ ٱللَّهَ شَيْـًۭٔا ۗ يُرِيدُ ٱللَّهُ أَلَّا يَجْعَلَ لَهُمْ حَظًّۭا فِى ٱلْءَاخِرَةِ ۖ وَلَهُمْ عَذَابٌ عَظِيمٌ", 't': "«ولا يُحْزِنْكَ» بضم الياء وكسر الزاي وبفتحها وضم الزاي من أحزنه «الذين يسارعون في الكفر» يقعون فيه سريعا بنصرته وهم أهل مكة أو المنافقون أي لا تهتم لكفرهم «إنَّهمُ لن يضروا الله شيئا» بفعلهم وإنما يضرون أنفسهم «يريد الله ألا يجعل لهم حظّا» نصيبا «في الآخرة» أي الجنة فلذلك خذلهم الله «ولهم عذاب عظيم» في النار."},
  {'n': '177', 'v': "إِنَّ ٱلَّذِينَ ٱشْتَرَوُا۟ ٱلْكُفْرَ بِٱلْإِيمَٰنِ لَن يَضُرُّوا۟ ٱللَّهَ شَيْـًۭٔا وَلَهُمْ عَذَابٌ أَلِيمٌۭ", 't': "«إن الذين اشتروا الكفر بالإيمان» أي أخذوه بدله «لن يضروا الله» بكفرهم «شيئا ولهم عذاب أليم» مؤلم."},
  {'n': '178', 'v': "وَلَا يَحْسَبَنَّ ٱلَّذِينَ كَفَرُوٓا۟ أَنَّمَا نُمْلِى لَهُمْ خَيْرٌۭ لِّأَنفُسِهِمْ ۚ إِنَّمَا نُمْلِى لَهُمْ لِيَزْدَادُوٓا۟ إِثْمًۭا ۚ وَلَهُمْ عَذَابٌۭ مُّهِينٌۭ", 't': "«ولا يحسبنَّ» بالياء والتاء «الذين كفروا أنما نملي» أي إملاءنا «لهم» بتطويل الأعمار وتأخيرهم «خير لأنفسهم» وأن ومعمولاها سدت مسد المفعولين في قراءة التحتانية ومسد الثاني في الأخرى «إنما نملي» نمهل «لهم ليزدادوا إثما» بكثرة المعاصي «ولهم عذاب مهين» ذو إهانة في الآخرة."},
  {'n': '179', 'v': "مَّا كَانَ ٱللَّهُ لِيَذَرَ ٱلْمُؤْمِنِينَ عَلَىٰ مَآ أَنتُمْ عَلَيْهِ حَتَّىٰ يَمِيزَ ٱلْخَبِيثَ مِنَ ٱلطَّيِّبِ ۗ وَمَا كَانَ ٱللَّهُ لِيُطْلِعَكُمْ عَلَى ٱلْغَيْبِ وَلَٰكِنَّ ٱللَّهَ يَجْتَبِى مِن رُّسُلِهِۦ مَن يَشَآءُ ۖ فَـَٔامِنُوا۟ بِٱللَّهِ وَرُسُلِهِۦ ۚ وَإِن تُؤْمِنُوا۟ وَتَتَّقُوا۟ فَلَكُمْ أَجْرٌ عَظِيمٌۭ", 't': "«ما كان الله ليذر» ليترك «المؤمنين على ما أنتم» أيها الناس «عليه» من اختلاط المخلص بغيره «حتى يَمِيزَ» بالتخفيف والتشديد يفصل «الخبيث» المنافق «من الطيب» المؤمن بالتكاليف الشاقة المبينة لذلك ففعل ذلك يوم أحد «وما كان الله ليطلعكم على الغيب» فتعرفوا المنافق من غيره قبل التمييز «ولكنَّ الله يجتبي» يختار «من رسله من يشاء» فيطلعه على غيبه كما أطلع النبي صلى الله عليه وسلم على حال المنافقين «فآمنوا بالله ورسله وإن تؤمنوا وتتقوا» النفاق «فلكم أجر عظيم»."},
  {'n': '180', 'v': "وَلَا يَحْسَبَنَّ ٱلَّذِينَ يَبْخَلُونَ بِمَآ ءَاتَىٰهُمُ ٱللَّهُ مِن فَضْلِهِۦ هُوَ خَيْرًۭا لَّهُم ۖ بَلْ هُوَ شَرٌّۭ لَّهُمْ ۖ سَيُطَوَّقُونَ مَا بَخِلُوا۟ بِهِۦ يَوْمَ ٱلْقِيَٰمَةِ ۗ وَلِلَّهِ مِيرَٰثُ ٱلسَّمَٰوَٰتِ وَٱلْأَرْضِ ۗ وَٱللَّهُ بِمَا تَعْمَلُونَ خَبِيرٌۭ", 't': "«ولايحسبن» بالياء والتاء «الذين يبخلون بما آتاهم الله من فضله» أي بزكاته «هو» أي بخلهم «خيرا لهم» مفعول ثان والضمير للفصل والأول بخلهم مقدرا قبل الوصول وقبل الضمير على التحتانية «بل هو شر لهم سيطوَّقون ما بخلوا به» أي بزكاته من المال «يوم القيامة» بأن يجعل حية في عنقه تنهشه كما ورد في الحديث «ولله ميراث السماوات والأرض» يرثهما بعد فناء أهلهما «والله بما تعلمون» بالتاء والياء «خبير» فيجازيكم به."},
  {'n': '181', 'v': "لَّقَدْ سَمِعَ ٱللَّهُ قَوْلَ ٱلَّذِينَ قَالُوٓا۟ إِنَّ ٱللَّهَ فَقِيرٌۭ وَنَحْنُ أَغْنِيَآءُ ۘ سَنَكْتُبُ مَا قَالُوا۟ وَقَتْلَهُمُ ٱلْأَنۢبِيَآءَ بِغَيْرِ حَقٍّۢ وَنَقُولُ ذُوقُوا۟ عَذَابَ ٱلْحَرِيقِ", 't': "«لقد سمع الله قول الذين قالوا إن الله فقير ونحن أغنياء» وهم اليهود قالوه لما نزل (من ذا الذي يقرض الله قرضا حسنا) وقالوا لو كان غنيا ما استقرضناه «سنكتب» نأمر بكتب «ما قالوا» في صحائف أعمالهم ليُجازَوا عليه وفي قراءة بالياء مبينا للمفعول «و» نكتب «قتلَهم» بالنصب والرفع «الأنبياء بغير حق ونقول» بالنون والياء أي الله لهم في الآخرة على لسان الملائكة «ذوقوا عذاب الحريق» النار ويقال لهم إذا القوا فيها."},
  {'n': '182', 'v': "ذَٰلِكَ بِمَا قَدَّمَتْ أَيْدِيكُمْ وَأَنَّ ٱللَّهَ لَيْسَ بِظَلَّامٍۢ لِّلْعَبِيدِ", 't': "«ذلك» العذاب «بما قدَّمت أيديكم» عبَّر بها عن الإنسان لأن أكثر الأفعال تزاول بها «وأن الله ليس بظلام» أي بذي ظلم «للعبيد» فيعذبهم بغير ذنب."},
  {'n': '183', 'v': "ٱلَّذِينَ قَالُوٓا۟ إِنَّ ٱللَّهَ عَهِدَ إِلَيْنَآ أَلَّا نُؤْمِنَ لِرَسُولٍ حَتَّىٰ يَأْتِيَنَا بِقُرْبَانٍۢ تَأْكُلُهُ ٱلنَّارُ ۗ قُلْ قَدْ جَآءَكُمْ رُسُلٌۭ مِّن قَبْلِى بِٱلْبَيِّنَٰتِ وَبِٱلَّذِى قُلْتُمْ فَلِمَ قَتَلْتُمُوهُمْ إِن كُنتُمْ صَٰدِقِينَ", 't': "«الَّذين» نعت للذين قبله «قالوا» لمحمد «إن الله» قد «عهد إلينا» في التوراة «ألا نؤمن لرسول» نصدقه «حتى يأتينا بقربانٍ تأكله النار» فلا نؤمن لك حتى تأتينا به وهو ما يتقرب به إلى الله من نعم وغيرها فإن قُبل جاءت نار بيضاء من السماء فأحرقته وإلا بقي مكانه وعُهد إلى بني إسرائيل ذلك إلا في المسيح ومحمد قال تعالى «قل» لهم توبيخا «قد جاءكم رسلٌ من قبلي بالبينات» بالمعجزات «وبالذي قلتم» كزكريا ويحيى فقتلتموهم والخطابُ لمن في زمن نبينا محمد صلى الله عليه وسلم وإن كان الفعل لأجدادهم لرضاهم به «فلم قتلتموهم إن كنتم صادقين» في أنكم تؤمنون عند الإتيان به."},
  {'n': '184', 'v': "فَإِن كَذَّبُوكَ فَقَدْ كُذِّبَ رُسُلٌۭ مِّن قَبْلِكَ جَآءُو بِٱلْبَيِّنَٰتِ وَٱلزُّبُرِ وَٱلْكِتَٰبِ ٱلْمُنِيرِ", 't': "«فإن كذَّبوك فقد كُذب رسل من قبلك جاءُوا بالبينات» المعجزات «والزبُر» كصحف إبراهيم «والكتاب» وفي قراءة بإثبات الباء فيهما «المنير» الواضح هو التوراة والإنجيل فاصبر كما صبروا."},
  {'n': '185', 'v': "كُلُّ نَفْسٍۢ ذَآئِقَةُ ٱلْمَوْتِ ۗ وَإِنَّمَا تُوَفَّوْنَ أُجُورَكُمْ يَوْمَ ٱلْقِيَٰمَةِ ۖ فَمَن زُحْزِحَ عَنِ ٱلنَّارِ وَأُدْخِلَ ٱلْجَنَّةَ فَقَدْ فَازَ ۗ وَمَا ٱلْحَيَوٰةُ ٱلدُّنْيَآ إِلَّا مَتَٰعُ ٱلْغُرُورِ", 't': "«كل نفس ذائقة الموت وإنما توفَّون أجوركم» جزاء أعمالكم «يوم القيامة فمن زُحزح» بعد «عن النار وأدخل الجنة فقد فاز» نال غاية مطلوبه «وما الحياة الدنيا» أي العيش فيها «إلا متاع الغرور» الباطل يتمتع به قليلا ثم يفنى."},
  {'n': '186', 'v': "۞ لَتُبْلَوُنَّ فِىٓ أَمْوَٰلِكُمْ وَأَنفُسِكُمْ وَلَتَسْمَعُنَّ مِنَ ٱلَّذِينَ أُوتُوا۟ ٱلْكِتَٰبَ مِن قَبْلِكُمْ وَمِنَ ٱلَّذِينَ أَشْرَكُوٓا۟ أَذًۭى كَثِيرًۭا ۚ وَإِن تَصْبِرُوا۟ وَتَتَّقُوا۟ فَإِنَّ ذَٰلِكَ مِنْ عَزْمِ ٱلْأُمُورِ", 't': "«لَتُبْلَوُنَّ» حذف منه نون الرفع لتوالي النونات والواو ضمير الجمع لالتقاء الساكنين، لتختبرن «في أموالكم» بالفرائض فيها والحوائج «وأنفسكم» بالعبادات والبلاء «وَلَتَسْمَعُنَّ من الذين أوتوا الكتاب من قبلكم» اليهود والنصارى «ومن الذين أشركوا» من العرب «أذى كثيرا» من السب والطعن والتشبيب بنسائكم «وإن تصبروا» على ذلك «وتتقوا» الله بالفرائض «فإن ذلك من عزم الأمور» أي: من معزوماتها التي يعزم عليها لوجوبها."},
  {'n': '187', 'v': "وَإِذْ أَخَذَ ٱللَّهُ مِيثَٰقَ ٱلَّذِينَ أُوتُوا۟ ٱلْكِتَٰبَ لَتُبَيِّنُنَّهُۥ لِلنَّاسِ وَلَا تَكْتُمُونَهُۥ فَنَبَذُوهُ وَرَآءَ ظُهُورِهِمْ وَٱشْتَرَوْا۟ بِهِۦ ثَمَنًۭا قَلِيلًۭا ۖ فَبِئْسَ مَا يَشْتَرُونَ", 't': "«و» اذكر «إذ أخذ الله ميثاق الذين أوتوا الكتاب» أي العهد عليهم في التوراة «لَيُبَيِّنَنَّهُ» أي الكتاب «للناس ولا يكتمونه» أي الكتاب بالياء والتاء في الفعلين «فنبذوه» طرحوا الميثاق «وراء ظهورهم» فلم يعملوا به «واشتروا به» أخذوا بدله «ثمنا قليلا» من الدنيا من سفلتهم برياستهم في العلم فكتموه خوف فوته عليهم «فبئس ما يشترون» شراؤهم هذا."},
  {'n': '188', 'v': "لَا تَحْسَبَنَّ ٱلَّذِينَ يَفْرَحُونَ بِمَآ أَتَوا۟ وَّيُحِبُّونَ أَن يُحْمَدُوا۟ بِمَا لَمْ يَفْعَلُوا۟ فَلَا تَحْسَبَنَّهُم بِمَفَازَةٍۢ مِّنَ ٱلْعَذَابِ ۖ وَلَهُمْ عَذَابٌ أَلِيمٌۭ", 't': "«لا تحسبن» بالتاء والياء «الذين يفرحون بما أتوا» فعلوا من إضلال الناس «ويحبون أن يُحمدوا بما لم يفعلوا» من التمسك بالحق وهم على ضلال «فلا تحسبنهم» في الوجهين تأكيد «بمفازة» بمكان ينجون فيه «من العذاب» في الآخرة بل هم في مكان يعذَّبون فيه وهو جهنم «ولهم عذاب أليم» مؤلم فيها، ومفعولا يحسب الاولى دل عليهما مفعولا الثانية على قراءة التحتانية وعلى الفوقانية حذف الثاني فقط."},
  {'n': '189', 'v': "وَلِلَّهِ مُلْكُ ٱلسَّمَٰوَٰتِ وَٱلْأَرْضِ ۗ وَٱللَّهُ عَلَىٰ كُلِّ شَىْءٍۢ قَدِيرٌ", 't': "«ولله ملك السماوات والأرض» خزائن المطر والرزق والنبات وغيرها «والله على كل شيء قدير» ومنه تعذيب الكافرين وإنجاء المؤمنين."},
  {'n': '190', 'v': "إِنَّ فِى خَلْقِ ٱلسَّمَٰوَٰتِ وَٱلْأَرْضِ وَٱخْتِلَٰفِ ٱلَّيْلِ وَٱلنَّهَارِ لَءَايَٰتٍۢ لِّأُو۟لِى ٱلْأَلْبَٰبِ", 't': "«إن في خلق السماوات والأرض» وما فيهما من العجائب «واختلاف الليل والنهار» بالمجيء والذهاب والزيادة والنقصان «لآيات» دلالات على قدرته تعالى «لأولي الألباب» لذوي العقول."},
  {'n': '191', 'v': "ٱلَّذِينَ يَذْكُرُونَ ٱللَّهَ قِيَٰمًۭا وَقُعُودًۭا وَعَلَىٰ جُنُوبِهِمْ وَيَتَفَكَّرُونَ فِى خَلْقِ ٱلسَّمَٰوَٰتِ وَٱلْأَرْضِ رَبَّنَا مَا خَلَقْتَ هَٰذَا بَٰطِلًۭا سُبْحَٰنَكَ فَقِنَا عَذَابَ ٱلنَّارِ", 't': "«الذين» نعت لما قبله أو بدل «يذكرون الله قياما وقعودا وعلى جنوبهم» مضطجعين أي في كل حال، وعن ابن عباس يصلون كذلك حسب الطاقة «ويتفكرون في خلق السماوات والأرض» ليستدلوا به على قدرة صانعهما يقولون «ربنا ما خلقت هذا» الخلق الذي نراه «باطلا» حال، عبثا بل دليلا على كمال قدرتك «سبحانك» تنزيها لك عن العبث «فقِنا عذاب النار»."},
  {'n': '192', 'v': "رَبَّنَآ إِنَّكَ مَن تُدْخِلِ ٱلنَّارَ فَقَدْ أَخْزَيْتَهُۥ ۖ وَمَا لِلظَّٰلِمِينَ مِنْ أَنصَارٍۢ", 't': "«ربَّنا إنك من تدخل النار» للخلود فيها «فقد أخزيته» أهنته «وما للظالمين» الكافرين، فيه وضع الظاهر موضع المضمر إشعارا بتخصيص الخزي بهم «من» زائدة «أنصار» يمنعونهم من عذاب الله تعالى."},
  {'n': '193', 'v': "رَّبَّنَآ إِنَّنَا سَمِعْنَا مُنَادِيًۭا يُنَادِى لِلْإِيمَٰنِ أَنْ ءَامِنُوا۟ بِرَبِّكُمْ فَـَٔامَنَّا ۚ رَبَّنَا فَٱغْفِرْ لَنَا ذُنُوبَنَا وَكَفِّرْ عَنَّا سَيِّـَٔاتِنَا وَتَوَفَّنَا مَعَ ٱلْأَبْرَارِ", 't': "«ربَّنا إننا سمعنا مناديا ينادي» يدعو الناس «للإيمان» أي إليه وهو محمد أو القرآن «أن» أي بأن «آمنوا بربكم فآمنا» به «ربنا فاغفر لنا ذنوبنا وكفِّر» حط «عنا سيئاتنا» فلا تظهرها بالعقاب عليها «وتوفَّنا» اقبض أرواحنا «مع» في جملة «الأبرار» الأنبياء الصالحين."},
  {'n': '194', 'v': "رَبَّنَا وَءَاتِنَا مَا وَعَدتَّنَا عَلَىٰ رُسُلِكَ وَلَا تُخْزِنَا يَوْمَ ٱلْقِيَٰمَةِ ۗ إِنَّكَ لَا تُخْلِفُ ٱلْمِيعَادَ", 't': "«ربَّنا وآتنا» أعطنا «ما وعدتنا» به «على» ألسنه «رسلك» من الرحمة والفضل وسؤالهم ذلك وإن كان وعده تعالى لا يخلف سؤال أن يجعلهم من مستحقيه لأنهم لم يتيقنوا استحقاقهم له وتكرير ربَّنا مبالغة في التضرع «ولا تُخزنا يوم القيامة إنك لا تُخلف الميعاد» الوعد بالبعث والجزاء."},
  {'n': '195', 'v': "فَٱسْتَجَابَ لَهُمْ رَبُّهُمْ أَنِّى لَآ أُضِيعُ عَمَلَ عَٰمِلٍۢ مِّنكُم مِّن ذَكَرٍ أَوْ أُنثَىٰ ۖ بَعْضُكُم مِّنۢ بَعْضٍۢ ۖ فَٱلَّذِينَ هَاجَرُوا۟ وَأُخْرِجُوا۟ مِن دِيَٰرِهِمْ وَأُوذُوا۟ فِى سَبِيلِى وَقَٰتَلُوا۟ وَقُتِلُوا۟ لَأُكَفِّرَنَّ عَنْهُمْ سَيِّـَٔاتِهِمْ وَلَأُدْخِلَنَّهُمْ جَنَّٰتٍۢ تَجْرِى مِن تَحْتِهَا ٱلْأَنْهَٰرُ ثَوَابًۭا مِّنْ عِندِ ٱللَّهِ ۗ وَٱللَّهُ عِندَهُۥ حُسْنُ ٱلثَّوَابِ", 't': "«فاستجاب لهم ربهم» دعاءهم «أنِّي» أي بأني «لا أضيع عمل عامل منكم من ذكر أو أنثى بعضكم» كائن «من بعض» أي الذكور من الإناث وبالعكس والجملة مؤكدة لما قبلها أي هم سواء في المجازاة بالأعمال وترك تضييعها، نزلت لما قالت أم سلمة يا رسول الله إني لا أسمع ذكر النساء في الهجرة بشيء «فالذين هاجروا» من مكة إلى المدينة «وأخرجوا من ديارهم وأوذوا في سبيلي» ديني «وقاتلوا» الكفار «وَقُتِلُوا» بالتخفيف والتشديد وفي قراءة بتقديمه «لأكفِّرنَّ عنهم سيئاتهم» أسترها بالمغفرة «ولأدخلنهم جنات تجري من تحتها الأنهار ثوابا» مصدر من معنى لأكفرن مؤكد له «من عند الله» فيه التفات عن التكلم «والله عنده حسن الثواب» الجزاء."},
  {'n': '196', 'v': "لَا يَغُرَّنَّكَ تَقَلُّبُ ٱلَّذِينَ كَفَرُوا۟ فِى ٱلْبِلَٰدِ", 't': "ونزل لما قال المسلمون: أعداء الله فيما نري من الخير ونحن في الجهد: «لا يغرنك تقلُّب الذين كفروا» تصرُّفهم «في البلاد» بالتجارة والكسب."},
  {'n': '197', 'v': "مَتَٰعٌۭ قَلِيلٌۭ ثُمَّ مَأْوَىٰهُمْ جَهَنَّمُ ۚ وَبِئْسَ ٱلْمِهَادُ", 't': "هو «متاع قليل» يتمتعون به يسيرا في الدنيا ويفنى «ثم مأواهم جهنم وبئس المهاد» الفراش هي."},
  {'n': '198', 'v': "لَٰكِنِ ٱلَّذِينَ ٱتَّقَوْا۟ رَبَّهُمْ لَهُمْ جَنَّٰتٌۭ تَجْرِى مِن تَحْتِهَا ٱلْأَنْهَٰرُ خَٰلِدِينَ فِيهَا نُزُلًۭا مِّنْ عِندِ ٱللَّهِ ۗ وَمَا عِندَ ٱللَّهِ خَيْرٌۭ لِّلْأَبْرَارِ", 't': "«لكن الذين اتقوا ربَّهم لهم جنات تجري من تحتها الأنهار خالدين» أي مقدرين بالخلود «فيها نُزُلا» وهو ما يعد للضيف ونصبه على الحال من جَنَّاتٍ والعامل فيها معنى الظرف «من عند الله وما عند الله» من الثواب «خير للأبرار» من متاع الدنيا."},
  {'n': '199', 'v': "وَإِنَّ مِنْ أَهْلِ ٱلْكِتَٰبِ لَمَن يُؤْمِنُ بِٱللَّهِ وَمَآ أُنزِلَ إِلَيْكُمْ وَمَآ أُنزِلَ إِلَيْهِمْ خَٰشِعِينَ لِلَّهِ لَا يَشْتَرُونَ بِـَٔايَٰتِ ٱللَّهِ ثَمَنًۭا قَلِيلًا ۗ أُو۟لَٰٓئِكَ لَهُمْ أَجْرُهُمْ عِندَ رَبِّهِمْ ۗ إِنَّ ٱللَّهَ سَرِيعُ ٱلْحِسَابِ", 't': "«وإن من أهل الكتاب لمن يؤمن بالله» كعبد الله بن سلام وأصحابه والنجاشي «وما أنزل إليكم» أي القرآن «وما أنزل إليهم» أي التوراة والإنجيل «خاشعين» حال من ضمير يؤمن مراعى فيه معنى من أي: متواضعين «لله لا يشترون بآيات الله» التي عندهم في التوراة والإنجيل من بعث النبي صلى الله عليه وسلم «ثمنا قليلا» من الدنيا بأن يكتموها خوفا على الرياسة كفعل غيرهم من اليهود «أولئك لهم أجرهم» ثواب أعمالهم «عند ربهم» يُؤْتَوْنَهُ مرتين كما في القصص «إن الله سريع الحساب» يحاسب الخلق في قدر نصف نهار من أيام الدنيا."},
  {'n': '200', 'v': "يَٰٓأَيُّهَا ٱلَّذِينَ ءَامَنُوا۟ ٱصْبِرُوا۟ وَصَابِرُوا۟ وَرَابِطُوا۟ وَٱتَّقُوا۟ ٱللَّهَ لَعَلَّكُمْ تُفْلِحُونَ", 't': "«يا أيها الذين آمنوا اصبروا» على الطاعات والمصائب وعن المعاصي «وصابروا» الكُفَّار فلا يكونوا أشد صبرا منكم «ورابطوا» أقيموا على الجهاد «واتقوا الله» في جميع أحوالكم «لعلَّكم تفلحون» تفوزون بالجنة وتنجون من النار."},
