  {'n': '11', 'v': "يُوصِيكُمُ ٱللَّهُ فِىٓ أَوْلَٰدِكُمْ ۖ لِلذَّكَرِ مِثْلُ حَظِّ ٱلْأُنثَيَيْنِ ۚ فَإِن كُنَّ نِسَآءًۭ فَوْقَ ٱثْنَتَيْنِ فَلَهُنَّ ثُلُثَا مَا تَرَكَ ۖ وَإِن كَانَتْ وَٰحِدَةًۭ فَلَهَا ٱلنِّصْفُ ۚ وَلِأَبَوَيْهِ لِكُلِّ وَٰحِدٍۢ مِّنْهُمَا ٱلسُّدُسُ مِمَّا تَرَكَ إِن كَانَ لَهُۥ وَلَدٌۭ ۚ فَإِن لَّمْ يَكُن لَّهُۥ وَلَدٌۭ وَوَرِثَهُۥٓ أَبَوَاهُ فَلِأُمِّهِ ٱلثُّلُثُ ۚ فَإِن كَانَ لَهُۥٓ إِخْوَةٌۭ فَلِأُمِّهِ ٱلسُّدُسُ ۚ مِنۢ بَعْدِ وَصِيَّةٍۢ يُوصِى بِهَآ أَوْ دَيْنٍ ۗ ءَابَآؤُكُمْ وَأَبْنَآؤُكُمْ لَا تَدْرُونَ أَيُّهُمْ أَقْرَبُ لَكُمْ نَفْعًۭا ۚ فَرِيضَةًۭ مِّنَ ٱللَّهِ ۗ إِنَّ ٱللَّهَ كَانَ عَلِيمًا حَكِيمًۭا", 't': "«يوصيكم» يأمركم «الله في» شأن «أولادكم» بما يذكر «للذكر» منهم «مثل حظ» نصيب «الأنثيين» إذا اجتمعنا معه فله نصف المال ولهما النصف فإن كان معه واحدة فلها الثلث وله الثلثان وإن انفرد جاز المال «فإن كنَّ» أي الأولاد «نساءً» فقط «فوق اثنتين فلهن ثلثا ما ترك» الميت وكذا الاثنتان لأنه للأختين بقوله «فلهما الثلثان مما ترك» فهما أولى به ولأن البنت تستحق الثلث مع الذكر فمع الأنثى أولى (وفوق) قيل صلة وقيل لدفع توهم زيادة النصيب بزيادة العدد لما فهم استحقاق البنتين الثلثين من جعل الثلث للواحدة مع الذكر «وإن كانت» المولودة «واحدة» وفي قراءة بالرفع فكان تامة «فلها النصف ولأبويه» أي الميت ويبدل منهما «لكل واحد منهما السدس مما ترك إن كان له ولد» ذكر أو أنثى ونكتة البدل إفادة أنهما لا يشتركان فيه وألحق بالولد ولد الابن وبالأب الجد «فإن لم يكن له ولد وورثه أبواه» فقط أو مع زوج «فلأمه» بضم الهمزة وكسرها فرارا من الانتقال من ضمة إلى كسرة لثقله في الموضعين «الثلث» أي ثلث المال أو ما ينبغي بعد الزوج والباقي للأب «فإن كان له إخوة» أي اثنان فصاعدا ذكورا أو إناثا «فلأمه السدس» والباقي للأب ولا شيء للأخوة وإرث من ذكر ما ذُكر «من بعد» تنفيذ «وصية يوصي» بالبناء للفاعل والمفعول «بها أو» قضاء «دين» عليه وتقديم الوصية على الدين وإن كانت مؤخرة عنه في الوفاء للاهتمام بها «آباؤكم وأبناؤكم» مبتدأ خبره «لا تدرون أيهم أقرب لكم نفعا» في الدنيا والآخرة فظان أن ابنه أنفع له فيعطيه الميراث فيكون الأب أنفع وبالعكس وإنما العالم بذلك هو الله ففرض لكم الميراث «فريضة من الله إن الله كان عليما» بخلقه «حكيما» فيما دبَّره لهم: أي لم يزل متصفا بذلك."},
  {'n': '12', 'v': "۞ وَلَكُمْ نِصْفُ مَا تَرَكَ أَزْوَٰجُكُمْ إِن لَّمْ يَكُن لَّهُنَّ وَلَدٌۭ ۚ فَإِن كَانَ لَهُنَّ وَلَدٌۭ فَلَكُمُ ٱلرُّبُعُ مِمَّا تَرَكْنَ ۚ مِنۢ بَعْدِ وَصِيَّةٍۢ يُوصِينَ بِهَآ أَوْ دَيْنٍۢ ۚ وَلَهُنَّ ٱلرُّبُعُ مِمَّا تَرَكْتُمْ إِن لَّمْ يَكُن لَّكُمْ وَلَدٌۭ ۚ فَإِن كَانَ لَكُمْ وَلَدٌۭ فَلَهُنَّ ٱلثُّمُنُ مِمَّا تَرَكْتُم ۚ مِّنۢ بَعْدِ وَصِيَّةٍۢ تُوصُونَ بِهَآ أَوْ دَيْنٍۢ ۗ وَإِن كَانَ رَجُلٌۭ يُورَثُ كَلَٰلَةً أَوِ ٱمْرَأَةٌۭ وَلَهُۥٓ أَخٌ أَوْ أُخْتٌۭ فَلِكُلِّ وَٰحِدٍۢ مِّنْهُمَا ٱلسُّدُسُ ۚ فَإِن كَانُوٓا۟ أَكْثَرَ مِن ذَٰلِكَ فَهُمْ شُرَكَآءُ فِى ٱلثُّلُثِ ۚ مِنۢ بَعْدِ وَصِيَّةٍۢ يُوصَىٰ بِهَآ أَوْ دَيْنٍ غَيْرَ مُضَآرٍّۢ ۚ وَصِيَّةًۭ مِّنَ ٱللَّهِ ۗ وَٱللَّهُ عَلِيمٌ حَلِيمٌۭ", 't': "«ولكم نصف ما ترك أزواجكم إن لم يكن لهن ولد» منكم أو من غيركم «فإن كان لهن ولد فلكم الربع مما تركن من بعد وصية يوصين بها أو دين» وألحق بالولد في ذلك ولد الابن بالإجماع «ولهن» أي الزوجات تعددن أو لا «الربع مما تركتم إن لم يكن لكم ولد فإن كان لكم ولد» منهن أو من غيرهن «فلهن الثمن مما تركتم من بعد وصية توصون بها أو دين» وولد الابن في ذلك كالولد إجماعا «وإن كان رجل يورث» صفة والخبر «كلالة» أي لا والد له ولا ولد «أو امرأة» تورث كلالة «وله» أي للمورث كلالة «أخ أو أخت» أي من أم وقرأ به ابن مسعود وغيره «فلكل واحد منهما السدس» مما ترك «فإن كانوا» أي الإخوة والأخوات من الأم «أكثر من ذلك» أي من واحد «فهم شركاء في الثلث» يستوي فيه ذكرهم وأنثاهم «من بعد وصية يوصي بها أو دين غير مُضارّ» حال من ضمير يوصي أي غير مدخل الضرر على الورثة بأن يوصي بأكثر من الثلث «وصيةً» مصدر مؤكد ليوصيكم «من الله والله عليم» بما دبره لخلقه من الفرائض «حليم» بتأخير العقوبة عمن خالفه، وخصت السنة توريث من ذكر بمن ليس فيه مانع من قتل أو اختلاف دين أو رقٌ."},
  {'n': '13', 'v': "تِلْكَ حُدُودُ ٱللَّهِ ۚ وَمَن يُطِعِ ٱللَّهَ وَرَسُولَهُۥ يُدْخِلْهُ جَنَّٰتٍۢ تَجْرِى مِن تَحْتِهَا ٱلْأَنْهَٰرُ خَٰلِدِينَ فِيهَا ۚ وَذَٰلِكَ ٱلْفَوْزُ ٱلْعَظِيمُ", 't': "«تلك» الأحكام المذكورة من أمر اليتامى وما بعده «حدود الله» شرائعه التي حدَّها لعباده ليعملوا بها ولا يتعدوها «ومن يطع الله ورسوله» فيما حكم به «يدخله» بالياء والنون التفاتا «جنات تجري من تحتها الأنهار خالدين فيها وذلك الفوز العظيم»."},
  {'n': '14', 'v': "وَمَن يَعْصِ ٱللَّهَ وَرَسُولَهُۥ وَيَتَعَدَّ حُدُودَهُۥ يُدْخِلْهُ نَارًا خَٰلِدًۭا فِيهَا وَلَهُۥ عَذَابٌۭ مُّهِينٌۭ", 't': "«ومن يعص الله ورسوله ويتعد حدوده يدخله» بالوجهين «نارا خالدا فيها وله» فيها «عذاب مهين» ذو إهانة روعي في الضمائر في الآيتين لفظ من وفي خالدين معناها."},
  {'n': '15', 'v': "وَٱلَّٰتِى يَأْتِينَ ٱلْفَٰحِشَةَ مِن نِّسَآئِكُمْ فَٱسْتَشْهِدُوا۟ عَلَيْهِنَّ أَرْبَعَةًۭ مِّنكُمْ ۖ فَإِن شَهِدُوا۟ فَأَمْسِكُوهُنَّ فِى ٱلْبُيُوتِ حَتَّىٰ يَتَوَفَّىٰهُنَّ ٱلْمَوْتُ أَوْ يَجْعَلَ ٱللَّهُ لَهُنَّ سَبِيلًۭا", 't': "(واللاتي يأتين الفاحشة) الزنا (من نسائكم فاستشهدوا عليهن أربعة منكم) أي من رجالكم المسلمين (فإن شهدوا) عليهن بها (فأمسكوهن) احبسوهن (في البيوت) وامنعوهن من مخالطة الناس (حتى يتوفاهن الموت) أي ملائكته (أو) إلى أن (يجعل الله لهن سبيلا) طريقا إلى الخروج منها أمروا بذلك أول الإسلام ثم جعل لهن سبيلا بجلد البكر مائة وتغريبها عاما ورجم المحصنة، وفي الحديث لما بين الحد قال \"\" خذوا عني خذوا عني قد جعل الله لهن سبيلا \"\" رواه مسلم."},
  {'n': '16', 'v': "وَٱلَّذَانِ يَأْتِيَٰنِهَا مِنكُمْ فَـَٔاذُوهُمَا ۖ فَإِن تَابَا وَأَصْلَحَا فَأَعْرِضُوا۟ عَنْهُمَآ ۗ إِنَّ ٱللَّهَ كَانَ تَوَّابًۭا رَّحِيمًا", 't': "«وَاًلَّلذّانِ» بتخفيف النون وتشديدها «يأتيانها» أي الفاحشة الزنا أو اللواط «منكم» أي الرجال «فآذوهما» بالسب والضرب بالنعال «فإن تابا» منها «وأصلحا» العمل «فأعرضوا عنهما» ولا تؤذوهما «إن الله كان توَّابا» على من تاب «رحيما» به وهذا منسوخ بالحد إن أريد بها الزنا وكذا إن أريد بها اللواط عن الشافعي لكن المفعول به لا يرجم عنده وإن كان محصنا بل يجلد ويغرب وإرادةُ اللواط أظهر بدليل تثنية الضمير والأول أراد الزاني والزانية ويرده تبيينهما بمن المتصلة بضمير الرجال واشتراكهما في الأذى والتوبة والإعراض وهو مخصوص بالرجال لما تقدم في النساء من الحبس."},
  {'n': '17', 'v': "إِنَّمَا ٱلتَّوْبَةُ عَلَى ٱللَّهِ لِلَّذِينَ يَعْمَلُونَ ٱلسُّوٓءَ بِجَهَٰلَةٍۢ ثُمَّ يَتُوبُونَ مِن قَرِيبٍۢ فَأُو۟لَٰٓئِكَ يَتُوبُ ٱللَّهُ عَلَيْهِمْ ۗ وَكَانَ ٱللَّهُ عَلِيمًا حَكِيمًۭا", 't': "«إنما التوبة على الله» أي التي كتب على نفسه قبولها بفضله «للذين يعملون السوء» المعصية «بجهالة» حال أي جاهلين إذا عصوا ربهم «ثم يتوبون من» زمن «قريب» قبل أن يغرغروا «فأولئك يتوب الله عليهم» يقبل توبتهم «وكان الله عليما» بخلقه «حكيما» في صنعه بهم."},
  {'n': '18', 'v': "وَلَيْسَتِ ٱلتَّوْبَةُ لِلَّذِينَ يَعْمَلُونَ ٱلسَّيِّـَٔاتِ حَتَّىٰٓ إِذَا حَضَرَ أَحَدَهُمُ ٱلْمَوْتُ قَالَ إِنِّى تُبْتُ ٱلْـَٰٔنَ وَلَا ٱلَّذِينَ يَمُوتُونَ وَهُمْ كُفَّارٌ ۚ أُو۟لَٰٓئِكَ أَعْتَدْنَا لَهُمْ عَذَابًا أَلِيمًۭا", 't': "«وليست التوبة للذين يعملون السيئات» الذنوب «حتى إذا حضر أحدهم الموتُ» وأخذ في النزع «قال» عند مشاهدة ما هو فيه «إنِّي تبت الآن» فلا ينفعه ذلك ولا يقبل منه «ولا الذين يموتون وهم كفار» إذا تابوا في الآخرة عند معاينة العذاب لا تقبل منهم «أولئك أعتدنا» أعددنا «لهم عذابا أليما» مؤلما."},
  {'n': '19', 'v': "يَٰٓأَيُّهَا ٱلَّذِينَ ءَامَنُوا۟ لَا يَحِلُّ لَكُمْ أَن تَرِثُوا۟ ٱلنِّسَآءَ كَرْهًۭا ۖ وَلَا تَعْضُلُوهُنَّ لِتَذْهَبُوا۟ بِبَعْضِ مَآ ءَاتَيْتُمُوهُنَّ إِلَّآ أَن يَأْتِينَ بِفَٰحِشَةٍۢ مُّبَيِّنَةٍۢ ۚ وَعَاشِرُوهُنَّ بِٱلْمَعْرُوفِ ۚ فَإِن كَرِهْتُمُوهُنَّ فَعَسَىٰٓ أَن تَكْرَهُوا۟ شَيْـًۭٔا وَيَجْعَلَ ٱللَّهُ فِيهِ خَيْرًۭا كَثِيرًۭا", 't': "«يا أيُّها الذين آمنوا لا يحلُّ لكم أن ترثوا النساء» أي ذاتهن «كرها» بالفتح والضم لغتان أي مكرهيهن على ذلك كانوا في الجاهلية يرثون نساء أقربائهم فإن شاءوا تزوجوهن بلا صداق أو زوَّجوهن وأخذوا صداقهن أو عضلوهن حتى يفتدين بما ورثنه أو يمتن فيرثوهن فنُهوا عن ذلك «ولا» أن «تعضلوهن» أي تمنعوا أزواجكم عن نكاح غيركم بإمساكهن ولا رغبة لكم فيهن ضرارا «لتذهبوا ببعض ما آتيتموهن» من المهر «إلا أن يأتين بفاحشة مبيَّنة» بفتح الياء وكسرها أي بينت أو هي بينة أي زنا أو نشوز فلكم أن تضاروهن حتى يفتدين منكم ويختلعن «وعاشروهن بالمعروف» أي بالإجمال في القول والنفقة والمبيت «فإن كرهتموهن» فاصبروا «فعسى أن تكرهوا شيئا ويجعل الله فيه خيرا كثيرا» ولعله يجعل فيهن ذلك بأن يرزقكم منهن ولدا صالحا."},
  {'n': '20', 'v': "وَإِنْ أَرَدتُّمُ ٱسْتِبْدَالَ زَوْجٍۢ مَّكَانَ زَوْجٍۢ وَءَاتَيْتُمْ إِحْدَىٰهُنَّ قِنطَارًۭا فَلَا تَأْخُذُوا۟ مِنْهُ شَيْـًٔا ۚ أَتَأْخُذُونَهُۥ بُهْتَٰنًۭا وَإِثْمًۭا مُّبِينًۭا", 't': "«وإن أردتم استبدال زوج مكان زوج» أي أخذها بدلها بأن طلقتموها «و» قد «آتيتم إحداهن» أي الزوجات «قنطارا» مالا كثيرا صداقا «فلا تأخذوا منه شيئا أتأخُذُونهُ بهتانا» ظلما «وإثما مبينا» بينا ونصبهما على الحال، والاستفهامُ للتوبيخ وللإنكار في قوله."},
  {'n': '21', 'v': "وَكَيْفَ تَأْخُذُونَهُۥ وَقَدْ أَفْضَىٰ بَعْضُكُمْ إِلَىٰ بَعْضٍۢ وَأَخَذْنَ مِنكُم مِّيثَٰقًا غَلِيظًۭا", 't': "«وكيف تأخذونه» أي بأي وجه «وقد أفضى» وصل «بعضكم إلى بعض» بالجماع المقرر للمهر «وأخذن منكم ميثاقا» عهدا «غليظا» شديدا وهو ما أمر الله به من إمساكهن بمعروف أو تسريحهن بإحسان."},
  {'n': '22', 'v': "وَلَا تَنكِحُوا۟ مَا نَكَحَ ءَابَآؤُكُم مِّنَ ٱلنِّسَآءِ إِلَّا مَا قَدْ سَلَفَ ۚ إِنَّهُۥ كَانَ فَٰحِشَةًۭ وَمَقْتًۭا وَسَآءَ سَبِيلًا", 't': "«ولا تنكحوا ما» بمعنى من «نكح آباؤكم من النساء إلا» لكن «ما قد سلف» من فعلكم ذلك فانه معفوّ عنه «إنه» أي نكاحهن «كان فاحشة» قبيحا «ومقتا» سببا للمقت من الله وهو أشد البغض «وساء» بئس «سبيلا» طريقا ذلك."},
  {'n': '23', 'v': "حُرِّمَتْ عَلَيْكُمْ أُمَّهَٰتُكُمْ وَبَنَاتُكُمْ وَأَخَوَٰتُكُمْ وَعَمَّٰتُكُمْ وَخَٰلَٰتُكُمْ وَبَنَاتُ ٱلْأَخِ وَبَنَاتُ ٱلْأُخْتِ وَأُمَّهَٰتُكُمُ ٱلَّٰتِىٓ أَرْضَعْنَكُمْ وَأَخَوَٰتُكُم مِّنَ ٱلرَّضَٰعَةِ وَأُمَّهَٰتُ نِسَآئِكُمْ وَرَبَٰٓئِبُكُمُ ٱلَّٰتِى فِى حُجُورِكُم مِّن نِّسَآئِكُمُ ٱلَّٰتِى دَخَلْتُم بِهِنَّ فَإِن لَّمْ تَكُونُوا۟ دَخَلْتُم بِهِنَّ فَلَا جُنَاحَ عَلَيْكُمْ وَحَلَٰٓئِلُ أَبْنَآئِكُمُ ٱلَّذِينَ مِنْ أَصْلَٰبِكُمْ وَأَن تَجْمَعُوا۟ بَيْنَ ٱلْأُخْتَيْنِ إِلَّا مَا قَدْ سَلَفَ ۗ إِنَّ ٱللَّهَ كَانَ غَفُورًۭا رَّحِيمًۭا", 't': "(حرمت عليكم أمهاتكم) أن تنكحوهن وشملت الجدات من قبل الأب أو الأم (وبناتكم) وشملت بنات الأولاد وإن سفلن (وأخواتكم) من جهة الأب أو الأم (وعماتكم) أي أخوات آبائكم وأجدادكم (وخالاتكم) أي أخوات أمهاتكم وجداتكم (وبنات الأخ وبنات الأخت) ويدخل فيهن أولادهم (وأمهاتكم اللاتي أرضعنكم) قبل استكمال الحولين خمس رضعات كما بينه الحديث (وأخواتكم من الرضاعة) ويلحق بذلك بالسنة البنات منها وهن من أرضعتهم موطوأته والعمات والخالات وبنات الأخ وبنات الأخت منها لحديث: \"\" يحرم من الرضاع ما يحرم من النسب \"\" رواه البخاري ومسلم (وأمهات نسائكم وربائبكم) جمع ربيبة وهي بنت الزوجة من غيره (اللاتي في حجوركم) تربونهن. صفة موافقة للغالب فلا مفهوم لها (من نسائكم اللاتي دخلتم بهن) أي جامعتموهن (فإن لم تكونوا دخلتم بهن فلا جناح عليكم) في نكاح بناتهن إذا فارقتموهن (وحلائل) أزواج (أبنائكم الذين من أصلابكم) بخلاف من تبنيتموهم فلكم نكاح حلائلهم (وأن تجمعوا بين الأختين) من نسب أو رضاع بالنكاح ويلحق بهما بالسنة الجمع بينها وبين عمتها أو خالتها ويجوز نكاح كل واحدة على الانفراد وملكهما معا ويطأ واحدة (إلا) لكن (ما قد سلف) في الجاهلية من نكاحهم بعض ما ذكر فلا جناح عليكم فيه (إن الله كان غفورا) لما سلف منكم قبل النهي (رحيما) بكم في ذلك."},
  {'n': '24', 'v': "۞ وَٱلْمُحْصَنَٰتُ مِنَ ٱلنِّسَآءِ إِلَّا مَا مَلَكَتْ أَيْمَٰنُكُمْ ۖ كِتَٰبَ ٱللَّهِ عَلَيْكُمْ ۚ وَأُحِلَّ لَكُم مَّا وَرَآءَ ذَٰلِكُمْ أَن تَبْتَغُوا۟ بِأَمْوَٰلِكُم مُّحْصِنِينَ غَيْرَ مُسَٰفِحِينَ ۚ فَمَا ٱسْتَمْتَعْتُم بِهِۦ مِنْهُنَّ فَـَٔاتُوهُنَّ أُجُورَهُنَّ فَرِيضَةًۭ ۚ وَلَا جُنَاحَ عَلَيْكُمْ فِيمَا تَرَٰضَيْتُم بِهِۦ مِنۢ بَعْدِ ٱلْفَرِيضَةِ ۚ إِنَّ ٱللَّهَ كَانَ عَلِيمًا حَكِيمًۭا", 't': "«و» حرمت عليكم «المحصَنات» أي ذوات الأزواج «من النساء» أن تنكحوهن قبل مفارقة أزواجهن حرائر مسلمات كن أو لا «إلا ما ملكت أيمانكم» من الإماء بالسبي فلكم وطؤهن وإن كان لهن أزواج في دار الحرب بعد الاستبراء «كتاب الله» نصب على المصدر أي كتب ذلك «عليكم وَأحلَّ» بالبناء للفاعل والمفعول «لكم ما وراء ذلكم» أي سوى ما حرم عليكم من النساء «أن تبتغوا» تطلبوا النساء «بأموالكم» بصداق أو ثمن «محصنين» متزوجين «غير مسافحين» زانين «فما» فمن «استمتعتم» تمتعتم «به منهن» ممن تزوجتم بالوطء «فآتوهن أجورهن» مهورهن التي فرضتم لهن «فريضة ولا جناح عليكم فيما تراضيتم» أنتم وهن «به من بعد الفريضة» من حطها أو بعضها أو زيادة عليها «إن الله كان عليما» بخلقه «حكيما» فيما دبره لهم."},
  {'n': '25', 'v': "وَمَن لَّمْ يَسْتَطِعْ مِنكُمْ طَوْلًا أَن يَنكِحَ ٱلْمُحْصَنَٰتِ ٱلْمُؤْمِنَٰتِ فَمِن مَّا مَلَكَتْ أَيْمَٰنُكُم مِّن فَتَيَٰتِكُمُ ٱلْمُؤْمِنَٰتِ ۚ وَٱللَّهُ أَعْلَمُ بِإِيمَٰنِكُم ۚ بَعْضُكُم مِّنۢ بَعْضٍۢ ۚ فَٱنكِحُوهُنَّ بِإِذْنِ أَهْلِهِنَّ وَءَاتُوهُنَّ أُجُورَهُنَّ بِٱلْمَعْرُوفِ مُحْصَنَٰتٍ غَيْرَ مُسَٰفِحَٰتٍۢ وَلَا مُتَّخِذَٰتِ أَخْدَانٍۢ ۚ فَإِذَآ أُحْصِنَّ فَإِنْ أَتَيْنَ بِفَٰحِشَةٍۢ فَعَلَيْهِنَّ نِصْفُ مَا عَلَى ٱلْمُحْصَنَٰتِ مِنَ ٱلْعَذَابِ ۚ ذَٰلِكَ لِمَنْ خَشِىَ ٱلْعَنَتَ مِنكُمْ ۚ وَأَن تَصْبِرُوا۟ خَيْرٌۭ لَّكُمْ ۗ وَٱللَّهُ غَفُورٌۭ رَّحِيمٌۭ", 't': "(ومن لم يستطع منكم طولا) أي غنى لـ (أن ينكح المحصنات) الحرائر (المؤمنات) هو جري على الغالب فلا مفهوم له (فمن ما ملكت أيمانكم) ينكح (من فتياتكم المؤمنات والله أعلم بإيمانكم) فاكتفوا بظاهره وكِلوا السرائر إليه فإنه العالم بتفضيلها ورب أمة تفضل حرة فيه وهذا تأنيس بنكاح الإماء (بعضكم من بعض) أي أنتم وهن سواء في الدين فلا تستنكفوا من نكاحهن (فانكحوهن بإذن أهلهن) مواليهن (وآتوهن) أعطوهن. (أجورهن) مهورهن (بالمعروف) من غير مطل ونقص (محصنات) عفائف حال (غير مسافحات) زانيات جهرا (ولا متخذات أخذان) أخلاء يزنون بهن سرا (فإذا أحصن) زوجن وفي قراءة بالبناء للفاعل تزوجن (فإن أتين بفاحشة) زنا (فعليهن نصف ما على المحصنات) الحرائر الأبكار إذا زنين (من العذاب) الحد فيجلدن خمسين ويغربن نصف سنة ويقاس عليهن العبيد ولم يجعل الإحصان شرطا لوجوب الحد لإفادة أنه لا رجم عليهن أصلا (ذلك) أي نكاح المملوكات عند عدم الطول (لمن خشي) خاف (العنت) الزنا وأصله المشقة سمي به الزنا لأنه سببها بالحد في الدنيا والعقوبة في الآخرة (منكم) بخلاف من لا يخافه من الأحرار فلا يحل له نكاحها وكذا من استطاع طول حرة وعليه الشافعي وخرج بقوله \"\" من فتياتكم المؤمنات \"\" الكافرات: فلا يحل له نكاحها ولو عدل وخاف (وأن تصبروا) عن نكاح المملوكات (خير لكم) لئلا يصير الولد رقيقا (والله غفور رحيم) بالتوسعة في ذلك."},
  {'n': '26', 'v': "يُرِيدُ ٱللَّهُ لِيُبَيِّنَ لَكُمْ وَيَهْدِيَكُمْ سُنَنَ ٱلَّذِينَ مِن قَبْلِكُمْ وَيَتُوبَ عَلَيْكُمْ ۗ وَٱللَّهُ عَلِيمٌ حَكِيمٌۭ", 't': "«يريد الله ليبين لكم» شرائع دينكم ومصالح أمركم «ويهديكم سنن» طرائق «الذين من قبلكم» من الأنبياء في التحليل والتحريم فتتَّبعوهم «وينوب عليكم» يرجع بكم عن معصيته التي كنتم عليها إلى طاعته «والله عليم» بكم «حكيم» فيما دبره لكم."},
  {'n': '27', 'v': "وَٱللَّهُ يُرِيدُ أَن يَتُوبَ عَلَيْكُمْ وَيُرِيدُ ٱلَّذِينَ يَتَّبِعُونَ ٱلشَّهَوَٰتِ أَن تَمِيلُوا۟ مَيْلًا عَظِيمًۭا", 't': "«والله يريد أن يتوب عليكم» كرره ليبنى عليه «ويريد الذين يتبعون الشهوات» اليهود والنصارى أو المجوس أو الزناة «أن تميلوا ميلا عظيما» تعدلوا عن الحق بارتكاب ما حُرم عليكم فتكونوا مثلهم."},
  {'n': '28', 'v': "يُرِيدُ ٱللَّهُ أَن يُخَفِّفَ عَنكُمْ ۚ وَخُلِقَ ٱلْإِنسَٰنُ ضَعِيفًۭا", 't': "«يريد الله أن يخفف عنكم» يسهل عليكم أحكام الشرع «وخلق الإنسان ضعيفا» لا يصبر عن النساء والشهوات."},
  {'n': '29', 'v': "يَٰٓأَيُّهَا ٱلَّذِينَ ءَامَنُوا۟ لَا تَأْكُلُوٓا۟ أَمْوَٰلَكُم بَيْنَكُم بِٱلْبَٰطِلِ إِلَّآ أَن تَكُونَ تِجَٰرَةً عَن تَرَاضٍۢ مِّنكُمْ ۚ وَلَا تَقْتُلُوٓا۟ أَنفُسَكُمْ ۚ إِنَّ ٱللَّهَ كَانَ بِكُمْ رَحِيمًۭا", 't': "«يا أيها الذين آمنوا لا تأكلوا أموالكم بينكم بالباطل» بالحرام في الشرع كالربا والغصب «إلا» لكن «أن تكون» تقع «تجارة» وفي قراءة بالنصب أن تكون الأموال أموال تجارة صادرة «عن تراضى منكم» وطيب نفس فلكم أن تأكلوها «ولا تقتلوا أنفسكم» بارتكاب ما يؤدي إلى هلاكها أيّا كان في الدنيا أو الآخرة بقرينة «إن الله كان بكم رحيما» في منعه لكم من ذلك."},
  {'n': '30', 'v': "وَمَن يَفْعَلْ ذَٰلِكَ عُدْوَٰنًۭا وَظُلْمًۭا فَسَوْفَ نُصْلِيهِ نَارًۭا ۚ وَكَانَ ذَٰلِكَ عَلَى ٱللَّهِ يَسِيرًا", 't': "«ومن يفعل ذلك» أي ما نُهي عنه «عُدوانا» تجاوزا للحلال حال «وظلما» تأكيد «فسوف نصليه» ندخله «نارا» يحترق فيها «وكان ذلك على الله يسيرا» هيِّنا."},
  {'n': '31', 'v': "إِن تَجْتَنِبُوا۟ كَبَآئِرَ مَا تُنْهَوْنَ عَنْهُ نُكَفِّرْ عَنكُمْ سَيِّـَٔاتِكُمْ وَنُدْخِلْكُم مُّدْخَلًۭا كَرِيمًۭا", 't': "«إن تجتنبوا كبائر ما تنهون عنه» وهي ما ورد عليها وعيد كالقتال والزنا والسرقة وعن ابن عباس هي إلى السبعمائة أقرب «نكفِّر عنكم سيِّئاتكم» الصغائر بالطاعات «وندخلكم مُدخلا» بضم الميم وفتحها أي إدخالا أو موضعا «كريما» هو الجنة."},
  {'n': '32', 'v': "وَلَا تَتَمَنَّوْا۟ مَا فَضَّلَ ٱللَّهُ بِهِۦ بَعْضَكُمْ عَلَىٰ بَعْضٍۢ ۚ لِّلرِّجَالِ نَصِيبٌۭ مِّمَّا ٱكْتَسَبُوا۟ ۖ وَلِلنِّسَآءِ نَصِيبٌۭ مِّمَّا ٱكْتَسَبْنَ ۚ وَسْـَٔلُوا۟ ٱللَّهَ مِن فَضْلِهِۦٓ ۗ إِنَّ ٱللَّهَ كَانَ بِكُلِّ شَىْءٍ عَلِيمًۭا", 't': "«ولا تتمنَّوا ما فضَّل الله به بعضكم على بعض» من جهة الدنيا أو الدين لئلا يؤدى إلى التحاسد والتباغض «للرجال نصيب» ثواب «مما اكتسبوا» بسبب ما عملوا من الجهاد وغيره «وللنساء نصيب مما اكتسبن» من طاعة أزواجهن وحفظ فروجهن نزلت لما قالت أم سلمة: ليتنا كنا رجالا فجاهدنا وكان لنا مثل أجر الرجال «واسألوا» بهمزة ودونها «الله من فضله» ما احتجتم إليه يعطكم «إن الله كان بكل شيء عليما» ومنه محل الفضل وسؤالكم."},
  {'n': '33', 'v': "وَلِكُلٍّۢ جَعَلْنَا مَوَٰلِىَ مِمَّا تَرَكَ ٱلْوَٰلِدَانِ وَٱلْأَقْرَبُونَ ۚ وَٱلَّذِينَ عَقَدَتْ أَيْمَٰنُكُمْ فَـَٔاتُوهُمْ نَصِيبَهُمْ ۚ إِنَّ ٱللَّهَ كَانَ عَلَىٰ كُلِّ شَىْءٍۢ شَهِيدًا", 't': "«ولكلٌ» عن الرجال والنساء «جعلنا موالي» عصبة يعطون «مما ترك الوالدان والأقربون» لهم من المال «والذين عاقدت» بألف ودونها «أيمانكم» جمع يمين بمعنى القسم أو اليد أي الخلفاء الذين عاهدتموهم في الجاهلية على النصرة والإرث «فآتوهم» الآن «نصيبهم» حظوظهم من الميراث وهو السدس «إن الله على كل شيء شهيدا» مطلعا ومنه حالكم وهذا منسوخ بقوله (وأولوا الأرحام بعضهم أول ببعض)."},
  {'n': '34', 'v': "ٱلرِّجَالُ قَوَّٰمُونَ عَلَى ٱلنِّسَآءِ بِمَا فَضَّلَ ٱللَّهُ بَعْضَهُمْ عَلَىٰ بَعْضٍۢ وَبِمَآ أَنفَقُوا۟ مِنْ أَمْوَٰلِهِمْ ۚ فَٱلصَّٰلِحَٰتُ قَٰنِتَٰتٌ حَٰفِظَٰتٌۭ لِّلْغَيْبِ بِمَا حَفِظَ ٱللَّهُ ۚ وَٱلَّٰتِى تَخَافُونَ نُشُوزَهُنَّ فَعِظُوهُنَّ وَٱهْجُرُوهُنَّ فِى ٱلْمَضَاجِعِ وَٱضْرِبُوهُنَّ ۖ فَإِنْ أَطَعْنَكُمْ فَلَا تَبْغُوا۟ عَلَيْهِنَّ سَبِيلًا ۗ إِنَّ ٱللَّهَ كَانَ عَلِيًّۭا كَبِيرًۭا", 't': "«الرِّجال قوَّامون» مسلطون «على النساء» يؤدبونهن ويأخذون على أيديهن «بما فضَّل الله بعضهم على بعض» أي بتفضيله لهم عليهن بالعلم والعقل والولاية وغير ذلك «وبما أنفقوا» عليهن «من أموالهم فالصالحات» منهن «قانتات» مطيعات لأزواجهن «حافظات للغيب» أي لفروجهن وغيرها في غيبة أزواجهن «بما حفظ» لهن «اللهُ» حيث أوصى عليهن الأزواج «والَّتي تخافون نشوزهن» عصيانهن لكم بأن ظهرت أمارته «فعظوهن» فخوِّفوهن الله «واهجروهن في المضاجع» اعتزلوا إلى فراش آخر إن أظهرن النشوز «واضربوهن» ضربا غير مبرح إن لم يرجعن بالهجران «فإن أطعنكم» فيما يراد منهن «فلا تبغوا» تطلبوا «عليهن سبيلا» طريقا إلى ضربهن ظلما «إن الله كان عليا كبيرا» فاحذروه أن يعاقبكم إن ظلمتموهن."},
  {'n': '35', 'v': "وَإِنْ خِفْتُمْ شِقَاقَ بَيْنِهِمَا فَٱبْعَثُوا۟ حَكَمًۭا مِّنْ أَهْلِهِۦ وَحَكَمًۭا مِّنْ أَهْلِهَآ إِن يُرِيدَآ إِصْلَٰحًۭا يُوَفِّقِ ٱللَّهُ بَيْنَهُمَآ ۗ إِنَّ ٱللَّهَ كَانَ عَلِيمًا خَبِيرًۭا", 't': "«وإن خفتم» علمتم «شقاق» خلاف «بينهما» بين الزوجين والإضافة للاتساع أي شقاقا بينهما «فابعثوا» إليهما برضاهما «حكما» رجلا عدلا «من أهله» أقاربه «وحكما من أهلها» ويوكل الزوج حكمه في طلاق وقبول عوض عليه وتوكل هي حكمها في الاختلاع فيجتهدان ويأمران الظالم بالرجوع أو يُفَرِّقَان إن رأياه، قال تعالى: «إن يريدا» أي الحكمان «إصلاحا يوفِّق الله بينهما» بين الزوجين أي يقدرهما على ما هو الطاعة من إصلاح أو فراق «إن الله كان عليما» بكل شيء «خبيرا» بالبواطن كالظواهر."},
  {'n': '36', 'v': "۞ وَٱعْبُدُوا۟ ٱللَّهَ وَلَا تُشْرِكُوا۟ بِهِۦ شَيْـًۭٔا ۖ وَبِٱلْوَٰلِدَيْنِ إِحْسَٰنًۭا وَبِذِى ٱلْقُرْبَىٰ وَٱلْيَتَٰمَىٰ وَٱلْمَسَٰكِينِ وَٱلْجَارِ ذِى ٱلْقُرْبَىٰ وَٱلْجَارِ ٱلْجُنُبِ وَٱلصَّاحِبِ بِٱلْجَنۢبِ وَٱبْنِ ٱلسَّبِيلِ وَمَا مَلَكَتْ أَيْمَٰنُكُمْ ۗ إِنَّ ٱللَّهَ لَا يُحِبُّ مَن كَانَ مُخْتَالًۭا فَخُورًا", 't': "«واعبدوا الله» وحِّدوه «ولا تُشركوا به شيئا و» أحسنوا «بالوالدين إحسانا» برّا ولين جانب «وبذي القربى» القرابة «واليتامى والمساكين والجار ذي القربى» القريب منك في الجوار أو النسب «والجار الجُنُب» البعيد عنك في الجوار أو النسب «والصاحب بالجنب» الرفيق في سفر أو صناعة وقيل الزوجة «وابن السبيل» المنقطع في سفره «وما ملكت أيمانكم» من الأرقاء «إن الله لا يحب من كان مختالا» متكبرا «فخورا» على الناس بما أوتي."},
  {'n': '37', 'v': "ٱلَّذِينَ يَبْخَلُونَ وَيَأْمُرُونَ ٱلنَّاسَ بِٱلْبُخْلِ وَيَكْتُمُونَ مَآ ءَاتَىٰهُمُ ٱللَّهُ مِن فَضْلِهِۦ ۗ وَأَعْتَدْنَا لِلْكَٰفِرِينَ عَذَابًۭا مُّهِينًۭا", 't': "«الذين» مبتدأ «يبخلون» بما يجب عليهم «ويأمرون الناس بالبخل» به «ويكتمون ما آتاهم الله من فضله» من العلم والمال وهم اليهود وخبر المبتدأ لهم وعيد شديد «وأعتدنا للكافرين» بذلك وبغيره «عذابا مهينا» ذا إهانة."},
  {'n': '38', 'v': "وَٱلَّذِينَ يُنفِقُونَ أَمْوَٰلَهُمْ رِئَآءَ ٱلنَّاسِ وَلَا يُؤْمِنُونَ بِٱللَّهِ وَلَا بِٱلْيَوْمِ ٱلْءَاخِرِ ۗ وَمَن يَكُنِ ٱلشَّيْطَٰنُ لَهُۥ قَرِينًۭا فَسَآءَ قَرِينًۭا", 't': "«والذين» عطف على الذين قبله «ينفقون أموالهم رئاء الناس» مرائين لهم «ولا يؤمنون بالله ولا باليوم الآخر» كالمنافقين وأهل مكة «ومن يكن الشيطان له قرينا» صاحبا يعمل بأمره كهؤلاء «فساء» بئس «قرينا» هو."},
  {'n': '39', 'v': "وَمَاذَا عَلَيْهِمْ لَوْ ءَامَنُوا۟ بِٱللَّهِ وَٱلْيَوْمِ ٱلْءَاخِرِ وَأَنفَقُوا۟ مِمَّا رَزَقَهُمُ ٱللَّهُ ۚ وَكَانَ ٱللَّهُ بِهِمْ عَلِيمًا", 't': "«وماذا عليهم لو آمنوا بالله واليوم الآخر وأنفقوا مما رزقهم الله» أي أيّ ضرر عليهم في ذلك والاستفهام للإنكار ولو مصدرية أي لا ضرر فيه وإنما الضرر فيما هم عليه «وكان الله بهم عليما» فيجازيهم بما عملوا."},
  {'n': '40', 'v': "إِنَّ ٱللَّهَ لَا يَظْلِمُ مِثْقَالَ ذَرَّةٍۢ ۖ وَإِن تَكُ حَسَنَةًۭ يُضَٰعِفْهَا وَيُؤْتِ مِن لَّدُنْهُ أَجْرًا عَظِيمًۭا", 't': "«إن الله لا يظلم» أحدا «مثقال» وزن «ذرَّة» أصغر نملة بأن ينقصها من حسناته أو يزيدها في سيئاته «وإن تك» الذرة «حسنة» من مؤمن وفي قراءة بالرفع فكان تامة «يضاعفها» من عشر إلى أكثر من سبعمائة وفي قراءة يضعفها بالتشديد «ويؤت من لدنه» من عنده مع المضاعفة «أجرا عظيما» لا يقدِّره أحد."},
  {'n': '41', 'v': "فَكَيْفَ إِذَا جِئْنَا مِن كُلِّ أُمَّةٍۭ بِشَهِيدٍۢ وَجِئْنَا بِكَ عَلَىٰ هَٰٓؤُلَآءِ شَهِيدًۭا", 't': "«فكيف» حال الكفـار «إذا جئنا من كل أمة بشهيد» يشهد عليها بعملها وهو نبيها «وجئنا بك» يا محمد «على هؤلاء شهيدا»."},
  {'n': '42', 'v': "يَوْمَئِذٍۢ يَوَدُّ ٱلَّذِينَ كَفَرُوا۟ وَعَصَوُا۟ ٱلرَّسُولَ لَوْ تُسَوَّىٰ بِهِمُ ٱلْأَرْضُ وَلَا يَكْتُمُونَ ٱللَّهَ حَدِيثًۭا", 't': "«يومئذ» يوم المجيء «يود الذين كفروا وعصوا الرَّسول لو» أي أن «تُسَوَّى» بالبناء للمفعول والفاعل مع حذف إحدى التاءين في الأصل ومع إدغامها في السين أي تتسوى «بهم الأرض» بأن يكونوا ترابا مثلها لعظم هوله كما في آية أخرى (ويقول الكافر يا ليتنى كنت ترابا) «ولا يكتمون الله حديثا» عما عملوه وفي وقت آخر يكتمونه ويقولون (والله ربِّنا ما كنا مشركين)."},
  {'n': '43', 'v': "يَٰٓأَيُّهَا ٱلَّذِينَ ءَامَنُوا۟ لَا تَقْرَبُوا۟ ٱلصَّلَوٰةَ وَأَنتُمْ سُكَٰرَىٰ حَتَّىٰ تَعْلَمُوا۟ مَا تَقُولُونَ وَلَا جُنُبًا إِلَّا عَابِرِى سَبِيلٍ حَتَّىٰ تَغْتَسِلُوا۟ ۚ وَإِن كُنتُم مَّرْضَىٰٓ أَوْ عَلَىٰ سَفَرٍ أَوْ جَآءَ أَحَدٌۭ مِّنكُم مِّنَ ٱلْغَآئِطِ أَوْ لَٰمَسْتُمُ ٱلنِّسَآءَ فَلَمْ تَجِدُوا۟ مَآءًۭ فَتَيَمَّمُوا۟ صَعِيدًۭا طَيِّبًۭا فَٱمْسَحُوا۟ بِوُجُوهِكُمْ وَأَيْدِيكُمْ ۗ إِنَّ ٱللَّهَ كَانَ عَفُوًّا غَفُورًا", 't': "«يا أيها الذين آمنوا لا تقربوا الصلاة» أي لا تصلوا «وأنتم سكارى» من الشراب لأن سبب نزولها صلاة جماعة في حال سكر «حتى تعلموا ما تقولون» بأن تصْحوا «ولا جُنُبا» بإيلاج أو إنزال ونصبه على الحال وهو يطلق على المفرد وغيره «إلا عابري» مجتازي «سبيل» طريق أي مسافرين «حتى تغتسلوا» فلكم أن تصلوا واستثناء المسافر لأن له حكما آخر سيأتي وقيل المراد النهي عن قربان مواضع الصلاة أي المساجد إلا عبورها من غير مكث «وإن كنتم مرضى» مرضا يضره الماء «أو على سفر» أي مسافرين وأنتم جنب أو محدثون «أو جاء أحد منكم من الغائط» هو المكان المعَدُّ لقضاء الحاجة أي أحدث «أو لامستم النساء» وفي قراءة بلا ألف وكلاهما بمعنى اللمس هو الجَسُّ باليد قاله ابن عمر وعليه الشافعى وألحق به الجس بباقي البشرة وعن ابن عباس هو الجماع «فلم تجدوا ماءً» تتطهرون به للصلاة بعد الطلب والتفتيش وهو راجع إلى ما عدا المرضى «فتيمموا» اقصدوا بعد دخول الوقت «صعيدا طيبا» ترابا طاهرا فاضربوا به ضربتين «فامسحوا بوجوهكم وأيديكم» مع المرفقين منه ومسح يتعدى بنفسه وبالحرف «إن الله كان عفوا غفورا»."},
  {'n': '44', 'v': "أَلَمْ تَرَ إِلَى ٱلَّذِينَ أُوتُوا۟ نَصِيبًۭا مِّنَ ٱلْكِتَٰبِ يَشْتَرُونَ ٱلضَّلَٰلَةَ وَيُرِيدُونَ أَن تَضِلُّوا۟ ٱلسَّبِيلَ", 't': "«ألم تر إلى الذين أوتوا نصيبا» حظا «من الكتاب» وهم اليهود «يشترون الضلالة» بالهدى «ويريدون أن تضلوا السبيل» تخطئوا الطريق الحق لتكونوا مثلهم."},
  {'n': '45', 'v': "وَٱللَّهُ أَعْلَمُ بِأَعْدَآئِكُمْ ۚ وَكَفَىٰ بِٱللَّهِ وَلِيًّۭا وَكَفَىٰ بِٱللَّهِ نَصِيرًۭا", 't': "«والله أعلم بأعدائكم» منكم فيخبركم بهم لتجتنبوهم «وكفى بالله وليا» حافظا لكم منهم «وكفى بالله نصيرا» مانعا لكم من كيدهم."},
  {'n': '46', 'v': "مِّنَ ٱلَّذِينَ هَادُوا۟ يُحَرِّفُونَ ٱلْكَلِمَ عَن مَّوَاضِعِهِۦ وَيَقُولُونَ سَمِعْنَا وَعَصَيْنَا وَٱسْمَعْ غَيْرَ مُسْمَعٍۢ وَرَٰعِنَا لَيًّۢا بِأَلْسِنَتِهِمْ وَطَعْنًۭا فِى ٱلدِّينِ ۚ وَلَوْ أَنَّهُمْ قَالُوا۟ سَمِعْنَا وَأَطَعْنَا وَٱسْمَعْ وَٱنظُرْنَا لَكَانَ خَيْرًۭا لَّهُمْ وَأَقْوَمَ وَلَٰكِن لَّعَنَهُمُ ٱللَّهُ بِكُفْرِهِمْ فَلَا يُؤْمِنُونَ إِلَّا قَلِيلًۭا", 't': "«من الذين هادوا» قوم «يحِّرفون» يغيرون «الكلم» الذي أنزل الله في التوراة من نعت محمد صلى الله عليه وسلم «عن مواضعه» التي وضع عليها «ويقولون» للنبي صلى الله عليه وسلم إذا أمرهم بشيء «سمعنا» قولك «وعصينا» أمرك «واسمع غير مُسمع» حال بمعنى الدعاء أي لا سمعت «و» يقولون له «راعنا» وقد نهى عن خطابه وهي كلمة سب بلغتهم «ليٌا» تحريفا «بألسنتهم وطعنا» قدحا «في الدين» الإسلام «ولو أنهم قالوا سمعنا وأطعنا» بذل وعصينا «واسمع» فقط «وانظرنا» انظر إلينا بدل راعنا «لكان خيرا لهم» مما قالوه «وأقوم» أعدل منه «ولكن لعنهم الله» أبعدهم عن رحمته «بكفرهم فلا يؤمنون إلا قليلا» منهم كعبد الله بن سلام وأصحابه."},
  {'n': '47', 'v': "يَٰٓأَيُّهَا ٱلَّذِينَ أُوتُوا۟ ٱلْكِتَٰبَ ءَامِنُوا۟ بِمَا نَزَّلْنَا مُصَدِّقًۭا لِّمَا مَعَكُم مِّن قَبْلِ أَن نَّطْمِسَ وُجُوهًۭا فَنَرُدَّهَا عَلَىٰٓ أَدْبَارِهَآ أَوْ نَلْعَنَهُمْ كَمَا لَعَنَّآ أَصْحَٰبَ ٱلسَّبْتِ ۚ وَكَانَ أَمْرُ ٱللَّهِ مَفْعُولًا", 't': "«يا أيها الذين أوتوا الكتاب آمنوا بما نزّلنا» من القرآن «مصدّقا لما معكم» من التوراة «من قبل أن نطمس وجوها» نمحو ما فيها من العين والأنف والحاجب «فنردها على أدبارها» فنجعلها كالأقفاء لوحا واحدا «أو نلعنهم» نمسخهم قردة «كما لعنَّا» مسخنا «أصحاب السبت» منهم «وكان أمر الله» قضاؤه «مفعولا» ولما نزلت أسلم عبد الله بن سلام فقيل كان وعيدا بشرط فلما أسلم به ببعضهم رفع وقيل يكون طمس ومسح قبل قيام الساعة."},
  {'n': '48', 'v': "إِنَّ ٱللَّهَ لَا يَغْفِرُ أَن يُشْرَكَ بِهِۦ وَيَغْفِرُ مَا دُونَ ذَٰلِكَ لِمَن يَشَآءُ ۚ وَمَن يُشْرِكْ بِٱللَّهِ فَقَدِ ٱفْتَرَىٰٓ إِثْمًا عَظِيمًا", 't': "«إن الله لا يغفر أن يُشرك» أي الإشراك «به ويغفر ما دون» سوى «ذلك» من الذنوب «لمن يشاء» المغفرة له بأن يدخله الجنة بلا عذاب ومن شاء عذّبه من المؤمنين بذنوبه ثم يدخله الجنة «ومن يشرك بالله فقد افترى إثما» ذنبا «عظيما» كبيرا."},
  {'n': '49', 'v': "أَلَمْ تَرَ إِلَى ٱلَّذِينَ يُزَكُّونَ أَنفُسَهُم ۚ بَلِ ٱللَّهُ يُزَكِّى مَن يَشَآءُ وَلَا يُظْلَمُونَ فَتِيلًا", 't': "«ألم تر إلى الذين يزكُون أنفسهم» وهم اليهود حيث قالوا نحن أبناء الله وأحباؤه أي ليس الأمر بتزكيتهم أنفسهم «بل الله يزكّي» يطهر «من يشاء» بالإيمان «ولا يُظلمون» ينقصون من أعمالهم «فتيلا» قدر قشرة النواة."},
  {'n': '50', 'v': "ٱنظُرْ كَيْفَ يَفْتَرُونَ عَلَى ٱللَّهِ ٱلْكَذِبَ ۖ وَكَفَىٰ بِهِۦٓ إِثْمًۭا مُّبِينًا", 't': "«اُنظر» متعجبا «كيف يفترون على الله الكذب» بذلك «وكفى به إثما مبينا» بيِّنا."},
  {'n': '51', 'v': "أَلَمْ تَرَ إِلَى ٱلَّذِينَ أُوتُوا۟ نَصِيبًۭا مِّنَ ٱلْكِتَٰبِ يُؤْمِنُونَ بِٱلْجِبْتِ وَٱلطَّٰغُوتِ وَيَقُولُونَ لِلَّذِينَ كَفَرُوا۟ هَٰٓؤُلَآءِ أَهْدَىٰ مِنَ ٱلَّذِينَ ءَامَنُوا۟ سَبِيلًا", 't': "ونزل في كعب بن الأشرف ونحوه من علماء اليهود لما قدموا مكة وشاهدوا قتلى بدر وحرضوا المشركين على الأخذ بثأرهم ومحاربة النبي صلى الله عليه وسلم «ألم تر إلى الذين أوتوا نصيبا من الكتاب يؤمنون بالجبت والطاغوت» صنمان لقريش «ويقولون للذين كفروا» أبي سفيان وأصاحبه حين قالوا لهم: نحن أهدى سبيلا ونحن ولاة البيت نسقي الحاج ونقري الضيف ونفك العاني ونفعل... أم محمد وقد خالف دين آبائه وقطع الرحم وفارق الحرم «هؤلاء» أي أنتم «أهدى من الذين آمنوا سبيلا» أقوم طريقا."},
  {'n': '52', 'v': "أُو۟لَٰٓئِكَ ٱلَّذِينَ لَعَنَهُمُ ٱللَّهُ ۖ وَمَن يَلْعَنِ ٱللَّهُ فَلَن تَجِدَ لَهُۥ نَصِيرًا", 't': "«أولئك الذين لعنهم الله ومن يلعنـ» ـه «الله فلن تجد له نصيرا» مانعا من عذابه."},
  {'n': '53', 'v': "أَمْ لَهُمْ نَصِيبٌۭ مِّنَ ٱلْمُلْكِ فَإِذًۭا لَّا يُؤْتُونَ ٱلنَّاسَ نَقِيرًا", 't': "«أم» بل «لهم نصيب من الملك» أي ليس لهم شيء منه ولو كان «فإذا لا يؤتون الناس نقيرا» أي شيئا تافها قدر النقرة في ظهر النواة لفرط بخلهم."},
  {'n': '54', 'v': "أَمْ يَحْسُدُونَ ٱلنَّاسَ عَلَىٰ مَآ ءَاتَىٰهُمُ ٱللَّهُ مِن فَضْلِهِۦ ۖ فَقَدْ ءَاتَيْنَآ ءَالَ إِبْرَٰهِيمَ ٱلْكِتَٰبَ وَٱلْحِكْمَةَ وَءَاتَيْنَٰهُم مُّلْكًا عَظِيمًۭا", 't': "«أم» بل «يحسدون الناس» أي النبي صلى الله عليه وسلم «على ما آتاهم الله من فضله» من النبوة وكثرة النساء، أي يتمنون زواله عنه ويقولون لو كان نبيا لاشتغل عن النساء «فقد آتينا آل إبراهيم» جده كموسى وداود وسليمان «الكتاب والحكمة» والنبوة «وآتيناهم ملكا عظيما» فكان لداود تسع وتسعون امرأة ولسليمان ألف ما بين حُرَّةِ وسرية."},
  {'n': '55', 'v': "فَمِنْهُم مَّنْ ءَامَنَ بِهِۦ وَمِنْهُم مَّن صَدَّ عَنْهُ ۚ وَكَفَىٰ بِجَهَنَّمَ سَعِيرًا", 't': "«فمنهم من آمن به» بمحمد صلى الله عليه وسلم «ومنهم من صدَّ» أعرض «عنه» فلم يؤمن «وكفي بجهنم سعيرا» عذابا لمن لا يؤمن."},
  {'n': '56', 'v': "إِنَّ ٱلَّذِينَ كَفَرُوا۟ بِـَٔايَٰتِنَا سَوْفَ نُصْلِيهِمْ نَارًۭا كُلَّمَا نَضِجَتْ جُلُودُهُم بَدَّلْنَٰهُمْ جُلُودًا غَيْرَهَا لِيَذُوقُوا۟ ٱلْعَذَابَ ۗ إِنَّ ٱللَّهَ كَانَ عَزِيزًا حَكِيمًۭا", 't': "«إن الذين كفروا بآياتنا سوف نصليهم» ندخلهم «نارا» يحترقون فيها «كلما نضجت» احترقت «جلودهم بدَّلناهم جلودا غيرها» بأن تعاد إلى حالها الأول غير محترقة «ليذوقوا العذاب» ليقاسوا شدته «إن الله كان عزيزا» لا يعجزه شيء «حكيما» في خلقه."},
  {'n': '57', 'v': "وَٱلَّذِينَ ءَامَنُوا۟ وَعَمِلُوا۟ ٱلصَّٰلِحَٰتِ سَنُدْخِلُهُمْ جَنَّٰتٍۢ تَجْرِى مِن تَحْتِهَا ٱلْأَنْهَٰرُ خَٰلِدِينَ فِيهَآ أَبَدًۭا ۖ لَّهُمْ فِيهَآ أَزْوَٰجٌۭ مُّطَهَّرَةٌۭ ۖ وَنُدْخِلُهُمْ ظِلًّۭا ظَلِيلًا", 't': "«والذين آمنوا وعملوا الصالحات سندخلهم جنات تجري من تحتها الأنهار خالدين فيها أبدا لهم فيها أزواج مطهرة» من الحيض وكل قذر «وندخلهم ظلا ظليلا» دائما لا تنسخه شمس وهو ظل الجنة,"},
  {'n': '58', 'v': "۞ إِنَّ ٱللَّهَ يَأْمُرُكُمْ أَن تُؤَدُّوا۟ ٱلْأَمَٰنَٰتِ إِلَىٰٓ أَهْلِهَا وَإِذَا حَكَمْتُم بَيْنَ ٱلنَّاسِ أَن تَحْكُمُوا۟ بِٱلْعَدْلِ ۚ إِنَّ ٱللَّهَ نِعِمَّا يَعِظُكُم بِهِۦٓ ۗ إِنَّ ٱللَّهَ كَانَ سَمِيعًۢا بَصِيرًۭا", 't': "«إن الله يأمركم أن تؤدوا الأمانات» أي ما اؤتمن عليه من الحقوق «إلى أهلها» نزلت لما أخذ عليّ رضي الله عنه مفتاح الكعبة من عثمان بن طلحة الحجبي سادنها قسرا لما قدم النبي صلى الله عليه وسلم مكة عام الفتح ومنعه وقال لو علمت أنه رسول الله لم أمنعه فأمر رسول الله صلى الله عليه وسلم برده إليه وقال هاك خالدة تالدة فعجب من ذلك فقرأ له عليُّ الآية، فأسلم وأعطاه عند موته لأخيه شيبة فبقي في ولده والآيةُ وإن وردت على سبب خاص فعمومها معتبر بقرينة الجمع «وإذا حكمتم بين الناس» يأمركم «أن تحكموا بالعدل إن الله نعمَّا» فيه إدغام ميم نعم في ما النكرة الموصولة أي نعم شيئا «يعظكم به» تأدية الأمانة والحكم بالعدل «إن الله كان سميعا» لما يقال «بصيرا» بما يفعل."},
  {'n': '59', 'v': "يَٰٓأَيُّهَا ٱلَّذِينَ ءَامَنُوٓا۟ أَطِيعُوا۟ ٱللَّهَ وَأَطِيعُوا۟ ٱلرَّسُولَ وَأُو۟لِى ٱلْأَمْرِ مِنكُمْ ۖ فَإِن تَنَٰزَعْتُمْ فِى شَىْءٍۢ فَرُدُّوهُ إِلَى ٱللَّهِ وَٱلرَّسُولِ إِن كُنتُمْ تُؤْمِنُونَ بِٱللَّهِ وَٱلْيَوْمِ ٱلْءَاخِرِ ۚ ذَٰلِكَ خَيْرٌۭ وَأَحْسَنُ تَأْوِيلًا", 't': "«يا أيها الذين آمنوا أطيعوا الله وأطيعوا الرسول وأولي» وأصحاب «الأمر» أي الولاة «منكم» إذا أمروكم بطاعة الله ورسوله «فإن تنازعتم» اختلفتم «في شيء فردوه إلى الله» أي إلى كتابه «والرسول» مدة حياته وبعده إلى سنته أي اكشفوا عليه منهما «إن كنتم تؤمنون بالله واليوم الآخر ذلك» أي الرد إليهما «خير» لكم من التنازع والقول بالرأي «وأحسن تأويلاً» مآلاً."},
  {'n': '60', 'v': "أَلَمْ تَرَ إِلَى ٱلَّذِينَ يَزْعُمُونَ أَنَّهُمْ ءَامَنُوا۟ بِمَآ أُنزِلَ إِلَيْكَ وَمَآ أُنزِلَ مِن قَبْلِكَ يُرِيدُونَ أَن يَتَحَاكَمُوٓا۟ إِلَى ٱلطَّٰغُوتِ وَقَدْ أُمِرُوٓا۟ أَن يَكْفُرُوا۟ بِهِۦ وَيُرِيدُ ٱلشَّيْطَٰنُ أَن يُضِلَّهُمْ ضَلَٰلًۢا بَعِيدًۭا", 't': "ونزل لما اختصم يهودي ومنافق فدعا المنافق إلى كعب بن الأشرف ليحكم بينهما ودعا اليهودي إلى النبي صلى الله عليه وسلم فأتياه فقضى لليهودي فلم يرض المنافق وأتيا عمر فذكر اليهودي ذلك فقال للمنافق أكذلك فقال نعم فقتله «ألم ترَ إلى الذين يزعمون أنهم آمنوا بما أنزل إليك وما أُنزل من قبلك يريدون أن يتحاكموا إلى الطاغوت» الكثير الطغيان وهو كعب بن الأشرف «وقد أمروا أن يكفروا به» ولا يوالوه «ويريد الشيطان أن يضلَّهم ضلالا بعيدا» عن الحق."},
  {'n': '61', 'v': "وَإِذَا قِيلَ لَهُمْ تَعَالَوْا۟ إِلَىٰ مَآ أَنزَلَ ٱللَّهُ وَإِلَى ٱلرَّسُولِ رَأَيْتَ ٱلْمُنَٰفِقِينَ يَصُدُّونَ عَنكَ صُدُودًۭا", 't': "«وإذا قيل لهم تعالوا إلى ما أنزل الله» في القرآن من الحكم «وإلى الرسول» ليحكم بينكم «رأيت المنافقين يصدون» يُعرضون «عنك» إلى غيرك «صدودا»."},
  {'n': '62', 'v': "فَكَيْفَ إِذَآ أَصَٰبَتْهُم مُّصِيبَةٌۢ بِمَا قَدَّمَتْ أَيْدِيهِمْ ثُمَّ جَآءُوكَ يَحْلِفُونَ بِٱللَّهِ إِنْ أَرَدْنَآ إِلَّآ إِحْسَٰنًۭا وَتَوْفِيقًا", 't': "«فكيف» يصنعون «إذا أصابتهم مصيبة» عقوبة «بما قدّمت أيديهم» من الكفر والمعاصي أي أيقدرون على الإعراض والفرار منها؟ لا «ثم جَاءُوك» معطوف على يصدون «يحلفون بالله إن» ما «أردنا» بالمحاكمة إلى غيرك «إلا إحسانا» صلحا «وتوفيقا» تأليفا بين الخصمين بالتقريب في الحكم دون الحمل على مر الحق."},
  {'n': '63', 'v': "أُو۟لَٰٓئِكَ ٱلَّذِينَ يَعْلَمُ ٱللَّهُ مَا فِى قُلُوبِهِمْ فَأَعْرِضْ عَنْهُمْ وَعِظْهُمْ وَقُل لَّهُمْ فِىٓ أَنفُسِهِمْ قَوْلًۢا بَلِيغًۭا", 't': "«أولئك الذين يعلم الله ما في قلوبهم» من النفاق وكذبهم في عذرهم «فأعرض عنهم» بالصفح «وعِظهم» خوِّفهم الله «وقل لهم في» شأن «أنفسهم قولا بليغا» مؤثرا فيهم أي أزجرهم ليرجعوا عن كفرهم."},
  {'n': '64', 'v': "وَمَآ أَرْسَلْنَا مِن رَّسُولٍ إِلَّا لِيُطَاعَ بِإِذْنِ ٱللَّهِ ۚ وَلَوْ أَنَّهُمْ إِذ ظَّلَمُوٓا۟ أَنفُسَهُمْ جَآءُوكَ فَٱسْتَغْفَرُوا۟ ٱللَّهَ وَٱسْتَغْفَرَ لَهُمُ ٱلرَّسُولُ لَوَجَدُوا۟ ٱللَّهَ تَوَّابًۭا رَّحِيمًۭا", 't': "«وما أرسلنا من رسول إلا ليُطاع» فيما يأمر به ويحكم «بإذن الله» بأمره لا ليعصى ويخالف «ولو أنهم إذ ظلموا أنفسهم» بتحاكمهم إلى الطاغوت «جاءُوك» تائبين «فاستغفروا الله واستغفر لهم الرسول» فيه التفات عن الخطاب تفخيما لشأنه «لوجدوا الله توَابا» عليهم «رحيما» بهم."},
  {'n': '65', 'v': "فَلَا وَرَبِّكَ لَا يُؤْمِنُونَ حَتَّىٰ يُحَكِّمُوكَ فِيمَا شَجَرَ بَيْنَهُمْ ثُمَّ لَا يَجِدُوا۟ فِىٓ أَنفُسِهِمْ حَرَجًۭا مِّمَّا قَضَيْتَ وَيُسَلِّمُوا۟ تَسْلِيمًۭا", 't': "«فلا وربِّك» لا زائدة «لا يؤمنون حتى يحكِّموك فيما شجر» اختلط «بينهم ثم لا يجدوا في أنفسهم حرجا» ضيقا أو شكٌا «مما قضيت» به «ويسلِّموا» ينقادوا لحكمك «تسليما» من غير معارضة."},
  {'n': '66', 'v': "وَلَوْ أَنَّا كَتَبْنَا عَلَيْهِمْ أَنِ ٱقْتُلُوٓا۟ أَنفُسَكُمْ أَوِ ٱخْرُجُوا۟ مِن دِيَٰرِكُم مَّا فَعَلُوهُ إِلَّا قَلِيلٌۭ مِّنْهُمْ ۖ وَلَوْ أَنَّهُمْ فَعَلُوا۟ مَا يُوعَظُونَ بِهِۦ لَكَانَ خَيْرًۭا لَّهُمْ وَأَشَدَّ تَثْبِيتًۭا", 't': "«ولو أنا كتبنا عليهم أن» مفسرة «اقتلوا أنفسكم أو اخرجوا من دياركم» كما كتبنا على بني إسرائيل «ما فعلوه» أي المكتوب عليهم «إلا قليل» بالرفع على البدل والنصب على الاستثناء «منهم ولو أنهم فعلوا ما يوعَظون به» من طاعة الرسول صلى الله عليه وسلم «لكان خيرا لهم وأشد تثبيتا» تحقيقا لإيمانهم."},
  {'n': '67', 'v': "وَإِذًۭا لَّءَاتَيْنَٰهُم مِّن لَّدُنَّآ أَجْرًا عَظِيمًۭا", 't': "«وإذا» أي لو ثبتوا «لآتيناهم من لدَّنا» من عندنا «أجرا عظيما» هو الجنة."},
  {'n': '68', 'v': "وَلَهَدَيْنَٰهُمْ صِرَٰطًۭا مُّسْتَقِيمًۭا", 't': "«ولهديناهم صراطا مستقيما» قال بعض الصحابة للنبي صلى الله عليه وسلم كيف نراك في الجنة وأنت في الدرجات العلى ونحن أسفل منك فنزل."},
  {'n': '69', 'v': "وَمَن يُطِعِ ٱللَّهَ وَٱلرَّسُولَ فَأُو۟لَٰٓئِكَ مَعَ ٱلَّذِينَ أَنْعَمَ ٱللَّهُ عَلَيْهِم مِّنَ ٱلنَّبِيِّۦنَ وَٱلصِّدِّيقِينَ وَٱلشُّهَدَآءِ وَٱلصَّٰلِحِينَ ۚ وَحَسُنَ أُو۟لَٰٓئِكَ رَفِيقًۭا", 't': "«ومن يطع الله والرسول» فيما أمر به «فأولئك مع الذين أنعم الله عليهم من النبيين والصديقين» أفاضل أصحاب الأنبياء لمبالغتهم في الصدق والتصديق «والشهداء» القتلى في سبيل الله «والصالحين» غير من ذكر «وحسُن أولئك رفيقا» رفقاء في الجنة بأن يستمتع فيها برؤيتهم وزيارتهم والحضور معهم وإن كان مقرهم في الدرجات العالية بالنسبة إلى غيرهم."},
  {'n': '70', 'v': "ذَٰلِكَ ٱلْفَضْلُ مِنَ ٱللَّهِ ۚ وَكَفَىٰ بِٱللَّهِ عَلِيمًۭا", 't': "«ذلك» أي كونهم مع ذكر مبتدأ خبره «الفضل من الله» تفضل به عليهم لا أنهم نالوه بطاعتهم «وكفى بالله عليما» بثواب الآخرة أي فثقوا بما أخبركم به (ولا ينبئك مثل خبير)."},
  {'n': '71', 'v': "يَٰٓأَيُّهَا ٱلَّذِينَ ءَامَنُوا۟ خُذُوا۟ حِذْرَكُمْ فَٱنفِرُوا۟ ثُبَاتٍ أَوِ ٱنفِرُوا۟ جَمِيعًۭا", 't': "«يا أيها الذين آمنوا خذوا حذركم» من عدوكم أي احترزوا منه وتيقظوا له «فانفروا» انهضوا إلى قتاله «ثُبَاتٍ» متفرقين سرية بعد أخرى «أو انفروا جميعا» مجتمعين."},
  {'n': '72', 'v': "وَإِنَّ مِنكُمْ لَمَن لَّيُبَطِّئَنَّ فَإِنْ أَصَٰبَتْكُم مُّصِيبَةٌۭ قَالَ قَدْ أَنْعَمَ ٱللَّهُ عَلَىَّ إِذْ لَمْ أَكُن مَّعَهُمْ شَهِيدًۭا", 't': "«وإنَّ منكم لمن ليبطئنَّ» ليتأخرن عن القتال كعبد الله بن أبيّ المنافق وأصحابه وجعله منهم من حيث الظاهر واللام في الفعل للقسم «فإن أصابتكم مصيبة» كقتل وهزيمة «قال قد أنعم الله علىَّ إذ لم أكن معهم شهيدا» حاضرا فأصاب."},
  {'n': '73', 'v': "وَلَئِنْ أَصَٰبَكُمْ فَضْلٌۭ مِّنَ ٱللَّهِ لَيَقُولَنَّ كَأَن لَّمْ تَكُنۢ بَيْنَكُمْ وَبَيْنَهُۥ مَوَدَّةٌۭ يَٰلَيْتَنِى كُنتُ مَعَهُمْ فَأَفُوزَ فَوْزًا عَظِيمًۭا", 't': "«ولئن» لام قسم «أصابكم فضل من الله» كفتح وغنيمة «لَيَقُولَنَّ» نادما «كأن» مخففة واسمها محذوف أي كأنه «لم يكن» بالياء والتاء «بينكم وبينه مودة» معرفة وصداقة وهذا راجع إلى قوله (قد أنعم الله علىَّ)، اعترض به بين القول ومقوله وهو «يا» للتنبيه «ليتني كنت معهم فأفوزَ فوزا عظيما» آخذ حظا وافرا من الغنيمة قال تعالى."},
  {'n': '74', 'v': "۞ فَلْيُقَٰتِلْ فِى سَبِيلِ ٱللَّهِ ٱلَّذِينَ يَشْرُونَ ٱلْحَيَوٰةَ ٱلدُّنْيَا بِٱلْءَاخِرَةِ ۚ وَمَن يُقَٰتِلْ فِى سَبِيلِ ٱللَّهِ فَيُقْتَلْ أَوْ يَغْلِبْ فَسَوْفَ نُؤْتِيهِ أَجْرًا عَظِيمًۭا", 't': "«فليقاتل في سبيل الله» لإعلاء دينه «الذين يشرون» يبيعون «الحياة الدنيا بالآخرة ومن يقاتل في سبيل الله فيُقتل» يستشهد «أو يَغلب» يظفر بعدوه «فسوف نؤتيه أجرا عظيما» ثوابا جزيلا."},
  {'n': '75', 'v': "وَمَا لَكُمْ لَا تُقَٰتِلُونَ فِى سَبِيلِ ٱللَّهِ وَٱلْمُسْتَضْعَفِينَ مِنَ ٱلرِّجَالِ وَٱلنِّسَآءِ وَٱلْوِلْدَٰنِ ٱلَّذِينَ يَقُولُونَ رَبَّنَآ أَخْرِجْنَا مِنْ هَٰذِهِ ٱلْقَرْيَةِ ٱلظَّالِمِ أَهْلُهَا وَٱجْعَل لَّنَا مِن لَّدُنكَ وَلِيًّۭا وَٱجْعَل لَّنَا مِن لَّدُنكَ نَصِيرًا", 't': "«وما لكم لا تقاتلون» إستفهام توبيخ، أي لا مانع لكم من القتال «في سبيل الله و» في تخليص «المستضعفين من الرجال والنساء والولدان» الذين حبسهم الكفار عن الهجرة وآذوهم، قال ابن عباس رضي الله عنهما: كنت أنا وأمي منهم «الذين يقولون» داعين يا «ربنا أخرجنا من هذه القرية» مكة «الظالم أهلُها» بالكفر «واجعل لنا من لدنك» من عندك «وليّاً» يتولى أمورنا «واجعل لنا من لدنك نصيرا» يمنعنا منهم وقد استجاب الله دعاءهم فيَسَّر لبعضهم الخروج وبقي بعضهم إلى أن فتحت مكة ووَلَّى صلى الله عليه وسلم عتاب بن أسيد فأنصف مظلومهم من ظالمهم."},
  {'n': '76', 'v': "ٱلَّذِينَ ءَامَنُوا۟ يُقَٰتِلُونَ فِى سَبِيلِ ٱللَّهِ ۖ وَٱلَّذِينَ كَفَرُوا۟ يُقَٰتِلُونَ فِى سَبِيلِ ٱلطَّٰغُوتِ فَقَٰتِلُوٓا۟ أَوْلِيَآءَ ٱلشَّيْطَٰنِ ۖ إِنَّ كَيْدَ ٱلشَّيْطَٰنِ كَانَ ضَعِيفًا", 't': "«الذين آمنوا يقاتلون في سبيل الله والذين كفروا يقاتلون في سبيل الطاغوت» الشيطان «فقاتلوا أولياء الشيطان» أنصار دينه تغلبوهم لقوتكم بالله «إن كيد الشيطان» بالمؤمنين «كان ضعيفا» واهيا لا يقاوم كيد الله بالكافرين"},
  {'n': '77', 'v': "أَلَمْ تَرَ إِلَى ٱلَّذِينَ قِيلَ لَهُمْ كُفُّوٓا۟ أَيْدِيَكُمْ وَأَقِيمُوا۟ ٱلصَّلَوٰةَ وَءَاتُوا۟ ٱلزَّكَوٰةَ فَلَمَّا كُتِبَ عَلَيْهِمُ ٱلْقِتَالُ إِذَا فَرِيقٌۭ مِّنْهُمْ يَخْشَوْنَ ٱلنَّاسَ كَخَشْيَةِ ٱللَّهِ أَوْ أَشَدَّ خَشْيَةًۭ ۚ وَقَالُوا۟ رَبَّنَا لِمَ كَتَبْتَ عَلَيْنَا ٱلْقِتَالَ لَوْلَآ أَخَّرْتَنَآ إِلَىٰٓ أَجَلٍۢ قَرِيبٍۢ ۗ قُلْ مَتَٰعُ ٱلدُّنْيَا قَلِيلٌۭ وَٱلْءَاخِرَةُ خَيْرٌۭ لِّمَنِ ٱتَّقَىٰ وَلَا تُظْلَمُونَ فَتِيلًا", 't': "«ألم تر إلى الذين قيل لهم كفُّوا أيديكم» عن قتال الكفار لما طلبوه بمكة لأذى الكفار لهم وهم جماعة من الصحابة «وأقيموا الصلاة وآتوا الزكاة فلما كُتب» فرض «عليهم القتال إذا فريق منهم يخشون» يخافون «الناس» الكفار، أي عذابهم بالقتل «كَخَشْيَتـ» ـهم عذاب «الله أو أشدَّ خشية» من خشيتهم له ونصب أشد على الحال وجواب لما دل عليه إذا وما بعدها أي فاجأتهم الخشية «وقالوا» جزعا من الموت «ربَنا لم كتبت علينا القتال لولا» هلاّ «أخَّرتنا إلى أجل قريب قل» لهم «متاعُ الدنيا» ما يتمتع به فيها أو الاستمتاع بها «قليل» آيل إلى الفناء «والآخرة» أي الجنة «خير لمن اتقى» عقاب الله بترك معصيته «ولا تُظلمون» بالتاء والياء تنقصون من أعمالكم «فتيلا» قدر قشرة النواة فجاهدوا."},
  {'n': '78', 'v': "أَيْنَمَا تَكُونُوا۟ يُدْرِككُّمُ ٱلْمَوْتُ وَلَوْ كُنتُمْ فِى بُرُوجٍۢ مُّشَيَّدَةٍۢ ۗ وَإِن تُصِبْهُمْ حَسَنَةٌۭ يَقُولُوا۟ هَٰذِهِۦ مِنْ عِندِ ٱللَّهِ ۖ وَإِن تُصِبْهُمْ سَيِّئَةٌۭ يَقُولُوا۟ هَٰذِهِۦ مِنْ عِندِكَ ۚ قُلْ كُلٌّۭ مِّنْ عِندِ ٱللَّهِ ۖ فَمَالِ هَٰٓؤُلَآءِ ٱلْقَوْمِ لَا يَكَادُونَ يَفْقَهُونَ حَدِيثًۭا", 't': "«أينما تكونوا يدرككُّم الموت ولو كنتم في بروج» حصون «مشيدة» مرتفعة فلا تخشوا القتال خوف الموت «وإن تصبهم» أي اليهود «حسنة» خصب وسعة «يقولوا هذه من عند الله وإن تصبهم سيئة» جدب وبلاء كما لهم عند قدوم النبي صلى الله عليه وسلم المدينة «يقولوا هذه من عندك» يا محمد أي بشؤمك «قل» لهم «كل» من الحسنة والسيئة «من عند الله» من قبله «فمال هؤلاء القوم لا يكادون يفقهون» أي لا يقاربون أن يفهموا «حديثا» يُلقى إليهم وما استفهام تعجب من فرط جهلهم ونفي مقاربة الفعل أشد من نفيه."},
  {'n': '79', 'v': "مَّآ أَصَابَكَ مِنْ حَسَنَةٍۢ فَمِنَ ٱللَّهِ ۖ وَمَآ أَصَابَكَ مِن سَيِّئَةٍۢ فَمِن نَّفْسِكَ ۚ وَأَرْسَلْنَٰكَ لِلنَّاسِ رَسُولًۭا ۚ وَكَفَىٰ بِٱللَّهِ شَهِيدًۭا", 't': "(ما أصابك) أيها الإنسان (من حسنة) خير (فمن الله) أتتك فضلا منه (وما أصابك من سيئة) بليَّة (فمن نفسك) أتتك حيث ارتكبت ما يستوجبها من الذنوب (وأرسلناك) يا محمد (للناس رسولا) حال مؤكدة (وكفى بالله شهيدا) على رسالتك."},
  {'n': '80', 'v': "مَّن يُطِعِ ٱلرَّسُولَ فَقَدْ أَطَاعَ ٱللَّهَ ۖ وَمَن تَوَلَّىٰ فَمَآ أَرْسَلْنَٰكَ عَلَيْهِمْ حَفِيظًۭا", 't': "«من يطع الرسول فقد أطاع الله ومن تولى أعرض عن طاعتك فلا يهمنَّك «فما أرسلناك عليهم حفيظا» حافظا لأعمالهم بل نذيرا وإلينا أمرهم فنجازيهم وهذا قبل الأمر بالقتال."},
  {'n': '81', 'v': "وَيَقُولُونَ طَاعَةٌۭ فَإِذَا بَرَزُوا۟ مِنْ عِندِكَ بَيَّتَ طَآئِفَةٌۭ مِّنْهُمْ غَيْرَ ٱلَّذِى تَقُولُ ۖ وَٱللَّهُ يَكْتُبُ مَا يُبَيِّتُونَ ۖ فَأَعْرِضْ عَنْهُمْ وَتَوَكَّلْ عَلَى ٱللَّهِ ۚ وَكَفَىٰ بِٱللَّهِ وَكِيلًا", 't': "«ويقولون» أي المنافقون إذا جاءوك أمرنا «طاعةٌ» لك «فإذا برزوا» خرجوا «من عندك بيَّت طائفة منهم» بإدغام التاء في الطاء وتركه أي أضمرت «غير الذي تقول» لك في حضورك من الطاعة أي عصيانك «والله يكتب» يأمر بكتب «ما يبيِّتون» في صحائفهم ليجازوا عليه «فأعرض عنهم» بالصفح «وتوكل على الله» ثق به فانه كافيك «وكفى بالله وكيلا» مفوضا إليه."},
  {'n': '82', 'v': "أَفَلَا يَتَدَبَّرُونَ ٱلْقُرْءَانَ ۚ وَلَوْ كَانَ مِنْ عِندِ غَيْرِ ٱللَّهِ لَوَجَدُوا۟ فِيهِ ٱخْتِلَٰفًۭا كَثِيرًۭا", 't': "«أفلا يتدبرون» يتأملون «القرآن» وما فيه من المعاني البديعة «ولو كان من عند غير الله لوجدوا فيه اختلافا كثيرا» تناقضا في معانيه وتباينا في نظمه."},
  {'n': '83', 'v': "وَإِذَا جَآءَهُمْ أَمْرٌۭ مِّنَ ٱلْأَمْنِ أَوِ ٱلْخَوْفِ أَذَاعُوا۟ بِهِۦ ۖ وَلَوْ رَدُّوهُ إِلَى ٱلرَّسُولِ وَإِلَىٰٓ أُو۟لِى ٱلْأَمْرِ مِنْهُمْ لَعَلِمَهُ ٱلَّذِينَ يَسْتَنۢبِطُونَهُۥ مِنْهُمْ ۗ وَلَوْلَا فَضْلُ ٱللَّهِ عَلَيْكُمْ وَرَحْمَتُهُۥ لَٱتَّبَعْتُمُ ٱلشَّيْطَٰنَ إِلَّا قَلِيلًۭا", 't': "«وإذا جاءهم أمر» عن سرايا النبي صلى الله عليه وسلم ما حصل لهم «من الأمن» بالنصر «أو الخوف» الهزيمة «أذاعوا به» أفشَوه نزل في جماعة من المنافقين أو في ضعفاء المؤمنين كانوا يفعلون ذلك فتضعف قلوب المؤمنين ويتأذى النبي «ولو ردوه» أي الخبر «إلى الرسول وإلى أُولي الأمر منهم» أي الرأي من أكابر الصحابة أي لو سكتوا عنه حتى يخبروا به «لعَلِمَه» هل هو مما ينبغي أن يذاع أو لا «الذين يستنبطونه» يتبعونه ويطلبون علمه وهم المذيعون «منهم» من الرسول وأولي الأمر «ولولا فضل الله عليكم» بالإسلام «ورحمته» لكم بالقرآن «لاتبعتم الشيطان» فيما يأمركم به من الفواحش «إلا قليلا»."},
  {'n': '84', 'v': "فَقَٰتِلْ فِى سَبِيلِ ٱللَّهِ لَا تُكَلَّفُ إِلَّا نَفْسَكَ ۚ وَحَرِّضِ ٱلْمُؤْمِنِينَ ۖ عَسَى ٱللَّهُ أَن يَكُفَّ بَأْسَ ٱلَّذِينَ كَفَرُوا۟ ۚ وَٱللَّهُ أَشَدُّ بَأْسًۭا وَأَشَدُّ تَنكِيلًۭا", 't': "(فقاتل) يا محمد (في سبيل الله لا تكلف إلا نفسك) فلا تهتم بتخلفهم عنك المعنى قاتل ولو وحدك فإنك موعود بالنصر (وحرض المؤمنين) حثهم على القتال ورغبهم فيه (عسى الله أن يكف بأس) حرب (الذين كفروا والله أشد بأسا) منهم (وأشد تنكيلا) تعذبيا منهم فقال رسول الله صلى الله عليه وسلم: \"\" والذي نفسي بيده لأخرجن ولو وحدي \"\" فخرج بسبعين راكبا إلى بدر الصغرى فكف الله بأس الكفار بإلقاء الرعب في قلوبهم ومنع أبي سفيان عن الخروج كما تقدم في آل عمران."},
  {'n': '85', 'v': "مَّن يَشْفَعْ شَفَٰعَةً حَسَنَةًۭ يَكُن لَّهُۥ نَصِيبٌۭ مِّنْهَا ۖ وَمَن يَشْفَعْ شَفَٰعَةًۭ سَيِّئَةًۭ يَكُن لَّهُۥ كِفْلٌۭ مِّنْهَا ۗ وَكَانَ ٱللَّهُ عَلَىٰ كُلِّ شَىْءٍۢ مُّقِيتًۭا", 't': "«من يشفع» بين الناس «شفاعة حسنة» موافقة للشرع «يكن له نصيب» من الأجر «منها» بسببها «ومن يشفع شفاعة سيئة» مخالفة له «يكن له كفل» نصيب من الوزر «منها» بسببها «وكان الله على كل شيء مقيتا» مقتدرا فيجازي كلَّ أحد بما عمل."},
  {'n': '86', 'v': "وَإِذَا حُيِّيتُم بِتَحِيَّةٍۢ فَحَيُّوا۟ بِأَحْسَنَ مِنْهَآ أَوْ رُدُّوهَآ ۗ إِنَّ ٱللَّهَ كَانَ عَلَىٰ كُلِّ شَىْءٍ حَسِيبًا", 't': "«وإذا حُيِّيتم بتحية» كأن قيل لكم سلام عليكم «فحيُّوا» المحيِّي «بأحسن منها» بأن تقولوا له عليك السلام ورحمة الله وبركاته «أوردُّوها» بأن تقولوا له كما قال أي الواجب أحدهما والأول أفضل «إن الله كان على كل شيء حسيبا» محاسبا فيجازي عليه ومنه ردُّ السلام وخصّت السنة الكافر والمبتدع والفاسق والمسلِّم على قاضي الحاجة ومن في الحمام والآكل فلا يجب الرد عليهم بل يكره في غير الأخير ويقال للكافر وعليك."},
  {'n': '87', 'v': "ٱللَّهُ لَآ إِلَٰهَ إِلَّا هُوَ ۚ لَيَجْمَعَنَّكُمْ إِلَىٰ يَوْمِ ٱلْقِيَٰمَةِ لَا رَيْبَ فِيهِ ۗ وَمَنْ أَصْدَقُ مِنَ ٱللَّهِ حَدِيثًۭا", 't': "«الله لا إله إلا هو» والله «ليجمعنكم» من قبوركم «إلى» في «يوم القيامة لا ريب» لا شك «فيه ومن» أي لا أحد «أصدق من الله حديثا» قولا."},
  {'n': '88', 'v': "۞ فَمَا لَكُمْ فِى ٱلْمُنَٰفِقِينَ فِئَتَيْنِ وَٱللَّهُ أَرْكَسَهُم بِمَا كَسَبُوٓا۟ ۚ أَتُرِيدُونَ أَن تَهْدُوا۟ مَنْ أَضَلَّ ٱللَّهُ ۖ وَمَن يُضْلِلِ ٱللَّهُ فَلَن تَجِدَ لَهُۥ سَبِيلًۭا", 't': "ولما رجع ناس من أُحد اختلف الناس فيهم، فقال فريق اقتلهم، وقال فريق: لا، فنزل: «فما لكم» ما شأنكم صرتم «في المنافقين فئتين» «والله أركسهم» ردهم «بما كسبوا» من الكفر والمعاصي «أتريدون أن تهدوا من أضلًـ» ـه «الله» أي تعدوهم من جملة المهتدين، والاستفهام في الموضعين للإنكار «ومن يضللـ» ـه «اللهُ فلن تجد له سبيلا» طريقا إلى الهدى."},
  {'n': '89', 'v': "وَدُّوا۟ لَوْ تَكْفُرُونَ كَمَا كَفَرُوا۟ فَتَكُونُونَ سَوَآءًۭ ۖ فَلَا تَتَّخِذُوا۟ مِنْهُمْ أَوْلِيَآءَ حَتَّىٰ يُهَاجِرُوا۟ فِى سَبِيلِ ٱللَّهِ ۚ فَإِن تَوَلَّوْا۟ فَخُذُوهُمْ وَٱقْتُلُوهُمْ حَيْثُ وَجَدتُّمُوهُمْ ۖ وَلَا تَتَّخِذُوا۟ مِنْهُمْ وَلِيًّۭا وَلَا نَصِيرًا", 't': "«ودُّوا» تمنوا «لو تكفرون كما كفروا فتكونون» أنتم وهم «سواء» في الكفر «فلا تتخذوا منهم أولياء» توالونهم وإن أظهروا الإيمان «حتى يهاجروا في سبيل الله» هجرة صحيحة تحقق إيمانهم «فإن تَوَلَّوْا» وأقاموا على ما هم عليه «فخذوهم» بالأسر «واقتلوهم حيث وجدتموهم ولا تتخذوا منهم وليا» توالونه «ولا نصيرا» تنتصرون به على عدوكم."},
  {'n': '90', 'v': "إِلَّا ٱلَّذِينَ يَصِلُونَ إِلَىٰ قَوْمٍۭ بَيْنَكُمْ وَبَيْنَهُم مِّيثَٰقٌ أَوْ جَآءُوكُمْ حَصِرَتْ صُدُورُهُمْ أَن يُقَٰتِلُوكُمْ أَوْ يُقَٰتِلُوا۟ قَوْمَهُمْ ۚ وَلَوْ شَآءَ ٱللَّهُ لَسَلَّطَهُمْ عَلَيْكُمْ فَلَقَٰتَلُوكُمْ ۚ فَإِنِ ٱعْتَزَلُوكُمْ فَلَمْ يُقَٰتِلُوكُمْ وَأَلْقَوْا۟ إِلَيْكُمُ ٱلسَّلَمَ فَمَا جَعَلَ ٱللَّهُ لَكُمْ عَلَيْهِمْ سَبِيلًۭا", 't': "«إلا الذين يصلون» يلجئون «إلى قوم بينكم وبينهم ميثاق» عهد بالأمان لهم ولمن وصل إليهم كما عاهد النبي صلى الله عليه وسلم هلال بن عويمر الأسلمي «أو» الذين «جاَءُوكم» وقد «حَصِرَتْ» ضاقت «صدورهم» عن «أن يقاتلوكم» مع قومهم «أو يقاتلوا قومهم» معكم أي ممسكين عن قتالكم وقتالهم فلا تتعرضوا إليهم بأخذ ولا قتل وهذا ما بعده منسوخ بآية السيف «ولو شاء الله» تسليطهم عليكم «لسلطهم عليكم» بأن يقّوي قلوبهم «فلقاتلوكم» ولكنه لم يشأه فألقى في قلوبهم الرعب «فإن اعتزلوكم فلم يقاتلوكم وألقوا إليكم السَّلَمَ» الصلح أي انقادوا «فما جعل الله لكم عليهم سبيلا» طريقا بالأخذ والقتال."},
  {'n': '91', 'v': "سَتَجِدُونَ ءَاخَرِينَ يُرِيدُونَ أَن يَأْمَنُوكُمْ وَيَأْمَنُوا۟ قَوْمَهُمْ كُلَّ مَا رُدُّوٓا۟ إِلَى ٱلْفِتْنَةِ أُرْكِسُوا۟ فِيهَا ۚ فَإِن لَّمْ يَعْتَزِلُوكُمْ وَيُلْقُوٓا۟ إِلَيْكُمُ ٱلسَّلَمَ وَيَكُفُّوٓا۟ أَيْدِيَهُمْ فَخُذُوهُمْ وَٱقْتُلُوهُمْ حَيْثُ ثَقِفْتُمُوهُمْ ۚ وَأُو۟لَٰٓئِكُمْ جَعَلْنَا لَكُمْ عَلَيْهِمْ سُلْطَٰنًۭا مُّبِينًۭا", 't': "«ستجدون آخرين يريدون أن يأمنوكم» بإظهار الإيمان عندكم «ويأمنوا قومهم» بالكفر إذا رجعوا إليهم وهم أسد وغطفان «كلما رُدُّوا إلى الفتنة» دعوا إلى الشرك «أركسوا فيها» وقعوا أشد وقوع «فإن لم يعتزلوكم» بترك قتالكم «و» لم «يلقوا إليكم السَّلم و» لم «يكفوا أيديهم» عنكم «فخذوهم» بالأسر «واقتلوهم حيث ثقفتموهم» وجدتموهم «وأولئكم جعلنا لكم عليهم سلطانا مبينا» برهانا بينا ظاهرً على قتلهم وسبيهم لغدرهم."},
  {'n': '92', 'v': "وَمَا كَانَ لِمُؤْمِنٍ أَن يَقْتُلَ مُؤْمِنًا إِلَّا خَطَـًۭٔا ۚ وَمَن قَتَلَ مُؤْمِنًا خَطَـًۭٔا فَتَحْرِيرُ رَقَبَةٍۢ مُّؤْمِنَةٍۢ وَدِيَةٌۭ مُّسَلَّمَةٌ إِلَىٰٓ أَهْلِهِۦٓ إِلَّآ أَن يَصَّدَّقُوا۟ ۚ فَإِن كَانَ مِن قَوْمٍ عَدُوٍّۢ لَّكُمْ وَهُوَ مُؤْمِنٌۭ فَتَحْرِيرُ رَقَبَةٍۢ مُّؤْمِنَةٍۢ ۖ وَإِن كَانَ مِن قَوْمٍۭ بَيْنَكُمْ وَبَيْنَهُم مِّيثَٰقٌۭ فَدِيَةٌۭ مُّسَلَّمَةٌ إِلَىٰٓ أَهْلِهِۦ وَتَحْرِيرُ رَقَبَةٍۢ مُّؤْمِنَةٍۢ ۖ فَمَن لَّمْ يَجِدْ فَصِيَامُ شَهْرَيْنِ مُتَتَابِعَيْنِ تَوْبَةًۭ مِّنَ ٱللَّهِ ۗ وَكَانَ ٱللَّهُ عَلِيمًا حَكِيمًۭا", 't': "«وما كان لمؤمن أن يقتل مؤمنا» أي ما ينبغي أن يصدر منه قتل له «إلا خطئا» مخطئا في قتله من غير قصد «ومن قتل مؤمنا خطأ» بأن قصد رمي غيره كصيد أو شجرة فأصابه أو ضربه بما لا يقتل غالبا «فتحرير» عتق «رقبة» نسمة «مؤمنة» عليه «ودية مسلمة» مؤداة «إلى أهله» أي ورثة المقتول «إلا أن يصَّدقوا» يتصدقوا عليه بها بأن يعفوا عنها وبينت السنة أنها مائة من الإبل عشرون بنت مخاض وكذا بنات لبون وبنو لبون، وحقاق وجذاع وأنها على عاقلة القاتل وهم عصبته إلا الأصل والفرع موزعة عليهم على ثلاث سنين على الغني منهم نصف دينار والمتوسط ربع كل سنة فان لم يفوا فمن بيت المال فإن تعذر فعلى الجاني «فإن كان» المقتول «من قوم عدوٌ» حرب «لكم وهو مؤمن فتحرير رقبة مؤمنة» على قاتله كفارة ولا دية تسلم إلى أهله لحرابتهم «وإن كان» المقتول «من قوم بينكم وبينهم ميثاق» عهد كأهل الذمة «فدية» له «مسلَّمة إلى أهله» وهي ثلث دية المؤمن إن كان يهوديا أو نصرانيا وثلثا عشرها إن كان مجوسيا «وتحرير رقبة مؤمنة» على قاتله «فمن لم يجد» الرقبة بأن فقدها وما يحصلها به «فصيام شهرين متتابعين» عليه كفارة ولم يذكر الله تعالى الانتقال إلى الطعام كالظهار وبه أخذ الشافعي في أصح قوليه «توبة من اللهِ» مصدر منصوب بفعله المقدر «وكان الله عليما» بخلقه «حكيما» فيما دبره لهم."},
  {'n': '93', 'v': "وَمَن يَقْتُلْ مُؤْمِنًۭا مُّتَعَمِّدًۭا فَجَزَآؤُهُۥ جَهَنَّمُ خَٰلِدًۭا فِيهَا وَغَضِبَ ٱللَّهُ عَلَيْهِ وَلَعَنَهُۥ وَأَعَدَّ لَهُۥ عَذَابًا عَظِيمًۭا", 't': "«ومن يقتل مؤمنا متعمِّدا» بأن يقصد قتله بما يقتل غالبا عالما بإيمانه «فجزاؤه جهنم خالدا فيها وغضب الله عليه ولعنه» أبعده من رحمته «وأعد له عذابا عظيما» في النار وهذا مؤوَّل بمن يستحله أو بأن هذا جزاؤه إن جُوزي ولا يدفع في خلف الوعيد لقوله (ويغفر ما دون ذلك لمن يشاء) وعن ابن عباس أنها على ظاهرها وأنها ناسخة لغيرها من آيات المغفرة وبينت آية البقرة أن قاتل العمد يقتل به وأن عليه الدية إن عفي عنه وسبق قدرها وبينت السنة أن بين العمد والخطأ قتلا يسمى شبه العمد وهو أن يقتله بما لا يقتل غالبا فلا قصاص فيه بل دية كالعمد في الصفة والخطأ في التأجيل والحمل وهو والعمد أولى بالكفارة من الخطأ."},
  {'n': '94', 'v': "يَٰٓأَيُّهَا ٱلَّذِينَ ءَامَنُوٓا۟ إِذَا ضَرَبْتُمْ فِى سَبِيلِ ٱللَّهِ فَتَبَيَّنُوا۟ وَلَا تَقُولُوا۟ لِمَنْ أَلْقَىٰٓ إِلَيْكُمُ ٱلسَّلَٰمَ لَسْتَ مُؤْمِنًۭا تَبْتَغُونَ عَرَضَ ٱلْحَيَوٰةِ ٱلدُّنْيَا فَعِندَ ٱللَّهِ مَغَانِمُ كَثِيرَةٌۭ ۚ كَذَٰلِكَ كُنتُم مِّن قَبْلُ فَمَنَّ ٱللَّهُ عَلَيْكُمْ فَتَبَيَّنُوٓا۟ ۚ إِنَّ ٱللَّهَ كَانَ بِمَا تَعْمَلُونَ خَبِيرًۭا", 't': "ونزل لما مر نفر من الصحابة برجل من بني سليم وهو يسوق غنما فسلم عليهم فقالوا ما سلم علينا إلا تقية فقتلوه واستاقوا غنمه «يا أيها الذين آمنوا إذا ضربتم» سافرتم للجهاد «في سبيل الله فتبينوا» وفي قراءة فتثبتوا في الموضعين «ولا تقولوا لمن ألقى إليكم السلام» بألف أو دونها أي التحية أو الانقياد بكلمة الشهادة التي هي أمارة على الإسلام «لست مؤمنا» وإنما قلت هذا تقيه لنفسك ومالك فقتلوه «تبتغون» تطلبون لذلك «عرَضَ الحياة الدنيا» متاعها من الغنيمة «فعند الله مغانم كثيرة» تغنيكم عن قتل مثله لماله «كذلك كنتم من قبل» تعصم دماؤكم وأموالكم بمجرد قولكم الشهادة «فمنَّ الله عليكم» بالاشتهار وبالإيمان والاستقامة «فتبينوا» أن تقتلوا مؤمناً وافعلوا بالداخل في الإسلام كما فُعل بكم «إن الله كان بما تعملون خبيرا» فيجازيكم به."},
  {'n': '95', 'v': "لَّا يَسْتَوِى ٱلْقَٰعِدُونَ مِنَ ٱلْمُؤْمِنِينَ غَيْرُ أُو۟لِى ٱلضَّرَرِ وَٱلْمُجَٰهِدُونَ فِى سَبِيلِ ٱللَّهِ بِأَمْوَٰلِهِمْ وَأَنفُسِهِمْ ۚ فَضَّلَ ٱللَّهُ ٱلْمُجَٰهِدِينَ بِأَمْوَٰلِهِمْ وَأَنفُسِهِمْ عَلَى ٱلْقَٰعِدِينَ دَرَجَةًۭ ۚ وَكُلًّۭا وَعَدَ ٱللَّهُ ٱلْحُسْنَىٰ ۚ وَفَضَّلَ ٱللَّهُ ٱلْمُجَٰهِدِينَ عَلَى ٱلْقَٰعِدِينَ أَجْرًا عَظِيمًۭا", 't': "«لا يستوي القاعدون من المؤمنين» عن الجهاد «غير أولي الضرر» بالرفع صفة والنصب استثناء من زمانة أو عمى ونحوه «والمجاهدون في سبيل الله بأموالهم وأنفسهم فضَّل الله المجاهدين بأموالهم وأنفسهم على القاعدين» لضرر «درجة» فضيلة لاستوائهما في النية وزيادة المجاهدين بالمباشرة «وكلاٌ» من الفريقين «وعد الله الحسنى» الجنة «وفضَّل الله المجاهدين على القاعدين» لغير ضرر «أجرا عظيما» ويبدل منه."},
  {'n': '96', 'v': "دَرَجَٰتٍۢ مِّنْهُ وَمَغْفِرَةًۭ وَرَحْمَةًۭ ۚ وَكَانَ ٱللَّهُ غَفُورًۭا رَّحِيمًا", 't': "«درجات منه» منازل بعضها فوق بعض من الكرامة «ومغفرة ورحمة» منصوبان بفعلهما المقدر «وكان الله غفورا» لأوليائه «رحيما» بأهل طاعته. ونزل في جماعة أسلموا ولم يهاجروا فقتلوا يوم بدر مع الكفار."},
  {'n': '97', 'v': "إِنَّ ٱلَّذِينَ تَوَفَّىٰهُمُ ٱلْمَلَٰٓئِكَةُ ظَالِمِىٓ أَنفُسِهِمْ قَالُوا۟ فِيمَ كُنتُمْ ۖ قَالُوا۟ كُنَّا مُسْتَضْعَفِينَ فِى ٱلْأَرْضِ ۚ قَالُوٓا۟ أَلَمْ تَكُنْ أَرْضُ ٱللَّهِ وَٰسِعَةًۭ فَتُهَاجِرُوا۟ فِيهَا ۚ فَأُو۟لَٰٓئِكَ مَأْوَىٰهُمْ جَهَنَّمُ ۖ وَسَآءَتْ مَصِيرًا", 't': "«إن الذين توفاهم الملائكة ظالمي أنفسهم» بالمقام مع الكفار وترك الهجرة «قالوا» لهم موبخين «فيم كنتم» أي في شيء كنتم في أمر دينكم «قالوا» معتذرين «كنا مستضعَفين» عاجزين عن إقامة الدين «في الأرض» أرض مكة «قالوا» لهم توبيخا «ألم تكن أرض الله واسعة فتهاجروا فيها» من أرض الكفر إلى بلد آخر كما فعل غيركم، قال الله تعالى «فأولئك مأواهم جهنم وساءت مصيرا» هي."},
  {'n': '98', 'v': "إِلَّا ٱلْمُسْتَضْعَفِينَ مِنَ ٱلرِّجَالِ وَٱلنِّسَآءِ وَٱلْوِلْدَٰنِ لَا يَسْتَطِيعُونَ حِيلَةًۭ وَلَا يَهْتَدُونَ سَبِيلًۭا", 't': "«إلا المستضعفين من الرجال والنساء والولدان» الذين «لا يستطيعون حيلة» لا قوة لهم على الهجرة ولا نفقة «ولا يهتدون سبيلا» طريقا إلى أرض الهجرة."},
  {'n': '99', 'v': "فَأُو۟لَٰٓئِكَ عَسَى ٱللَّهُ أَن يَعْفُوَ عَنْهُمْ ۚ وَكَانَ ٱللَّهُ عَفُوًّا غَفُورًۭا", 't': "«فأولئك عسى اللهُ أن يعفو عنهم وكان الله عفوَّا غفورا»."},
  {'n': '100', 'v': "۞ وَمَن يُهَاجِرْ فِى سَبِيلِ ٱللَّهِ يَجِدْ فِى ٱلْأَرْضِ مُرَٰغَمًۭا كَثِيرًۭا وَسَعَةًۭ ۚ وَمَن يَخْرُجْ مِنۢ بَيْتِهِۦ مُهَاجِرًا إِلَى ٱللَّهِ وَرَسُولِهِۦ ثُمَّ يُدْرِكْهُ ٱلْمَوْتُ فَقَدْ وَقَعَ أَجْرُهُۥ عَلَى ٱللَّهِ ۗ وَكَانَ ٱللَّهُ غَفُورًۭا رَّحِيمًۭا", 't': "«ومن يهاجر في سبيل الله يجد في الأرض مراغما» مهاجرا «كثيرا وسعة» في الرزق «ومن يخرج من بيته مهاجرا إلى الله ورسوله ثم يدركه الموت» في الطريق كما وقع لجندع بن ضمرة الليثي «فقد وقع» ثبت «أجره على الله وكان الله غفورا رحيما»."},
  {'n': '101', 'v': "وَإِذَا ضَرَبْتُمْ فِى ٱلْأَرْضِ فَلَيْسَ عَلَيْكُمْ جُنَاحٌ أَن تَقْصُرُوا۟ مِنَ ٱلصَّلَوٰةِ إِنْ خِفْتُمْ أَن يَفْتِنَكُمُ ٱلَّذِينَ كَفَرُوٓا۟ ۚ إِنَّ ٱلْكَٰفِرِينَ كَانُوا۟ لَكُمْ عَدُوًّۭا مُّبِينًۭا", 't': "«وإذا ضربتم» سافرتم «في الأرض فليس عليكم جُناح» في «أن تَقصروا من الصلاة» بأن تردُّوها من أربع إلى اثنتين «إن خفتم أن يفتنكم» أي ينالكم بمكروه «الذين كفروا» بيان للواقع إذ ذاك فلا مفهوم له وبينت السنة أن المراد بالسفر الطويل وهو أربع برد وهي مرحلتان ويؤخذ من قوله تعالى: (فليس عيكم جُناح) أنه رخصة لا واجب وعليه الشافعي «إن الكافرين كانوا لكم عدوا مبينا» بيّني العداوة."},
  {'n': '102', 'v': "وَإِذَا كُنتَ فِيهِمْ فَأَقَمْتَ لَهُمُ ٱلصَّلَوٰةَ فَلْتَقُمْ طَآئِفَةٌۭ مِّنْهُم مَّعَكَ وَلْيَأْخُذُوٓا۟ أَسْلِحَتَهُمْ فَإِذَا سَجَدُوا۟ فَلْيَكُونُوا۟ مِن وَرَآئِكُمْ وَلْتَأْتِ طَآئِفَةٌ أُخْرَىٰ لَمْ يُصَلُّوا۟ فَلْيُصَلُّوا۟ مَعَكَ وَلْيَأْخُذُوا۟ حِذْرَهُمْ وَأَسْلِحَتَهُمْ ۗ وَدَّ ٱلَّذِينَ كَفَرُوا۟ لَوْ تَغْفُلُونَ عَنْ أَسْلِحَتِكُمْ وَأَمْتِعَتِكُمْ فَيَمِيلُونَ عَلَيْكُم مَّيْلَةًۭ وَٰحِدَةًۭ ۚ وَلَا جُنَاحَ عَلَيْكُمْ إِن كَانَ بِكُمْ أَذًۭى مِّن مَّطَرٍ أَوْ كُنتُم مَّرْضَىٰٓ أَن تَضَعُوٓا۟ أَسْلِحَتَكُمْ ۖ وَخُذُوا۟ حِذْرَكُمْ ۗ إِنَّ ٱللَّهَ أَعَدَّ لِلْكَٰفِرِينَ عَذَابًۭا مُّهِينًۭا", 't': "«وإذا كنت» يا محمد حاضرا «فيهم» وأنتم تخافون العدو «فأقمت لهم الصلاة» وهذا جري على عادة القرآن في الخطاب «فلتقم طائفة منهم معك» وتتأخر طائفة «وليأخذوا» أي الطائفة التي قامت معك «أٍسلحتهم» معهم «فإذا سجدوا» أي صلوا «فليكونوا» أي الطائفة الأخرى «من ورائكم» يحرسون إلى أن تقضوا الصلاة وتذهب هذه الطائفة تحرس «ولتأت طائفة أخرى لم يصلوا فليصلوا معك وليأخذوا حذرهم وأسلحتهم» معهم إلى أن تقضوا الصلاة وقد فعل النبي صلى الله عليه وسلم كذلك ببطن نخل رواه الشيخان «ودَّ الذين كفروا لو تغفلون» إذا قمتم إلى الصلاة «عن أسلحتكم وأمتعتكم فيميلون عليكم ميلة واحدة» بأن يحملوا عليكم فيأخذوكم وهذا علة الأمر بأخذ السلاح «ولا جُناح عليكم إن كان بكم أذى من مطر أو كنتم مرضى أن تضعوا أسلحتكم» فلا تحملوها وهذا يقيد إيجاب حملها عند عدم العذر وهو أحد قولين للشافعي والثاني أنه سنة ورجح «وخذوا حذركم» من العدو أي احترزوا منه ما استطعتم «إن الله أعد للكافرين عذابا مهينا» ذا إهانة."},
  {'n': '103', 'v': "فَإِذَا قَضَيْتُمُ ٱلصَّلَوٰةَ فَٱذْكُرُوا۟ ٱللَّهَ قِيَٰمًۭا وَقُعُودًۭا وَعَلَىٰ جُنُوبِكُمْ ۚ فَإِذَا ٱطْمَأْنَنتُمْ فَأَقِيمُوا۟ ٱلصَّلَوٰةَ ۚ إِنَّ ٱلصَّلَوٰةَ كَانَتْ عَلَى ٱلْمُؤْمِنِينَ كِتَٰبًۭا مَّوْقُوتًۭا", 't': "«فإذا قضيتم الصلاة» فرغتم منها «فاذكروا الله» بالتهليل والتسبيح «قياما وقعودا وعلى جنوبكم» مضطجعين أي في كل حال «فإذا اطمأننتم» أمنتم «فأقيموا الصلاة» أدُّوها بحقوقها «إن الصلاة كانت على المؤمنين كتابا» مكتوبا مفروضا «موْقوتا» أي مقدرا وقتها فلا تؤخر عنه، ونزل لما بعث اصلى الله عليه وسلم طائفة في طلب أبي سفيان وأصحابه لما رجعوا من أحد فشكوا الجراحات."},
  {'n': '104', 'v': "وَلَا تَهِنُوا۟ فِى ٱبْتِغَآءِ ٱلْقَوْمِ ۖ إِن تَكُونُوا۟ تَأْلَمُونَ فَإِنَّهُمْ يَأْلَمُونَ كَمَا تَأْلَمُونَ ۖ وَتَرْجُونَ مِنَ ٱللَّهِ مَا لَا يَرْجُونَ ۗ وَكَانَ ٱللَّهُ عَلِيمًا حَكِيمًا", 't': "«ولا تهنوا» تضعفوا «في ابتغاء» طلب «القوم» الكفار لتقاتلوهم «إن تكونوا تألمون» تجدون ألم الجراح «فإنهم يألمون كما تألمون» أي مثلكم ولا يجبنون على قتالكم «وترجون» أنتم «من الله» من النصر والثواب عليه «مالا يرجون» هم فأنتم تزيدون عليهم بذلك فينبغي أن تكونوا أرغب منهم فيه «وكان الله عليما» بكل شيء «حكيما» في صنعه."},
  {'n': '105', 'v': "إِنَّآ أَنزَلْنَآ إِلَيْكَ ٱلْكِتَٰبَ بِٱلْحَقِّ لِتَحْكُمَ بَيْنَ ٱلنَّاسِ بِمَآ أَرَىٰكَ ٱللَّهُ ۚ وَلَا تَكُن لِّلْخَآئِنِينَ خَصِيمًۭا", 't': "وسرق طعمة بن ابيرق درعا وخبأها عند يهودي فوجدت عنده فرماه طعمة بها وحلف أنه ما سرقها فسأل قومه النبي صلى الله عليه وسلم أن يجادل عنه ويبرئه فنزل «إنا أنزلنا إليك الكتاب» القرآن «بالحق» متعلق بأنزل «لتحكم بين الناس بما أراك» أعلمك «الله» فيه «ولا تكن للخائنين» كطعمة «خصيما» مخاصما عنهم."},
  {'n': '106', 'v': "وَٱسْتَغْفِرِ ٱللَّهَ ۖ إِنَّ ٱللَّهَ كَانَ غَفُورًۭا رَّحِيمًۭا", 't': "«واستغفر الله» مما هممت به «إن الله كان غفورا رحيما»."},
  {'n': '107', 'v': "وَلَا تُجَٰدِلْ عَنِ ٱلَّذِينَ يَخْتَانُونَ أَنفُسَهُمْ ۚ إِنَّ ٱللَّهَ لَا يُحِبُّ مَن كَانَ خَوَّانًا أَثِيمًۭا", 't': "«ولا تجادل عن الذين يختانون أنفسهم» يخونونها بالمعاصي لأن وبال خيانتهم عليهم «إن الله لا يحب من كان خوانا» كثير الخيانة «أثيما» أي يعاقبه."},
  {'n': '108', 'v': "يَسْتَخْفُونَ مِنَ ٱلنَّاسِ وَلَا يَسْتَخْفُونَ مِنَ ٱللَّهِ وَهُوَ مَعَهُمْ إِذْ يُبَيِّتُونَ مَا لَا يَرْضَىٰ مِنَ ٱلْقَوْلِ ۚ وَكَانَ ٱللَّهُ بِمَا يَعْمَلُونَ مُحِيطًا", 't': "«يستخفون» أي طعمة وقومه حياءً «من الناس ولا يستخفون من الله وهو معهم» بعلمه «إذ يبيِّتون» يضمرون «ما لا يرضى من القول» من عزمهم على الحلف على نفي السرقة ورمي اليهودي بها «وكان الله بما يعملون محيطا» علما."},
  {'n': '109', 'v': "هَٰٓأَنتُمْ هَٰٓؤُلَآءِ جَٰدَلْتُمْ عَنْهُمْ فِى ٱلْحَيَوٰةِ ٱلدُّنْيَا فَمَن يُجَٰدِلُ ٱللَّهَ عَنْهُمْ يَوْمَ ٱلْقِيَٰمَةِ أَم مَّن يَكُونُ عَلَيْهِمْ وَكِيلًۭا", 't': "«ها أنتم» يا «هؤلاء» خطاب لقوم طعمة «جادلتم» خاصمتم «عنهم» أي عن طعمة وذويه وقرئ عنه «في الحياة الدنيا فمن يجادل الله عنهم يوم القيامة» إذ عذبهم «أم من يكون عليهم وكيلا» يتولى أمرهم ويذبُّ عنهم أي لا أحد يفعل ذلك."},
  {'n': '110', 'v': "وَمَن يَعْمَلْ سُوٓءًا أَوْ يَظْلِمْ نَفْسَهُۥ ثُمَّ يَسْتَغْفِرِ ٱللَّهَ يَجِدِ ٱللَّهَ غَفُورًۭا رَّحِيمًۭا", 't': "«ومن يعمل سوءا» ذنبا يسوء به غيره كرمي طعمة اليهودي «أو يظلم نفسه» يعمل ذنبا قاصرا عليه «ثم يستغفر الله» منه أي يتب «يجد الله غفورا» له «رحيما» به."},
  {'n': '111', 'v': "وَمَن يَكْسِبْ إِثْمًۭا فَإِنَّمَا يَكْسِبُهُۥ عَلَىٰ نَفْسِهِۦ ۚ وَكَانَ ٱللَّهُ عَلِيمًا حَكِيمًۭا", 't': "«ومن يكسب إثما» ذنبا «فإنما يكسبه على نفسه» لأن وباله عليها ولا يضر غيره «وكان الله عليما حكيما» في صنعه."},
  {'n': '112', 'v': "وَمَن يَكْسِبْ خَطِيٓـَٔةً أَوْ إِثْمًۭا ثُمَّ يَرْمِ بِهِۦ بَرِيٓـًۭٔا فَقَدِ ٱحْتَمَلَ بُهْتَٰنًۭا وَإِثْمًۭا مُّبِينًۭا", 't': "«ومن يكسب خطيئة» ذنبا صغيرا «أو إثما» ذنبا كبيرا «ثم يرم به بريئا» منه «فقد احتمل» تحمل «بهتانا» برميه «وإثما مبينا» بينا بكسبه."},
  {'n': '113', 'v': "وَلَوْلَا فَضْلُ ٱللَّهِ عَلَيْكَ وَرَحْمَتُهُۥ لَهَمَّت طَّآئِفَةٌۭ مِّنْهُمْ أَن يُضِلُّوكَ وَمَا يُضِلُّونَ إِلَّآ أَنفُسَهُمْ ۖ وَمَا يَضُرُّونَكَ مِن شَىْءٍۢ ۚ وَأَنزَلَ ٱللَّهُ عَلَيْكَ ٱلْكِتَٰبَ وَٱلْحِكْمَةَ وَعَلَّمَكَ مَا لَمْ تَكُن تَعْلَمُ ۚ وَكَانَ فَضْلُ ٱللَّهِ عَلَيْكَ عَظِيمًۭا", 't': "«ولولا فضل الله عليك» يا محمد «ورحمته» بالعصمة «لهمَّت» أضمرت «طائفة منهم» من قوم طعمة «أن يضلوك» عن القضاء بالحق بتلبيسهم عليك «وما يضلون إلا أنفسهم وما يضرونك من» زائدة «شيء» لأن وبال إضلالهم عليهم «وأنزل الله عليك الكتاب» القرآن «والحكمة» ما فيه من الأحكام «وعلَّمك ما لم تكن تعلم» من الأحكام والغيب «وكان فضل الله عليك» بذلك وغيره «عظيما»."},
  {'n': '114', 'v': "۞ لَّا خَيْرَ فِى كَثِيرٍۢ مِّن نَّجْوَىٰهُمْ إِلَّا مَنْ أَمَرَ بِصَدَقَةٍ أَوْ مَعْرُوفٍ أَوْ إِصْلَٰحٍۭ بَيْنَ ٱلنَّاسِ ۚ وَمَن يَفْعَلْ ذَٰلِكَ ٱبْتِغَآءَ مَرْضَاتِ ٱللَّهِ فَسَوْفَ نُؤْتِيهِ أَجْرًا عَظِيمًۭا", 't': "«لا خير في كثير من نجواهم» أي الناس أي يتناجون فيه ويتحدثون «إلا» نجوى «من أمر بصدقة أو معروف» عمل بر «أو إصلاح بين الناس ومن يفعل ذلك» المذكور «ابتغاء» طلب «مرضات الله» لا غيره من أمور الدنيا «فسوف نؤتيه» بالنون والياء أي الله «أجرا عظيما»."},
  {'n': '115', 'v': "وَمَن يُشَاقِقِ ٱلرَّسُولَ مِنۢ بَعْدِ مَا تَبَيَّنَ لَهُ ٱلْهُدَىٰ وَيَتَّبِعْ غَيْرَ سَبِيلِ ٱلْمُؤْمِنِينَ نُوَلِّهِۦ مَا تَوَلَّىٰ وَنُصْلِهِۦ جَهَنَّمَ ۖ وَسَآءَتْ مَصِيرًا", 't': "«ومن يُشاقق» يخالف «الرسول» فيما جاء به من الحق «من بعد ما تبين له الهدى» ظهر له الحق بالمعجزات «ويتَّبع» طريقا «غير سبيل المؤمنين» أي طريقهم الذي هم عليه من الدين بأن يكفر «نولِّه ما تولَّى» نجعله واليا لما تولاه من الضلال بأن نخلي بينه وبينه في الدنيا «ونصله» ندخله في الآخرة «جهنم» فيحترق فيها «وساءت مصيرا» مرجعا هي."},
  {'n': '116', 'v': "إِنَّ ٱللَّهَ لَا يَغْفِرُ أَن يُشْرَكَ بِهِۦ وَيَغْفِرُ مَا دُونَ ذَٰلِكَ لِمَن يَشَآءُ ۚ وَمَن يُشْرِكْ بِٱللَّهِ فَقَدْ ضَلَّ ضَلَٰلًۢا بَعِيدًا", 't': "«إن الله لا يغفر أن يُشرك به ويغفر مادون ذلك لمن يشاء ومن يشرك بالله فقد ضل ضلالا بعيدا» عن الحق."},
  {'n': '117', 'v': "إِن يَدْعُونَ مِن دُونِهِۦٓ إِلَّآ إِنَٰثًۭا وَإِن يَدْعُونَ إِلَّا شَيْطَٰنًۭا مَّرِيدًۭا", 't': "«إن» ما «يدعون» يعبد المشركون «من دونه» أي الله، أي غيره «إلا إناثا» أصناما مؤنثة كاللات والعزى ومناة «وإن» ما «يدعون» يعبدون بعبادتها «إلا شيطانا مريدا» خارجا عن الطاعة لطاعتهم له فيها وهو إبليس."},
  {'n': '118', 'v': "لَّعَنَهُ ٱللَّهُ ۘ وَقَالَ لَأَتَّخِذَنَّ مِنْ عِبَادِكَ نَصِيبًۭا مَّفْرُوضًۭا", 't': "«لعنه الله» أبعده عن رحمته «وقال» أي الشيطان «لأتخذنَّ» لأجعلن لي «من عبادك نصيبا» حظّا «مفروضا» مقطوعا أدعوهم إلى طاعتي."},
  {'n': '119', 'v': "وَلَأُضِلَّنَّهُمْ وَلَأُمَنِّيَنَّهُمْ وَلَءَامُرَنَّهُمْ فَلَيُبَتِّكُنَّ ءَاذَانَ ٱلْأَنْعَٰمِ وَلَءَامُرَنَّهُمْ فَلَيُغَيِّرُنَّ خَلْقَ ٱللَّهِ ۚ وَمَن يَتَّخِذِ ٱلشَّيْطَٰنَ وَلِيًّۭا مِّن دُونِ ٱللَّهِ فَقَدْ خَسِرَ خُسْرَانًۭا مُّبِينًۭا", 't': "«ولأضلنهم» عن الحق بالوسوسة «ولأمنينهم» ألقي في قلوبهم طول الحياة وأن لا بعث ولا حساب «ولآمرنهم فليبتِّكُنَّ» يقطعن «آذان الأنعام» وقد فعل ذلك بالبحائر «ولآمرنهم فليغيرن خلق الله» دينه بالكفر وإحلال ما حرم الله وتحريم ما أحل «ومن يتخذ الشيطان وليا» يتولاه يطيعه «من دون الله» أي غيره «فقد خسر خسرانا مبينا» بينا لمصيره إلى النار المؤبدة عليه."},
  {'n': '120', 'v': "يَعِدُهُمْ وَيُمَنِّيهِمْ ۖ وَمَا يَعِدُهُمُ ٱلشَّيْطَٰنُ إِلَّا غُرُورًا", 't': "«يعدهم» طول العمر «ويمنيهم» نيل الآمال في الدنيا وألا بعث ولا جزاء «وما يعدهم الشيطان» بذلك «إلا غرورا» باطلا."},
  {'n': '121', 'v': "أُو۟لَٰٓئِكَ مَأْوَىٰهُمْ جَهَنَّمُ وَلَا يَجِدُونَ عَنْهَا مَحِيصًۭا", 't': "«أولئك مأواهم جهنم ولا يجدون عنها محيصا» معدلا."},
  {'n': '122', 'v': "وَٱلَّذِينَ ءَامَنُوا۟ وَعَمِلُوا۟ ٱلصَّٰلِحَٰتِ سَنُدْخِلُهُمْ جَنَّٰتٍۢ تَجْرِى مِن تَحْتِهَا ٱلْأَنْهَٰرُ خَٰلِدِينَ فِيهَآ أَبَدًۭا ۖ وَعْدَ ٱللَّهِ حَقًّۭا ۚ وَمَنْ أَصْدَقُ مِنَ ٱللَّهِ قِيلًۭا", 't': "«والذين آمنوا وعملوا الصالحات سندخلهم جنات تجري من تحتها الأنهار خالدين فيها أبدا وعد الله حقا» أي وعدهم الله ذلك وحقه حقا «ومن» أي لا أحد «أصدق من الله قيلا» أي قولا."},
  {'n': '123', 'v': "لَّيْسَ بِأَمَانِيِّكُمْ وَلَآ أَمَانِىِّ أَهْلِ ٱلْكِتَٰبِ ۗ مَن يَعْمَلْ سُوٓءًۭا يُجْزَ بِهِۦ وَلَا يَجِدْ لَهُۥ مِن دُونِ ٱللَّهِ وَلِيًّۭا وَلَا نَصِيرًۭا", 't': "ونزل لما افتخر المسلمون وأهل الكتاب «ليس» الأمر منوطا «بأمانيكم ولا أماني أهل الكتاب» بل بالعمل الصالح «من يعمل سوءًا يُجز به» إما في الآخرة أو في الدنيا بالبلاء والمحن كما ورد في الحديث «ولا يجد له من دون الله» أي غيره «وليا» يحفظه «ولا نصيرا» يمنعه منه."},
  {'n': '124', 'v': "وَمَن يَعْمَلْ مِنَ ٱلصَّٰلِحَٰتِ مِن ذَكَرٍ أَوْ أُنثَىٰ وَهُوَ مُؤْمِنٌۭ فَأُو۟لَٰٓئِكَ يَدْخُلُونَ ٱلْجَنَّةَ وَلَا يُظْلَمُونَ نَقِيرًۭا", 't': "«ومن يعمل» شيئا «من الصالحات من ذكر أو أنثى وهو مؤمن فأولئك يدخلون» بالبناء للمفعول والفاعل «الجنة ولا يظلمون نقيرا» قدر نقرة النواة."},
  {'n': '125', 'v': "وَمَنْ أَحْسَنُ دِينًۭا مِّمَّنْ أَسْلَمَ وَجْهَهُۥ لِلَّهِ وَهُوَ مُحْسِنٌۭ وَٱتَّبَعَ مِلَّةَ إِبْرَٰهِيمَ حَنِيفًۭا ۗ وَٱتَّخَذَ ٱللَّهُ إِبْرَٰهِيمَ خَلِيلًۭا", 't': "«ومن» أي لا أحد «أحسن دينا ممن أسلم وجهه» أي انقاد وأخلص عمله «لله وهو محسن» موحد «واتبع ملة إبراهيم» الموافقة لملة الإسلام «حنيفا» حال أي مائلا عن الأديان كلها إلى الدين القيم «واتخذ الله إبراهيم خليلا» صفيا خالص المحبة له."},
  {'n': '126', 'v': "وَلِلَّهِ مَا فِى ٱلسَّمَٰوَٰتِ وَمَا فِى ٱلْأَرْضِ ۚ وَكَانَ ٱللَّهُ بِكُلِّ شَىْءٍۢ مُّحِيطًۭا", 't': "«ولله ما في السماوات وما في الأرض» ملكا وخلقا وعبيدا «وكان الله بكل شيء محيطا» علما وقدرة أي لم يزل متصفا بذلك."},
  {'n': '127', 'v': "وَيَسْتَفْتُونَكَ فِى ٱلنِّسَآءِ ۖ قُلِ ٱللَّهُ يُفْتِيكُمْ فِيهِنَّ وَمَا يُتْلَىٰ عَلَيْكُمْ فِى ٱلْكِتَٰبِ فِى يَتَٰمَى ٱلنِّسَآءِ ٱلَّٰتِى لَا تُؤْتُونَهُنَّ مَا كُتِبَ لَهُنَّ وَتَرْغَبُونَ أَن تَنكِحُوهُنَّ وَٱلْمُسْتَضْعَفِينَ مِنَ ٱلْوِلْدَٰنِ وَأَن تَقُومُوا۟ لِلْيَتَٰمَىٰ بِٱلْقِسْطِ ۚ وَمَا تَفْعَلُوا۟ مِنْ خَيْرٍۢ فَإِنَّ ٱللَّهَ كَانَ بِهِۦ عَلِيمًۭا", 't': "«ويستفتونك» يطلبون منك الفتوي «في» شأن «النساء» وميراثهن «قل» لهم «الله يفتيكم فيهن وما يتلى عليكم في الكتاب» القرآن من آية الميراث ويفتيكم أيضا «في يتامى النساء اللاتي لا تؤتونهن ما كتب» فرض «لهن» من الميراث «وترغبون» أيها الأولياء عن «أن تنكحوهن» لدمامتهن وتعضلوهن أن يتزوجن طمعا في ميراثهن أي يفتيكم أن لا تفعلوا ذلك «و» في «المستضعفين» الصغار «ومن الولدان» أن تعطوهم حقوقهم «و» يأمركم «أن تقوموا لليتامى بالقسط» بالعدل في الميراث والمهر «وما تفعلوا من خير فإن الله كان به عليما» فيجازيكم به."},
  {'n': '128', 'v': "وَإِنِ ٱمْرَأَةٌ خَافَتْ مِنۢ بَعْلِهَا نُشُوزًا أَوْ إِعْرَاضًۭا فَلَا جُنَاحَ عَلَيْهِمَآ أَن يُصْلِحَا بَيْنَهُمَا صُلْحًۭا ۚ وَٱلصُّلْحُ خَيْرٌۭ ۗ وَأُحْضِرَتِ ٱلْأَنفُسُ ٱلشُّحَّ ۚ وَإِن تُحْسِنُوا۟ وَتَتَّقُوا۟ فَإِنَّ ٱللَّهَ كَانَ بِمَا تَعْمَلُونَ خَبِيرًۭا", 't': "«وإن امرأة» مرفوع بفعل يفسره «خافت» توقعت «من بعلها» زوجها «نشوزا» ترفعا عليها بترك مضاجتعها والتقصير في نفقتها لبغضها وطموح عينه إلى أجمل منها «أو إعراضا» عنها بوجهه «فلا جُناح عليهما أن يَصَّالَحَا» فيه إدغام التاء في الأصل في الصاد وفي قراءة يصلحا من أصلح «بينهما صلحا» في القسم والنفقة بأن تترك له شيئا طلبا لبقاء الصحبة فإن رضيت بذلك والإ فعلى الزوج أن يوفيها حقها أو يفارقها «والصلح خير» من الفرقة والنشوز والإعراض قال تعالى في بيان ما جبل عليه الإنسان «وأحضرت الأنفس الشح» شدة البخل أي جبلت عليه فكأنها حاضرته لا تغيب عنه، المعنى أن المرأة لا تكاد تسمح بنصيبها من زوجها والرجل لا يكاد يسمح عليها بنفسه إذا أحب غيرها «وإن تحسنوا» عشرة النساء «وتتقوا» الجور عليهن «فإن الله كان بما تعملون خبيرا» فيجازيكم به."},
  {'n': '129', 'v': "وَلَن تَسْتَطِيعُوٓا۟ أَن تَعْدِلُوا۟ بَيْنَ ٱلنِّسَآءِ وَلَوْ حَرَصْتُمْ ۖ فَلَا تَمِيلُوا۟ كُلَّ ٱلْمَيْلِ فَتَذَرُوهَا كَٱلْمُعَلَّقَةِ ۚ وَإِن تُصْلِحُوا۟ وَتَتَّقُوا۟ فَإِنَّ ٱللَّهَ كَانَ غَفُورًۭا رَّحِيمًۭا", 't': "«ولن تستطيعوا أن تعدلوا» تسووا «بين النساء» في المحبة «ولو حرصتم» على ذلك «فلا تميلوا كل الميل» إلى التي تحبونها في القسم والنفقة «فتذروها» أي تتركوا الممال عنها «كالمعلَّقة» التي لا هي أيم ولا هي ذات بعل «وإن تصلحوا» بالعدل بالقسم «وتتقوا» الجور «فإن الله كان غفورا» لما في قلبكم من الميل «رحيما» بكم في ذلك."},
  {'n': '130', 'v': "وَإِن يَتَفَرَّقَا يُغْنِ ٱللَّهُ كُلًّۭا مِّن سَعَتِهِۦ ۚ وَكَانَ ٱللَّهُ وَٰسِعًا حَكِيمًۭا", 't': "«وإن يتفرقا» أي الزوجان بالطلاق «يُغن الله كلا» عن صاحبه «من سعته» أي فضله بأن يرزقها زوجا غيره ويرزقه غيرها «وكان الله واسعا» لخلقه في الفضل «حكيما» فيما دبره لهم."},
  {'n': '131', 'v': "وَلِلَّهِ مَا فِى ٱلسَّمَٰوَٰتِ وَمَا فِى ٱلْأَرْضِ ۗ وَلَقَدْ وَصَّيْنَا ٱلَّذِينَ أُوتُوا۟ ٱلْكِتَٰبَ مِن قَبْلِكُمْ وَإِيَّاكُمْ أَنِ ٱتَّقُوا۟ ٱللَّهَ ۚ وَإِن تَكْفُرُوا۟ فَإِنَّ لِلَّهِ مَا فِى ٱلسَّمَٰوَٰتِ وَمَا فِى ٱلْأَرْضِ ۚ وَكَانَ ٱللَّهُ غَنِيًّا حَمِيدًۭا", 't': "«ولله ما في السماوات وما في الأرض ولقد وصينا الذين أوتوا الكتاب» بمعني الكتب «من قبلكم» أي اليهود والنصارى «وإياكم» يا أهل القرآن «أن» أي بأن «اتقوا الله» خافوا عقابه بأن تطيعوه «و» قلنا لهم ولكم «إن تكفروا» بما وُصيتم به «فإن لله ما في السماوات وما في الأرض» خلقا وملكا وعبيدا فلا يضره كفركم «وكان الله غنيا» عن خلقه وعبادتهم «حميدا» محمودا في صنعه بهم."},
  {'n': '132', 'v': "وَلِلَّهِ مَا فِى ٱلسَّمَٰوَٰتِ وَمَا فِى ٱلْأَرْضِ ۚ وَكَفَىٰ بِٱللَّهِ وَكِيلًا", 't': "«ولله ما في السماوات وما في الأرض» كرره تأكيدا لتقرير موجب التقوى «وكفى بالله وكيلا» شهيدا بأن ما فيهما له."},
  {'n': '133', 'v': "إِن يَشَأْ يُذْهِبْكُمْ أَيُّهَا ٱلنَّاسُ وَيَأْتِ بِـَٔاخَرِينَ ۚ وَكَانَ ٱللَّهُ عَلَىٰ ذَٰلِكَ قَدِيرًۭا", 't': "«إن يشأ يذهبكم» يا «أيها الناس ويأت بآخرين» بدلكم «وكان الله على ذلك قديرا»."},
  {'n': '134', 'v': "مَّن كَانَ يُرِيدُ ثَوَابَ ٱلدُّنْيَا فَعِندَ ٱللَّهِ ثَوَابُ ٱلدُّنْيَا وَٱلْءَاخِرَةِ ۚ وَكَانَ ٱللَّهُ سَمِيعًۢا بَصِيرًۭا", 't': "«من كان يريد» بعمله «ثواب الدنيا» «فعند الله ثواب الدنيا والاخرة» لمن أراده لا عند غيره فلم يطلب أحدكم الأخس وهلا طلب الأعلى بإخلاصه له حيث كان مطلبه لا يوجد إلا عنده «وكان الله سميعا بصيرا»."},
  {'n': '135', 'v': "۞ يَٰٓأَيُّهَا ٱلَّذِينَ ءَامَنُوا۟ كُونُوا۟ قَوَّٰمِينَ بِٱلْقِسْطِ شُهَدَآءَ لِلَّهِ وَلَوْ عَلَىٰٓ أَنفُسِكُمْ أَوِ ٱلْوَٰلِدَيْنِ وَٱلْأَقْرَبِينَ ۚ إِن يَكُنْ غَنِيًّا أَوْ فَقِيرًۭا فَٱللَّهُ أَوْلَىٰ بِهِمَا ۖ فَلَا تَتَّبِعُوا۟ ٱلْهَوَىٰٓ أَن تَعْدِلُوا۟ ۚ وَإِن تَلْوُۥٓا۟ أَوْ تُعْرِضُوا۟ فَإِنَّ ٱللَّهَ كَانَ بِمَا تَعْمَلُونَ خَبِيرًۭا", 't': "«يا أيها الذين آمنوا كونوا قوامين» قائمين «بالقسط» بالعدل «شهداء» بالحق «لله ولو» كانت الشهادة «على أنفسكم» فاشهدوا عليها بأن تقروا بالحق ولا تكتموه «أو» على «الوالدين والأقربين إن يكن» المشهود عليه «غنيّا أو فقيرا فالله أولى بهما» منكم وأعلم بمصالحهما «فلا تتَّبعوا الهوى» في شهادتكم بأن تحابوا الغني لرضاه أو الفقير رحمةّ له لـ «أن» لا «تعدلوا» تميلوا عن الحق «وإن تلووا» تحرفوا الشهادة وفي قراءة بحذف الواو الأولى تخفيفا «أو تعرضوا» عن أدائها «فإن الله كان بما تعملون خبيرا» فيجازيكم به."},
  {'n': '136', 'v': "يَٰٓأَيُّهَا ٱلَّذِينَ ءَامَنُوٓا۟ ءَامِنُوا۟ بِٱللَّهِ وَرَسُولِهِۦ وَٱلْكِتَٰبِ ٱلَّذِى نَزَّلَ عَلَىٰ رَسُولِهِۦ وَٱلْكِتَٰبِ ٱلَّذِىٓ أَنزَلَ مِن قَبْلُ ۚ وَمَن يَكْفُرْ بِٱللَّهِ وَمَلَٰٓئِكَتِهِۦ وَكُتُبِهِۦ وَرُسُلِهِۦ وَٱلْيَوْمِ ٱلْءَاخِرِ فَقَدْ ضَلَّ ضَلَٰلًۢا بَعِيدًا", 't': "«يا أيها الذين آمَنوا آمِنوا» داوموا على الإيمان «بالله ورسوله والكتاب الذي نزَّل على رسوله» محمد صلى الله عليه وسلم وهو القرآن «والكتاب الذي أنزل من قبل» على الرسل بمعنى الكتب، وفي قراءة بالبناء للفاعل في الفعلين «ومن يكفر بالله وملائكته وكتبه ورسله واليوم الآخر فقد ضل ضلالا بعيدا» عن الحق."},
  {'n': '137', 'v': "إِنَّ ٱلَّذِينَ ءَامَنُوا۟ ثُمَّ كَفَرُوا۟ ثُمَّ ءَامَنُوا۟ ثُمَّ كَفَرُوا۟ ثُمَّ ٱزْدَادُوا۟ كُفْرًۭا لَّمْ يَكُنِ ٱللَّهُ لِيَغْفِرَ لَهُمْ وَلَا لِيَهْدِيَهُمْ سَبِيلًۢا", 't': "«إن الذين آمنوا» بموسى وهم اليهود «ثم كفروا» بعبادتهم العجل «ثم آمنوا» بعده «ثم كفروا» بعيسي «ثم ازدادوا كفرا» بمحمد «لم يكن الله ليغفر لهم» ما أقاموا عليه «ولا ليهديهم سبيلا» طريقا إلى الحق."},
  {'n': '138', 'v': "بَشِّرِ ٱلْمُنَٰفِقِينَ بِأَنَّ لَهُمْ عَذَابًا أَلِيمًا", 't': "«بشِّر» أخبر يا محمد «المنافقين بأن لهم عذابا أليماً» مؤلما هو عذاب النار."},
  {'n': '139', 'v': "ٱلَّذِينَ يَتَّخِذُونَ ٱلْكَٰفِرِينَ أَوْلِيَآءَ مِن دُونِ ٱلْمُؤْمِنِينَ ۚ أَيَبْتَغُونَ عِندَهُمُ ٱلْعِزَّةَ فَإِنَّ ٱلْعِزَّةَ لِلَّهِ جَمِيعًۭا", 't': "«الذين» بدل أو نعت للمنافقين «يتخذون الكافرين أولياء من دون المؤمنين» لما يتوهمون فيهم من القوة «أيبتغون» يطلبون «عندهم العزة» استفهام إنكار أي لا يجدونها عندهم «فإن العزة لله جميعا» في الدنيا والآخرة ولا ينالها إلا أولياؤه."},
  {'n': '140', 'v': "وَقَدْ نَزَّلَ عَلَيْكُمْ فِى ٱلْكِتَٰبِ أَنْ إِذَا سَمِعْتُمْ ءَايَٰتِ ٱللَّهِ يُكْفَرُ بِهَا وَيُسْتَهْزَأُ بِهَا فَلَا تَقْعُدُوا۟ مَعَهُمْ حَتَّىٰ يَخُوضُوا۟ فِى حَدِيثٍ غَيْرِهِۦٓ ۚ إِنَّكُمْ إِذًۭا مِّثْلُهُمْ ۗ إِنَّ ٱللَّهَ جَامِعُ ٱلْمُنَٰفِقِينَ وَٱلْكَٰفِرِينَ فِى جَهَنَّمَ جَمِيعًا", 't': "«وقد نزَّل» بالبناء للفاعل والمفعول «عليكم في الكتاب» القرآن في سورة الأنعام «أن» مخففة واسمها محذوف، أي أنه «إذا سمعتم آيات الله» القرآن «يُكفر بها ويستهزأ بها فلا تقعدوا معهم» أي الكافرين والمستهزئين «حتى يخوضوا في حديث غيره إنكم إذا» إن قعدتم معهم «مثلهم» في الإثم «إن الله جامع المنافقين والكافرين في جهنم جميعا» كما اجتمعوا في الدنيا على الكفر والاستهزاء."},
  {'n': '141', 'v': "ٱلَّذِينَ يَتَرَبَّصُونَ بِكُمْ فَإِن كَانَ لَكُمْ فَتْحٌۭ مِّنَ ٱللَّهِ قَالُوٓا۟ أَلَمْ نَكُن مَّعَكُمْ وَإِن كَانَ لِلْكَٰفِرِينَ نَصِيبٌۭ قَالُوٓا۟ أَلَمْ نَسْتَحْوِذْ عَلَيْكُمْ وَنَمْنَعْكُم مِّنَ ٱلْمُؤْمِنِينَ ۚ فَٱللَّهُ يَحْكُمُ بَيْنَكُمْ يَوْمَ ٱلْقِيَٰمَةِ ۗ وَلَن يَجْعَلَ ٱللَّهُ لِلْكَٰفِرِينَ عَلَى ٱلْمُؤْمِنِينَ سَبِيلًا", 't': "«الذين» بدل من الذين قبله «يتربصون» ينتظرون «بكم» الدوائر «فإن كان لكم فتح» ظفر وغنيمة «من الله قالوا» لكم «ألم نكن معكم» في الدين والجهاد فأعطونا من الغنيمة «وإن كان للكافرين نصيب» من الظفر عليكم «قالوا» لهم «ألم نستحوذ» نستول «عليكم» ونقدر على أخذكم وقتلكم فأبقينا عليكم «و» ألم «نمنعكم من المؤمنين» أن يظفروا بكم بتخذيلهم ومراسلتكم بأخبارهم فلنا عليكم المنة قال تعالى: «فالله يحكم بينكم» وبينهم «يوم القيامة» بأن يدخلكم الجنة ويدخلهم النار «ولن يجعل الله للكافرين على المؤمنين سبيلا» طريقا بالإستئصال."},
  {'n': '142', 'v': "إِنَّ ٱلْمُنَٰفِقِينَ يُخَٰدِعُونَ ٱللَّهَ وَهُوَ خَٰدِعُهُمْ وَإِذَا قَامُوٓا۟ إِلَى ٱلصَّلَوٰةِ قَامُوا۟ كُسَالَىٰ يُرَآءُونَ ٱلنَّاسَ وَلَا يَذْكُرُونَ ٱللَّهَ إِلَّا قَلِيلًۭا", 't': "«إن المنافقين يخادعون الله» بإظهارهم خلاف ما أبطنوا من الكفر ليدفعوا عنهم أحكامه الدنيوية «وهو خادعهم» مجازيهم على خداعهم فيفتضحون في الدنيا بإطلاع الله نبيه على ما أبطنوه ويعاقبون في الآخرة «وإذا قاموا إلى الصلاة» مع المؤمنين «قاموا كسالى» متثاقلين «يراءون الناس» بصلاتهم «ولا يذكرون الله» يصلون «إلا قليلا» رياء."},
  {'n': '143', 'v': "مُّذَبْذَبِينَ بَيْنَ ذَٰلِكَ لَآ إِلَىٰ هَٰٓؤُلَآءِ وَلَآ إِلَىٰ هَٰٓؤُلَآءِ ۚ وَمَن يُضْلِلِ ٱللَّهُ فَلَن تَجِدَ لَهُۥ سَبِيلًۭا", 't': "«مذبذبين» مترددين «بين ذلك» الكفر والإيمان «لا» منسوبين «إلى هؤلاء» أي الكفار «ولا إلى هؤلاء» أي المؤمنين «ومن يضللـ» ـه «الله فلن تجد له سبيلا» طريقا إلى الهدى."},
  {'n': '144', 'v': "يَٰٓأَيُّهَا ٱلَّذِينَ ءَامَنُوا۟ لَا تَتَّخِذُوا۟ ٱلْكَٰفِرِينَ أَوْلِيَآءَ مِن دُونِ ٱلْمُؤْمِنِينَ ۚ أَتُرِيدُونَ أَن تَجْعَلُوا۟ لِلَّهِ عَلَيْكُمْ سُلْطَٰنًۭا مُّبِينًا", 't': "«يا أيها الذين آمنوا لا تتخذوا الكافرين أولياء من دون المؤمنين أتريدون أن تجعلوا لله عليكم» بموالاتهم «سلطانا مبينا» برهانا بينا على نفاقكم."},
  {'n': '145', 'v': "إِنَّ ٱلْمُنَٰفِقِينَ فِى ٱلدَّرْكِ ٱلْأَسْفَلِ مِنَ ٱلنَّارِ وَلَن تَجِدَ لَهُمْ نَصِيرًا", 't': "«إن المنافقين في الدرك» المكان «الأسفل من النار» وهو قعرها «ولن تجد لهم نصيرا» مانعا من العذاب."},
  {'n': '146', 'v': "إِلَّا ٱلَّذِينَ تَابُوا۟ وَأَصْلَحُوا۟ وَٱعْتَصَمُوا۟ بِٱللَّهِ وَأَخْلَصُوا۟ دِينَهُمْ لِلَّهِ فَأُو۟لَٰٓئِكَ مَعَ ٱلْمُؤْمِنِينَ ۖ وَسَوْفَ يُؤْتِ ٱللَّهُ ٱلْمُؤْمِنِينَ أَجْرًا عَظِيمًۭا", 't': "«إلا الذين تابوا» من النفاق «وأصلحوا» عملهم «واعتصموا» وثقوا «بالله وأخلصوا دينهم لله» من الرياء «فأولئك مع المؤمنين» فيما يؤتونه «وسوف يؤت الله المؤمنين أجرا عظيما» في الآخرة وهو الجنة."},
  {'n': '147', 'v': "مَّا يَفْعَلُ ٱللَّهُ بِعَذَابِكُمْ إِن شَكَرْتُمْ وَءَامَنتُمْ ۚ وَكَانَ ٱللَّهُ شَاكِرًا عَلِيمًۭا", 't': "«ما يفعل الله بعذابكم إن شكرتم» نعمه «وآمنتم» به والاستفهام بمعنى النفي أي لا يعذبكم «وكان الله شاكرا» لأعمال المؤمنين بالإثابة «عليما» بخلقه."},
  {'n': '148', 'v': "۞ لَّا يُحِبُّ ٱللَّهُ ٱلْجَهْرَ بِٱلسُّوٓءِ مِنَ ٱلْقَوْلِ إِلَّا مَن ظُلِمَ ۚ وَكَانَ ٱللَّهُ سَمِيعًا عَلِيمًا", 't': "«لا يحب الله الجهر بالسوء من القول» من أحد أي يعاقبه عليه «إلا من ظُلم» فلا يؤاخذه بالجهر به بأن يخبر عن ظلم ظالمه ويدعو عليه «وكان الله سميعا» لما يقال «عليما» بما يفعل."},
  {'n': '149', 'v': "إِن تُبْدُوا۟ خَيْرًا أَوْ تُخْفُوهُ أَوْ تَعْفُوا۟ عَن سُوٓءٍۢ فَإِنَّ ٱللَّهَ كَانَ عَفُوًّۭا قَدِيرًا", 't': "«إن تبدوا» تظهروا «خيرا» من أعمال البر «أو تخفوه» تعملوه سرا «أو تعفوا عن سوء» ظلم «فإن الله كان عفّوا قديرا»."},
  {'n': '150', 'v': "إِنَّ ٱلَّذِينَ يَكْفُرُونَ بِٱللَّهِ وَرُسُلِهِۦ وَيُرِيدُونَ أَن يُفَرِّقُوا۟ بَيْنَ ٱللَّهِ وَرُسُلِهِۦ وَيَقُولُونَ نُؤْمِنُ بِبَعْضٍۢ وَنَكْفُرُ بِبَعْضٍۢ وَيُرِيدُونَ أَن يَتَّخِذُوا۟ بَيْنَ ذَٰلِكَ سَبِيلًا", 't': "«إن الذين يكفرون بالله ورسله ويريدون أن يفرقوا بين الله ورسله» بأن يؤمنوا به دونهم «ويقولن نؤمن ببعض» من الرسل «ونكفر ببعض» منهم «ويريدون أن يتخذوا بين ذلك» الكفر والإيمان «سبيلا» طريقا يذهبون إليه."},
  {'n': '151', 'v': "أُو۟لَٰٓئِكَ هُمُ ٱلْكَٰفِرُونَ حَقًّۭا ۚ وَأَعْتَدْنَا لِلْكَٰفِرِينَ عَذَابًۭا مُّهِينًۭا", 't': "«أولئك هم الكافرون حقا» مصدر مؤكد لمضمون الجملة قبله «وأعتدنا للكافرين عذابا مهينا» ذا إهانة وهو عذاب النار."},
  {'n': '152', 'v': "وَٱلَّذِينَ ءَامَنُوا۟ بِٱللَّهِ وَرُسُلِهِۦ وَلَمْ يُفَرِّقُوا۟ بَيْنَ أَحَدٍۢ مِّنْهُمْ أُو۟لَٰٓئِكَ سَوْفَ يُؤْتِيهِمْ أُجُورَهُمْ ۗ وَكَانَ ٱللَّهُ غَفُورًۭا رَّحِيمًۭا", 't': "«والذين آمنوا بالله ورسله» كلهم «ولم يفرقوا بين أحد منهم أولئك سوف يؤتيهم» بالياء والنون «أجورهم» ثواب أعمالهم «وكان الله غفورا» لأوليائه «رحيما» بأهل طاعته."},
  {'n': '153', 'v': "يَسْـَٔلُكَ أَهْلُ ٱلْكِتَٰبِ أَن تُنَزِّلَ عَلَيْهِمْ كِتَٰبًۭا مِّنَ ٱلسَّمَآءِ ۚ فَقَدْ سَأَلُوا۟ مُوسَىٰٓ أَكْبَرَ مِن ذَٰلِكَ فَقَالُوٓا۟ أَرِنَا ٱللَّهَ جَهْرَةًۭ فَأَخَذَتْهُمُ ٱلصَّٰعِقَةُ بِظُلْمِهِمْ ۚ ثُمَّ ٱتَّخَذُوا۟ ٱلْعِجْلَ مِنۢ بَعْدِ مَا جَآءَتْهُمُ ٱلْبَيِّنَٰتُ فَعَفَوْنَا عَن ذَٰلِكَ ۚ وَءَاتَيْنَا مُوسَىٰ سُلْطَٰنًۭا مُّبِينًۭا", 't': "«يسألك» يا محمد «أهل الكتاب» اليهود «أن تنزِّل عليهم كتابا من السماء» جملة كما أنزل على موسى تعنتا فإن استكبرت ذلك «فقد سألوا» أي آباؤهم «موسى أكبر» أعظم «من ذلك فقالوا أرنا الله جهرة» عيانا «فأخذتهم الصاعقة» الموت عقابا لهم «بظلمهم» حيث تعتنوا في السؤال «ثم اتخذوا العجل» إلها «من بعد ما جاءتهم البينات» المعجزات على وحدانية الله «فعفونا عن ذلك» ولم نستأصلهم «وآتينا موسى سلطانا مبينا» تسلطا بينا ظاهرا عليهم حيث أمرهم بقتل أنفسهم توبة فأطاعوه."},
  {'n': '154', 'v': "وَرَفَعْنَا فَوْقَهُمُ ٱلطُّورَ بِمِيثَٰقِهِمْ وَقُلْنَا لَهُمُ ٱدْخُلُوا۟ ٱلْبَابَ سُجَّدًۭا وَقُلْنَا لَهُمْ لَا تَعْدُوا۟ فِى ٱلسَّبْتِ وَأَخَذْنَا مِنْهُم مِّيثَٰقًا غَلِيظًۭا", 't': "«ورفعنا فوقهم الطور» الجبل «بميثاقهم» بسبب أخذ الميثاق عليهم ليخافوا فقبلوه «وقلنا لهم» وهو مُظلِّ عليهم «ادخلوا الباب» باب القرية «سجدا» سجود انحناء «وقلنا لهم لا تعدوا» وفي قراءة بفتح العين وتشديد الدال وفيه إدغام التاء في الأصل في الدال أي لا تعدوا «في السبت» باصطياد الحيتان فيه «وأخذنا منهم ميثاقا غليظا» على ذلك فنقضوه."},
  {'n': '155', 'v': "فَبِمَا نَقْضِهِم مِّيثَٰقَهُمْ وَكُفْرِهِم بِـَٔايَٰتِ ٱللَّهِ وَقَتْلِهِمُ ٱلْأَنۢبِيَآءَ بِغَيْرِ حَقٍّۢ وَقَوْلِهِمْ قُلُوبُنَا غُلْفٌۢ ۚ بَلْ طَبَعَ ٱللَّهُ عَلَيْهَا بِكُفْرِهِمْ فَلَا يُؤْمِنُونَ إِلَّا قَلِيلًۭا", 't': "«فبما نقضهم» ما زائدة والباء للسببية متعلقة بمحذوف، أي لعناهم بسبب نقضهم «ميثاقهم وكفرهم بآيات الله وقتلهم الأنبياء بغير حق وقولهم» للنبي صلى الله عليه وسلم «قلوبنا غلف» لا تعي كلامك «بل طبع» ختم «الله عليها بكفرهم» فلا تعي وعظا «فلا يؤمنون إلا قليلا» منهم كعبد الله بن سلام وأصحابه."},
  {'n': '156', 'v': "وَبِكُفْرِهِمْ وَقَوْلِهِمْ عَلَىٰ مَرْيَمَ بُهْتَٰنًا عَظِيمًۭا", 't': "«وبكفرهم» ثانيا بعيسى وكرر الباء للفصل بينه وبين ما عطف عليه «وقولهم على مريم بهتانا عظيما» حيث رموها بالزنا."},
  {'n': '157', 'v': "وَقَوْلِهِمْ إِنَّا قَتَلْنَا ٱلْمَسِيحَ عِيسَى ٱبْنَ مَرْيَمَ رَسُولَ ٱللَّهِ وَمَا قَتَلُوهُ وَمَا صَلَبُوهُ وَلَٰكِن شُبِّهَ لَهُمْ ۚ وَإِنَّ ٱلَّذِينَ ٱخْتَلَفُوا۟ فِيهِ لَفِى شَكٍّۢ مِّنْهُ ۚ مَا لَهُم بِهِۦ مِنْ عِلْمٍ إِلَّا ٱتِّبَاعَ ٱلظَّنِّ ۚ وَمَا قَتَلُوهُ يَقِينًۢا", 't': "«وقولهم» مفتخرين «إنا قتلنا المسيح عيسى بن مريم رسول الله» في زعمهم، أي بمجموع ذلك عذبناهم قال تعالى تكذيبا لهم في قتله «وما قتلوه وما صلبوه ولكن شبه لهم» المقتول والمصلوب وهو صاحبهم بعيسى، أي ألقى الله عليه شبهه فظنوه إياه «وإن الذين اختلفوا فيه» أي في عيسى «لفي شك منه» من قتله حيث قال بعضهم لما رأوا المقتول الوجه وجه عيسى والجسد ليس بجسده فليس به، وقال آخرون: بل هو هو «ما لهم به» بقتله «من علم إلا اتباع الظن» استثناء منقطع، أي لكن يتبعون فيه الظن الذي تخيلوه «وما قتلوه يقينا» حال مؤكدة تنفي القتل."},
  {'n': '158', 'v': "بَل رَّفَعَهُ ٱللَّهُ إِلَيْهِ ۚ وَكَانَ ٱللَّهُ عَزِيزًا حَكِيمًۭا", 't': "«بل رفعه الله إليه وكان الله عزيزا» في ملكه «حكيما» في صنعه."},
  {'n': '159', 'v': "وَإِن مِّنْ أَهْلِ ٱلْكِتَٰبِ إِلَّا لَيُؤْمِنَنَّ بِهِۦ قَبْلَ مَوْتِهِۦ ۖ وَيَوْمَ ٱلْقِيَٰمَةِ يَكُونُ عَلَيْهِمْ شَهِيدًۭا", 't': "«وإنْ» ما «من أهل الكتاب» أحَد «إلا ليؤمنن به» بعيسى «قبل موته» أي الكتابي حين يعاين ملائكة الموت فلا ينفعه إيمانه أو قبل موت عيسى لما ينزل قرب الساعة كما ورد في حديث «ويوم القيامة يكون» عيسى «شهيدا» بما فعلوه لما بعث إليهم."},
  {'n': '160', 'v': "فَبِظُلْمٍۢ مِّنَ ٱلَّذِينَ هَادُوا۟ حَرَّمْنَا عَلَيْهِمْ طَيِّبَٰتٍ أُحِلَّتْ لَهُمْ وَبِصَدِّهِمْ عَن سَبِيلِ ٱللَّهِ كَثِيرًۭا", 't': "«فبظلم» أي فبسبب ظلم «من الذين هادوا» هم اليهود «حرمنا عليهم طيبات أحلت لهم» من التي في قوله تعالى: (حرمنا كل ذي ظفر) الآية «وبصدهم» الناس «عن سبيل الله» دينه صدا «كثيرا»."},
  {'n': '161', 'v': "وَأَخْذِهِمُ ٱلرِّبَوٰا۟ وَقَدْ نُهُوا۟ عَنْهُ وَأَكْلِهِمْ أَمْوَٰلَ ٱلنَّاسِ بِٱلْبَٰطِلِ ۚ وَأَعْتَدْنَا لِلْكَٰفِرِينَ مِنْهُمْ عَذَابًا أَلِيمًۭا", 't': "«وأخذهم الربا وقد نُهوا عنه» في التوراة «وأكلهم أموال الناس بالباطل» بالرشا في الحكم «وأعتدنا للكافرين منهم عذابا أليما» مؤلما."},
  {'n': '162', 'v': "لَّٰكِنِ ٱلرَّٰسِخُونَ فِى ٱلْعِلْمِ مِنْهُمْ وَٱلْمُؤْمِنُونَ يُؤْمِنُونَ بِمَآ أُنزِلَ إِلَيْكَ وَمَآ أُنزِلَ مِن قَبْلِكَ ۚ وَٱلْمُقِيمِينَ ٱلصَّلَوٰةَ ۚ وَٱلْمُؤْتُونَ ٱلزَّكَوٰةَ وَٱلْمُؤْمِنُونَ بِٱللَّهِ وَٱلْيَوْمِ ٱلْءَاخِرِ أُو۟لَٰٓئِكَ سَنُؤْتِيهِمْ أَجْرًا عَظِيمًا", 't': "«لكن الراسخون» الثابتون «في العلم منهم» كعبد الله بن سلام «والمؤمنون» المهاجرون والأنصار «يؤمنون بما أنزل إليك وما انزل من قبلك» من الكتب «والمقيمين الصلاة» نصب على المدح وقرئ بالرفع «والمؤتون الزكاة والمؤمنون بالله واليوم الآخر أولئك سنؤتيهم» بالنون والياء «أجرا عظيما» هو الجنة."},
  {'n': '163', 'v': "۞ إِنَّآ أَوْحَيْنَآ إِلَيْكَ كَمَآ أَوْحَيْنَآ إِلَىٰ نُوحٍۢ وَٱلنَّبِيِّۦنَ مِنۢ بَعْدِهِۦ ۚ وَأَوْحَيْنَآ إِلَىٰٓ إِبْرَٰهِيمَ وَإِسْمَٰعِيلَ وَإِسْحَٰقَ وَيَعْقُوبَ وَٱلْأَسْبَاطِ وَعِيسَىٰ وَأَيُّوبَ وَيُونُسَ وَهَٰرُونَ وَسُلَيْمَٰنَ ۚ وَءَاتَيْنَا دَاوُۥدَ زَبُورًۭا", 't': "«إنا أوحينا إليك كما أوحينا إلى نوح والنبيين من بعده و» كما «أوحينا إلى إبراهيم وإسماعيل وإسحاق» ابنيه «ويعقوب» ابن إسحاق «والأسباط» أولاده «وعيسى وأيوب ويونس وهارون وسليمان وآتينا» أباه «داود زَبورا» بالفتح اسم للكتاب المؤتى والضم مصدر بمعنى مزبورا أي مكتوبا."},
  {'n': '164', 'v': "وَرُسُلًۭا قَدْ قَصَصْنَٰهُمْ عَلَيْكَ مِن قَبْلُ وَرُسُلًۭا لَّمْ نَقْصُصْهُمْ عَلَيْكَ ۚ وَكَلَّمَ ٱللَّهُ مُوسَىٰ تَكْلِيمًۭا", 't': "«و» أرسلنا «رسلا قد قصصناهم عليك من قبل ورسلا لم نقصصهم عليك» روي أنه تعالى بعث ثمانية آلاف نبي أربعة آلاف من إسرائيل وأربعة آلاف من سائر الناس قاله الشيخ في سورة غافر «وكلَّم اللهُ موسى» بلا واسطة «تكليما»."},
  {'n': '165', 'v': "رُّسُلًۭا مُّبَشِّرِينَ وَمُنذِرِينَ لِئَلَّا يَكُونَ لِلنَّاسِ عَلَى ٱللَّهِ حُجَّةٌۢ بَعْدَ ٱلرُّسُلِ ۚ وَكَانَ ٱللَّهُ عَزِيزًا حَكِيمًۭا", 't': "«رسلا» بدل من رسلا قبله «مبشرين» بالثواب من آمن «ومنذرين» بالعقاب من كفر أرسلناهم «لئلا يكون للناس على الله حجة» تقال «بعد» إرسال «الرسل» إليهم فيقولوا: ربنا لولا أرسلت إلينا رسولا فنتبع آياتك ونكون من المؤمنين فبعثناهم لقطع عذرهم «وكان الله عزيزا» في ملكْه «حكيما» في صنعه."},
  {'n': '166', 'v': "لَّٰكِنِ ٱللَّهُ يَشْهَدُ بِمَآ أَنزَلَ إِلَيْكَ ۖ أَنزَلَهُۥ بِعِلْمِهِۦ ۖ وَٱلْمَلَٰٓئِكَةُ يَشْهَدُونَ ۚ وَكَفَىٰ بِٱللَّهِ شَهِيدًا", 't': "ونزل لما سئل اليهود عن نبوته صلى الله عليه وسلم فأنكروه «لكن الله يشهد» يبين نبوتك «بما أنزل إليك» من القرآن المعجز «أنزله» ملتبسا «بعلمه» أي عالما به أو فيه علمه «والملائكة يشهدون» لك أيضا «وكفى بالله شهيدا» على ذلك."},
  {'n': '167', 'v': "إِنَّ ٱلَّذِينَ كَفَرُوا۟ وَصَدُّوا۟ عَن سَبِيلِ ٱللَّهِ قَدْ ضَلُّوا۟ ضَلَٰلًۢا بَعِيدًا", 't': "«إن الذين كفروا» بالله «وصدوا» الناس «عن سبيل الله» دين الإسلام بكتمهم نعت محمد صلى الله عليه وسلم وهم اليهود «قد ضلوا ضلالا بعيدا» عن الحق."},
  {'n': '168', 'v': "إِنَّ ٱلَّذِينَ كَفَرُوا۟ وَظَلَمُوا۟ لَمْ يَكُنِ ٱللَّهُ لِيَغْفِرَ لَهُمْ وَلَا لِيَهْدِيَهُمْ طَرِيقًا", 't': "«إن الذين كفروا» بالله «وظلموا» نبيه بكتمان نعته «لم يكن الله ليغفر لهم ولا ليهديهم طريقا» من الطرق."},
  {'n': '169', 'v': "إِلَّا طَرِيقَ جَهَنَّمَ خَٰلِدِينَ فِيهَآ أَبَدًۭا ۚ وَكَانَ ذَٰلِكَ عَلَى ٱللَّهِ يَسِيرًۭا", 't': "«إلا طريق جهنم» أي الطريق المؤدي إليها «خالدين» مقدرين الخلود «فيها» إذا دخلوها «أبدا وكان ذلك على الله يسيرا» هينا."},
  {'n': '170', 'v': "يَٰٓأَيُّهَا ٱلنَّاسُ قَدْ جَآءَكُمُ ٱلرَّسُولُ بِٱلْحَقِّ مِن رَّبِّكُمْ فَـَٔامِنُوا۟ خَيْرًۭا لَّكُمْ ۚ وَإِن تَكْفُرُوا۟ فَإِنَّ لِلَّهِ مَا فِى ٱلسَّمَٰوَٰتِ وَٱلْأَرْضِ ۚ وَكَانَ ٱللَّهُ عَلِيمًا حَكِيمًۭا", 't': "«يا أيها الناس» أي أهل مكة «قد جاءكم الرسول» محمد صلى الله عليه وسلم «بالحق من ربكم فآمنوا» به واقصدوا «خيرا لكم» مما أنتم فيه «وإن تكفروا» به «فإن لله ما في السماوات والأرض» ملكا وخلقا وعبيدا فلا يضره كفركم «وكان الله عليما» بخلقه «حكيما» في صنعه بهم."},
