  {'n': '15', 'v': "قَالَ إِنَّكَ مِنَ ٱلْمُنظَرِينَ", 't': "«قال إنك من المنظرين» وفي آية أخرى «إلى يوم الوقت المعلوم» أي يوم النفخة الأولى."},
  {'n': '16', 'v': "قَالَ فَبِمَآ أَغْوَيْتَنِى لَأَقْعُدَنَّ لَهُمْ صِرَٰطَكَ ٱلْمُسْتَقِيمَ", 't': "«قال فبما أغويتني» أي بإغوائك لي والياء للقسم وجوابه «لأقعدن لهم» أي لبني آدم «صراطك المستقيم» أي على الطريق الموصل إليك."},
  {'n': '17', 'v': "ثُمَّ لَءَاتِيَنَّهُم مِّنۢ بَيْنِ أَيْدِيهِمْ وَمِنْ خَلْفِهِمْ وَعَنْ أَيْمَٰنِهِمْ وَعَن شَمَآئِلِهِمْ ۖ وَلَا تَجِدُ أَكْثَرَهُمْ شَٰكِرِينَ", 't': "«ثم لآتينهم من بين أيديهم ومن خلفهم وعن أيمانهم وعن شمائلهم» أي من كل جهة فأمنعهم عن سلوكه قال ابن عباس ولا يستطيع أن يأتي من فوقهم لئلا يحول بين العبد وبين رحمة الله تعالى «ولا تجد أكثرهم شاكرين» مؤمنين."},
  {'n': '18', 'v': "قَالَ ٱخْرُجْ مِنْهَا مَذْءُومًۭا مَّدْحُورًۭا ۖ لَّمَن تَبِعَكَ مِنْهُمْ لَأَمْلَأَنَّ جَهَنَّمَ مِنكُمْ أَجْمَعِينَ", 't': "«قال اخرج منها مذءوما» بالهمزة معيبا أو ممقوتا «مدحورا» مبعدا عن الرحمة «لمن تبعك منهم» من الناس واللام للابتداء أو موطئة للقسم وهو «لأملأنَّ جهنم منكم أجمعين» أي منك بذريتك ومن الناس وفيه تغليب الحاضر على الغائب وفي الجملة معنى جزاء من الشرطية أي من تبعك أعذبه."},
  {'n': '19', 'v': "وَيَٰٓـَٔادَمُ ٱسْكُنْ أَنتَ وَزَوْجُكَ ٱلْجَنَّةَ فَكُلَا مِنْ حَيْثُ شِئْتُمَا وَلَا تَقْرَبَا هَٰذِهِ ٱلشَّجَرَةَ فَتَكُونَا مِنَ ٱلظَّٰلِمِينَ", 't': "«و» قال «يا آدم اسكن أنت» تأكيد للضمير في اسكن ليعطف عليه «وزوجك» حواء بالمد «الجنة فكلا من حيث شئتما ولا تقربا هذه الشجرة» بالأكل منها وهي الحنطة «فتكونا من الظالمين»."},
  {'n': '20', 'v': "فَوَسْوَسَ لَهُمَا ٱلشَّيْطَٰنُ لِيُبْدِىَ لَهُمَا مَا وُۥرِىَ عَنْهُمَا مِن سَوْءَٰتِهِمَا وَقَالَ مَا نَهَىٰكُمَا رَبُّكُمَا عَنْ هَٰذِهِ ٱلشَّجَرَةِ إِلَّآ أَن تَكُونَا مَلَكَيْنِ أَوْ تَكُونَا مِنَ ٱلْخَٰلِدِينَ", 't': "«فوسوس لهما الشيطان» إبليس «ليبدي» يظهر «لهما ما ووري» فوعل من الموارة «عنهما من سوآتهما وقال ما نهاكما ربُّكما عن هذه الشجرة إلا» كراهة «أن تكونا مَلَكَيْنِ» وقرئ بكسر اللام «أو تكونا من الخالدين» أي وذلك لازم عن الأكل منها في آية أخرى (هل أدلك على شجرة الخلد ومُلك لا يبلى)."},
  {'n': '21', 'v': "وَقَاسَمَهُمَآ إِنِّى لَكُمَا لَمِنَ ٱلنَّٰصِحِينَ", 't': "«وقاسمهما» أي أقسم لهما بالله «إني لكما لمن الناصحين» في ذلك."},
  {'n': '22', 'v': "فَدَلَّىٰهُمَا بِغُرُورٍۢ ۚ فَلَمَّا ذَاقَا ٱلشَّجَرَةَ بَدَتْ لَهُمَا سَوْءَٰتُهُمَا وَطَفِقَا يَخْصِفَانِ عَلَيْهِمَا مِن وَرَقِ ٱلْجَنَّةِ ۖ وَنَادَىٰهُمَا رَبُّهُمَآ أَلَمْ أَنْهَكُمَا عَن تِلْكُمَا ٱلشَّجَرَةِ وَأَقُل لَّكُمَآ إِنَّ ٱلشَّيْطَٰنَ لَكُمَا عَدُوٌّۭ مُّبِينٌۭ", 't': "«فدلاهما» حطهما عن منزلتهما «بغرور» منه «فلما ذاقا الشجرة» أي أكلا منها «بدت لهما سوآتهما» أي ظهر لكل منهما قبله وقبل الآخر ودبره وسمي كل منها سوأة لأن انكشافه يسوء صاحبه «وطفقا يخصفان» أخذ يلزقان «عليهما من ورق الجنة» ليستترا به «وناداهما ربهما ألم أنهكما عن تلكما الشجرة وأقل لكما إن الشيطان لكما عدو مبين» بيِّن العداوة والاستفهام للتقرير."},
  {'n': '23', 'v': "قَالَا رَبَّنَا ظَلَمْنَآ أَنفُسَنَا وَإِن لَّمْ تَغْفِرْ لَنَا وَتَرْحَمْنَا لَنَكُونَنَّ مِنَ ٱلْخَٰسِرِينَ", 't': "«قالا ربَّنا ظلمنا أنفسنا» بمعصيتنا «وإن لم تغفر لنا وترحمنا لنكونن من الخاسرين»."},
  {'n': '24', 'v': "قَالَ ٱهْبِطُوا۟ بَعْضُكُمْ لِبَعْضٍ عَدُوٌّۭ ۖ وَلَكُمْ فِى ٱلْأَرْضِ مُسْتَقَرٌّۭ وَمَتَٰعٌ إِلَىٰ حِينٍۢ", 't': "«قال اهبطوا» أي آدم وحواء بما اشتملتما عليه من ذريتكما «بعضكم» بعض الذرية «لبعض عدوٌ» من ظلم بعضهم بعضا «ولكم في الأرض» مستقر» أي مكان استقرار «ومتاع» تمتع «إلى حين» تنقضي فيه آجالكم."},
  {'n': '25', 'v': "قَالَ فِيهَا تَحْيَوْنَ وَفِيهَا تَمُوتُونَ وَمِنْهَا تُخْرَجُونَ", 't': "«قال فيها» أي الأرض «تحيون وفيها تموتون ومنها تخرجون» بالبعث، وبالباء للفاعل والمفعول."},
  {'n': '26', 'v': "يَٰبَنِىٓ ءَادَمَ قَدْ أَنزَلْنَا عَلَيْكُمْ لِبَاسًۭا يُوَٰرِى سَوْءَٰتِكُمْ وَرِيشًۭا ۖ وَلِبَاسُ ٱلتَّقْوَىٰ ذَٰلِكَ خَيْرٌۭ ۚ ذَٰلِكَ مِنْ ءَايَٰتِ ٱللَّهِ لَعَلَّهُمْ يَذَّكَّرُونَ", 't': "«يا بني آدم قد أنزلنا عليكم لباسا» أي خلقناه لكم «يواري» يستر «سوآتكم وريشا» وهو ما يتحمل به من الثياب «ولباس التقوى» العمل الصالح والسمت الحسن بالنصب عطف على لباسا والرفع مبتدأ خبره جملة «ذلك خيرٌ ذلك من آيات الله» دلائل قدرته «لعلهم يذَّكرون» فيؤمنون فيه التفات عن الخطاب."},
  {'n': '27', 'v': "يَٰبَنِىٓ ءَادَمَ لَا يَفْتِنَنَّكُمُ ٱلشَّيْطَٰنُ كَمَآ أَخْرَجَ أَبَوَيْكُم مِّنَ ٱلْجَنَّةِ يَنزِعُ عَنْهُمَا لِبَاسَهُمَا لِيُرِيَهُمَا سَوْءَٰتِهِمَآ ۗ إِنَّهُۥ يَرَىٰكُمْ هُوَ وَقَبِيلُهُۥ مِنْ حَيْثُ لَا تَرَوْنَهُمْ ۗ إِنَّا جَعَلْنَا ٱلشَّيَٰطِينَ أَوْلِيَآءَ لِلَّذِينَ لَا يُؤْمِنُونَ", 't': "«يا بني آدم لا يفتننَّكم» يضلكم «الشيطان» أي لا تتبعوه فتفتنوا «كما أخرج أبويكم» بفتنته «من الجنة ينزع» حال «عنهما لباسهما ليريهما سوآتهما إنه» أي الشيطان «يراكم هو وقبيله» جنوده «من حيث لا ترونهم» للطافة أجسادهم أو عدم ألوانهم «إنا جعلنا الشياطين أولياء» أعوانا وقرناء «للذين لا يؤمنون»."},
  {'n': '28', 'v': "وَإِذَا فَعَلُوا۟ فَٰحِشَةًۭ قَالُوا۟ وَجَدْنَا عَلَيْهَآ ءَابَآءَنَا وَٱللَّهُ أَمَرَنَا بِهَا ۗ قُلْ إِنَّ ٱللَّهَ لَا يَأْمُرُ بِٱلْفَحْشَآءِ ۖ أَتَقُولُونَ عَلَى ٱللَّهِ مَا لَا تَعْلَمُونَ", 't': "«وإذا فعلوا فاحشة» كالشرك وطوافهم بالبيت عراة قائلين لا نطوف في ثياب عصينا الله فيها فنهوا عنها «قالوا وجدنا عليها آباءنا» فاقتدينا بهم «والله أمرنا بها» أيضا «قل» لهم «إن الله لا يأمر بالفحشاء أتقولون على الله ما لا تعلمون» أنه قاله، استفهام إنكار."},
  {'n': '29', 'v': "قُلْ أَمَرَ رَبِّى بِٱلْقِسْطِ ۖ وَأَقِيمُوا۟ وُجُوهَكُمْ عِندَ كُلِّ مَسْجِدٍۢ وَٱدْعُوهُ مُخْلِصِينَ لَهُ ٱلدِّينَ ۚ كَمَا بَدَأَكُمْ تَعُودُونَ", 't': "«قل أمر ربي بالقسط» بالعدل «وأقيموا» معطوف على معنى بالقسط أي قال أقسطوا وأقيموا أو قبله فاقبلوا مقدرا «وجوهكم» لله «عند كل مسجد» أي أخلصوا له سجودكم «وادعوه» اعبدوه «مخلصين له الدين» من الشرك «كما بدأكم» خلقكم ولم تكونوا شيئا «تعودون» أي يعيدكم أحياء يوم القيامة."},
  {'n': '30', 'v': "فَرِيقًا هَدَىٰ وَفَرِيقًا حَقَّ عَلَيْهِمُ ٱلضَّلَٰلَةُ ۗ إِنَّهُمُ ٱتَّخَذُوا۟ ٱلشَّيَٰطِينَ أَوْلِيَآءَ مِن دُونِ ٱللَّهِ وَيَحْسَبُونَ أَنَّهُم مُّهْتَدُونَ", 't': "«فريقا» منكم «هدى وفريقا حق عليهم الضلالة إنهم اتخذوا الشياطين أولياء من دون الله» أي غيره «ويحسبون أنهم مهتدون»."},
  {'n': '31', 'v': "۞ يَٰبَنِىٓ ءَادَمَ خُذُوا۟ زِينَتَكُمْ عِندَ كُلِّ مَسْجِدٍۢ وَكُلُوا۟ وَٱشْرَبُوا۟ وَلَا تُسْرِفُوٓا۟ ۚ إِنَّهُۥ لَا يُحِبُّ ٱلْمُسْرِفِينَ", 't': "«يا بني آدم خذوا زينتكم» ما يستر عورتكم «عند كل مسجد» عند الصلاة والطواف «وكلوا واشربوا» ما شئتم «ولا تسرفوا إنه لا يحب المسرفين»."},
  {'n': '32', 'v': "قُلْ مَنْ حَرَّمَ زِينَةَ ٱللَّهِ ٱلَّتِىٓ أَخْرَجَ لِعِبَادِهِۦ وَٱلطَّيِّبَٰتِ مِنَ ٱلرِّزْقِ ۚ قُلْ هِىَ لِلَّذِينَ ءَامَنُوا۟ فِى ٱلْحَيَوٰةِ ٱلدُّنْيَا خَالِصَةًۭ يَوْمَ ٱلْقِيَٰمَةِ ۗ كَذَٰلِكَ نُفَصِّلُ ٱلْءَايَٰتِ لِقَوْمٍۢ يَعْلَمُونَ", 't': "«قل» إنكارا عليهم «من حرَّم زينة الله التي أخرج لعباده» من اللباس «والطيبات» المستلذات «من الرزق قل هي للذين آمنوا في الحياة الدنيا» بالاستحقاق وإن فيها غيرهم «خالصةٌ» خاصة بهم بالرفع والنصب حال «يوم القيامة كذلك نفصِّل الآيات» نبينها مثل ذلك التفصيل «قوم يعلمون» يتدبَّرون فإنهم المنتفعون بها."},
  {'n': '33', 'v': "قُلْ إِنَّمَا حَرَّمَ رَبِّىَ ٱلْفَوَٰحِشَ مَا ظَهَرَ مِنْهَا وَمَا بَطَنَ وَٱلْإِثْمَ وَٱلْبَغْىَ بِغَيْرِ ٱلْحَقِّ وَأَن تُشْرِكُوا۟ بِٱللَّهِ مَا لَمْ يُنَزِّلْ بِهِۦ سُلْطَٰنًۭا وَأَن تَقُولُوا۟ عَلَى ٱللَّهِ مَا لَا تَعْلَمُونَ", 't': "«قل إنما حرَّم ربي الفواحش» الكبائر كالزنا «ما ظهر منها وما بطن» أي جهرها وسرها «والإثم» المعصية «والبغي» على الناس «بغير الحق» وهو الظلم «وأن تشركوا بالله ما لم ينزل به» بإشراكه «سلطانا» حجة «وأن تقولوا على الله ما لا تعلمون» من تحريم ما لم يحرم وغيره."},
  {'n': '34', 'v': "وَلِكُلِّ أُمَّةٍ أَجَلٌۭ ۖ فَإِذَا جَآءَ أَجَلُهُمْ لَا يَسْتَأْخِرُونَ سَاعَةًۭ ۖ وَلَا يَسْتَقْدِمُونَ", 't': "«ولكل أمَّة أجل» مدة «فإذا جاء أجلهم لا يستأخرون» عنه «ساعة ولا يستقدمون» عليه."},
  {'n': '35', 'v': "يَٰبَنِىٓ ءَادَمَ إِمَّا يَأْتِيَنَّكُمْ رُسُلٌۭ مِّنكُمْ يَقُصُّونَ عَلَيْكُمْ ءَايَٰتِى ۙ فَمَنِ ٱتَّقَىٰ وَأَصْلَحَ فَلَا خَوْفٌ عَلَيْهِمْ وَلَا هُمْ يَحْزَنُونَ", 't': "«يابني آدم إمَّا» فيه إدغام نون إن الشرطية في ما المزيدة «يأتينكم رسل منكم يقصُّون عليكم آياتي فمن اتقى» الشرك «وأصلح» عمله «فلا خوف عليهم ولا هم يحزنون» في الآخرة."},
  {'n': '36', 'v': "وَٱلَّذِينَ كَذَّبُوا۟ بِـَٔايَٰتِنَا وَٱسْتَكْبَرُوا۟ عَنْهَآ أُو۟لَٰٓئِكَ أَصْحَٰبُ ٱلنَّارِ ۖ هُمْ فِيهَا خَٰلِدُونَ", 't': "«والذين كذبوا بآياتنا واستكبروا» تكبروا «عنها» فلم يؤمنوا بها «أولئك أصحاب النار هم فيها خالدون»."},
  {'n': '37', 'v': "فَمَنْ أَظْلَمُ مِمَّنِ ٱفْتَرَىٰ عَلَى ٱللَّهِ كَذِبًا أَوْ كَذَّبَ بِـَٔايَٰتِهِۦٓ ۚ أُو۟لَٰٓئِكَ يَنَالُهُمْ نَصِيبُهُم مِّنَ ٱلْكِتَٰبِ ۖ حَتَّىٰٓ إِذَا جَآءَتْهُمْ رُسُلُنَا يَتَوَفَّوْنَهُمْ قَالُوٓا۟ أَيْنَ مَا كُنتُمْ تَدْعُونَ مِن دُونِ ٱللَّهِ ۖ قَالُوا۟ ضَلُّوا۟ عَنَّا وَشَهِدُوا۟ عَلَىٰٓ أَنفُسِهِمْ أَنَّهُمْ كَانُوا۟ كَٰفِرِينَ", 't': "«فمن» أي لا أحد «أظلم ممن افترى على الله كذبا» بنسبة الشريك والولد إليه «أو كذَّب بآياته» القرآن «أولئك ينالهم» يصيبهم «نصيبهم» حظهم «من الكتاب» مما كتب لهم في اللوح المحفوظ من الرزق والأجل وغير ذلك «حتى إذا جاءتهم رسلنا» أي الملائكة «يتوفونهم قالوا» لهم تبكيتا «أين ما كنتم تدعون» تعبدون «من دون الله قالوا ضلُّوا» غابوا «عنا» فلم نرهم «وشهدوا على أنفسهم» عند الموت «أنهم كانوا كافرين»."},
  {'n': '38', 'v': "قَالَ ٱدْخُلُوا۟ فِىٓ أُمَمٍۢ قَدْ خَلَتْ مِن قَبْلِكُم مِّنَ ٱلْجِنِّ وَٱلْإِنسِ فِى ٱلنَّارِ ۖ كُلَّمَا دَخَلَتْ أُمَّةٌۭ لَّعَنَتْ أُخْتَهَا ۖ حَتَّىٰٓ إِذَا ٱدَّارَكُوا۟ فِيهَا جَمِيعًۭا قَالَتْ أُخْرَىٰهُمْ لِأُولَىٰهُمْ رَبَّنَا هَٰٓؤُلَآءِ أَضَلُّونَا فَـَٔاتِهِمْ عَذَابًۭا ضِعْفًۭا مِّنَ ٱلنَّارِ ۖ قَالَ لِكُلٍّۢ ضِعْفٌۭ وَلَٰكِن لَّا تَعْلَمُونَ", 't': "«قال» تعالى لهم يوم القيامة «ادخلوا في» جملة «أمم قد خلت من قبلكم من الجن والإنس في النار» متعلق بادخلوا «كلما دخلت أُمة» النار «لعنت أختها» التي قبلها لضلالها بها «حتى إذا ادَّاركوا» تلاحقوا «فيها جميعا قالت أخراهم» وهم الأتباع «لأولاهم» أي لأجلائهم وهم المتبوعون «ربنا هؤلاء أضلونا فآتهم عذابا ضعفا» مضعفا «من النار قال» تعالى «لكل» منكم ومنهم «ضعف» عذاب مضعف «ولكن لا يعلمون» بالياء والتاء ما لكل فريق."},
  {'n': '39', 'v': "وَقَالَتْ أُولَىٰهُمْ لِأُخْرَىٰهُمْ فَمَا كَانَ لَكُمْ عَلَيْنَا مِن فَضْلٍۢ فَذُوقُوا۟ ٱلْعَذَابَ بِمَا كُنتُمْ تَكْسِبُونَ", 't': "«وقالت أُولاهم لأخراهم فما كان لكم علينا من فضل» لأنكم لم تكفروا بسببنا فنحن وأنتم سواء قال تعالى لهم «فذوقوا العذاب بما كنتم تكسبون»."},
  {'n': '40', 'v': "إِنَّ ٱلَّذِينَ كَذَّبُوا۟ بِـَٔايَٰتِنَا وَٱسْتَكْبَرُوا۟ عَنْهَا لَا تُفَتَّحُ لَهُمْ أَبْوَٰبُ ٱلسَّمَآءِ وَلَا يَدْخُلُونَ ٱلْجَنَّةَ حَتَّىٰ يَلِجَ ٱلْجَمَلُ فِى سَمِّ ٱلْخِيَاطِ ۚ وَكَذَٰلِكَ نَجْزِى ٱلْمُجْرِمِينَ", 't': "«إن الذين كذبوا بآياتنا واستكبروا» تكبروا «عنها» فلم يؤمنوا بها «لا تفتَّح لهم أبواب السماء» إذا عرج بأرواحهم إليها بعد الموت فيهبط بها إلى سجين بخلاف المؤمن فتفتح له ويصعد بروحه إلى السماء السابعة كما ورد في حديث «ولا يدخلون الجنة حتى يلج» يدخل «الجمل في سمِّ الخياط» ثقب الإبرة وهو غير ممكن فكذا دخولهم «وكذلك» الجزاء «نجزي المجرمين» بالكفر."},
  {'n': '41', 'v': "لَهُم مِّن جَهَنَّمَ مِهَادٌۭ وَمِن فَوْقِهِمْ غَوَاشٍۢ ۚ وَكَذَٰلِكَ نَجْزِى ٱلظَّٰلِمِينَ", 't': "«لهم من جهنم مهاد» فراش «ومن فوقهم غواشٍ» أغطية من النار جمع غاشية وتنوينه عوض من الياء المحذوفة «وكذلك نجزي الظالمين»."},
  {'n': '42', 'v': "وَٱلَّذِينَ ءَامَنُوا۟ وَعَمِلُوا۟ ٱلصَّٰلِحَٰتِ لَا نُكَلِّفُ نَفْسًا إِلَّا وُسْعَهَآ أُو۟لَٰٓئِكَ أَصْحَٰبُ ٱلْجَنَّةِ ۖ هُمْ فِيهَا خَٰلِدُونَ", 't': "«والذين آمنوا وعملوا الصالحات» مبتدأ وقوله «لا نكلّف نفسا إلا وسعها» طاقتها من العمل اعتراض بينه وبين خبره وهو «أولئك أصحاب الجنة هم فيها خالدون»."},
  {'n': '43', 'v': "وَنَزَعْنَا مَا فِى صُدُورِهِم مِّنْ غِلٍّۢ تَجْرِى مِن تَحْتِهِمُ ٱلْأَنْهَٰرُ ۖ وَقَالُوا۟ ٱلْحَمْدُ لِلَّهِ ٱلَّذِى هَدَىٰنَا لِهَٰذَا وَمَا كُنَّا لِنَهْتَدِىَ لَوْلَآ أَنْ هَدَىٰنَا ٱللَّهُ ۖ لَقَدْ جَآءَتْ رُسُلُ رَبِّنَا بِٱلْحَقِّ ۖ وَنُودُوٓا۟ أَن تِلْكُمُ ٱلْجَنَّةُ أُورِثْتُمُوهَا بِمَا كُنتُمْ تَعْمَلُونَ", 't': "«ونزعنا ما في صدورهم من غل» حقد كان بينهم في الدنيا «تجري من تحتهم» تحت قصورهم «الأنهار وقالوا» عند الاستقرار في منازلهم «الحمد لله الذي هدانا لهذا» العمل الذي هذا جزاؤه «وما كنا لنهتدي لولا أن هدانا الله» حذف جواب لولا لدلالة ما قبله عليه «لقد جاءت رسل ربنا بالحق ونودوا أن» مخففة أي أنه أو مفسرة في المواضع الخمسة «تلكم الجنة أورثتموها بما كنتم تعملون»."},
  {'n': '44', 'v': "وَنَادَىٰٓ أَصْحَٰبُ ٱلْجَنَّةِ أَصْحَٰبَ ٱلنَّارِ أَن قَدْ وَجَدْنَا مَا وَعَدَنَا رَبُّنَا حَقًّۭا فَهَلْ وَجَدتُّم مَّا وَعَدَ رَبُّكُمْ حَقًّۭا ۖ قَالُوا۟ نَعَمْ ۚ فَأَذَّنَ مُؤَذِّنٌۢ بَيْنَهُمْ أَن لَّعْنَةُ ٱللَّهِ عَلَى ٱلظَّٰلِمِينَ", 't': "«ونادى أصحابُ الجنة أصحاب النار» تقريرا أو تبكيتا «أن قد وجدنا ما وعدنا ربنا» من الثواب «حقا فهل وجدتم ما وعد» كم «ربكُم» من العذاب «حقا؟ قالوا نعمْ فأذَّن مؤذَّن» نادى منادٍ «بينهم» بين الفريقين أسمعهم «أن لعنة الله على الظالمين»."},
  {'n': '45', 'v': "ٱلَّذِينَ يَصُدُّونَ عَن سَبِيلِ ٱللَّهِ وَيَبْغُونَهَا عِوَجًۭا وَهُم بِٱلْءَاخِرَةِ كَٰفِرُونَ", 't': "«الذين يصدون» الناس «عن سبيل الله» دينه «ويبغونها» أي يطلبون السبيل «عوجا» معوجة «وهم بالآخرة كافرون»."},
  {'n': '46', 'v': "وَبَيْنَهُمَا حِجَابٌۭ ۚ وَعَلَى ٱلْأَعْرَافِ رِجَالٌۭ يَعْرِفُونَ كُلًّۢا بِسِيمَىٰهُمْ ۚ وَنَادَوْا۟ أَصْحَٰبَ ٱلْجَنَّةِ أَن سَلَٰمٌ عَلَيْكُمْ ۚ لَمْ يَدْخُلُوهَا وَهُمْ يَطْمَعُونَ", 't': "(وبينهما) أي أصحاب الجنة والنار (حجاب) حاجز قيل هو سور الأعراف (وعلى الأعراف) وهو سور الجنة (رجال) استوت حسناتهم وسيئاتهم كما في الحديث (يعرفون كلا) من أهل الجنة والنار (بسيماهم) بعلامتهم وهي بياض الوجوه للمؤمنين وسوادها للكافرين لرؤيتهم لهم إذ موضعهم عال (ونادوا أصحاب الجنة أن سلام عليكم) قال تعالى (لم يدخلوها) أي أصحاب الأعراف الجنة (وهم يطمعون) في دخولها قال الحسن: لم يطمعهم إلا لكرامة يريدها بهم وروى الحاكم عن حذيفة قال \"\" بينما هم كذلك إذ طلع عليهم ربك فقال قوموا ادخلوا الجنة فقد غفرت لكم \"\"."},
  {'n': '47', 'v': "۞ وَإِذَا صُرِفَتْ أَبْصَٰرُهُمْ تِلْقَآءَ أَصْحَٰبِ ٱلنَّارِ قَالُوا۟ رَبَّنَا لَا تَجْعَلْنَا مَعَ ٱلْقَوْمِ ٱلظَّٰلِمِينَ", 't': "«وإذا صرفت أبصارهم» أي أصحاب الأعراف «تلقاء» جهة «أصحاب النار قالوا ربنا لا تجعلنا» في النار «مع القوم الظالمين»."},
  {'n': '48', 'v': "وَنَادَىٰٓ أَصْحَٰبُ ٱلْأَعْرَافِ رِجَالًۭا يَعْرِفُونَهُم بِسِيمَىٰهُمْ قَالُوا۟ مَآ أَغْنَىٰ عَنكُمْ جَمْعُكُمْ وَمَا كُنتُمْ تَسْتَكْبِرُونَ", 't': "«ونادى أصحاب الأعراف رجالا» من أصحاب النار «يعرفونهم بسيماهم قالوا ما أغنى عنكم» من النار «جمعكم» المال أو كثرتكم «وما كنتم تستكبرون» أي واستكباركم عن الإيمان، ويقولون لهم مشيرين إلى ضعفاء المسلمين."},
  {'n': '49', 'v': "أَهَٰٓؤُلَآءِ ٱلَّذِينَ أَقْسَمْتُمْ لَا يَنَالُهُمُ ٱللَّهُ بِرَحْمَةٍ ۚ ٱدْخُلُوا۟ ٱلْجَنَّةَ لَا خَوْفٌ عَلَيْكُمْ وَلَآ أَنتُمْ تَحْزَنُونَ", 't': "«أهؤلاء الذين أقسمتم لا ينالهم الله برحمة» قد قيل لهم «ادخلوا الجنة لا خوف عليكم ولا أنتم تحزنون» وقرئ: أُدخِلوا بالبناء للمفعول ودخلوا فجملة النفي حال أي مقولا لهم بذلك."},
  {'n': '50', 'v': "وَنَادَىٰٓ أَصْحَٰبُ ٱلنَّارِ أَصْحَٰبَ ٱلْجَنَّةِ أَنْ أَفِيضُوا۟ عَلَيْنَا مِنَ ٱلْمَآءِ أَوْ مِمَّا رَزَقَكُمُ ٱللَّهُ ۚ قَالُوٓا۟ إِنَّ ٱللَّهَ حَرَّمَهُمَا عَلَى ٱلْكَٰفِرِينَ", 't': "«ونادى أصحاب النار أصحاب الجنة أن أفيضوا علينا من الماء أو مما رزقكم الله» من الطعام «قالوا إن الله حرَّمهما» منعهما «على الكافرين»."},
  {'n': '51', 'v': "ٱلَّذِينَ ٱتَّخَذُوا۟ دِينَهُمْ لَهْوًۭا وَلَعِبًۭا وَغَرَّتْهُمُ ٱلْحَيَوٰةُ ٱلدُّنْيَا ۚ فَٱلْيَوْمَ نَنسَىٰهُمْ كَمَا نَسُوا۟ لِقَآءَ يَوْمِهِمْ هَٰذَا وَمَا كَانُوا۟ بِـَٔايَٰتِنَا يَجْحَدُونَ", 't': "«الذين اتخذوا دينهم لهوا ولعبا وغرتهم الحياة الدنيا فاليوم ننساهم» نتركهم في النار «كما نسوا لقاء يومهم هذا» بتركهم العمل له «وما كانوا بآياتنا يجحدون» أي وكما جحدوا."},
  {'n': '52', 'v': "وَلَقَدْ جِئْنَٰهُم بِكِتَٰبٍۢ فَصَّلْنَٰهُ عَلَىٰ عِلْمٍ هُدًۭى وَرَحْمَةًۭ لِّقَوْمٍۢ يُؤْمِنُونَ", 't': "«ولقد جئناهم» أي أهل مكة «بكتاب» قرآن «فصَّلناه» بيَّناه بالأخبار والوعد والوعيد «على علم» حال أي عالمين بما فصَّل فيه «هدى» حال من الهاء «ورحمة لقوم يؤمنون» به."},
  {'n': '53', 'v': "هَلْ يَنظُرُونَ إِلَّا تَأْوِيلَهُۥ ۚ يَوْمَ يَأْتِى تَأْوِيلُهُۥ يَقُولُ ٱلَّذِينَ نَسُوهُ مِن قَبْلُ قَدْ جَآءَتْ رُسُلُ رَبِّنَا بِٱلْحَقِّ فَهَل لَّنَا مِن شُفَعَآءَ فَيَشْفَعُوا۟ لَنَآ أَوْ نُرَدُّ فَنَعْمَلَ غَيْرَ ٱلَّذِى كُنَّا نَعْمَلُ ۚ قَدْ خَسِرُوٓا۟ أَنفُسَهُمْ وَضَلَّ عَنْهُم مَّا كَانُوا۟ يَفْتَرُونَ", 't': "«هل ينظرون» ما ينتظرون «إلا تأويله» عاقبة ما فيه «يوم يأتي تأويله» هو يوم القيامة «يقول الذين نسوه من قبل» تركوا الإيمان به «قد جاءت رسل ربنا بالحق فهل لنا من شفعاء فيشفعوا لنا أو» هل «نُرد» إلى الدنيا «فنعمل غير الذي كنا نعمل» نوحِّد الله ونترك الشرك، فيقال لهم: لا، قال تعالى: «قد خسروا أنفسهم» إذ صاروا إلى الهلاك «وضلّ» ذهب «عنهم ما كانوا يفترون» من دعوى الشريك."},
  {'n': '54', 'v': "إِنَّ رَبَّكُمُ ٱللَّهُ ٱلَّذِى خَلَقَ ٱلسَّمَٰوَٰتِ وَٱلْأَرْضَ فِى سِتَّةِ أَيَّامٍۢ ثُمَّ ٱسْتَوَىٰ عَلَى ٱلْعَرْشِ يُغْشِى ٱلَّيْلَ ٱلنَّهَارَ يَطْلُبُهُۥ حَثِيثًۭا وَٱلشَّمْسَ وَٱلْقَمَرَ وَٱلنُّجُومَ مُسَخَّرَٰتٍۭ بِأَمْرِهِۦٓ ۗ أَلَا لَهُ ٱلْخَلْقُ وَٱلْأَمْرُ ۗ تَبَارَكَ ٱللَّهُ رَبُّ ٱلْعَٰلَمِينَ", 't': "«إن ربكم الله الذي خلق السماوات والأرض في ستة أيام» من أيام الدنيا، أي في قدرها لأنه لم يكن ثَمَّ شمس ولو شاء خلقهم في لمحة، والعدول عنه لتعليم خلقه التثبيت «ثم استوى على العرش» هو في اللغة: سرير الملك استواء يليق به «يُغْشِي الليل النهار» مخففا ومشددا أي يغطي كلا منهما بالآخر طلبا «يطلبه حثيثا» سريعا «والشمس والقمر والنجوم» بالنصب عطفا على السماوات والرفع مبتدأ خبره «مسخرات» مذلَّلات «بأمره» بقدرته «ألا له الخلق» جميعا «والأمر» كله «تبارك» تعاظم «الله ربُّ» مالك «العالمين»."},
  {'n': '55', 'v': "ٱدْعُوا۟ رَبَّكُمْ تَضَرُّعًۭا وَخُفْيَةً ۚ إِنَّهُۥ لَا يُحِبُّ ٱلْمُعْتَدِينَ", 't': "«ادعوا ربَّكم تضرُّعا» حال تذللا «وخُفية» سرا «إنه لا يحب المعتدين» في الدعاء بالتشدق ورفع الصوت."},
  {'n': '56', 'v': "وَلَا تُفْسِدُوا۟ فِى ٱلْأَرْضِ بَعْدَ إِصْلَٰحِهَا وَٱدْعُوهُ خَوْفًۭا وَطَمَعًا ۚ إِنَّ رَحْمَتَ ٱللَّهِ قَرِيبٌۭ مِّنَ ٱلْمُحْسِنِينَ", 't': "«ولا تُفسدوا في الأرض» بالشرك والمعاصي «بعد إصلاحها» ببعث الرسل «وادعوه خوفا» من عقابه «وطمعا» في رحمته «إن رحمة الله قريب من المحسنين» المطيعين وتذكير قريب المخبر به عن رحمة لإضافتها إلى الله."},
  {'n': '57', 'v': "وَهُوَ ٱلَّذِى يُرْسِلُ ٱلرِّيَٰحَ بُشْرًۢا بَيْنَ يَدَىْ رَحْمَتِهِۦ ۖ حَتَّىٰٓ إِذَآ أَقَلَّتْ سَحَابًۭا ثِقَالًۭا سُقْنَٰهُ لِبَلَدٍۢ مَّيِّتٍۢ فَأَنزَلْنَا بِهِ ٱلْمَآءَ فَأَخْرَجْنَا بِهِۦ مِن كُلِّ ٱلثَّمَرَٰتِ ۚ كَذَٰلِكَ نُخْرِجُ ٱلْمَوْتَىٰ لَعَلَّكُمْ تَذَكَّرُونَ", 't': "«وهو الذي يرسل الرياح نُشُرا بين يدي رحمته» أي متفرقة قدام المطر، وفي قراءة سكون الشين تخفيفا، وفي أخرى بسكونها وفتح النون مصدرا، وفي أخرى بسكونها وضم الموحدة بدل النون: أي مبشرا ومفرد الأولى نشور كرسول والأخيرة بشير «حتى إذا أقلت» حملت الرياح «سحابا ثقالا» بالمطر «سقناه» أي السحاب وفيه التفات عن الغيبة «لبلد ميت» لا نبات به أي لإحيائها «فأنزلنا به» بالبلد «الماء فأخرجنا به» بالماء «من كل الثمرات كذلك» الإخراج «نخرج الموتى» من قبورهم بالإحياء «لعلكم تذكرون» فتؤمنون."},
  {'n': '58', 'v': "وَٱلْبَلَدُ ٱلطَّيِّبُ يَخْرُجُ نَبَاتُهُۥ بِإِذْنِ رَبِّهِۦ ۖ وَٱلَّذِى خَبُثَ لَا يَخْرُجُ إِلَّا نَكِدًۭا ۚ كَذَٰلِكَ نُصَرِّفُ ٱلْءَايَٰتِ لِقَوْمٍۢ يَشْكُرُونَ", 't': "«والبلد الطيب» العذب التراب «يخرج نباته» حسنا «بإذن ربه» هذا مثل للمؤمن يسمع الموعظة فينتفع بها «والذي خبث» ترابه «لا يخرج» نباته «إلا نكدا» عسرا بمشقة وهذا مثل للكافر «كذلك» كما بينا ما ذكر «نُصرِّف» نبين «الآيات لقوم يشكرون» الله يؤمنون."},
  {'n': '59', 'v': "لَقَدْ أَرْسَلْنَا نُوحًا إِلَىٰ قَوْمِهِۦ فَقَالَ يَٰقَوْمِ ٱعْبُدُوا۟ ٱللَّهَ مَا لَكُم مِّنْ إِلَٰهٍ غَيْرُهُۥٓ إِنِّىٓ أَخَافُ عَلَيْكُمْ عَذَابَ يَوْمٍ عَظِيمٍۢ", 't': "«لقد» جواب قسم محذوف «أرسلنا نوحا إلى قومه فقال يا قوم اعبدوا الله ما لكم من إله غَيْرُِهُ» بالجر صفة لإله والرفع بدل من محله «إني أخاف عليكم» إن عبدتم غيره «عذاب يوم عظيم» هو يوم القيامة."},
  {'n': '60', 'v': "قَالَ ٱلْمَلَأُ مِن قَوْمِهِۦٓ إِنَّا لَنَرَىٰكَ فِى ضَلَٰلٍۢ مُّبِينٍۢ", 't': "«قال الملأ» الأشراف «من قومه إنا لنراك في ضلالٍ مبين» بيَّن."},
  {'n': '61', 'v': "قَالَ يَٰقَوْمِ لَيْسَ بِى ضَلَٰلَةٌۭ وَلَٰكِنِّى رَسُولٌۭ مِّن رَّبِّ ٱلْعَٰلَمِينَ", 't': "«قال يا قوم ليس بي ضلالة» هي أعم من الضلال فنفيها أبلغ من نفيه «ولكني رسول من رب العالمين»."},
  {'n': '62', 'v': "أُبَلِّغُكُمْ رِسَٰلَٰتِ رَبِّى وَأَنصَحُ لَكُمْ وَأَعْلَمُ مِنَ ٱللَّهِ مَا لَا تَعْلَمُونَ", 't': "«أبلِّغُكم» بالتخفيف والتشديد «رسالات ربَّي وأنصح» أريد الخبر «لكم وأعلم من الله ما لا تعلمون»."},
  {'n': '63', 'v': "أَوَعَجِبْتُمْ أَن جَآءَكُمْ ذِكْرٌۭ مِّن رَّبِّكُمْ عَلَىٰ رَجُلٍۢ مِّنكُمْ لِيُنذِرَكُمْ وَلِتَتَّقُوا۟ وَلَعَلَّكُمْ تُرْحَمُونَ", 't': "«أ» كذبتم «وعجبتم أن جاءكم ذكر» موعظة «من ربكم على» لسان «رجل منكم لينذركم» العذاب إن لم تؤمنوا «ولتتَّقوا» الله «ولعلكم ترحمون» بها."},
  {'n': '64', 'v': "فَكَذَّبُوهُ فَأَنجَيْنَٰهُ وَٱلَّذِينَ مَعَهُۥ فِى ٱلْفُلْكِ وَأَغْرَقْنَا ٱلَّذِينَ كَذَّبُوا۟ بِـَٔايَٰتِنَآ ۚ إِنَّهُمْ كَانُوا۟ قَوْمًا عَمِينَ", 't': "«فكذَّبوه فأنجيناه والذين معه» من الغرق «في الفلك» السفينة «وأغرقنا الذين كذَّبوا بآياتنا» بالطوفان «إنهم كانوا قوما عَمين» عن الحق."},
  {'n': '65', 'v': "۞ وَإِلَىٰ عَادٍ أَخَاهُمْ هُودًۭا ۗ قَالَ يَٰقَوْمِ ٱعْبُدُوا۟ ٱللَّهَ مَا لَكُم مِّنْ إِلَٰهٍ غَيْرُهُۥٓ ۚ أَفَلَا تَتَّقُونَ", 't': "«و» أرسلنا «إلى عاد» الأولى «أخاهم هودا قال يا قوم اعبدوا الله» وحِّدوه «ما لكم من إله غيرُه أفلا تتقون» تخافونه فتؤمنون."},
  {'n': '66', 'v': "قَالَ ٱلْمَلَأُ ٱلَّذِينَ كَفَرُوا۟ مِن قَوْمِهِۦٓ إِنَّا لَنَرَىٰكَ فِى سَفَاهَةٍۢ وَإِنَّا لَنَظُنُّكَ مِنَ ٱلْكَٰذِبِينَ", 't': "«قال الملأ الذين كفروا من قومه إنا لنراك في سفاهة» جهالة «وإنا لنظنُّك من الكاذبين» في رسالتك."},
  {'n': '67', 'v': "قَالَ يَٰقَوْمِ لَيْسَ بِى سَفَاهَةٌۭ وَلَٰكِنِّى رَسُولٌۭ مِّن رَّبِّ ٱلْعَٰلَمِينَ", 't': "«قال يا قوم ليس بي سفاهة ولكني رسول من ربِّ العالمين»."},
  {'n': '68', 'v': "أُبَلِّغُكُمْ رِسَٰلَٰتِ رَبِّى وَأَنَا۠ لَكُمْ نَاصِحٌ أَمِينٌ", 't': "«أبلَّغكم رسالات ربي وأنا لكم ناصح أمين» مأمون على الرسالة."},
  {'n': '69', 'v': "أَوَعَجِبْتُمْ أَن جَآءَكُمْ ذِكْرٌۭ مِّن رَّبِّكُمْ عَلَىٰ رَجُلٍۢ مِّنكُمْ لِيُنذِرَكُمْ ۚ وَٱذْكُرُوٓا۟ إِذْ جَعَلَكُمْ خُلَفَآءَ مِنۢ بَعْدِ قَوْمِ نُوحٍۢ وَزَادَكُمْ فِى ٱلْخَلْقِ بَصْۜطَةًۭ ۖ فَٱذْكُرُوٓا۟ ءَالَآءَ ٱللَّهِ لَعَلَّكُمْ تُفْلِحُونَ", 't': "«أو عجبتم أن جاءكم ذِكْرٌ من ربكم على» لسان «رجل منكم لينذركم واذكروا إذ جعلكم خلفاء» في الأرض «من بعد قوم نوح وزادكم في الخلق بسطة» قوة وَطَوْلا وكان طويلهم مائة ذراع وقصيرهم ستين «فاذكروا آلاء الله» نعمه «لعلكم تفلحون» تفوزون."},
  {'n': '70', 'v': "قَالُوٓا۟ أَجِئْتَنَا لِنَعْبُدَ ٱللَّهَ وَحْدَهُۥ وَنَذَرَ مَا كَانَ يَعْبُدُ ءَابَآؤُنَا ۖ فَأْتِنَا بِمَا تَعِدُنَآ إِن كُنتَ مِنَ ٱلصَّٰدِقِينَ", 't': "«قالوا أجئتنا لنعبد الله وحده ونذر» نترك «ما كان يعبد آباؤنا فأتنا بما تعدنا» به من العذاب «إن كنت من الصادقين» في قولك."},
  {'n': '71', 'v': "قَالَ قَدْ وَقَعَ عَلَيْكُم مِّن رَّبِّكُمْ رِجْسٌۭ وَغَضَبٌ ۖ أَتُجَٰدِلُونَنِى فِىٓ أَسْمَآءٍۢ سَمَّيْتُمُوهَآ أَنتُمْ وَءَابَآؤُكُم مَّا نَزَّلَ ٱللَّهُ بِهَا مِن سُلْطَٰنٍۢ ۚ فَٱنتَظِرُوٓا۟ إِنِّى مَعَكُم مِّنَ ٱلْمُنتَظِرِينَ", 't': "«قال قد وقع» وجب «عليكم من ربَّكم رجس» عذاب «وغضب أتجادلونني في أسماء سميتموها» أي سميتم بها «أنتم وآباؤكم» أصناما تعبدونها «ما نزَّل الله بها» أي بعبادتها «من سلطان» حجة وبرهان «فانتظروا» العذاب «إني معكم من المنتظرين» ذلكم بتكذيبكم لي فأرسلت عليهم الريح العقيم."},
  {'n': '72', 'v': "فَأَنجَيْنَٰهُ وَٱلَّذِينَ مَعَهُۥ بِرَحْمَةٍۢ مِّنَّا وَقَطَعْنَا دَابِرَ ٱلَّذِينَ كَذَّبُوا۟ بِـَٔايَٰتِنَا ۖ وَمَا كَانُوا۟ مُؤْمِنِينَ", 't': "«فأنجيناه» أي هودا «والذين معه» من المؤمنين «برحمة منا وقطعنا دابر» القوم «الذين كذبوا بآياتنا» أي استأصلناكم «وما كانوا مؤمنين» عطف على كذبوا."},
  {'n': '73', 'v': "وَإِلَىٰ ثَمُودَ أَخَاهُمْ صَٰلِحًۭا ۗ قَالَ يَٰقَوْمِ ٱعْبُدُوا۟ ٱللَّهَ مَا لَكُم مِّنْ إِلَٰهٍ غَيْرُهُۥ ۖ قَدْ جَآءَتْكُم بَيِّنَةٌۭ مِّن رَّبِّكُمْ ۖ هَٰذِهِۦ نَاقَةُ ٱللَّهِ لَكُمْ ءَايَةًۭ ۖ فَذَرُوهَا تَأْكُلْ فِىٓ أَرْضِ ٱللَّهِ ۖ وَلَا تَمَسُّوهَا بِسُوٓءٍۢ فَيَأْخُذَكُمْ عَذَابٌ أَلِيمٌۭ", 't': "«و» أرسلنا «إلى ثمود» بترك الصرف مرادا به القبيلة «أخاهم صالحا قال يا قوم اعبدوا الله ما لكم من إله غيره قد جاءتكم بيَّنة» معجزة «من ربكم» على صدقي «هذه ناقة الله لكم آية» حال عاملها معنى الإشارة وكانوا سألوه أن يخرجها لهم صخرة عينوها «فذروها تأكل في أرض الله ولا تمسوها بسوء» بعقر أو ضرب «فيأخذكم عذاب أليم»."},
  {'n': '74', 'v': "وَٱذْكُرُوٓا۟ إِذْ جَعَلَكُمْ خُلَفَآءَ مِنۢ بَعْدِ عَادٍۢ وَبَوَّأَكُمْ فِى ٱلْأَرْضِ تَتَّخِذُونَ مِن سُهُولِهَا قُصُورًۭا وَتَنْحِتُونَ ٱلْجِبَالَ بُيُوتًۭا ۖ فَٱذْكُرُوٓا۟ ءَالَآءَ ٱللَّهِ وَلَا تَعْثَوْا۟ فِى ٱلْأَرْضِ مُفْسِدِينَ", 't': "«واذكروا إذ جعلكم خلفاء» في الأرض «من بعد عاد وبوَّأكم» أسكنكم «في الأرض تتَّخذون من سهولها قصورا» تسكنونها في الصيف «وتنحتون الجبال بيوتا» تسكنونها في الشتاء ونصبه على الحال المقدرة «فاذكروا آلاء الله ولا تعثوا في الأرض مفسدين»."},
  {'n': '75', 'v': "قَالَ ٱلْمَلَأُ ٱلَّذِينَ ٱسْتَكْبَرُوا۟ مِن قَوْمِهِۦ لِلَّذِينَ ٱسْتُضْعِفُوا۟ لِمَنْ ءَامَنَ مِنْهُمْ أَتَعْلَمُونَ أَنَّ صَٰلِحًۭا مُّرْسَلٌۭ مِّن رَّبِّهِۦ ۚ قَالُوٓا۟ إِنَّا بِمَآ أُرْسِلَ بِهِۦ مُؤْمِنُونَ", 't': "«قال الملأ الذين استكبروا من قومه» تكبروا عن الإيمان به «للذين استُضعفوا لمن آمن منهم» أي من قومه بدل مما قبله بإعادة الجار «أتعلمون أن صالحا مرسل من ربه» إليكم «قالوا» نعم «إنا بما أرسل به مؤمنون»."},
  {'n': '76', 'v': "قَالَ ٱلَّذِينَ ٱسْتَكْبَرُوٓا۟ إِنَّا بِٱلَّذِىٓ ءَامَنتُم بِهِۦ كَٰفِرُونَ", 't': "«قال الذين استكبروا إنا بالذي آمنتم به كافرون»."},
  {'n': '77', 'v': "فَعَقَرُوا۟ ٱلنَّاقَةَ وَعَتَوْا۟ عَنْ أَمْرِ رَبِّهِمْ وَقَالُوا۟ يَٰصَٰلِحُ ٱئْتِنَا بِمَا تَعِدُنَآ إِن كُنتَ مِنَ ٱلْمُرْسَلِينَ", 't': "وكانت الناقة لها يوم في الماء ولهم يوم فملوا ذلك «فعقروا الناقة» عقرها قدار بأمرهم بأن قتلها بالسيف «وعتوا عن أمر ربهم وقالوا يا صالح ائتنا بما تعدنا» به من العذاب على قتلها «إن كنت من المرسلين»."},
  {'n': '78', 'v': "فَأَخَذَتْهُمُ ٱلرَّجْفَةُ فَأَصْبَحُوا۟ فِى دَارِهِمْ جَٰثِمِينَ", 't': "«فأخذتهم الرجفة» الزلزلة الشديدة من الأرض والصيحة من السماء «فأصبحوا في دارهم جاثمين» باركين على الركب ميِّتين."},
  {'n': '79', 'v': "فَتَوَلَّىٰ عَنْهُمْ وَقَالَ يَٰقَوْمِ لَقَدْ أَبْلَغْتُكُمْ رِسَالَةَ رَبِّى وَنَصَحْتُ لَكُمْ وَلَٰكِن لَّا تُحِبُّونَ ٱلنَّٰصِحِينَ", 't': "«فتولى» أعرض صالح «عنهم وقال يا قوم لقد أبلغتكم رسالة ربي ونصحت لكم ولكن لا تحبون الناصحين»."},
  {'n': '80', 'v': "وَلُوطًا إِذْ قَالَ لِقَوْمِهِۦٓ أَتَأْتُونَ ٱلْفَٰحِشَةَ مَا سَبَقَكُم بِهَا مِنْ أَحَدٍۢ مِّنَ ٱلْعَٰلَمِينَ", 't': "«و» اذكر «لوطا» ويبدل منه «إذا قال لقومه أتأتون الفاحشة» أي أدبار الرجال «ما سبقكم بها من أحد من العالمين» الإنس والجن."},
  {'n': '81', 'v': "إِنَّكُمْ لَتَأْتُونَ ٱلرِّجَالَ شَهْوَةًۭ مِّن دُونِ ٱلنِّسَآءِ ۚ بَلْ أَنتُمْ قَوْمٌۭ مُّسْرِفُونَ", 't': "«أئِنَّكُم» بتحقيق الهمزتين وتسهيل الثانية وإدخال الألف بينهما وفي قراءة إنَّكُمْ «لتأتون الرجال شهوة من دون النساء بل أنتم قوم مسرفون» متجاوزون الحلال إلى الحرام."},
  {'n': '82', 'v': "وَمَا كَانَ جَوَابَ قَوْمِهِۦٓ إِلَّآ أَن قَالُوٓا۟ أَخْرِجُوهُم مِّن قَرْيَتِكُمْ ۖ إِنَّهُمْ أُنَاسٌۭ يَتَطَهَّرُونَ", 't': "«وما كان جواب قومه إلا أن قالوا أخرجوهم» أي لوطا وأتباعه «من قريتكم إنهم أناس يتطهرون» من أدبار الرجال."},
  {'n': '83', 'v': "فَأَنجَيْنَٰهُ وَأَهْلَهُۥٓ إِلَّا ٱمْرَأَتَهُۥ كَانَتْ مِنَ ٱلْغَٰبِرِينَ", 't': "«فأنجيناه وأهله إلا امرأته كانت من الغابرين» الباقين في العذاب."},
  {'n': '84', 'v': "وَأَمْطَرْنَا عَلَيْهِم مَّطَرًۭا ۖ فَٱنظُرْ كَيْفَ كَانَ عَٰقِبَةُ ٱلْمُجْرِمِينَ", 't': "«وأمطرنا عليهم مطرا» هو حجارة السجيل فأهلكتهم «فانظر كيف كان عاقبة المجرمين»."},
  {'n': '85', 'v': "وَإِلَىٰ مَدْيَنَ أَخَاهُمْ شُعَيْبًۭا ۗ قَالَ يَٰقَوْمِ ٱعْبُدُوا۟ ٱللَّهَ مَا لَكُم مِّنْ إِلَٰهٍ غَيْرُهُۥ ۖ قَدْ جَآءَتْكُم بَيِّنَةٌۭ مِّن رَّبِّكُمْ ۖ فَأَوْفُوا۟ ٱلْكَيْلَ وَٱلْمِيزَانَ وَلَا تَبْخَسُوا۟ ٱلنَّاسَ أَشْيَآءَهُمْ وَلَا تُفْسِدُوا۟ فِى ٱلْأَرْضِ بَعْدَ إِصْلَٰحِهَا ۚ ذَٰلِكُمْ خَيْرٌۭ لَّكُمْ إِن كُنتُم مُّؤْمِنِينَ", 't': "«و» أرسلنا «إلى مدين أخاهم شعيبا قال يا قوم اعبدوا الله ما لكم من إله غيره قد جاءتكم بينة» معجزة «من ربكم» على صدقي «فأوفوا» أتموا «الكيل والميزان ولا تبخسوا» تنقصوا «الناس أشياءهم ولا تفسدوا في الأرض» بالكفر والمعاصي «بعد إصلاحها» ببعث الرسل «ذلكم» المذكور «خير لكم إن كنتم مؤمنين» مريدي الإيمان فبادروا إليه."},
  {'n': '86', 'v': "وَلَا تَقْعُدُوا۟ بِكُلِّ صِرَٰطٍۢ تُوعِدُونَ وَتَصُدُّونَ عَن سَبِيلِ ٱللَّهِ مَنْ ءَامَنَ بِهِۦ وَتَبْغُونَهَا عِوَجًۭا ۚ وَٱذْكُرُوٓا۟ إِذْ كُنتُمْ قَلِيلًۭا فَكَثَّرَكُمْ ۖ وَٱنظُرُوا۟ كَيْفَ كَانَ عَٰقِبَةُ ٱلْمُفْسِدِينَ", 't': "«ولا تقعدوا بكل صراط» طريق «تُوعدون» تخوفون الناس بأخذ ثيابهم أو المكس منهم «وتصدون» تصرفون «عن سبيل الله» دينه «من آمن به» بتوعدكم إياه بالقتل «وتبغونها» تطلبون الطريق «عوجا» معوجة «واذكروا إذ كنتم قليلا فكثَّركم وانظروا كيف كان عاقبة المفسدين» قبلكم بتكذيب رسلهم أي آخر أمرهم من الهلاك."},
  {'n': '87', 'v': "وَإِن كَانَ طَآئِفَةٌۭ مِّنكُمْ ءَامَنُوا۟ بِٱلَّذِىٓ أُرْسِلْتُ بِهِۦ وَطَآئِفَةٌۭ لَّمْ يُؤْمِنُوا۟ فَٱصْبِرُوا۟ حَتَّىٰ يَحْكُمَ ٱللَّهُ بَيْنَنَا ۚ وَهُوَ خَيْرُ ٱلْحَٰكِمِينَ", 't': "«وإن كان طائفةٌ منكم آمنوا بالذي أُرسلت به وطائفة لم يؤمنوا» به «فاصبروا» انتظروا «حتى يحكم الله بيننا» وبينكم بإنجاء المحق وإهلاك المبطل «وهو خير الحاكمين» أعدلهم."},
  {'n': '88', 'v': "۞ قَالَ ٱلْمَلَأُ ٱلَّذِينَ ٱسْتَكْبَرُوا۟ مِن قَوْمِهِۦ لَنُخْرِجَنَّكَ يَٰشُعَيْبُ وَٱلَّذِينَ ءَامَنُوا۟ مَعَكَ مِن قَرْيَتِنَآ أَوْ لَتَعُودُنَّ فِى مِلَّتِنَا ۚ قَالَ أَوَلَوْ كُنَّا كَٰرِهِينَ", 't': "«قال الملأ الذين استكبروا من قومه» عن الإيمان «لنخرجنك يا شعيب والذين آمنوا معك من قريتنا أو لتعودُن» ترجعن «في ملتنا» ديننا وغلبوا في الخطاب الجمع على الواحد لأن شعيبا لم يكن في ملتهم قط وعلى نحوه أجاب «قال أ» نعود فيها «ولو كنا كارهين» لها استفهام إنكار."},
  {'n': '89', 'v': "قَدِ ٱفْتَرَيْنَا عَلَى ٱللَّهِ كَذِبًا إِنْ عُدْنَا فِى مِلَّتِكُم بَعْدَ إِذْ نَجَّىٰنَا ٱللَّهُ مِنْهَا ۚ وَمَا يَكُونُ لَنَآ أَن نَّعُودَ فِيهَآ إِلَّآ أَن يَشَآءَ ٱللَّهُ رَبُّنَا ۚ وَسِعَ رَبُّنَا كُلَّ شَىْءٍ عِلْمًا ۚ عَلَى ٱللَّهِ تَوَكَّلْنَا ۚ رَبَّنَا ٱفْتَحْ بَيْنَنَا وَبَيْنَ قَوْمِنَا بِٱلْحَقِّ وَأَنتَ خَيْرُ ٱلْفَٰتِحِينَ", 't': "«قد افترينا على الله كذبا إن عدنا في ملَّتكم بعد إذ نجَّانا الله منها وما يكون» ينبغي «لنا أن نعود فيها إلا أن يشاء الله ربُّنا» ذلك فيخذلنا «وسع ربُّنا كلَّ شيء علما» أي وسع علمه كل شيء ومنه حالي وحالكم «على الله توكلنا ربنا افتح» احكم «بيننا وبين قومنا بالحق وأنت خير الفاتحين» الحاكمين."},
  {'n': '90', 'v': "وَقَالَ ٱلْمَلَأُ ٱلَّذِينَ كَفَرُوا۟ مِن قَوْمِهِۦ لَئِنِ ٱتَّبَعْتُمْ شُعَيْبًا إِنَّكُمْ إِذًۭا لَّخَٰسِرُونَ", 't': "«وقال الملأ الذين كفروا من قومه» أي قال بعضهم لبعض «لئن» لام قسم «اتبعتم شعيبا إنكم إذًا الخاسرون»."},
  {'n': '91', 'v': "فَأَخَذَتْهُمُ ٱلرَّجْفَةُ فَأَصْبَحُوا۟ فِى دَارِهِمْ جَٰثِمِينَ", 't': "«فأخذتهم الرجفة» الزلزلة الشديدة «فأصبحوا في دارهم جاثمين» باركين على الركب ميِّتين."},
  {'n': '92', 'v': "ٱلَّذِينَ كَذَّبُوا۟ شُعَيْبًۭا كَأَن لَّمْ يَغْنَوْا۟ فِيهَا ۚ ٱلَّذِينَ كَذَّبُوا۟ شُعَيْبًۭا كَانُوا۟ هُمُ ٱلْخَٰسِرِينَ", 't': "«الذين كذَّبوا شعيبا» مبتدأ خبره «كأن» مخففة واسمها محذوف أي كأنهم «لم يَغنوا» يقيموا «فيها» في ديارهم «الذين كذَّبوا شعيبا كانوا هم الخاسرين» التأكيد بإعادة الموصول وغيره للرد عليهم في قولهم السابق."},
  {'n': '93', 'v': "فَتَوَلَّىٰ عَنْهُمْ وَقَالَ يَٰقَوْمِ لَقَدْ أَبْلَغْتُكُمْ رِسَٰلَٰتِ رَبِّى وَنَصَحْتُ لَكُمْ ۖ فَكَيْفَ ءَاسَىٰ عَلَىٰ قَوْمٍۢ كَٰفِرِينَ", 't': "«فتولى» أعرض «عنهم وقال يا قوم لقد أبلغتكم رسالات ربي ونصحت لكم» فلم تؤمنوا «فكيف آسى» أحزن «على قوم كافرين» استفهام بمعنى النفي."},
  {'n': '94', 'v': "وَمَآ أَرْسَلْنَا فِى قَرْيَةٍۢ مِّن نَّبِىٍّ إِلَّآ أَخَذْنَآ أَهْلَهَا بِٱلْبَأْسَآءِ وَٱلضَّرَّآءِ لَعَلَّهُمْ يَضَّرَّعُونَ", 't': "«وما أرسلنا في قرية من نبي» فكذبوا «إلا أخذنا» عاقبنا «أهلها بالبأساء» شدة الفقر «والضرَّاء» المرض «لعلهم يضَّرَّعون» يتذللون فيؤمنون."},
  {'n': '95', 'v': "ثُمَّ بَدَّلْنَا مَكَانَ ٱلسَّيِّئَةِ ٱلْحَسَنَةَ حَتَّىٰ عَفَوا۟ وَّقَالُوا۟ قَدْ مَسَّ ءَابَآءَنَا ٱلضَّرَّآءُ وَٱلسَّرَّآءُ فَأَخَذْنَٰهُم بَغْتَةًۭ وَهُمْ لَا يَشْعُرُونَ", 't': "«ثم بدَّلنا» أعطيناهم «مكان السيئة» العذاب «الحسنة» الغنى والصحة «حتى عفوا» كثروا «وقالوا» كفرا للنعمة «قد مس آباءنا الضرَّاء والسرَّاء» كما مسنا وهذه عادة الدهر وليست بعقوبة من الله فكونوا على ما أنتم عليه قال تعالى: «فأخذناهم» بالعذاب «بغتة» فجأة «وهم لا يشعرون» بوقت مجيئه قبله."},
  {'n': '96', 'v': "وَلَوْ أَنَّ أَهْلَ ٱلْقُرَىٰٓ ءَامَنُوا۟ وَٱتَّقَوْا۟ لَفَتَحْنَا عَلَيْهِم بَرَكَٰتٍۢ مِّنَ ٱلسَّمَآءِ وَٱلْأَرْضِ وَلَٰكِن كَذَّبُوا۟ فَأَخَذْنَٰهُم بِمَا كَانُوا۟ يَكْسِبُونَ", 't': "«ولو أنَّ أهل القرى» المكذَّبين «آمنوا» بالله ورسلهم «واتقوا» الكفر والمعاصي «لفتحنا» بالتخفيف والتشديد «عليهم بركات من السماء» بالمطر «والأرض» بالنبات «ولكن كذَّبوا» الرسل «فأخذناهم» عاقبناهم «بما كانوا يكسبون»."},
  {'n': '97', 'v': "أَفَأَمِنَ أَهْلُ ٱلْقُرَىٰٓ أَن يَأْتِيَهُم بَأْسُنَا بَيَٰتًۭا وَهُمْ نَآئِمُونَ", 't': "«أفأمن أهل القرى» المكذِّبون «أن يأتيهم بأسنا» عذابنا «بياتا» ليلا «وهم نائمون» غافلون عنه."},
  {'n': '98', 'v': "أَوَأَمِنَ أَهْلُ ٱلْقُرَىٰٓ أَن يَأْتِيَهُم بَأْسُنَا ضُحًۭى وَهُمْ يَلْعَبُونَ", 't': "«أو أمن أهل القرى أن يأتيهم بأسنا ضحى» نهارا «وهم يلعبون»."},
  {'n': '99', 'v': "أَفَأَمِنُوا۟ مَكْرَ ٱللَّهِ ۚ فَلَا يَأْمَنُ مَكْرَ ٱللَّهِ إِلَّا ٱلْقَوْمُ ٱلْخَٰسِرُونَ", 't': "«أفأمنوا مكر الله» استدراجه إياهم بالنعمة وأخذهم بغتة «فلا يأمن مكر الله إلا القوم الخاسرون»."},
  {'n': '100', 'v': "أَوَلَمْ يَهْدِ لِلَّذِينَ يَرِثُونَ ٱلْأَرْضَ مِنۢ بَعْدِ أَهْلِهَآ أَن لَّوْ نَشَآءُ أَصَبْنَٰهُم بِذُنُوبِهِمْ ۚ وَنَطْبَعُ عَلَىٰ قُلُوبِهِمْ فَهُمْ لَا يَسْمَعُونَ", 't': "«أو لم يهد» يتبيَّن «للذين يرثون الأرض» بالسكنى «من بعد» هلاك «أهلها أن» فاعل مخففة واسمها محذوف أي أنه «لو نشاء أصبناهم» بالعذاب «بذنوبهم» كما أصبنا من قبلهم. والهمزةُ في المواضع الأربعة للتوبيخ والفاء والواو الداخلة عليهما للعطف، وفي قراءة بسكون الواو في الموضع الأول عطفا بأو «و» نحن «نطبع» نختم «على قلوبهم فهم لا يسمعون» الموعظة سماع تدبر."},
  {'n': '101', 'v': "تِلْكَ ٱلْقُرَىٰ نَقُصُّ عَلَيْكَ مِنْ أَنۢبَآئِهَا ۚ وَلَقَدْ جَآءَتْهُمْ رُسُلُهُم بِٱلْبَيِّنَٰتِ فَمَا كَانُوا۟ لِيُؤْمِنُوا۟ بِمَا كَذَّبُوا۟ مِن قَبْلُ ۚ كَذَٰلِكَ يَطْبَعُ ٱللَّهُ عَلَىٰ قُلُوبِ ٱلْكَٰفِرِينَ", 't': "«تلك القرى» التي مرَّ ذكرها «نقصُّ عليك» يا محمد «من أنبائها» أخبار أهلها «ولقد جاءتهم رسلهم بالبينات» المعجزات الظاهرات «فما كانوا ليؤمنوا» عند مجيئهم «بما كذبوا» كفروا به «من قبل» قبل مجيئهم بل استمروا على الكفر «كذلك» الطبع «يطبع الله على قلوب الكافرين»."},
  {'n': '102', 'v': "وَمَا وَجَدْنَا لِأَكْثَرِهِم مِّنْ عَهْدٍۢ ۖ وَإِن وَجَدْنَآ أَكْثَرَهُمْ لَفَٰسِقِينَ", 't': "«وما وجدنا لأكثرهم» أي الناس «من عهد» أي وفاء بعهدهم يوم أخذ الميثاق «وإن» مخففة «وجدنا أكثرهم لفاسقين»."},
  {'n': '103', 'v': "ثُمَّ بَعَثْنَا مِنۢ بَعْدِهِم مُّوسَىٰ بِـَٔايَٰتِنَآ إِلَىٰ فِرْعَوْنَ وَمَلَإِي۟هِۦ فَظَلَمُوا۟ بِهَا ۖ فَٱنظُرْ كَيْفَ كَانَ عَٰقِبَةُ ٱلْمُفْسِدِينَ", 't': "«ثم بعثنا من بعدهم» أي الرسل المذكورين «موسى بآياتنا» التسع «إلى فرعون وملئِهِ» قومه «فظلموا» كفروا «بها فانظر كيف كان عاقبة المفسدين» بالكفر من إهلاكهم."},
  {'n': '104', 'v': "وَقَالَ مُوسَىٰ يَٰفِرْعَوْنُ إِنِّى رَسُولٌۭ مِّن رَّبِّ ٱلْعَٰلَمِينَ", 't': "«وقال موسى يا فرعون إني رسول من ربِّ العالمين» إليك فكذبه فقال أنا."},
  {'n': '105', 'v': "حَقِيقٌ عَلَىٰٓ أَن لَّآ أَقُولَ عَلَى ٱللَّهِ إِلَّا ٱلْحَقَّ ۚ قَدْ جِئْتُكُم بِبَيِّنَةٍۢ مِّن رَّبِّكُمْ فَأَرْسِلْ مَعِىَ بَنِىٓ إِسْرَٰٓءِيلَ", 't': "«حقيق» جدير «على أن» أي بأن «لا أقول على الله إلا الحق» وفي قراءة بتشديد الياء فحقيق مبتدأ خبره أن وما بعده «قد جئتكم ببينة من ربِّكم فأرسل معي» إلى الشام «بني إسرائيل» وكان استعبدهم."},
  {'n': '106', 'v': "قَالَ إِن كُنتَ جِئْتَ بِـَٔايَةٍۢ فَأْتِ بِهَآ إِن كُنتَ مِنَ ٱلصَّٰدِقِينَ", 't': "«قال» فرعون له «إن كنت جئت بآية» على دعواك «فأت بها إن كنت من الصادقين» فيها."},
  {'n': '107', 'v': "فَأَلْقَىٰ عَصَاهُ فَإِذَا هِىَ ثُعْبَانٌۭ مُّبِينٌۭ", 't': "«فألقى عصاه فإذا هي ثعبان مبين» حية عظيمة."},
  {'n': '108', 'v': "وَنَزَعَ يَدَهُۥ فَإِذَا هِىَ بَيْضَآءُ لِلنَّٰظِرِينَ", 't': "«ونزع يده» أخرجها من جيبه «فإذا هي بيضاء» ذات شعاع «للناظرين» خلاف ما كانت عليه من الأدمة."},
  {'n': '109', 'v': "قَالَ ٱلْمَلَأُ مِن قَوْمِ فِرْعَوْنَ إِنَّ هَٰذَا لَسَٰحِرٌ عَلِيمٌۭ", 't': "«قال الملأ من قوم فرعون إنَّ هذا لساحر عليم» فائق في علم السحر. وفي الشعراء أنه من قول فرعون نفسه فكأنهم قالوه معه على سبيل التشاور."},
  {'n': '110', 'v': "يُرِيدُ أَن يُخْرِجَكُم مِّنْ أَرْضِكُمْ ۖ فَمَاذَا تَأْمُرُونَ", 't': "«يريد أن يخرجكم من أرضكم فماذا تأمرون»."},
  {'n': '111', 'v': "قَالُوٓا۟ أَرْجِهْ وَأَخَاهُ وَأَرْسِلْ فِى ٱلْمَدَآئِنِ حَٰشِرِينَ", 't': "«قالوا أرجه وأخاه» أخِّرْ أمرهما «وأرسل في المدائن حاشرين» جامعين."},
  {'n': '112', 'v': "يَأْتُوكَ بِكُلِّ سَٰحِرٍ عَلِيمٍۢ", 't': "«يأتوك بكل ساحر» وفي قراءة سحَّار «عليم» بفضل موسى في علم السحر فجمعوا."},
  {'n': '113', 'v': "وَجَآءَ ٱلسَّحَرَةُ فِرْعَوْنَ قَالُوٓا۟ إِنَّ لَنَا لَأَجْرًا إِن كُنَّا نَحْنُ ٱلْغَٰلِبِينَ", 't': "«وجاء السحرة فرعون قالوا أئِنَّ» بتحقيق الهمزتين وتسهيل الثانية وإدخال ألف بينهما على الوجهين «لنا لأجرا إن كنا نحن الغالبين»."},
  {'n': '114', 'v': "قَالَ نَعَمْ وَإِنَّكُمْ لَمِنَ ٱلْمُقَرَّبِينَ", 't': "«قال نعم وإنكم لمن المقربين»."},
  {'n': '115', 'v': "قَالُوا۟ يَٰمُوسَىٰٓ إِمَّآ أَن تُلْقِىَ وَإِمَّآ أَن نَّكُونَ نَحْنُ ٱلْمُلْقِينَ", 't': "«قالوا يا موسى إما أن تُلقي» عصاك «وإما أن نكون نحن الملقين» ما معنا."},
  {'n': '116', 'v': "قَالَ أَلْقُوا۟ ۖ فَلَمَّآ أَلْقَوْا۟ سَحَرُوٓا۟ أَعْيُنَ ٱلنَّاسِ وَٱسْتَرْهَبُوهُمْ وَجَآءُو بِسِحْرٍ عَظِيمٍۢ", 't': "«قال ألقوا» أمر للإذن بتقديم إلقائهم توصلا به إلى إظهار الحق «فلما ألقوا» حبالهم وعصيهم «سحروا أعين الناس» صرفوها عن حقيقة إدراكها «واسترهبوهم» خوفوهم حيث خيلوها حيات تسعى «وجاءوا بسحر عظيم»."},
  {'n': '117', 'v': "۞ وَأَوْحَيْنَآ إِلَىٰ مُوسَىٰٓ أَنْ أَلْقِ عَصَاكَ ۖ فَإِذَا هِىَ تَلْقَفُ مَا يَأْفِكُونَ", 't': "«وأوحينا إلى موسى أن ألق عصاك فإذا هي تلقف» بحذف إحدى التاءين في الأصل تبتلع «ما يأفكون» يقلبون بتمويههم."},
  {'n': '118', 'v': "فَوَقَعَ ٱلْحَقُّ وَبَطَلَ مَا كَانُوا۟ يَعْمَلُونَ", 't': "«فوقع الحق» ثبت وظهر «وبطل ما كانوا يعملون» من السحر."},
  {'n': '119', 'v': "فَغُلِبُوا۟ هُنَالِكَ وَٱنقَلَبُوا۟ صَٰغِرِينَ", 't': "«فغُلبوا» أي فرعون وقومه «هنالك وانقلبوا صاغرين» صاروا ذليلين."},
  {'n': '120', 'v': "وَأُلْقِىَ ٱلسَّحَرَةُ سَٰجِدِينَ", 't': "«وأُلقي السحرة ساجدين»."},
  {'n': '121', 'v': "قَالُوٓا۟ ءَامَنَّا بِرَبِّ ٱلْعَٰلَمِينَ", 't': "«قالوا آمنا برب العالمين»."},
  {'n': '122', 'v': "رَبِّ مُوسَىٰ وَهَٰرُونَ", 't': "«رب موسى وهارون» لعلمهم بأن ما شهدوه من العصا لا يتأتى بالسحر."},
  {'n': '123', 'v': "قَالَ فِرْعَوْنُ ءَامَنتُم بِهِۦ قَبْلَ أَنْ ءَاذَنَ لَكُمْ ۖ إِنَّ هَٰذَا لَمَكْرٌۭ مَّكَرْتُمُوهُ فِى ٱلْمَدِينَةِ لِتُخْرِجُوا۟ مِنْهَآ أَهْلَهَا ۖ فَسَوْفَ تَعْلَمُونَ", 't': "«قال فرعون أآمنتم» بتحقيق الهمزتين وإبدال الثانية ألفا «به» بموسى «قبل أن آذن» «لكم إنَّ هذا» الذي صنعتموه «لمكر مكرتموه في المدينة لتخرجوا منها أهلها فسوف تعلمون» ما ينالكم مني."},
  {'n': '124', 'v': "لَأُقَطِّعَنَّ أَيْدِيَكُمْ وَأَرْجُلَكُم مِّنْ خِلَٰفٍۢ ثُمَّ لَأُصَلِّبَنَّكُمْ أَجْمَعِينَ", 't': "«لأقطعنَّ أيديكم وأرجلكم من خلاف» أي يد كل واحد اليمنى ورجله اليسرى «ثم لأصلِّبنَّكم أجمعين»."},
  {'n': '125', 'v': "قَالُوٓا۟ إِنَّآ إِلَىٰ رَبِّنَا مُنقَلِبُونَ", 't': "«قالوا إنا إلى ربِّنا» بعد موتنا بأي وجه كان «منقلبون» راجعون في الآخرة."},
  {'n': '126', 'v': "وَمَا تَنقِمُ مِنَّآ إِلَّآ أَنْ ءَامَنَّا بِـَٔايَٰتِ رَبِّنَا لَمَّا جَآءَتْنَا ۚ رَبَّنَآ أَفْرِغْ عَلَيْنَا صَبْرًۭا وَتَوَفَّنَا مُسْلِمِينَ", 't': "«وما تنقم» تنكر «منا إلا أن آمنَّا بآيات ربِّنا لما جاءتنا ربنا أفرغ علينا صبرا» عند فعل ما توعدنا به لئلا نرجع كفارا «وتوفنا مسلمين»."},
  {'n': '127', 'v': "وَقَالَ ٱلْمَلَأُ مِن قَوْمِ فِرْعَوْنَ أَتَذَرُ مُوسَىٰ وَقَوْمَهُۥ لِيُفْسِدُوا۟ فِى ٱلْأَرْضِ وَيَذَرَكَ وَءَالِهَتَكَ ۚ قَالَ سَنُقَتِّلُ أَبْنَآءَهُمْ وَنَسْتَحْىِۦ نِسَآءَهُمْ وَإِنَّا فَوْقَهُمْ قَٰهِرُونَ", 't': "«وقال الملأ من قوم فرعون» له «أتذر» تترك «موسى وقومه ليفسدوا في الأرض» بالدعاء إلى مخالفتك «ويذرك وآلهتك» وكان صنع لهم أصناما صغارا يعبدونها وقال أنا ربُّكم وربها ولذا قال أنا ربكم الأعلى «قال سنُقَتِّل» بالتشديد والتخفيف «أبناءهم» المولودين «ونستحي» نستبقي «نساءهم» كفعلنا بهم من قبل «وإنا فوقهم قاهرون» قادرون ففعلوا بهم ذلك فشكا بنو إسرائيل."},
  {'n': '128', 'v': "قَالَ مُوسَىٰ لِقَوْمِهِ ٱسْتَعِينُوا۟ بِٱللَّهِ وَٱصْبِرُوٓا۟ ۖ إِنَّ ٱلْأَرْضَ لِلَّهِ يُورِثُهَا مَن يَشَآءُ مِنْ عِبَادِهِۦ ۖ وَٱلْعَٰقِبَةُ لِلْمُتَّقِينَ", 't': "«قال موسى لقومه استعينوا بالله واصبروا» على أذاهم «إنَّ الأرض لله يورثها» يعطيها «من يشاء من عباده والعاقبة» المحمودة «للمتقين» الله."},
  {'n': '129', 'v': "قَالُوٓا۟ أُوذِينَا مِن قَبْلِ أَن تَأْتِيَنَا وَمِنۢ بَعْدِ مَا جِئْتَنَا ۚ قَالَ عَسَىٰ رَبُّكُمْ أَن يُهْلِكَ عَدُوَّكُمْ وَيَسْتَخْلِفَكُمْ فِى ٱلْأَرْضِ فَيَنظُرَ كَيْفَ تَعْمَلُونَ", 't': "«قالوا أوذينا من قبل أن تأتينا ومن بعد ما جئتنا قال عسى ربُّكم أن يهلك عدوكم ويستخلفكم في الأرض فينظر كيف تعملون» فيها."},
  {'n': '130', 'v': "وَلَقَدْ أَخَذْنَآ ءَالَ فِرْعَوْنَ بِٱلسِّنِينَ وَنَقْصٍۢ مِّنَ ٱلثَّمَرَٰتِ لَعَلَّهُمْ يَذَّكَّرُونَ", 't': "«ولقد أخذنا آل فرعون بالسِّنين» بالقحط «ونقص من الثمرات لعلهم يذكرون» يتعظون فيؤمنون."},
  {'n': '131', 'v': "فَإِذَا جَآءَتْهُمُ ٱلْحَسَنَةُ قَالُوا۟ لَنَا هَٰذِهِۦ ۖ وَإِن تُصِبْهُمْ سَيِّئَةٌۭ يَطَّيَّرُوا۟ بِمُوسَىٰ وَمَن مَّعَهُۥٓ ۗ أَلَآ إِنَّمَا طَٰٓئِرُهُمْ عِندَ ٱللَّهِ وَلَٰكِنَّ أَكْثَرَهُمْ لَا يَعْلَمُونَ", 't': "«فإذا جاءتهم الحسنة» الخصب والغنى «قالوا لنا هذه» أي نستحقها ولم يشكروا عليها «وإن تصبهم سيئة» جدب وبلاء «يَطَّيَّروا» يتشاءموا «بموسى ومن معه» من المؤمنين «ألا إنما طائرهم» شؤمهم «عند الله» يأتيهم به «ولكن أكثرهم لا يعلمون» أنَّ ما يصيبهم من عنده."},
  {'n': '132', 'v': "وَقَالُوا۟ مَهْمَا تَأْتِنَا بِهِۦ مِنْ ءَايَةٍۢ لِّتَسْحَرَنَا بِهَا فَمَا نَحْنُ لَكَ بِمُؤْمِنِينَ", 't': "«وقالوا» لموسى «مهما تأتنا به من آية لتسحرنا بها فما نحن لك بمؤمنين» فدعا عليهم."},
  {'n': '133', 'v': "فَأَرْسَلْنَا عَلَيْهِمُ ٱلطُّوفَانَ وَٱلْجَرَادَ وَٱلْقُمَّلَ وَٱلضَّفَادِعَ وَٱلدَّمَ ءَايَٰتٍۢ مُّفَصَّلَٰتٍۢ فَٱسْتَكْبَرُوا۟ وَكَانُوا۟ قَوْمًۭا مُّجْرِمِينَ", 't': "«فأرسلنا عليهم الطُّوفان» وهو ماء دخل بيوتهم ووصل إلى حلوق الجالسين سبعة أيام «والجراد» فأكل زرعهم وثمارهم، كذلك «والقمَّل» السوس أو نوع من القراد، فتتبع ما تركه الجراد «والضفادع» فملأت بيوتهم وطعامهم «والدم» في مياههم «آياتِ مفصَّلاتِ» مبينات «فاستكبروا» عن الإيمان بها «وكانوا قوما مجرمين»."},
  {'n': '134', 'v': "وَلَمَّا وَقَعَ عَلَيْهِمُ ٱلرِّجْزُ قَالُوا۟ يَٰمُوسَى ٱدْعُ لَنَا رَبَّكَ بِمَا عَهِدَ عِندَكَ ۖ لَئِن كَشَفْتَ عَنَّا ٱلرِّجْزَ لَنُؤْمِنَنَّ لَكَ وَلَنُرْسِلَنَّ مَعَكَ بَنِىٓ إِسْرَٰٓءِيلَ", 't': "«ولما وقع عليهم الرجز» العذاب «قالوا يا موسى ادع لنا ربَّك بما عهد عندك» من كشف العذاب عنا إن آمنا «لئن» لام قسم «كشفت عنا الرجز لنؤمنن لك ولنرسلنَّ معك بني إسرائيل»."},
  {'n': '135', 'v': "فَلَمَّا كَشَفْنَا عَنْهُمُ ٱلرِّجْزَ إِلَىٰٓ أَجَلٍ هُم بَٰلِغُوهُ إِذَا هُمْ يَنكُثُونَ", 't': "«فلمًّا كشفنا» بدعاء موسى «عنهم الرجز إلى أجل هم بالغوه إذا هم ينكثون» ينقضون عهدهم ويصرون على كفرهم."},
  {'n': '136', 'v': "فَٱنتَقَمْنَا مِنْهُمْ فَأَغْرَقْنَٰهُمْ فِى ٱلْيَمِّ بِأَنَّهُمْ كَذَّبُوا۟ بِـَٔايَٰتِنَا وَكَانُوا۟ عَنْهَا غَٰفِلِينَ", 't': "«فانتقمنا منهم فأغرقناهم في اليمِّ» البحر الملح «بأنهم» بسبب أنهم «كذَّبوا بآياتنا وكانوا عنها غافلين» لا يتدبرونها."},
  {'n': '137', 'v': "وَأَوْرَثْنَا ٱلْقَوْمَ ٱلَّذِينَ كَانُوا۟ يُسْتَضْعَفُونَ مَشَٰرِقَ ٱلْأَرْضِ وَمَغَٰرِبَهَا ٱلَّتِى بَٰرَكْنَا فِيهَا ۖ وَتَمَّتْ كَلِمَتُ رَبِّكَ ٱلْحُسْنَىٰ عَلَىٰ بَنِىٓ إِسْرَٰٓءِيلَ بِمَا صَبَرُوا۟ ۖ وَدَمَّرْنَا مَا كَانَ يَصْنَعُ فِرْعَوْنُ وَقَوْمُهُۥ وَمَا كَانُوا۟ يَعْرِشُونَ", 't': "«وأورثنا القوم الذين كانوا يُستضعفون» بالاستعباد، وهم بنو إسرائيل «مشارق الأرض ومغاربها التي باركنا فيها» بالماء والشجر، صفة للأرض وهي الشام «وتمت كلمة ربَّك الحسنى» وهي قوله تعالى (ونريد أن نمنَّ على الذين استضعفوا في الأرض) إلخ «على بني إسرائيل بما صبروا» على أذى عدوهم «ودمَّرنا» أهلكنا «ما كان يصنع فرعون وقومه» من العمارة «وما كانوا يعرُِشون» بكسر الراء وضمها، يرفعون من البنيان."},
  {'n': '138', 'v': "وَجَٰوَزْنَا بِبَنِىٓ إِسْرَٰٓءِيلَ ٱلْبَحْرَ فَأَتَوْا۟ عَلَىٰ قَوْمٍۢ يَعْكُفُونَ عَلَىٰٓ أَصْنَامٍۢ لَّهُمْ ۚ قَالُوا۟ يَٰمُوسَى ٱجْعَل لَّنَآ إِلَٰهًۭا كَمَا لَهُمْ ءَالِهَةٌۭ ۚ قَالَ إِنَّكُمْ قَوْمٌۭ تَجْهَلُونَ", 't': "«وجاوزنا» عبرنا «ببني إسرائيل البحر فأتوا» فمروا «على قوم يعكُِفون» بضم الكاف وكسرها «على أصنام لهم» على عبادتها «قالوا يا موسى لنا اجعل إلها» صنما نعبده «كما لهم آلهة قال إنكم قوم تجهلون» حيث قابلتم نعمة الله عليكم بما قلتموه."},
  {'n': '139', 'v': "إِنَّ هَٰٓؤُلَآءِ مُتَبَّرٌۭ مَّا هُمْ فِيهِ وَبَٰطِلٌۭ مَّا كَانُوا۟ يَعْمَلُونَ", 't': "«إن هؤلاء مُتَبَّرٌ» هالك «ما هم فيه وباطل ما كانوا يعملون»."},
  {'n': '140', 'v': "قَالَ أَغَيْرَ ٱللَّهِ أَبْغِيكُمْ إِلَٰهًۭا وَهُوَ فَضَّلَكُمْ عَلَى ٱلْعَٰلَمِينَ", 't': "«قال أغير الله أبغيكم إلها» معبودا وأصله أبغي لكم «وهو فضَّلكم على العالمين» في زمانكم بما ذكره في قوله."},
  {'n': '141', 'v': "وَإِذْ أَنجَيْنَٰكُم مِّنْ ءَالِ فِرْعَوْنَ يَسُومُونَكُمْ سُوٓءَ ٱلْعَذَابِ ۖ يُقَتِّلُونَ أَبْنَآءَكُمْ وَيَسْتَحْيُونَ نِسَآءَكُمْ ۚ وَفِى ذَٰلِكُم بَلَآءٌۭ مِّن رَّبِّكُمْ عَظِيمٌۭ", 't': "«و» اذكروا «إذ أنجيناكم» وفي قراءة أنجاكم «من آل فرعون يسومونكم» يكلفونكم ويذيقونكم «سوء العذاب» أشده وهو «يقتلون أبناءكم ويستحيون» يستَبْقون «نساءكم وفي ذلكم» الإنجاء أو العذاب «بلاء» إنعام أو ابتلاء «من ربِّكم عظيم» أفلا تتعظون فتنتهوا عما قلتم."},
  {'n': '142', 'v': "۞ وَوَٰعَدْنَا مُوسَىٰ ثَلَٰثِينَ لَيْلَةًۭ وَأَتْمَمْنَٰهَا بِعَشْرٍۢ فَتَمَّ مِيقَٰتُ رَبِّهِۦٓ أَرْبَعِينَ لَيْلَةًۭ ۚ وَقَالَ مُوسَىٰ لِأَخِيهِ هَٰرُونَ ٱخْلُفْنِى فِى قَوْمِى وَأَصْلِحْ وَلَا تَتَّبِعْ سَبِيلَ ٱلْمُفْسِدِينَ", 't': "«وواعدنا» بألف ودونها «موسى ثلاثين ليلة» نكلمه عند انتهائها بأن يصومها، وهي ذو القعدة فصامها فلما تمَّت أنكر خلوف فمه فاستاك فأمره الله بعشرة أخرى ليكلمه بخلوف فمه كما قال تعالى: «وأتممناها بعشر» من ذي الحجة «فتم ميقات ربِّه» وقت وعده بكلامه إياه «أربعين» حال «ليلة» تتميز «وقال موسى لأخيه هارون» عند ذهابه إلى الجبل للمناجاة «اخلفني» كن خليفتي «في قومي وأصلح» أمرهم «ولا تتبع سبيل المفسدين» بموافقتهم على المعاصي."},
  {'n': '143', 'v': "وَلَمَّا جَآءَ مُوسَىٰ لِمِيقَٰتِنَا وَكَلَّمَهُۥ رَبُّهُۥ قَالَ رَبِّ أَرِنِىٓ أَنظُرْ إِلَيْكَ ۚ قَالَ لَن تَرَىٰنِى وَلَٰكِنِ ٱنظُرْ إِلَى ٱلْجَبَلِ فَإِنِ ٱسْتَقَرَّ مَكَانَهُۥ فَسَوْفَ تَرَىٰنِى ۚ فَلَمَّا تَجَلَّىٰ رَبُّهُۥ لِلْجَبَلِ جَعَلَهُۥ دَكًّۭا وَخَرَّ مُوسَىٰ صَعِقًۭا ۚ فَلَمَّآ أَفَاقَ قَالَ سُبْحَٰنَكَ تُبْتُ إِلَيْكَ وَأَنَا۠ أَوَّلُ ٱلْمُؤْمِنِينَ", 't': "«ولما جاء موسى لميقاتنا» أي للوقت الذي وعدناه بالكلام فيه «وكلَّمه ربُّه» بلا واسطة كلاما سمعه من كل جهة «قال رب أرني» نفسك «أنظر إليك قال لن تراني» أي لا تقدر على رؤيتي، والتعبير به دون لن أرى يفيد إمكان رؤيته تعالى «ولكن انظر إلى الجبل» الذي هو أقوى منك «فإن استقر» ثبت «مكانه فسوف تراني» أي تثبيت لرؤيتي وإلا فلا طاقة لك «فلما تجلَّى ربُّه» أي ظهر من نوره قدر نصف أنملة الخنصر كما في حديث صححه الحاكم «للجبل جعله دكا» بالقصر والمد، أي مدكوكا مستويا بالأرض «وخرَّ موسى صَعقا» مغشيا عليه لهول ما رأى «فلما أفاق قال سبحانك» تنزيها لك «تبت إليك» من سؤال ما لم أؤمر به «وأنا أوَّلُ المؤمنين» في زماني."},
  {'n': '144', 'v': "قَالَ يَٰمُوسَىٰٓ إِنِّى ٱصْطَفَيْتُكَ عَلَى ٱلنَّاسِ بِرِسَٰلَٰتِى وَبِكَلَٰمِى فَخُذْ مَآ ءَاتَيْتُكَ وَكُن مِّنَ ٱلشَّٰكِرِينَ", 't': "«قال» تعالى له «يا موسى إني اصطفيتك» اخترتك «على الناس» أهل زمانك «برسالاتي» بالجمع والإفراد «وبكلامي» أي تكليمي إياك «فخذ ما آتيتك» من الفضل «وكن من الشاكرين» لأنعمي."},
  {'n': '145', 'v': "وَكَتَبْنَا لَهُۥ فِى ٱلْأَلْوَاحِ مِن كُلِّ شَىْءٍۢ مَّوْعِظَةًۭ وَتَفْصِيلًۭا لِّكُلِّ شَىْءٍۢ فَخُذْهَا بِقُوَّةٍۢ وَأْمُرْ قَوْمَكَ يَأْخُذُوا۟ بِأَحْسَنِهَا ۚ سَأُو۟رِيكُمْ دَارَ ٱلْفَٰسِقِينَ", 't': "«وكتبا له في الألواح» أي ألواح التوراة وكانت من سدر الجنة أو زبرجد أو زمرد سبعة أو عشرة «من كل شيء» يحتاج إليه في الدين «موعظة وتفصيلا» تبينا «لكل شيء» بدل من الجار والمجرور قبله «فخذها» قبله قلنا مقدرا «بقوة» بجد واجتهاد «وأمر قومك يأخذوا بأحسنها سأريكم دار الفاسقين» فرعون وأتباعه وهي مصر لتعتبروا بهم."},
  {'n': '146', 'v': "سَأَصْرِفُ عَنْ ءَايَٰتِىَ ٱلَّذِينَ يَتَكَبَّرُونَ فِى ٱلْأَرْضِ بِغَيْرِ ٱلْحَقِّ وَإِن يَرَوْا۟ كُلَّ ءَايَةٍۢ لَّا يُؤْمِنُوا۟ بِهَا وَإِن يَرَوْا۟ سَبِيلَ ٱلرُّشْدِ لَا يَتَّخِذُوهُ سَبِيلًۭا وَإِن يَرَوْا۟ سَبِيلَ ٱلْغَىِّ يَتَّخِذُوهُ سَبِيلًۭا ۚ ذَٰلِكَ بِأَنَّهُمْ كَذَّبُوا۟ بِـَٔايَٰتِنَا وَكَانُوا۟ عَنْهَا غَٰفِلِينَ", 't': "«سأصرف عن آياتي» دلائل قدرتي من المصنوعات وغيرها «الذين يتكبرون في الأرض بغير الحق» بأن أخذلهم فلا يتكبرون فيها «وإن يروا كل آية لا يؤمنوا بها وإن يروا سبيل» طريق «الرُّشد» الهدى الذي جاء من عند الله «لا يتخذوه سبيلا» يسلكوه «وإن يروا سبيل الغي» الضلال «يتخذوه سبيلا ذلك» الصرف «بأنهم كذبوا بآياتنا وكانوا عنها غافلين» تقدم مثله."},
  {'n': '147', 'v': "وَٱلَّذِينَ كَذَّبُوا۟ بِـَٔايَٰتِنَا وَلِقَآءِ ٱلْءَاخِرَةِ حَبِطَتْ أَعْمَٰلُهُمْ ۚ هَلْ يُجْزَوْنَ إِلَّا مَا كَانُوا۟ يَعْمَلُونَ", 't': "«والذين كذبوا بآياتنا ولقاء الآخرة» البعث وغيره «حبطت» بطَلَت «أعمالهم» ما عملوه في الدنيا من خير كصلة رحم وصدقة فلا ثواب لهم لعدم شرطه «هل» ما «يُجزون إلا» جزاء «ما كانوا يعملون» من التكذيب والمعاصي."},
  {'n': '148', 'v': "وَٱتَّخَذَ قَوْمُ مُوسَىٰ مِنۢ بَعْدِهِۦ مِنْ حُلِيِّهِمْ عِجْلًۭا جَسَدًۭا لَّهُۥ خُوَارٌ ۚ أَلَمْ يَرَوْا۟ أَنَّهُۥ لَا يُكَلِّمُهُمْ وَلَا يَهْدِيهِمْ سَبِيلًا ۘ ٱتَّخَذُوهُ وَكَانُوا۟ ظَٰلِمِينَ", 't': "«واتخذ قوم موسى من بعده» أي بعد ذهابه إلى المناجاة «من حُليِّهم» الذي استعاروه من قوم فرعون بعلَّة عرس فبقي عندهم «عجلا» صاغه لهم منه السامري «جسدا» بدل لحما ودما «له خُوارٌ» أي صوت يسمع، انقلب كذلك بوضع التراب الذي أخذه من حافر فرس جبريل في فمه فإن أثره الحياة فيما يوضع فيه، ومفعول اتخذ الثاني محذوف أي إلها «ألم يروا أنه لا يكلِّمهم ولا يهديهم سبيلا» فكيف يُتَّخذ إلها «اتخذوه» إلها «وكانوا ظالمين» باتخاذه."},
  {'n': '149', 'v': "وَلَمَّا سُقِطَ فِىٓ أَيْدِيهِمْ وَرَأَوْا۟ أَنَّهُمْ قَدْ ضَلُّوا۟ قَالُوا۟ لَئِن لَّمْ يَرْحَمْنَا رَبُّنَا وَيَغْفِرْ لَنَا لَنَكُونَنَّ مِنَ ٱلْخَٰسِرِينَ", 't': "«ولما سُقط في أيديهم» أي ندموا على عبادته «ورأوْا» علموا «أنهم قد ضلوا» بها وذلك بعد رجوع موسى «وقالوا لئن لم يرحْمنا ربنا ويغفرْ لنا» بالياء والتاء فيهما «لنكونن من الخاسرين»."},
  {'n': '150', 'v': "وَلَمَّا رَجَعَ مُوسَىٰٓ إِلَىٰ قَوْمِهِۦ غَضْبَٰنَ أَسِفًۭا قَالَ بِئْسَمَا خَلَفْتُمُونِى مِنۢ بَعْدِىٓ ۖ أَعَجِلْتُمْ أَمْرَ رَبِّكُمْ ۖ وَأَلْقَى ٱلْأَلْوَاحَ وَأَخَذَ بِرَأْسِ أَخِيهِ يَجُرُّهُۥٓ إِلَيْهِ ۚ قَالَ ٱبْنَ أُمَّ إِنَّ ٱلْقَوْمَ ٱسْتَضْعَفُونِى وَكَادُوا۟ يَقْتُلُونَنِى فَلَا تُشْمِتْ بِىَ ٱلْأَعْدَآءَ وَلَا تَجْعَلْنِى مَعَ ٱلْقَوْمِ ٱلظَّٰلِمِينَ", 't': "«ولما رجع موسى إلى قومه غضبان» من جهتهم «أسفا» شديد الحزن «قال» «بئسما» أي بئس خلافة «خلفتموني» ها «من بعدي» خلافتكم هذه حيث أشركتم «أعجلتم أمر ربكم وألقى الألواح» ألواح التوراة غضبا لربه فتكسرت «وأخذ برأس أخيه» أي شعره بيمينه ولحيته بشماله «يجره إليه» غضبا «قال» يا «ابْنَ أُمِّ» بكسر الميم وفتحها، أراد أمي وذكرها أعطف لقبله «إن القوم استضعفوني وكادوا» قاربوا «يقتلونني فلا تُشْمت» تُفرح «بي الأعداء» بإهانتك إياي «ولا تجعلني مع القوم الظالمين» بعبادة العجل في المؤاخذة."},
  {'n': '151', 'v': "قَالَ رَبِّ ٱغْفِرْ لِى وَلِأَخِى وَأَدْخِلْنَا فِى رَحْمَتِكَ ۖ وَأَنتَ أَرْحَمُ ٱلرَّٰحِمِينَ", 't': "«قال رب اغفر لي» ما صنعت بأخي «ولأخي» أشركه في الدعاء إرضاءً له ودفعا للشماتة به «وأدخلنا في رحمتك وأنت أرحم الراحمين» قال تعالى."},
  {'n': '152', 'v': "إِنَّ ٱلَّذِينَ ٱتَّخَذُوا۟ ٱلْعِجْلَ سَيَنَالُهُمْ غَضَبٌۭ مِّن رَّبِّهِمْ وَذِلَّةٌۭ فِى ٱلْحَيَوٰةِ ٱلدُّنْيَا ۚ وَكَذَٰلِكَ نَجْزِى ٱلْمُفْتَرِينَ", 't': "«إن الذين اتخذوا العجل» إلها «سينالهم غضب» عذاب «من ربِّهم وذلَّة في الحياة الدنيا» فعذبوا بالأمر بقتل أنفسهم وضربت عليهم الذلة إلى يوم القيامة «وكذلك» كما جزيناهم «نجزي المفترين» على الله بالإشراك وغيره."},
  {'n': '153', 'v': "وَٱلَّذِينَ عَمِلُوا۟ ٱلسَّيِّـَٔاتِ ثُمَّ تَابُوا۟ مِنۢ بَعْدِهَا وَءَامَنُوٓا۟ إِنَّ رَبَّكَ مِنۢ بَعْدِهَا لَغَفُورٌۭ رَّحِيمٌۭ", 't': "«والذين عملوا السيَّئات ثم تابوا» رجعوا عنها «من بعدها وآمنوا» بالله «إن ربَّك من بعدها» أي التوبة «لغفور» لهم «رحيم» بهم."},
  {'n': '154', 'v': "وَلَمَّا سَكَتَ عَن مُّوسَى ٱلْغَضَبُ أَخَذَ ٱلْأَلْوَاحَ ۖ وَفِى نُسْخَتِهَا هُدًۭى وَرَحْمَةٌۭ لِّلَّذِينَ هُمْ لِرَبِّهِمْ يَرْهَبُونَ", 't': "«ولمَّا سكت» سكن «عن موسى الغضب أخذ الألواح» التي ألقاها «وفي نسخَتها» أي ما نسخ فيها، أي كتب «هدىّ» من الضلالة «ورحمهٌ للذين هم لربِّهم يرهبون» يخافون، وأدخل اللام على المفعول لتقدمه."},
  {'n': '155', 'v': "وَٱخْتَارَ مُوسَىٰ قَوْمَهُۥ سَبْعِينَ رَجُلًۭا لِّمِيقَٰتِنَا ۖ فَلَمَّآ أَخَذَتْهُمُ ٱلرَّجْفَةُ قَالَ رَبِّ لَوْ شِئْتَ أَهْلَكْتَهُم مِّن قَبْلُ وَإِيَّٰىَ ۖ أَتُهْلِكُنَا بِمَا فَعَلَ ٱلسُّفَهَآءُ مِنَّآ ۖ إِنْ هِىَ إِلَّا فِتْنَتُكَ تُضِلُّ بِهَا مَن تَشَآءُ وَتَهْدِى مَن تَشَآءُ ۖ أَنتَ وَلِيُّنَا فَٱغْفِرْ لَنَا وَٱرْحَمْنَا ۖ وَأَنتَ خَيْرُ ٱلْغَٰفِرِينَ", 't': "«واختار موسى قومه» أي من قومه «سبعين رجلا» ممن لم يعبدوا العجل بأمره تعالى «لميقاتنا» أي للوقت الذي وعدناه بإتيانهم فيه ليعتذروا من عبادة أصحابهم العجل فخرج بهم «فلما أخذتهم الرجفة» الزلزلة الشديدة، قال ابن عباس: لأنهم لم يزايلوا قومهم حين عبدوا العجل، قال: وهم غير الذين سألوا الرؤية وأخذتهم الصاعقة «قال» موسى «ربِّ لو شئت أهلكتهم من قبل» أي قبل خروجي بهم ليعاين بنو إسرائيل ذلك ولا يتهموني «وإياي أتهلكنا بما فعل السفهاء منا» استفهام استعطاف، أي لا تعذبنا بذنب غيرنا «إن» ما «هي» أي الفتنة التي وقع فيها السفهاء «إلا فتنتُك» ابتلاؤك «تضل بها من تشاء» إضلاله «وتهدي من تشاء» هدايته «أنت ولينا» متولي أمورنا «فاغفر لنا وارحمنا وأنت خير الغافرين»."},
  {'n': '156', 'v': "۞ وَٱكْتُبْ لَنَا فِى هَٰذِهِ ٱلدُّنْيَا حَسَنَةًۭ وَفِى ٱلْءَاخِرَةِ إِنَّا هُدْنَآ إِلَيْكَ ۚ قَالَ عَذَابِىٓ أُصِيبُ بِهِۦ مَنْ أَشَآءُ ۖ وَرَحْمَتِى وَسِعَتْ كُلَّ شَىْءٍۢ ۚ فَسَأَكْتُبُهَا لِلَّذِينَ يَتَّقُونَ وَيُؤْتُونَ ٱلزَّكَوٰةَ وَٱلَّذِينَ هُم بِـَٔايَٰتِنَا يُؤْمِنُونَ", 't': "«واكتب» وأجب «لنا في هذه الدنيا حسنة وفي الآخرة» حسنة «إنَّا هُدْنا» تبنا «إليك قال» تعالى: «عذابي أصيب به من أشاء» تعذيبه «ورحمتي وسعت» عمَّت «كلَّ شيء» في الدنيا «فسأكتبها» في الآخرة «للذين يتقون ويؤتون الزكاة والذين هم بآياتتا يؤمنون»."},
  {'n': '157', 'v': "ٱلَّذِينَ يَتَّبِعُونَ ٱلرَّسُولَ ٱلنَّبِىَّ ٱلْأُمِّىَّ ٱلَّذِى يَجِدُونَهُۥ مَكْتُوبًا عِندَهُمْ فِى ٱلتَّوْرَىٰةِ وَٱلْإِنجِيلِ يَأْمُرُهُم بِٱلْمَعْرُوفِ وَيَنْهَىٰهُمْ عَنِ ٱلْمُنكَرِ وَيُحِلُّ لَهُمُ ٱلطَّيِّبَٰتِ وَيُحَرِّمُ عَلَيْهِمُ ٱلْخَبَٰٓئِثَ وَيَضَعُ عَنْهُمْ إِصْرَهُمْ وَٱلْأَغْلَٰلَ ٱلَّتِى كَانَتْ عَلَيْهِمْ ۚ فَٱلَّذِينَ ءَامَنُوا۟ بِهِۦ وَعَزَّرُوهُ وَنَصَرُوهُ وَٱتَّبَعُوا۟ ٱلنُّورَ ٱلَّذِىٓ أُنزِلَ مَعَهُۥٓ ۙ أُو۟لَٰٓئِكَ هُمُ ٱلْمُفْلِحُونَ", 't': "«الذين يتبعون الرسول النبي الأمي» محمدا صلى الله عليه وسلم «الذي يجدونه مكتوبا عندهم في التوراة والإنجيل» باسمه وصفته «يأمرهم بالمعروف وينهاهم عن المنكر ويحل لهم الطيبات» مما حُرم في شرعهم «ويحرم عليهم الخبائث» من الميتة ونحوها «ويضع عنهم إصرَهُم» ثقلهم «والأغلال» الشدائد «التي كانت عليهم» كقتل النفس من التوبة وقطع أثر النجاسة. «فالذين آمنوا به» منهم «وعَزَّروه» ووقروه «ونصروه واتبعوا النور الذي أنزل معه» أي القرآن «أولئك هم المفلحون»."},
  {'n': '158', 'v': "قُلْ يَٰٓأَيُّهَا ٱلنَّاسُ إِنِّى رَسُولُ ٱللَّهِ إِلَيْكُمْ جَمِيعًا ٱلَّذِى لَهُۥ مُلْكُ ٱلسَّمَٰوَٰتِ وَٱلْأَرْضِ ۖ لَآ إِلَٰهَ إِلَّا هُوَ يُحْىِۦ وَيُمِيتُ ۖ فَـَٔامِنُوا۟ بِٱللَّهِ وَرَسُولِهِ ٱلنَّبِىِّ ٱلْأُمِّىِّ ٱلَّذِى يُؤْمِنُ بِٱللَّهِ وَكَلِمَٰتِهِۦ وَٱتَّبِعُوهُ لَعَلَّكُمْ تَهْتَدُونَ", 't': "«قل» خطاب للنبي صلى الله عليه وسلم «يا أيها الناس إني رسول الله إليكم جميعا الذي له ملك السماوات والأرض لا إله إلا هو يحيي ويميت فآمنوا بالله ورسوله النبي الأمي الذي يؤمن بالله وكلماته» القرآن «واتَّبعوه لعلكم تهتدون» ترشدون."},
  {'n': '159', 'v': "وَمِن قَوْمِ مُوسَىٰٓ أُمَّةٌۭ يَهْدُونَ بِٱلْحَقِّ وَبِهِۦ يَعْدِلُونَ", 't': "«ومن قوم موسى أمَّةٌ» جماعة «يهدون» الناس «بالحق وبه يعدلون» في الحكم."},
  {'n': '160', 'v': "وَقَطَّعْنَٰهُمُ ٱثْنَتَىْ عَشْرَةَ أَسْبَاطًا أُمَمًۭا ۚ وَأَوْحَيْنَآ إِلَىٰ مُوسَىٰٓ إِذِ ٱسْتَسْقَىٰهُ قَوْمُهُۥٓ أَنِ ٱضْرِب بِّعَصَاكَ ٱلْحَجَرَ ۖ فَٱنۢبَجَسَتْ مِنْهُ ٱثْنَتَا عَشْرَةَ عَيْنًۭا ۖ قَدْ عَلِمَ كُلُّ أُنَاسٍۢ مَّشْرَبَهُمْ ۚ وَظَلَّلْنَا عَلَيْهِمُ ٱلْغَمَٰمَ وَأَنزَلْنَا عَلَيْهِمُ ٱلْمَنَّ وَٱلسَّلْوَىٰ ۖ كُلُوا۟ مِن طَيِّبَٰتِ مَا رَزَقْنَٰكُمْ ۚ وَمَا ظَلَمُونَا وَلَٰكِن كَانُوٓا۟ أَنفُسَهُمْ يَظْلِمُونَ", 't': "«وقَطَّعناهم» فّرَّقنا بني إسرائيل «اثنتي عشرة» حال «أسباطا» بدل منه، أي قبائل «أمما» بدل مما قبله «وأوحينا إلى موسى إذ استسقاه قومه» في التيه «أن اضرب بعصاك الحجر» فضربه «فانبجست» انفجرت «منه اثنتا عشرة عينا» بعدد الأسباط «قد علم كل أُناس» سبط منهم «مشربهم وظللنا عليهم الغمام» في التيه من حر الشمس «وأنزلنا عليهم المن والسلوى» هما الترنجبين والطير السماني بتخفيف الميم والقصر وقلنا لهم «كلوا من طيبات ما رزقناكم وما ظلمونا ولكن كانوا أنفسهم يظلمون»."},
  {'n': '161', 'v': "وَإِذْ قِيلَ لَهُمُ ٱسْكُنُوا۟ هَٰذِهِ ٱلْقَرْيَةَ وَكُلُوا۟ مِنْهَا حَيْثُ شِئْتُمْ وَقُولُوا۟ حِطَّةٌۭ وَٱدْخُلُوا۟ ٱلْبَابَ سُجَّدًۭا نَّغْفِرْ لَكُمْ خَطِيٓـَٰٔتِكُمْ ۚ سَنَزِيدُ ٱلْمُحْسِنِينَ", 't': "«و» اذكر «إذ قيل لهم اسكنوا هذه القرية» بيت المقدس «وكلوا منها حيث شئتم وقولوا» أمرنا «حطَّةٌ وادخلوا الباب» أي باب القرية «سجَّدا» سجود انحناء «نغفر» بالنون والتاء مبينا للمفعول «لكم خطيئاتكم سنزيد المحسنين» بالطاعة ثوابا."},
  {'n': '162', 'v': "فَبَدَّلَ ٱلَّذِينَ ظَلَمُوا۟ مِنْهُمْ قَوْلًا غَيْرَ ٱلَّذِى قِيلَ لَهُمْ فَأَرْسَلْنَا عَلَيْهِمْ رِجْزًۭا مِّنَ ٱلسَّمَآءِ بِمَا كَانُوا۟ يَظْلِمُونَ", 't': "«فبدَّل الذين ظلموا منهم قولا غير الذي قيل لهم» فقالوا: حبة في شعرة ودخلوا يزحفون على أستاههم «فأرسلنا عليهم رجزا» عذابا «من السماء بما كانوا يظلمون»."},
  {'n': '163', 'v': "وَسْـَٔلْهُمْ عَنِ ٱلْقَرْيَةِ ٱلَّتِى كَانَتْ حَاضِرَةَ ٱلْبَحْرِ إِذْ يَعْدُونَ فِى ٱلسَّبْتِ إِذْ تَأْتِيهِمْ حِيتَانُهُمْ يَوْمَ سَبْتِهِمْ شُرَّعًۭا وَيَوْمَ لَا يَسْبِتُونَ ۙ لَا تَأْتِيهِمْ ۚ كَذَٰلِكَ نَبْلُوهُم بِمَا كَانُوا۟ يَفْسُقُونَ", 't': "«واسألهم» يا محمد توبيخا «عن القرية التي كانت حاضرة البحر» مجاورة بحر القلزم وهي أيلة ما وقع بأهلها «إذ يعدون» يعتدون «في السبت» بصيد السمك المأمورين بتركه فيه «إذ» ظرف ليعدون «تأتيهم حيتانهم يوم سبتهم شُرَّعا» ظاهرة على الماء «ويوم لا يسبتون» لا يعظمون السبت أي سائر الأيام «لا تأتيهم» ابتلاء من الله «كذلك نبلوهم» بما كانوا يفسقون» ولما صادوا السمك افترقت القرية أثلاثا، ثلث صادوا معهم وثلث نهوهم، وثلث أمسكوا عن الصيد والنهي."},
  {'n': '164', 'v': "وَإِذْ قَالَتْ أُمَّةٌۭ مِّنْهُمْ لِمَ تَعِظُونَ قَوْمًا ۙ ٱللَّهُ مُهْلِكُهُمْ أَوْ مُعَذِّبُهُمْ عَذَابًۭا شَدِيدًۭا ۖ قَالُوا۟ مَعْذِرَةً إِلَىٰ رَبِّكُمْ وَلَعَلَّهُمْ يَتَّقُونَ", 't': "«وإذ» عطف على إذ قبله «قالت أمَّة منهم» لم تصد ولم تنهَ لمن نهى «لم تعظون قوما الله مُهلكهم أو معذبهم عذابا شديدا قالوا» موعظتنا «معذرة» نعتذر بها «إلى ربِّكم» لئلا ننسب إلى تقصير في ترك النهي «ولعلَّهم يتقون» الصيد."},
  {'n': '165', 'v': "فَلَمَّا نَسُوا۟ مَا ذُكِّرُوا۟ بِهِۦٓ أَنجَيْنَا ٱلَّذِينَ يَنْهَوْنَ عَنِ ٱلسُّوٓءِ وَأَخَذْنَا ٱلَّذِينَ ظَلَمُوا۟ بِعَذَابٍۭ بَـِٔيسٍۭ بِمَا كَانُوا۟ يَفْسُقُونَ", 't': "«فما نسوا» تركوا «ما ذكِّروا» وعظوا «به» فلم يرجعوا «أنجينا الذين ينهوْن عن السوء وأخذنا الذين ظلموا» بالاعتداء «بعذابٍ بَئيس» شديد «بما كانوا يفسقون»."},
  {'n': '166', 'v': "فَلَمَّا عَتَوْا۟ عَن مَّا نُهُوا۟ عَنْهُ قُلْنَا لَهُمْ كُونُوا۟ قِرَدَةً خَٰسِـِٔينَ", 't': "«فلما عَتَوا» تكبروا «عن» ترك «ما نهوا عنه قلنا لهم كونوا قردة خاسئين» صاغرين فكانوها، وهذا تفصيل لما قبله، قال ابن عباس: ما أدري ما فعل بالفرقة الساكنة وقال عكرمة: لم تهلك لأنها كرهت ما فعلوه، وقالت: لم تعظون إلخ، وروى الحاكم عن ابن عباس: أنه رجع إليه وأعجبه."},
  {'n': '167', 'v': "وَإِذْ تَأَذَّنَ رَبُّكَ لَيَبْعَثَنَّ عَلَيْهِمْ إِلَىٰ يَوْمِ ٱلْقِيَٰمَةِ مَن يَسُومُهُمْ سُوٓءَ ٱلْعَذَابِ ۗ إِنَّ رَبَّكَ لَسَرِيعُ ٱلْعِقَابِ ۖ وَإِنَّهُۥ لَغَفُورٌۭ رَّحِيمٌۭ", 't': "«وإذ تأذَّن» أعلم «ربُّك ليبعثنَّ عليهم» أي اليهود «إلى يوم القيامة من يسومهم سوء العذاب» بالذل وأخذ الجزية، فبعث عليهم سليمان وبعده بختنصر فقتلهم وسباهم وضرب عليهم الجزية فكانوا يؤدونها إلى المجوس إلى أن بعث نبينا صلى الله عليه وسلم فضربها عليهم «إن ربك لسريع العقاب» لمن عصاه «وإنه لغفور» لأهل طاعته «رحيم» بهم."},
  {'n': '168', 'v': "وَقَطَّعْنَٰهُمْ فِى ٱلْأَرْضِ أُمَمًۭا ۖ مِّنْهُمُ ٱلصَّٰلِحُونَ وَمِنْهُمْ دُونَ ذَٰلِكَ ۖ وَبَلَوْنَٰهُم بِٱلْحَسَنَٰتِ وَٱلسَّيِّـَٔاتِ لَعَلَّهُمْ يَرْجِعُونَ", 't': "«وقطَّعناهم» فرَّقناهم «في الأرض أُمما» فرقا «منهم الصالحون ومنهم» ناس «دون ذلك» الكفار والفاسقون «وبلوناهم بالحسنات» بالنعم «والسيئات» النقم «لعلهم يرجعون» عن فسقهم."},
  {'n': '169', 'v': "فَخَلَفَ مِنۢ بَعْدِهِمْ خَلْفٌۭ وَرِثُوا۟ ٱلْكِتَٰبَ يَأْخُذُونَ عَرَضَ هَٰذَا ٱلْأَدْنَىٰ وَيَقُولُونَ سَيُغْفَرُ لَنَا وَإِن يَأْتِهِمْ عَرَضٌۭ مِّثْلُهُۥ يَأْخُذُوهُ ۚ أَلَمْ يُؤْخَذْ عَلَيْهِم مِّيثَٰقُ ٱلْكِتَٰبِ أَن لَّا يَقُولُوا۟ عَلَى ٱللَّهِ إِلَّا ٱلْحَقَّ وَدَرَسُوا۟ مَا فِيهِ ۗ وَٱلدَّارُ ٱلْءَاخِرَةُ خَيْرٌۭ لِّلَّذِينَ يَتَّقُونَ ۗ أَفَلَا تَعْقِلُونَ", 't': "«فخلف من بعدهم خَلْفٌ ورثوا الكتاب» التوراة عن آبائهم «يأخذون عرض هذا الأدنى» أي حطام هذا الشيء الدنيء أي الدنيا من حلال وحرام «ويقولون سيغفر لنا» ما عملناه لنا «و إن يأتهم عرض مثله يأخذوه» الجملة حال، أي يرجون المغفرة وهم عائدون إلى ما فعلوه مصرون عليه، وليس في التوراة وعد المغفرة مع الإصرار «ألم يؤخذ» استفهام تقرير «عليهم ميثاق الكتب» الإضافة بمعنى في «أن لا يقولوا على الله إلا الحقَّ ودرسوا» عطف على يؤخذ قرءوا «ما فيه» فلم كذبوا عليه بنسبة المغفرة إليه مع الإصرار «والدَّار الآخرة خير للَّذين يتقون» الحرام «أفلا يعقلون» بالياء والتاء أنها خير فيؤثرونها على الدنيا."},
  {'n': '170', 'v': "وَٱلَّذِينَ يُمَسِّكُونَ بِٱلْكِتَٰبِ وَأَقَامُوا۟ ٱلصَّلَوٰةَ إِنَّا لَا نُضِيعُ أَجْرَ ٱلْمُصْلِحِينَ", 't': "«والذين يمسِّكون» بالتشديد والتخفيف «بالكتاب» منهم «وأقاموا الصلاة» كعبد الله بن سلام وأصحابه «إنا لا نضيع أجر المصلحين» الجملة خبر الذين، وفيه وضع الظاهر موضع المضمر أي أجرهم."},
  {'n': '171', 'v': "۞ وَإِذْ نَتَقْنَا ٱلْجَبَلَ فَوْقَهُمْ كَأَنَّهُۥ ظُلَّةٌۭ وَظَنُّوٓا۟ أَنَّهُۥ وَاقِعٌۢ بِهِمْ خُذُوا۟ مَآ ءَاتَيْنَٰكُم بِقُوَّةٍۢ وَٱذْكُرُوا۟ مَا فِيهِ لَعَلَّكُمْ تَتَّقُونَ", 't': "«و» «إذ نتقنا الجبل» رفعناه من أصله «فوقهم كأنه ظُلَّةٌ وظنوا» أيقنوا «أنه واقع بهم» ساقط عليهم بوعد الله إياهم بوقوعه إن لم يقبلوا أحكام التوراة ن وكانوا أبَوْها لثقلها فقلبوا وقلنا لهم «خذوا ما آتيناكم بقوة» بجد واجتهاد «واذكروا ما فيه» بالعمل به «لعلكم تتقون»."},
  {'n': '172', 'v': "وَإِذْ أَخَذَ رَبُّكَ مِنۢ بَنِىٓ ءَادَمَ مِن ظُهُورِهِمْ ذُرِّيَّتَهُمْ وَأَشْهَدَهُمْ عَلَىٰٓ أَنفُسِهِمْ أَلَسْتُ بِرَبِّكُمْ ۖ قَالُوا۟ بَلَىٰ ۛ شَهِدْنَآ ۛ أَن تَقُولُوا۟ يَوْمَ ٱلْقِيَٰمَةِ إِنَّا كُنَّا عَنْ هَٰذَا غَٰفِلِينَ", 't': "«و» اذكر «إذ» حين «أخذ ربُّك من بني آدم من ظهورهم» بدل اشتمال مما قبله بإعادة الجار «ذرِّيّاتهم» بأن أخرج بعضهم من صلب بعض من صلب آدم نسلا بعد نسل كنحو ما يتوالدون كالذّر بنعمان يوم عرفة ونصب لهم دلائل على ربوبيته وركب فيهم عقلا «وأشْهدهم على أنفسهم» قال «ألست بربكم؟ قالوا بلى» أنت ربنا «شهدنا» بذلك والإشهاد لـ «أن» لا «يقولوا» بالياء والتاء في الموضعين، أي الكفار «يوم القيامة إنا كنَّا عن هذا» التوحيد «غافلين» لا نعرفه."},
  {'n': '173', 'v': "أَوْ تَقُولُوٓا۟ إِنَّمَآ أَشْرَكَ ءَابَآؤُنَا مِن قَبْلُ وَكُنَّا ذُرِّيَّةًۭ مِّنۢ بَعْدِهِمْ ۖ أَفَتُهْلِكُنَا بِمَا فَعَلَ ٱلْمُبْطِلُونَ", 't': "«أو يقولوا إنما أشرك آباؤنا من قبل» أي قبلنا «وكنا ذريَّة من بعدهم» فاقتدينا بهم «أفتهلكنا» تعذبنا «بما فعل المبطلون» من آبائنا بتأسيس الشرك، المعنى لا يمكنهم الاحتجاج بذلك مع إشهادهم على أنفسهم بالتوحيد، والتذكير به على لسان صاحب المعجزة قائم مقام ذكره في النفوس."},
  {'n': '174', 'v': "وَكَذَٰلِكَ نُفَصِّلُ ٱلْءَايَٰتِ وَلَعَلَّهُمْ يَرْجِعُونَ", 't': "«وكذلك نفصِّل الآيات» نبيّنها مثل ما بينا الميثاق ليتدبروها «ولعلهم يرجعون» عن كفرهم."},
  {'n': '175', 'v': "وَٱتْلُ عَلَيْهِمْ نَبَأَ ٱلَّذِىٓ ءَاتَيْنَٰهُ ءَايَٰتِنَا فَٱنسَلَخَ مِنْهَا فَأَتْبَعَهُ ٱلشَّيْطَٰنُ فَكَانَ مِنَ ٱلْغَاوِينَ", 't': "«واتل» يا محمد «عليهم» أي اليهود «نبأ» خبر «الذي آتيناه آياتنا فانسلخ منها» خرج بكفره كما تخرج الحية من جلدها، وهو بلعم بن باعوراء من علماء بني إسرائيل، سُئل أن يدعو على موسى وأُهدي إليه شيء، فدعا فانقلب عليه اندلع لسانه على صدره «فأتبعه الشيطان» فأدركه فصار قرينه «فكان من الغاوين»."},
  {'n': '176', 'v': "وَلَوْ شِئْنَا لَرَفَعْنَٰهُ بِهَا وَلَٰكِنَّهُۥٓ أَخْلَدَ إِلَى ٱلْأَرْضِ وَٱتَّبَعَ هَوَىٰهُ ۚ فَمَثَلُهُۥ كَمَثَلِ ٱلْكَلْبِ إِن تَحْمِلْ عَلَيْهِ يَلْهَثْ أَوْ تَتْرُكْهُ يَلْهَث ۚ ذَّٰلِكَ مَثَلُ ٱلْقَوْمِ ٱلَّذِينَ كَذَّبُوا۟ بِـَٔايَٰتِنَا ۚ فَٱقْصُصِ ٱلْقَصَصَ لَعَلَّهُمْ يَتَفَكَّرُونَ", 't': "«ولو شئنا لرفعناه» إلى منازل العلماء «بها» بأن نوقفه للعمل «ولكنه أخلد» سكن «إلى الأرض» أي الدنيا ومال إليها «واتَّبع هواه» في دعائه إليها فوضعناه «فمثله» صفته «كمثل الكلب إن تحمل عليه» بالطرد والزجر «يلهث» يدلع لسانه «أو» إن «تتركه يلهث» وليس غيره من الحيوان كذلك، وجملتا الشرط حال، أي لاهثا ذليلا بكل حال، والقصد التشبيه في الوضع والخسة بقرينة الفاء المشعرة بترتيب ما بعدها على ما قبلها من الميل إلى الدنيا واتباع الهوى وبقرينة، قوله «ذلك» المثل «مَثَلُ القوم الذين كذَّبوا بآياتنا فاقصص القَصَصَ» على اليهود «لعلهم يتفكرون» يتدبرون فيها فيؤمنون."},
  {'n': '177', 'v': "سَآءَ مَثَلًا ٱلْقَوْمُ ٱلَّذِينَ كَذَّبُوا۟ بِـَٔايَٰتِنَا وَأَنفُسَهُمْ كَانُوا۟ يَظْلِمُونَ", 't': "«ساء» بئس «مثلا القوم» أي مثل القوم «الذين كذَّبوا بآياتنا وأنفسهم كانوا يظلمون» بالتكذيب."},
  {'n': '178', 'v': "مَن يَهْدِ ٱللَّهُ فَهُوَ ٱلْمُهْتَدِى ۖ وَمَن يُضْلِلْ فَأُو۟لَٰٓئِكَ هُمُ ٱلْخَٰسِرُونَ", 't': "«من يهَدِ الله فهو المهتدي ومن يُضْللْ فأولئك هم الخاسرون»."},
  {'n': '179', 'v': "وَلَقَدْ ذَرَأْنَا لِجَهَنَّمَ كَثِيرًۭا مِّنَ ٱلْجِنِّ وَٱلْإِنسِ ۖ لَهُمْ قُلُوبٌۭ لَّا يَفْقَهُونَ بِهَا وَلَهُمْ أَعْيُنٌۭ لَّا يُبْصِرُونَ بِهَا وَلَهُمْ ءَاذَانٌۭ لَّا يَسْمَعُونَ بِهَآ ۚ أُو۟لَٰٓئِكَ كَٱلْأَنْعَٰمِ بَلْ هُمْ أَضَلُّ ۚ أُو۟لَٰٓئِكَ هُمُ ٱلْغَٰفِلُونَ", 't': "«ولقد ذَرأْنا» خلقنا «لجهنم كثيرا من الجن والإنس لهم قلوب لا يفقهون بها» الحق «ولهم أعين لا يبصرون بها» دلائل قدرة الله بصر اعتبار «ولهم آذان لا يسمعون بها» الآيات والمواعظ سماع تدبر واتعاظ «أولئك كالأنعام» في عدم الفقه والبصر والاستماع «بل هم أضل» من الأنعام لأنها تطلب منافعها وتهرب من مضارها وهؤلاء يقدمون على النار معاندة «أولئك هم الغافلون»."},
  {'n': '180', 'v': "وَلِلَّهِ ٱلْأَسْمَآءُ ٱلْحُسْنَىٰ فَٱدْعُوهُ بِهَا ۖ وَذَرُوا۟ ٱلَّذِينَ يُلْحِدُونَ فِىٓ أَسْمَٰٓئِهِۦ ۚ سَيُجْزَوْنَ مَا كَانُوا۟ يَعْمَلُونَ", 't': "«ولله الأسماء الحسنى» التسعة والتسعون الوارد بها الحديث، والحسنى مؤنث الأحسن «فادعوه» سموه «بها وذروا» اتركوا «الذين يُلحدون» من ألحد ولحد، يميلون عن الحق «في أسمائه» حيث اشتقوا منها أسماء لآلهتهم: كاللات من الله، والعزى من العزيز، ومناة من المنَّان «سيجزون» في الآخرة جزاء «ما كانوا يعملون» وهذا قبل الأمر بالقتال."},
  {'n': '181', 'v': "وَمِمَّنْ خَلَقْنَآ أُمَّةٌۭ يَهْدُونَ بِٱلْحَقِّ وَبِهِۦ يَعْدِلُونَ", 't': "«وممن خلقنا أمة يهدون بالحق وبه يَعدِلون» هم أمة محمد صلى الله عليه وسلم كما في حديث."},
  {'n': '182', 'v': "وَٱلَّذِينَ كَذَّبُوا۟ بِـَٔايَٰتِنَا سَنَسْتَدْرِجُهُم مِّنْ حَيْثُ لَا يَعْلَمُونَ", 't': "«والذين كذبوا بآياتنا» القرآن من أهل مكة «سنستدرجهم» نأخذهم قليلا قليلا «من حيث لا يعلمون»."},
  {'n': '183', 'v': "وَأُمْلِى لَهُمْ ۚ إِنَّ كَيْدِى مَتِينٌ", 't': "«وأُملي لهم» أمهلهم «إن كيدي متينٌ» شديد لا يطاق."},
  {'n': '184', 'v': "أَوَلَمْ يَتَفَكَّرُوا۟ ۗ مَا بِصَاحِبِهِم مِّن جِنَّةٍ ۚ إِنْ هُوَ إِلَّا نَذِيرٌۭ مُّبِينٌ", 't': "«أو لم يتفكروا» فيعلموا «ما بصاحبهم» محمد صلى الله عليه وسلم «من جِنَّة» جنون «إن» ما «هو إلا نذير مبين» بيَّن الإنذار."},
  {'n': '185', 'v': "أَوَلَمْ يَنظُرُوا۟ فِى مَلَكُوتِ ٱلسَّمَٰوَٰتِ وَٱلْأَرْضِ وَمَا خَلَقَ ٱللَّهُ مِن شَىْءٍۢ وَأَنْ عَسَىٰٓ أَن يَكُونَ قَدِ ٱقْتَرَبَ أَجَلُهُمْ ۖ فَبِأَىِّ حَدِيثٍۭ بَعْدَهُۥ يُؤْمِنُونَ", 't': "«أو لم ينظروا في ملكوت» ملك «السماوات والأرض و» في «ما خلق الله من شيء» بيان لما، فيستدلوا به على قدرة صانعه ووحدانيته «و» في «أن» أي أنه «عسى أن يكون قد اقترب» قرب «أجلهم» فيموتوا كفارا فيصيروا إلى النار فيبادروا إلى الإيمان «فبأي حديث بعده» أي القرآن «يؤمنون»."},
  {'n': '186', 'v': "مَن يُضْلِلِ ٱللَّهُ فَلَا هَادِىَ لَهُۥ ۚ وَيَذَرُهُمْ فِى طُغْيَٰنِهِمْ يَعْمَهُونَ", 't': "«من يضلل الله فلا هادي له ويذرهم» بالياء والنون مع الرفع استئنافا، والجزم عطفا على محل ما بعد الفاء «في طغيانهم يعمهون» يترددون تحيُّرا."},
  {'n': '187', 'v': "يَسْـَٔلُونَكَ عَنِ ٱلسَّاعَةِ أَيَّانَ مُرْسَىٰهَا ۖ قُلْ إِنَّمَا عِلْمُهَا عِندَ رَبِّى ۖ لَا يُجَلِّيهَا لِوَقْتِهَآ إِلَّا هُوَ ۚ ثَقُلَتْ فِى ٱلسَّمَٰوَٰتِ وَٱلْأَرْضِ ۚ لَا تَأْتِيكُمْ إِلَّا بَغْتَةًۭ ۗ يَسْـَٔلُونَكَ كَأَنَّكَ حَفِىٌّ عَنْهَا ۖ قُلْ إِنَّمَا عِلْمُهَا عِندَ ٱللَّهِ وَلَٰكِنَّ أَكْثَرَ ٱلنَّاسِ لَا يَعْلَمُونَ", 't': "«يسألونك» أي أهل مكة «عن الساعة» القيامة «أيَّان» متى «مُرساها قل» لهم «إنَّما علمها» متى تكون «عند ربي لا يُجلّيها» يظهرها «لوقتها» اللام بمعنى في «إلا هو ثقُلت» عظمت «في السماوات والأرض» على أهلها لهولها «لا تأتيكم إلا بغتة» فجأة «يسألونك كأنك حَفيٌ» مبالغ في السؤال «عنها» حتى علمتها «قل إنما علمها عند الله» تأكيد «ولكن أكثر الناس لا يعلمون» أن علمها عنده تعالى."},
  {'n': '188', 'v': "قُل لَّآ أَمْلِكُ لِنَفْسِى نَفْعًۭا وَلَا ضَرًّا إِلَّا مَا شَآءَ ٱللَّهُ ۚ وَلَوْ كُنتُ أَعْلَمُ ٱلْغَيْبَ لَٱسْتَكْثَرْتُ مِنَ ٱلْخَيْرِ وَمَا مَسَّنِىَ ٱلسُّوٓءُ ۚ إِنْ أَنَا۠ إِلَّا نَذِيرٌۭ وَبَشِيرٌۭ لِّقَوْمٍۢ يُؤْمِنُونَ", 't': "«قل لا أملك لنفسي نفعا» أجلبه «ولا ضرا» أدفعه «إلا ما شاء الله ولو كنت أعلم الغيب» ما غاب عني «لاستكثرت من الخير وما مسَّني السوء» من فقر وغيره لاحترازي عنه باجتناب المضار «إن» ما «أنا إلا نذير» بالنار للكافرين «وبشير» بالجنة «لقوم يؤمنون»."},
  {'n': '189', 'v': "۞ هُوَ ٱلَّذِى خَلَقَكُم مِّن نَّفْسٍۢ وَٰحِدَةٍۢ وَجَعَلَ مِنْهَا زَوْجَهَا لِيَسْكُنَ إِلَيْهَا ۖ فَلَمَّا تَغَشَّىٰهَا حَمَلَتْ حَمْلًا خَفِيفًۭا فَمَرَّتْ بِهِۦ ۖ فَلَمَّآ أَثْقَلَت دَّعَوَا ٱللَّهَ رَبَّهُمَا لَئِنْ ءَاتَيْتَنَا صَٰلِحًۭا لَّنَكُونَنَّ مِنَ ٱلشَّٰكِرِينَ", 't': "«هو» أي الله «الذي خلقكم من نفس واحدة» أي آدم «وجعل» خلق «منها زوجها» حواء «ليسكن إليها» ويألفها «فلما تغشَّاها» جامعها «حملت حملا خفيفا» هو النطفة «فمرت به» ذهبت وجاءت لخفته «فلما أثقلت» بكبر الولد في بطنها وأشفقا أن يكون بهيمة «دعوا الله ربَّهما لئن آتيتنا» ولدا «صالحا» سويا «لنكونن من الشاكرين» لك عليه."},
  {'n': '190', 'v': "فَلَمَّآ ءَاتَىٰهُمَا صَٰلِحًۭا جَعَلَا لَهُۥ شُرَكَآءَ فِيمَآ ءَاتَىٰهُمَا ۚ فَتَعَٰلَى ٱللَّهُ عَمَّا يُشْرِكُونَ", 't': "«فلمَّا آتاهما» ولدا «صالحا جعلا له شركاء» وفي قراءة بكسر الشين والتنوين أي شريكا «فيما آتاهما» بتسميته عبد الحارث ولا ينبغي أن يكون عبدا إلا لله، وليس بإشراك في العبودية لعصمة آدم وروى سمرة عن النبي صلى الله عليه وسلم قال: لما ولدت حواء طاف بها إبليس وكان لا يعيش لها ولد فقال: سميه عبد الحارث فإنه يعيش فسمته فعاش فكان ذلك من وحي الشيطان وأمره رواه الحاكم وقال صحيح والترمذي وقال حسن غريب «فتعالى الله عما يشركون» أي أهل مكة به من الأصنام، والجملة مسببة عطف على خلقكم وما بينهما اعتراض."},
  {'n': '191', 'v': "أَيُشْرِكُونَ مَا لَا يَخْلُقُ شَيْـًۭٔا وَهُمْ يُخْلَقُونَ", 't': "«أيشركون» به في العبادة «ما لا يخلق شيئا وهم يُخلقون»."},
  {'n': '192', 'v': "وَلَا يَسْتَطِيعُونَ لَهُمْ نَصْرًۭا وَلَآ أَنفُسَهُمْ يَنصُرُونَ", 't': "«ولا يستطيعون لهم» أي لعابديهم «نصرا ولا أنفسهم يَنْصرون» بمنعها ممن أراد بهم سوءا من كسر أو غيره، والاستفهام للتوبيخ."},
  {'n': '193', 'v': "وَإِن تَدْعُوهُمْ إِلَى ٱلْهُدَىٰ لَا يَتَّبِعُوكُمْ ۚ سَوَآءٌ عَلَيْكُمْ أَدَعَوْتُمُوهُمْ أَمْ أَنتُمْ صَٰمِتُونَ", 't': "«وإن تدعوهم» أي الأصنام «إلى الهدى لا يتبعوكم» بالتخفيف والتشديد «سواء عليكم أدعوتموهم» إليه «أم أنتم صامتون» عن دعائهم لا يتبعوه لعدم سماعهم."},
  {'n': '194', 'v': "إِنَّ ٱلَّذِينَ تَدْعُونَ مِن دُونِ ٱللَّهِ عِبَادٌ أَمْثَالُكُمْ ۖ فَٱدْعُوهُمْ فَلْيَسْتَجِيبُوا۟ لَكُمْ إِن كُنتُمْ صَٰدِقِينَ", 't': "«إن الذين تدعون» تعبدون «من دون الله عبادٌ» مملوكة «أمثالكم فادعوهم فليستجيبوا لكم» دعاءكم «إن كنتم صادقين» في أنها آلهة، ثم بين غاية عجزهم وفضل عابديهم عليهم فقال."},
  {'n': '195', 'v': "أَلَهُمْ أَرْجُلٌۭ يَمْشُونَ بِهَآ ۖ أَمْ لَهُمْ أَيْدٍۢ يَبْطِشُونَ بِهَآ ۖ أَمْ لَهُمْ أَعْيُنٌۭ يُبْصِرُونَ بِهَآ ۖ أَمْ لَهُمْ ءَاذَانٌۭ يَسْمَعُونَ بِهَا ۗ قُلِ ٱدْعُوا۟ شُرَكَآءَكُمْ ثُمَّ كِيدُونِ فَلَا تُنظِرُونِ", 't': "«ألهم أرجل يمشون بها أم» بل أ «لهم أيد» جمع يد «يبطشون بها أم» بل أ «لهم آذان يسمعون بها» استفهام إنكاري، أي ليس لهم شيء من ذلك مما هو لكم فكيف تعبدوهم وأنتم حالا منهم «قل» لهم يا محمد «ادعوا شركاءكم» إلى هلاكي «ثم كيدون فلا تُنظرون» تمهلون فإني لا أبالي بكم."},
  {'n': '196', 'v': "إِنَّ وَلِۦِّىَ ٱللَّهُ ٱلَّذِى نَزَّلَ ٱلْكِتَٰبَ ۖ وَهُوَ يَتَوَلَّى ٱلصَّٰلِحِينَ", 't': "«إن وليي الله» متولي أموري «الذي نزَّل الكتاب» القرآن «وهو يتولى الصالحين» بحفظه."},
  {'n': '197', 'v': "وَٱلَّذِينَ تَدْعُونَ مِن دُونِهِۦ لَا يَسْتَطِيعُونَ نَصْرَكُمْ وَلَآ أَنفُسَهُمْ يَنصُرُونَ", 't': "«والذين تدعون من دونه لا يستطيعون نصركم ولا أنفسهم ينصرون» فكيف أبالي بهم."},
  {'n': '198', 'v': "وَإِن تَدْعُوهُمْ إِلَى ٱلْهُدَىٰ لَا يَسْمَعُوا۟ ۖ وَتَرَىٰهُمْ يَنظُرُونَ إِلَيْكَ وَهُمْ لَا يُبْصِرُونَ", 't': "«وإن تدعوهم» أي الأصنام «إلى الهدى لا يسمعوا وتراهم» أي الأصنام يا محمد «ينظرون إليك» أي يقابلونك كالناظر «وهم لا يبصرون»."},
  {'n': '199', 'v': "خُذِ ٱلْعَفْوَ وَأْمُرْ بِٱلْعُرْفِ وَأَعْرِضْ عَنِ ٱلْجَٰهِلِينَ", 't': "«خذ العفو» اليسر من أخلاق الناس ولا تبحث عنها «وأمر بالعرف» بالمعروف «وأعرض عن الجاهلين» فلا تقابلهم بسفههم."},
  {'n': '200', 'v': "وَإِمَّا يَنزَغَنَّكَ مِنَ ٱلشَّيْطَٰنِ نَزْغٌۭ فَٱسْتَعِذْ بِٱللَّهِ ۚ إِنَّهُۥ سَمِيعٌ عَلِيمٌ", 't': "«وإما» فيه إدغام نون إن الشرطية في ما المزيدة «ينزغنَّك من الشيطان نَزْغٌ» أي إن يصرفك عما أمرت به صارف «فاستعذ بالله» جواب الشرط وجواب الأمر محذوف، أي يدفعه عنك «إنه سميع» للقول «عليم» بالفعل."},
  {'n': '201', 'v': "إِنَّ ٱلَّذِينَ ٱتَّقَوْا۟ إِذَا مَسَّهُمْ طَٰٓئِفٌۭ مِّنَ ٱلشَّيْطَٰنِ تَذَكَّرُوا۟ فَإِذَا هُم مُّبْصِرُونَ", 't': "«إن الذين اتقوا إذا مسَّهم» أصابهم «طيفٌ» وفي قراءة طائف أي شيء ألَّم بهم «من الشيطان تذكَّروا» عقاب الله وثوابه «فإذا هم مبصرون» الحق من غيره فيرجعون."},
  {'n': '202', 'v': "وَإِخْوَٰنُهُمْ يَمُدُّونَهُمْ فِى ٱلْغَىِّ ثُمَّ لَا يُقْصِرُونَ", 't': "«وإخوانهم» أي إخوان الشياطين من الكفار «يَمدُّونَهُمْ» أي الشياطين «في الغي ثم» هم «لا يُقْصِرُونَ» يكفون عنه بالتبصر كما تبصَّر المتقون."},
  {'n': '203', 'v': "وَإِذَا لَمْ تَأْتِهِم بِـَٔايَةٍۢ قَالُوا۟ لَوْلَا ٱجْتَبَيْتَهَا ۚ قُلْ إِنَّمَآ أَتَّبِعُ مَا يُوحَىٰٓ إِلَىَّ مِن رَّبِّى ۚ هَٰذَا بَصَآئِرُ مِن رَّبِّكُمْ وَهُدًۭى وَرَحْمَةٌۭ لِّقَوْمٍۢ يُؤْمِنُونَ", 't': "«وإذا لم تأتهم» أي أهل مكة «بآية» مما اقترحوا «قالوا لولا» هلا «اجتبيتها» أنشأتها من قبل نفسك «قل» لهم «إنَّما أتَّبع ما يوحى إلي من ربي» وليس لي أن آتي من عند نفسي بشيء «هذا» القرآن «بصائر» حجج «من ربِّكم وهدى ورحمة لقوم يؤمنون»."},
