  {'n': '9', 'v': "ٱقْتُلُوا۟ يُوسُفَ أَوِ ٱطْرَحُوهُ أَرْضًۭا يَخْلُ لَكُمْ وَجْهُ أَبِيكُمْ وَتَكُونُوا۟ مِنۢ بَعْدِهِۦ قَوْمًۭا صَٰلِحِينَ", 't': "«اقتلوا يوسف أو اطرحوه أرضا» أي بأرض بعيدة «يخل لكم وجه أبيكم» بأن يقبل عليكم ولا يلتفت لغيركم «وتكونوا من بعده» أي بعد قتل يوسف أو طرحه «قوما صالحين» بأن تتوبوا."},
  {'n': '10', 'v': "قَالَ قَآئِلٌۭ مِّنْهُمْ لَا تَقْتُلُوا۟ يُوسُفَ وَأَلْقُوهُ فِى غَيَٰبَتِ ٱلْجُبِّ يَلْتَقِطْهُ بَعْضُ ٱلسَّيَّارَةِ إِن كُنتُمْ فَٰعِلِينَ", 't': "«قال قائل منهم» هو يهوذا «لا تقتلوا يوسف وألقوه» اطرحوه «في غيابت الجب» مظلم البئر في قراءة بالجمع «يلتقطه بعض السيارة» المسافرين «إن كنتم فاعلين» ما أردتم من التفريق فاكتفوا بذلك."},
  {'n': '11', 'v': "قَالُوا۟ يَٰٓأَبَانَا مَا لَكَ لَا تَأْمَ۫نَّا عَلَىٰ يُوسُفَ وَإِنَّا لَهُۥ لَنَٰصِحُونَ", 't': "«قالوا يا أبانا مالك لا تأمنا على يوسف وإنا له لناصحون» لقائمون بمصالحه."},
  {'n': '12', 'v': "أَرْسِلْهُ مَعَنَا غَدًۭا يَرْتَعْ وَيَلْعَبْ وَإِنَّا لَهُۥ لَحَٰفِظُونَ", 't': "«أرسله معنا غدا» إلى الصحراء «نرتع ونلعب» بالنون والياء فيهما ننشط ونتسع «وإنَّا له لحافظون»."},
  {'n': '13', 'v': "قَالَ إِنِّى لَيَحْزُنُنِىٓ أَن تَذْهَبُوا۟ بِهِۦ وَأَخَافُ أَن يَأْكُلَهُ ٱلذِّئْبُ وَأَنتُمْ عَنْهُ غَٰفِلُونَ", 't': "«قال إني ليحزنني أن تذهبوا» أي ذهابكم «به» لفراقه «وأخاف أن يأكله الذئب» المراد به الجنس وكانت أرضهم كثيرة الذئاب «وأنتم عنه غافلون» مشغلون."},
  {'n': '14', 'v': "قَالُوا۟ لَئِنْ أَكَلَهُ ٱلذِّئْبُ وَنَحْنُ عُصْبَةٌ إِنَّآ إِذًۭا لَّخَٰسِرُونَ", 't': "«قالوا لإن» لام قسم «أكله الذئب ونحن عصبة» جماعة «إنا إذا لخاسرون» عاجزون فأرسله معهم."},
  {'n': '15', 'v': "فَلَمَّا ذَهَبُوا۟ بِهِۦ وَأَجْمَعُوٓا۟ أَن يَجْعَلُوهُ فِى غَيَٰبَتِ ٱلْجُبِّ ۚ وَأَوْحَيْنَآ إِلَيْهِ لَتُنَبِّئَنَّهُم بِأَمْرِهِمْ هَٰذَا وَهُمْ لَا يَشْعُرُونَ", 't': "«فلما ذهبوا به وأجمعوا» عزموا «أن يجعلوه في غيابت الجب» وجواب لما محذوف أي فعلوا ذلك بأن نزعوا قميصه بعد ضربه وإهانته وإرادة قتله وأدلوه فلما وصل إلى نصف البئر ألقوه ليموت فسقط في الماء ثم أوى إلى صخرة فنادوه فأجابهم يظن رحمتهم فأرادوا رضخه بصخرة فمنعهم يهوذا «وأوحينا إليه» في الجب وحي حقيقة وله سبع عشرة سنة أو دونها تطمينا لقلبه «لتنبئنهم» بعد اليوم «بأمرهم» بصنيعهم «هذا وهم لا يشعرون» بك حال الإنباء."},
  {'n': '16', 'v': "وَجَآءُوٓ أَبَاهُمْ عِشَآءًۭ يَبْكُونَ", 't': "«وجاءُوا أباهم عِشاءً» وقت المساء «يبكون»."},
  {'n': '17', 'v': "قَالُوا۟ يَٰٓأَبَانَآ إِنَّا ذَهَبْنَا نَسْتَبِقُ وَتَرَكْنَا يُوسُفَ عِندَ مَتَٰعِنَا فَأَكَلَهُ ٱلذِّئْبُ ۖ وَمَآ أَنتَ بِمُؤْمِنٍۢ لَّنَا وَلَوْ كُنَّا صَٰدِقِينَ", 't': "«قالوا يا أبانا إنا ذهبا نستبقُ» نرمي «وتركنا يوسف عند متاعنا» ثيابنا «فأكله الذئب وما أنت بمؤمن» بمصدق «لنا ولو كنا صادقين» عندك لاتهمتنا في هذه القصة لمحبة يوسف فكيف وأنت تسيء الظن بنا."},
  {'n': '18', 'v': "وَجَآءُو عَلَىٰ قَمِيصِهِۦ بِدَمٍۢ كَذِبٍۢ ۚ قَالَ بَلْ سَوَّلَتْ لَكُمْ أَنفُسُكُمْ أَمْرًۭا ۖ فَصَبْرٌۭ جَمِيلٌۭ ۖ وَٱللَّهُ ٱلْمُسْتَعَانُ عَلَىٰ مَا تَصِفُونَ", 't': "«وجاءُوا على قميصه» محله نصب على الظرفية أي فوقه «بدم كذب» أي ذي كذب بأن ذبحوا سخلة ولطخوه بدمها وذهلوا عن شقه وقالوا إنه دمه «قال» يعقوب لما رآه صحيحا وعلم كذبهم «بل سوَّلت» زينت «لكم أنفسكم أمرا» ففعلتموه به «فصبر جميل» لا جزع فيه، وهو خبر مبتدأ محذوف أي أمري «والله المستعان» المطلوب منه العون «على ما تصفون» تذكرون من أمر يوسف."},
  {'n': '19', 'v': "وَجَآءَتْ سَيَّارَةٌۭ فَأَرْسَلُوا۟ وَارِدَهُمْ فَأَدْلَىٰ دَلْوَهُۥ ۖ قَالَ يَٰبُشْرَىٰ هَٰذَا غُلَٰمٌۭ ۚ وَأَسَرُّوهُ بِضَٰعَةًۭ ۚ وَٱللَّهُ عَلِيمٌۢ بِمَا يَعْمَلُونَ", 't': "«وجاءت سيارة» مسافرون من مدين إلى مصر فنزلوا قريبا من جب يوسف «فأرسلوا واردهم» الذي يرد الماء ليستقي منه «فأدلى» أرسل «دلوه» في البئر فتعلق بها يوسف فأخرجه فلما رآه «قال يا بشراي» وفي قراءة بشرى ونداؤها مجاز أي احضري فهذا وقتك «هذا غلام» فعلم به إخوته فأتوه «وأسَرُّوه» أي أخفوا أمره جاعليه «بضاعة» بأن قالوا هذا عبدنا أبق، وسكت يوسف خوفا من أن يقتلوه «والله عليم بما يعملون»."},
  {'n': '20', 'v': "وَشَرَوْهُ بِثَمَنٍۭ بَخْسٍۢ دَرَٰهِمَ مَعْدُودَةٍۢ وَكَانُوا۟ فِيهِ مِنَ ٱلزَّٰهِدِينَ", 't': "«وشروه» باعوه منهم «بثمن بخس» ناقص «دراهم معدودة» عشرين أو اثنين وعشرين «وكانوا» أي إخوته «فيه من الزاهدين» فجاءت به السيارة إلى مصر فباعه الذي اشتراه بعشرين دينارا وزوجي نعل وثوبين."},
  {'n': '21', 'v': "وَقَالَ ٱلَّذِى ٱشْتَرَىٰهُ مِن مِّصْرَ لِٱمْرَأَتِهِۦٓ أَكْرِمِى مَثْوَىٰهُ عَسَىٰٓ أَن يَنفَعَنَآ أَوْ نَتَّخِذَهُۥ وَلَدًۭا ۚ وَكَذَٰلِكَ مَكَّنَّا لِيُوسُفَ فِى ٱلْأَرْضِ وَلِنُعَلِّمَهُۥ مِن تَأْوِيلِ ٱلْأَحَادِيثِ ۚ وَٱللَّهُ غَالِبٌ عَلَىٰٓ أَمْرِهِۦ وَلَٰكِنَّ أَكْثَرَ ٱلنَّاسِ لَا يَعْلَمُونَ", 't': "«وقال الذي اشتراه من مصر» وهو قطفير العزيز «لامرأته» زليخا «أكرمي مثواه» مقامه عندنا «عسى أن ينفعنا أو نتخذه ولدا» وكان حصورا «وكذلك» كما نجيناه من القتل والجب وعطفنا عليه قلب العزيز «مكنَّا ليوسف في الأرض» أرض مصر حتى بلغ ما بلغ «ولنعلِّمه من تأويل الأحاديث» تعبير الرؤيا عطف على مقدر متعلق بمكنا أي لنملكه أو الواو زائدة «والله غالب على أمره» تعالى لا يعجزه شيء «ولكن أكثر الناس» وهم الكفار «لا يعلمون» ذلك."},
  {'n': '22', 'v': "وَلَمَّا بَلَغَ أَشُدَّهُۥٓ ءَاتَيْنَٰهُ حُكْمًۭا وَعِلْمًۭا ۚ وَكَذَٰلِكَ نَجْزِى ٱلْمُحْسِنِينَ", 't': "«ولما بلغ أشده» وهو ثلاثون سنة أو وثلاث «آتيناه حكما» حكمة «وعلما» فقها في الدين قبل أن يبعث نبيا «وكذلك» كما جزيناه «نجزي المحسنين» لأنفسهم."},
  {'n': '23', 'v': "وَرَٰوَدَتْهُ ٱلَّتِى هُوَ فِى بَيْتِهَا عَن نَّفْسِهِۦ وَغَلَّقَتِ ٱلْأَبْوَٰبَ وَقَالَتْ هَيْتَ لَكَ ۚ قَالَ مَعَاذَ ٱللَّهِ ۖ إِنَّهُۥ رَبِّىٓ أَحْسَنَ مَثْوَاىَ ۖ إِنَّهُۥ لَا يُفْلِحُ ٱلظَّٰلِمُونَ", 't': "«وراودته التي هو في بيتها» هي زليخا «عن نفسه» أي طلبت منه أن يواقعها «وغلَّقت الأبواب» للبيت «وقالت» له «هيْت لك» أي هلم واللام للتبيين وفي قراءة بكسر الهاء وأخرى بضم التاء «قال معاذ الله» أعوذ بالله من ذلك «إنه» الذي اشتراني «ربي» سيدي «أحسن مثواي» مقامي فلا أخونه في أهله «إنه» أي الشأن «لا يفلح الظالمون» الزناة."},
  {'n': '24', 'v': "وَلَقَدْ هَمَّتْ بِهِۦ ۖ وَهَمَّ بِهَا لَوْلَآ أَن رَّءَا بُرْهَٰنَ رَبِّهِۦ ۚ كَذَٰلِكَ لِنَصْرِفَ عَنْهُ ٱلسُّوٓءَ وَٱلْفَحْشَآءَ ۚ إِنَّهُۥ مِنْ عِبَادِنَا ٱلْمُخْلَصِينَ", 't': "«ولقد همَّت به» قصدت منه الجماع «وهمَّ بها» قصد ذلك «لولا أن رأى برهان ربه» قال ابن عباس مَثُل له يعقوب فضرب صدره فخرجت شهوته من أنامله وجواب لولا لجامعها «كذلك» أريناه البرهان «لنصرف عنه السوء» الخيانة «والفحشاء» الزنا «إنه من عبادنا المخلصين» في الطاعة وفي قراءة بفتح اللام أي المختارين."},
  {'n': '25', 'v': "وَٱسْتَبَقَا ٱلْبَابَ وَقَدَّتْ قَمِيصَهُۥ مِن دُبُرٍۢ وَأَلْفَيَا سَيِّدَهَا لَدَا ٱلْبَابِ ۚ قَالَتْ مَا جَزَآءُ مَنْ أَرَادَ بِأَهْلِكَ سُوٓءًا إِلَّآ أَن يُسْجَنَ أَوْ عَذَابٌ أَلِيمٌۭ", 't': "«واستبقا الباب» بادر إليه يوسف للفرار وهي للتشبث به فأمسكت ثوبه وجذبته إليها «وقدَّت» شقت «قميصه من دبر وألفيا» وجدا «سيدها» زوجها «لدى الباب» فنزعت نفسها ثم «قالت ما جزاء من أراد بأهلك سوءا» زنا «إلا أن يسجن» يحبس في سجن «أو عذاب أليم» مؤلم بأن يضرب."},
  {'n': '26', 'v': "قَالَ هِىَ رَٰوَدَتْنِى عَن نَّفْسِى ۚ وَشَهِدَ شَاهِدٌۭ مِّنْ أَهْلِهَآ إِن كَانَ قَمِيصُهُۥ قُدَّ مِن قُبُلٍۢ فَصَدَقَتْ وَهُوَ مِنَ ٱلْكَٰذِبِينَ", 't': "«قال» يوسف متبرئا «هي راودتني عن نفسي وشهد شاهد من أهلها» ابن عمها، روي أنه كان في المهد فقال «إن كان قميصه قُدَّ من قُبل» قدام «فصدقت وهو من الكاذبين»"},
  {'n': '27', 'v': "وَإِن كَانَ قَمِيصُهُۥ قُدَّ مِن دُبُرٍۢ فَكَذَبَتْ وَهُوَ مِنَ ٱلصَّٰدِقِينَ", 't': "«وإن كان قميصه قُدَّ من دبُر» خلف «فكذبت وهو من الصادقين»."},
  {'n': '28', 'v': "فَلَمَّا رَءَا قَمِيصَهُۥ قُدَّ مِن دُبُرٍۢ قَالَ إِنَّهُۥ مِن كَيْدِكُنَّ ۖ إِنَّ كَيْدَكُنَّ عَظِيمٌۭ", 't': "«فلما رأى» زوجها «قميصه قُدّ من دبر قال إنه» أي قولك (ما جزاء من أراد) إلخ «من كيدكن» أيها النساء «إن كيدكن عظيم»."},
  {'n': '29', 'v': "يُوسُفُ أَعْرِضْ عَنْ هَٰذَا ۚ وَٱسْتَغْفِرِى لِذَنۢبِكِ ۖ إِنَّكِ كُنتِ مِنَ ٱلْخَاطِـِٔينَ", 't': "ثم قال يا «يوسف أعرض عن هذا» الأمر ولا تذكره لئلا يشيع «واستغفري» يا زليخا «لذنبك إنك كنت من الخاطئين» الآثمين، واشتهر الخبر وشاع."},
  {'n': '30', 'v': "۞ وَقَالَ نِسْوَةٌۭ فِى ٱلْمَدِينَةِ ٱمْرَأَتُ ٱلْعَزِيزِ تُرَٰوِدُ فَتَىٰهَا عَن نَّفْسِهِۦ ۖ قَدْ شَغَفَهَا حُبًّا ۖ إِنَّا لَنَرَىٰهَا فِى ضَلَٰلٍۢ مُّبِينٍۢ", 't': "«وقال نسوة في المدينة» مدينة مصر «امرأة العزيز تراود فتاها» عبدها «عن نفسه قد شغفها حبا» تمييز، أي دخل حبه شغاف قلبها، أي غلافه «إنا لنراها في ضلال» أي في خطأ «مبين» بيِّن بحبها إياه."},
  {'n': '31', 'v': "فَلَمَّا سَمِعَتْ بِمَكْرِهِنَّ أَرْسَلَتْ إِلَيْهِنَّ وَأَعْتَدَتْ لَهُنَّ مُتَّكَـًۭٔا وَءَاتَتْ كُلَّ وَٰحِدَةٍۢ مِّنْهُنَّ سِكِّينًۭا وَقَالَتِ ٱخْرُجْ عَلَيْهِنَّ ۖ فَلَمَّا رَأَيْنَهُۥٓ أَكْبَرْنَهُۥ وَقَطَّعْنَ أَيْدِيَهُنَّ وَقُلْنَ حَٰشَ لِلَّهِ مَا هَٰذَا بَشَرًا إِنْ هَٰذَآ إِلَّا مَلَكٌۭ كَرِيمٌۭ", 't': "«فلما سمعت بمكرهن» غيبتهن لها «أرسلت إليهن وأعتدت» أعدت «لهن متكأ» طعاما يقطع بالسكين للاتكاء عنده وهو الأترج «وآتت» أعطت «كل واحدة منهن سكينا وقالت» ليوسف «اخرج عليهن فلما رأينه أكبرنه» أعظمنه «وقطَّعن أيديهن» بالسكاكين ولم يشعرن بالألم لشغل قلبهن بيوسف «وقلن حاش لله» تنزيها له «ما هذا» أي يوسف «بشرا إن» ما «هذا إلا ملك كريم» لما حواه من الحسن الذي لا يكون عادة في النسمة البشرية، وفي الحديث (أنه أعطي شطر الحسن)."},
  {'n': '32', 'v': "قَالَتْ فَذَٰلِكُنَّ ٱلَّذِى لُمْتُنَّنِى فِيهِ ۖ وَلَقَدْ رَٰوَدتُّهُۥ عَن نَّفْسِهِۦ فَٱسْتَعْصَمَ ۖ وَلَئِن لَّمْ يَفْعَلْ مَآ ءَامُرُهُۥ لَيُسْجَنَنَّ وَلَيَكُونًۭا مِّنَ ٱلصَّٰغِرِينَ", 't': "«قالت» امرأة العزيز لما رأت ما حل بهن «فذلكن» فهذا هو «الذي لمتنني فيه» في حبه بيان لعذرها «ولقد راودته عن نفسه فاستعصم» امتنع «ولإن لم يفعل ما آمره» به «ليسجنن وليكونا من الصاغرين» الذليلين فقلن له أطع مولاتك."},
  {'n': '33', 'v': "قَالَ رَبِّ ٱلسِّجْنُ أَحَبُّ إِلَىَّ مِمَّا يَدْعُونَنِىٓ إِلَيْهِ ۖ وَإِلَّا تَصْرِفْ عَنِّى كَيْدَهُنَّ أَصْبُ إِلَيْهِنَّ وَأَكُن مِّنَ ٱلْجَٰهِلِينَ", 't': "«قال رب السجن أحبُ إليّ مما يدعونني إليه وإلا تصرف عني كيدهن أصْبُ» أمل «إليهن وأكن» أصر «من الجاهلين» المذنبين والقصد بذلك الدعاء فلذا قال تعالى."},
  {'n': '34', 'v': "فَٱسْتَجَابَ لَهُۥ رَبُّهُۥ فَصَرَفَ عَنْهُ كَيْدَهُنَّ ۚ إِنَّهُۥ هُوَ ٱلسَّمِيعُ ٱلْعَلِيمُ", 't': "«فاستجاب له ربه» دعاءه «فصرف عنه كيدهن إنه هو السميع» للقول «العليم» بالفعل."},
  {'n': '35', 'v': "ثُمَّ بَدَا لَهُم مِّنۢ بَعْدِ مَا رَأَوُا۟ ٱلْءَايَٰتِ لَيَسْجُنُنَّهُۥ حَتَّىٰ حِينٍۢ", 't': "«ثم بدا» ظهر «لهم من بعد ما رأوا الآيات» الدالات على براءة يوسف أن يسجنوه دل على هذا «ليسجننه حتى» إلى «حين» ينقطع فيه كلام الناس فسجن."},
  {'n': '36', 'v': "وَدَخَلَ مَعَهُ ٱلسِّجْنَ فَتَيَانِ ۖ قَالَ أَحَدُهُمَآ إِنِّىٓ أَرَىٰنِىٓ أَعْصِرُ خَمْرًۭا ۖ وَقَالَ ٱلْءَاخَرُ إِنِّىٓ أَرَىٰنِىٓ أَحْمِلُ فَوْقَ رَأْسِى خُبْزًۭا تَأْكُلُ ٱلطَّيْرُ مِنْهُ ۖ نَبِّئْنَا بِتَأْوِيلِهِۦٓ ۖ إِنَّا نَرَىٰكَ مِنَ ٱلْمُحْسِنِينَ", 't': "«ودخل معه السجن فتيان» غلامان للملك أحدهما ساقيه والآخر صاحب طعامه فرأياه يعبر الرؤيا فقالا لنختبرنه «قال أحدهما» وهو الساقي «إني أراني أعصر خمرا» أي عنبا «وقال الآخر» وهو صاحب الطعام «إني أراني أحمل فوق رأسي خبزا تأكل الطير منه نبئنا» خبرنا «بتأويله» بتعبيره «إنا نراك من المحسنين»."},
  {'n': '37', 'v': "قَالَ لَا يَأْتِيكُمَا طَعَامٌۭ تُرْزَقَانِهِۦٓ إِلَّا نَبَّأْتُكُمَا بِتَأْوِيلِهِۦ قَبْلَ أَن يَأْتِيَكُمَا ۚ ذَٰلِكُمَا مِمَّا عَلَّمَنِى رَبِّىٓ ۚ إِنِّى تَرَكْتُ مِلَّةَ قَوْمٍۢ لَّا يُؤْمِنُونَ بِٱللَّهِ وَهُم بِٱلْءَاخِرَةِ هُمْ كَٰفِرُونَ", 't': "«قال» لهما مخبرا أنه عالم بتعبير الرؤيا «لا يأتيكما طعام ترزقانه» في منامكما «إلا نبأتكما بتأويله» في اليقظة «قبل أن يأتيكما» تأويله «ذلكما مما علمني ربي» فيه حث على إيمانهما ثم قوّاه بقوله «إني تركت ملة» دين «قوم لا يؤمنون بالله وهم بالآخرة هم» تأكيد «كافرون»."},
  {'n': '38', 'v': "وَٱتَّبَعْتُ مِلَّةَ ءَابَآءِىٓ إِبْرَٰهِيمَ وَإِسْحَٰقَ وَيَعْقُوبَ ۚ مَا كَانَ لَنَآ أَن نُّشْرِكَ بِٱللَّهِ مِن شَىْءٍۢ ۚ ذَٰلِكَ مِن فَضْلِ ٱللَّهِ عَلَيْنَا وَعَلَى ٱلنَّاسِ وَلَٰكِنَّ أَكْثَرَ ٱلنَّاسِ لَا يَشْكُرُونَ", 't': "«واتبعت ملة آبائي إبراهيم وإسحاق ويعقوب ما كان» ينبغي «لنا أن نشرك بالله من» زائدة «شيء» لعصمتنا «ذلك» التوحيد «من فضل الله علينا وعلى الناس ولكن أكثر الناس» وهم الكفار «لا يشكرون» الله فيشركون ثم صرح بدعائهما إلى الإيمان فقال."},
  {'n': '39', 'v': "يَٰصَىٰحِبَىِ ٱلسِّجْنِ ءَأَرْبَابٌۭ مُّتَفَرِّقُونَ خَيْرٌ أَمِ ٱللَّهُ ٱلْوَٰحِدُ ٱلْقَهَّارُ", 't': "«يا صاحبي» ساكني «السجن أأرباب متفرقون خير أم الله الواحد القهار» خير؟ استفهام تقرير."},
  {'n': '40', 'v': "مَا تَعْبُدُونَ مِن دُونِهِۦٓ إِلَّآ أَسْمَآءًۭ سَمَّيْتُمُوهَآ أَنتُمْ وَءَابَآؤُكُم مَّآ أَنزَلَ ٱللَّهُ بِهَا مِن سُلْطَٰنٍ ۚ إِنِ ٱلْحُكْمُ إِلَّا لِلَّهِ ۚ أَمَرَ أَلَّا تَعْبُدُوٓا۟ إِلَّآ إِيَّاهُ ۚ ذَٰلِكَ ٱلدِّينُ ٱلْقَيِّمُ وَلَٰكِنَّ أَكْثَرَ ٱلنَّاسِ لَا يَعْلَمُونَ", 't': "«ما تعبدون من دونه» أي غيره «إلا أسماء سميتموها» سميتم بها أصناما «أنتم وآباؤكم ما أنزل الله بها» بعادتها «من سلطان» حجة وبرهان «إن» ما «الحكم» القضاء «إلا لله» وحده «أمر ألا تعبدوا إلا إياه ذلك» التوحيد «الدين القيم» المستقيم «ولكنَّ أكثر الناس» وهم الكفار «لا يعلمون» ما يصيرون إليه من العذاب فيشركون."},
  {'n': '41', 'v': "يَٰصَىٰحِبَىِ ٱلسِّجْنِ أَمَّآ أَحَدُكُمَا فَيَسْقِى رَبَّهُۥ خَمْرًۭا ۖ وَأَمَّا ٱلْءَاخَرُ فَيُصْلَبُ فَتَأْكُلُ ٱلطَّيْرُ مِن رَّأْسِهِۦ ۚ قُضِىَ ٱلْأَمْرُ ٱلَّذِى فِيهِ تَسْتَفْتِيَانِ", 't': "«يا صاحبي السجن أما أحدكما» أي الساقي فيخرج بعد ثلاث «فيسقي ربه» سيده «خمرا» على عادته «وأما الآخر» فيخرج بعد ثلاث «فيصلب فتأكل الطير من رأسه» هذا تأويل رؤياكما فقالا ما رأينا شيئا فقال «قضي» تمَّ «الأمر الذي فيه تستفتيان» سألتما عنه صدقتما أم كذبتما."},
  {'n': '42', 'v': "وَقَالَ لِلَّذِى ظَنَّ أَنَّهُۥ نَاجٍۢ مِّنْهُمَا ٱذْكُرْنِى عِندَ رَبِّكَ فَأَنسَىٰهُ ٱلشَّيْطَٰنُ ذِكْرَ رَبِّهِۦ فَلَبِثَ فِى ٱلسِّجْنِ بِضْعَ سِنِينَ", 't': "«وقال للذي ظن» أيقن «أنه ناج منهما» وهو الساقي «اذكرني عند ربك» سيدك فقل له إن في السجن غلاما محبوسا ظلما فخرج «فأنساه» أي الساقي «الشيطان ذكْرَ» يوسف عند «ربه فلبث» مكث يوسف «في السجن بضع سنين» قيل سبعا وقيل اثنتي عشرة."},
  {'n': '43', 'v': "وَقَالَ ٱلْمَلِكُ إِنِّىٓ أَرَىٰ سَبْعَ بَقَرَٰتٍۢ سِمَانٍۢ يَأْكُلُهُنَّ سَبْعٌ عِجَافٌۭ وَسَبْعَ سُنۢبُلَٰتٍ خُضْرٍۢ وَأُخَرَ يَابِسَٰتٍۢ ۖ يَٰٓأَيُّهَا ٱلْمَلَأُ أَفْتُونِى فِى رُءْيَٰىَ إِن كُنتُمْ لِلرُّءْيَا تَعْبُرُونَ", 't': "«وقال الملك» ملك مصر الريان بن الوليد «إني أرى» أي رأيت «سبع بقرات سمان يأكلهن» يبتلعهن «سبع» من البقر «عجاف» جمع عجفاء «وسبع سنبلات خضر وأخر» أي سبع سنبلات «يابسات» قد التوت على الخضر وعلت عليها «يا أيها الملأ أفتوني في رؤياي» بينوا لي تعبيرها «إن كنتم للرؤيا تعبرون» فاعبروها."},
  {'n': '44', 'v': "قَالُوٓا۟ أَضْغَٰثُ أَحْلَٰمٍۢ ۖ وَمَا نَحْنُ بِتَأْوِيلِ ٱلْأَحْلَٰمِ بِعَٰلِمِينَ", 't': "«قالوا» هذه «أضغاث أحلام» أخلاط «وما نحن بتأويل الأحلام بعالمين»."},
  {'n': '45', 'v': "وَقَالَ ٱلَّذِى نَجَا مِنْهُمَا وَٱدَّكَرَ بَعْدَ أُمَّةٍ أَنَا۠ أُنَبِّئُكُم بِتَأْوِيلِهِۦ فَأَرْسِلُونِ", 't': "«وقال الذي نجا منهما» أي من الفَتَيِيْنِ وهو الساقي «وادَّكر» فيه إبدال التاء في الأصل دالا وإدغامها في الدال أي تذكر «بعد أُمَّةٍ» حينِ حال يوسف «أنا أنبئكم بتأويله فأرسلون» فأرسلوه فأتى يوسف فقال."},
  {'n': '46', 'v': "يُوسُفُ أَيُّهَا ٱلصِّدِّيقُ أَفْتِنَا فِى سَبْعِ بَقَرَٰتٍۢ سِمَانٍۢ يَأْكُلُهُنَّ سَبْعٌ عِجَافٌۭ وَسَبْعِ سُنۢبُلَٰتٍ خُضْرٍۢ وَأُخَرَ يَابِسَٰتٍۢ لَّعَلِّىٓ أَرْجِعُ إِلَى ٱلنَّاسِ لَعَلَّهُمْ يَعْلَمُونَ", 't': "يا «يوسف أيها الصدّيق» الكثير الصدق «أفتنا في سبع بقرات سمان يأكلهن سبع عجاف وسبع سنبلات خضر وأخر يابسات لعلي أرجع إلى الناس» أي الملك وأصحابه «لعلهم يعلمون» تعبيرها."},
  {'n': '47', 'v': "قَالَ تَزْرَعُونَ سَبْعَ سِنِينَ دَأَبًۭا فَمَا حَصَدتُّمْ فَذَرُوهُ فِى سُنۢبُلِهِۦٓ إِلَّا قَلِيلًۭا مِّمَّا تَأْكُلُونَ", 't': "«قال تزرعون» أي ازرعوا «سبع سنين دأبا» متتابعة وهي تأويل السبع السمان «فما حصدتم فذروه» أي اتركوه «في سنبله» لئلا يفسد «إلا قليلا مما تأكلون» فادرسوه."},
  {'n': '48', 'v': "ثُمَّ يَأْتِى مِنۢ بَعْدِ ذَٰلِكَ سَبْعٌۭ شِدَادٌۭ يَأْكُلْنَ مَا قَدَّمْتُمْ لَهُنَّ إِلَّا قَلِيلًۭا مِّمَّا تُحْصِنُونَ", 't': "«ثم يأتي من بعد ذلك» أي السبع المخصبات «سبع شداد» مجدبات صعاب وهي تأويل السبع العجاف «يأكلن ما قدمتم لهن» من الحب المزروع في السنين المخصبات أي تأكلونه «إلا قليلا مما تحصنون» تدخرون."},
  {'n': '49', 'v': "ثُمَّ يَأْتِى مِنۢ بَعْدِ ذَٰلِكَ عَامٌۭ فِيهِ يُغَاثُ ٱلنَّاسُ وَفِيهِ يَعْصِرُونَ", 't': "«ثم يأتي من بعد ذلك» أي السبع المجدبات «عام فيه يغاث الناس» بالمطر «وفيه يعصرون» الأعناب وغيرها لخصبه."},
  {'n': '50', 'v': "وَقَالَ ٱلْمَلِكُ ٱئْتُونِى بِهِۦ ۖ فَلَمَّا جَآءَهُ ٱلرَّسُولُ قَالَ ٱرْجِعْ إِلَىٰ رَبِّكَ فَسْـَٔلْهُ مَا بَالُ ٱلنِّسْوَةِ ٱلَّٰتِى قَطَّعْنَ أَيْدِيَهُنَّ ۚ إِنَّ رَبِّى بِكَيْدِهِنَّ عَلِيمٌۭ", 't': "«وقال الملك» لما جاءه الرسول وأخبره بتأويلها «ائتوني به» أي بالذي عبرها «فلما جاءه» أي يوسف «الرسول» وطلبه للخروج «قال» قاصدا إظهار براءته «ارجع إلى ربك فاسأله» أن يسأل «ما بال» حال «النسوة اللاتي قطعن أيديهن إن ربي» سيدي «بكيدهن عليم» فرجع فأخبر الملك فجمعهن."},
  {'n': '51', 'v': "قَالَ مَا خَطْبُكُنَّ إِذْ رَٰوَدتُّنَّ يُوسُفَ عَن نَّفْسِهِۦ ۚ قُلْنَ حَٰشَ لِلَّهِ مَا عَلِمْنَا عَلَيْهِ مِن سُوٓءٍۢ ۚ قَالَتِ ٱمْرَأَتُ ٱلْعَزِيزِ ٱلْـَٰٔنَ حَصْحَصَ ٱلْحَقُّ أَنَا۠ رَٰوَدتُّهُۥ عَن نَّفْسِهِۦ وَإِنَّهُۥ لَمِنَ ٱلصَّٰدِقِينَ", 't': "«قال ما خطبكن» شأنكن «إذ راودتن يوسف عن نفسه» هل وجدتن منه ميلا إليكن «قلن حاش لله ما علمنا عليه من سوء قالت امرأة العزيز الآن حصحص» وضح «الحق أنا راودته عن نفسه وإنه لمن الصادقين» في قوله (هي راودتني عن نفسي) فأخبر يوسف بذلك فقال."},
  {'n': '52', 'v': "ذَٰلِكَ لِيَعْلَمَ أَنِّى لَمْ أَخُنْهُ بِٱلْغَيْبِ وَأَنَّ ٱللَّهَ لَا يَهْدِى كَيْدَ ٱلْخَآئِنِينَ", 't': "«ذلك» أي طلب البراءة «ليعلم» العزيز «أني لم أخنه» في أهله «بالغيب» حال «وأن الله لا يهدي كيد الخائنين» ثم تواضع لله فقال."},
  {'n': '53', 'v': "۞ وَمَآ أُبَرِّئُ نَفْسِىٓ ۚ إِنَّ ٱلنَّفْسَ لَأَمَّارَةٌۢ بِٱلسُّوٓءِ إِلَّا مَا رَحِمَ رَبِّىٓ ۚ إِنَّ رَبِّى غَفُورٌۭ رَّحِيمٌۭ", 't': "«وما أبري نفسي» من الزلل «إن النفس» الجنس «لأمَّارة» كثيرة الأمر «بالسوء إلا ما» بمعنى من «رحم ربي» فعصمه «إن ربي غفور رحيم»."},
  {'n': '54', 'v': "وَقَالَ ٱلْمَلِكُ ٱئْتُونِى بِهِۦٓ أَسْتَخْلِصْهُ لِنَفْسِى ۖ فَلَمَّا كَلَّمَهُۥ قَالَ إِنَّكَ ٱلْيَوْمَ لَدَيْنَا مَكِينٌ أَمِينٌۭ", 't': "«وقال الملك ائتوني به أستخلصه لنفسي» أجعله خالصا لي دون شريك فجاءه الرسول وقال: أجب الملك فقام وودع أهل السجن ودعا لهم ثم اغتسل ولبس ثيابا حسانا ودخل عليه «فلما كلمه قال» له «إنك اليوم لدينا مكين أمين» ذو مكانة وأمانة على أمرنا فماذا ترى أن نفعل؟ قال: اجمع الطعام وازرع زرعا كثيرا في هذه السنين المخصبة وادخر الطعام في سنبله فتأتي إليك الخلق ليمتاروا منك فقال: ومن لي بهذا؟."},
  {'n': '55', 'v': "قَالَ ٱجْعَلْنِى عَلَىٰ خَزَآئِنِ ٱلْأَرْضِ ۖ إِنِّى حَفِيظٌ عَلِيمٌۭ", 't': "«قال» يوسف «اجعلني على خزائن الأرض» أرض مصر «إني حفيظ عليم» ذو حفظ وعلم بأمرها، وقيل كاتب حاسب."},
  {'n': '56', 'v': "وَكَذَٰلِكَ مَكَّنَّا لِيُوسُفَ فِى ٱلْأَرْضِ يَتَبَوَّأُ مِنْهَا حَيْثُ يَشَآءُ ۚ نُصِيبُ بِرَحْمَتِنَا مَن نَّشَآءُ ۖ وَلَا نُضِيعُ أَجْرَ ٱلْمُحْسِنِينَ", 't': "«وكذلك» كإنعامنا عليه بالخلاص من السجن «مكنَّا ليوسف في الأرض» أرض مصر «يتبوّأُ» ينزل «منها حيث يشاء» بعد الضيق والحبس وفي القصة أن الملك توَّجه وختَّمه وولاه مكان العزيز وعزله ومات بعد، فزوجه امرأته فوجدها عذراء وولدت له ولدين، وأقام العدل بمصر ودانت له الرقاب «نصيب برحمتنا من نشاء ولا نضيع أجر المحسنين»."},
  {'n': '57', 'v': "وَلَأَجْرُ ٱلْءَاخِرَةِ خَيْرٌۭ لِّلَّذِينَ ءَامَنُوا۟ وَكَانُوا۟ يَتَّقُونَ", 't': "«ولأجر الآخرة خير» من أجر الدنيا «للذين آمنوا وكانوا يتقون» ودخلت سنو القحط وأصاب أرض كنعان والشام."},
  {'n': '58', 'v': "وَجَآءَ إِخْوَةُ يُوسُفَ فَدَخَلُوا۟ عَلَيْهِ فَعَرَفَهُمْ وَهُمْ لَهُۥ مُنكِرُونَ", 't': "«وجاء إخوة يوسف» إلا بنيامين ليمتاروا لما بلغهم أن عزيز مصر يعطي الطعام بثمنه «فدخلوا عليه فعرفهم» أنهم إخوته «وهم له منكرون» لا يعرفونه لبعد عهدهم به وظنهم هلاكه فكلموه بالعبرانية فقال كالمنكر عليهم: ما أقدمكم بلادي؟ فقالوا للميرة فقال لعلكم عيون قالوا معاذ الله قال فمن أين أنتم؟ قالوا من بلاد كنعان وأبونا يعقوب نبي الله، قال وله أولاد غيركم؟ قالوا نعم كنا اثني عشر فذهب أصغرنا هلك في البرية وكان أحبَّنا إليه وبقي شقيقه فاحتبسه ليتسلى به عنه فأمر بإنزالهم وإكرامهم."},
  {'n': '59', 'v': "وَلَمَّا جَهَّزَهُم بِجَهَازِهِمْ قَالَ ٱئْتُونِى بِأَخٍۢ لَّكُم مِّنْ أَبِيكُمْ ۚ أَلَا تَرَوْنَ أَنِّىٓ أُوفِى ٱلْكَيْلَ وَأَنَا۠ خَيْرُ ٱلْمُنزِلِينَ", 't': "«ولما جهزهم بجهازهم» وفى لهم كيلهم «قال ائتوني بأخ لكم من أبيكم» أي بنيامين لأعلم صدقكم فيما قلتم «ألا ترون أني أوفي الكيل» أتمه من غير بخس «وأنا خير المنزلين»."},
  {'n': '60', 'v': "فَإِن لَّمْ تَأْتُونِى بِهِۦ فَلَا كَيْلَ لَكُمْ عِندِى وَلَا تَقْرَبُونِ", 't': "«فإن لم تأتوني به فلا كيل لكم عندي» أي ميرة «ولا تقربون» نهي أو عطف على محل فلا كيل أي تحرموا ولا تقربوا."},
  {'n': '61', 'v': "قَالُوا۟ سَنُرَٰوِدُ عَنْهُ أَبَاهُ وَإِنَّا لَفَٰعِلُونَ", 't': "«قالوا سنراود عنه أباه» سنجتهد في طلبه منه «وإنا لفاعلون» ذلك."},
  {'n': '62', 'v': "وَقَالَ لِفِتْيَٰنِهِ ٱجْعَلُوا۟ بِضَٰعَتَهُمْ فِى رِحَالِهِمْ لَعَلَّهُمْ يَعْرِفُونَهَآ إِذَا ٱنقَلَبُوٓا۟ إِلَىٰٓ أَهْلِهِمْ لَعَلَّهُمْ يَرْجِعُونَ", 't': "«وقال لفتيته» وفي قراءة لفتيانه غلمانه «اجعلوا بضاعتهم» التي أتوا بها ثمن الميرة وكانت دراهم «في رحالهم» أوعيتهم «لعلهم يعرفونها إذا انقلبوا إلى أهلهم» وفرغوا أوعيتهم «لعلم يرجعون» إلينا لأنهم لا يستحلون إمساكها."},
  {'n': '63', 'v': "فَلَمَّا رَجَعُوٓا۟ إِلَىٰٓ أَبِيهِمْ قَالُوا۟ يَٰٓأَبَانَا مُنِعَ مِنَّا ٱلْكَيْلُ فَأَرْسِلْ مَعَنَآ أَخَانَا نَكْتَلْ وَإِنَّا لَهُۥ لَحَٰفِظُونَ", 't': "«فلما رجعوا إلى أبيهم قالوا: يا أبانا منع منا الكيل» إن لم ترسل أخانا إليه «فأرسل معنا أخانا نكتل» بالنون والياء «وإنا له لحافظون»."},
  {'n': '64', 'v': "قَالَ هَلْ ءَامَنُكُمْ عَلَيْهِ إِلَّا كَمَآ أَمِنتُكُمْ عَلَىٰٓ أَخِيهِ مِن قَبْلُ ۖ فَٱللَّهُ خَيْرٌ حَٰفِظًۭا ۖ وَهُوَ أَرْحَمُ ٱلرَّٰحِمِينَ", 't': "«قال هل» ما «آمنكم عليه إلا كما أمنتكم على أخيه» يوسف «من قبل» وقد فعلتم به ما فعلتم «فالله خير حفظا» وفي قراءة حافظا تمييز كقولهم لله دره فارسا «وهو أرحم الراحمين» فأرجو أن يمن بحفظه."},
  {'n': '65', 'v': "وَلَمَّا فَتَحُوا۟ مَتَٰعَهُمْ وَجَدُوا۟ بِضَٰعَتَهُمْ رُدَّتْ إِلَيْهِمْ ۖ قَالُوا۟ يَٰٓأَبَانَا مَا نَبْغِى ۖ هَٰذِهِۦ بِضَٰعَتُنَا رُدَّتْ إِلَيْنَا ۖ وَنَمِيرُ أَهْلَنَا وَنَحْفَظُ أَخَانَا وَنَزْدَادُ كَيْلَ بَعِيرٍۢ ۖ ذَٰلِكَ كَيْلٌۭ يَسِيرٌۭ", 't': "«ولما فتحوا متاعهم وجدوا بضاعتهم ردت إليهم قالوا يا أبانا ما نبغي» ما استفهامية أي أيَّ نطلب من إكرام الملك أعظم من هذا وقرئ بالفوقانية خطابا ليعقوب وكانوا ذكروا له إكرامه لهم «هذه بضاعتنا ردت إلينا ونمير أهلنا» تأتي بالميرة لهم وهي الطعام «ونحفظ أخانا ونزداد كيل بعير» لأخينا «ذلك كيل يسير» سهل على الملك لسخائه."},
  {'n': '66', 'v': "قَالَ لَنْ أُرْسِلَهُۥ مَعَكُمْ حَتَّىٰ تُؤْتُونِ مَوْثِقًۭا مِّنَ ٱللَّهِ لَتَأْتُنَّنِى بِهِۦٓ إِلَّآ أَن يُحَاطَ بِكُمْ ۖ فَلَمَّآ ءَاتَوْهُ مَوْثِقَهُمْ قَالَ ٱللَّهُ عَلَىٰ مَا نَقُولُ وَكِيلٌۭ", 't': "«قال لن أرسله معكم حتى تؤتون موثقا» عهدا «من الله» بأن تحلفوا «لتأتنني به إلا أن يحاط بكم» بأن تموتوا أو تغلبوا فلا تطيقوا الإتيان به فأجابوه إلى ذلك «فلما آتوه موثقهم» بذلك «قال الله على ما نقول» نحن وأنتم «وكيل» شهيد وأرسله معهم."},
  {'n': '67', 'v': "وَقَالَ يَٰبَنِىَّ لَا تَدْخُلُوا۟ مِنۢ بَابٍۢ وَٰحِدٍۢ وَٱدْخُلُوا۟ مِنْ أَبْوَٰبٍۢ مُّتَفَرِّقَةٍۢ ۖ وَمَآ أُغْنِى عَنكُم مِّنَ ٱللَّهِ مِن شَىْءٍ ۖ إِنِ ٱلْحُكْمُ إِلَّا لِلَّهِ ۖ عَلَيْهِ تَوَكَّلْتُ ۖ وَعَلَيْهِ فَلْيَتَوَكَّلِ ٱلْمُتَوَكِّلُونَ", 't': "«وقال يا بني لا تدخلوا» مصر «من باب واحد وادخلوا من أبواب متفرقة» لئلا تصيبكم العين «وما أغني» أدفع «عنكم» بقولي ذلك «من الله من» زائدة «شيء» قدَّره عليكم وإنما ذلك شفقة «إن» ما «الحكم إلا لله» وحده «عليه توكلت» به وثقت «وعليه فليتوكل المتوكلون»."},
  {'n': '68', 'v': "وَلَمَّا دَخَلُوا۟ مِنْ حَيْثُ أَمَرَهُمْ أَبُوهُم مَّا كَانَ يُغْنِى عَنْهُم مِّنَ ٱللَّهِ مِن شَىْءٍ إِلَّا حَاجَةًۭ فِى نَفْسِ يَعْقُوبَ قَضَىٰهَا ۚ وَإِنَّهُۥ لَذُو عِلْمٍۢ لِّمَا عَلَّمْنَٰهُ وَلَٰكِنَّ أَكْثَرَ ٱلنَّاسِ لَا يَعْلَمُونَ", 't': "«قال تعالى: «ولما دخلوا من حيث أمرهم أبوهم» أي متفرقين «ما كان يغني عنهم من الله» أي قضائه «من» زائدة «شيء إلا» لكن «حاجة في نفس يعقوب قضاها» وهي إرادة دفع العين شفقة «وإنه لذو علم لما علمناه» لتعليمنا إياه «ولكن أكثر الناس» وهم الكفار «لا يعلمون» إلهام الله لأصفيائه."},
  {'n': '69', 'v': "وَلَمَّا دَخَلُوا۟ عَلَىٰ يُوسُفَ ءَاوَىٰٓ إِلَيْهِ أَخَاهُ ۖ قَالَ إِنِّىٓ أَنَا۠ أَخُوكَ فَلَا تَبْتَئِسْ بِمَا كَانُوا۟ يَعْمَلُونَ", 't': "«ولما دخلوا على يوسف آوى» ضم «إليه أخاه قال إني أنا أخوك فلا تبتئس» تحزن «بما كانوا يعملون» من الحسد لنا وأمره ألا يخبرهم وتواطأ معه على أنه سيحتال على أن يبقيه عنده."},
  {'n': '70', 'v': "فَلَمَّا جَهَّزَهُم بِجَهَازِهِمْ جَعَلَ ٱلسِّقَايَةَ فِى رَحْلِ أَخِيهِ ثُمَّ أَذَّنَ مُؤَذِّنٌ أَيَّتُهَا ٱلْعِيرُ إِنَّكُمْ لَسَٰرِقُونَ", 't': "«فلما جهزهم بجهازهم جعل السقاية» هي صاع من الذهب مرصع بالجوهر «في رحل أخيه» بنيامين «ثم أذن مؤذن» نادى مناد بعد انفصالهم عن مجلس يوسف «أيتها العير» القافلة «إنكم لسارقون»."},
  {'n': '71', 'v': "قَالُوا۟ وَأَقْبَلُوا۟ عَلَيْهِم مَّاذَا تَفْقِدُونَ", 't': "«قالوا و» قد «أقبلوا عليهم ماذا» ما الذي «تفقدونـ» ـه."},
  {'n': '72', 'v': "قَالُوا۟ نَفْقِدُ صُوَاعَ ٱلْمَلِكِ وَلِمَن جَآءَ بِهِۦ حِمْلُ بَعِيرٍۢ وَأَنَا۠ بِهِۦ زَعِيمٌۭ", 't': "«قالوا نفقد صواع» صاع «الملك ولمن جاء به حمل بعير» من الطعام «وأنا به» بالحمل «زعيم» كفيل."},
  {'n': '73', 'v': "قَالُوا۟ تَٱللَّهِ لَقَدْ عَلِمْتُم مَّا جِئْنَا لِنُفْسِدَ فِى ٱلْأَرْضِ وَمَا كُنَّا سَٰرِقِينَ", 't': "«قالوا تالله» قسم فيه معنى التعجب «لقد علمتم ما جئنا لنفسد في الأرض وما كنا سارقين» ما سرقنا قط."},
  {'n': '74', 'v': "قَالُوا۟ فَمَا جَزَٰٓؤُهُۥٓ إِن كُنتُمْ كَٰذِبِينَ", 't': "«قالوا» أي المؤذن وأصحابه «فما جزاؤه» أي السارق «إن كنتم كاذبين» في قولكم ما كنا سارقين ووجد فيكم."},
  {'n': '75', 'v': "قَالُوا۟ جَزَٰٓؤُهُۥ مَن وُجِدَ فِى رَحْلِهِۦ فَهُوَ جَزَٰٓؤُهُۥ ۚ كَذَٰلِكَ نَجْزِى ٱلظَّٰلِمِينَ", 't': "«قالوا جزاؤه» مبتدأ خبره «من وجد في رحله» يُسْتَرق ثم أكد بقوله «فهو» أي السارق «جزاؤه» أي المسروق لا غير وكانت سنة آل يعقوب «كذلك» الجزاء «نجزي الظالمين» بالسرقة فصرحوا ليوسف بتفتيش أوعيتهم."},
  {'n': '76', 'v': "فَبَدَأَ بِأَوْعِيَتِهِمْ قَبْلَ وِعَآءِ أَخِيهِ ثُمَّ ٱسْتَخْرَجَهَا مِن وِعَآءِ أَخِيهِ ۚ كَذَٰلِكَ كِدْنَا لِيُوسُفَ ۖ مَا كَانَ لِيَأْخُذَ أَخَاهُ فِى دِينِ ٱلْمَلِكِ إِلَّآ أَن يَشَآءَ ٱللَّهُ ۚ نَرْفَعُ دَرَجَٰتٍۢ مَّن نَّشَآءُ ۗ وَفَوْقَ كُلِّ ذِى عِلْمٍ عَلِيمٌۭ", 't': "«فبدأ بأوعيتهم» ففتشها «قبل وعاء أخيه» لئلا يتهم «ثم استخرجها» أي السقاية «من وعاء أخيه» قال تعالى: «كذلك» الكيد «كدنا ليوسف» علمناه الاحتيال في أخذ أخيه «ما كان» يوسف «ليأخذ أخاه» رقيقا عن السرقة «في دين الملك» حكم ملك مصر لأن جزاءه عنده الضرب وتغريم مثلي المسروق لا الاسترقاق «إلا أن يشاء الله» أخذه بحكم أبيه أي لم يتمكن من أخذه إلا بمشيئة الله بإلهامه سؤال إخوته وجوابهم بسنتهم «نرفع درجاتِ من نشاء» بالإضافة والتنوين في العلم كيوسف «وفوق كل ذي علم» من المخلوقين «عليم» أعلم منه حتى ينتهي إلى الله تعالى."},
  {'n': '77', 'v': "۞ قَالُوٓا۟ إِن يَسْرِقْ فَقَدْ سَرَقَ أَخٌۭ لَّهُۥ مِن قَبْلُ ۚ فَأَسَرَّهَا يُوسُفُ فِى نَفْسِهِۦ وَلَمْ يُبْدِهَا لَهُمْ ۚ قَالَ أَنتُمْ شَرٌّۭ مَّكَانًۭا ۖ وَٱللَّهُ أَعْلَمُ بِمَا تَصِفُونَ", 't': "«قالوا إن يسرق فقد سرق أخ له من قبل» أي يوسف وكان سرق لأبي أمه صنما من ذهب فكسره لئلا يعبده «فأسرها يوسف في نفسه ولم يبدها» يظهرها «لهم» والضمير للكلمة التي في قوله «قال» في نفسه «أنتم شر مكانا» من يوسف وأخيه لسرقتكم أخاكم من أبيكم وظلمكم له «والله أعلم» عالم «بما تصفون» تذكرون من أمره."},
  {'n': '78', 'v': "قَالُوا۟ يَٰٓأَيُّهَا ٱلْعَزِيزُ إِنَّ لَهُۥٓ أَبًۭا شَيْخًۭا كَبِيرًۭا فَخُذْ أَحَدَنَا مَكَانَهُۥٓ ۖ إِنَّا نَرَىٰكَ مِنَ ٱلْمُحْسِنِينَ", 't': "«قالوا يا أيها العزيز إن له أبا شيخا كبيرا» يحبه أكثر منا ويتسلى به عن ولده الهالك ويحزنه ففراقه «فخذ أحدنا» استبعده «مكانه» بدلا منه «إنا نراك من المحسنين» في أفعالك."},
  {'n': '79', 'v': "قَالَ مَعَاذَ ٱللَّهِ أَن نَّأْخُذَ إِلَّا مَن وَجَدْنَا مَتَٰعَنَا عِندَهُۥٓ إِنَّآ إِذًۭا لَّظَٰلِمُونَ", 't': "«قال معاذ الله» نصب على المصدر حذف فعله وأضيف إلى المفعول أي نعوذ بالله من «أن نأخذ إلا من وجدنا متاعنا عنده» لم يقل من سرق تحرّزا من الكذب «إنا إذا» إن أخذنا غيره «لظالمون»."},
  {'n': '80', 'v': "فَلَمَّا ٱسْتَيْـَٔسُوا۟ مِنْهُ خَلَصُوا۟ نَجِيًّۭا ۖ قَالَ كَبِيرُهُمْ أَلَمْ تَعْلَمُوٓا۟ أَنَّ أَبَاكُمْ قَدْ أَخَذَ عَلَيْكُم مَّوْثِقًۭا مِّنَ ٱللَّهِ وَمِن قَبْلُ مَا فَرَّطتُمْ فِى يُوسُفَ ۖ فَلَنْ أَبْرَحَ ٱلْأَرْضَ حَتَّىٰ يَأْذَنَ لِىٓ أَبِىٓ أَوْ يَحْكُمَ ٱللَّهُ لِى ۖ وَهُوَ خَيْرُ ٱلْحَٰكِمِينَ", 't': "«فلما استيأسوا» يئسوا «منه خلصوا» اعتزلوا «نجيا» مصدر يصلح للواحد وغيره أي يناجي بعضهم بعضا «قال كبيرهم» سنًّا روبيل أو رأيا: يهوذا «ألم تعلموا أن أباكم قد أخذ عليكم موثقا» عهدا «من الله» في أخيكم «ومن قبل ما» زائد «فرطتم في يوسف» وقيل ما مصدرية مبتدأ خبره من قبل «فلن أبرح» أفارق «الأرض» أرض مصر «حتى يأذن لي أبي» بالعود إليه «أو يحكم الله لي» بخلاص أخي «وهو خير الحاكمين» أعدلهم."},
  {'n': '81', 'v': "ٱرْجِعُوٓا۟ إِلَىٰٓ أَبِيكُمْ فَقُولُوا۟ يَٰٓأَبَانَآ إِنَّ ٱبْنَكَ سَرَقَ وَمَا شَهِدْنَآ إِلَّا بِمَا عَلِمْنَا وَمَا كُنَّا لِلْغَيْبِ حَٰفِظِينَ", 't': "«ارجعوا إلى أبيكم فقولوا يا أبانا إن ابنك سرق وما شهدنا» عليه «إلا بما علمنا» تيقنَّا من مشاهدة الصاع في رحله «وما كنا للغيب» لما غاب عنا حين إعطاء الموثق «حافظين» ولو علمنا أنه يسرق لم نأخذه."},
  {'n': '82', 'v': "وَسْـَٔلِ ٱلْقَرْيَةَ ٱلَّتِى كُنَّا فِيهَا وَٱلْعِيرَ ٱلَّتِىٓ أَقْبَلْنَا فِيهَا ۖ وَإِنَّا لَصَٰدِقُونَ", 't': "«واسأل القرية التي كنا فيها» هي مصر أي أرسل إلى أهلها فاسألهم «والعير» أصحاب العير «التي أقبلنا فيها» وهم قوم من كنعان «وإنا لصادقون» في قولنا فرجعوا إليه وقالوا له ذلك."},
  {'n': '83', 'v': "قَالَ بَلْ سَوَّلَتْ لَكُمْ أَنفُسُكُمْ أَمْرًۭا ۖ فَصَبْرٌۭ جَمِيلٌ ۖ عَسَى ٱللَّهُ أَن يَأْتِيَنِى بِهِمْ جَمِيعًا ۚ إِنَّهُۥ هُوَ ٱلْعَلِيمُ ٱلْحَكِيمُ", 't': "«قال بل سولت» زينت «لكم أنفسكم أمرا» ففعلتموه اتهمهم لما سبق منهم من أمر يوسف «فصبر جميل» صبري «عسى الله أن يأتيني بهم» بيوسف وأخويه «جميعا إنه هو العليم» بحالي «الحكيم» في صنعه."},
  {'n': '84', 'v': "وَتَوَلَّىٰ عَنْهُمْ وَقَالَ يَٰٓأَسَفَىٰ عَلَىٰ يُوسُفَ وَٱبْيَضَّتْ عَيْنَاهُ مِنَ ٱلْحُزْنِ فَهُوَ كَظِيمٌۭ", 't': "«وتولى عنهم» تاركا خطابهم «وقال يا أسفى» الألف بدل من ياء الإضافة أي يا حزني «على يوسف وابيضت عيناه» انمحق سوادهما وبدل بياضا من بكائه «من الحزن» عليه «فهو كظيم» مغموم مكروب لا يظهر كربه."},
  {'n': '85', 'v': "قَالُوا۟ تَٱللَّهِ تَفْتَؤُا۟ تَذْكُرُ يُوسُفَ حَتَّىٰ تَكُونَ حَرَضًا أَوْ تَكُونَ مِنَ ٱلْهَٰلِكِينَ", 't': "«قالوا تالله» لا «تفتأ» تزال «تذكر يوسف حتى تكون حرضا» مشرفا على الهلاك لطول مرضك وهو مصدر يستوي فيه الواحد وغيره «أو تكون من الهالكين» الموتى."},
  {'n': '86', 'v': "قَالَ إِنَّمَآ أَشْكُوا۟ بَثِّى وَحُزْنِىٓ إِلَى ٱللَّهِ وَأَعْلَمُ مِنَ ٱللَّهِ مَا لَا تَعْلَمُونَ", 't': "«قال» لهم «إنما أشكو بثي» هو عظيم الحزن الذي لا يصبر عليه حتى يبث إلى الناس «وحزني إلى الله» لا إلى غيره فهو الذي تنفع الشكوى إليه «وأعلم من الله ما لا تعلمون» من أن رؤيا يوسف صدق وهو حي ثم قال."},
  {'n': '87', 'v': "يَٰبَنِىَّ ٱذْهَبُوا۟ فَتَحَسَّسُوا۟ مِن يُوسُفَ وَأَخِيهِ وَلَا تَا۟يْـَٔسُوا۟ مِن رَّوْحِ ٱللَّهِ ۖ إِنَّهُۥ لَا يَا۟يْـَٔسُ مِن رَّوْحِ ٱللَّهِ إِلَّا ٱلْقَوْمُ ٱلْكَٰفِرُونَ", 't': "«يا بني اذهبوا فتحسسوا من يوسف وأخيه» اطلبوا خبرهما «ولا تيأسوا» تقنطوا «من روح الله» رحمته «إنه لا ييأس من روح الله إلا القوم الكافرون» فانطلقوا نحو مصر ليوسف."},
  {'n': '88', 'v': "فَلَمَّا دَخَلُوا۟ عَلَيْهِ قَالُوا۟ يَٰٓأَيُّهَا ٱلْعَزِيزُ مَسَّنَا وَأَهْلَنَا ٱلضُّرُّ وَجِئْنَا بِبِضَٰعَةٍۢ مُّزْجَىٰةٍۢ فَأَوْفِ لَنَا ٱلْكَيْلَ وَتَصَدَّقْ عَلَيْنَآ ۖ إِنَّ ٱللَّهَ يَجْزِى ٱلْمُتَصَدِّقِينَ", 't': "«فلما دخلوا عليه قالوا يا أيها العزيز مسنا وأهلنا الضر» الجوع «وجئنا ببضاعة مزجاة» مدفوعة يدفعها كل من رآها لرداءتها وكانت دراهم زيوفا أو غيرها «فأوف» أتم «لنا الكيل وتصدق علينا» بالمسامحة عن رداءة بضاعتنا «إن الله يجزي المتصدقين» يثيبهم فَرَقَّ لهم وأدركته الرحمة ورفع الحجاب بينه وبينهم."},
  {'n': '89', 'v': "قَالَ هَلْ عَلِمْتُم مَّا فَعَلْتُم بِيُوسُفَ وَأَخِيهِ إِذْ أَنتُمْ جَٰهِلُونَ", 't': "ثم «قال» لهم توبيخا «هل علمتم ما فعلتم بيوسف» من الضرب والبيع وغير ذلك «وأخيه» من هضمكم له بعد فراق أخيه «إذ أنتم جاهلون» ما يئول إليه أمر يوسف."},
  {'n': '90', 'v': "قَالُوٓا۟ أَءِنَّكَ لَأَنتَ يُوسُفُ ۖ قَالَ أَنَا۠ يُوسُفُ وَهَٰذَآ أَخِى ۖ قَدْ مَنَّ ٱللَّهُ عَلَيْنَآ ۖ إِنَّهُۥ مَن يَتَّقِ وَيَصْبِرْ فَإِنَّ ٱللَّهَ لَا يُضِيعُ أَجْرَ ٱلْمُحْسِنِينَ", 't': "«قالوا» بعد أن عرفوه لما ظهر من شمائله متثبتين «أإنك» بتحقيق الهمزتين وتسهيل الثانية وإدخال ألف بينهما على الوجهين «لأنت يوسف قال أنا يوسف وهذا أخي قد منَّ» أنعم «الله علينا» بالاجتماع «إنه من يتق» يخف الله «ويصبر» على ما يناله «فإن الله لا يضيع أجر المحسنين» فيه وضع الظاهر موضع المضمر."},
  {'n': '91', 'v': "قَالُوا۟ تَٱللَّهِ لَقَدْ ءَاثَرَكَ ٱللَّهُ عَلَيْنَا وَإِن كُنَّا لَخَٰطِـِٔينَ", 't': "«قالوا تالله لقد آثرك» فضلك «الله علينا» بالملك وغيره «وإن» مخففة أي إنَّا «كنا لخاطئين» آثمين في أمرك فأذللناك."},
  {'n': '92', 'v': "قَالَ لَا تَثْرِيبَ عَلَيْكُمُ ٱلْيَوْمَ ۖ يَغْفِرُ ٱللَّهُ لَكُمْ ۖ وَهُوَ أَرْحَمُ ٱلرَّٰحِمِينَ", 't': "«قال لا تثريب» عتب «عليكم اليوم» خصه بالذكر لأنه مظنة التثريب فغيره أولى «يغفر الله لكم وهو أرحم الراحمين» وسألهم عن أبيه فقالوا ذهبت عيناه فقال."},
  {'n': '93', 'v': "ٱذْهَبُوا۟ بِقَمِيصِى هَٰذَا فَأَلْقُوهُ عَلَىٰ وَجْهِ أَبِى يَأْتِ بَصِيرًۭا وَأْتُونِى بِأَهْلِكُمْ أَجْمَعِينَ", 't': "«اذهبوا بقميصي هذا» وهو قميص إبراهيم الذي لبسه حين ألقي في النار كان في عنقه في الجب وهو من الجنة أمره جبريل بإرساله وقال إن فيه ريحها ولا يُلقى على مبتلًى إلا عوفي «فألقوه على وجه أبي يأت» يصر «بصيرا وائتوني بأهلكم أجمعين»."},
  {'n': '94', 'v': "وَلَمَّا فَصَلَتِ ٱلْعِيرُ قَالَ أَبُوهُمْ إِنِّى لَأَجِدُ رِيحَ يُوسُفَ ۖ لَوْلَآ أَن تُفَنِّدُونِ", 't': "«ولما فصلت العير» خرجت من عريش مصر «قال أبوهم» لمن حضر من بنيه وأولادهم «إني لأجد ريح يوسف» أوصلته إليه الصبا بإذنه تعالى من مسير ثلاثة أيام أو ثمانية أو أكثر «لولا أن تفندونِ» تسفهون لصدقتموني."},
  {'n': '95', 'v': "قَالُوا۟ تَٱللَّهِ إِنَّكَ لَفِى ضَلَٰلِكَ ٱلْقَدِيمِ", 't': "«قالوا» له «تالله إنك لفي ضلالك» خطئك «القديم» من إفراطك في محبته ورجاء لقائه على بعد العهد."},
  {'n': '96', 'v': "فَلَمَّآ أَن جَآءَ ٱلْبَشِيرُ أَلْقَىٰهُ عَلَىٰ وَجْهِهِۦ فَٱرْتَدَّ بَصِيرًۭا ۖ قَالَ أَلَمْ أَقُل لَّكُمْ إِنِّىٓ أَعْلَمُ مِنَ ٱللَّهِ مَا لَا تَعْلَمُونَ", 't': "«فلما أن» زائدة «جاء البشير» يهوذا بالقميص وكان قد حمل قميص الدم فأحب أن يفرحه كما أحزنه «ألقاه» طرح القميص «على وجهه فارتد» رجع «بصيرا قال ألم أقل لكم إني أعلم من الله ما لا تعلمون»."},
  {'n': '97', 'v': "قَالُوا۟ يَٰٓأَبَانَا ٱسْتَغْفِرْ لَنَا ذُنُوبَنَآ إِنَّا كُنَّا خَٰطِـِٔينَ", 't': "«قالوا يا أبانا استغفر لنا ذنوبنا إنا كنا خاطئين»."},
  {'n': '98', 'v': "قَالَ سَوْفَ أَسْتَغْفِرُ لَكُمْ رَبِّىٓ ۖ إِنَّهُۥ هُوَ ٱلْغَفُورُ ٱلرَّحِيمُ", 't': "«قال سوف أستغفر لكم ربي إنه الغفور الرحيم» أخَّر ذلك إلى السحر ليكون أقرب إلى الإجابة أو إلى ليلة الجمعة ثم توجهوا إلى مصر وخرج يوسف والأكابر لتلقيهم."},
  {'n': '99', 'v': "فَلَمَّا دَخَلُوا۟ عَلَىٰ يُوسُفَ ءَاوَىٰٓ إِلَيْهِ أَبَوَيْهِ وَقَالَ ٱدْخُلُوا۟ مِصْرَ إِن شَآءَ ٱللَّهُ ءَامِنِينَ", 't': "«فلما دخلوا على يوسف» في مضربه «آوى» ضم «إليه أبويه» أباه وأمه أو خالته «وقال» لهم «ادخلوا مصر إن شاء الله آمنين» فدخلوا وجلس يوسف على سريره."},
  {'n': '100', 'v': "وَرَفَعَ أَبَوَيْهِ عَلَى ٱلْعَرْشِ وَخَرُّوا۟ لَهُۥ سُجَّدًۭا ۖ وَقَالَ يَٰٓأَبَتِ هَٰذَا تَأْوِيلُ رُءْيَٰىَ مِن قَبْلُ قَدْ جَعَلَهَا رَبِّى حَقًّۭا ۖ وَقَدْ أَحْسَنَ بِىٓ إِذْ أَخْرَجَنِى مِنَ ٱلسِّجْنِ وَجَآءَ بِكُم مِّنَ ٱلْبَدْوِ مِنۢ بَعْدِ أَن نَّزَغَ ٱلشَّيْطَٰنُ بَيْنِى وَبَيْنَ إِخْوَتِىٓ ۚ إِنَّ رَبِّى لَطِيفٌۭ لِّمَا يَشَآءُ ۚ إِنَّهُۥ هُوَ ٱلْعَلِيمُ ٱلْحَكِيمُ", 't': "«ورفع أبويه» أحلهما معه «على العرش» السرير «وخروا» أي أبواه وإخوته «له سجدا» سجود انحناء لا وضع جبهة وكان تحيتهم في ذلك الزمان «وقال يا أبت هذا تأويل رؤياي من قبل قد جعلها ربي حقا وقد أحسن بي» إليَّ «إذ أخرجني من السجن» لم يقل من الحب تكرما لئلا تخجل إخوته «وجاء بكم من البدو» البادية «من بعد أن نزغ» أفسد «الشيطان بيني وبين إخوتي إن ربي لطيف لما يشاء إنه هو العليم» بخلقه «الحكيم» في صنعه وأقام عنده أبوه أربعا وعشرين سنة أو سبع عشرة سنة وكانت مدة فراقه ثماني عشرة أو أربعين أو ثمانين سنة وحضره الموت فوصى يوسف أن يحمله ويدفنه عند أبيه فمضى بنفسه ودفنه ثمة، ثم عاد إلى مصر وأقام بعده ثلاثا وعشرين سنة ولما تم أمره وعلم أنه لا يدوم تاقت نفسه إلى الملك الدائم فقال."},
