  {'n': '17', 'v': "يَتَجَرَّعُهُۥ وَلَا يَكَادُ يُسِيغُهُۥ وَيَأْتِيهِ ٱلْمَوْتُ مِن كُلِّ مَكَانٍۢ وَمَا هُوَ بِمَيِّتٍۢ ۖ وَمِن وَرَآئِهِۦ عَذَابٌ غَلِيظٌۭ", 't': "«يتجرعه» يبتلعه مرة بعد مرة لمرارته «ولا يكاد يسيغه» يزدرده لقبحه وكراهته «ويأتيه الموت» أي أسبابه المقتضية له من أنواع العذاب «من كل مكان وما هو بميت ومن ورائه» بعد ذلك العذاب «عذاب غليظ» قوي متصل."},
  {'n': '18', 'v': "مَّثَلُ ٱلَّذِينَ كَفَرُوا۟ بِرَبِّهِمْ ۖ أَعْمَٰلُهُمْ كَرَمَادٍ ٱشْتَدَّتْ بِهِ ٱلرِّيحُ فِى يَوْمٍ عَاصِفٍۢ ۖ لَّا يَقْدِرُونَ مِمَّا كَسَبُوا۟ عَلَىٰ شَىْءٍۢ ۚ ذَٰلِكَ هُوَ ٱلضَّلَٰلُ ٱلْبَعِيدُ", 't': "«مثل» صفة «الذين كفروا بربهم» مبتدأ ويبدل منه «أعمالهم» الصالحة كصلة وصدقة في عدم الانتفاع بها «كرماد اشتدت به الريح في يوم عاصف» شديد هبوب الريح فجعلته هباءً منثورا لا يقدر عليه والمجرور خبر المبتدأ «لا يقدرون» أي الكفار «مما كسبوا» عملوا في الدنيا «على شيء» أي لا يجدون له ثوابا لعدم شرطه «ذلك هو الضلال» الهلاك «البعيد»."},
  {'n': '19', 'v': "أَلَمْ تَرَ أَنَّ ٱللَّهَ خَلَقَ ٱلسَّمَٰوَٰتِ وَٱلْأَرْضَ بِٱلْحَقِّ ۚ إِن يَشَأْ يُذْهِبْكُمْ وَيَأْتِ بِخَلْقٍۢ جَدِيدٍۢ", 't': "«ألم تر» تنظر يا مخاطب استفهام تقرير «أن الله خلق السماوات والأرض بالحق» متعلق بخلق «إن يشأ يذهبكم» أيها الناس «ويأت بخلق جديد» بدلكم."},
  {'n': '20', 'v': "وَمَا ذَٰلِكَ عَلَى ٱللَّهِ بِعَزِيزٍۢ", 't': "«وما ذلك على الله بعزيز» شديد."},
  {'n': '21', 'v': "وَبَرَزُوا۟ لِلَّهِ جَمِيعًۭا فَقَالَ ٱلضُّعَفَٰٓؤُا۟ لِلَّذِينَ ٱسْتَكْبَرُوٓا۟ إِنَّا كُنَّا لَكُمْ تَبَعًۭا فَهَلْ أَنتُم مُّغْنُونَ عَنَّا مِنْ عَذَابِ ٱللَّهِ مِن شَىْءٍۢ ۚ قَالُوا۟ لَوْ هَدَىٰنَا ٱللَّهُ لَهَدَيْنَٰكُمْ ۖ سَوَآءٌ عَلَيْنَآ أَجَزِعْنَآ أَمْ صَبَرْنَا مَا لَنَا مِن مَّحِيصٍۢ", 't': "«وبرزوا» أي الخلائق والتعبير فيه وفيما بعده بالماضي لتحقيق وقوعه «لله جميعا فقال الضعفاء» الأتباع «للذين استكبروا» المتبوعين «إنا كنا لكم تبعا» جمع تابع «فهل أنتم مغنون» دافعون «عنا من عذاب الله من شيء» من الأولى للتبيين والثانية للتبعيض «قالوا» المتبوعون «لو هدانا الله لهديناكم» لدعوناكم إلى الهدى «سواء علينا أجزعنا أم صبرنا ما لنا من» زائدة «محيص» ملجأ."},
  {'n': '22', 'v': "وَقَالَ ٱلشَّيْطَٰنُ لَمَّا قُضِىَ ٱلْأَمْرُ إِنَّ ٱللَّهَ وَعَدَكُمْ وَعْدَ ٱلْحَقِّ وَوَعَدتُّكُمْ فَأَخْلَفْتُكُمْ ۖ وَمَا كَانَ لِىَ عَلَيْكُم مِّن سُلْطَٰنٍ إِلَّآ أَن دَعَوْتُكُمْ فَٱسْتَجَبْتُمْ لِى ۖ فَلَا تَلُومُونِى وَلُومُوٓا۟ أَنفُسَكُم ۖ مَّآ أَنَا۠ بِمُصْرِخِكُمْ وَمَآ أَنتُم بِمُصْرِخِىَّ ۖ إِنِّى كَفَرْتُ بِمَآ أَشْرَكْتُمُونِ مِن قَبْلُ ۗ إِنَّ ٱلظَّٰلِمِينَ لَهُمْ عَذَابٌ أَلِيمٌۭ", 't': "«وقال الشيطان» إبليس «لما قضي الأمر» وأدخل أهل الجنة الجنة وأهل النار النار واجتمعوا عليه «إن الله وعدكم وعد الحق» بالبعث والجزاء فصدقكم «ووعدتكم» أنه غير كائن «فأخلفتكم وما كان لي عليكم من» زائدة «سلطان» قوة وقدرة أقهركم على متابعتي «إلا» لكن «أن دعوتكم فاستجبتم لي فلا تلوموني ولموا أنفسكم» على إجابتي «ما أنا بمصرخكم» بمغيثكم «وما أنتم بمصرخيَِّ» بفتح الياء وكسرها «إني كفرت بما أشركتمون» بإشراككم إياي مع الله «من قبل» من الدنيا قال تعالى «إن الظالمين» الكافرين «لهم عذاب أليم» مؤلم."},
  {'n': '23', 'v': "وَأُدْخِلَ ٱلَّذِينَ ءَامَنُوا۟ وَعَمِلُوا۟ ٱلصَّٰلِحَٰتِ جَنَّٰتٍۢ تَجْرِى مِن تَحْتِهَا ٱلْأَنْهَٰرُ خَٰلِدِينَ فِيهَا بِإِذْنِ رَبِّهِمْ ۖ تَحِيَّتُهُمْ فِيهَا سَلَٰمٌ", 't': "«وأدخل الذين آمنوا وعملوا الصالحات جنات تجري من تحتها الأنهار خالدين» حال مقدرة «فيها بإذن ربهم تحيتهم فيها» من الله ومن الملائكة وفيما بينهم «سلام»."},
  {'n': '24', 'v': "أَلَمْ تَرَ كَيْفَ ضَرَبَ ٱللَّهُ مَثَلًۭا كَلِمَةًۭ طَيِّبَةًۭ كَشَجَرَةٍۢ طَيِّبَةٍ أَصْلُهَا ثَابِتٌۭ وَفَرْعُهَا فِى ٱلسَّمَآءِ", 't': "«ألم تر» تنظر «كيف ضرب الله مثلا» ويبدل منه «كلمة طيبة» أي لا إله إلا الله «كشجرة طيبة» هي النخلة «أصلها ثابت» في الأرض «وفرعها» غصنها «في السماء»."},
  {'n': '25', 'v': "تُؤْتِىٓ أُكُلَهَا كُلَّ حِينٍۭ بِإِذْنِ رَبِّهَا ۗ وَيَضْرِبُ ٱللَّهُ ٱلْأَمْثَالَ لِلنَّاسِ لَعَلَّهُمْ يَتَذَكَّرُونَ", 't': "«تؤتي» تعطي «أكلها» ثمرها «كل حين بإذن ربها» بإرادته كذلك كلمة الإيمان ثابتة في قلب المؤمن وعمله يصعد إلى السماء ويناله بركته وثوابه كل وقت «ويضرب» يبين «الله الأمثال للناس لعلهم يتذكرون» يتعظون فيؤمنون."},
  {'n': '26', 'v': "وَمَثَلُ كَلِمَةٍ خَبِيثَةٍۢ كَشَجَرَةٍ خَبِيثَةٍ ٱجْتُثَّتْ مِن فَوْقِ ٱلْأَرْضِ مَا لَهَا مِن قَرَارٍۢ", 't': "«ومثل كلمة خبيثة» هي كلمة الكفر «كشجرة خبيثة» هي الحنظل «اجتثت» استؤصلت «من فوق الأرض ما لها من قرار» مستقر وثبات كذلك كلمة الكفر لا ثبات لها ولا فرع ولا بركة."},
  {'n': '27', 'v': "يُثَبِّتُ ٱللَّهُ ٱلَّذِينَ ءَامَنُوا۟ بِٱلْقَوْلِ ٱلثَّابِتِ فِى ٱلْحَيَوٰةِ ٱلدُّنْيَا وَفِى ٱلْءَاخِرَةِ ۖ وَيُضِلُّ ٱللَّهُ ٱلظَّٰلِمِينَ ۚ وَيَفْعَلُ ٱللَّهُ مَا يَشَآءُ", 't': "«يثبت الله الذين آمنوا بالقول الثابت» هي كلمة التوحيد «في الحياة الدنيا وفي الآخرة» أي في القبر لما يسألهم الملكان عن ربهم ودينهم ونبيهم فيجيبون بالصواب كما في حديث الشيخين «ويضل الله الظالمين» الكفار فلا يهتدون للجواب بالصواب بل يقولون لا ندري كما في الحديث «ويفعل الله ما يشاء»."},
  {'n': '28', 'v': "۞ أَلَمْ تَرَ إِلَى ٱلَّذِينَ بَدَّلُوا۟ نِعْمَتَ ٱللَّهِ كُفْرًۭا وَأَحَلُّوا۟ قَوْمَهُمْ دَارَ ٱلْبَوَارِ", 't': "«ألم تر» تنظر «إلى الذين بدلوا نعمة الله» أي شكرها «كفرا» هم كفار قريش «وأحلوا» أنزلوا «قومهم» بإضلالهم إياهم «دار البوار» الهلاك."},
  {'n': '29', 'v': "جَهَنَّمَ يَصْلَوْنَهَا ۖ وَبِئْسَ ٱلْقَرَارُ", 't': "«جهنم» عطف بيان «يصلوْنها» يدخلونها «وبئس القرار» المقر هي."},
  {'n': '30', 'v': "وَجَعَلُوا۟ لِلَّهِ أَندَادًۭا لِّيُضِلُّوا۟ عَن سَبِيلِهِۦ ۗ قُلْ تَمَتَّعُوا۟ فَإِنَّ مَصِيرَكُمْ إِلَى ٱلنَّارِ", 't': "«وجعلوا لله أندادًا» شركاء «ليَُضِلُّوا» بفتح الياء وضمها «عن سبيله» دين الإسلام «قل» لهم «تمتعوا» بدنياكم قليلا «فإن مصيركم» مرجعكم «إلى النار»."},
  {'n': '31', 'v': "قُل لِّعِبَادِىَ ٱلَّذِينَ ءَامَنُوا۟ يُقِيمُوا۟ ٱلصَّلَوٰةَ وَيُنفِقُوا۟ مِمَّا رَزَقْنَٰهُمْ سِرًّۭا وَعَلَانِيَةًۭ مِّن قَبْلِ أَن يَأْتِىَ يَوْمٌۭ لَّا بَيْعٌۭ فِيهِ وَلَا خِلَٰلٌ", 't': "«قل لعبادي الذين آمنوا يقيموا الصلاة وينفقوا مما رزقناهم سرا وعلانية من قبل أن يأتي يوم لا بيع» فداء «فيه ولا خلال» مُخالة أي صداقة تنفع، هو يوم القيامة."},
  {'n': '32', 'v': "ٱللَّهُ ٱلَّذِى خَلَقَ ٱلسَّمَٰوَٰتِ وَٱلْأَرْضَ وَأَنزَلَ مِنَ ٱلسَّمَآءِ مَآءًۭ فَأَخْرَجَ بِهِۦ مِنَ ٱلثَّمَرَٰتِ رِزْقًۭا لَّكُمْ ۖ وَسَخَّرَ لَكُمُ ٱلْفُلْكَ لِتَجْرِىَ فِى ٱلْبَحْرِ بِأَمْرِهِۦ ۖ وَسَخَّرَ لَكُمُ ٱلْأَنْهَٰرَ", 't': "«الله الذي خلق السماوات والأرض وأنزل من السماء ماءً فأخرج به من الثمرات رزقا لكم وسخر لكم الفلك» السفن «لتجري في البحر» بالركوب والحمل «بأمره» بإذنه «وسخر لكم الأنهار»."},
  {'n': '33', 'v': "وَسَخَّرَ لَكُمُ ٱلشَّمْسَ وَٱلْقَمَرَ دَآئِبَيْنِ ۖ وَسَخَّرَ لَكُمُ ٱلَّيْلَ وَٱلنَّهَارَ", 't': "«وسخر لكم الشمس والقمر دائبين» جاريين في فلكهما لا يفتران «وسخر لكم الليل» لتسكنوا فيه «والنهار» لتبتغوا فيه من فضله."},
  {'n': '34', 'v': "وَءَاتَىٰكُم مِّن كُلِّ مَا سَأَلْتُمُوهُ ۚ وَإِن تَعُدُّوا۟ نِعْمَتَ ٱللَّهِ لَا تُحْصُوهَآ ۗ إِنَّ ٱلْإِنسَٰنَ لَظَلُومٌۭ كَفَّارٌۭ", 't': "«وآتاكم من كل ما سألتموه» على حسب مصالحكم «وإن تعدوا نعمة الله» بمعنى إنعامه «لا تحصوها» لا تطيقوا عدها «إن الإنسان» الكافر «لظلوم كفار» كثير الظلم لنفسه بالمعصية والكفر لنعمة ربه."},
  {'n': '35', 'v': "وَإِذْ قَالَ إِبْرَٰهِيمُ رَبِّ ٱجْعَلْ هَٰذَا ٱلْبَلَدَ ءَامِنًۭا وَٱجْنُبْنِى وَبَنِىَّ أَن نَّعْبُدَ ٱلْأَصْنَامَ", 't': "«و» اذكر «إذ قال إبراهيم رب اجعل هذا البلد» مكة «آمنا» ذا أمن وقد أجاب الله دعاءه فجعله حرما لا يسفك فيه دم إنسان ولا يظلم فيه أحد ولا يُصاد صيده ولا يتخلى خلاه «واجنبني» بعدني «وبنيَّ» عن «أن نعبد الأصنام»."},
  {'n': '36', 'v': "رَبِّ إِنَّهُنَّ أَضْلَلْنَ كَثِيرًۭا مِّنَ ٱلنَّاسِ ۖ فَمَن تَبِعَنِى فَإِنَّهُۥ مِنِّى ۖ وَمَنْ عَصَانِى فَإِنَّكَ غَفُورٌۭ رَّحِيمٌۭ", 't': "«رب إنهن» أي الأصنام «أضللن كثيرا من الناس» بعبادتهم لها «فمن تبعني» على التوحيد «فإنه مني» من أهل ديني «ومن عصاني فإنك غفور رحيم» هذا قبل علمه أنه تعالى لا يغفر الشرك."},
  {'n': '37', 'v': "رَّبَّنَآ إِنِّىٓ أَسْكَنتُ مِن ذُرِّيَّتِى بِوَادٍ غَيْرِ ذِى زَرْعٍ عِندَ بَيْتِكَ ٱلْمُحَرَّمِ رَبَّنَا لِيُقِيمُوا۟ ٱلصَّلَوٰةَ فَٱجْعَلْ أَفْـِٔدَةًۭ مِّنَ ٱلنَّاسِ تَهْوِىٓ إِلَيْهِمْ وَٱرْزُقْهُم مِّنَ ٱلثَّمَرَٰتِ لَعَلَّهُمْ يَشْكُرُونَ", 't': "«ربنا إني أسكنت من ذريتي» أي بعضها وهو إسماعيل مع أمه هاجر «بواد غير ذي زرع» هو مكة «عند بيتك المحرم» الذي كان قبل الطوفان «ربنا ليقيموا الصلاة فاجعل أفئدة» قلوبا «من الناس تهوي» تميل وتحنُّ «إليهم» قال ابن عباس لو قال أفئدة الناس لحنت إليه فارس والروم والناس كلهم «وارزقهم من الثمرات لعلهم يشكرون» وقد فعل بنقل الطائف إليه."},
  {'n': '38', 'v': "رَبَّنَآ إِنَّكَ تَعْلَمُ مَا نُخْفِى وَمَا نُعْلِنُ ۗ وَمَا يَخْفَىٰ عَلَى ٱللَّهِ مِن شَىْءٍۢ فِى ٱلْأَرْضِ وَلَا فِى ٱلسَّمَآءِ", 't': "«ربنا إنك تعلم ما نخفي» نسر «وما نعلن وما يخفى على الله من» زائدة «شيء في الأرض ولا في السماء» يحتمل أن يكون من كلامه تعالى أو كلام إبراهيم."},
  {'n': '39', 'v': "ٱلْحَمْدُ لِلَّهِ ٱلَّذِى وَهَبَ لِى عَلَى ٱلْكِبَرِ إِسْمَٰعِيلَ وَإِسْحَٰقَ ۚ إِنَّ رَبِّى لَسَمِيعُ ٱلدُّعَآءِ", 't': "«الحمد لله الذي وهب لي» أعطاني «على» مع «الكبر إسماعيل» ولد وله تسع وتسعون سنة «وإسحاق» ولد وله مائة واثنتا عشرة سنة «إن ربي لسميع الدعاء»."},
  {'n': '40', 'v': "رَبِّ ٱجْعَلْنِى مُقِيمَ ٱلصَّلَوٰةِ وَمِن ذُرِّيَّتِى ۚ رَبَّنَا وَتَقَبَّلْ دُعَآءِ", 't': "«رب اجعلني مقيم الصلاة و» اجعل «من ذريتي» ومن يقيمها وأتى بمن لإعلام الله تعالى له أن منهم كفارا «ربنا وتقبل دعاء» المذكور."},
