  {'n': '21', 'v': "وَإِن مِّن شَىْءٍ إِلَّا عِندَنَا خَزَآئِنُهُۥ وَمَا نُنَزِّلُهُۥٓ إِلَّا بِقَدَرٍۢ مَّعْلُومٍۢ", 't': "«وإن» ما «من» زائدة «شيء إلا عندنا خزائنه» مفاتيح خزائنه «وما ننزله إلا بقدر معلوم» على حسب المصالح."},
  {'n': '22', 'v': "وَأَرْسَلْنَا ٱلرِّيَٰحَ لَوَٰقِحَ فَأَنزَلْنَا مِنَ ٱلسَّمَآءِ مَآءًۭ فَأَسْقَيْنَٰكُمُوهُ وَمَآ أَنتُمْ لَهُۥ بِخَٰزِنِينَ", 't': "«وأرسلنا الرياح لواقح» تلقح السحاب فيمتلئ ماء «فأنزلنا من السماء» السحاب «ماء» مطرا «فأسقيناكموه وما أنتم له بخازنين» أي ليست خزائنه بأيديكم."},
  {'n': '23', 'v': "وَإِنَّا لَنَحْنُ نُحْىِۦ وَنُمِيتُ وَنَحْنُ ٱلْوَٰرِثُونَ", 't': "«وإنا لنحن نحي ونميت ونحن الوارثون» الباقون نرث جميع الخلق."},
  {'n': '24', 'v': "وَلَقَدْ عَلِمْنَا ٱلْمُسْتَقْدِمِينَ مِنكُمْ وَلَقَدْ عَلِمْنَا ٱلْمُسْتَـْٔخِرِينَ", 't': "«ولقد علمنا المستقدمين منكم» أي من تقدم من الخلق من لدن آدم «ولقد علمنا المستأخرين» المتأخرين إلى يوم القيامة."},
  {'n': '25', 'v': "وَإِنَّ رَبَّكَ هُوَ يَحْشُرُهُمْ ۚ إِنَّهُۥ حَكِيمٌ عَلِيمٌۭ", 't': "«وإن ربك هو يحشرهم إنه حكيم» في صنعه «عليم» بخلقه."},
  {'n': '26', 'v': "وَلَقَدْ خَلَقْنَا ٱلْإِنسَٰنَ مِن صَلْصَٰلٍۢ مِّنْ حَمَإٍۢ مَّسْنُونٍۢ", 't': "«ولقد خلقنا الإنسان» آدم «من صلصال» طين يابس يسمع له صلصلة إذا نقر «من حمأ» طين أسود «مسنون» متغير."},
  {'n': '27', 'v': "وَٱلْجَآنَّ خَلَقْنَٰهُ مِن قَبْلُ مِن نَّارِ ٱلسَّمُومِ", 't': "«والجان» أبا الجان وهو إبليس «خلقناه من قبل» أي قبل خلق آدم «من نار السموم» هي نار لا دخان لها تنفذ من المسام."},
  {'n': '28', 'v': "وَإِذْ قَالَ رَبُّكَ لِلْمَلَٰٓئِكَةِ إِنِّى خَٰلِقٌۢ بَشَرًۭا مِّن صَلْصَٰلٍۢ مِّنْ حَمَإٍۢ مَّسْنُونٍۢ", 't': "«و» اذكر «إذ قال ربك للملائكة إني خالق بشرا من صلصال من حمأ مسنون»."},
  {'n': '29', 'v': "فَإِذَا سَوَّيْتُهُۥ وَنَفَخْتُ فِيهِ مِن رُّوحِى فَقَعُوا۟ لَهُۥ سَٰجِدِينَ", 't': "«فإذا سويته» أتممته «ونفخت» أجريت «فيه من روحي» فصار حيا وإضافة الروح إليه تشريف لآدم «فقعوا له ساجدين» سجود تحية بالانحناء."},
  {'n': '30', 'v': "فَسَجَدَ ٱلْمَلَٰٓئِكَةُ كُلُّهُمْ أَجْمَعُونَ", 't': "«فسجد الملائكة كلهم أجمعون» فيه تأكيدان."},
  {'n': '31', 'v': "إِلَّآ إِبْلِيسَ أَبَىٰٓ أَن يَكُونَ مَعَ ٱلسَّٰجِدِينَ", 't': "«إلا إبليس» هو أبو الجن كان بين الملائكة «أبى» امتنع من «أن يكون مع الساجدين»."},
  {'n': '32', 'v': "قَالَ يَٰٓإِبْلِيسُ مَا لَكَ أَلَّا تَكُونَ مَعَ ٱلسَّٰجِدِينَ", 't': "«قال» تعالى «يا إبليس مالك» ما منعك «أ» ن «لا» زائدة «تكون مع الساجدين»."},
  {'n': '33', 'v': "قَالَ لَمْ أَكُن لِّأَسْجُدَ لِبَشَرٍ خَلَقْتَهُۥ مِن صَلْصَٰلٍۢ مِّنْ حَمَإٍۢ مَّسْنُونٍۢ", 't': "«قال لم أكن لأسجد» لا ينبغي لي أن أسجد «لبشر خلقته من صلصال من حمأ مسنون»."},
  {'n': '34', 'v': "قَالَ فَٱخْرُجْ مِنْهَا فَإِنَّكَ رَجِيمٌۭ", 't': "«قال فاخرج منها» أي الجنة وقيل من السماوات «فإنك رجيم» مطرود."},
  {'n': '35', 'v': "وَإِنَّ عَلَيْكَ ٱللَّعْنَةَ إِلَىٰ يَوْمِ ٱلدِّينِ", 't': "«وإن عليك اللعنة إلى يوم الدين» الجزاء."},
  {'n': '36', 'v': "قَالَ رَبِّ فَأَنظِرْنِىٓ إِلَىٰ يَوْمِ يُبْعَثُونَ", 't': "«قال رب فأنظرني إلى يوم يبعثون» أي الناس."},
  {'n': '37', 'v': "قَالَ فَإِنَّكَ مِنَ ٱلْمُنظَرِينَ", 't': "«قال فإنك من المنظرين»."},
  {'n': '38', 'v': "إِلَىٰ يَوْمِ ٱلْوَقْتِ ٱلْمَعْلُومِ", 't': "«إلى يوم الوقت المعلوم» وقت النفخة الأولى."},
  {'n': '39', 'v': "قَالَ رَبِّ بِمَآ أَغْوَيْتَنِى لَأُزَيِّنَنَّ لَهُمْ فِى ٱلْأَرْضِ وَلَأُغْوِيَنَّهُمْ أَجْمَعِينَ", 't': "«قال ربّ بما أغويتني» أي بإغوائك لي والباء للقسم وجوابه «لأزيِّنَنَّ لهم في الأرض» المعاصي «ولأغوينهم أجمعين»,"},
  {'n': '40', 'v': "إِلَّا عِبَادَكَ مِنْهُمُ ٱلْمُخْلَصِينَ", 't': "«إلا عبادك منهم المخلصين» أي المؤمنين."},
  {'n': '41', 'v': "قَالَ هَٰذَا صِرَٰطٌ عَلَىَّ مُسْتَقِيمٌ", 't': "«قال» تعالى «هذا صراط عليَّ مستقيم»."},
  {'n': '42', 'v': "إِنَّ عِبَادِى لَيْسَ لَكَ عَلَيْهِمْ سُلْطَٰنٌ إِلَّا مَنِ ٱتَّبَعَكَ مِنَ ٱلْغَاوِينَ", 't': "وهو «إن عبادي» أي المؤمنين «ليس لك عليهم سلطان» قوة «إلا» لكن «من اتبعك من الغاوين» الكافرين."},
  {'n': '43', 'v': "وَإِنَّ جَهَنَّمَ لَمَوْعِدُهُمْ أَجْمَعِينَ", 't': "«وإن جهنم لموعدهم أجمعين» أي من اتبعك معك."},
  {'n': '44', 'v': "لَهَا سَبْعَةُ أَبْوَٰبٍۢ لِّكُلِّ بَابٍۢ مِّنْهُمْ جُزْءٌۭ مَّقْسُومٌ", 't': "«لها سبعة أبواب» أطباق «لكل باب» منها «منهم جزء» نصيب «مقسوم»."},
  {'n': '45', 'v': "إِنَّ ٱلْمُتَّقِينَ فِى جَنَّٰتٍۢ وَعُيُونٍ", 't': "«إن المتقين في جنات» بساتين «وعيون» تجري فيها."},
  {'n': '46', 'v': "ٱدْخُلُوهَا بِسَلَٰمٍ ءَامِنِينَ", 't': "ويقال لهم «ادخلوها بسلام» أي سالمين من كل مخوّف أو مع سلام أي سلموا وادخلوا «آمنين» من كل فزع."},
  {'n': '47', 'v': "وَنَزَعْنَا مَا فِى صُدُورِهِم مِّنْ غِلٍّ إِخْوَٰنًا عَلَىٰ سُرُرٍۢ مُّتَقَٰبِلِينَ", 't': "«ونزعنا ما في صدورهم من غِلِّ» حقد «إخوانا» حال منهم «على سُرر متقابلين» حال أيضا أي لا ينظر بعضهم إلى قفا بعض لدورات الأسرَّة بهم."},
  {'n': '48', 'v': "لَا يَمَسُّهُمْ فِيهَا نَصَبٌۭ وَمَا هُم مِّنْهَا بِمُخْرَجِينَ", 't': "«لا يمسهم فيها نَصَبٌ» تعب «وما هم منها بمخرجين» أبدا."},
  {'n': '49', 'v': "۞ نَبِّئْ عِبَادِىٓ أَنِّىٓ أَنَا ٱلْغَفُورُ ٱلرَّحِيمُ", 't': "«نبئ» خبر يا محمد «عبادي أني أنا الغفور» للمؤمنين «الرحيم» بهم."},
  {'n': '50', 'v': "وَأَنَّ عَذَابِى هُوَ ٱلْعَذَابُ ٱلْأَلِيمُ", 't': "«وأن عذابي» للعصاة «هو العذاب الأليم» المؤلم."},
  {'n': '51', 'v': "وَنَبِّئْهُمْ عَن ضَيْفِ إِبْرَٰهِيمَ", 't': "«ونبئهم عن ضيف إبراهيم» وهم الملائكة اثنا عشر أو عشرة أو ثلاثة منهم جبريل."},
  {'n': '52', 'v': "إِذْ دَخَلُوا۟ عَلَيْهِ فَقَالُوا۟ سَلَٰمًۭا قَالَ إِنَّا مِنكُمْ وَجِلُونَ", 't': "«إذ دخلوا عليه فقالوا سلاما» أي هذا اللفظ «قال» إبراهيم لما عرض عليم الأكل فلم يأكلوا «إنا منكم وجلون» خائفون."},
  {'n': '53', 'v': "قَالُوا۟ لَا تَوْجَلْ إِنَّا نُبَشِّرُكَ بِغُلَٰمٍ عَلِيمٍۢ", 't': "«قالوا لا توجل» لا تخف «إنا» رسل ربك «نبشرك بغلام عليم» ذي علم كثير هو إسحاق كما ذكرنا في سورة هود."},
  {'n': '54', 'v': "قَالَ أَبَشَّرْتُمُونِى عَلَىٰٓ أَن مَّسَّنِىَ ٱلْكِبَرُ فَبِمَ تُبَشِّرُونَ", 't': "«قال أبشرتموني» بالولد «على أن مسني الكبر» حال أي مع مسه إياي «فبم» فبأي شيء «تبشرون» استفهام تعجب."},
  {'n': '55', 'v': "قَالُوا۟ بَشَّرْنَٰكَ بِٱلْحَقِّ فَلَا تَكُن مِّنَ ٱلْقَٰنِطِينَ", 't': "«قالوا بشرناك بالحق» بالصدق «فلا تكن من القانطين» الآيسين."},
  {'n': '56', 'v': "قَالَ وَمَن يَقْنَطُ مِن رَّحْمَةِ رَبِّهِۦٓ إِلَّا ٱلضَّآلُّونَ", 't': "«قال ومن» أي لا «يقنَِط» بكسر النون وفتحها «من رحمة ربه إلا الضالون» الكافرون."},
  {'n': '57', 'v': "قَالَ فَمَا خَطْبُكُمْ أَيُّهَا ٱلْمُرْسَلُونَ", 't': "«قال فما خطبكم» شأنكم «أيها المرسلون»."},
  {'n': '58', 'v': "قَالُوٓا۟ إِنَّآ أُرْسِلْنَآ إِلَىٰ قَوْمٍۢ مُّجْرِمِينَ", 't': "«قالوا إنا أرسلنا إلى قوم مجرمين» كافرين أي لوط لإهلاكهم."},
  {'n': '59', 'v': "إِلَّآ ءَالَ لُوطٍ إِنَّا لَمُنَجُّوهُمْ أَجْمَعِينَ", 't': "«إلا آل لوط إنا لمنجوهم أجمعين» لإيمانهم."},
  {'n': '60', 'v': "إِلَّا ٱمْرَأَتَهُۥ قَدَّرْنَآ ۙ إِنَّهَا لَمِنَ ٱلْغَٰبِرِينَ", 't': "«إلا امرأته قدرنا إنها لمن الغابرين» الباقين في العذاب لكفرها."},
  {'n': '61', 'v': "فَلَمَّا جَآءَ ءَالَ لُوطٍ ٱلْمُرْسَلُونَ", 't': "«فلما جاء آل لوط» أي لوطا «المرسلون»."},
  {'n': '62', 'v': "قَالَ إِنَّكُمْ قَوْمٌۭ مُّنكَرُونَ", 't': "«قال» لهم «إنكم قوم منكرون» لا أعرفكم."},
  {'n': '63', 'v': "قَالُوا۟ بَلْ جِئْنَٰكَ بِمَا كَانُوا۟ فِيهِ يَمْتَرُونَ", 't': "«قالوا بل جئناك بما كانوا» أي قومك «فيه يمترون» يشكون وهو العذاب."},
  {'n': '64', 'v': "وَأَتَيْنَٰكَ بِٱلْحَقِّ وَإِنَّا لَصَٰدِقُونَ", 't': "«وأتيناك بالحق وإنا لصادقون» في قولنا."},
  {'n': '65', 'v': "فَأَسْرِ بِأَهْلِكَ بِقِطْعٍۢ مِّنَ ٱلَّيْلِ وَٱتَّبِعْ أَدْبَٰرَهُمْ وَلَا يَلْتَفِتْ مِنكُمْ أَحَدٌۭ وَٱمْضُوا۟ حَيْثُ تُؤْمَرُونَ", 't': "«فأَسْرِ بأهلك بقطع من الليل واتبع أدبارهم» امش خلفهم «ولا يلتفت منكم أحد» لئلا يرى عظيم ما ينزل بهم «وامضوا حيث تؤمرون» وهو الشام."},
  {'n': '66', 'v': "وَقَضَيْنَآ إِلَيْهِ ذَٰلِكَ ٱلْأَمْرَ أَنَّ دَابِرَ هَٰٓؤُلَآءِ مَقْطُوعٌۭ مُّصْبِحِينَ", 't': "«وقضينا» أوحينا «إليه ذلك الأمر» وهو «أن دابر هؤلاء مقطوع مصبحين» حال أي يتم استئصالهم في الصباح."},
  {'n': '67', 'v': "وَجَآءَ أَهْلُ ٱلْمَدِينَةِ يَسْتَبْشِرُونَ", 't': "«وجاء أهل المدينة» مدينة سدوم وهم قوم لوط لما أخبروا أن في بيت لوط مردا حسانا وهم الملائكة «يستبشرون» حال طمعا في فعل الفاحشة بهم."},
  {'n': '68', 'v': "قَالَ إِنَّ هَٰٓؤُلَآءِ ضَيْفِى فَلَا تَفْضَحُونِ", 't': "«قال» لوط «إن هؤلاء ضيفي فلا تفضحون»."},
  {'n': '69', 'v': "وَٱتَّقُوا۟ ٱللَّهَ وَلَا تُخْزُونِ", 't': "«واتقوا الله ولا تخزون» بقصدكم إياهم بفعل الفاحشة بهم."},
  {'n': '70', 'v': "قَالُوٓا۟ أَوَلَمْ نَنْهَكَ عَنِ ٱلْعَٰلَمِينَ", 't': "«قالوا أو لم ننهك عن العالمين» عن إضافتهم."},
  {'n': '71', 'v': "قَالَ هَٰٓؤُلَآءِ بَنَاتِىٓ إِن كُنتُمْ فَٰعِلِينَ", 't': "«قال هؤلاء بناتي إن كنتم فاعلين» ما تريدون من قضاء الشهوة فتزوجوهن. قال تعالى:"},
  {'n': '72', 'v': "لَعَمْرُكَ إِنَّهُمْ لَفِى سَكْرَتِهِمْ يَعْمَهُونَ", 't': "«لعمرك» خطاب للنبي صلى الله عليه وسلم أي وحياتك «إنهم لفي سكرتهم يعمهون» يترددون."},
  {'n': '73', 'v': "فَأَخَذَتْهُمُ ٱلصَّيْحَةُ مُشْرِقِينَ", 't': "«فأخذتهم الصيحة» صيحة جبريل «مشرقين» وقت شروق الشمس."},
  {'n': '74', 'v': "فَجَعَلْنَا عَٰلِيَهَا سَافِلَهَا وَأَمْطَرْنَا عَلَيْهِمْ حِجَارَةًۭ مِّن سِجِّيلٍ", 't': "«فجعلنا عاليها» أي قراهم «سافلها» بأن رفعها جبريل إلى السماء وأسقطها مقلوبة إلى الأرض «وأمطرنا عليهم حجارة من سجيل» طين طبخ بالنار."},
  {'n': '75', 'v': "إِنَّ فِى ذَٰلِكَ لَءَايَٰتٍۢ لِّلْمُتَوَسِّمِينَ", 't': "«إن في ذلك» المذكور «لآيات» دلالات على وحدانية الله «للمتوسمين» للناظرين المعتبرين."},
