  {'n': '16', 'v': "وَعَلَٰمَٰتٍۢ ۚ وَبِٱلنَّجْمِ هُمْ يَهْتَدُونَ", 't': "«وعلامات» تستدلون بها على الطرق كالجبال بالنهار «وبالنجم» بمعنى النجوم «هم يهتدون» إلى الطرق والقبلة بالليل."},
  {'n': '17', 'v': "أَفَمَن يَخْلُقُ كَمَن لَّا يَخْلُقُ ۗ أَفَلَا تَذَكَّرُونَ", 't': "«أفمن يخلق» وهو الله «كمن لا يخلق» وهو الأصنام حيث تشركونها معه في العبادة؟ لا «أفلا تذكرون» هذا فتؤمنون."},
  {'n': '18', 'v': "وَإِن تَعُدُّوا۟ نِعْمَةَ ٱللَّهِ لَا تُحْصُوهَآ ۗ إِنَّ ٱللَّهَ لَغَفُورٌۭ رَّحِيمٌۭ", 't': "«وإن تعدّوا نعمة الله لا تحصوها» تضبطوها فضلاً أن تطيقوا شكرها «إن الله لغفور رحيم» حيث ينعم عليكم مع تقصيركم وعصيانكم."},
  {'n': '19', 'v': "وَٱللَّهُ يَعْلَمُ مَا تُسِرُّونَ وَمَا تُعْلِنُونَ", 't': "«والله يعلم ما تسرون وما تعلنون»."},
  {'n': '20', 'v': "وَٱلَّذِينَ يَدْعُونَ مِن دُونِ ٱللَّهِ لَا يَخْلُقُونَ شَيْـًۭٔا وَهُمْ يُخْلَقُونَ", 't': "«والذين تدعون» بالتاء والياء تعبدون «من دون الله» وهم الأصنام «لا يخلقون شيئاً وهم يُخلقون» يصورون من الحجارة وغيرها."},
  {'n': '21', 'v': "أَمْوَٰتٌ غَيْرُ أَحْيَآءٍۢ ۖ وَمَا يَشْعُرُونَ أَيَّانَ يُبْعَثُونَ", 't': "«أموات» لا روح فيه خبر ثان «غير أحياء» تأكيد «وما يشعرون» أي الأصنام «أيان» وقت «يبعثون» أي الخلق فكيف يعبدون، إذ لا يكون إلهاً إلا الخالق الحي العالم بالغيب."},
  {'n': '22', 'v': "إِلَٰهُكُمْ إِلَٰهٌۭ وَٰحِدٌۭ ۚ فَٱلَّذِينَ لَا يُؤْمِنُونَ بِٱلْءَاخِرَةِ قُلُوبُهُم مُّنكِرَةٌۭ وَهُم مُّسْتَكْبِرُونَ", 't': "«إلهكم» المستحق للعبادة منكم «إله واحد» لا نظير له في ذاته ولا في صفاته وهو الله تعالى «فالذين لا يؤمنون بالآخرة قلوبهم منكرة» جاحدة للوحدانية «وهم مستكبرون» متكبرون عن الإيمان بها."},
  {'n': '23', 'v': "لَا جَرَمَ أَنَّ ٱللَّهَ يَعْلَمُ مَا يُسِرُّونَ وَمَا يُعْلِنُونَ ۚ إِنَّهُۥ لَا يُحِبُّ ٱلْمُسْتَكْبِرِينَ", 't': "«لا جرم» حقا «أن الله يعلم ما يسرون وما يعلنون» فيجازيهم بذلك «إنه لا يحب المستكبرين» بمعنى أنه يعاقبهم."},
  {'n': '24', 'v': "وَإِذَا قِيلَ لَهُم مَّاذَآ أَنزَلَ رَبُّكُمْ ۙ قَالُوٓا۟ أَسَٰطِيرُ ٱلْأَوَّلِينَ", 't': "ونزل في النضر بن الحارث «وإذا قيل لهم ما» استفهامية «ذا» موصولة «أنزل ربكم» على محمد «قالوا» هو «أساطير» أكاذيب «الأولين» إضلالاً للناس."},
  {'n': '25', 'v': "لِيَحْمِلُوٓا۟ أَوْزَارَهُمْ كَامِلَةًۭ يَوْمَ ٱلْقِيَٰمَةِ ۙ وَمِنْ أَوْزَارِ ٱلَّذِينَ يُضِلُّونَهُم بِغَيْرِ عِلْمٍ ۗ أَلَا سَآءَ مَا يَزِرُونَ", 't': "«ليحملوا» في عاقبة الأمر «أوزارهم» ذنوبهم «كاملة» لم يُكفَّر منها شيء «يوم القيامة ومن» بعض «أوزار الذين يضلونهم بغير علم» لأنهم دعوهم إلى الضلال فاتبعوهم فاشتركوا في الإثم «ألا ساء» بئس «ما يزرون» يحملونه حملهم هذا."},
  {'n': '26', 'v': "قَدْ مَكَرَ ٱلَّذِينَ مِن قَبْلِهِمْ فَأَتَى ٱللَّهُ بُنْيَٰنَهُم مِّنَ ٱلْقَوَاعِدِ فَخَرَّ عَلَيْهِمُ ٱلسَّقْفُ مِن فَوْقِهِمْ وَأَتَىٰهُمُ ٱلْعَذَابُ مِنْ حَيْثُ لَا يَشْعُرُونَ", 't': "«قد مكر الذين من قبلهم» وهو نمروذ بنى صرحاً طويلا ليصعد منه إلى السماء ليقاتل أهلها «فأتى اللهُ» قصد «بنيانهم من القواعد» الأساس فأرسل عليه الريح والزلزلة فهدمته «فخر عليهم السقف من فوقهم» أي هم تحته «وأتاهم العذاب من حيث لا يشعرون» من جهة لا تخطر ببالهم وقيل هذا تمثيل لإفساد ما أبرموه من المكر بالرسل."},
  {'n': '27', 'v': "ثُمَّ يَوْمَ ٱلْقِيَٰمَةِ يُخْزِيهِمْ وَيَقُولُ أَيْنَ شُرَكَآءِىَ ٱلَّذِينَ كُنتُمْ تُشَٰٓقُّونَ فِيهِمْ ۚ قَالَ ٱلَّذِينَ أُوتُوا۟ ٱلْعِلْمَ إِنَّ ٱلْخِزْىَ ٱلْيَوْمَ وَٱلسُّوٓءَ عَلَى ٱلْكَٰفِرِينَ", 't': "«ثم يوم القيامة يخزيهم» يذلهم «ويقول» الله لهم على لسان الملائكة توبيخاً «أين شركائي» بزعمكم «الذين كنتم تشاقون» تخالفون المؤمنين «فيهم» في شأنهم «قال» أي يقول «الذين أوتوا العلم» من الأنبياء والمؤمنين «إن الخزي اليوم والسوء على الكافرين» يقولونه شماتة بهم."},
  {'n': '28', 'v': "ٱلَّذِينَ تَتَوَفَّىٰهُمُ ٱلْمَلَٰٓئِكَةُ ظَالِمِىٓ أَنفُسِهِمْ ۖ فَأَلْقَوُا۟ ٱلسَّلَمَ مَا كُنَّا نَعْمَلُ مِن سُوٓءٍۭ ۚ بَلَىٰٓ إِنَّ ٱللَّهَ عَلِيمٌۢ بِمَا كُنتُمْ تَعْمَلُونَ", 't': "«الذين تتوفاهم» بالتاء والياء «الملائكة ظالمي أنفسهم» بالكفر «فألقوا السلم» انقادوا واستسلموا عند الموت قائلين «ما كنا نعمل من سوء» شرك فتقول الملائكة «بلى إن الله عليم بما كنتم تعملون» فيجازيكم به."},
  {'n': '29', 'v': "فَٱدْخُلُوٓا۟ أَبْوَٰبَ جَهَنَّمَ خَٰلِدِينَ فِيهَا ۖ فَلَبِئْسَ مَثْوَى ٱلْمُتَكَبِّرِينَ", 't': "ويقال لهم «فادخلوا أبواب جهنم خالدين فيها فلبئس مثوى» مأوى «المتكبرين»."},
  {'n': '30', 'v': "۞ وَقِيلَ لِلَّذِينَ ٱتَّقَوْا۟ مَاذَآ أَنزَلَ رَبُّكُمْ ۚ قَالُوا۟ خَيْرًۭا ۗ لِّلَّذِينَ أَحْسَنُوا۟ فِى هَٰذِهِ ٱلدُّنْيَا حَسَنَةٌۭ ۚ وَلَدَارُ ٱلْءَاخِرَةِ خَيْرٌۭ ۚ وَلَنِعْمَ دَارُ ٱلْمُتَّقِينَ", 't': "«وقيل للذين اتقوْا» الشرك «ماذا أنزل ربكم قالوا خيراً للذين أحسنوا» بالإيمان «في هذه الدنيا حسنة» حياة طيبة «ولدار الآخرة» أي الجنة «خير» من الدنيا وما فيها قال تعالى فيها «ولنعم دار المتقين» هي."},
  {'n': '31', 'v': "جَنَّٰتُ عَدْنٍۢ يَدْخُلُونَهَا تَجْرِى مِن تَحْتِهَا ٱلْأَنْهَٰرُ ۖ لَهُمْ فِيهَا مَا يَشَآءُونَ ۚ كَذَٰلِكَ يَجْزِى ٱللَّهُ ٱلْمُتَّقِينَ", 't': "«جنات عدن» إقامة مبتدأ خبره «يدخلونها تجري من تحتها الأنهار لهم فيها ما يشاءُون كذلك» الجزاء «يجزي الله المتقين»."},
  {'n': '32', 'v': "ٱلَّذِينَ تَتَوَفَّىٰهُمُ ٱلْمَلَٰٓئِكَةُ طَيِّبِينَ ۙ يَقُولُونَ سَلَٰمٌ عَلَيْكُمُ ٱدْخُلُوا۟ ٱلْجَنَّةَ بِمَا كُنتُمْ تَعْمَلُونَ", 't': "«الذين» نعت «تتوفاهم الملائكة طيبين» طاهرين من الكفر «يقولون» عند الموت «سلام عليكم» ويقال لهم في الآخرة «ادخلوا الجنة بما كنتم تعملون»."},
  {'n': '33', 'v': "هَلْ يَنظُرُونَ إِلَّآ أَن تَأْتِيَهُمُ ٱلْمَلَٰٓئِكَةُ أَوْ يَأْتِىَ أَمْرُ رَبِّكَ ۚ كَذَٰلِكَ فَعَلَ ٱلَّذِينَ مِن قَبْلِهِمْ ۚ وَمَا ظَلَمَهُمُ ٱللَّهُ وَلَٰكِن كَانُوٓا۟ أَنفُسَهُمْ يَظْلِمُونَ", 't': "«هل» ما «ينظرون» ينتظر الكفار «إلا أن تأتيهم» بالتاء والياء «الملائكة» لقبض أرواحهم «أو يأتي أمر ربك» العذاب أو القيامة المشتملة عليه «كذلك» كما فعل هؤلاء «فعل الذين من قبلهم» من الأمم كذبوا رسلهم فأهلكوا «وما ظلمهم الله» بإهلاكهم بغير ذنب «ولكن كانوا أنفسهم يظلمون» بالكفر."},
  {'n': '34', 'v': "فَأَصَابَهُمْ سَيِّـَٔاتُ مَا عَمِلُوا۟ وَحَاقَ بِهِم مَّا كَانُوا۟ بِهِۦ يَسْتَهْزِءُونَ", 't': "فأصابهم سيئات ما عملوا» أي جزاءها «وحاق» نزل «بهم ما كانوا به يستهزءُون» أي العذاب."},
  {'n': '35', 'v': "وَقَالَ ٱلَّذِينَ أَشْرَكُوا۟ لَوْ شَآءَ ٱللَّهُ مَا عَبَدْنَا مِن دُونِهِۦ مِن شَىْءٍۢ نَّحْنُ وَلَآ ءَابَآؤُنَا وَلَا حَرَّمْنَا مِن دُونِهِۦ مِن شَىْءٍۢ ۚ كَذَٰلِكَ فَعَلَ ٱلَّذِينَ مِن قَبْلِهِمْ ۚ فَهَلْ عَلَى ٱلرُّسُلِ إِلَّا ٱلْبَلَٰغُ ٱلْمُبِينُ", 't': "«وقال الذين أشركوا» من أهل مكة «لو شاء الله ما عبدنا من دونه من شيء نحن ولا آباؤنا ولا حرمنا من دونه من شيء» من البحائر والسوائب فإشراكنا وتحريمنا بمشيئته فهو راض به، قال تعالى: «كذلك فعل الذين من قبلهم» أي كذبوا ربهم فيما جاءوا به «فهل» فما «على الرسل إلا البلاغ المبين» إلا البلاغ البيِّن وليس عليهم الهداية."},
  {'n': '36', 'v': "وَلَقَدْ بَعَثْنَا فِى كُلِّ أُمَّةٍۢ رَّسُولًا أَنِ ٱعْبُدُوا۟ ٱللَّهَ وَٱجْتَنِبُوا۟ ٱلطَّٰغُوتَ ۖ فَمِنْهُم مَّنْ هَدَى ٱللَّهُ وَمِنْهُم مَّنْ حَقَّتْ عَلَيْهِ ٱلضَّلَٰلَةُ ۚ فَسِيرُوا۟ فِى ٱلْأَرْضِ فَٱنظُرُوا۟ كَيْفَ كَانَ عَٰقِبَةُ ٱلْمُكَذِّبِينَ", 't': "«ولقد بعثنا في كل أمة رسولاً» كما بعثناك في هؤلاء «أن» بأن «اعبدوا الله» وحدوه «واجتنبوا الطاغوت» الأوثان أن تعبدوها «فمنهم من هدى الله» فآمن «ومنهم من حقت» وجَبَتْ «عليه الضلالة» في علم الله فلم يؤمن «فسيروا» يا كفار مكة «في الأرض فانظروا كيف كان عاقبة المكذبين» رسلهم من الهلاك."},
  {'n': '37', 'v': "إِن تَحْرِصْ عَلَىٰ هُدَىٰهُمْ فَإِنَّ ٱللَّهَ لَا يَهْدِى مَن يُضِلُّ ۖ وَمَا لَهُم مِّن نَّٰصِرِينَ", 't': "«إن تحرص» يا محمد «على هداهم» وقد أضلهم الله لا تقدر على ذلك «فإن الله لا يُهدِي» بالبناء للمفعول وللفاعل «من يضل» من يريد إضلاله «وما لهم من ناصرين» مانعين من عذاب الله."},
  {'n': '38', 'v': "وَأَقْسَمُوا۟ بِٱللَّهِ جَهْدَ أَيْمَٰنِهِمْ ۙ لَا يَبْعَثُ ٱللَّهُ مَن يَمُوتُ ۚ بَلَىٰ وَعْدًا عَلَيْهِ حَقًّۭا وَلَٰكِنَّ أَكْثَرَ ٱلنَّاسِ لَا يَعْلَمُونَ", 't': "«وأقسموا بالله جهد أيمانهم» أي غاية اجتهادهم فيها «لا يبعث الله من يموت» قال تعالى «بلى» يبعثهم «وعداً عليه حقا» مصدران مؤكدان منصوبان بفعلهما المقدر أي وعد ذلك وحقه حقا «ولكن أكثر الناس» أي أهل مكة «لا يعلمون» ذلك."},
  {'n': '39', 'v': "لِيُبَيِّنَ لَهُمُ ٱلَّذِى يَخْتَلِفُونَ فِيهِ وَلِيَعْلَمَ ٱلَّذِينَ كَفَرُوٓا۟ أَنَّهُمْ كَانُوا۟ كَٰذِبِينَ", 't': "«ليبين» متعلق ببعثهم المقدر «لهم الذي يختلفون» مع المؤمنين «فيه» من أمر الدين بتعذيبهم وإثابة المؤمنين «وليعلم الذين كفروا أنهم كانوا كاذبين» في إنكار البعث."},
  {'n': '40', 'v': "إِنَّمَا قَوْلُنَا لِشَىْءٍ إِذَآ أَرَدْنَٰهُ أَن نَّقُولَ لَهُۥ كُن فَيَكُونُ", 't': "«إنما قوْلنا لشيء إذا أردناه» أي أردنا إيجاده وقولنا مبتدأ خبره «أن نقول له كن فيكونُ» أي فهو يكون وفي قراءة بالنصب عطفاً على نقول والآية لتقرير القدرة على البعث."},
  {'n': '41', 'v': "وَٱلَّذِينَ هَاجَرُوا۟ فِى ٱللَّهِ مِنۢ بَعْدِ مَا ظُلِمُوا۟ لَنُبَوِّئَنَّهُمْ فِى ٱلدُّنْيَا حَسَنَةًۭ ۖ وَلَأَجْرُ ٱلْءَاخِرَةِ أَكْبَرُ ۚ لَوْ كَانُوا۟ يَعْلَمُونَ", 't': "«والذين هاجروا في الله» لإقامة دينه «من بعدما ظلموا» بالأذى من أهل مكة وهم النبي وأصحابه «لنبوِّئَنهم» ننزلهم «في الدنيا» داراً «حسنة» هي المدينة «ولأجر الآخرة» أي الجنة «أكبر» أعظم «لو كانوا يعلمون» أي الكفار أو المتخلفون عن الهجرة ما للمهاجرين من الكرامة لوافقوهم."},
  {'n': '42', 'v': "ٱلَّذِينَ صَبَرُوا۟ وَعَلَىٰ رَبِّهِمْ يَتَوَكَّلُونَ", 't': "هم «الذين صبروا» على أذى المشركين والهجرة لإظهار الدين «وعلى ربهم يتوكلون» فيرزقهم من حيث لا يحتسبون."},
  {'n': '43', 'v': "وَمَآ أَرْسَلْنَا مِن قَبْلِكَ إِلَّا رِجَالًۭا نُّوحِىٓ إِلَيْهِمْ ۚ فَسْـَٔلُوٓا۟ أَهْلَ ٱلذِّكْرِ إِن كُنتُمْ لَا تَعْلَمُونَ", 't': "«وما أرسلنا من قبلك إلا رجالاً نوحي إليهم» لا ملائكة «فاسألوا أهل الذكر» العلماء بالتوراة والإنجيل «إن كنتم لا تعلمون» ذلك، فإنهم يعلمونه وأنتم إلى تصديقهم أقرب من تصديق المؤمنين بمحمد صلى الله عليه وسلم."},
  {'n': '44', 'v': "بِٱلْبَيِّنَٰتِ وَٱلزُّبُرِ ۗ وَأَنزَلْنَآ إِلَيْكَ ٱلذِّكْرَ لِتُبَيِّنَ لِلنَّاسِ مَا نُزِّلَ إِلَيْهِمْ وَلَعَلَّهُمْ يَتَفَكَّرُونَ", 't': "«بالبينات» متعلق بمحذوف أي أرسلناهم بالحجج الواضحة «والزُّبُر» الكتب «وأنزلنا إليك الذكر» القرآن «لتبين للناس ما نزل إليهم» فيه من الحلال والحرام «ولعلهم يتفكرون» في ذلك فيعتبرون."},
  {'n': '45', 'v': "أَفَأَمِنَ ٱلَّذِينَ مَكَرُوا۟ ٱلسَّيِّـَٔاتِ أَن يَخْسِفَ ٱللَّهُ بِهِمُ ٱلْأَرْضَ أَوْ يَأْتِيَهُمُ ٱلْعَذَابُ مِنْ حَيْثُ لَا يَشْعُرُونَ", 't': "«أفأمِنَ الذين مكروا» المكرات «السيئات» بالنبي صلى اله عليه وسلم في دار الندوة من تقييده أو قتله أو إخراجه كما ذكر في الأنفال «أن يخسف الله بهم الأرض» كقارون «أو يأتيهم العذاب من حيث لا يشعرون» أي جهة لا تخطر ببالهم وقد أهلكوا ببدر ولم يكونوا يقدّرون ذلك."},
  {'n': '46', 'v': "أَوْ يَأْخُذَهُمْ فِى تَقَلُّبِهِمْ فَمَا هُم بِمُعْجِزِينَ", 't': "«أو يأخذهم في تقلبهم» في أسفارهم للتجارة «فما هم بمعجزين» بفائتي العذاب."},
  {'n': '47', 'v': "أَوْ يَأْخُذَهُمْ عَلَىٰ تَخَوُّفٍۢ فَإِنَّ رَبَّكُمْ لَرَءُوفٌۭ رَّحِيمٌ", 't': "«أو يأخذهم على تخوف» تنقص شيئاً فشيئاً حتى يهلك الجميع حال من الفاعل أو المفعول «فإن ربكم لرءُوف رحيم» حيث لم يعاجلهم بالعقوبة."},
  {'n': '48', 'v': "أَوَلَمْ يَرَوْا۟ إِلَىٰ مَا خَلَقَ ٱللَّهُ مِن شَىْءٍۢ يَتَفَيَّؤُا۟ ظِلَٰلُهُۥ عَنِ ٱلْيَمِينِ وَٱلشَّمَآئِلِ سُجَّدًۭا لِّلَّهِ وَهُمْ دَٰخِرُونَ", 't': "«أولم يروْا إلى ما خلق الله من شيء» له ظل كشجرة وجبل «تتفيَّؤ» تتميل «ظلاله عن اليمين والشمائل» جمع شمال أي عن جانبيهما أول النهار وآخره «سجداً لله» حال أي خاضعين له بما يراد منهم «وهم» أي الظلال «داخرون» صاغرون نزلوا منزلة العقلاء."},
  {'n': '49', 'v': "وَلِلَّهِ يَسْجُدُ مَا فِى ٱلسَّمَٰوَٰتِ وَمَا فِى ٱلْأَرْضِ مِن دَآبَّةٍۢ وَٱلْمَلَٰٓئِكَةُ وَهُمْ لَا يَسْتَكْبِرُونَ", 't': "«ولله يسجد ما في السماوات وما في والأرض من دابة» أي نسمة تدب عليها أي تخضع له بما يراد منها، وغلب في الإتيان بما لا يعقل لكثرته «والملائكة» خصهم بالذكر تفضيلاً «وهم لا يستكبرون» يتكبرون عن عبادته."},
  {'n': '50', 'v': "يَخَافُونَ رَبَّهُم مِّن فَوْقِهِمْ وَيَفْعَلُونَ مَا يُؤْمَرُونَ ۩", 't': "«يخافون» أي الملائكة حال من ضمير يستكبرون «ربهم من فوقهم» حال من هم أي عالياً عليهم بالقهر «ويفعلون ما يؤمرون» به."},
  {'n': '51', 'v': "۞ وَقَالَ ٱللَّهُ لَا تَتَّخِذُوٓا۟ إِلَٰهَيْنِ ٱثْنَيْنِ ۖ إِنَّمَا هُوَ إِلَٰهٌۭ وَٰحِدٌۭ ۖ فَإِيَّٰىَ فَٱرْهَبُونِ", 't': "«وقال الله لا تتخذوا إلهين اثنين» تأكيد «إنما هو إله واحد» أتى به لإثبات الإلهية والوحدانية «فإياي فارهبون» خافون دون غيري وفيه التفات عن الغيبة."},
  {'n': '52', 'v': "وَلَهُۥ مَا فِى ٱلسَّمَٰوَٰتِ وَٱلْأَرْضِ وَلَهُ ٱلدِّينُ وَاصِبًا ۚ أَفَغَيْرَ ٱللَّهِ تَتَّقُونَ", 't': "«وله ما في السماوات والأرض» ملكاً وخلقاً وعبيداً «وله الدين» الطاعة «واصباً» دائماً حال من الدين والعامل فيه معنى الظرف «أفغير الله تتقون» وهو الإله الحق ولا إله غيره والاستفهام للإنكار والتوبيخ."},
  {'n': '53', 'v': "وَمَا بِكُم مِّن نِّعْمَةٍۢ فَمِنَ ٱللَّهِ ۖ ثُمَّ إِذَا مَسَّكُمُ ٱلضُّرُّ فَإِلَيْهِ تَجْـَٔرُونَ", 't': "«وما بكم من نعمة فمن الله» لا يأتي بها غيره و\"ما\" شرطية أو موصولة «ثم إذا مسكم» أصابكم «الضر» الفقر والمرض «فإليه تجأرون» ترفعون أصواتكم بالاستغاثة والدعاء ولا تدعون غيره."},
  {'n': '54', 'v': "ثُمَّ إِذَا كَشَفَ ٱلضُّرَّ عَنكُمْ إِذَا فَرِيقٌۭ مِّنكُم بِرَبِّهِمْ يُشْرِكُونَ", 't': "«ثم إذا كشف الضر عنكم إذا فريق منكم بربهم يشركون»."},
  {'n': '55', 'v': "لِيَكْفُرُوا۟ بِمَآ ءَاتَيْنَٰهُمْ ۚ فَتَمَتَّعُوا۟ ۖ فَسَوْفَ تَعْلَمُونَ", 't': "«ليكفروا بما آتيناهم» من النعمة «فتمتعوا» باجتماعكم على عبادة الأصنام أمر تهديد «فسوف تعلمون» عاقبة ذلك."},
  {'n': '56', 'v': "وَيَجْعَلُونَ لِمَا لَا يَعْلَمُونَ نَصِيبًۭا مِّمَّا رَزَقْنَٰهُمْ ۗ تَٱللَّهِ لَتُسْـَٔلُنَّ عَمَّا كُنتُمْ تَفْتَرُونَ", 't': "«ويجعلون» أي المشركون «لما لا يعلمون» أنها تضر ولا تنفع وهي الأصنام «نصيباً مما رزقناهم» من الحرث والأنعام بقولهم هذا لله لشركائنا «تالله لتسألن» سؤال توبيخ وفيه التفات عن الغيبة «عما كنتم تفترون» على الله من أنه أمركم بذلك."},
  {'n': '57', 'v': "وَيَجْعَلُونَ لِلَّهِ ٱلْبَنَٰتِ سُبْحَٰنَهُۥ ۙ وَلَهُم مَّا يَشْتَهُونَ", 't': "(ويجعلون لله البنات) بقولهم الملائكة بنات الله (سبحانه) تنزيهاً له عما زعموا (ولهم ما يشتهون) ـه أي البنون والجملة في محل رفع أو نصب بيجعل، المعنى يجعلون له البنات التي يكرهونها وهو منزه عن الولد ويجعلون لهم الأبناء الذين يختارونهم فيختصون بالأسنى كقوله \"\" فاستفتهم ألربك البنات ولهم البنون \"\"."},
  {'n': '58', 'v': "وَإِذَا بُشِّرَ أَحَدُهُم بِٱلْأُنثَىٰ ظَلَّ وَجْهُهُۥ مُسْوَدًّۭا وَهُوَ كَظِيمٌۭ", 't': "«وإذا بُشّر أحدهم بالأنثى» تولد له «ظل» صار «وجهه مسوداً» متغيراً تغير مغتَمّ «وهو كظيم» ممتلئ غمًّا فكيف تنسب البنات إليه تعالى."},
  {'n': '59', 'v': "يَتَوَٰرَىٰ مِنَ ٱلْقَوْمِ مِن سُوٓءِ مَا بُشِّرَ بِهِۦٓ ۚ أَيُمْسِكُهُۥ عَلَىٰ هُونٍ أَمْ يَدُسُّهُۥ فِى ٱلتُّرَابِ ۗ أَلَا سَآءَ مَا يَحْكُمُونَ", 't': "«يتوارى» يختفي «من القوم» أي قومه «من سوء ما بشر به» خوفاً من التعيير متردداً فيما يفعل به «أيمسكه» يتركه بلا قتل «على هون» هوان وذل «أم يدسه في التراب» بأن يئده «ألا ساء» بئس «ما يحكمون» حكمهم هذا حيث نسبوا لخالقهم البنات اللاتي هن عندهم بهذا المحل."},
  {'n': '60', 'v': "لِلَّذِينَ لَا يُؤْمِنُونَ بِٱلْءَاخِرَةِ مَثَلُ ٱلسَّوْءِ ۖ وَلِلَّهِ ٱلْمَثَلُ ٱلْأَعْلَىٰ ۚ وَهُوَ ٱلْعَزِيزُ ٱلْحَكِيمُ", 't': "«للذين لا يؤمنون بالآخرة» أي الكفار «مثل السَّوء» أي الصفة السوأى بمعنى القبيحة وهي وأدهم البنات مع احتياجهم إليهن للنكاح «ولله المثل الأعلى» الصفة العليا وهو أنه لا إله إلا هو «وهو العزيز» في ملكه «الحكيم» في خلقه."},
  {'n': '61', 'v': "وَلَوْ يُؤَاخِذُ ٱللَّهُ ٱلنَّاسَ بِظُلْمِهِم مَّا تَرَكَ عَلَيْهَا مِن دَآبَّةٍۢ وَلَٰكِن يُؤَخِّرُهُمْ إِلَىٰٓ أَجَلٍۢ مُّسَمًّۭى ۖ فَإِذَا جَآءَ أَجَلُهُمْ لَا يَسْتَـْٔخِرُونَ سَاعَةًۭ ۖ وَلَا يَسْتَقْدِمُونَ", 't': "«ولو يؤاخذ الله الناس بظلمهم» بالمعاصي «ما ترك عليها» أي الأرض «من دابة» نسمة تدب عليها «ولكن يؤخرهم إلى أجل مسمى فإذا جاء أجلهم لا يستأخرون» عنه «ساعة ولا يستقدمون» عليه."},
  {'n': '62', 'v': "وَيَجْعَلُونَ لِلَّهِ مَا يَكْرَهُونَ وَتَصِفُ أَلْسِنَتُهُمُ ٱلْكَذِبَ أَنَّ لَهُمُ ٱلْحُسْنَىٰ ۖ لَا جَرَمَ أَنَّ لَهُمُ ٱلنَّارَ وَأَنَّهُم مُّفْرَطُونَ", 't': "«ويجعلون لله ما يكرهون» لأنفسهم من البنات والشريك في الرياسة وإهانة الرسل «وتصف» تقول «ألسنتهم» مع ذلك «الكذب» وهو «أن لهم الحسنى» عند الله أي الجنة لقوله: (ولئن رجعت إلى ربي إن لي عنده للحسنى) «لا جرم» حقا «أن لهم النار وأنهم مفرطون» متروكون فيها أو مقدمون إليها وفي قراءة بكسر الراء أي متجاوزون الحد."},
  {'n': '63', 'v': "تَٱللَّهِ لَقَدْ أَرْسَلْنَآ إِلَىٰٓ أُمَمٍۢ مِّن قَبْلِكَ فَزَيَّنَ لَهُمُ ٱلشَّيْطَٰنُ أَعْمَٰلَهُمْ فَهُوَ وَلِيُّهُمُ ٱلْيَوْمَ وَلَهُمْ عَذَابٌ أَلِيمٌۭ", 't': "«تالله لقد أرسلنا إلى أمم من قبلك» رسلاً «فزين لهم الشيطان أعمالهم» السيئة فرأوها حسنة فكذبوا الرسل «فهو وليهم» متولي أمورهم «اليوم» أي في الدنيا «ولهم عذاب أليم» مؤلم في الآخرة وقيل المراد باليوم يوم القيامة على حكاية الحال الآتية لا ولي لهم غيره وهو عاجز عن نصر نفسه فكيف ينصرهم."},
  {'n': '64', 'v': "وَمَآ أَنزَلْنَا عَلَيْكَ ٱلْكِتَٰبَ إِلَّا لِتُبَيِّنَ لَهُمُ ٱلَّذِى ٱخْتَلَفُوا۟ فِيهِ ۙ وَهُدًۭى وَرَحْمَةًۭ لِّقَوْمٍۢ يُؤْمِنُونَ", 't': "«وما أنزلنا عليك» يا محمد «الكتاب» القرآن «إلا لتبين لهم الذي اختلفوا فيه» من أمر الدين «وهدى» عطف على لتبين «ورحمة لقوم يؤمنون» به."},
  {'n': '65', 'v': "وَٱللَّهُ أَنزَلَ مِنَ ٱلسَّمَآءِ مَآءًۭ فَأَحْيَا بِهِ ٱلْأَرْضَ بَعْدَ مَوْتِهَآ ۚ إِنَّ فِى ذَٰلِكَ لَءَايَةًۭ لِّقَوْمٍۢ يَسْمَعُونَ", 't': "«والله أنزل من السماء ماء فأحيا به الأرض» بالنبات «بعد موتها» يبسها «إن في ذلك» المذكور «لآية» دالة على البعث «لقوم يسمعون» سماع تدبر."},
  {'n': '66', 'v': "وَإِنَّ لَكُمْ فِى ٱلْأَنْعَٰمِ لَعِبْرَةًۭ ۖ نُّسْقِيكُم مِّمَّا فِى بُطُونِهِۦ مِنۢ بَيْنِ فَرْثٍۢ وَدَمٍۢ لَّبَنًا خَالِصًۭا سَآئِغًۭا لِّلشَّٰرِبِينَ", 't': "«وإن لكم في الأنعام لعبرة» اعتبار «نسقيكم» بيان للعبرة «مما في بطونه» أي الأنعام «من» للابتداء متعلقة بنسقيكم «بين فرث» ثفل الكرش «ودمٍ لبناً خالصاً» لا يشوبه شيء من الفرث والدم من طعم أو ريح أو لون أو بينهما «سائغاًً للشاربين» سهل المرور في حلقهم لا يغص به."},
  {'n': '67', 'v': "وَمِن ثَمَرَٰتِ ٱلنَّخِيلِ وَٱلْأَعْنَٰبِ تَتَّخِذُونَ مِنْهُ سَكَرًۭا وَرِزْقًا حَسَنًا ۗ إِنَّ فِى ذَٰلِكَ لَءَايَةًۭ لِّقَوْمٍۢ يَعْقِلُونَ", 't': "«ومن ثمرات النخيل والأعناب» ثمر «تتخذون منه سكراً» خمراً يسكِر سميت بالمصدر وهذا قبل تحريمها «ورزقاً حسناً» كالتمر والزبيب والخل والدبس «إن في ذلك» المذكور «لآية» دالة على قدرته تعالى «لقوم يعقلون» يتدبرون."},
  {'n': '68', 'v': "وَأَوْحَىٰ رَبُّكَ إِلَى ٱلنَّحْلِ أَنِ ٱتَّخِذِى مِنَ ٱلْجِبَالِ بُيُوتًۭا وَمِنَ ٱلشَّجَرِ وَمِمَّا يَعْرِشُونَ", 't': "«وأوحى ربك إلى النحل» وحي إلهام «أن» مفسرة أو مصدرية «اتخذي من الجبال بيوتاً» تأوين إليها «ومن الشجر» بيوتًا «ومما يعرشون» أي الناس يبنون لك من الأماكن وإلا لم تأو إليها."},
  {'n': '69', 'v': "ثُمَّ كُلِى مِن كُلِّ ٱلثَّمَرَٰتِ فَٱسْلُكِى سُبُلَ رَبِّكِ ذُلُلًۭا ۚ يَخْرُجُ مِنۢ بُطُونِهَا شَرَابٌۭ مُّخْتَلِفٌ أَلْوَٰنُهُۥ فِيهِ شِفَآءٌۭ لِّلنَّاسِ ۗ إِنَّ فِى ذَٰلِكَ لَءَايَةًۭ لِّقَوْمٍۢ يَتَفَكَّرُونَ", 't': "«ثم كلي من كل الثمرات فاسلكي» ادخلي «سبل ربك» طرقه في طلب المرعى «ذللا» جمع ذلول حال من السبل أي مسخرة لك فلا تعسر عليك وإن توعرت ولا تضلي على العود منها وإن بعدت، وقيل من الضمير في اسلكي أي منقادة لما يراد منك «يخرج من بطونها شراب» هو العسل «مختلف ألوانه فيه شفاء للناس» من الأوجاع قيل لبعضها كما دل عليه تنكير شفاء أو لكلها بضميمته إلى غيره وبدونها بنيته وقد أمر به صلى الله عليه وسلم من استطلق عليه بطنه رواه الشيخان «إن في ذلك لآية لقوم يتفكرون» في صنعه تعالى."},
  {'n': '70', 'v': "وَٱللَّهُ خَلَقَكُمْ ثُمَّ يَتَوَفَّىٰكُمْ ۚ وَمِنكُم مَّن يُرَدُّ إِلَىٰٓ أَرْذَلِ ٱلْعُمُرِ لِكَىْ لَا يَعْلَمَ بَعْدَ عِلْمٍۢ شَيْـًٔا ۚ إِنَّ ٱللَّهَ عَلِيمٌۭ قَدِيرٌۭ", 't': "«والله خلقكم» ولم تكونوا شيئاً «ثم يتوفاكم» عند انقضاء آجالكم «ومنكم من يرد إلى أرذل العمر» أي أخسه من الهرم والخرف «لكي لا يعلم بعد علم شيئاً» قال عكرمة من قرأ القرآن لم يصر بهذه الحالة «إن الله عليم» بتدبير خلقه «قدير» على ما يريده."},
  {'n': '71', 'v': "وَٱللَّهُ فَضَّلَ بَعْضَكُمْ عَلَىٰ بَعْضٍۢ فِى ٱلرِّزْقِ ۚ فَمَا ٱلَّذِينَ فُضِّلُوا۟ بِرَآدِّى رِزْقِهِمْ عَلَىٰ مَا مَلَكَتْ أَيْمَٰنُهُمْ فَهُمْ فِيهِ سَوَآءٌ ۚ أَفَبِنِعْمَةِ ٱللَّهِ يَجْحَدُونَ", 't': "«والله فضل بعضكم على بعض في الرزق» فمنكم غني وفقير ومالك ومملوك «فما الذين فضلوا» أي الموالي «برادي رزقهم على ما ملكت أيمانهم» أي بجاعلي ما رزقناهم من الأموال وغيرها شركة بينهم وبين مماليكهم «فهم» أي المماليك والموالي «فيه سواء» شركاء المعنى ليس لهم شركاء من مماليكهم في أموالهم فكيف يجعلون بعض مماليك الله شركاء له «أفبنعمة الله يجحدون» يكفرون حيث يجعلون له شركاء."},
  {'n': '72', 'v': "وَٱللَّهُ جَعَلَ لَكُم مِّنْ أَنفُسِكُمْ أَزْوَٰجًۭا وَجَعَلَ لَكُم مِّنْ أَزْوَٰجِكُم بَنِينَ وَحَفَدَةًۭ وَرَزَقَكُم مِّنَ ٱلطَّيِّبَٰتِ ۚ أَفَبِٱلْبَٰطِلِ يُؤْمِنُونَ وَبِنِعْمَتِ ٱللَّهِ هُمْ يَكْفُرُونَ", 't': "«والله جعل لكم من أنفسكم أزواجا» فخلق حواء من ضلع آدم وسائر الناس من نطف الرجال والنساء «وجعل لكم من أزواجكم بنين وحفدة» أولاد الأولاد «ورزقكم من الطيبات» من أنواع الثمار والحبوب والحيوان «أفبالباطل» الصنم «يؤمنون وبنعمة الله هم يكفرون» بإشراكهم."},
  {'n': '73', 'v': "وَيَعْبُدُونَ مِن دُونِ ٱللَّهِ مَا لَا يَمْلِكُ لَهُمْ رِزْقًۭا مِّنَ ٱلسَّمَٰوَٰتِ وَٱلْأَرْضِ شَيْـًۭٔا وَلَا يَسْتَطِيعُونَ", 't': "«ويعبدون من دون الله» أي غيره «ما لا يملك لهم رزقا من السماوات» بالمطر «والأرض» بالنبات «شيئا» بدل من رزقا «ولا يستطيعون» يقدرون على شيء وهو الأصنام."},
  {'n': '74', 'v': "فَلَا تَضْرِبُوا۟ لِلَّهِ ٱلْأَمْثَالَ ۚ إِنَّ ٱللَّهَ يَعْلَمُ وَأَنتُمْ لَا تَعْلَمُونَ", 't': "«فلا تضربوا لله الأمثال» لا تجعلوا لله أشباها تشركون به «إن الله يعلم» أن لا مثل له «وأنتم لا تعلمون» ذلك."},
  {'n': '75', 'v': "۞ ضَرَبَ ٱللَّهُ مَثَلًا عَبْدًۭا مَّمْلُوكًۭا لَّا يَقْدِرُ عَلَىٰ شَىْءٍۢ وَمَن رَّزَقْنَٰهُ مِنَّا رِزْقًا حَسَنًۭا فَهُوَ يُنفِقُ مِنْهُ سِرًّۭا وَجَهْرًا ۖ هَلْ يَسْتَوُۥنَ ۚ ٱلْحَمْدُ لِلَّهِ ۚ بَلْ أَكْثَرُهُمْ لَا يَعْلَمُونَ", 't': "«ضرب الله مثلاً» ويبدل منه «عبدا مملوكا» صفة تميزه من الحر فإنه عبد الله «لا يقدر على شيء» لعدم ملكه «ومن» نكرة موصوفة أي حرا «رزقناه منا رزقا حسنا فهو ينفق منه سرا وجهرا» أي يتصرف فيه كيف يشاء والأول مثل الأصنام والثاني مثله تعالى «هل يستوون» أي العبيد العجزة والحر المتصرف؟ لا «الحمد لله» وحده «بل أكثرهم» أي أهل مكة «لا يعلمون» ما يصيرون إليه من العذاب فيشركون."},
  {'n': '76', 'v': "وَضَرَبَ ٱللَّهُ مَثَلًۭا رَّجُلَيْنِ أَحَدُهُمَآ أَبْكَمُ لَا يَقْدِرُ عَلَىٰ شَىْءٍۢ وَهُوَ كَلٌّ عَلَىٰ مَوْلَىٰهُ أَيْنَمَا يُوَجِّههُّ لَا يَأْتِ بِخَيْرٍ ۖ هَلْ يَسْتَوِى هُوَ وَمَن يَأْمُرُ بِٱلْعَدْلِ ۙ وَهُوَ عَلَىٰ صِرَٰطٍۢ مُّسْتَقِيمٍۢ", 't': "«وضرب الله مثلاً» ويبدل منه «رجلين أحدهما أبكم» ولد أخرس «لا يقدر على شيء» لأنه لا يفهم ولا يُفهم «وهو كلّ» ثقيل «على مولاه» وليّ أمره «أينما يوجهه» يصرفه «لا يأت» منه «بخير» ينجح وهذا مثل الكافر «هل يستوي هو» أي الأبكم المذكور «ومن يأمر بالعدل» أي ومن هو ناطق نافع للناس حيث يأمر به ويحث عليه «وهو على صراط» طريق «مستقيم» وهو الثاني المؤمن؟ لا، وقيل هذا مثل الله، والأبكم للأصنام والذي قبله مثل الكافر والمؤمن."},
  {'n': '77', 'v': "وَلِلَّهِ غَيْبُ ٱلسَّمَٰوَٰتِ وَٱلْأَرْضِ ۚ وَمَآ أَمْرُ ٱلسَّاعَةِ إِلَّا كَلَمْحِ ٱلْبَصَرِ أَوْ هُوَ أَقْرَبُ ۚ إِنَّ ٱللَّهَ عَلَىٰ كُلِّ شَىْءٍۢ قَدِيرٌۭ", 't': "«ولله غيب السماوات والأرض» أي علم ما غاب فيهما «وما أمر الساعة إلا كلمح البصر أو هو أقرب» لأنه بلفظ كن فيكون «إن الله على كل شيء قدير»."},
  {'n': '78', 'v': "وَٱللَّهُ أَخْرَجَكُم مِّنۢ بُطُونِ أُمَّهَٰتِكُمْ لَا تَعْلَمُونَ شَيْـًۭٔا وَجَعَلَ لَكُمُ ٱلسَّمْعَ وَٱلْأَبْصَٰرَ وَٱلْأَفْـِٔدَةَ ۙ لَعَلَّكُمْ تَشْكُرُونَ", 't': "«والله أخرجكم من بطون أمهاتكم لا تعلمون شيئا» الجملة حال «وجعل لكم السمع» بمعنى الأسماع «والأبصار والأفئدة» القلوب «لعلكم تشكرونـ» ـه على ذلك فتؤمنون."},
  {'n': '79', 'v': "أَلَمْ يَرَوْا۟ إِلَى ٱلطَّيْرِ مُسَخَّرَٰتٍۢ فِى جَوِّ ٱلسَّمَآءِ مَا يُمْسِكُهُنَّ إِلَّا ٱللَّهُ ۗ إِنَّ فِى ذَٰلِكَ لَءَايَٰتٍۢ لِّقَوْمٍۢ يُؤْمِنُونَ", 't': "«ألم يروْا إلى الطير مسخرات» مذللات للطيران «في جو السماء» أي الهواء بين السماء والأرض «ما يمسكهن» عند قبض أجنحتهن أو بسطها أن يقعن «إلا الله» بقدرته «إن في ذلك لآيات لقوم يؤمنون» هي خلقها بحيث يمكنها الطيران وخلق الجو بحيث يمكن الطيران فيه وإمساكها."},
  {'n': '80', 'v': "وَٱللَّهُ جَعَلَ لَكُم مِّنۢ بُيُوتِكُمْ سَكَنًۭا وَجَعَلَ لَكُم مِّن جُلُودِ ٱلْأَنْعَٰمِ بُيُوتًۭا تَسْتَخِفُّونَهَا يَوْمَ ظَعْنِكُمْ وَيَوْمَ إِقَامَتِكُمْ ۙ وَمِنْ أَصْوَافِهَا وَأَوْبَارِهَا وَأَشْعَارِهَآ أَثَٰثًۭا وَمَتَٰعًا إِلَىٰ حِينٍۢ", 't': "«والله جعل لكم من بيوتكم سكنا» موضعا تسكنون فيه «وجعل لكم من جلود الأنعام بيوتا» كالخيام والقباب «تستخفونها» للحمل «يوم ظعنكم» سفركم «ويوم إقامتكم ومن أصوافها» أي الغنم «وأوبارها» أي الإبل «وأشعارها» أي المعز «أثاثا» متاعا لبيوتكم كبسط وأكسية «ومتاعا» تتمتعون به «إلى حين» يبلى فيه."},
  {'n': '81', 'v': "وَٱللَّهُ جَعَلَ لَكُم مِّمَّا خَلَقَ ظِلَٰلًۭا وَجَعَلَ لَكُم مِّنَ ٱلْجِبَالِ أَكْنَٰنًۭا وَجَعَلَ لَكُمْ سَرَٰبِيلَ تَقِيكُمُ ٱلْحَرَّ وَسَرَٰبِيلَ تَقِيكُم بَأْسَكُمْ ۚ كَذَٰلِكَ يُتِمُّ نِعْمَتَهُۥ عَلَيْكُمْ لَعَلَّكُمْ تُسْلِمُونَ", 't': "«والله جعل لكم مما خلق» من البيوت والشجر والغمام «ظلالاً» جمع ظل، تقيكم حر الشمس «وجعل لكم من الجبال أكنانا» جمع كن، وهو ما يستكن فيه كالغار والسرب «وجعل لكم سرابيل» قمصا «تقيكم الحر» أي والبرد «وسرابيل تقيكم بأسكم» حربكم أي الطعن والضرب فيها كالدروع والجواشن «كذلك» كما خلق هذه الأشياء «يُتم نعمته» في الدنيا «عليكم» بخلق ما تحتاجون إليه «لعلكم» يا أهل مكة «تسلمون» توحدونه."},
  {'n': '82', 'v': "فَإِن تَوَلَّوْا۟ فَإِنَّمَا عَلَيْكَ ٱلْبَلَٰغُ ٱلْمُبِينُ", 't': "«فإن تولوْا» أعرضوا عن الإسلام «فإنما عليك» يا محمد «البلاغ المبين» الإبلاغ البيِّن وهذا قبل الأمر بالقتال."},
  {'n': '83', 'v': "يَعْرِفُونَ نِعْمَتَ ٱللَّهِ ثُمَّ يُنكِرُونَهَا وَأَكْثَرُهُمُ ٱلْكَٰفِرُونَ", 't': "«يعرفون نعمة الله» أي يقرّون بأنها من عنده «ثم ينكرونها» بإشراكهم «وأكثرهم الكافرون»."},
  {'n': '84', 'v': "وَيَوْمَ نَبْعَثُ مِن كُلِّ أُمَّةٍۢ شَهِيدًۭا ثُمَّ لَا يُؤْذَنُ لِلَّذِينَ كَفَرُوا۟ وَلَا هُمْ يُسْتَعْتَبُونَ", 't': "«و» اذكر «يوم نبعث من كل أمة شهيداً» هو نبيها يشهد لها وعليها وهو يوم القيامة «ثم لا يؤذن للذين كفروا» في الاعتذار «ولا هم يستعتبون» لا يطلب منهم العتبى أي الرجوع إلى ما يرضي الله."},
  {'n': '85', 'v': "وَإِذَا رَءَا ٱلَّذِينَ ظَلَمُوا۟ ٱلْعَذَابَ فَلَا يُخَفَّفُ عَنْهُمْ وَلَا هُمْ يُنظَرُونَ", 't': "«وإذا رأى الذين ظلموا» كفروا «العذاب» النار «فلا يُخفف عنهم» العذاب «ولا هم يُنظرون» يمهلون عنه إذا رأوه."},
  {'n': '86', 'v': "وَإِذَا رَءَا ٱلَّذِينَ أَشْرَكُوا۟ شُرَكَآءَهُمْ قَالُوا۟ رَبَّنَا هَٰٓؤُلَآءِ شُرَكَآؤُنَا ٱلَّذِينَ كُنَّا نَدْعُوا۟ مِن دُونِكَ ۖ فَأَلْقَوْا۟ إِلَيْهِمُ ٱلْقَوْلَ إِنَّكُمْ لَكَٰذِبُونَ", 't': "(وإذا رأى الذين أشركوا شركاءهم) من الشياطين وغيرها (قالوا ربنا هؤلاء شركاؤنا الذين كنا ندعو) نعبدهم (من دونك فألقوا إليهم القول) أي قالوا لهم (إنكم لكاذبون) في قولكم إنكم عبدتمونا كما في آية أخرى \" ما كانوا إيانا يعبدون \"، سيكفرون بعبادتهم."},
  {'n': '87', 'v': "وَأَلْقَوْا۟ إِلَى ٱللَّهِ يَوْمَئِذٍ ٱلسَّلَمَ ۖ وَضَلَّ عَنْهُم مَّا كَانُوا۟ يَفْتَرُونَ", 't': "«وألقوا إلى الله يومئذ السلم» أي استسلموا لحكمه «وضل» غاب «عنهم ما كانوا يفترون» من أن آلهتهم تشفع لهم."},
  {'n': '88', 'v': "ٱلَّذِينَ كَفَرُوا۟ وَصَدُّوا۟ عَن سَبِيلِ ٱللَّهِ زِدْنَٰهُمْ عَذَابًۭا فَوْقَ ٱلْعَذَابِ بِمَا كَانُوا۟ يُفْسِدُونَ", 't': "«الذين كفروا وصدوا» الناس «عن سبيل الله» دينه «زدناهم عذابا فوق العذاب» الذي استحقوه بكفرهم قال ابن مسعود: عقارب أنيابها كالنخل الطوال «بما كانوا يفسدون» بصدهم الناس عن الإيمان."},
  {'n': '89', 'v': "وَيَوْمَ نَبْعَثُ فِى كُلِّ أُمَّةٍۢ شَهِيدًا عَلَيْهِم مِّنْ أَنفُسِهِمْ ۖ وَجِئْنَا بِكَ شَهِيدًا عَلَىٰ هَٰٓؤُلَآءِ ۚ وَنَزَّلْنَا عَلَيْكَ ٱلْكِتَٰبَ تِبْيَٰنًۭا لِّكُلِّ شَىْءٍۢ وَهُدًۭى وَرَحْمَةًۭ وَبُشْرَىٰ لِلْمُسْلِمِينَ", 't': "«و» اذكر «يوم نبعث في كل أمة شهيدا عليهم من أنفسهم» وهو نبيهم «وجئنا بك» يا محمد «شهيدا على هؤلاء» أي قومك «ونزلنا عليك الكتاب» القرآن «تبيانا» بيانا «لكل شيء» يحتاج إليه الناس من أمر الشريعة «وهدى» من الضلالة «ورحمة وبشرى» بالجنة «للمسلمين» الموحدين."},
  {'n': '90', 'v': "۞ إِنَّ ٱللَّهَ يَأْمُرُ بِٱلْعَدْلِ وَٱلْإِحْسَٰنِ وَإِيتَآئِ ذِى ٱلْقُرْبَىٰ وَيَنْهَىٰ عَنِ ٱلْفَحْشَآءِ وَٱلْمُنكَرِ وَٱلْبَغْىِ ۚ يَعِظُكُمْ لَعَلَّكُمْ تَذَكَّرُونَ", 't': "«إن الله يأمر بالعدل» التوحيد أو الإنصاف «والإحسان» أداء الفرائض أو أن تعبد الله كأنك تراه كما في الحديث «وإيتاءِ» إعطاء «ذي القربى» القرابة خصه بالذكر اهتماما به «وينهى عن الفحشاء» الزنا «والمنكر» شرعا من الكفر والمعاصي «والبغي» الظلم للناس خصه بالذكر اهتماما كما بدأ بالفحشاء كذلك «يعظكم» بالأمر والنهي «لعلكم تذكرون» تتعظون وفيه إدغام التاء في الأصل في الذال، وفي المستدرك عن ابن مسعود وهذه أجمع آية في القرآن للخير والشر."},
  {'n': '91', 'v': "وَأَوْفُوا۟ بِعَهْدِ ٱللَّهِ إِذَا عَٰهَدتُّمْ وَلَا تَنقُضُوا۟ ٱلْأَيْمَٰنَ بَعْدَ تَوْكِيدِهَا وَقَدْ جَعَلْتُمُ ٱللَّهَ عَلَيْكُمْ كَفِيلًا ۚ إِنَّ ٱللَّهَ يَعْلَمُ مَا تَفْعَلُونَ", 't': "«وأوْفوا بعهد الله» من البيع والأيمان وغيرها «إذا عاهدتم ولا تنقضوا الأيمان بعد توكيدها» توثيقها «وقد جعلتم الله عليكم كفيلاً» بالوفاء حيث حلفتم به والجملة حال «إن الله يعلم ما تفعلون» تهديد لهم."},
  {'n': '92', 'v': "وَلَا تَكُونُوا۟ كَٱلَّتِى نَقَضَتْ غَزْلَهَا مِنۢ بَعْدِ قُوَّةٍ أَنكَٰثًۭا تَتَّخِذُونَ أَيْمَٰنَكُمْ دَخَلًۢا بَيْنَكُمْ أَن تَكُونَ أُمَّةٌ هِىَ أَرْبَىٰ مِنْ أُمَّةٍ ۚ إِنَّمَا يَبْلُوكُمُ ٱللَّهُ بِهِۦ ۚ وَلَيُبَيِّنَنَّ لَكُمْ يَوْمَ ٱلْقِيَٰمَةِ مَا كُنتُمْ فِيهِ تَخْتَلِفُونَ", 't': "«ولا تكونوا كالتي نقضت» أفسدت «غزلها» ما غزلته «من بعد قوة» إحكام له وبرم «أنكاثا» حال جمع نكث وهو ما ينكث أي يحل إحكامه وهي امرأة حمقاء من مكة كانت تغزل طوال يومها ثم تنقضه «تتخذون» حال من ضمير تكونوا: أي لا تكونوا مثلها في اتخاذكم «أيمانكم دخلاً» هو ما يدخل في الشيء وليس منه أي فسادا أو خديعة «بينكم» بأن تنقضوها «أن» أي لأن «تكون أُمة» جماعة «هي أربى» أكثر «من أمة» وكانوا يحالفون الحلفاء فإذا وجد أكثر منهم وأعز نقضوا حلف أولئك وحالفوهم «إنما يبلوكم» يختبركم «الله به» أي بما أمر به من الوفاء بالعهد لينظر المطيع منكم والعاصي أو يكون أمة أربى لينظر أتفون أم لا «وليبينن لكم يوم القيامة ما كنتم فيه تختلفون» في الدنيا من أمر العهد وغيره بأن يعذب الناكث ويثبت الوافي."},
  {'n': '93', 'v': "وَلَوْ شَآءَ ٱللَّهُ لَجَعَلَكُمْ أُمَّةًۭ وَٰحِدَةًۭ وَلَٰكِن يُضِلُّ مَن يَشَآءُ وَيَهْدِى مَن يَشَآءُ ۚ وَلَتُسْـَٔلُنَّ عَمَّا كُنتُمْ تَعْمَلُونَ", 't': "«ولو شاء الله لجعلكم أمة واحدة» أهل دين واحد «ولكن يضل من يشاء ويهدي من يشاء ولتسألُن» يوم القيامة سؤال تبكيت «عما كنتم تعملون» لتجازوا عليه."},
  {'n': '94', 'v': "وَلَا تَتَّخِذُوٓا۟ أَيْمَٰنَكُمْ دَخَلًۢا بَيْنَكُمْ فَتَزِلَّ قَدَمٌۢ بَعْدَ ثُبُوتِهَا وَتَذُوقُوا۟ ٱلسُّوٓءَ بِمَا صَدَدتُّمْ عَن سَبِيلِ ٱللَّهِ ۖ وَلَكُمْ عَذَابٌ عَظِيمٌۭ", 't': "«ولا تتخذوا أيمانكم دخلاً بينكم» كرره تأكدا «فتزل قدم» أي أقدامكم عن محجة الإسلام «بعد ثبوتها» استقامتها عليها «وتذوقوا السوء» أي العذاب «بما صددتم عن سبيل الله» أي بصدكم عن الوفاء بالعهد أو بصدكم غيركم عنه لأنه يستن بكم «ولكم عذاب عظيم» في الآخرة."},
  {'n': '95', 'v': "وَلَا تَشْتَرُوا۟ بِعَهْدِ ٱللَّهِ ثَمَنًۭا قَلِيلًا ۚ إِنَّمَا عِندَ ٱللَّهِ هُوَ خَيْرٌۭ لَّكُمْ إِن كُنتُمْ تَعْلَمُونَ", 't': "«ولا تشتروا بعهد الله ثمنا قليلاً» من الدنيا بأن تنقضوه لأجله «إنما عند الله» من الثواب «هو خير لكم» مما في الدنيا «إن كنتم تعلمون» ذلك فلا تنقضوا."},
  {'n': '96', 'v': "مَا عِندَكُمْ يَنفَدُ ۖ وَمَا عِندَ ٱللَّهِ بَاقٍۢ ۗ وَلَنَجْزِيَنَّ ٱلَّذِينَ صَبَرُوٓا۟ أَجْرَهُم بِأَحْسَنِ مَا كَانُوا۟ يَعْمَلُونَ", 't': "«ما عندكم» من الدنيا «يَنفدُ» يفنى «وما عند الله باقي» دائم «وليجزينَّ» بالياء والنون «الذين صبروا» من الوفاء بالعهود «أجرهم بأحسن ما كانوا يعملون» أحسن بمعنى حسن."},
  {'n': '97', 'v': "مَنْ عَمِلَ صَٰلِحًۭا مِّن ذَكَرٍ أَوْ أُنثَىٰ وَهُوَ مُؤْمِنٌۭ فَلَنُحْيِيَنَّهُۥ حَيَوٰةًۭ طَيِّبَةًۭ ۖ وَلَنَجْزِيَنَّهُمْ أَجْرَهُم بِأَحْسَنِ مَا كَانُوا۟ يَعْمَلُونَ", 't': "«من عمل صالحاً من ذكر أو أنثى وهو مؤمن فلنحيينه حياة طيبة» قيل هي حياة الجنة وقيل في الدنيا بالقناعة أو الرزق الحلال «ولنجزينهم أجرهم بأحسن ما كانوا يعملون»."},
  {'n': '98', 'v': "فَإِذَا قَرَأْتَ ٱلْقُرْءَانَ فَٱسْتَعِذْ بِٱللَّهِ مِنَ ٱلشَّيْطَٰنِ ٱلرَّجِيمِ", 't': "«فإذا قرأت القرآن» أي أردت قراءته «فاستعذ بالله من الشيطان الرجيم» أي قل: أعوذ بالله من الشيطان الرجيم."},
  {'n': '99', 'v': "إِنَّهُۥ لَيْسَ لَهُۥ سُلْطَٰنٌ عَلَى ٱلَّذِينَ ءَامَنُوا۟ وَعَلَىٰ رَبِّهِمْ يَتَوَكَّلُونَ", 't': "«إنه ليس له سلطان» تسلط «على الذين آمنوا وعلى ربهم يتوكلون»."},
  {'n': '100', 'v': "إِنَّمَا سُلْطَٰنُهُۥ عَلَى ٱلَّذِينَ يَتَوَلَّوْنَهُۥ وَٱلَّذِينَ هُم بِهِۦ مُشْرِكُونَ", 't': "«إنما سلطانه على الذين يتولوْنه» بطاعته «والذين هم به» أي الله «مشركون»."},
  {'n': '101', 'v': "وَإِذَا بَدَّلْنَآ ءَايَةًۭ مَّكَانَ ءَايَةٍۢ ۙ وَٱللَّهُ أَعْلَمُ بِمَا يُنَزِّلُ قَالُوٓا۟ إِنَّمَآ أَنتَ مُفْتَرٍۭ ۚ بَلْ أَكْثَرُهُمْ لَا يَعْلَمُونَ", 't': "«وإذا بدلنا آية مكان آية» بنسخها وإنزال غيرها بمصلحة العباد «والله أعلم بما ينزل قالوا» أي الكفار للنبي صلى الله عليه وسلم «إنما أنت مفتر» كذاب تقوله من عندك «بل أكثرهم لا يعلمون» حقيقة القرآن وفائدة النسخ."},
  {'n': '102', 'v': "قُلْ نَزَّلَهُۥ رُوحُ ٱلْقُدُسِ مِن رَّبِّكَ بِٱلْحَقِّ لِيُثَبِّتَ ٱلَّذِينَ ءَامَنُوا۟ وَهُدًۭى وَبُشْرَىٰ لِلْمُسْلِمِينَ", 't': "«قل» لهم «نزَّله روح القدس» جبريل «من ربك بالحق» متعلق بنزل «ليثبت الذين آمنوا» بإيمانهم به «وهدى وبشرى للمسلمين»."},
  {'n': '103', 'v': "وَلَقَدْ نَعْلَمُ أَنَّهُمْ يَقُولُونَ إِنَّمَا يُعَلِّمُهُۥ بَشَرٌۭ ۗ لِّسَانُ ٱلَّذِى يُلْحِدُونَ إِلَيْهِ أَعْجَمِىٌّۭ وَهَٰذَا لِسَانٌ عَرَبِىٌّۭ مُّبِينٌ", 't': "«ولقد» للتحقيق «نعلم أنهم يقولون إنما يعلمه» القرآن «بشر» وهو قين نصراني كان النبي صلى الله عليه وسلم يدخل عليه قال تعالى «لسان» لغة «الذي يلحدون» يميلون «إليه» أنه يعلمه «أعجمي وهذا» القرآن «لسان عربي مبين» ذو بيان وفصاحة فكيف يعلمه أعجمي."},
  {'n': '104', 'v': "إِنَّ ٱلَّذِينَ لَا يُؤْمِنُونَ بِـَٔايَٰتِ ٱللَّهِ لَا يَهْدِيهِمُ ٱللَّهُ وَلَهُمْ عَذَابٌ أَلِيمٌ", 't': "«إن الذين لا يؤمنون بآيات الله لا يهديهم الله ولهم عذاب أليم» مؤلم."},
  {'n': '105', 'v': "إِنَّمَا يَفْتَرِى ٱلْكَذِبَ ٱلَّذِينَ لَا يُؤْمِنُونَ بِـَٔايَٰتِ ٱللَّهِ ۖ وَأُو۟لَٰٓئِكَ هُمُ ٱلْكَٰذِبُونَ", 't': "(إنما يفتري الكذب الذين لا يؤمنون بآيات الله) القرآن بقولهم هذا من قول البشر (وأولئك هم الكاذبون) والتأكيد بالتكرار، وإن وغيرهما رد لقولهم \"\" إنما أنت مفتر \"\"."},
  {'n': '106', 'v': "مَن كَفَرَ بِٱللَّهِ مِنۢ بَعْدِ إِيمَٰنِهِۦٓ إِلَّا مَنْ أُكْرِهَ وَقَلْبُهُۥ مُطْمَئِنٌّۢ بِٱلْإِيمَٰنِ وَلَٰكِن مَّن شَرَحَ بِٱلْكُفْرِ صَدْرًۭا فَعَلَيْهِمْ غَضَبٌۭ مِّنَ ٱللَّهِ وَلَهُمْ عَذَابٌ عَظِيمٌۭ", 't': "«من كفر بالله من بعد إيمانه إلا من أكره» على التلفظ بالكفر فتلفظ به «وقلبه مطمئن بالإيمان» ومن مبتدأ أو شرطية والخبر أو الجواب لهم وعيد شديد دل على هذا «ولكن من شرح بالكفر صدرا» له أي فتحه ووسعه بمعنى طابت به نفسه «فعليهم غضب من الله ولهم عذاب عظيم»."},
  {'n': '107', 'v': "ذَٰلِكَ بِأَنَّهُمُ ٱسْتَحَبُّوا۟ ٱلْحَيَوٰةَ ٱلدُّنْيَا عَلَى ٱلْءَاخِرَةِ وَأَنَّ ٱللَّهَ لَا يَهْدِى ٱلْقَوْمَ ٱلْكَٰفِرِينَ", 't': "«ذلك» الوعيد لهم «بأنهم استحبوا الحياة الدنيا» اختاروها «على الآخرة وأن الله لا يهدي القوم الكافرين»."},
  {'n': '108', 'v': "أُو۟لَٰٓئِكَ ٱلَّذِينَ طَبَعَ ٱللَّهُ عَلَىٰ قُلُوبِهِمْ وَسَمْعِهِمْ وَأَبْصَٰرِهِمْ ۖ وَأُو۟لَٰٓئِكَ هُمُ ٱلْغَٰفِلُونَ", 't': "«أولئك الذين طبع الله على قلوبهم وسمعهم وأبصارهم وأولئك هم الغافلون» عما يراد بهم."},
  {'n': '109', 'v': "لَا جَرَمَ أَنَّهُمْ فِى ٱلْءَاخِرَةِ هُمُ ٱلْخَٰسِرُونَ", 't': "«لا جرم» حقاً «أنهم في الآخرة هم الخاسرون» لمصيرهم إلى النار المؤبدة عليهم."},
