  {'n': '18', 'v': "مَّن كَانَ يُرِيدُ ٱلْعَاجِلَةَ عَجَّلْنَا لَهُۥ فِيهَا مَا نَشَآءُ لِمَن نُّرِيدُ ثُمَّ جَعَلْنَا لَهُۥ جَهَنَّمَ يَصْلَىٰهَا مَذْمُومًۭا مَّدْحُورًۭا", 't': "«من كان يريد» بعمله «العاجلة» أي الدنيا «عجلنا له فيها ما نشاء لمن نريد» التعجيل له بدل من له بإعادة الجار «ثم جعلنا له» في الآخرة «جهنم يصلاها» يدخلها «مذموما» ملوما «مدحورا» مطرودا عن الرحمة."},
  {'n': '19', 'v': "وَمَنْ أَرَادَ ٱلْءَاخِرَةَ وَسَعَىٰ لَهَا سَعْيَهَا وَهُوَ مُؤْمِنٌۭ فَأُو۟لَٰٓئِكَ كَانَ سَعْيُهُم مَّشْكُورًۭا", 't': "«ومن أراد الآخرة وسعى لها سعيها» عمل عملها اللائق بها «وهو مؤمن» حال «فأولئك كان سعيهم مشكورا» عند الله أي مقبولاً مثابا عليه."},
  {'n': '20', 'v': "كُلًّۭا نُّمِدُّ هَٰٓؤُلَآءِ وَهَٰٓؤُلَآءِ مِنْ عَطَآءِ رَبِّكَ ۚ وَمَا كَانَ عَطَآءُ رَبِّكَ مَحْظُورًا", 't': "«كلا» من الفريقين «نمد» نعطي «هؤلاء وهؤلاء» بدل «من» متعلق بنمد «عطاء ربك» في الدنيا «وما كان عطاء ربك» فيها «محظورا» ممنوعا عن أحد."},
  {'n': '21', 'v': "ٱنظُرْ كَيْفَ فَضَّلْنَا بَعْضَهُمْ عَلَىٰ بَعْضٍۢ ۚ وَلَلْءَاخِرَةُ أَكْبَرُ دَرَجَٰتٍۢ وَأَكْبَرُ تَفْضِيلًۭا", 't': "«انظر كيف فضلنا بعضهم على بعض» في الرزق والجاه «وللآخرة أكبر» أعظم «درجات وأكبر تفضيلاً» من الدنيا فينبغي الاعتناء بها دونها."},
  {'n': '22', 'v': "لَّا تَجْعَلْ مَعَ ٱللَّهِ إِلَٰهًا ءَاخَرَ فَتَقْعُدَ مَذْمُومًۭا مَّخْذُولًۭا", 't': "«لا تجعل مع الله إلها آخر فتقعد مذموما مخذولاً» لا ناصر لك."},
  {'n': '23', 'v': "۞ وَقَضَىٰ رَبُّكَ أَلَّا تَعْبُدُوٓا۟ إِلَّآ إِيَّاهُ وَبِٱلْوَٰلِدَيْنِ إِحْسَٰنًا ۚ إِمَّا يَبْلُغَنَّ عِندَكَ ٱلْكِبَرَ أَحَدُهُمَآ أَوْ كِلَاهُمَا فَلَا تَقُل لَّهُمَآ أُفٍّۢ وَلَا تَنْهَرْهُمَا وَقُل لَّهُمَا قَوْلًۭا كَرِيمًۭا", 't': "«وقضى» أمر «ربك أ» ن أي بأن «لا تعبدوا إلا إياه و» أن تحسنوا «بالوالدين إحسانا» بأن تبروهما «إما يبلغن عندك الكبر أحدهما» فاعل «أو كلاهما» وفي قراءة يَبْلُغان فأحدهما بدل من ألفه «فلا تقل لهما أف» بفتح الفاء وكسرها منونا وغير منون مصدر بمعنى تبا وقبحا «ولا تنهرهما» تزجرهما «وقل لهما قولاً كريما» جميلاً لينا."},
  {'n': '24', 'v': "وَٱخْفِضْ لَهُمَا جَنَاحَ ٱلذُّلِّ مِنَ ٱلرَّحْمَةِ وَقُل رَّبِّ ٱرْحَمْهُمَا كَمَا رَبَّيَانِى صَغِيرًۭا", 't': "«واخفض لهما جناح الذل» ألن لهما جانبك الذليل «من الرحمة» أي لرقتك عليهما «وقل رب ارحمهما كما» رحماني حين «ربياني صغيرا»."},
  {'n': '25', 'v': "رَّبُّكُمْ أَعْلَمُ بِمَا فِى نُفُوسِكُمْ ۚ إِن تَكُونُوا۟ صَٰلِحِينَ فَإِنَّهُۥ كَانَ لِلْأَوَّٰبِينَ غَفُورًۭا", 't': "«ربكم أعلم بما في نفوسكم» من إضمار البر والعقوق «إن تكونوا صالحين» طائعين لله «فإنه كان للأوابين» الرجّاعين إلى طاعته «غفورا» لما صدر منهم في حق الوالدين من بادرة وهم لا يضمرون عقوقا."},
  {'n': '26', 'v': "وَءَاتِ ذَا ٱلْقُرْبَىٰ حَقَّهُۥ وَٱلْمِسْكِينَ وَٱبْنَ ٱلسَّبِيلِ وَلَا تُبَذِّرْ تَبْذِيرًا", 't': "«وآت» أعط «ذا القربى» القرابة «حقه» من البر والصلة «والمسكين وابن السبيل ولا تبذر تبذيرا» بالإنفاق في غير طاعة الله."},
  {'n': '27', 'v': "إِنَّ ٱلْمُبَذِّرِينَ كَانُوٓا۟ إِخْوَٰنَ ٱلشَّيَٰطِينِ ۖ وَكَانَ ٱلشَّيْطَٰنُ لِرَبِّهِۦ كَفُورًۭا", 't': "«إن المبذرين كانوا إخوان الشياطين» أي على طريقتهم «وكان الشيطان لربه كفورا» شديد الكفر لنعمه فكذلك أخوه المبذر."},
  {'n': '28', 'v': "وَإِمَّا تُعْرِضَنَّ عَنْهُمُ ٱبْتِغَآءَ رَحْمَةٍۢ مِّن رَّبِّكَ تَرْجُوهَا فَقُل لَّهُمْ قَوْلًۭا مَّيْسُورًۭا", 't': "«وإما تعرضن عنهم» أي المذكورين من ذي القربى وما بعدهم فلم تعطهم «ابتغاء رحمة من ربك ترجوها» أي لطلب رزق تنتظره يأتيك تعطيهم منه «فقل لهم قولاً ميسورا» لينا سهلاً بأن تعدهم بالإعطاء عند مجيء الرزق."},
  {'n': '29', 'v': "وَلَا تَجْعَلْ يَدَكَ مَغْلُولَةً إِلَىٰ عُنُقِكَ وَلَا تَبْسُطْهَا كُلَّ ٱلْبَسْطِ فَتَقْعُدَ مَلُومًۭا مَّحْسُورًا", 't': "«ولا تجعل يدك مغلولة إلى عنقك» أي لا تمسكها عن الإنفاق كل المسك «ولا تبسطها» في الإنفاق «كل البسط فتقعد ملوما» راجع للأول «محسورا» منقطعا لا شيء عندك راجع للثاني."},
  {'n': '30', 'v': "إِنَّ رَبَّكَ يَبْسُطُ ٱلرِّزْقَ لِمَن يَشَآءُ وَيَقْدِرُ ۚ إِنَّهُۥ كَانَ بِعِبَادِهِۦ خَبِيرًۢا بَصِيرًۭا", 't': "«إن ربك يبسط الرزق» يوسعه «لمن يشاء ويقدر» يضيقه لمن يشاء «إنه كان بعباده خبيرا بصيرا» عالما ببواطنهم وظواهرهم فيرزقهم على حسب مصالحهم."},
  {'n': '31', 'v': "وَلَا تَقْتُلُوٓا۟ أَوْلَٰدَكُمْ خَشْيَةَ إِمْلَٰقٍۢ ۖ نَّحْنُ نَرْزُقُهُمْ وَإِيَّاكُمْ ۚ إِنَّ قَتْلَهُمْ كَانَ خِطْـًۭٔا كَبِيرًۭا", 't': "«ولا تقتلوا أولادكم» بالوأد «خشية» مخافة «إملاق» فقر «نحن نرزقهم وإياكم إن قتلهم كان خطأ» إثما «كبيرا» عظيما."},
  {'n': '32', 'v': "وَلَا تَقْرَبُوا۟ ٱلزِّنَىٰٓ ۖ إِنَّهُۥ كَانَ فَٰحِشَةًۭ وَسَآءَ سَبِيلًۭا", 't': "«ولا تقربوا الزنى» أبلغ من لا تأتوه «إنه كان فاحشة» قبيحا «وساء» بئس «سبيلاً» طريقا هو."},
  {'n': '33', 'v': "وَلَا تَقْتُلُوا۟ ٱلنَّفْسَ ٱلَّتِى حَرَّمَ ٱللَّهُ إِلَّا بِٱلْحَقِّ ۗ وَمَن قُتِلَ مَظْلُومًۭا فَقَدْ جَعَلْنَا لِوَلِيِّهِۦ سُلْطَٰنًۭا فَلَا يُسْرِف فِّى ٱلْقَتْلِ ۖ إِنَّهُۥ كَانَ مَنصُورًۭا", 't': "«ولا تقتلوا النفس التي حرم الله إلا بالحق ومن قُتل مظلوما فقد جعلنا لوليه» لوارثه «سلطانا» تسلطا على القاتل «فلا يسرف» يتجاوز الحد «في القتل» بأن يقتل غير قاتله أو بغير ما قتل به «إنه كان منصورا»."},
  {'n': '34', 'v': "وَلَا تَقْرَبُوا۟ مَالَ ٱلْيَتِيمِ إِلَّا بِٱلَّتِى هِىَ أَحْسَنُ حَتَّىٰ يَبْلُغَ أَشُدَّهُۥ ۚ وَأَوْفُوا۟ بِٱلْعَهْدِ ۖ إِنَّ ٱلْعَهْدَ كَانَ مَسْـُٔولًۭا", 't': "«ولا تقربوا مال اليتيم إلا بالتي هي أحسن حتى يبلغ أشده وأوفوا بالعهد» إذا عاهدتم الله أو الناس «إن العهد كان مسؤولا» عنه."},
  {'n': '35', 'v': "وَأَوْفُوا۟ ٱلْكَيْلَ إِذَا كِلْتُمْ وَزِنُوا۟ بِٱلْقِسْطَاسِ ٱلْمُسْتَقِيمِ ۚ ذَٰلِكَ خَيْرٌۭ وَأَحْسَنُ تَأْوِيلًۭا", 't': "«وأوْفوا الكيل» أتموه «إذا كلتم وزنوا بالقسطاس المستقيم» الميزان السوي «ذلك خير وأحسن تأويلاً» مآلاً."},
  {'n': '36', 'v': "وَلَا تَقْفُ مَا لَيْسَ لَكَ بِهِۦ عِلْمٌ ۚ إِنَّ ٱلسَّمْعَ وَٱلْبَصَرَ وَٱلْفُؤَادَ كُلُّ أُو۟لَٰٓئِكَ كَانَ عَنْهُ مَسْـُٔولًۭا", 't': "«ولا تقفُ» تتبع «ما ليس لك به علم إن السمع والبصر والفؤاد» القلب «كل أولئك كان عنه مسؤولاً» صاحبه ماذا فعل به."},
  {'n': '37', 'v': "وَلَا تَمْشِ فِى ٱلْأَرْضِ مَرَحًا ۖ إِنَّكَ لَن تَخْرِقَ ٱلْأَرْضَ وَلَن تَبْلُغَ ٱلْجِبَالَ طُولًۭا", 't': "«ولا تمش في الأرض مرحا» أي ذا مرح بالكبر والخيلاء «إنك لن تخرق الأرض» تثقبها حتى تبلغ آخرها بكبرك «ولن تبلغ الجبال طولاً» المعنى أنك لا تبلغ هذا المبلغ فكيف تختال."},
  {'n': '38', 'v': "كُلُّ ذَٰلِكَ كَانَ سَيِّئُهُۥ عِندَ رَبِّكَ مَكْرُوهًۭا", 't': "«كل ذلك» المذكور «كان سيِّئُهُ عند ربك مكروها»."},
  {'n': '39', 'v': "ذَٰلِكَ مِمَّآ أَوْحَىٰٓ إِلَيْكَ رَبُّكَ مِنَ ٱلْحِكْمَةِ ۗ وَلَا تَجْعَلْ مَعَ ٱللَّهِ إِلَٰهًا ءَاخَرَ فَتُلْقَىٰ فِى جَهَنَّمَ مَلُومًۭا مَّدْحُورًا", 't': "«ذلك مما أوحى إليك» يا محمد «ربك من الحكمة» الموعظة «ولا تجعل مع الله إلها آخر فتلقى في جهنم ملوما مدحورا» مطرودا من رحمة الله."},
  {'n': '40', 'v': "أَفَأَصْفَىٰكُمْ رَبُّكُم بِٱلْبَنِينَ وَٱتَّخَذَ مِنَ ٱلْمَلَٰٓئِكَةِ إِنَٰثًا ۚ إِنَّكُمْ لَتَقُولُونَ قَوْلًا عَظِيمًۭا", 't': "«أفأصفاكم» أخلصكم يا أهل مكة «ربكم بالبنين واتخذ من الملائكة إناثا» بنات لنفسه بزعمكم «إنكم لتقولون» بذلك «قولاً عظيما»."},
  {'n': '41', 'v': "وَلَقَدْ صَرَّفْنَا فِى هَٰذَا ٱلْقُرْءَانِ لِيَذَّكَّرُوا۟ وَمَا يَزِيدُهُمْ إِلَّا نُفُورًۭا", 't': "«ولقد صرفنا» بينا «في هذا القرآن» من الأمثال والوعد والوعيد «ليذكروا» يتعظوا «وما يزيدهم» ذلك «إلا نفروا» عن الحق."},
  {'n': '42', 'v': "قُل لَّوْ كَانَ مَعَهُۥٓ ءَالِهَةٌۭ كَمَا يَقُولُونَ إِذًۭا لَّٱبْتَغَوْا۟ إِلَىٰ ذِى ٱلْعَرْشِ سَبِيلًۭا", 't': "«قل» لهم «لو كان معه» أي الله «آلهة كما يقولون إذا لابتغوْا» طلبوا «إلى ذي العرش» أي الله «سبيلاً» ليقاتلوه."},
  {'n': '43', 'v': "سُبْحَٰنَهُۥ وَتَعَٰلَىٰ عَمَّا يَقُولُونَ عُلُوًّۭا كَبِيرًۭا", 't': "«سبحانه» تنزيها له «وتعالى عما يقولون» من الشركاء «علوا كبيرا»."},
  {'n': '44', 'v': "تُسَبِّحُ لَهُ ٱلسَّمَٰوَٰتُ ٱلسَّبْعُ وَٱلْأَرْضُ وَمَن فِيهِنَّ ۚ وَإِن مِّن شَىْءٍ إِلَّا يُسَبِّحُ بِحَمْدِهِۦ وَلَٰكِن لَّا تَفْقَهُونَ تَسْبِيحَهُمْ ۗ إِنَّهُۥ كَانَ حَلِيمًا غَفُورًۭا", 't': "«تسبح له» تنزهه «السماوات السبع والأرض ومن فيهن وإن» ما «من شيء» من المخلوقات «إلا يسبح» متلبسا «بحمده» أي يقول سبحان الله وبحمده «ولكن لا تفقهون» تفهمون «تسبيحهم» لأنه ليس بلغتكم «إنه كان حليما غفورا» حيث لم يعاجلكم بالعقوبة."},
  {'n': '45', 'v': "وَإِذَا قَرَأْتَ ٱلْقُرْءَانَ جَعَلْنَا بَيْنَكَ وَبَيْنَ ٱلَّذِينَ لَا يُؤْمِنُونَ بِٱلْءَاخِرَةِ حِجَابًۭا مَّسْتُورًۭا", 't': "«وإذا قرأت القرآن جعلنا بينك وبين الذين لا يؤمنون بالآخرة حجابا مستورا» أي ساترا لك عنهم فلا يرونك، نزل فيمن أراد الفتك به صلى الله عليه وسلم"},
  {'n': '46', 'v': "وَجَعَلْنَا عَلَىٰ قُلُوبِهِمْ أَكِنَّةً أَن يَفْقَهُوهُ وَفِىٓ ءَاذَانِهِمْ وَقْرًۭا ۚ وَإِذَا ذَكَرْتَ رَبَّكَ فِى ٱلْقُرْءَانِ وَحْدَهُۥ وَلَّوْا۟ عَلَىٰٓ أَدْبَٰرِهِمْ نُفُورًۭا", 't': "«وجعلنا على قلوبهم أكنة» أغطية «أن يفقهوه» من أن يفهموا القرآن أي فلا يفهمونه «وفي آذانهم وقرا» ثقلاً فلا يسمعونه «وإذا ذكرت ربك في القرآن وحده ولَّوا على أدبارهم نفورا» عنه."},
  {'n': '47', 'v': "نَّحْنُ أَعْلَمُ بِمَا يَسْتَمِعُونَ بِهِۦٓ إِذْ يَسْتَمِعُونَ إِلَيْكَ وَإِذْ هُمْ نَجْوَىٰٓ إِذْ يَقُولُ ٱلظَّٰلِمُونَ إِن تَتَّبِعُونَ إِلَّا رَجُلًۭا مَّسْحُورًا", 't': "«نحن أعلم بما يستمعون به» بسببه من الهزء «إذ يستمعون إليك» قراءتك «وإذ هم نجوى» يتناجون بينهم أي يتحدثون «إذ» بدل من إذ قبله «يقول الظالمون» في تناجيهم «إن» ما «تتبعون إلا رجلاً مسحورا» مخدوعا مغلوبا على عقله. قال تعالى:"},
  {'n': '48', 'v': "ٱنظُرْ كَيْفَ ضَرَبُوا۟ لَكَ ٱلْأَمْثَالَ فَضَلُّوا۟ فَلَا يَسْتَطِيعُونَ سَبِيلًۭا", 't': "«انظر كيف ضربوا لك الأمثال» بالمسحور والكاهن والشاعر «فضَلُّوا» بذلك عن الهدى «فلا يستطيعون سبيلاً» طريقا إليه «وقالوا» منكرين للبعث:"},
  {'n': '49', 'v': "وَقَالُوٓا۟ أَءِذَا كُنَّا عِظَٰمًۭا وَرُفَٰتًا أَءِنَّا لَمَبْعُوثُونَ خَلْقًۭا جَدِيدًۭا", 't': "«أئذا كنا عظاما ورفاتا أئنا لمبعوثون خلقا جديدا»."},
  {'n': '50', 'v': "۞ قُلْ كُونُوا۟ حِجَارَةً أَوْ حَدِيدًا", 't': "«قل» لهم «كونوا حجارة أو حديدا»."},
  {'n': '51', 'v': "أَوْ خَلْقًۭا مِّمَّا يَكْبُرُ فِى صُدُورِكُمْ ۚ فَسَيَقُولُونَ مَن يُعِيدُنَا ۖ قُلِ ٱلَّذِى فَطَرَكُمْ أَوَّلَ مَرَّةٍۢ ۚ فَسَيُنْغِضُونَ إِلَيْكَ رُءُوسَهُمْ وَيَقُولُونَ مَتَىٰ هُوَ ۖ قُلْ عَسَىٰٓ أَن يَكُونَ قَرِيبًۭا", 't': "«أو خلقا مما يكبر في صدوركم» يعظم عن قبول الحياة فضلا عن العظام والرفات فلا بد من إيجاد الروح فيكم «فسيقولون من يعيدنا» إلى الحياة «قل الذي فطركم» خلقكم «أول مرة» ولم تكونوا شيئا لأن القادر على البدء قادر على الإعادة بل هي أهون «فسينغضون» يحركون «إليك رءوسهم» تعجبا «ويقولون» استهزاء «متى هو» أي البعث «قل عسى أن يكون قريبا»."},
  {'n': '52', 'v': "يَوْمَ يَدْعُوكُمْ فَتَسْتَجِيبُونَ بِحَمْدِهِۦ وَتَظُنُّونَ إِن لَّبِثْتُمْ إِلَّا قَلِيلًۭا", 't': "«يوم يدعوكم» يناديكم من القبور على لسان إسرافيل «فتستجيبون» فتجيبون دعوته من القبور «بحمده» بأمره وقيل وله الحمد «وتظنون إن» ما «لبثتم» في الدنيا «إلا قليلا» لهول ما ترون."},
  {'n': '53', 'v': "وَقُل لِّعِبَادِى يَقُولُوا۟ ٱلَّتِى هِىَ أَحْسَنُ ۚ إِنَّ ٱلشَّيْطَٰنَ يَنزَغُ بَيْنَهُمْ ۚ إِنَّ ٱلشَّيْطَٰنَ كَانَ لِلْإِنسَٰنِ عَدُوًّۭا مُّبِينًۭا", 't': "«وقل لعبادي» المؤمنين «يقولوا» للكفار الكلمة «التي هي أحسن إن الشيطان ينزغ» يفسد «بينهم إن الشيطان كان للإنسان عدوا مبينا» بين العداوة والكلمة التي هي أحسن هي:"},
  {'n': '54', 'v': "رَّبُّكُمْ أَعْلَمُ بِكُمْ ۖ إِن يَشَأْ يَرْحَمْكُمْ أَوْ إِن يَشَأْ يُعَذِّبْكُمْ ۚ وَمَآ أَرْسَلْنَٰكَ عَلَيْهِمْ وَكِيلًۭا", 't': "«ربكم أعلم بكم إن يشأ يرحمكم» بالتوبة والإيمان «أو إن يشأ» تعذيبكم «يعذبكم» بالموت على الكفر «وما أرسلناك عليهم وكيلاً» فتجبرهم على الإيمان وهذا قبل الأمر بالقتال."},
  {'n': '55', 'v': "وَرَبُّكَ أَعْلَمُ بِمَن فِى ٱلسَّمَٰوَٰتِ وَٱلْأَرْضِ ۗ وَلَقَدْ فَضَّلْنَا بَعْضَ ٱلنَّبِيِّۦنَ عَلَىٰ بَعْضٍۢ ۖ وَءَاتَيْنَا دَاوُۥدَ زَبُورًۭا", 't': "«وربك أعلم بمن في السماوات والأرض» فيخصهم بما شاء على قدر أحوالهم «ولقد فضلنا بعض النبيين على بعض» بتخصيص كل منهم بفضيلة كموسى بالكلام وإبراهيم بالخلة ومحمد بالإسراء «وآتينا داود زبورا»."},
  {'n': '56', 'v': "قُلِ ٱدْعُوا۟ ٱلَّذِينَ زَعَمْتُم مِّن دُونِهِۦ فَلَا يَمْلِكُونَ كَشْفَ ٱلضُّرِّ عَنكُمْ وَلَا تَحْوِيلًا", 't': "«قل» لهم «ادعوا الذين زعمتم» أنهم آلهة «من دونه» كالملائكة وعيسى وعزير «فلا يملكون كشف الضر عنكم ولا تحويلا» له إلى غيركم."},
  {'n': '57', 'v': "أُو۟لَٰٓئِكَ ٱلَّذِينَ يَدْعُونَ يَبْتَغُونَ إِلَىٰ رَبِّهِمُ ٱلْوَسِيلَةَ أَيُّهُمْ أَقْرَبُ وَيَرْجُونَ رَحْمَتَهُۥ وَيَخَافُونَ عَذَابَهُۥٓ ۚ إِنَّ عَذَابَ رَبِّكَ كَانَ مَحْذُورًۭا", 't': "«أولئك الذين يدعونـ» ـهم آلهة «يبتغون» يطلبون «إلى ربهم الوسيلة» القربة بالطاعة «أيهم» بدل من واو يبتغون أي يبتغيها الذي هو «أقرب» إليه فكيف بغيره «ويرجون رحمته ويخافون عذابه» كغيرهم فكيف تدعونهم آلهة «إن عذاب ربك كان محذوراً»."},
  {'n': '58', 'v': "وَإِن مِّن قَرْيَةٍ إِلَّا نَحْنُ مُهْلِكُوهَا قَبْلَ يَوْمِ ٱلْقِيَٰمَةِ أَوْ مُعَذِّبُوهَا عَذَابًۭا شَدِيدًۭا ۚ كَانَ ذَٰلِكَ فِى ٱلْكِتَٰبِ مَسْطُورًۭا", 't': "«وإن» ما «من قرية» أريد أهلها «إلا نحن مهلكوها قبل يوم القيامة» بالموت «أو معذبوها عذابا شديدا» بالقتل وغيره «كان ذلك في الكتاب» اللوح المحفوظ «مسطورا» مكتوبا."},
  {'n': '59', 'v': "وَمَا مَنَعَنَآ أَن نُّرْسِلَ بِٱلْءَايَٰتِ إِلَّآ أَن كَذَّبَ بِهَا ٱلْأَوَّلُونَ ۚ وَءَاتَيْنَا ثَمُودَ ٱلنَّاقَةَ مُبْصِرَةًۭ فَظَلَمُوا۟ بِهَا ۚ وَمَا نُرْسِلُ بِٱلْءَايَٰتِ إِلَّا تَخْوِيفًۭا", 't': "«وما منعنا أن نرسل بالآيات» التي اقترحها أهل مكة «إلا أن كذب بها الأولون» لما أرسلناها فأهلكناهم ولو أرسلناها إلى هؤلاء لكذبوا بها واستحثوا الإهلاك وقد حكمنا بإمهالهم لإتمام أمر محمد صلى الله عليه وسلم «وآتينا ثمود الناقة» أي «مبصرة» بينة واضحة «فظلموا» كفروا «بها» فأهلكوا «وما نرسل بالآيات» المعجزات «إلا تخويفا» للعباد فيؤمنوا."},
  {'n': '60', 'v': "وَإِذْ قُلْنَا لَكَ إِنَّ رَبَّكَ أَحَاطَ بِٱلنَّاسِ ۚ وَمَا جَعَلْنَا ٱلرُّءْيَا ٱلَّتِىٓ أَرَيْنَٰكَ إِلَّا فِتْنَةًۭ لِّلنَّاسِ وَٱلشَّجَرَةَ ٱلْمَلْعُونَةَ فِى ٱلْقُرْءَانِ ۚ وَنُخَوِّفُهُمْ فَمَا يَزِيدُهُمْ إِلَّا طُغْيَٰنًۭا كَبِيرًۭا", 't': "«و» اذكر «إذ قلنا لك إن ربك أحاط بالناس» علما وقدرة فهم في قبضته فبلّغهم ولا تخف أحدا فهو يعصمك منهم «وما جعلنا الرؤيا التي أريناك» عيانا ليلة الإسراء «إلا فتنة للناس» أهل مكة إذ كذبوا بها وارتد بعضهم لما أخبرهم بها «والشجرة الملعونة في القرآن» هي الزقوم التي تنبت في أصل الجحيم جعلناها فتنة لهم إذ قالوا: النار تحرق الشجر فكيف تنبته «ونخوفهم» بها «فما يزيدهم» تخويفنا «إلا طغيانا كبيرا»."},
  {'n': '61', 'v': "وَإِذْ قُلْنَا لِلْمَلَٰٓئِكَةِ ٱسْجُدُوا۟ لِءَادَمَ فَسَجَدُوٓا۟ إِلَّآ إِبْلِيسَ قَالَ ءَأَسْجُدُ لِمَنْ خَلَقْتَ طِينًۭا", 't': "«و» اذكر «إذ قلنا للملائكة اسجدوا لآدم» سجود تحية بالانحناء «فسجدوا إلا إبليس قال أأسجد لمن خلقت طينا» نصب بنزع الخافض أي من طين."},
  {'n': '62', 'v': "قَالَ أَرَءَيْتَكَ هَٰذَا ٱلَّذِى كَرَّمْتَ عَلَىَّ لَئِنْ أَخَّرْتَنِ إِلَىٰ يَوْمِ ٱلْقِيَٰمَةِ لَأَحْتَنِكَنَّ ذُرِّيَّتَهُۥٓ إِلَّا قَلِيلًۭا", 't': "(قال أرأيتك) أي أخبرني (هذا الذي كرمت) فضلت (علي) بالأمر بالسجود له \"\" وأنا خير منه خلقتني من نار \"\" (لئن) لام قسم (أخرتن إلى يوم القيامة لأحتنكن) لأستأصلن (ذريته) بالإغواء (إلا قليلاً) منهم ممن عصمته."},
  {'n': '63', 'v': "قَالَ ٱذْهَبْ فَمَن تَبِعَكَ مِنْهُمْ فَإِنَّ جَهَنَّمَ جَزَآؤُكُمْ جَزَآءًۭ مَّوْفُورًۭا", 't': "«قال» تعالى له «اذهب» منظرا إلى وقت النفخة الأولى «فمن تبعك منهم فإن جهنم جزاؤكم» أنت وهم «جزاءً موفورا» وافرا كاملاً."},
  {'n': '64', 'v': "وَٱسْتَفْزِزْ مَنِ ٱسْتَطَعْتَ مِنْهُم بِصَوْتِكَ وَأَجْلِبْ عَلَيْهِم بِخَيْلِكَ وَرَجِلِكَ وَشَارِكْهُمْ فِى ٱلْأَمْوَٰلِ وَٱلْأَوْلَٰدِ وَعِدْهُمْ ۚ وَمَا يَعِدُهُمُ ٱلشَّيْطَٰنُ إِلَّا غُرُورًا", 't': "«واستفزز» استخف «من استطعت منهم بصوتك» بدعائك بالغناء والمزامير وكل داع إلى المعصية «وأجلب» صحْ «عليهم بخيلك ورجلك» وهم الركاب والمشاة في المعاصي «وشاركهم في الأموال» المحرمة كالربا والغصب «والأولاد» من الزنى «وعدهم» بأن لا بعث ولا جزاء «وما يعدهم الشيطان» بذلك «إلا غرورا» باطلاً."},
  {'n': '65', 'v': "إِنَّ عِبَادِى لَيْسَ لَكَ عَلَيْهِمْ سُلْطَٰنٌۭ ۚ وَكَفَىٰ بِرَبِّكَ وَكِيلًۭا", 't': "«إن عبادي» المؤمنين «ليس لك عليهم سلطان» تسلط وقوة «وكفى بربك وكيلا» حافظا لهم منك."},
  {'n': '66', 'v': "رَّبُّكُمُ ٱلَّذِى يُزْجِى لَكُمُ ٱلْفُلْكَ فِى ٱلْبَحْرِ لِتَبْتَغُوا۟ مِن فَضْلِهِۦٓ ۚ إِنَّهُۥ كَانَ بِكُمْ رَحِيمًۭا", 't': "«ربكم الذي يزجي» يجري «لكم الفلك» السفن «في البحر لتبتغوا» تطلبوا «من فضله» تعالى بالتجارة «إنه كان بكم رحيما» في تسخيرها لكم."},
  {'n': '67', 'v': "وَإِذَا مَسَّكُمُ ٱلضُّرُّ فِى ٱلْبَحْرِ ضَلَّ مَن تَدْعُونَ إِلَّآ إِيَّاهُ ۖ فَلَمَّا نَجَّىٰكُمْ إِلَى ٱلْبَرِّ أَعْرَضْتُمْ ۚ وَكَانَ ٱلْإِنسَٰنُ كَفُورًا", 't': "«وإذا مسكم الضر» الشدة «في البحر» خوف الغرق «ضل» غاب عنكم «من تدعون» تعبدون من الآلهة فلا تدعونه «إلا إياه» تعالى فإنكم تدعونه وحده لأنكم في شدة لا يكشفها إلا هو «فلما نجاكم» من الغرق وأوصلكم «إلى البر أعرضتم» عن التوحيد «وكان الإنسان كفورا» جحودا للنعم."},
  {'n': '68', 'v': "أَفَأَمِنتُمْ أَن يَخْسِفَ بِكُمْ جَانِبَ ٱلْبَرِّ أَوْ يُرْسِلَ عَلَيْكُمْ حَاصِبًۭا ثُمَّ لَا تَجِدُوا۟ لَكُمْ وَكِيلًا", 't': "«أفأمنتم أن يخسف بكم جانب البر» أي الأرض كقارون «أو يرسل عليكم حاصبا» أي يرميكم بالحصباء كقوم لوط «ثم لا تجدوا لكم وكيلاً» حافظا منه."},
  {'n': '69', 'v': "أَمْ أَمِنتُمْ أَن يُعِيدَكُمْ فِيهِ تَارَةً أُخْرَىٰ فَيُرْسِلَ عَلَيْكُمْ قَاصِفًۭا مِّنَ ٱلرِّيحِ فَيُغْرِقَكُم بِمَا كَفَرْتُمْ ۙ ثُمَّ لَا تَجِدُوا۟ لَكُمْ عَلَيْنَا بِهِۦ تَبِيعًۭا", 't': "«أم أمنتم أن نعيدكم فيه» أي البحر «تارة» مرة «أخرى فنرسل عليكم قاصفا من الريح» أي ريحا شديدة لا تمر بشيء إلا قصفته فتكسر فلككم «فتغرقكم بما كفرتم» بكفركم «ثم لا تجدوا لكم علينا به تبيعا» ناصرا وتابعا يطالبنا بما فعلنا بكم."},
  {'n': '70', 'v': "۞ وَلَقَدْ كَرَّمْنَا بَنِىٓ ءَادَمَ وَحَمَلْنَٰهُمْ فِى ٱلْبَرِّ وَٱلْبَحْرِ وَرَزَقْنَٰهُم مِّنَ ٱلطَّيِّبَٰتِ وَفَضَّلْنَٰهُمْ عَلَىٰ كَثِيرٍۢ مِّمَّنْ خَلَقْنَا تَفْضِيلًۭا", 't': "«ولقد كرمنا» فضلنا «بني آدم» بالعلم والنطق واعتدال الخلق وغير ذلك ومنه طهارتهم بعد الموت «وحملناهم في البر» على الدواب «والبحر» على السفن «ورزقناهم من الطيبات وفضلناهم على كثير ممن خلقنا» كالبهائم والوحوش «تفضيلاً» فمن بمعنى ما أو على بابها وتشمل الملائكة والمراد تفضيل الجنس، ولا يلزم تفضيل أفراده إذ هم أفضل من البشر غير الأنبياء."},
  {'n': '71', 'v': "يَوْمَ نَدْعُوا۟ كُلَّ أُنَاسٍۭ بِإِمَٰمِهِمْ ۖ فَمَنْ أُوتِىَ كِتَٰبَهُۥ بِيَمِينِهِۦ فَأُو۟لَٰٓئِكَ يَقْرَءُونَ كِتَٰبَهُمْ وَلَا يُظْلَمُونَ فَتِيلًۭا", 't': "اذكر «يوم ندعو كل أناس بإمامهم» نبيهم فيقال يا أمة فلان أو بكتاب أعمالهم فيقال يا صاحب الشر وهو يوم القيامة «فمن أوتي» منهم «كتابه بيمينه» وهم السعداء أولو البصائر في الدنيا «فأولئك يقرءُون كتابهم ولا يُظلمون» ينقصون من أعمالهم «فتيلاً» قدر قشرة النواة."},
  {'n': '72', 'v': "وَمَن كَانَ فِى هَٰذِهِۦٓ أَعْمَىٰ فَهُوَ فِى ٱلْءَاخِرَةِ أَعْمَىٰ وَأَضَلُّ سَبِيلًۭا", 't': "«ومن كان في هذه» أي الدنيا «أعمى» عن الحق «فهو في الآخرة أعمى» عن طريق النجاة وقراءة القرآن «وأضل سبيلاً» أبعد طريقا عنه. ونزل في ثقيف وقد سألوا صلى الله عليه وسلم أن يحرم واديهم وألحوا عليه."},
  {'n': '73', 'v': "وَإِن كَادُوا۟ لَيَفْتِنُونَكَ عَنِ ٱلَّذِىٓ أَوْحَيْنَآ إِلَيْكَ لِتَفْتَرِىَ عَلَيْنَا غَيْرَهُۥ ۖ وَإِذًۭا لَّٱتَّخَذُوكَ خَلِيلًۭا", 't': "«وإن» مخففة «كادوا» قاربوا «ليفتنونك» ليستنزلون «عن الذي أوحينا إليك لتفتري علينا غيره وإذا» لو فعلت ذلك «لاتخذوك خليلاً»."},
  {'n': '74', 'v': "وَلَوْلَآ أَن ثَبَّتْنَٰكَ لَقَدْ كِدتَّ تَرْكَنُ إِلَيْهِمْ شَيْـًۭٔا قَلِيلًا", 't': "«ولولا أن ثبتناك» على الحق بالعصمة «لقد كدت» قاربت «تركن» تميل «إليهم شيئا» ركونا «قليلاً» لشدة احتيالهم وإلحاحهم، وهو صريح في أنه صلى الله عليه وسلم لم يركن ولا قارب."},
  {'n': '75', 'v': "إِذًۭا لَّأَذَقْنَٰكَ ضِعْفَ ٱلْحَيَوٰةِ وَضِعْفَ ٱلْمَمَاتِ ثُمَّ لَا تَجِدُ لَكَ عَلَيْنَا نَصِيرًۭا", 't': "«إذاً» لو ركنت «لأذقناك ضعف» عذاب «الحياة وضعف» عذاب «الممات» أي مثلي ما يعذب غيرك في الدنيا والآخرة «ثم لا تجد لك علينا نصيرا» مانعا منه."},
  {'n': '76', 'v': "وَإِن كَادُوا۟ لَيَسْتَفِزُّونَكَ مِنَ ٱلْأَرْضِ لِيُخْرِجُوكَ مِنْهَا ۖ وَإِذًۭا لَّا يَلْبَثُونَ خِلَٰفَكَ إِلَّا قَلِيلًۭا", 't': "ونزل لما قال له اليهود: إن كنت نبيا فالحق بالشام فإنها أرض الأنبياء «وإن» مخففة «كادوا ليستفزونك من الأرض» أرض المدينة «ليخرجوك منها وإذا» لو أخرجوك «لا يلبثون خلافك» فيها «إلا قليلاً» ثم يهلكون."},
  {'n': '77', 'v': "سُنَّةَ مَن قَدْ أَرْسَلْنَا قَبْلَكَ مِن رُّسُلِنَا ۖ وَلَا تَجِدُ لِسُنَّتِنَا تَحْوِيلًا", 't': "«سنّة من قد أرسلنا قبلك من رسلنا» أي كسنتنا فيهم من إهلاك من أخرجهم «ولا تجد لسنتنا تحويلاً» تبديلاً."},
  {'n': '78', 'v': "أَقِمِ ٱلصَّلَوٰةَ لِدُلُوكِ ٱلشَّمْسِ إِلَىٰ غَسَقِ ٱلَّيْلِ وَقُرْءَانَ ٱلْفَجْرِ ۖ إِنَّ قُرْءَانَ ٱلْفَجْرِ كَانَ مَشْهُودًۭا", 't': "«أقم الصلاة لدلوك الشمس» أي من وقت زوالها «إلى غسق الليل» إقبال ظلمته أي الظهر والعصر والمغرب والعشاء «وقرآن الفجر» صلاة الصبح «إن قرآن الفجر كان مشهودا» تشهده ملائكة الليل وملائكة النهار."},
  {'n': '79', 'v': "وَمِنَ ٱلَّيْلِ فَتَهَجَّدْ بِهِۦ نَافِلَةًۭ لَّكَ عَسَىٰٓ أَن يَبْعَثَكَ رَبُّكَ مَقَامًۭا مَّحْمُودًۭا", 't': "«ومن الليل فتهجد» فصلِّ «به» بالقرآن «نافلة لك» فريضة زائدة لك دون أمتك أو فضيلة على الصلوات المفروضة «عسى أن يبعثك» يقيمك «ربك» في الآخرة «مقاما محمودا» يحمدك فيه الأولون والآخرون وهو مقام الشفاعة في فصل القضاء، ونزل لما أمر بالهجرة."},
  {'n': '80', 'v': "وَقُل رَّبِّ أَدْخِلْنِى مُدْخَلَ صِدْقٍۢ وَأَخْرِجْنِى مُخْرَجَ صِدْقٍۢ وَٱجْعَل لِّى مِن لَّدُنكَ سُلْطَٰنًۭا نَّصِيرًۭا", 't': "«وقل ربِّ أدخلني» المدينة «مُدخل صدق» إدخالاً مرضيا لا أرى فيه ما أكره «وأخرجني» من مكة «مُخرج صدق» إخراجا لا ألتفت بقلبي إليها «واجعل لي من لدنك سلطانا نصيرا» قوة تنصرني بها على أعدائك."},
  {'n': '81', 'v': "وَقُلْ جَآءَ ٱلْحَقُّ وَزَهَقَ ٱلْبَٰطِلُ ۚ إِنَّ ٱلْبَٰطِلَ كَانَ زَهُوقًۭا", 't': "(وقل) عند دخولك مكة (جاء الحق) الإسلام (وزهق الباطل) بطل الكفر (إن الباطل كان زهوقا) مضمحلاً زائلاً \"\" وقد دخلها صلى الله عليه وسلم وحول البيت ثلاثمائة وستون صنما فجعل يطعنها بعود في يده ويقول ذلك حتى سقطت \"\" رواه الشيخان."},
  {'n': '82', 'v': "وَنُنَزِّلُ مِنَ ٱلْقُرْءَانِ مَا هُوَ شِفَآءٌۭ وَرَحْمَةٌۭ لِّلْمُؤْمِنِينَ ۙ وَلَا يَزِيدُ ٱلظَّٰلِمِينَ إِلَّا خَسَارًۭا", 't': "«وننزل من» للبيان «القرآن ما هو شفاء» من الضلالة «ورحمة للمؤمنين» به «ولا يزيد الظالمين» الكافرين «إلا خسارا» لكفرهم به."},
  {'n': '83', 'v': "وَإِذَآ أَنْعَمْنَا عَلَى ٱلْإِنسَٰنِ أَعْرَضَ وَنَـَٔا بِجَانِبِهِۦ ۖ وَإِذَا مَسَّهُ ٱلشَّرُّ كَانَ يَـُٔوسًۭا", 't': "«وإذا أنعمنا على الإنسان» الكافر «أعرض» عن الشكر «ونأى بجانبه» ثنى عطفه متبخترا «وإذا مسه الشر» الفقر والشدة «كان يؤوسا» قنوطا من رحمة الله."},
  {'n': '84', 'v': "قُلْ كُلٌّۭ يَعْمَلُ عَلَىٰ شَاكِلَتِهِۦ فَرَبُّكُمْ أَعْلَمُ بِمَنْ هُوَ أَهْدَىٰ سَبِيلًۭا", 't': "«قل كل» منا ومنكم «يعمل على شاكلته» طريقته «فربكم أعلم بمن هو أهدى سبيلاً» طريقا فيثيبه."},
  {'n': '85', 'v': "وَيَسْـَٔلُونَكَ عَنِ ٱلرُّوحِ ۖ قُلِ ٱلرُّوحُ مِنْ أَمْرِ رَبِّى وَمَآ أُوتِيتُم مِّنَ ٱلْعِلْمِ إِلَّا قَلِيلًۭا", 't': "«ويسألونك» أي اليهود «عن الروح» الذي يحيا به البدن «قل» لهم «الروح من أمر ربي» أي علمه لا تعلمونه «وما أويتم من العلم إلا قليلاً» بالنسبة إلى علمه تعالى."},
  {'n': '86', 'v': "وَلَئِن شِئْنَا لَنَذْهَبَنَّ بِٱلَّذِىٓ أَوْحَيْنَآ إِلَيْكَ ثُمَّ لَا تَجِدُ لَكَ بِهِۦ عَلَيْنَا وَكِيلًا", 't': "«ولئن» لام قسم «شئنا لنذهبن بالذي أوحينا إليك» أي القرآن بأن نمحوه من الصدور والمصاحف «ثم لا تجد لك به علينا وكيلاً»."},
  {'n': '87', 'v': "إِلَّا رَحْمَةًۭ مِّن رَّبِّكَ ۚ إِنَّ فَضْلَهُۥ كَانَ عَلَيْكَ كَبِيرًۭا", 't': "«إلا» لكن أبقيناه «رحمة من ربك إن فضله كان عليك كبيرا» عظيما حيث أنزله عليك وأعطاك المقام المحمود وغير ذلك من الفضائل."},
  {'n': '88', 'v': "قُل لَّئِنِ ٱجْتَمَعَتِ ٱلْإِنسُ وَٱلْجِنُّ عَلَىٰٓ أَن يَأْتُوا۟ بِمِثْلِ هَٰذَا ٱلْقُرْءَانِ لَا يَأْتُونَ بِمِثْلِهِۦ وَلَوْ كَانَ بَعْضُهُمْ لِبَعْضٍۢ ظَهِيرًۭا", 't': "(قل لئن اجتمعت الإنس والجن على أن يأتوا بمثل هذا القرآن) في الفصاحة والبلاغة. (لا يأتون بمثله ولو كان بعضهم لبعض ظهيرا) معينا نزل ردا لقولهم \"\" ولو نشاء لقلنا مثل هذا \"\"."},
  {'n': '89', 'v': "وَلَقَدْ صَرَّفْنَا لِلنَّاسِ فِى هَٰذَا ٱلْقُرْءَانِ مِن كُلِّ مَثَلٍۢ فَأَبَىٰٓ أَكْثَرُ ٱلنَّاسِ إِلَّا كُفُورًۭا", 't': "«ولقد صرفنا» بينا «للناس في هذا القرآن من كل مثل» صفة لمحذوف أي مثلاً من جنس كل مثل ليتعظوا «فأبى أكثر الناس» أي أهل مكة «إلا كفورا» جحودا للحق."},
  {'n': '90', 'v': "وَقَالُوا۟ لَن نُّؤْمِنَ لَكَ حَتَّىٰ تَفْجُرَ لَنَا مِنَ ٱلْأَرْضِ يَنۢبُوعًا", 't': "«وقالوا» عطف على أبى «لن نؤمن لك حتى تفجر لنا من الأرض ينبوعا» عينا ينبع منها الماء."},
  {'n': '91', 'v': "أَوْ تَكُونَ لَكَ جَنَّةٌۭ مِّن نَّخِيلٍۢ وَعِنَبٍۢ فَتُفَجِّرَ ٱلْأَنْهَٰرَ خِلَٰلَهَا تَفْجِيرًا", 't': "«أو تكون لك جنة» بستان «من نخيل وعنب فتفجر الأنهار خلالها» وسطها «تفجيرا»."},
  {'n': '92', 'v': "أَوْ تُسْقِطَ ٱلسَّمَآءَ كَمَا زَعَمْتَ عَلَيْنَا كِسَفًا أَوْ تَأْتِىَ بِٱللَّهِ وَٱلْمَلَٰٓئِكَةِ قَبِيلًا", 't': "«أو تسقط السماء كما زعمت علينا كسفا» قطعا «أو تأتي بالله والملائكة قبيلاً» مقابلة وعيانا فنراهم."},
  {'n': '93', 'v': "أَوْ يَكُونَ لَكَ بَيْتٌۭ مِّن زُخْرُفٍ أَوْ تَرْقَىٰ فِى ٱلسَّمَآءِ وَلَن نُّؤْمِنَ لِرُقِيِّكَ حَتَّىٰ تُنَزِّلَ عَلَيْنَا كِتَٰبًۭا نَّقْرَؤُهُۥ ۗ قُلْ سُبْحَانَ رَبِّى هَلْ كُنتُ إِلَّا بَشَرًۭا رَّسُولًۭا", 't': "«أو يكون لك بيت من زخرف» ذهب «أو ترقى» تصعد «في السماء» بسُلَّم «ولن نؤمن لرقيك» لو رقيت فيها «حتى تنزل علينا» منها «كتابا» فيه تصديقك «نقرؤه قل» لهم «سبحان ربي» تعجب «هل» ما «كنت إلا بشرا رسولاً» كسائر الرسل ولم يكونوا يأتون بآية إلا بإذن الله."},
  {'n': '94', 'v': "وَمَا مَنَعَ ٱلنَّاسَ أَن يُؤْمِنُوٓا۟ إِذْ جَآءَهُمُ ٱلْهُدَىٰٓ إِلَّآ أَن قَالُوٓا۟ أَبَعَثَ ٱللَّهُ بَشَرًۭا رَّسُولًۭا", 't': "«وما منع الناس أن يؤمنوا إذ جاءهم الهدى إلا أن قالوا» أي قولهم منكرين «أبعث الله بشرا رسولاً» ولم يبعث ملكا."},
  {'n': '95', 'v': "قُل لَّوْ كَانَ فِى ٱلْأَرْضِ مَلَٰٓئِكَةٌۭ يَمْشُونَ مُطْمَئِنِّينَ لَنَزَّلْنَا عَلَيْهِم مِّنَ ٱلسَّمَآءِ مَلَكًۭا رَّسُولًۭا", 't': "«قل» لهم «لو كان في الأرض» بدل البشر «ملائكة يمشون مطمئنين لنزّلنا عليهم من السماء ملكا رسولاً» إذ لا يرسل إلى قوم رسول إلا من جنسهم ليمكنهم مخاطبته والفهم عنه."},
  {'n': '96', 'v': "قُلْ كَفَىٰ بِٱللَّهِ شَهِيدًۢا بَيْنِى وَبَيْنَكُمْ ۚ إِنَّهُۥ كَانَ بِعِبَادِهِۦ خَبِيرًۢا بَصِيرًۭا", 't': "«قل كفى بالله شهيدا بيني وبينكم» على صدقي «إنه كان بعباده خبيرا بصيرا» عالما ببواطنهم وظواهرهم."},
