  {'n': '16', 'v': "فَلَا يَصُدَّنَّكَ عَنْهَا مَن لَّا يُؤْمِنُ بِهَا وَٱتَّبَعَ هَوَىٰهُ فَتَرْدَىٰ", 't': "«فلا يَصُدنَّكَ» يصرفنَّك «عنها» أي عن الإيمان بها «من لا يؤمن بها واتبع هواه» في إنكارها «فَتَردى» أي فتهلك إن صددت عنها."},
  {'n': '17', 'v': "وَمَا تِلْكَ بِيَمِينِكَ يَٰمُوسَىٰ", 't': "«وما تلك» كائنة «بيمينك يا موسى» الاستفهام للتقرير ليرتب عليه المعجزة فيها."},
  {'n': '18', 'v': "قَالَ هِىَ عَصَاىَ أَتَوَكَّؤُا۟ عَلَيْهَا وَأَهُشُّ بِهَا عَلَىٰ غَنَمِى وَلِىَ فِيهَا مَـَٔارِبُ أُخْرَىٰ", 't': "«قال هي عصاي أتوكَّأ» أعتمد «عليها» عند الوثوب والمشي «وأهش» أخبط ورق الشجر «بها» ليسقط «على غنمي» فتأكله «ولي فيها مآرب» جمع مأربة مثلث الراء أي: حوائج «أخرى» كحمل الزاد والسقاء وطرد الهوام زاد في الجواب بيان حاجاته بها."},
  {'n': '19', 'v': "قَالَ أَلْقِهَا يَٰمُوسَىٰ", 't': "«قال ألقها يا موسى»."},
  {'n': '20', 'v': "فَأَلْقَىٰهَا فَإِذَا هِىَ حَيَّةٌۭ تَسْعَىٰ", 't': "«فألقاها فإذا هي حية» ثعبان عظيم «تسعى» تمشي على بطنها سريعا كسرعة الثعبان الصغير المسمى بالجان المعبر به فيها في آية أخرى."},
  {'n': '21', 'v': "قَالَ خُذْهَا وَلَا تَخَفْ ۖ سَنُعِيدُهَا سِيرَتَهَا ٱلْأُولَىٰ", 't': "«قال خذها ولا تخف» منها «سنعيدها سيرتها» منصوب بنزع الخافض أي: إلى حالتها «الأولى» فأدخل يده في فمها فعادت عصا، فتبين أن موضع الإدخال موضع مسكها بين شعبتيها، وأي ذلك السيد موسى لئلا يجزع إذا انقلبت حية لدى فرعون."},
  {'n': '22', 'v': "وَٱضْمُمْ يَدَكَ إِلَىٰ جَنَاحِكَ تَخْرُجْ بَيْضَآءَ مِنْ غَيْرِ سُوٓءٍ ءَايَةً أُخْرَىٰ", 't': "«واضمم يدك» اليمنى بمعنى الكف «إلى جناحك» أي جنبك الأيسر تحت العضد إلى الإبط وأخرجها «تخرج» خلاف ما كانت عليه من الأدمة «بيضاء من غير سوءٍ» أي بَرَص تضيء كشعاع الشمس تغشى البصر «آية أخرى» وهي بيضاء حالان من ضمير تخرج."},
  {'n': '23', 'v': "لِنُرِيَكَ مِنْ ءَايَٰتِنَا ٱلْكُبْرَى", 't': "«لنريك» بها إذا فعلت ذلك لإظهارها «من آياتنا» الآية «الكبرى» أي العظمى على رسالتك، وإذا أراد عودها إلى حالتها الأولى ضمها إلى جناحه كما تقدم وأخرجها."},
  {'n': '24', 'v': "ٱذْهَبْ إِلَىٰ فِرْعَوْنَ إِنَّهُۥ طَغَىٰ", 't': "«اذهب» رسولا «إلى فرعون» ومن معه «إنه طغى» جاوز الحد في كفره إلى ادعاء الإلهية."},
  {'n': '25', 'v': "قَالَ رَبِّ ٱشْرَحْ لِى صَدْرِى", 't': "«قال رب اشرح لي صدري» وسّعه لتحمل الرسالة."},
  {'n': '26', 'v': "وَيَسِّرْ لِىٓ أَمْرِى", 't': "«ويسِّر» سَهِّلْ «لي أمري» لأبلغها."},
  {'n': '27', 'v': "وَٱحْلُلْ عُقْدَةًۭ مِّن لِّسَانِى", 't': "«واحلل عقدة من لساني» حدثت من احتراقه بجمرة وضعها بفيه وهو صغير."},
  {'n': '28', 'v': "يَفْقَهُوا۟ قَوْلِى", 't': "«يفقهوا» يفهموا «قولي» عند تبليغ الرسالة."},
  {'n': '29', 'v': "وَٱجْعَل لِّى وَزِيرًۭا مِّنْ أَهْلِى", 't': "«واجعل لي وزيرا» معينا عليها «من أهلي»."},
  {'n': '30', 'v': "هَٰرُونَ أَخِى", 't': "«هارون» مفعول ثان «أخي» عطف بيان."},
  {'n': '31', 'v': "ٱشْدُدْ بِهِۦٓ أَزْرِى", 't': "«اشدد به أزري» ظهري."},
  {'n': '32', 'v': "وَأَشْرِكْهُ فِىٓ أَمْرِى", 't': "«وأشركه في أمري» أي الرسالة والفعلان بصيغتي الأمر والمضارع المجزوم وهو جواب الطلب."},
  {'n': '33', 'v': "كَىْ نُسَبِّحَكَ كَثِيرًۭا", 't': "«كي نسبحك» تسبيحا «كثيرا»."},
  {'n': '34', 'v': "وَنَذْكُرَكَ كَثِيرًا", 't': "«ونذكرك» ذكرا «كثيرا»."},
  {'n': '35', 'v': "إِنَّكَ كُنتَ بِنَا بَصِيرًۭا", 't': "«إنك كنت بصيرا» عالما فأنعمت بالرسالة."},
  {'n': '36', 'v': "قَالَ قَدْ أُوتِيتَ سُؤْلَكَ يَٰمُوسَىٰ", 't': "«قال قد أوتيت سُؤلك يا موسى» منا عليك."},
  {'n': '37', 'v': "وَلَقَدْ مَنَنَّا عَلَيْكَ مَرَّةً أُخْرَىٰٓ", 't': "«ولقد مننا عليك مرة أخرى»."},
  {'n': '38', 'v': "إِذْ أَوْحَيْنَآ إِلَىٰٓ أُمِّكَ مَا يُوحَىٰٓ", 't': "«إذ» للتعليل «أوحينا إلى أمك» مناما أو إلهاما لما ولدتك وخافت أن يقتلك فرعون في جملة من يولد «ما يوحى» في أمرك ويبدل منه:"},
  {'n': '39', 'v': "أَنِ ٱقْذِفِيهِ فِى ٱلتَّابُوتِ فَٱقْذِفِيهِ فِى ٱلْيَمِّ فَلْيُلْقِهِ ٱلْيَمُّ بِٱلسَّاحِلِ يَأْخُذْهُ عَدُوٌّۭ لِّى وَعَدُوٌّۭ لَّهُۥ ۚ وَأَلْقَيْتُ عَلَيْكَ مَحَبَّةًۭ مِّنِّى وَلِتُصْنَعَ عَلَىٰ عَيْنِىٓ", 't': "«أن اقذفيه» ألقيه «في التابوت فاقذفيه» بالتابوت «في اليم» بحر النيل «فلْيُلقه اليم بالساحل» أي شاطئه والأمر بمعنى الخبر «يأخذه عدو لي وعدو له» وهو فرعون «وألقيت» بعد أن أخذك «عليك محبة مني» لتحب في الناس فأحبك فرعون وكل من رآك «ولتُصنع على عيني» تربى على رعايتي وحفظي لك."},
  {'n': '40', 'v': "إِذْ تَمْشِىٓ أُخْتُكَ فَتَقُولُ هَلْ أَدُلُّكُمْ عَلَىٰ مَن يَكْفُلُهُۥ ۖ فَرَجَعْنَٰكَ إِلَىٰٓ أُمِّكَ كَىْ تَقَرَّ عَيْنُهَا وَلَا تَحْزَنَ ۚ وَقَتَلْتَ نَفْسًۭا فَنَجَّيْنَٰكَ مِنَ ٱلْغَمِّ وَفَتَنَّٰكَ فُتُونًۭا ۚ فَلَبِثْتَ سِنِينَ فِىٓ أَهْلِ مَدْيَنَ ثُمَّ جِئْتَ عَلَىٰ قَدَرٍۢ يَٰمُوسَىٰ", 't': "«إذ» للتعليل «تمشي أختك» مريم لتتعرف من خبرك وقد أحضروا مراضع وأنت لا تقبل ثدي واحدة منهن «فتقول هل أدلكم على من يكفله» فأجيبت فجاءت بأمه فقبل ثديها «فرجعناك إلى أمك كي تقر عينها» بلقائك «ولا تحزن» حينئذ «وقتلت نفسا» هو القبطي بمصر، فاغتممت لقتله من جهة فرعون «فنجيناك من الغم وفتناك فتونا» اختبرناك بالإيقاع في غير ذلك وخلصناك منه «فلبثت سنين» عشرا «في أهل مدين» بعد مجيئك إليها من مصر عند شعيب النبي وتزوجك بابنته «ثم جئت على قدر» في علمي بالرسالة وهو أربعون سنة من عمرك «يا موسى»."},
  {'n': '41', 'v': "وَٱصْطَنَعْتُكَ لِنَفْسِى", 't': "«واصطنعتك» اخترتك «لنفسي» بالرسالة."},
  {'n': '42', 'v': "ٱذْهَبْ أَنتَ وَأَخُوكَ بِـَٔايَٰتِى وَلَا تَنِيَا فِى ذِكْرِى", 't': "«اذهب أنت وأخوك» إلى الناس «بآياتي» التسع «ولا تَنِيا» تفترا «في ذكري» بتسبيح وغيره."},
  {'n': '43', 'v': "ٱذْهَبَآ إِلَىٰ فِرْعَوْنَ إِنَّهُۥ طَغَىٰ", 't': "«اذهبا إلى فرعون إنه طغى» بادعائه الربوبية."},
  {'n': '44', 'v': "فَقُولَا لَهُۥ قَوْلًۭا لَّيِّنًۭا لَّعَلَّهُۥ يَتَذَكَّرُ أَوْ يَخْشَىٰ", 't': "«فقولا له قولا لينا» في رجوعه عن ذلك «لعله يتذكر» يتعظ «أو يخشى» الله فيرجع والترجي بالنسبة إليهما لعلمه تعالى بأنه لا يرجع."},
  {'n': '45', 'v': "قَالَا رَبَّنَآ إِنَّنَا نَخَافُ أَن يَفْرُطَ عَلَيْنَآ أَوْ أَن يَطْغَىٰ", 't': "«قالا ربنا إننا نخاف أن يفرط علينا» أي يعجل بالعقوبة «أو أن يطغى» علينا أي يتكبر."},
  {'n': '46', 'v': "قَالَ لَا تَخَافَآ ۖ إِنَّنِى مَعَكُمَآ أَسْمَعُ وَأَرَىٰ", 't': "«قال لا تخافا إنني معكما» بعوني «أسمع» ما يقول «وأرى» ما يفعل."},
  {'n': '47', 'v': "فَأْتِيَاهُ فَقُولَآ إِنَّا رَسُولَا رَبِّكَ فَأَرْسِلْ مَعَنَا بَنِىٓ إِسْرَٰٓءِيلَ وَلَا تُعَذِّبْهُمْ ۖ قَدْ جِئْنَٰكَ بِـَٔايَةٍۢ مِّن رَّبِّكَ ۖ وَٱلسَّلَٰمُ عَلَىٰ مَنِ ٱتَّبَعَ ٱلْهُدَىٰٓ", 't': "«فأتياه فقولا إنَّا رسولا ربك فأرسل معنا بني إسرائيل» إلى الشام «ولا تعذبهم» أي خل عنهم من استعمالك إياهم في أشغالك الشاقة كالحفر والبناء وحمل الثقيل «قد جئناك بآية» بحجة «من ربك» على صدقنا بالرسالة «والسلام على من اتبع الهدى» أي السلامة له من العذاب."},
  {'n': '48', 'v': "إِنَّا قَدْ أُوحِىَ إِلَيْنَآ أَنَّ ٱلْعَذَابَ عَلَىٰ مَن كَذَّبَ وَتَوَلَّىٰ", 't': "«إنا قد أوحي إلينا أن العذاب على مَن كذب» ما جئنا له «وتولى» أعرض عنه، فأتياه وقالا جميع ما ذكر."},
  {'n': '49', 'v': "قَالَ فَمَن رَّبُّكُمَا يَٰمُوسَىٰ", 't': "«قال فمن ربكما يا موسى» اقتصر عليه لأنه الأصل ولإدلاله عليه بالتربية."},
  {'n': '50', 'v': "قَالَ رَبُّنَا ٱلَّذِىٓ أَعْطَىٰ كُلَّ شَىْءٍ خَلْقَهُۥ ثُمَّ هَدَىٰ", 't': "«قال ربنا الذي أعطى كل شيء» من الخلق «خلقه» الذي هو عليه متميز به عن غيره «ثم هدى» الحيوان منه إلى مطعمه ومشربه ومنكحه وغير ذلك."},
  {'n': '51', 'v': "قَالَ فَمَا بَالُ ٱلْقُرُونِ ٱلْأُولَىٰ", 't': "«قال» فرعون «فما بال» حال «القرون» الأمم «الأولى» كقوم نوح وهود ولوط وصالح في عبادتهم الأوثان."},
  {'n': '52', 'v': "قَالَ عِلْمُهَا عِندَ رَبِّى فِى كِتَٰبٍۢ ۖ لَّا يَضِلُّ رَبِّى وَلَا يَنسَى", 't': "«قال» موسى «علمها» أي علم حالهم محفوظ «عند ربي في كتاب» هو اللوح المحفوظ يجازيهم عليها يوم القيامة «لا يضل» يغيب «ربي» عن شيء «ولا ينسى» ربي شيئا."},
  {'n': '53', 'v': "ٱلَّذِى جَعَلَ لَكُمُ ٱلْأَرْضَ مَهْدًۭا وَسَلَكَ لَكُمْ فِيهَا سُبُلًۭا وَأَنزَلَ مِنَ ٱلسَّمَآءِ مَآءًۭ فَأَخْرَجْنَا بِهِۦٓ أَزْوَٰجًۭا مِّن نَّبَاتٍۢ شَتَّىٰ", 't': "هو «الذي جعل لكم» في جملة الخلق «الأرض مهادا» فراشا «وسلك» سهل «لكم فيها سبلا» طرقا «وأنزل من السماء ماءً» مطرا قال تعالى تتميما لما وصفه به موسى وخطابا لأهل مكة «فأخرجنا به أزواجا» أصنافا «من نبات شتى» صفة أزواجا أي مختلفة الألوان والطعوم وغيرهما، وشتى جمع شتيت كمريض ومرضى، من شت الأمر تفرق."},
  {'n': '54', 'v': "كُلُوا۟ وَٱرْعَوْا۟ أَنْعَٰمَكُمْ ۗ إِنَّ فِى ذَٰلِكَ لَءَايَٰتٍۢ لِّأُو۟لِى ٱلنُّهَىٰ", 't': "«كلوا» منها «وارعوا أنعامكم» فيها جمع نعم، وهي الإبل والبقر والغنم، يقال رعت الأنعام ورعيتها والأمر للإباحة وتذكير النعمة والجملة حال من ضمير أخرجنا، أي مبيحين لكم الأكل ورعي الأنعام «إن في ذلك» المذكور «لآيات» لعبرا «لأولي النهى» لأصحاب العقول ينهى صاحبه عن ارتكاب القبائح."},
  {'n': '55', 'v': "۞ مِنْهَا خَلَقْنَٰكُمْ وَفِيهَا نُعِيدُكُمْ وَمِنْهَا نُخْرِجُكُمْ تَارَةً أُخْرَىٰ", 't': "«منها» أي من الأرض «خلقناكم» بخلق أبيكم آدم منها «وفيها نعيدكم» مقبورين بعد الموت «ومنها نخرجكم» عند البعث «تارة» مرة «أخرى» كما أخرجناكم عند ابتداء خلقكم."},
  {'n': '56', 'v': "وَلَقَدْ أَرَيْنَٰهُ ءَايَٰتِنَا كُلَّهَا فَكَذَّبَ وَأَبَىٰ", 't': "«ولقد أريناه» أي أبصرنا فرعون «آياتنا كلها» التسع «فكذب» بها وزعم أنها سحر «وأبى» أن يوحد الله تعالى."},
  {'n': '57', 'v': "قَالَ أَجِئْتَنَا لِتُخْرِجَنَا مِنْ أَرْضِنَا بِسِحْرِكَ يَٰمُوسَىٰ", 't': "«قال أجئتنا لتخرجنا من أرضنا» مصر ويكون لك فيها «بسحرك يا موسى»."},
  {'n': '58', 'v': "فَلَنَأْتِيَنَّكَ بِسِحْرٍۢ مِّثْلِهِۦ فَٱجْعَلْ بَيْنَنَا وَبَيْنَكَ مَوْعِدًۭا لَّا نُخْلِفُهُۥ نَحْنُ وَلَآ أَنتَ مَكَانًۭا سُوًۭى", 't': "«فلنأتينك بسحر مثله» يعارضه «فاجعل بيننا وبينك موعدا» لذلك «لا نخلفه نحن ولا أنت مكانا» منصوب بنزع الخافض في «سِوى» بكسر أوله وضمه أي وسطا تستوي مسافة الجائي إليه من الطرفين."},
  {'n': '59', 'v': "قَالَ مَوْعِدُكُمْ يَوْمُ ٱلزِّينَةِ وَأَن يُحْشَرَ ٱلنَّاسُ ضُحًۭى", 't': "«قال» موسى «موعدكم يوم الزينة» يوم عيد لهم يتزينون فيه ويجتمعون «وأن يُحشر الناس» يجمع أهل مصر «ضحى» وقته للنظر فيما يقع."},
  {'n': '60', 'v': "فَتَوَلَّىٰ فِرْعَوْنُ فَجَمَعَ كَيْدَهُۥ ثُمَّ أَتَىٰ", 't': "«فتولى فرعون» أدير «فجمع كيده» أي ذوي كيده من السحرة «ثم أتى» بهم الموعد."},
  {'n': '61', 'v': "قَالَ لَهُم مُّوسَىٰ وَيْلَكُمْ لَا تَفْتَرُوا۟ عَلَى ٱللَّهِ كَذِبًۭا فَيُسْحِتَكُم بِعَذَابٍۢ ۖ وَقَدْ خَابَ مَنِ ٱفْتَرَىٰ", 't': "«قال لهم موسى» وهم اثنان وسبعون مع كل واحد حبل وعصا «ويلكم» أي ألزمكم الله الويل «لا تفتروا على الله كذبا» بإشراك أحد معه «فيُسحتكم» بضم الياء وكسر الحاء وبفتحهما أي يهلككم «بعذاب» من عنده «وقد خاب» خسر «من افترى» كذب على الله."},
  {'n': '62', 'v': "فَتَنَٰزَعُوٓا۟ أَمْرَهُم بَيْنَهُمْ وَأَسَرُّوا۟ ٱلنَّجْوَىٰ", 't': "«فتنازعوا أمرهم بينهم» في موسى وأخيه «وأسرُّوا النجوى» أي الكلام بينهم فيهما."},
  {'n': '63', 'v': "قَالُوٓا۟ إِنْ هَٰذَٰنِ لَسَٰحِرَٰنِ يُرِيدَانِ أَن يُخْرِجَاكُم مِّنْ أَرْضِكُم بِسِحْرِهِمَا وَيَذْهَبَا بِطَرِيقَتِكُمُ ٱلْمُثْلَىٰ", 't': "«قالوا» لأنفسهم «إن هذان» وهو موافق للغة من يأتي في المثنى بالألف في أحواله الثلاث ولأبي عمرو: هذين «لساحران يريدان أن يخرجاكم من أرضكم بسحرهما ويذهبا بطريقتكم المثلى» مؤنث أمثل بمعنى أشرف أي بأشرافكم بميلهم إليهما لغلبتهما."},
  {'n': '64', 'v': "فَأَجْمِعُوا۟ كَيْدَكُمْ ثُمَّ ٱئْتُوا۟ صَفًّۭا ۚ وَقَدْ أَفْلَحَ ٱلْيَوْمَ مَنِ ٱسْتَعْلَىٰ", 't': "«فأجمعوا كيدكم» من السحر بهمزة وصل وفتح الميم من جمع أي لمَّ وبهمزة قطع وكسر الميم من أجمع أحكم «ثم أئتوا صفا» حال أي مصطفين «وقد أفلح» فاز «اليوم من استعلى» غلب."},
  {'n': '65', 'v': "قَالُوا۟ يَٰمُوسَىٰٓ إِمَّآ أَن تُلْقِىَ وَإِمَّآ أَن نَّكُونَ أَوَّلَ مَنْ أَلْقَىٰ", 't': "«قالوا يا موسى» اختر «إما أن تُلقيَ» عصاك أولا «وإما أن نكون أول من ألقى» عصاه."},
  {'n': '66', 'v': "قَالَ بَلْ أَلْقُوا۟ ۖ فَإِذَا حِبَالُهُمْ وَعِصِيُّهُمْ يُخَيَّلُ إِلَيْهِ مِن سِحْرِهِمْ أَنَّهَا تَسْعَىٰ", 't': "«قال بل ألقوا» فألقوا «فإذا حبالهم وعصيهم» أصله عصوو قبلت الواوان ياءين وكسرت العين والصاد «يخيل إليه من سحرهم أنها» حيات «تسعى» على بطونها."},
  {'n': '67', 'v': "فَأَوْجَسَ فِى نَفْسِهِۦ خِيفَةًۭ مُّوسَىٰ", 't': "«فأوجس» أحس «في نفسه خيفة موسى» أي خاف من جهة أن سحرهم من جنس معجزته أن يتلبس أمره على الناس فلا يؤمنوا به."},
  {'n': '68', 'v': "قُلْنَا لَا تَخَفْ إِنَّكَ أَنتَ ٱلْأَعْلَىٰ", 't': "«قلنا» له «لا تخف إنك أنت الأعلى» عليهم بالغلبة."},
  {'n': '69', 'v': "وَأَلْقِ مَا فِى يَمِينِكَ تَلْقَفْ مَا صَنَعُوٓا۟ ۖ إِنَّمَا صَنَعُوا۟ كَيْدُ سَٰحِرٍۢ ۖ وَلَا يُفْلِحُ ٱلسَّاحِرُ حَيْثُ أَتَىٰ", 't': "«وألقِ ما في يمينك» وهي عصاه «تَلْقَف» تبتلع «ما صنعوا إنما صنعوا كيد ساحر» أي جنسه «ولا يفلح الساحر حيث أتى» بسحره فألقى موسى عصاه فتلقَّفت كل ما صنعوه."},
  {'n': '70', 'v': "فَأُلْقِىَ ٱلسَّحَرَةُ سُجَّدًۭا قَالُوٓا۟ ءَامَنَّا بِرَبِّ هَٰرُونَ وَمُوسَىٰ", 't': "«فألقي السحرة سجدا» خرّوا ساجدين لله تعالى «قالوا آمنا برب هارون وموسى»."},
  {'n': '71', 'v': "قَالَ ءَامَنتُمْ لَهُۥ قَبْلَ أَنْ ءَاذَنَ لَكُمْ ۖ إِنَّهُۥ لَكَبِيرُكُمُ ٱلَّذِى عَلَّمَكُمُ ٱلسِّحْرَ ۖ فَلَأُقَطِّعَنَّ أَيْدِيَكُمْ وَأَرْجُلَكُم مِّنْ خِلَٰفٍۢ وَلَأُصَلِّبَنَّكُمْ فِى جُذُوعِ ٱلنَّخْلِ وَلَتَعْلَمُنَّ أَيُّنَآ أَشَدُّ عَذَابًۭا وَأَبْقَىٰ", 't': "«قال» فرعون «آمنتم» بتحقيق الهمزتين وإبدال الثانية ألفا «له قبل أن آذن» أنا «لكم إنه لكبيركم» معلمكم «الذي علمكم السحر فلأقطعن أيديكم وأرجلكم من خلاف» حال بمعنى مختلعة أي الأيدي اليمنى والأرجل اليسرى «ولأصلبنكم في جذوع النخل» أي عليها «ولتعلمن أينا» يعني نفسه ورب موسى «أشد عذابا وأبقى» أدوم على مخالفته."},
  {'n': '72', 'v': "قَالُوا۟ لَن نُّؤْثِرَكَ عَلَىٰ مَا جَآءَنَا مِنَ ٱلْبَيِّنَٰتِ وَٱلَّذِى فَطَرَنَا ۖ فَٱقْضِ مَآ أَنتَ قَاضٍ ۖ إِنَّمَا تَقْضِى هَٰذِهِ ٱلْحَيَوٰةَ ٱلدُّنْيَآ", 't': "«قالوا لن نؤثرك» نختارك «على ما جاءنا من البيانات» الدالة على صدق موسى «والذي فطرنا» خلفنا قسم أو عطف على ما «فاقض ما أنت قاض» أي اصنع ما قتله «إنما تقضي هذه الحياة الدنيا» النصب على الاتساع أي فيها وتجزى عليه في الآخرة."},
  {'n': '73', 'v': "إِنَّآ ءَامَنَّا بِرَبِّنَا لِيَغْفِرَ لَنَا خَطَٰيَٰنَا وَمَآ أَكْرَهْتَنَا عَلَيْهِ مِنَ ٱلسِّحْرِ ۗ وَٱللَّهُ خَيْرٌۭ وَأَبْقَىٰٓ", 't': "«إنا آمنا بربنا ليغفر لنا خطايانا» من الإشراك وغيره «وما أكرهتنا عليه من السحر» تعلما وعملاً لمعارضة موسى «والله خير» منك ثوابا إذا أطيع «وأبقى» منك عذابا إذا عصي."},
  {'n': '74', 'v': "إِنَّهُۥ مَن يَأْتِ رَبَّهُۥ مُجْرِمًۭا فَإِنَّ لَهُۥ جَهَنَّمَ لَا يَمُوتُ فِيهَا وَلَا يَحْيَىٰ", 't': "قال تعالى «إنه من يأت ربه مجرما» كافرا كفرعون «فإن له جهنم لا يموت فيها» فيستريح «ولا يحيى» حياة تنفعه."},
  {'n': '75', 'v': "وَمَن يَأْتِهِۦ مُؤْمِنًۭا قَدْ عَمِلَ ٱلصَّٰلِحَٰتِ فَأُو۟لَٰٓئِكَ لَهُمُ ٱلدَّرَجَٰتُ ٱلْعُلَىٰ", 't': "«ومن يأته مؤمنا قد عمل الصالحات» الفرائض والنوافل «فأولئك لهم الدرجات العلى» جمع مؤنث أعلى."},
  {'n': '76', 'v': "جَنَّٰتُ عَدْنٍۢ تَجْرِى مِن تَحْتِهَا ٱلْأَنْهَٰرُ خَٰلِدِينَ فِيهَا ۚ وَذَٰلِكَ جَزَآءُ مَن تَزَكَّىٰ", 't': "«جنات عدن» أي إقامة بيان له «تجري من تحتها الأنهار خالدين فيها وذلك جزاءُ من تزكى» تَطهَّر من الذنوب."},
  {'n': '77', 'v': "وَلَقَدْ أَوْحَيْنَآ إِلَىٰ مُوسَىٰٓ أَنْ أَسْرِ بِعِبَادِى فَٱضْرِبْ لَهُمْ طَرِيقًۭا فِى ٱلْبَحْرِ يَبَسًۭا لَّا تَخَٰفُ دَرَكًۭا وَلَا تَخْشَىٰ", 't': "«ولقد أوحينا إلى موسى أن أسْر بعبادي» بهمزة قطع من أسرى، وبهمز وصل وكسر النون من سرى لغتان أي سر بهم ليلا من أرض مصر «فاضرب لهم» اجعل لهم بالضرب بعصاك «طريقا في البحر يبسا» أي يابسا فامتثل ما أمر به وأيبس الله الأرض فمروا فيها «لا تخاف دَرَكا» أي أن يدركك فرعون «ولا تخشى» غرقا."},
  {'n': '78', 'v': "فَأَتْبَعَهُمْ فِرْعَوْنُ بِجُنُودِهِۦ فَغَشِيَهُم مِّنَ ٱلْيَمِّ مَا غَشِيَهُمْ", 't': "«فأتبعهم فرعون بجنوده» وهو معهم «فغشيهم من اليَمِّ» أي البحر «ما غشيهم» فأغرقهم."},
  {'n': '79', 'v': "وَأَضَلَّ فِرْعَوْنُ قَوْمَهُۥ وَمَا هَدَىٰ", 't': "«وأضل فرعون قومه» بدعائهم إلى عبادته «وما هدى» بل أوقعهم في الهلاك خلاف قوله «وما أهديكم إلا سبيل الرشاد»."},
  {'n': '80', 'v': "يَٰبَنِىٓ إِسْرَٰٓءِيلَ قَدْ أَنجَيْنَٰكُم مِّنْ عَدُوِّكُمْ وَوَٰعَدْنَٰكُمْ جَانِبَ ٱلطُّورِ ٱلْأَيْمَنَ وَنَزَّلْنَا عَلَيْكُمُ ٱلْمَنَّ وَٱلسَّلْوَىٰ", 't': "«يا بني إسرائيل قد أنجيناكم من عدوكم» فرعون بإغراقه «ووعدناكم جانب الطور الأيمن» فنؤتي موسى التوراة للعمل بها «ونزلنا عليكم المن والسلوى» الترنجبين والطير السمانى بتخفيف الميم والقصر، والمنادى من وُجد من اليهود زمن النبي صلى الله عليه وسلم وخُوطبوا لما أنعم الله به على أجدادهم زمن النبي موسى توطئة لقوله تعالى لهم:"},
  {'n': '81', 'v': "كُلُوا۟ مِن طَيِّبَٰتِ مَا رَزَقْنَٰكُمْ وَلَا تَطْغَوْا۟ فِيهِ فَيَحِلَّ عَلَيْكُمْ غَضَبِى ۖ وَمَن يَحْلِلْ عَلَيْهِ غَضَبِى فَقَدْ هَوَىٰ", 't': "«كلوا من طيبات ما رزقناكم» أي المنعم به عليكم «ولا تطغوا فيه» بأن تكفروا النعمة به «فيحل عليكم غضبي» بكسر الحاء: أي يجب وبضمها أي ينزل «ومن يحلل عليه غضبي» بكسر اللام وضمها «فقد هوى» سقط في النار."},
  {'n': '82', 'v': "وَإِنِّى لَغَفَّارٌۭ لِّمَن تَابَ وَءَامَنَ وَعَمِلَ صَٰلِحًۭا ثُمَّ ٱهْتَدَىٰ", 't': "«وإني لغفار لمن تاب» من الشرك «وآمن» وحَّد الله «وعمل صالحا» يصدق بالفرض والنفل «ثم اهتدى» باستمراره على ما ذكر إلى موته."},
  {'n': '83', 'v': "۞ وَمَآ أَعْجَلَكَ عَن قَوْمِكَ يَٰمُوسَىٰ", 't': "«وما أعجلك عن قومك» لمجيء ميعاد أخذ التوراة «يا موسى»."},
  {'n': '84', 'v': "قَالَ هُمْ أُو۟لَآءِ عَلَىٰٓ أَثَرِى وَعَجِلْتُ إِلَيْكَ رَبِّ لِتَرْضَىٰ", 't': "«قال هم أولاء» أي بالقرب مني يأتون «على أثري وعجلت إليك رب لترضى» عني أي زيادة في رضاك وقبل الجواب أتى بالاعتذار حسب ظنه، وتخلف المظنون لما:"},
  {'n': '85', 'v': "قَالَ فَإِنَّا قَدْ فَتَنَّا قَوْمَكَ مِنۢ بَعْدِكَ وَأَضَلَّهُمُ ٱلسَّامِرِىُّ", 't': "«قال» تعالى «فإنا قد فتنا قومك من بعدك» أي بعد فراقك لهم «وأضلهم السامري» فعبدوا العجل."},
  {'n': '86', 'v': "فَرَجَعَ مُوسَىٰٓ إِلَىٰ قَوْمِهِۦ غَضْبَٰنَ أَسِفًۭا ۚ قَالَ يَٰقَوْمِ أَلَمْ يَعِدْكُمْ رَبُّكُمْ وَعْدًا حَسَنًا ۚ أَفَطَالَ عَلَيْكُمُ ٱلْعَهْدُ أَمْ أَرَدتُّمْ أَن يَحِلَّ عَلَيْكُمْ غَضَبٌۭ مِّن رَّبِّكُمْ فَأَخْلَفْتُم مَّوْعِدِى", 't': "«فرجع موسى إلى قومه غضبان» من جهتهم «أسفا» شديد الحزن «قال يا قوم ألم يعدكم ربكم وعدا حسنا» أي صدقا أنه يعطيكم التوراة «أفطال عليكم العهد» مدة مفارقتي إياكم «أم أردتم أن يحل» يجب «عليكم غضب من ربكم» بعبادتكم العجل «فأخلفتم موعدي» وتركتم المجيء بعدي."},
  {'n': '87', 'v': "قَالُوا۟ مَآ أَخْلَفْنَا مَوْعِدَكَ بِمَلْكِنَا وَلَٰكِنَّا حُمِّلْنَآ أَوْزَارًۭا مِّن زِينَةِ ٱلْقَوْمِ فَقَذَفْنَٰهَا فَكَذَٰلِكَ أَلْقَى ٱلسَّامِرِىُّ", 't': "«قالوا ما أخلفنا موعدك بملكنا» مثلث الميم أي بقدرتنا أو أمرنا «ولكنا حَمَلْنا» بفتح الحاء مخففا وبضمها وكسر الميم مشددا «أوزارا» أثقالاً «من زينة القوم» أي قوم فرعون، استعارها بنو إسرائيل بعلَّة عرس فبقيت عندهم «فقذفناها» طرحناها في النار بأمر السامري «فكذلك» كما ألقينا «ألقى السامري» ما معه من حليهم، ومن التراب الذي أخذه من أثر حافر فرس جبريل على الوجه الآتي:"},
  {'n': '88', 'v': "فَأَخْرَجَ لَهُمْ عِجْلًۭا جَسَدًۭا لَّهُۥ خُوَارٌۭ فَقَالُوا۟ هَٰذَآ إِلَٰهُكُمْ وَإِلَٰهُ مُوسَىٰ فَنَسِىَ", 't': "«فأخرج لهم عجلاً» صاغه من الحلي «جسدا» لحما ودما «له خوار» أي صوت يُسمع أي انقلب كذلك بسبب التراب الذي أثره الحياة فيما يوضع ووضعه بعد صوغه في فمه «فقالوا» أي السامري وأتباعه «هذا إلهكم وإله موسى فنسيَ» موسى ربه هنا وذهب يطلبه قال تعالى:"},
  {'n': '89', 'v': "أَفَلَا يَرَوْنَ أَلَّا يَرْجِعُ إِلَيْهِمْ قَوْلًۭا وَلَا يَمْلِكُ لَهُمْ ضَرًّۭا وَلَا نَفْعًۭا", 't': "(أفلا يرون أ) أن مخففة من الثقيلة واسمها محذوف أي أنه (لا يرجع) العجل (إليهم قولاً) أي لا يرد لهم جوابا (ولا يملك لهم ضرا) أي دفعه (ولا نفعا) أي جلبه أي فكيف يتخذ إلها؟"},
  {'n': '90', 'v': "وَلَقَدْ قَالَ لَهُمْ هَٰرُونُ مِن قَبْلُ يَٰقَوْمِ إِنَّمَا فُتِنتُم بِهِۦ ۖ وَإِنَّ رَبَّكُمُ ٱلرَّحْمَٰنُ فَٱتَّبِعُونِى وَأَطِيعُوٓا۟ أَمْرِى", 't': "«ولقد قال لهم هارون من قبل» أي قبل أن يرجع موسى «يا قوم إنما فُتنْتم به وإنَّ ربكم الرحمن فاتَّبعوني» في عبادته «وأطيعوا أمري» فيها."},
  {'n': '91', 'v': "قَالُوا۟ لَن نَّبْرَحَ عَلَيْهِ عَٰكِفِينَ حَتَّىٰ يَرْجِعَ إِلَيْنَا مُوسَىٰ", 't': "«قالوا لن نبرح» نزال «عليه عاكفين» على عبادته مقيمين «حتى يرجع إلينا موسى»."},
  {'n': '92', 'v': "قَالَ يَٰهَٰرُونُ مَا مَنَعَكَ إِذْ رَأَيْتَهُمْ ضَلُّوٓا۟", 't': "«قال» موسى بعد رجوعه «يا هارون ما منعك إذ رأيتهم ضلوا» بعبادته."},
  {'n': '93', 'v': "أَلَّا تَتَّبِعَنِ ۖ أَفَعَصَيْتَ أَمْرِى", 't': "«أ» ن «لا تتبعن» لا زائدة «أفعصيت أمري» بإقامتك بين من يعبد غير الله تعالى."},
  {'n': '94', 'v': "قَالَ يَبْنَؤُمَّ لَا تَأْخُذْ بِلِحْيَتِى وَلَا بِرَأْسِىٓ ۖ إِنِّى خَشِيتُ أَن تَقُولَ فَرَّقْتَ بَيْنَ بَنِىٓ إِسْرَٰٓءِيلَ وَلَمْ تَرْقُبْ قَوْلِى", 't': "«قال» هارون «يا ابن أم» بكسر الميم وفتحها أراد أمي وذكرها أَعْطَف لقلبه «لا تأخذ بلحيتي» وكان أخذها بشماله «ولا برأسي» وكان أخذ شعره بيمينه غضبا «إني خشيت» لو اتبعك ولا بد أن يتبعني جمع ممن لم يعبدوا العجل «أن تقول فرقت بين بني إسرائيل» وتغضب عليَّ «ولم ترقب» تنتظر «قولي» فيما رأيته في ذلك."},
  {'n': '95', 'v': "قَالَ فَمَا خَطْبُكَ يَٰسَٰمِرِىُّ", 't': "«قال فما خطبك» شأنك الداعي إلى ما صنعت «يا سامري»."},
  {'n': '96', 'v': "قَالَ بَصُرْتُ بِمَا لَمْ يَبْصُرُوا۟ بِهِۦ فَقَبَضْتُ قَبْضَةًۭ مِّنْ أَثَرِ ٱلرَّسُولِ فَنَبَذْتُهَا وَكَذَٰلِكَ سَوَّلَتْ لِى نَفْسِى", 't': "«قال بصرت بما لم يبصروا به» بالياء والتاء أي علمت ما لم يعلموه «فقبضت قبضة من» تراب «أثر» حافر فرس «الرسول» جبريل «فنبذتها» ألقيتها في صورة العجل المصاغ «وكذلك سولت» زينت «لي نفسي» وألقى فيها أن أخذ قبضة من تراب ما ذكر، وألقيها على ما لا روح، به يصير له روح ورأيت قومك طلبوا منك أن تجعل لهم إلها فحدثتني نفسي أن يكون ذلك العجل إلههم."},
  {'n': '97', 'v': "قَالَ فَٱذْهَبْ فَإِنَّ لَكَ فِى ٱلْحَيَوٰةِ أَن تَقُولَ لَا مِسَاسَ ۖ وَإِنَّ لَكَ مَوْعِدًۭا لَّن تُخْلَفَهُۥ ۖ وَٱنظُرْ إِلَىٰٓ إِلَٰهِكَ ٱلَّذِى ظَلْتَ عَلَيْهِ عَاكِفًۭا ۖ لَّنُحَرِّقَنَّهُۥ ثُمَّ لَنَنسِفَنَّهُۥ فِى ٱلْيَمِّ نَسْفًا", 't': "«قال» له موسى «فاذهب» من بيننا «فإن لك في الحياة» أي مدة حياتك «أن تقول» لمن رأيته «لا مساس» أي لا تقربني فكان بهم في البرية وإذا مس أحدا أو مسه أحد حُمَّا جميعا «وإن لك موعدا» لعذابك «لن تخلفه» بكسر اللام: أي لن تغيب عنه، وبفتحها أي بل تبعث إليه «وانظر إلى إلهك الذي ظلْت» أصله ظللت بلامين أولاهما مكسورة حذفت تخفيفا أي دمت «عليه عاكفا» أي مقيما تعبده «لنحرقنه» بالنار «ثم لننسفنه في اليمّ نسفا» نذرينه في هواء البحر، وفعل موسى بعد ذبحه ما ذكره."},
  {'n': '98', 'v': "إِنَّمَآ إِلَٰهُكُمُ ٱللَّهُ ٱلَّذِى لَآ إِلَٰهَ إِلَّا هُوَ ۚ وَسِعَ كُلَّ شَىْءٍ عِلْمًۭا", 't': "«إنما إلهكم الله الذي لا اله إلا هو وسع كل شيء علما» تمييز محول عن الفاعل وسع علمه كل شيء."},
  {'n': '99', 'v': "كَذَٰلِكَ نَقُصُّ عَلَيْكَ مِنْ أَنۢبَآءِ مَا قَدْ سَبَقَ ۚ وَقَدْ ءَاتَيْنَٰكَ مِن لَّدُنَّا ذِكْرًۭا", 't': "«كذلك» أي كما قصصنا عليك يا محمد هذه القصة «نقص عليك من أنباء» أخبار «ما قد سبق» من الأمم «وقد آتيناك» أعطيناك «من لدنا» من عندنا «ذكرا» قرآنا."},
  {'n': '100', 'v': "مَّنْ أَعْرَضَ عَنْهُ فَإِنَّهُۥ يَحْمِلُ يَوْمَ ٱلْقِيَٰمَةِ وِزْرًا", 't': "«من أعرض عنه» فلم يؤمن به «فإنه يحمل يوم القيامة وزرا» حملا ثقيلا من الإثم."},
  {'n': '101', 'v': "خَٰلِدِينَ فِيهِ ۖ وَسَآءَ لَهُمْ يَوْمَ ٱلْقِيَٰمَةِ حِمْلًۭا", 't': "«خالدين فيه» أي في عذاب الوزر «وساء لهم يوم القيامة حملا» تمييز مفسر للضمير في ساء والمخصوص بالذم محذوف تقديره وزرهم، واللام للبيان ويبدل من يوم القيامة."},
  {'n': '102', 'v': "يَوْمَ يُنفَخُ فِى ٱلصُّورِ ۚ وَنَحْشُرُ ٱلْمُجْرِمِينَ يَوْمَئِذٍۢ زُرْقًۭا", 't': "«يوم ننفخ في الصور» القرن، النفخة الثانية «ونحشر المجرمين» الكافرين «يومئذ زرقا» عيونهم مع سواد وجوههم."},
  {'n': '103', 'v': "يَتَخَٰفَتُونَ بَيْنَهُمْ إِن لَّبِثْتُمْ إِلَّا عَشْرًۭا", 't': "«يتخافتون بينهم» يتسارون «إن» ما «لبثتم» في الدنيا «إلا عشرا» من الليالي بأيامها."},
  {'n': '104', 'v': "نَّحْنُ أَعْلَمُ بِمَا يَقُولُونَ إِذْ يَقُولُ أَمْثَلُهُمْ طَرِيقَةً إِن لَّبِثْتُمْ إِلَّا يَوْمًۭا", 't': "«نحن أعلم بما يقولون» في ذلك: أي ليس كما قالوا «إذ يقول أمثلهم» أعدلهم «طريقة» فيه «إن لبثتم إلا يوما» يستقلون لبثهم في الدنيا جدا بما يعاينونه في الآخرة من أهوالها."},
  {'n': '105', 'v': "وَيَسْـَٔلُونَكَ عَنِ ٱلْجِبَالِ فَقُلْ يَنسِفُهَا رَبِّى نَسْفًۭا", 't': "«ويسألونك عن الجبال» كيف تكون يوم القيامة «فقل» لهم «ينسفها ربي نسفا» بأن يفتتها كالرمل السائل ثم يطيرها بالرياح."},
  {'n': '106', 'v': "فَيَذَرُهَا قَاعًۭا صَفْصَفًۭا", 't': "«فيذرها قاعا» منبسطا «صفصفا» مستويا."},
  {'n': '107', 'v': "لَّا تَرَىٰ فِيهَا عِوَجًۭا وَلَآ أَمْتًۭا", 't': "«لا ترى فيها عوجا» انخفاضا «ولا أمْتا» ارتفاعا."},
  {'n': '108', 'v': "يَوْمَئِذٍۢ يَتَّبِعُونَ ٱلدَّاعِىَ لَا عِوَجَ لَهُۥ ۖ وَخَشَعَتِ ٱلْأَصْوَاتُ لِلرَّحْمَٰنِ فَلَا تَسْمَعُ إِلَّا هَمْسًۭا", 't': "«يومئذ» أي يوم إذ نسفت الجبال «يتبعون» أي الناس بعد القيام من القبور «الداعي» إلى المحشر بصوته وهو إسرافيل يقول: هلموا إلى عرض الرحمن «لا عوج له» أي لاتباعهم: أي لا يقدرون أن لا يتعبوا «وخشعت» سكنت «الأصوات للرحمن فلا تسمع إلا همسا» صوت وطء الأقدام في نقلها إلى المحشر كصوت أخفاف الإبل في مشيها."},
  {'n': '109', 'v': "يَوْمَئِذٍۢ لَّا تَنفَعُ ٱلشَّفَٰعَةُ إِلَّا مَنْ أَذِنَ لَهُ ٱلرَّحْمَٰنُ وَرَضِىَ لَهُۥ قَوْلًۭا", 't': "«يومئذ لا تنفع الشفاعة» أحداً «إلا من أذن له الرحمن» أن يشفع له «ورضي له قولا» بأن يقول: لا إله إلا الله."},
  {'n': '110', 'v': "يَعْلَمُ مَا بَيْنَ أَيْدِيهِمْ وَمَا خَلْفَهُمْ وَلَا يُحِيطُونَ بِهِۦ عِلْمًۭا", 't': "«يعلم ما بين أيديهم» من أمور الآخرة «وما خلفهم» من أمور الدنيا «ولا يحيطون به علماً» لا يعلمون ذلك."},
  {'n': '111', 'v': "۞ وَعَنَتِ ٱلْوُجُوهُ لِلْحَىِّ ٱلْقَيُّومِ ۖ وَقَدْ خَابَ مَنْ حَمَلَ ظُلْمًۭا", 't': "«وعنت الوجوه» خضعت «للحي القيوم» أي الله «وقد خاب» خسر «من حَمَلَ ظلماً» أي شركاً."},
  {'n': '112', 'v': "وَمَن يَعْمَلْ مِنَ ٱلصَّٰلِحَٰتِ وَهُوَ مُؤْمِنٌۭ فَلَا يَخَافُ ظُلْمًۭا وَلَا هَضْمًۭا", 't': "«ومن يعمل من الصالحات» الطاعات «وهو مؤمن فلا يخاف ظلماً» بزيادة في سيئاته «ولا هضماً» بنقص من حسناته."},
  {'n': '113', 'v': "وَكَذَٰلِكَ أَنزَلْنَٰهُ قُرْءَانًا عَرَبِيًّۭا وَصَرَّفْنَا فِيهِ مِنَ ٱلْوَعِيدِ لَعَلَّهُمْ يَتَّقُونَ أَوْ يُحْدِثُ لَهُمْ ذِكْرًۭا", 't': "«وكذلك» معطوف على كذلك نقص: أي مثل إنزال ما ذكر «أنزلناه» أي القرآن «قرآناً عربيا وصرفنا» كررنا «فيه من الوعيد لعلهم يتقون» الشرك «أو يُحدث» القرآن «لهم ذكراً» بهلاك من تقدمهم من الأمم فيعتبرون."},
  {'n': '114', 'v': "فَتَعَٰلَى ٱللَّهُ ٱلْمَلِكُ ٱلْحَقُّ ۗ وَلَا تَعْجَلْ بِٱلْقُرْءَانِ مِن قَبْلِ أَن يُقْضَىٰٓ إِلَيْكَ وَحْيُهُۥ ۖ وَقُل رَّبِّ زِدْنِى عِلْمًۭا", 't': "«فتعالى الله الملك الحق» عما يقول المشركون «ولا تعجل بالقرآن» أي بقراءته «من قبل أن يُقضى إليك وحيه» أي يفرغ جبريل من إبلاغه «وقل ربّ زدني علما» أي بالقرآن فكلما أنزل عليه منه زاد به علمه."},
  {'n': '115', 'v': "وَلَقَدْ عَهِدْنَآ إِلَىٰٓ ءَادَمَ مِن قَبْلُ فَنَسِىَ وَلَمْ نَجِدْ لَهُۥ عَزْمًۭا", 't': "«ولقد عهدنا إلى آدم» وصيناه أن لا يأكل من الشجرة «من قبل» أي قبل أكله منها «فنسي» ترك عهدنا «ولم نجد له عزماً» حزماً وصبراً عما نهيناه عنه."},
  {'n': '116', 'v': "وَإِذْ قُلْنَا لِلْمَلَٰٓئِكَةِ ٱسْجُدُوا۟ لِءَادَمَ فَسَجَدُوٓا۟ إِلَّآ إِبْلِيسَ أَبَىٰ", 't': "(و) اذكر (إذ قلنا للملائكة اسجدوا لآدم فسجدوا إلا إبليس) وهو أبو الجن كان يصحب الملائكة ويعبد الله معهم (أبى) عن السجود لآدم \"\" قال أنا خير منه \"\"."},
  {'n': '117', 'v': "فَقُلْنَا يَٰٓـَٔادَمُ إِنَّ هَٰذَا عَدُوٌّۭ لَّكَ وَلِزَوْجِكَ فَلَا يُخْرِجَنَّكُمَا مِنَ ٱلْجَنَّةِ فَتَشْقَىٰٓ", 't': "«فقلنا يا آدم إنَّ هذا عدو لك ولزوجك» حواء بالمد «فلا يخرجنكما من الجنة فتشقى» تتعب بالحرث والزرع والحصد والطحن والخبز وغير ذلك واقتصر على شقائه لأن الرجل يسعى على زوجته."},
  {'n': '118', 'v': "إِنَّ لَكَ أَلَّا تَجُوعَ فِيهَا وَلَا تَعْرَىٰ", 't': "«إن لك أ» «لا تجوع فيها ولا تعرى»."},
