  {'n': '14', 'v': "إِنَّ ٱللَّهَ يُدْخِلُ ٱلَّذِينَ ءَامَنُوا۟ وَعَمِلُوا۟ ٱلصَّٰلِحَٰتِ جَنَّٰتٍۢ تَجْرِى مِن تَحْتِهَا ٱلْأَنْهَٰرُ ۚ إِنَّ ٱللَّهَ يَفْعَلُ مَا يُرِيدُ", 't': "«إن الله يدخل الذين آمنوا وعملوا الصالحات» من الفروض والنوافل «جناتِ تجري من تحتها الأنهار إن الله يفعل ما يريد» من إكرام من يعطيه وإهانة من يعصيه."},
  {'n': '15', 'v': "مَن كَانَ يَظُنُّ أَن لَّن يَنصُرَهُ ٱللَّهُ فِى ٱلدُّنْيَا وَٱلْءَاخِرَةِ فَلْيَمْدُدْ بِسَبَبٍ إِلَى ٱلسَّمَآءِ ثُمَّ لْيَقْطَعْ فَلْيَنظُرْ هَلْ يُذْهِبَنَّ كَيْدُهُۥ مَا يَغِيظُ", 't': "«من كان يظن أن لن ينصره الله» أي محمدا نبيه «في الدنيا والآخرة فليمدد بسبب» بحبل «إلى السماء» أي سقف بيته يشدّه فيه وفي عنقه «ثم ليقطع» أي ليختنق به بأن يقطع نفسه من الأرض كما في الصحاح «فلينظر هل يُذهبن كيده» في عدم نصرة النبي «ما يغيظ» منها المعنى فليختنق غيظا منها فلا بد منها."},
  {'n': '16', 'v': "وَكَذَٰلِكَ أَنزَلْنَٰهُ ءَايَٰتٍۭ بَيِّنَٰتٍۢ وَأَنَّ ٱللَّهَ يَهْدِى مَن يُرِيدُ", 't': "«وكذلك» أي مثل إنزالنا الآية السابقة «أنزلناه» أي القرآن الباقي «آيات بينات» ظاهرات حال «وأن الله يهدي من يريد» هداه معطوف على هاء أنزلناه."},
  {'n': '17', 'v': "إِنَّ ٱلَّذِينَ ءَامَنُوا۟ وَٱلَّذِينَ هَادُوا۟ وَٱلصَّٰبِـِٔينَ وَٱلنَّصَٰرَىٰ وَٱلْمَجُوسَ وَٱلَّذِينَ أَشْرَكُوٓا۟ إِنَّ ٱللَّهَ يَفْصِلُ بَيْنَهُمْ يَوْمَ ٱلْقِيَٰمَةِ ۚ إِنَّ ٱللَّهَ عَلَىٰ كُلِّ شَىْءٍۢ شَهِيدٌ", 't': "«إن الذين آمنوا والذين هادوا» هم اليهود «والصابئين» طائفة منهم «والنصارى والمجوس والذين أشركوا إن الله يفصل بينهم يوم القيامة» بإدخال المؤمنين الجنة وإدخال غيرهم النار «إن الله على كل شيء» من عملهم «شهيد» عالم به علم مشاهدة"},
  {'n': '18', 'v': "أَلَمْ تَرَ أَنَّ ٱللَّهَ يَسْجُدُ لَهُۥ مَن فِى ٱلسَّمَٰوَٰتِ وَمَن فِى ٱلْأَرْضِ وَٱلشَّمْسُ وَٱلْقَمَرُ وَٱلنُّجُومُ وَٱلْجِبَالُ وَٱلشَّجَرُ وَٱلدَّوَآبُّ وَكَثِيرٌۭ مِّنَ ٱلنَّاسِ ۖ وَكَثِيرٌ حَقَّ عَلَيْهِ ٱلْعَذَابُ ۗ وَمَن يُهِنِ ٱللَّهُ فَمَا لَهُۥ مِن مُّكْرِمٍ ۚ إِنَّ ٱللَّهَ يَفْعَلُ مَا يَشَآءُ ۩", 't': "«ألم تر» تعلم «أن الله يسجد له من في السماوات ومن في الأرض والشمس والقمر والنجوم والجبال والشجر والدواب» أي يخضع له بما يراد منه «وكثير من الناس» وهم المؤمنون بزيادة على الخضوع في سجود الصلاة «وكثير حق عليه العذاب» وهم الكافرون لأنهم أبوا السجود المتوقف على الإيمان «ومن يهن الله» يشقه «فما له من مكرم» مسعد «إن الله يفعل ما يشاء» من الإهانة والإكرام."},
  {'n': '19', 'v': "۞ هَٰذَانِ خَصْمَانِ ٱخْتَصَمُوا۟ فِى رَبِّهِمْ ۖ فَٱلَّذِينَ كَفَرُوا۟ قُطِّعَتْ لَهُمْ ثِيَابٌۭ مِّن نَّارٍۢ يُصَبُّ مِن فَوْقِ رُءُوسِهِمُ ٱلْحَمِيمُ", 't': "«هذان خصمان» أي المؤمنون خصم، والكفار الخمسة خصم، وهو يطلق على الواحد والجماعة «اختصموا في ربهم» أي في دينه «فالذين كفروا قطعت لهم ثياب من نار» يلبسونها يعني أحيطت بهم النار «يصب من فوق رؤوسهم الحميم» الماء البالغ نهاية الحرارة."},
  {'n': '20', 'v': "يُصْهَرُ بِهِۦ مَا فِى بُطُونِهِمْ وَٱلْجُلُودُ", 't': "«يصهر» يذاب «به ما في بطونهم» من شحوم وغيرها «و» تشوى به «الجلود»."},
  {'n': '21', 'v': "وَلَهُم مَّقَٰمِعُ مِنْ حَدِيدٍۢ", 't': "«ولهم مقامع من حديد» لضرب رؤوسهم."},
  {'n': '22', 'v': "كُلَّمَآ أَرَادُوٓا۟ أَن يَخْرُجُوا۟ مِنْهَا مِنْ غَمٍّ أُعِيدُوا۟ فِيهَا وَذُوقُوا۟ عَذَابَ ٱلْحَرِيقِ", 't': "«كلما أرادوا أن يخرجوا منها» أي النار «من غم» يلحقهم بها «أعيدوا فيها» ردوا إليها بالمقامع «و» قيل لهم «ذوقوا عذاب الحريق» أي البالغ نهاية الإحراق."},
  {'n': '23', 'v': "إِنَّ ٱللَّهَ يُدْخِلُ ٱلَّذِينَ ءَامَنُوا۟ وَعَمِلُوا۟ ٱلصَّٰلِحَٰتِ جَنَّٰتٍۢ تَجْرِى مِن تَحْتِهَا ٱلْأَنْهَٰرُ يُحَلَّوْنَ فِيهَا مِنْ أَسَاوِرَ مِن ذَهَبٍۢ وَلُؤْلُؤًۭا ۖ وَلِبَاسُهُمْ فِيهَا حَرِيرٌۭ", 't': "وقال في المؤمنين «إن الله يدخل الذين آمنوا وعملوا الصالحات جنات تجري من تحتها الأنهار يحلون فيها من أساور من ذهب ولؤلؤ» بالجرّ أي منهما بأن يرصع اللؤلؤ بالذهب، وبالنصب عطفا على محل من أساور «ولباسهم فيها حرير» هو المحرَّم لبسه على الرجال في الدنيا."},
  {'n': '24', 'v': "وَهُدُوٓا۟ إِلَى ٱلطَّيِّبِ مِنَ ٱلْقَوْلِ وَهُدُوٓا۟ إِلَىٰ صِرَٰطِ ٱلْحَمِيدِ", 't': "«وهدوا» في الدنيا «إلى الطيب من القول» وهو لا إله إلا الله «وهدوا إلى صراط الحميد» أي طريق الله المحمود ودينه."},
  {'n': '25', 'v': "إِنَّ ٱلَّذِينَ كَفَرُوا۟ وَيَصُدُّونَ عَن سَبِيلِ ٱللَّهِ وَٱلْمَسْجِدِ ٱلْحَرَامِ ٱلَّذِى جَعَلْنَٰهُ لِلنَّاسِ سَوَآءً ٱلْعَٰكِفُ فِيهِ وَٱلْبَادِ ۚ وَمَن يُرِدْ فِيهِ بِإِلْحَادٍۭ بِظُلْمٍۢ نُّذِقْهُ مِنْ عَذَابٍ أَلِيمٍۢ", 't': "«إن الذين كفروا ويصدون عن سبيل الله» طاعته «و» عن «المسجد الحرام الذي جعلناه» منسكا ومتعبدا «للناس سواءً العاكف» المقيم «فيه والباد» الطارئ «ومن يرد فيه بإلحاد» الباء زائدة «بظلم» أي بسببه بأن ارتكب منهيا، ولو شتم الخادم «نذقه من عذاب أليم» مؤلم: أي بعضه، ومن هذا يؤخذ خبر إن: أي نذيقهم من عذاب أليم."},
  {'n': '26', 'v': "وَإِذْ بَوَّأْنَا لِإِبْرَٰهِيمَ مَكَانَ ٱلْبَيْتِ أَن لَّا تُشْرِكْ بِى شَيْـًۭٔا وَطَهِّرْ بَيْتِىَ لِلطَّآئِفِينَ وَٱلْقَآئِمِينَ وَٱلرُّكَّعِ ٱلسُّجُودِ", 't': "«و» اذكر «إذ بوأنا» بينا «لإبراهيم مكان البيت» ليبنيه، وكان قد رفع زمن الطوفان، وأمرناه «أن لا تشرك بي شيئا وطهر بيتي» من الأوثان «للطائفين والقائمين» المقيمين به «والركع السجود» جمع راكع وساجد: المصلين."},
  {'n': '27', 'v': "وَأَذِّن فِى ٱلنَّاسِ بِٱلْحَجِّ يَأْتُوكَ رِجَالًۭا وَعَلَىٰ كُلِّ ضَامِرٍۢ يَأْتِينَ مِن كُلِّ فَجٍّ عَمِيقٍۢ", 't': "«وأذِّن» ناد «في الناس بالحج» فنادى على جبل أبي قبيس: يا أيها الناس إن ربكم بنى بيتاً وأوجب عليكم الحج إليه فأجيبوا ربكم، والتفت بوجهه يمينا وشمالا وشرقا وغربا، فأجابه كل من كتب له أن يحج من أصلاب الرجال وأرحام الأمهات: لبيك اللهم لبيك، وجواب الأمر «يأتوك رجالا» مشاة جمع راجل كقائم وقيام «و» ركبانا «على كل ضامر» أي بعير مهزول وهو يطلق على الذكر والأنثى «يأتين» أي الضوامر حملا على المعنى «من كل فج عميق» طريق بعيد."},
  {'n': '28', 'v': "لِّيَشْهَدُوا۟ مَنَٰفِعَ لَهُمْ وَيَذْكُرُوا۟ ٱسْمَ ٱللَّهِ فِىٓ أَيَّامٍۢ مَّعْلُومَٰتٍ عَلَىٰ مَا رَزَقَهُم مِّنۢ بَهِيمَةِ ٱلْأَنْعَٰمِ ۖ فَكُلُوا۟ مِنْهَا وَأَطْعِمُوا۟ ٱلْبَآئِسَ ٱلْفَقِيرَ", 't': "«ليشهدوا» أي يحضروا «منافع لهم» في الدنيا بالتجارة أو في الآخرة أو فيهما أقوال «ويذكروا اسم الله في أيام معلومات» أي عشر ذي الحجة أو يوم عرفة أو يوم النحر إلى آخر أيام التشريق أقوال «على ما رزقهم من بهيمة الأنعام» الإبل والبقر والغنم التي تنحر في يوم العيد، وما بعده من الهدايا والضحايا «فكلوا منها» إذا كانت مستحبة «وأطعموا البائس الفقير» أي الشديد الفقر."},
  {'n': '29', 'v': "ثُمَّ لْيَقْضُوا۟ تَفَثَهُمْ وَلْيُوفُوا۟ نُذُورَهُمْ وَلْيَطَّوَّفُوا۟ بِٱلْبَيْتِ ٱلْعَتِيقِ", 't': "«ثم ليقضوا تفثهم» أي يزيلوا أوساخهم وشعثهم كطول الظفر «وليوفوا» بالتخفيف والشديد «نذورهم» من الهدايا والضحايا «وليطوفوا» طواف الإفاضة «بالبيت العتيق» أي القديم لأنه أول بيت وضع للناس."},
  {'n': '30', 'v': "ذَٰلِكَ وَمَن يُعَظِّمْ حُرُمَٰتِ ٱللَّهِ فَهُوَ خَيْرٌۭ لَّهُۥ عِندَ رَبِّهِۦ ۗ وَأُحِلَّتْ لَكُمُ ٱلْأَنْعَٰمُ إِلَّا مَا يُتْلَىٰ عَلَيْكُمْ ۖ فَٱجْتَنِبُوا۟ ٱلرِّجْسَ مِنَ ٱلْأَوْثَٰنِ وَٱجْتَنِبُوا۟ قَوْلَ ٱلزُّورِ", 't': "«ذلك» خبر مبتدأ مقدر: أي الأمر أو الشأن ذلك المذكور «ومن يعظم حرمات الله» هي ما لا يحل انتهاكه «فهو» أي تعظيمها «خير له عند ربه» في الآخرة «وأحلت لكم الأنعام» أكلا بعد الذبح «إلا ما يتلى عليكم» تحريم في (حرمت عليكم الميتة) الآية فالاستثناء منقطع، ويجوز أن يكون متصلا، والتحريم لما عرض من الموت ونحوه «فاجتنبوا الرجس من الأوثان» من للبيان أي الذي هو الأوثان «واجتنبوا قول الزور» أي الشرك بالله في تلبيتكم أو شهادة الزور."},
  {'n': '31', 'v': "حُنَفَآءَ لِلَّهِ غَيْرَ مُشْرِكِينَ بِهِۦ ۚ وَمَن يُشْرِكْ بِٱللَّهِ فَكَأَنَّمَا خَرَّ مِنَ ٱلسَّمَآءِ فَتَخْطَفُهُ ٱلطَّيْرُ أَوْ تَهْوِى بِهِ ٱلرِّيحُ فِى مَكَانٍۢ سَحِيقٍۢ", 't': "«حنفاء لله» مسلمين عادلين عن كل دين سوى دينه «غير مشركين به» تأكيد لما قبله، وهما حالان من الواو «ومن يشرك بالله فكأنما خر» سقط «من السماء فتخطفه الطير» أي تأخذه بسرعة «أو تهوي به الريح» أي تسقطه «في مكان سحيق» بعيد فهو لا يرجى خلاصه."},
  {'n': '32', 'v': "ذَٰلِكَ وَمَن يُعَظِّمْ شَعَٰٓئِرَ ٱللَّهِ فَإِنَّهَا مِن تَقْوَى ٱلْقُلُوبِ", 't': "«ذلك» يقدر قبله الأمر، مبتدأ «ومن يعظم شعائر الله فإنها» أي فإن تعظيمها وهي البدن التي تهدى للحرم بأن تُستَحسَنَ وتُستمنَ «من تقوى القلوب» منهم، وسميت شعائر لإشعارها بما تعرف به أنها هدي طعن حديد بسنامها."},
  {'n': '33', 'v': "لَكُمْ فِيهَا مَنَٰفِعُ إِلَىٰٓ أَجَلٍۢ مُّسَمًّۭى ثُمَّ مَحِلُّهَآ إِلَى ٱلْبَيْتِ ٱلْعَتِيقِ", 't': "«لكم فيها منافع» كركوبها ولحمل عليها ما لا يضرها «إلى أجل مسمى» وقت نحرها «ثم محلها» أي مكان حل نحرها «إلى البيت العتيق» أي عنده، والمراد الحرم جميعه."},
  {'n': '34', 'v': "وَلِكُلِّ أُمَّةٍۢ جَعَلْنَا مَنسَكًۭا لِّيَذْكُرُوا۟ ٱسْمَ ٱللَّهِ عَلَىٰ مَا رَزَقَهُم مِّنۢ بَهِيمَةِ ٱلْأَنْعَٰمِ ۗ فَإِلَٰهُكُمْ إِلَٰهٌۭ وَٰحِدٌۭ فَلَهُۥٓ أَسْلِمُوا۟ ۗ وَبَشِّرِ ٱلْمُخْبِتِينَ", 't': "«ولكل أمة» أي جماعة مؤمنة سلفت قبلكم «جعلنا منسكا» بفتح السين مصدر وبكسرها اسم مكان: أي ذبحا قربانا أو مكانه «ليذكروا اسم الله على ما رزقهم من بهيمة الأنعام» عند ذبحها «فإلهكم إله واحد فله أسلموا» انقادوا «وبشر المخبتين» المطيعين المتواضعين."},
  {'n': '35', 'v': "ٱلَّذِينَ إِذَا ذُكِرَ ٱللَّهُ وَجِلَتْ قُلُوبُهُمْ وَٱلصَّٰبِرِينَ عَلَىٰ مَآ أَصَابَهُمْ وَٱلْمُقِيمِى ٱلصَّلَوٰةِ وَمِمَّا رَزَقْنَٰهُمْ يُنفِقُونَ", 't': "«الذين إذا ذكر الله وجلت» خافت «قلوبهم والصابرين على ما أصابهم» من البلايا «والمقيمي الصلاة» في أوقاتها «ومما رزقناهم ينفقون» يتصدقون."},
  {'n': '36', 'v': "وَٱلْبُدْنَ جَعَلْنَٰهَا لَكُم مِّن شَعَٰٓئِرِ ٱللَّهِ لَكُمْ فِيهَا خَيْرٌۭ ۖ فَٱذْكُرُوا۟ ٱسْمَ ٱللَّهِ عَلَيْهَا صَوَآفَّ ۖ فَإِذَا وَجَبَتْ جُنُوبُهَا فَكُلُوا۟ مِنْهَا وَأَطْعِمُوا۟ ٱلْقَانِعَ وَٱلْمُعْتَرَّ ۚ كَذَٰلِكَ سَخَّرْنَٰهَا لَكُمْ لَعَلَّكُمْ تَشْكُرُونَ", 't': "«والبدن» جمع بدنة: وهي الإبل «جعلناها لكم من شعائر الله» أعلام دينه «لكم فيها خير» نفع في الدنيا كما تقدم، وأجر في العقبى «فاذكروا اسم الله عليها» عند نحرها «صوافَّ» قائمة على ثلاث معقولة اليد اليسرى «فإذا وجبت جنوبها» سقطت إلى الأرض بعد النحر: وهو وقت الأكل منها «فكلوا منها» إن شئتم «وأطعموا القانع» الذي يقنع بما يعطى ولا يسأل ولا يتعرّض «والمعترَّ» والسائل أو المتعرض «كذلك» أي مثل ذلك التسخير «سخرناها لكم» بأن تُنحر وتركب، وإلا لم تطق «لعلكم تشكرون» إنعامي عليكم."},
  {'n': '37', 'v': "لَن يَنَالَ ٱللَّهَ لُحُومُهَا وَلَا دِمَآؤُهَا وَلَٰكِن يَنَالُهُ ٱلتَّقْوَىٰ مِنكُمْ ۚ كَذَٰلِكَ سَخَّرَهَا لَكُمْ لِتُكَبِّرُوا۟ ٱللَّهَ عَلَىٰ مَا هَدَىٰكُمْ ۗ وَبَشِّرِ ٱلْمُحْسِنِينَ", 't': "«لن ينال الله لحومها ولا دماؤها» أي لا يرفعان إليه «ولكن يناله التقوى منكم» أي يرفع إليه منكم العمل الصالح الخالص له مع الإيمان «كذلك سخرها لكم لتكبروا الله على ما هداكم» أرشدكم لمعالم دينه ومناسك حجه «وبشر المحسنين» أي الموحدين."},
  {'n': '38', 'v': "۞ إِنَّ ٱللَّهَ يُدَٰفِعُ عَنِ ٱلَّذِينَ ءَامَنُوٓا۟ ۗ إِنَّ ٱللَّهَ لَا يُحِبُّ كُلَّ خَوَّانٍۢ كَفُورٍ", 't': "«إن الله يدافع عن الذين آمنوا» غوائل المشركين «إن الله لا يحب كل خوَّانِ» في أمانته «كفور» لنعمته، وهم المشركون المعنى أنه يعاقبهم."},
  {'n': '39', 'v': "أُذِنَ لِلَّذِينَ يُقَٰتَلُونَ بِأَنَّهُمْ ظُلِمُوا۟ ۚ وَإِنَّ ٱللَّهَ عَلَىٰ نَصْرِهِمْ لَقَدِيرٌ", 't': "«أذن للذين يقاتلون» أي للمؤمنين أن يقاتلوا، وهذه أول آية نزلت في الجهاد «بأنهم» أي بسبب أنهم «ظلموا» لظلم الكافرين إياهم «وإن الله على نصرهم لقدير»."},
  {'n': '40', 'v': "ٱلَّذِينَ أُخْرِجُوا۟ مِن دِيَٰرِهِم بِغَيْرِ حَقٍّ إِلَّآ أَن يَقُولُوا۟ رَبُّنَا ٱللَّهُ ۗ وَلَوْلَا دَفْعُ ٱللَّهِ ٱلنَّاسَ بَعْضَهُم بِبَعْضٍۢ لَّهُدِّمَتْ صَوَٰمِعُ وَبِيَعٌۭ وَصَلَوَٰتٌۭ وَمَسَٰجِدُ يُذْكَرُ فِيهَا ٱسْمُ ٱللَّهِ كَثِيرًۭا ۗ وَلَيَنصُرَنَّ ٱللَّهُ مَن يَنصُرُهُۥٓ ۗ إِنَّ ٱللَّهَ لَقَوِىٌّ عَزِيزٌ", 't': "هم «الذين أخرجوا من ديارهم بغير حق» في الإخراج، ما أخرجوا «إلا أن يقولوا» أي بقولهم «ربنا الله» وحده وهذا القول حق فالإخراج به إخراج بغير حق «ولولا دفع الله الناس بعضهم» بدل بعض من الناس «ببعض لهدمت» بالتشديد للتكثير وبالتخفيف «صوامع» للرهبان «وبيع» كنائس للنصارى «وصلوات» كنائس لليهود بالعبرانية «ومساجد» للمسلمين «يذكر فيها» أي المواضع المذكورة «اسم الله كثيرا» وتنقطع العبادات بخرابها «ولينصرن الله من ينصره» أي ينصر دينه «إن الله لقويٌ» على خلقه «عزيز» منيع في سلطانه وقدرته."},
  {'n': '41', 'v': "ٱلَّذِينَ إِن مَّكَّنَّٰهُمْ فِى ٱلْأَرْضِ أَقَامُوا۟ ٱلصَّلَوٰةَ وَءَاتَوُا۟ ٱلزَّكَوٰةَ وَأَمَرُوا۟ بِٱلْمَعْرُوفِ وَنَهَوْا۟ عَنِ ٱلْمُنكَرِ ۗ وَلِلَّهِ عَٰقِبَةُ ٱلْأُمُورِ", 't': "«الذين إن مكانهم في الأرض» بنصرهم على عدوهم «أقاموا الصلاة وآتوا الزكاة وأمروا بالمعروف ونهوا عن المنكر» جواب الشرط، وهو وجوابه صلة الموصول، ويقدر قبله هم بمبتدأ «ولله عاقبة الأمور» أي إليه مرجعها في الآخرة."},
  {'n': '42', 'v': "وَإِن يُكَذِّبُوكَ فَقَدْ كَذَّبَتْ قَبْلَهُمْ قَوْمُ نُوحٍۢ وَعَادٌۭ وَثَمُودُ", 't': "«وإن يكذبوك» إلى آخره فيه تسليه للنبي صلى الله عليه وسلم «فقد كذبت قبلهم قوم نوح» تأنيث قوم باعتبار المعنى «وعاد» قوم هود «وثمود» قوم صالح."},
  {'n': '43', 'v': "وَقَوْمُ إِبْرَٰهِيمَ وَقَوْمُ لُوطٍۢ", 't': "«وقوم إبراهيم وقوم لوط»."},
  {'n': '44', 'v': "وَأَصْحَٰبُ مَدْيَنَ ۖ وَكُذِّبَ مُوسَىٰ فَأَمْلَيْتُ لِلْكَٰفِرِينَ ثُمَّ أَخَذْتُهُمْ ۖ فَكَيْفَ كَانَ نَكِيرِ", 't': "«وأصحاب مدين» قوم شعيب «وكُذب موسى» كذبه القبط لا قومه بنو إسرائيل أي كذب هؤلاء رسلهم فلك أسوة بهم «فأمليتُ للكافرين» أمهلتهم بتأخير العقاب لهم «ثم أخذتهم» بالعذاب «فكيف كان نكير» أي إنكاري عليم بتكذيبهم بإهلاكهم والاستفهام للتقرير: أي هو واقع موقعه."},
  {'n': '45', 'v': "فَكَأَيِّن مِّن قَرْيَةٍ أَهْلَكْنَٰهَا وَهِىَ ظَالِمَةٌۭ فَهِىَ خَاوِيَةٌ عَلَىٰ عُرُوشِهَا وَبِئْرٍۢ مُّعَطَّلَةٍۢ وَقَصْرٍۢ مَّشِيدٍ", 't': "«فكأين» أي كم «من قرية أهلكتها» وفي قراءة أهلكناها «وهي ظالمة» أي أحلها بكفرهم «فهي خاوية» ساقطة «على عروشها» سقوفها «و» كم من «بئر معطلة» متروكة بموت أهلها «وقصر مشيد» رفيع خال بموت أهله."},
  {'n': '46', 'v': "أَفَلَمْ يَسِيرُوا۟ فِى ٱلْأَرْضِ فَتَكُونَ لَهُمْ قُلُوبٌۭ يَعْقِلُونَ بِهَآ أَوْ ءَاذَانٌۭ يَسْمَعُونَ بِهَا ۖ فَإِنَّهَا لَا تَعْمَى ٱلْأَبْصَٰرُ وَلَٰكِن تَعْمَى ٱلْقُلُوبُ ٱلَّتِى فِى ٱلصُّدُورِ", 't': "«أفلم يسيروا» أي كفار مكة «في الأرض فتكون لهم قلوب يعقلون بها» ما نزل بالمكذبين قبلهم «أو آذان يسمعون بها» أخبارهم بإلاهلاك وخراب الديار فيعتبروا «فإنها» أي القصة «لا تعمى الأبصار ولكن تعمى القلوب التي في الصدور» تأكيد."},
  {'n': '47', 'v': "وَيَسْتَعْجِلُونَكَ بِٱلْعَذَابِ وَلَن يُخْلِفَ ٱللَّهُ وَعْدَهُۥ ۚ وَإِنَّ يَوْمًا عِندَ رَبِّكَ كَأَلْفِ سَنَةٍۢ مِّمَّا تَعُدُّونَ", 't': "«ويستعجلونك بالعذاب ولن يخلف الله وعده» بإنزال العذاب فأنزله يوم بدر «وإنَّ يوما عند ربك» من أيام الآخرة بسبب العذاب «كألف سنة مما تعدون» بالتاء والياء في الدنيا."},
  {'n': '48', 'v': "وَكَأَيِّن مِّن قَرْيَةٍ أَمْلَيْتُ لَهَا وَهِىَ ظَالِمَةٌۭ ثُمَّ أَخَذْتُهَا وَإِلَىَّ ٱلْمَصِيرُ", 't': "«وكأيِّن من قرية أمليت لها وهي ظالمة ثم أخذتها» المراد أهلها «وإليَّ المصير» المرجع."},
  {'n': '49', 'v': "قُلْ يَٰٓأَيُّهَا ٱلنَّاسُ إِنَّمَآ أَنَا۠ لَكُمْ نَذِيرٌۭ مُّبِينٌۭ", 't': "«قل يا أيها الناس» أهل مكة «إنما أنا لكم نذير مبين» الإنذار وأنا بشير للمؤمنين."},
  {'n': '50', 'v': "فَٱلَّذِينَ ءَامَنُوا۟ وَعَمِلُوا۟ ٱلصَّٰلِحَٰتِ لَهُم مَّغْفِرَةٌۭ وَرِزْقٌۭ كَرِيمٌۭ", 't': "«فالذين آمنوا وعملوا الصالحات لهم مغفرة» من الذنوب «ورزق كريم» هو الجنة."},
  {'n': '51', 'v': "وَٱلَّذِينَ سَعَوْا۟ فِىٓ ءَايَٰتِنَا مُعَٰجِزِينَ أُو۟لَٰٓئِكَ أَصْحَٰبُ ٱلْجَحِيمِ", 't': "«والذين سعوْا في آياتنا» القرآن بإبطالها «معجِّزين» من اتبع النبي أي ينسبونهم إلى العجز، ويثبطونهم عن الإيمان أو مقدرين عجزنا عنهم، وفي قراءة معاجزين: مسابقين لنا، أي يظنون أن يفوتونا بإنكارهم البعث والعقاب «أولئك أصحاب الجحيم» النار."},
  {'n': '52', 'v': "وَمَآ أَرْسَلْنَا مِن قَبْلِكَ مِن رَّسُولٍۢ وَلَا نَبِىٍّ إِلَّآ إِذَا تَمَنَّىٰٓ أَلْقَى ٱلشَّيْطَٰنُ فِىٓ أُمْنِيَّتِهِۦ فَيَنسَخُ ٱللَّهُ مَا يُلْقِى ٱلشَّيْطَٰنُ ثُمَّ يُحْكِمُ ٱللَّهُ ءَايَٰتِهِۦ ۗ وَٱللَّهُ عَلِيمٌ حَكِيمٌۭ", 't': "«وما أرسلنا من قبلك من رسول» هو نبي أمر بالتبليغ «ولا نبي» أي لم يؤمر بالتبليغ «إلا إذا تمنى» قرأ «ألقى الشيطان في أمنيته» قراءته ما ليس من القرآن مما يرضاه المرسل إليهم، وقد قرأ النبي صلى الله عليه وسلم في سورة النجم بمجلس من قريش بعد: (أفرأيتم اللات والعزى، ومناة الثالثة الأخرى) بإلقاء الشيطان على لسانه من غير علمه صلى الله عليه وسلم به: تلك الغرانيق العلا، وإن شفاعتهن لترجي، ففرحوا لذلك، ثم أخبره جبريل بما ألقه الشيطان على لسانه من ذلك، بحزن فسلي بهذه الآية ليطمئن «فينسخ الله» يبطل «ما يلقي الشيطان ثم يحكم الله آياته» يثبتها «والله عليم» بإلقاء الشيطان ما ذكر «حكيم» في تمكنيه منه يفعل ما يشاء."},
  {'n': '53', 'v': "لِّيَجْعَلَ مَا يُلْقِى ٱلشَّيْطَٰنُ فِتْنَةًۭ لِّلَّذِينَ فِى قُلُوبِهِم مَّرَضٌۭ وَٱلْقَاسِيَةِ قُلُوبُهُمْ ۗ وَإِنَّ ٱلظَّٰلِمِينَ لَفِى شِقَاقٍۭ بَعِيدٍۢ", 't': "«ليجعل ما يلقي الشيطان فتنة» محنة «للذين في قلوبهم مرض» شقاق ونفاق «والقاسية قلوبهم» أي المشركين عن قبول الحق «وإن الظالمين» الكافرين «لفي شقاق بعيد» خلاف طويل مع النبي صلى الله عليه وسلم والمؤمنين حيث جرى على لسانه ذكر آلهتهم بما يرضيهم ثم أبطل ذلك."},
  {'n': '54', 'v': "وَلِيَعْلَمَ ٱلَّذِينَ أُوتُوا۟ ٱلْعِلْمَ أَنَّهُ ٱلْحَقُّ مِن رَّبِّكَ فَيُؤْمِنُوا۟ بِهِۦ فَتُخْبِتَ لَهُۥ قُلُوبُهُمْ ۗ وَإِنَّ ٱللَّهَ لَهَادِ ٱلَّذِينَ ءَامَنُوٓا۟ إِلَىٰ صِرَٰطٍۢ مُّسْتَقِيمٍۢ", 't': "«وليعلم الذين أوتوا العلم» التوحيد والقرآن «أنه» أي القرآن «الحق من ربك فيؤمنوا به فتخبت» نطمئن «له قلوبهم وإن الله لهاد الذين آمنوا إلى صراط» طريق «مستقيم» أي دين الإسلام."},
  {'n': '55', 'v': "وَلَا يَزَالُ ٱلَّذِينَ كَفَرُوا۟ فِى مِرْيَةٍۢ مِّنْهُ حَتَّىٰ تَأْتِيَهُمُ ٱلسَّاعَةُ بَغْتَةً أَوْ يَأْتِيَهُمْ عَذَابُ يَوْمٍ عَقِيمٍ", 't': "«ولا يزال الذين كفروا في مرية» شك «منه» أي القرآن بما ألقاه الشيطان على لسان النبي ثم أبطل «حتى تأتيهم الساعة بغتة» أي ساعة موتهم أو القيامة فجأة «أو يأتيهم عذاب يوم عقيم» هو يوم بدر لا خير فيه للكفار كالريح العقيم التي لا تأتي بخير، أو هو يوم القيامة لا ليل بعده."},
  {'n': '56', 'v': "ٱلْمُلْكُ يَوْمَئِذٍۢ لِّلَّهِ يَحْكُمُ بَيْنَهُمْ ۚ فَٱلَّذِينَ ءَامَنُوا۟ وَعَمِلُوا۟ ٱلصَّٰلِحَٰتِ فِى جَنَّٰتِ ٱلنَّعِيمِ", 't': "«الملك يومئذ» أي يوم القيامة «لله» وحده وما تضمنه من الاستقرار ناصب للظرف «يحكم بينهم» بين المؤمنين والكافرين بما بيّن بعده «فالذين آمنوا وعملوا الصالحات في جنات النعيم» فضلا من الله."},
  {'n': '57', 'v': "وَٱلَّذِينَ كَفَرُوا۟ وَكَذَّبُوا۟ بِـَٔايَٰتِنَا فَأُو۟لَٰٓئِكَ لَهُمْ عَذَابٌۭ مُّهِينٌۭ", 't': "«والذين كفروا وكذبوا بآياتنا فأولئك لهم عذاب مُهين» شديد بسبب كفرهم."},
  {'n': '58', 'v': "وَٱلَّذِينَ هَاجَرُوا۟ فِى سَبِيلِ ٱللَّهِ ثُمَّ قُتِلُوٓا۟ أَوْ مَاتُوا۟ لَيَرْزُقَنَّهُمُ ٱللَّهُ رِزْقًا حَسَنًۭا ۚ وَإِنَّ ٱللَّهَ لَهُوَ خَيْرُ ٱلرَّٰزِقِينَ", 't': "«والذين هاجروا في سبيل الله» أي طاعته من مكة إلى المدينة «ثم قُتلوا أو ماتوا ليرزقنهم الله رزقا حسنا» هو رزق الجنة «وإن الله لهو خير الرازقين» أفضل المعطين"},
  {'n': '59', 'v': "لَيُدْخِلَنَّهُم مُّدْخَلًۭا يَرْضَوْنَهُۥ ۗ وَإِنَّ ٱللَّهَ لَعَلِيمٌ حَلِيمٌۭ", 't': "«ليدخلنهم مدخلا» بضم الميم وفتحها أي إدخالا أو موضعا «يرضونه» وهو الجنة «وإن الله لعليم» بنياتهم «حليم» عن عقابهم."},
  {'n': '60', 'v': "۞ ذَٰلِكَ وَمَنْ عَاقَبَ بِمِثْلِ مَا عُوقِبَ بِهِۦ ثُمَّ بُغِىَ عَلَيْهِ لَيَنصُرَنَّهُ ٱللَّهُ ۗ إِنَّ ٱللَّهَ لَعَفُوٌّ غَفُورٌۭ", 't': "الأمر «ذلك» الذي قصصناه عليك «ومن عاقب» جازي من المؤمنين «بمثل ما عوقب به» ظلما من المشركين: أي قاتلهم كما قاتلوه في الشهر الحرام «ثم بغي عليه» منهم أي ظلم بإخراجه من منزله «لينصرنه الله إن الله لعفوٌ» عن المؤمنين «غفور» لهم عن قتالهم في الشهر الحرام."},
  {'n': '61', 'v': "ذَٰلِكَ بِأَنَّ ٱللَّهَ يُولِجُ ٱلَّيْلَ فِى ٱلنَّهَارِ وَيُولِجُ ٱلنَّهَارَ فِى ٱلَّيْلِ وَأَنَّ ٱللَّهَ سَمِيعٌۢ بَصِيرٌۭ", 't': "«ذلك» النصر «بأن الله يولج الليل في النهار ويولج النهار في الليل» أي يدخل كلا منهما في الآخر بأن يزيد به، من أثر قدرته تعالى التي بها النصر «وأن الله سميع» دعاء المؤمنين «بصير» بهم حيث جعل فيهم الإيمان فأجاب دعائهم."},
  {'n': '62', 'v': "ذَٰلِكَ بِأَنَّ ٱللَّهَ هُوَ ٱلْحَقُّ وَأَنَّ مَا يَدْعُونَ مِن دُونِهِۦ هُوَ ٱلْبَٰطِلُ وَأَنَّ ٱللَّهَ هُوَ ٱلْعَلِىُّ ٱلْكَبِيرُ", 't': "«ذلك» النصر أيضا «بأن الله هو الحق» الثابت «وأن ما يدعون» بالياء والتاء يعبدون «من دونه» وهو الأصنام «هو الباطل» الزائل «وأن الله هو العلي» أي العالي على كل شيء بقدرته «الكبير» الذي يصغر كل شيء سواه."},
  {'n': '63', 'v': "أَلَمْ تَرَ أَنَّ ٱللَّهَ أَنزَلَ مِنَ ٱلسَّمَآءِ مَآءًۭ فَتُصْبِحُ ٱلْأَرْضُ مُخْضَرَّةً ۗ إِنَّ ٱللَّهَ لَطِيفٌ خَبِيرٌۭ", 't': "«ألم تر» تعلم «أن الله أنزل من السماء ماءً» مطرا «فتصبح الأرض مخضرة» بالنبات وهذا من أثر قدرته «إن الله لطيف» بعباده في إخراج النبات بالماء «خبير» بما في قلوبهم عند تأخير المطر."},
  {'n': '64', 'v': "لَّهُۥ مَا فِى ٱلسَّمَٰوَٰتِ وَمَا فِى ٱلْأَرْضِ ۗ وَإِنَّ ٱللَّهَ لَهُوَ ٱلْغَنِىُّ ٱلْحَمِيدُ", 't': "«له ما في السماوات وما في الأرض» على جهة الملك «وإن الله لهو الغني» عن عباده «الحميد» لأوليائه."},
  {'n': '65', 'v': "أَلَمْ تَرَ أَنَّ ٱللَّهَ سَخَّرَ لَكُم مَّا فِى ٱلْأَرْضِ وَٱلْفُلْكَ تَجْرِى فِى ٱلْبَحْرِ بِأَمْرِهِۦ وَيُمْسِكُ ٱلسَّمَآءَ أَن تَقَعَ عَلَى ٱلْأَرْضِ إِلَّا بِإِذْنِهِۦٓ ۗ إِنَّ ٱللَّهَ بِٱلنَّاسِ لَرَءُوفٌۭ رَّحِيمٌۭ", 't': "«ألم ترَ» تَعلم «أن الله سخر لكم ما في الأرض» من البهائم «والفلك» السفن «تجري في البحر» للركوب والحمل «بأمره» بإذنه «ويمسك السماء» من «أن» أو لئلا «تقع على الأرض إلا بإذنه» فتهلكوا «إن الله بالناس لرؤوف رحيم» في التسخير والإمساك."},
  {'n': '66', 'v': "وَهُوَ ٱلَّذِىٓ أَحْيَاكُمْ ثُمَّ يُمِيتُكُمْ ثُمَّ يُحْيِيكُمْ ۗ إِنَّ ٱلْإِنسَٰنَ لَكَفُورٌۭ", 't': "«وهو الذي أحياكم» بالإنشاء «ثم يميتكم» عند انتهاء آجالكم «ثم يحييكم» عند البعث «إن الإنسان» أي المشرك «لكفور» لنعم الله بتركه توحيده."},
  {'n': '67', 'v': "لِّكُلِّ أُمَّةٍۢ جَعَلْنَا مَنسَكًا هُمْ نَاسِكُوهُ ۖ فَلَا يُنَٰزِعُنَّكَ فِى ٱلْأَمْرِ ۚ وَٱدْعُ إِلَىٰ رَبِّكَ ۖ إِنَّكَ لَعَلَىٰ هُدًۭى مُّسْتَقِيمٍۢ", 't': "«لكل أمة جعلنا منسكا» بفتح السين وكسرها شريعة «هم ناسكوه» عاملون به «فلا يُنازعُنَّك» يراد به لا تنازعهم «في الأمر» أي أمر الذبيحة إذ قالوا: ما قتل الله أحق أن تأكلوه مما قتلتم «وادع إلى ربك» إلى دينه «إنك لعلى هدى» دين «مستقيم»."},
  {'n': '68', 'v': "وَإِن جَٰدَلُوكَ فَقُلِ ٱللَّهُ أَعْلَمُ بِمَا تَعْمَلُونَ", 't': "«وإن جادلوك» في أمر الدين «فقل الله أعلم بما تعملون» فيجازيكم عليه، وهذا قبل الأمر بالقتال."},
  {'n': '69', 'v': "ٱللَّهُ يَحْكُمُ بَيْنَكُمْ يَوْمَ ٱلْقِيَٰمَةِ فِيمَا كُنتُمْ فِيهِ تَخْتَلِفُونَ", 't': "«الله يحكم بينكم» أيها المؤمنون والكافرون «يوم القيامة فيما كنتم فيه تختلفون» بأن يقول كل من الفريقين خلاف قول الآخر."},
  {'n': '70', 'v': "أَلَمْ تَعْلَمْ أَنَّ ٱللَّهَ يَعْلَمُ مَا فِى ٱلسَّمَآءِ وَٱلْأَرْضِ ۗ إِنَّ ذَٰلِكَ فِى كِتَٰبٍ ۚ إِنَّ ذَٰلِكَ عَلَى ٱللَّهِ يَسِيرٌۭ", 't': "«ألم تعلم» الاستفهام فيه للتقرير «أن الله يعلم ما في السماء والأرض إن ذلك» أي ما ذكر «في كتاب» هو اللوح المحفوظ «إن ذلك» أي علم ما ذكر «على الله يسير» سهل."},
  {'n': '71', 'v': "وَيَعْبُدُونَ مِن دُونِ ٱللَّهِ مَا لَمْ يُنَزِّلْ بِهِۦ سُلْطَٰنًۭا وَمَا لَيْسَ لَهُم بِهِۦ عِلْمٌۭ ۗ وَمَا لِلظَّٰلِمِينَ مِن نَّصِيرٍۢ", 't': "«ويعبدون» أي المشركون «من دون الله ما لم ينزل به» هو الأصنام «سلطانا» حجة «وما ليس لهم به علم» أنها آلهة «وما للظالمين» بالإشراك «من نصير» يمنع عنهم عذاب الله."},
  {'n': '72', 'v': "وَإِذَا تُتْلَىٰ عَلَيْهِمْ ءَايَٰتُنَا بَيِّنَٰتٍۢ تَعْرِفُ فِى وُجُوهِ ٱلَّذِينَ كَفَرُوا۟ ٱلْمُنكَرَ ۖ يَكَادُونَ يَسْطُونَ بِٱلَّذِينَ يَتْلُونَ عَلَيْهِمْ ءَايَٰتِنَا ۗ قُلْ أَفَأُنَبِّئُكُم بِشَرٍّۢ مِّن ذَٰلِكُمُ ۗ ٱلنَّارُ وَعَدَهَا ٱللَّهُ ٱلَّذِينَ كَفَرُوا۟ ۖ وَبِئْسَ ٱلْمَصِيرُ", 't': "«وإذا تُتلى عليهم آياتنا» من القرآن «بيِّنات» ظاهرات حال «تعرف في وجوه الذين كفروا المنكر» أي الإنكار لها: أي أثره من الكراهة والعبوس «يكادون يسطون بالذين يتلون عليهم آياتنا» أي يقعون فيه بالبطش «قل أفأنبئكم بشرِّ من ذلكم» بأكره إليكم من القرآن المتلو عليكم هو «النار وعَدَها الله الذين كفروا» بأن مصيرهم إليها «وبئس المصير» هي."},
  {'n': '73', 'v': "يَٰٓأَيُّهَا ٱلنَّاسُ ضُرِبَ مَثَلٌۭ فَٱسْتَمِعُوا۟ لَهُۥٓ ۚ إِنَّ ٱلَّذِينَ تَدْعُونَ مِن دُونِ ٱللَّهِ لَن يَخْلُقُوا۟ ذُبَابًۭا وَلَوِ ٱجْتَمَعُوا۟ لَهُۥ ۖ وَإِن يَسْلُبْهُمُ ٱلذُّبَابُ شَيْـًۭٔا لَّا يَسْتَنقِذُوهُ مِنْهُ ۚ ضَعُفَ ٱلطَّالِبُ وَٱلْمَطْلُوبُ", 't': "«يا أيها الناس» أي أهل مكة «ضُرب مثل فاستمعوا له» وهو «إن الذين تدعون» تعبدون «من دون الله» أي غيره وهم الأصنام «لن يخلقوا ذباباً» اسم جنس، واحده ذبابة يقع على المذكر والمؤنث «ولو اجتمعوا له» لخلقه «وإن يسلبهم الذباب شيئا» مما عليهم من الطيب والزعفران الملطخين به «لا يستنقذوه» لا يستردوه «منه» لعجزهم، فكيف يعبدون شركاء لله تعالى؟ هذا أمر مستغرب عبر عنه بضرب مثل «ضعف الطالب» العابد «والمطلوب» المعبود."},
  {'n': '74', 'v': "مَا قَدَرُوا۟ ٱللَّهَ حَقَّ قَدْرِهِۦٓ ۗ إِنَّ ٱللَّهَ لَقَوِىٌّ عَزِيزٌ", 't': "«ما قدروا الله» عظموه «حقَّ قدره» عظمته إذ أشركوا به ما لم يمتنع من الذباب ولا ينتصف منه «إن الله لقوي عزيز» غالب."},
  {'n': '75', 'v': "ٱللَّهُ يَصْطَفِى مِنَ ٱلْمَلَٰٓئِكَةِ رُسُلًۭا وَمِنَ ٱلنَّاسِ ۚ إِنَّ ٱللَّهَ سَمِيعٌۢ بَصِيرٌۭ", 't': "«الله يصطفي من الملائكة رسلا ومن الناس» رسلا، نزل لما قال المشركون (أأنزل عليه الذكر من بيننا) «إن الله سميع» لمقالتهم «بصير» بمن يتخذه رسولاً كجبريل وميكائيل وإبراهيم ومحمد وغيرهم صلى الله عليهم وسلم."},
  {'n': '76', 'v': "يَعْلَمُ مَا بَيْنَ أَيْدِيهِمْ وَمَا خَلْفَهُمْ ۗ وَإِلَى ٱللَّهِ تُرْجَعُ ٱلْأُمُورُ", 't': "«يعلم ما بين أيديهم وما خلفهم» أي ما قدَّموا وما خلّفوا وما عملوا وما هم عاملون بعد «وإلى الله ترجع الأمور»."},
  {'n': '77', 'v': "يَٰٓأَيُّهَا ٱلَّذِينَ ءَامَنُوا۟ ٱرْكَعُوا۟ وَٱسْجُدُوا۟ وَٱعْبُدُوا۟ رَبَّكُمْ وَٱفْعَلُوا۟ ٱلْخَيْرَ لَعَلَّكُمْ تُفْلِحُونَ ۩", 't': "«يا أيها الذين آمنوا اركعوا واسجدوا» أي صلوا «واعبدوا ربكم» وحدوه «وافعلوا الخير» كصلة الرحم ومكارم الأخلاق «لعلكم تفلحون» تفوزون بالبقاء في الجنة."},
  {'n': '78', 'v': "وَجَٰهِدُوا۟ فِى ٱللَّهِ حَقَّ جِهَادِهِۦ ۚ هُوَ ٱجْتَبَىٰكُمْ وَمَا جَعَلَ عَلَيْكُمْ فِى ٱلدِّينِ مِنْ حَرَجٍۢ ۚ مِّلَّةَ أَبِيكُمْ إِبْرَٰهِيمَ ۚ هُوَ سَمَّىٰكُمُ ٱلْمُسْلِمِينَ مِن قَبْلُ وَفِى هَٰذَا لِيَكُونَ ٱلرَّسُولُ شَهِيدًا عَلَيْكُمْ وَتَكُونُوا۟ شُهَدَآءَ عَلَى ٱلنَّاسِ ۚ فَأَقِيمُوا۟ ٱلصَّلَوٰةَ وَءَاتُوا۟ ٱلزَّكَوٰةَ وَٱعْتَصِمُوا۟ بِٱللَّهِ هُوَ مَوْلَىٰكُمْ ۖ فَنِعْمَ ٱلْمَوْلَىٰ وَنِعْمَ ٱلنَّصِيرُ", 't': "«وجاهدوا في الله» لإقامة دينه «حق جهاده» باستفراغ الطاقة فيه ونصب حَقَّ على المصدر «هو اجتباكم» اختاركم لدينه «وما جعل عليكم في الدين من حَرَج» أي ضيق بأن سهله عند الضرورات كالقصر والتيمم وأكل الميتة والفطر للمرض والسفر «مِلة أبيكم» منصوب الخافض الكاف «إبراهيم» عطف بيان «هو» أي الله «سمَّاكم المسلمين من قبل» أي قبل هذا الكتاب «وفي هذا» أي القرآن «ليكون الرسول شهيداً عليكم» يوم القيامة أنه بلَّغكم «وتكونوا» أنتم «شهداء على الناس» أن رسلهم بلَّغوهم «فأقيموا الصلاة» داوموا عليها «وآتوا الزكاة واعتصموا بالله» ثقوا به «هو مولاكم» ناصركم ومتولي أموركم «فنعم المولى» هو «ونعم النصير» الناصر لكم."},
];

