  {'n': '36', 'v': "۞ هَيْهَاتَ هَيْهَاتَ لِمَا تُوعَدُونَ", 't': "«هَيْهات هَيْهات» اسم فعل ماض بمعنى مصدر: أي بعد «لما توعدون» من الإخراج من القبور واللام زائدة للبيان."},
  {'n': '37', 'v': "إِنْ هِىَ إِلَّا حَيَاتُنَا ٱلدُّنْيَا نَمُوتُ وَنَحْيَا وَمَا نَحْنُ بِمَبْعُوثِينَ", 't': "«إن هي» أي ما الحياة «إلا حياتنا الدنيا نموت ونحيا» بحياة أبنائنا «وما نحن بمبعوثين»."},
  {'n': '38', 'v': "إِنْ هُوَ إِلَّا رَجُلٌ ٱفْتَرَىٰ عَلَى ٱللَّهِ كَذِبًۭا وَمَا نَحْنُ لَهُۥ بِمُؤْمِنِينَ", 't': "«إن هو» ما الرسول «إلا رجل افترى على الله كذباً وما نحن له بمؤمنين» مصدقين بالبعث بعد الموت."},
  {'n': '39', 'v': "قَالَ رَبِّ ٱنصُرْنِى بِمَا كَذَّبُونِ", 't': "«قال رب انصرني بما كذبون»."},
  {'n': '40', 'v': "قَالَ عَمَّا قَلِيلٍۢ لَّيُصْبِحُنَّ نَٰدِمِينَ", 't': "«قال عما قليل» من الزمان وما زائدة «ليصبحن» ليصيرن «نادمين» على كفرهم وتكذيبهم."},
  {'n': '41', 'v': "فَأَخَذَتْهُمُ ٱلصَّيْحَةُ بِٱلْحَقِّ فَجَعَلْنَٰهُمْ غُثَآءًۭ ۚ فَبُعْدًۭا لِّلْقَوْمِ ٱلظَّٰلِمِينَ", 't': "«فأخذتهم الصيحة» صيحة العذاب والهلاك كائنة «بالحق» فماتوا «فجعلناهم غثاءً» هو نبت يبس أي صيرناهم مثله في اليبس «فبعداً» من الرحمة «للقوم الظالمين» المكذبين."},
  {'n': '42', 'v': "ثُمَّ أَنشَأْنَا مِنۢ بَعْدِهِمْ قُرُونًا ءَاخَرِينَ", 't': "«ثم أنشأنا من بعدهم قروناً» أقواماً «آخرين»."},
  {'n': '43', 'v': "مَا تَسْبِقُ مِنْ أُمَّةٍ أَجَلَهَا وَمَا يَسْتَـْٔخِرُونَ", 't': "«ما تسبق من أمة أجلها» بأن تموت قبله «وما يستأخرون» عنه ذكر الضمير بعد تأنيثه رعاية للمعنى."},
  {'n': '44', 'v': "ثُمَّ أَرْسَلْنَا رُسُلَنَا تَتْرَا ۖ كُلَّ مَا جَآءَ أُمَّةًۭ رَّسُولُهَا كَذَّبُوهُ ۚ فَأَتْبَعْنَا بَعْضَهُم بَعْضًۭا وَجَعَلْنَٰهُمْ أَحَادِيثَ ۚ فَبُعْدًۭا لِّقَوْمٍۢ لَّا يُؤْمِنُونَ", 't': "«ثم أرسلنا رسلنا تتراً» بالتنوين وعدمه متتابعين بين كل اثنين زمان طويل «كلما جاء أمة» بتحقيق الهمزتين وتسهيل الثانية بينها وبين الواو «رسولها كذبوه فأتبعنا بعضهم بعضاً» في الهلاك «وجعلناهم أحاديث فعبداً لقوم لا يؤمنون»."},
  {'n': '45', 'v': "ثُمَّ أَرْسَلْنَا مُوسَىٰ وَأَخَاهُ هَٰرُونَ بِـَٔايَٰتِنَا وَسُلْطَٰنٍۢ مُّبِينٍ", 't': "«ثم أرسلنا موسى وأخاه هارون بآياتنا وسلطان مبين» حجة وهي اليد والعصا وغيرهما من الآيات."},
  {'n': '46', 'v': "إِلَىٰ فِرْعَوْنَ وَمَلَإِي۟هِۦ فَٱسْتَكْبَرُوا۟ وَكَانُوا۟ قَوْمًا عَالِينَ", 't': "«إلى فرعون وملئه فاستكبروا» عن الإيمان بها وبالله «وكانوا قوماً عالين» قاهرين بني إسرائيل بالظلم."},
  {'n': '47', 'v': "فَقَالُوٓا۟ أَنُؤْمِنُ لِبَشَرَيْنِ مِثْلِنَا وَقَوْمُهُمَا لَنَا عَٰبِدُونَ", 't': "«فقالوا أنؤمن لبشرين مثلنا وقومهما لنا عابدون» مطيعون خاضعون."},
  {'n': '48', 'v': "فَكَذَّبُوهُمَا فَكَانُوا۟ مِنَ ٱلْمُهْلَكِينَ", 't': "«فكذبوهما فكانوا من المهلكين»."},
  {'n': '49', 'v': "وَلَقَدْ ءَاتَيْنَا مُوسَى ٱلْكِتَٰبَ لَعَلَّهُمْ يَهْتَدُونَ", 't': "«ولقد آتينا موسى الكتاب» التوراة «لعلهم» قومه بني إسرائيل «يهتدون» به من الضلالة، وأوتيها بعد هلاك فرعون وقومه جملة واحدة."},
  {'n': '50', 'v': "وَجَعَلْنَا ٱبْنَ مَرْيَمَ وَأُمَّهُۥٓ ءَايَةًۭ وَءَاوَيْنَٰهُمَآ إِلَىٰ رَبْوَةٍۢ ذَاتِ قَرَارٍۢ وَمَعِينٍۢ", 't': "«وجعلنا ابن مريم» عيسى «وأمه آية» لم يقل آيتين لأن الآية فيهما واحدة: ولادته من غير فحل «وآوينهما إلى ربوة» مكان مرتفع وهو بيت المقدس أو دمشق أو فلسطين، أقوال «ذات قرار» أي مستوية يستقر عليها ساكنوها «ومعين» وماء جار ظاهر تراه العيون."},
  {'n': '51', 'v': "يَٰٓأَيُّهَا ٱلرُّسُلُ كُلُوا۟ مِنَ ٱلطَّيِّبَٰتِ وَٱعْمَلُوا۟ صَٰلِحًا ۖ إِنِّى بِمَا تَعْمَلُونَ عَلِيمٌۭ", 't': "«يا أيها الرسل كلوا من الطيبات» الحلالات «واعلموا صالحاً» من فرض ونفل «إني بما تعملون عليم» فأجازيكم عليه."},
  {'n': '52', 'v': "وَإِنَّ هَٰذِهِۦٓ أُمَّتُكُمْ أُمَّةًۭ وَٰحِدَةًۭ وَأَنَا۠ رَبُّكُمْ فَٱتَّقُونِ", 't': "«و» اعلموا «إنَّ هذه» أي ملة الإسلام «أمتكم» دينكم أيها المخاطبون أي يجب أن تكونوا عليها «أمة واحدة» حال لازمة وفي قراءة بتخفيف النون وفي أخرى بكسرها مشددة استئنافا «وأنا ربكم فاتقون» فاحذرون."},
  {'n': '53', 'v': "فَتَقَطَّعُوٓا۟ أَمْرَهُم بَيْنَهُمْ زُبُرًۭا ۖ كُلُّ حِزْبٍۭ بِمَا لَدَيْهِمْ فَرِحُونَ", 't': "«فتقطعوا» أي الأتباع «أمرهم» دينهم «بينهم زبرا» حال من فاعل تقطعوا أي أحزابا متخالفين كاليهود والنصارى وغيرهم «كل حزب بما لديهم» أي عندهم من الدين «فرحون» مسرورون."},
  {'n': '54', 'v': "فَذَرْهُمْ فِى غَمْرَتِهِمْ حَتَّىٰ حِينٍ", 't': "«فذرهم» اترك كفار مكة «في غمرتهم» ضلالتهم «حتى حين» إلى حين موتهم."},
  {'n': '55', 'v': "أَيَحْسَبُونَ أَنَّمَا نُمِدُّهُم بِهِۦ مِن مَّالٍۢ وَبَنِينَ", 't': "«أيحسبون أنما نمدهم به» نعطيهم «من مال وبنين» في الدنيا."},
  {'n': '56', 'v': "نُسَارِعُ لَهُمْ فِى ٱلْخَيْرَٰتِ ۚ بَل لَّا يَشْعُرُونَ", 't': "«نسارع» نعجل «لهم في الخيرات» لا «بل لا يشعرون» أن ذلك استدراج لهم."},
  {'n': '57', 'v': "إِنَّ ٱلَّذِينَ هُم مِّنْ خَشْيَةِ رَبِّهِم مُّشْفِقُونَ", 't': "«إن الذين هم من خشية ربهم» خوفهم منه «مشفقون» خائفون من عذابه."},
  {'n': '58', 'v': "وَٱلَّذِينَ هُم بِـَٔايَٰتِ رَبِّهِمْ يُؤْمِنُونَ", 't': "«والذين هم بآيات ربهم» القرآن «يؤمنون» يصدقون."},
  {'n': '59', 'v': "وَٱلَّذِينَ هُم بِرَبِّهِمْ لَا يُشْرِكُونَ", 't': "«والذين هم بربهم لا يشركون» معه غيره."},
  {'n': '60', 'v': "وَٱلَّذِينَ يُؤْتُونَ مَآ ءَاتَوا۟ وَّقُلُوبُهُمْ وَجِلَةٌ أَنَّهُمْ إِلَىٰ رَبِّهِمْ رَٰجِعُونَ", 't': "«والذين يؤتون» يعطون «ما آتوْا» أعطوا من الصدقة والأعمال الصالحة «وقلوبهم وجلة» خائفة أن لا تقبل منهم «أنهم» يقدر قبله لام الجر «إلى ربهم راجعون»."},
  {'n': '61', 'v': "أُو۟لَٰٓئِكَ يُسَٰرِعُونَ فِى ٱلْخَيْرَٰتِ وَهُمْ لَهَا سَٰبِقُونَ", 't': "«أولئك يسارعون في الخيرات وهم لها سابقون» في علم الله."},
  {'n': '62', 'v': "وَلَا نُكَلِّفُ نَفْسًا إِلَّا وُسْعَهَا ۖ وَلَدَيْنَا كِتَٰبٌۭ يَنطِقُ بِٱلْحَقِّ ۚ وَهُمْ لَا يُظْلَمُونَ", 't': "«ولا نكلف نفسا إلا وسعها» طاقتها فمن لم يستطع أن يصلي قائما فليصل جالسا، ومن لم يستطع أن يصوم فليأكل «ولدينا» عندنا «كتاب ينطق بالحق» بما عملته وهو واللوح المحفوظ تسطر فيه الأعمال «وهم» أي النفوس العاملة «لا يظلمون» شيئا منها فلا ينقص من ثواب أعمال الخيرات ولا يزاد في السيئات."},
  {'n': '63', 'v': "بَلْ قُلُوبُهُمْ فِى غَمْرَةٍۢ مِّنْ هَٰذَا وَلَهُمْ أَعْمَٰلٌۭ مِّن دُونِ ذَٰلِكَ هُمْ لَهَا عَٰمِلُونَ", 't': "«بل قلوبهم» أي الكفار «في غمره» جهالة «من هذا» القرآن «ولهم أعمال من دون ذلك» المذكور للمؤمنين «هم لها عاملون» فيعذبون عليها."},
  {'n': '64', 'v': "حَتَّىٰٓ إِذَآ أَخَذْنَا مُتْرَفِيهِم بِٱلْعَذَابِ إِذَا هُمْ يَجْـَٔرُونَ", 't': "«حتى» ابتدائية «إذا أخذنا مترفيهم» أغنياءهم ورؤساءهم «بالعذاب» أي السيف يوم بدر «إذا هم يجأرون» يضجون يقال لهم."},
  {'n': '65', 'v': "لَا تَجْـَٔرُوا۟ ٱلْيَوْمَ ۖ إِنَّكُم مِّنَّا لَا تُنصَرُونَ", 't': "«لا تجأروا اليوم إنكم منا لا تنصرون» لا تمنعون."},
  {'n': '66', 'v': "قَدْ كَانَتْ ءَايَٰتِى تُتْلَىٰ عَلَيْكُمْ فَكُنتُمْ عَلَىٰٓ أَعْقَٰبِكُمْ تَنكِصُونَ", 't': "«قد كانت آياتي» من القرآن «تتلى عليكم فكنتم على إعقابكم تنكصون» ترجعون القهقرى."},
  {'n': '67', 'v': "مُسْتَكْبِرِينَ بِهِۦ سَٰمِرًۭا تَهْجُرُونَ", 't': "«مستكبرين» عن الإيمان «به» أي بالبيت أو الحرم بأنهم أهله في أمن بخلاف سائر الناس في مواطنهم «سامرا» حال أي جماعة يتحدثون بالليل حول البيت «تهجرون» من الثلاثي تتركون القرآن، ومن الرباعي أي تقولن غير الحق في النبي والقرآن قال تعالى."},
  {'n': '68', 'v': "أَفَلَمْ يَدَّبَّرُوا۟ ٱلْقَوْلَ أَمْ جَآءَهُم مَّا لَمْ يَأْتِ ءَابَآءَهُمُ ٱلْأَوَّلِينَ", 't': "«أفلم يدَّبروا» أصله يتدبروا فأدغمت التاء في الدال «القول» أي القرآن الدال على صدق النبي «أم جاءهم ما لم يأت آباءهم الأولين»."},
  {'n': '69', 'v': "أَمْ لَمْ يَعْرِفُوا۟ رَسُولَهُمْ فَهُمْ لَهُۥ مُنكِرُونَ", 't': "«أم لم يعرفوا رسولهم فهم له منكرون»."},
  {'n': '70', 'v': "أَمْ يَقُولُونَ بِهِۦ جِنَّةٌۢ ۚ بَلْ جَآءَهُم بِٱلْحَقِّ وَأَكْثَرُهُمْ لِلْحَقِّ كَٰرِهُونَ", 't': "«أم يقولون به جنَّة» الاستفهام للتقرير بالحق من صدق النبيّ ومجيء الرسل للأمم الماضية ومعرفة رسولهم بالصدق والأمانة وأن لا جنون به «بل» للانتقال «جاءهم بالحق» أي القرآن المشتمل على التوحيد وشرائع الإسلام «وأكثرهم للحق كارهون»."},
  {'n': '71', 'v': "وَلَوِ ٱتَّبَعَ ٱلْحَقُّ أَهْوَآءَهُمْ لَفَسَدَتِ ٱلسَّمَٰوَٰتُ وَٱلْأَرْضُ وَمَن فِيهِنَّ ۚ بَلْ أَتَيْنَٰهُم بِذِكْرِهِمْ فَهُمْ عَن ذِكْرِهِم مُّعْرِضُونَ", 't': "«ولو اتبع الحق» أي القرآن «أهواءهم» بأن جاء بما يهوونه من الشريك والولد لله، تعالى الله عن ذلك: «لفسدت السماوات والأرض ومن فيهن» خرجت عن نظامها المشاهد لوجود التمانع في الشيء عادة عند تعدد الحاكم «بل أتيناهم بذكرهم» أي القرآن الذي فيه ذكرهم وشرفهم «فهم عن ذكرهم معرضون»."},
  {'n': '72', 'v': "أَمْ تَسْـَٔلُهُمْ خَرْجًۭا فَخَرَاجُ رَبِّكَ خَيْرٌۭ ۖ وَهُوَ خَيْرُ ٱلرَّٰزِقِينَ", 't': "«أم تسألهم خرجا» أجرا على ما جئتهم به من الإيمان «فخراج ربك» أجره وثوابه ورزقه «خير» وفي قراءة خرجا في الموضعين وفي قراءة أخرى خراجا فيهما «وهو خير الرازقين» أفضل من أعطى وآجر."},
  {'n': '73', 'v': "وَإِنَّكَ لَتَدْعُوهُمْ إِلَىٰ صِرَٰطٍۢ مُّسْتَقِيمٍۢ", 't': "«وإنك لتدعوهم إلى صراط» طريق «مستقيم» أي دين الإسلام."},
  {'n': '74', 'v': "وَإِنَّ ٱلَّذِينَ لَا يُؤْمِنُونَ بِٱلْءَاخِرَةِ عَنِ ٱلصِّرَٰطِ لَنَٰكِبُونَ", 't': "«وإن الذين لا يؤمنون بالآخرة» بالبعث والثواب والعقاب «عن الصراط» أي الطريق «لناكبون» عادلون."},
  {'n': '75', 'v': "۞ وَلَوْ رَحِمْنَٰهُمْ وَكَشَفْنَا مَا بِهِم مِّن ضُرٍّۢ لَّلَجُّوا۟ فِى طُغْيَٰنِهِمْ يَعْمَهُونَ", 't': "«ولو رحمناهم وكشفنا ما بهم من ضر» أي جوع أصابهم بمكة سبع سنين «للجوا» تمادوا «في طغيانهم» ضلالتهم «يعمهون» يترددون."},
  {'n': '76', 'v': "وَلَقَدْ أَخَذْنَٰهُم بِٱلْعَذَابِ فَمَا ٱسْتَكَانُوا۟ لِرَبِّهِمْ وَمَا يَتَضَرَّعُونَ", 't': "«ولقد أخذناهم بالعذاب» الجوع «فما استكانوا» تواضعوا «لربهم وما يتضرعون» يرغبون إلى الله بالدعاء."},
  {'n': '77', 'v': "حَتَّىٰٓ إِذَا فَتَحْنَا عَلَيْهِم بَابًۭا ذَا عَذَابٍۢ شَدِيدٍ إِذَا هُمْ فِيهِ مُبْلِسُونَ", 't': "«حتى» ابتدائية «إذا فتحنا عليهم بابا ذا» صاحب «عذاب شديد» هو يوم بدر بالقتل «إذا هم فيه مبلسون» آيسون من كل خير."},
