  {'n': '19', 'v': "فَقَدْ كَذَّبُوكُم بِمَا تَقُولُونَ فَمَا تَسْتَطِيعُونَ صَرْفًۭا وَلَا نَصْرًۭا ۚ وَمَن يَظْلِم مِّنكُمْ نُذِقْهُ عَذَابًۭا كَبِيرًۭا", 't': "«فقد كذبوكم» أي كذب المعبودون العابدين «بما تقولون» بالفوقانية أنهم آلهة «فما يستطيعون» بالتحتانية والفوقانية: أي لا هم ولا أنتم «صرفا» دفعا للعذاب عنكم «ولا نصرا» منعا لكم منه «ومن يظلم» يشرك «منكم نُذقْه عذابا كبيرا» شديدا في الآخرة."},
  {'n': '20', 'v': "وَمَآ أَرْسَلْنَا قَبْلَكَ مِنَ ٱلْمُرْسَلِينَ إِلَّآ إِنَّهُمْ لَيَأْكُلُونَ ٱلطَّعَامَ وَيَمْشُونَ فِى ٱلْأَسْوَاقِ ۗ وَجَعَلْنَا بَعْضَكُمْ لِبَعْضٍۢ فِتْنَةً أَتَصْبِرُونَ ۗ وَكَانَ رَبُّكَ بَصِيرًۭا", 't': "«وما أرسلنا قبلك من المرسلين إلا إنهم ليأكلون الطعام ويمشون في الأسواق» فأنت مثلهم في ذلك، وقد قيل لهم مثل ما قيل لك «وجلنا بعضكم لبعض فتنة» بلية ابتلى الغني بالفقير والصحيح بالمريض، والشريف بالوضيع يقول الثاني في كلّ: ما لي لا أكون كالأول في كلّ: «أتصبرون» على ما تسمعون ممن ابتليتم بهم استفهام بمعنى الأمر: أي اصبروا «وكان ربك بصيرا» بمن يصبر وبمن يجزع."},
  {'n': '21', 'v': "۞ وَقَالَ ٱلَّذِينَ لَا يَرْجُونَ لِقَآءَنَا لَوْلَآ أُنزِلَ عَلَيْنَا ٱلْمَلَٰٓئِكَةُ أَوْ نَرَىٰ رَبَّنَا ۗ لَقَدِ ٱسْتَكْبَرُوا۟ فِىٓ أَنفُسِهِمْ وَعَتَوْ عُتُوًّۭا كَبِيرًۭا", 't': "«وقال الذين لا يرجون لقاءنا» لا يخافون البعث «لولا» هلا «أنزل علينا الملائكة» فكانوا رسلا إلينا «أو نرى ربنا» فنخبر بأن محمدا رسوله قال تعالى: «لقد استكبروا» تكبروا «في» شأن «أنفسهم وعتوْا» طغوا «عُتُوَّا كبيرا» بطلبهم رؤية الله تعالى في الدنيا، وعتوا بالواو على أصله بخلاف عتى بالإبدال في مريم."},
  {'n': '22', 'v': "يَوْمَ يَرَوْنَ ٱلْمَلَٰٓئِكَةَ لَا بُشْرَىٰ يَوْمَئِذٍۢ لِّلْمُجْرِمِينَ وَيَقُولُونَ حِجْرًۭا مَّحْجُورًۭا", 't': "«يوم يرون الملائكة» في جملة الخلائق هو يوم القيامة ونصبه باذكر مقدرا «لا بشرى يومئذٍ للمجرمين» أي الكافرين بخلاف المؤمنين فلهم البشرى بالجنة «ويقولون حِجرا محجورا» على عادتهم في الدنيا إذا نزلت بهم شدة: أي عوذا معاذا يستعيذون من الملائكة، قال تعالى."},
  {'n': '23', 'v': "وَقَدِمْنَآ إِلَىٰ مَا عَمِلُوا۟ مِنْ عَمَلٍۢ فَجَعَلْنَٰهُ هَبَآءًۭ مَّنثُورًا", 't': "«وقدمنا» عمدنا «إلى ما عملوا من عمل» من الخير كصدقة وصلة رحم، وقرى ضيف وإغاثة ملهوف في الدنيا «فجعلناه هباءً منشورا» هو ما يرى في الكوى التي عليها الشمس كالغبار المفرق: أي مثله في عدم النفع به إذ لا ثواب فيه لعدم شرطه ويجازون عليه في الدنيا."},
  {'n': '24', 'v': "أَصْحَٰبُ ٱلْجَنَّةِ يَوْمَئِذٍ خَيْرٌۭ مُّسْتَقَرًّۭا وَأَحْسَنُ مَقِيلًۭا", 't': "«أصحاب الجنة يومئذ» يوم القيامة «خيرٌ مستقرا» من الكافرين في الدنيا «وأحسن مقيلا» منهم: أي موضع قائلة فيها، وهي الاستراحة نصف النهار في الحر، وأخذ من ذلك انقضاء الحساب في نصف نهار كما ورد في حديث."},
  {'n': '25', 'v': "وَيَوْمَ تَشَقَّقُ ٱلسَّمَآءُ بِٱلْغَمَٰمِ وَنُزِّلَ ٱلْمَلَٰٓئِكَةُ تَنزِيلًا", 't': "«ويوم تشقق السماء» أي كل سماء «بالغمام» أي معه وهو غيم أبيض «ونزّل الملائكة» من كل سماء «تنزيلا» هو يوم القيامة ونصبه باذكر مقدرا وفي قراءة بتشديد شين تشقق بإدغام التاء الثانية في الأصل فيها، وفي أخرى: ننزل بنونين الثانية ساكنة وضم اللام ونصب الملائكة."},
  {'n': '26', 'v': "ٱلْمُلْكُ يَوْمَئِذٍ ٱلْحَقُّ لِلرَّحْمَٰنِ ۚ وَكَانَ يَوْمًا عَلَى ٱلْكَٰفِرِينَ عَسِيرًۭا", 't': "«الملك يومئذ الحق للرحمن» لا يشركه فيه أحد «وكان» اليوم «يوما على الكافرين عسيرا» بخلاف المؤمنين."},
  {'n': '27', 'v': "وَيَوْمَ يَعَضُّ ٱلظَّالِمُ عَلَىٰ يَدَيْهِ يَقُولُ يَٰلَيْتَنِى ٱتَّخَذْتُ مَعَ ٱلرَّسُولِ سَبِيلًۭا", 't': "«ويوم يعضُّ الظالم» المشرك: عقبة بن أبي معيط كان نطق بالشهادتين ثم رجع إرضاءً لأبيّ بن خلف «على يديه» ندما وتحسرا في يوم القيامة «يقول يا» للتنبيه «ليتني اتخذت مع الرسول» محمد «سبيلا» طريقا إلى الهدى."},
  {'n': '28', 'v': "يَٰوَيْلَتَىٰ لَيْتَنِى لَمْ أَتَّخِذْ فُلَانًا خَلِيلًۭا", 't': "«يا وَيْلَتَى» ألفه عوض عن ياء الإضافة أي ويلتي، ومعناه هلكتي «ليتني لم أتخذ فلانا» أي أبيَّا «خليلا»."},
  {'n': '29', 'v': "لَّقَدْ أَضَلَّنِى عَنِ ٱلذِّكْرِ بَعْدَ إِذْ جَآءَنِى ۗ وَكَانَ ٱلشَّيْطَٰنُ لِلْإِنسَٰنِ خَذُولًۭا", 't': "«لقد أضلني عن الذكر» أي القرآن «بعد إذ جاءني» بأن ردَّني عن الإيمان به، قال تعالى: «وكان الشيطان للإنسان» الكافر «خذولا» بأن يتركه ويتبرأ منه عند البلاء."},
  {'n': '30', 'v': "وَقَالَ ٱلرَّسُولُ يَٰرَبِّ إِنَّ قَوْمِى ٱتَّخَذُوا۟ هَٰذَا ٱلْقُرْءَانَ مَهْجُورًۭا", 't': "«وقال الرسول» محمد «يا رب إن قومي» قريشا «اتخذوا هذا القرآن مهجورا» متروكا قال تعالى."},
  {'n': '31', 'v': "وَكَذَٰلِكَ جَعَلْنَا لِكُلِّ نَبِىٍّ عَدُوًّۭا مِّنَ ٱلْمُجْرِمِينَ ۗ وَكَفَىٰ بِرَبِّكَ هَادِيًۭا وَنَصِيرًۭا", 't': "«وكذلك» كما جعلنا لك عدوّا من مشركي قومك «جعلنا لكل نبي» قبلك «عدوا من المجرمين» المشركين فاصبر كما صبروا «وكفى بربك هاديا» لك «ونصيرا» ناصرا لك على أعدائك."},
  {'n': '32', 'v': "وَقَالَ ٱلَّذِينَ كَفَرُوا۟ لَوْلَا نُزِّلَ عَلَيْهِ ٱلْقُرْءَانُ جُمْلَةًۭ وَٰحِدَةًۭ ۚ كَذَٰلِكَ لِنُثَبِّتَ بِهِۦ فُؤَادَكَ ۖ وَرَتَّلْنَٰهُ تَرْتِيلًۭا", 't': "«وقال الذين كفروا لولا» هلا «نزل عليه القرآن جملة واحدة» كالتوراة والإنجيل والزَّبور، قال تعالى: نزلناه، «كذلك» متفرّقا «لنثبَّت به فؤادك» نقوي قلبك «ورتلناه ترتيلا» أي أتينا به شيئا بعد شيء بتمهل وتؤدة لتيسر فهمه وحفظه."},
  {'n': '33', 'v': "وَلَا يَأْتُونَكَ بِمَثَلٍ إِلَّا جِئْنَٰكَ بِٱلْحَقِّ وَأَحْسَنَ تَفْسِيرًا", 't': "«ولا يأتونك بمثل» في إبطال أمرك «إلا جئناك بالحق» الدافع له «وأحسن تفسيرا» بيانا."},
  {'n': '34', 'v': "ٱلَّذِينَ يُحْشَرُونَ عَلَىٰ وُجُوهِهِمْ إِلَىٰ جَهَنَّمَ أُو۟لَٰٓئِكَ شَرٌّۭ مَّكَانًۭا وَأَضَلُّ سَبِيلًۭا", 't': "هم «الذين يُحشرون على وجوههم» أي يساقون «إلى جهنم أولئك شرٌ مكانا» هو جهنم «وأضَلُّ سبيلا» أخطأ طريقا من غيرهم وهو كفرهم."},
  {'n': '35', 'v': "وَلَقَدْ ءَاتَيْنَا مُوسَى ٱلْكِتَٰبَ وَجَعَلْنَا مَعَهُۥٓ أَخَاهُ هَٰرُونَ وَزِيرًۭا", 't': "«ولقد آتينا موسى الكتاب» التوراة «وجعلنا معه أخاه هارون وزيرا» معينا."},
  {'n': '36', 'v': "فَقُلْنَا ٱذْهَبَآ إِلَى ٱلْقَوْمِ ٱلَّذِينَ كَذَّبُوا۟ بِـَٔايَٰتِنَا فَدَمَّرْنَٰهُمْ تَدْمِيرًۭا", 't': "«فقلنا اذهبا إلى القوم الذين كذبوا بآياتنا» أي القبط فرعون وقومه فذهبا إليهم بالرسالة فكذبوهما «فدمرناهم تدميرا» أهلكناهم إهلاكا."},
  {'n': '37', 'v': "وَقَوْمَ نُوحٍۢ لَّمَّا كَذَّبُوا۟ ٱلرُّسُلَ أَغْرَقْنَٰهُمْ وَجَعَلْنَٰهُمْ لِلنَّاسِ ءَايَةًۭ ۖ وَأَعْتَدْنَا لِلظَّٰلِمِينَ عَذَابًا أَلِيمًۭا", 't': "«و» اذكر «قوم نوح لما كذبوا الرسل» بتكذيبهم نوحا لطول لبثه فيهم فكأنه رسل، أو لأن تكذيبه تكذيب لباقي الرسل لاشتراكهم في المجيء بالتوحيد «أغرقناهم» جواب لما «وجعلناهم للناس» بعدهم «آية» عبرة «وأعتدنا» في الآخرة «للظالمين» الكافرين «عذابا أليما» مؤلما سوى ما يحل بهم في الدنيا."},
  {'n': '38', 'v': "وَعَادًۭا وَثَمُودَا۟ وَأَصْحَٰبَ ٱلرَّسِّ وَقُرُونًۢا بَيْنَ ذَٰلِكَ كَثِيرًۭا", 't': "«و» اذكر «عادا» يوم هود «وثمود» قوم صالح «وأصحاب الرَّسَّ» اسم بئر، ونبيهم قيل شعيب وقيل غيره كانوا قعودا حولها فانهارت بهم وبمنازلهم «وقرونا» أقواما «بين ذلك كثيرا» أي بين عاد وأصحاب الرَّسَّ."},
  {'n': '39', 'v': "وَكُلًّۭا ضَرَبْنَا لَهُ ٱلْأَمْثَٰلَ ۖ وَكُلًّۭا تَبَّرْنَا تَتْبِيرًۭا", 't': "«وكلا ضربنا له الأمثال» في إقامة الحجة عليهم فلم نهلكهم إلا بعد الإنذار «وكلاٌ تبَّرنا تتبيرا» أهلكنا إهلاكا بتكذيبهم أنبياءهم."},
  {'n': '40', 'v': "وَلَقَدْ أَتَوْا۟ عَلَى ٱلْقَرْيَةِ ٱلَّتِىٓ أُمْطِرَتْ مَطَرَ ٱلسَّوْءِ ۚ أَفَلَمْ يَكُونُوا۟ يَرَوْنَهَا ۚ بَلْ كَانُوا۟ لَا يَرْجُونَ نُشُورًۭا", 't': "«ولقد أتوا» أي مرَّ كفار مكة «على القرية التي أمطرت مطر السوء» مصدر ساء أي بالحجارة وهي عظمى قرى قوم لوط فأهلك الله أهلها لفعلهم الفاحشة «أفلم يكونوا يرونَها» في سفرهم إلى الشام فيعتبرون، والاستفهام للتقرير «بل كانوا لا يرجون» يخافون «نشورا» بعثا فلا يؤمنون."},
  {'n': '41', 'v': "وَإِذَا رَأَوْكَ إِن يَتَّخِذُونَكَ إِلَّا هُزُوًا أَهَٰذَا ٱلَّذِى بَعَثَ ٱللَّهُ رَسُولًا", 't': "«وإذا رأوْك إن» ما «يتخذونك إلا هزؤا» مهزوءا به يقولن «أهذا الذي بعث الله رسولا» في دعواه محتقرين له عن الرسالة."},
  {'n': '42', 'v': "إِن كَادَ لَيُضِلُّنَا عَنْ ءَالِهَتِنَا لَوْلَآ أَن صَبَرْنَا عَلَيْهَا ۚ وَسَوْفَ يَعْلَمُونَ حِينَ يَرَوْنَ ٱلْعَذَابَ مَنْ أَضَلُّ سَبِيلًا", 't': "«إن» مخففة من الثقيلة واسمها محذوف أي إنه «كاد ليضلنا» يصرفنا «عن آلهتنا لولا أن صبرنا عليها» لصرفنا عنها، قال تعالى: «وسوف يعلمون حين يرون العذاب» عينانا في الآخرة «من أضلُّ سبيلا» أخطأ طريقا، أهم أم المؤمنون."},
  {'n': '43', 'v': "أَرَءَيْتَ مَنِ ٱتَّخَذَ إِلَٰهَهُۥ هَوَىٰهُ أَفَأَنتَ تَكُونُ عَلَيْهِ وَكِيلًا", 't': "«أرأيت» أخبرني «من اتخذ إلههُ هواه» أي مُهويه قدَّم المفعول الثاني لأنه أهمّ وجملة من اتخذ مفعول أول لرأيت والثاني «أفأنت تكون عليه وكيلا» حافظا تحفظه عن ابتاع هواه لا."},
  {'n': '44', 'v': "أَمْ تَحْسَبُ أَنَّ أَكْثَرَهُمْ يَسْمَعُونَ أَوْ يَعْقِلُونَ ۚ إِنْ هُمْ إِلَّا كَٱلْأَنْعَٰمِ ۖ بَلْ هُمْ أَضَلُّ سَبِيلًا", 't': "«أم تحسب أن أكثرهم يسمعون» سماع تفهم «أو يعقلون» ما تقول لهم «إن» ما «هم إلا كالأنعام بل هم أضل سبيلا» أخطأ طريقا منها لأنها تنقاد لمن يتعهدها، وهم لا يطيعون مولاهم المنعم عليهم."},
  {'n': '45', 'v': "أَلَمْ تَرَ إِلَىٰ رَبِّكَ كَيْفَ مَدَّ ٱلظِّلَّ وَلَوْ شَآءَ لَجَعَلَهُۥ سَاكِنًۭا ثُمَّ جَعَلْنَا ٱلشَّمْسَ عَلَيْهِ دَلِيلًۭا", 't': "«ألم تَرَ» تنظر «إلى» فعل «ربّك كيف مدَّ الظل» من وقت الإسفار إلى وقت طلوع الشمس «ولو شاء» ربك «لجعله ساكنا» مقيما لا يزول بطلوع الشمس «ثم جعلنا الشمس عليه» أي الظل «دليلا» فلولا الشمس ما عرف الظل."},
  {'n': '46', 'v': "ثُمَّ قَبَضْنَٰهُ إِلَيْنَا قَبْضًۭا يَسِيرًۭا", 't': "«ثم قبضناه» أي الظل الممدود «إلينا قبضا يسيرا» خفيفا بطلوع الشمس."},
  {'n': '47', 'v': "وَهُوَ ٱلَّذِى جَعَلَ لَكُمُ ٱلَّيْلَ لِبَاسًۭا وَٱلنَّوْمَ سُبَاتًۭا وَجَعَلَ ٱلنَّهَارَ نُشُورًۭا", 't': "«وهو الذي جعل لكم الليل لباسا» ساترا كاللباس «والنوم سُباتا» راحة للأبدان بقطع الأعمال «وجعل النهار نشورا» منشورا فيه لابتغاء الرزق وغيره."},
