  {'n': '3', 'v': "لَعَلَّكَ بَٰخِعٌۭ نَّفْسَكَ أَلَّا يَكُونُوا۟ مُؤْمِنِينَ", 't': "«لعلك» يا محمد «باخعٌ نفسك» قاتلها غما من أجل «ألا يكونوا» أي أهل مكة «مؤمنين» ولعل هنا للإشفاق أي أشفق عليها بتخفيف هذا الغم."},
  {'n': '4', 'v': "إِن نَّشَأْ نُنَزِّلْ عَلَيْهِم مِّنَ ٱلسَّمَآءِ ءَايَةًۭ فَظَلَّتْ أَعْنَٰقُهُمْ لَهَا خَٰضِعِينَ", 't': "«إن نشأ ننزل عليهم من السماء آية فظلّت» بمعنى المضارع: أي تظل، أي تدوم «أعناقهم لها خاضعين» فيؤمنون، ولما وصفت الأعناق بالخضوع الذي هو لأربابها جمعت الصفة جمع العقلاء."},
  {'n': '5', 'v': "وَمَا يَأْتِيهِم مِّن ذِكْرٍۢ مِّنَ ٱلرَّحْمَٰنِ مُحْدَثٍ إِلَّا كَانُوا۟ عَنْهُ مُعْرِضِينَ", 't': "«وما يأتيهم من ذكر» قرآن «من الرحمن مُحدّث» صفة كاشفة «إلا كانوا عنه معرضين»."},
  {'n': '6', 'v': "فَقَدْ كَذَّبُوا۟ فَسَيَأْتِيهِمْ أَنۢبَٰٓؤُا۟ مَا كَانُوا۟ بِهِۦ يَسْتَهْزِءُونَ", 't': "«فقد كذبوا» به «فسيأتيهم أنباء» عواقب «ما كانوا به يستهزءُون»."},
  {'n': '7', 'v': "أَوَلَمْ يَرَوْا۟ إِلَى ٱلْأَرْضِ كَمْ أَنۢبَتْنَا فِيهَا مِن كُلِّ زَوْجٍۢ كَرِيمٍ", 't': "«أوَلم يروا» ينظروا «إلى الأرض كم أنبتنا فيها» أي كثيرا «من كل زوجِ كريم» نوع حسن."},
  {'n': '8', 'v': "إِنَّ فِى ذَٰلِكَ لَءَايَةًۭ ۖ وَمَا كَانَ أَكْثَرُهُم مُّؤْمِنِينَ", 't': "«إن في ذلك لآية» دلالة على كمال قدرته تعالى «وما كان أكثرهم مؤمنين» في علم الله، وكان قال سيبويه: زائدة."},
  {'n': '9', 'v': "وَإِنَّ رَبَّكَ لَهُوَ ٱلْعَزِيزُ ٱلرَّحِيمُ", 't': "«وإن ربك لهو العزيز» ذو العزة ينتقم من الكافرين «الرحيم» يرحم المؤمنين."},
  {'n': '10', 'v': "وَإِذْ نَادَىٰ رَبُّكَ مُوسَىٰٓ أَنِ ٱئْتِ ٱلْقَوْمَ ٱلظَّٰلِمِينَ", 't': "«و» اذكر يا محمد لقومك «إذ نادى ربك موسى» ليلة رأى النار والشجرة «أن» أي: بأن «ائت القوم الظالمين» رسولا."},
  {'n': '11', 'v': "قَوْمَ فِرْعَوْنَ ۚ أَلَا يَتَّقُونَ", 't': "«قوم فرعون» معه ظلموا أنفسهم بالكفر بالله وبني إسرائيل باستعبادهم «ألا» الهمزة للاستفهام الإنكارى «يتقون» الله بطاعته فيوحدونه."},
  {'n': '12', 'v': "قَالَ رَبِّ إِنِّىٓ أَخَافُ أَن يُكَذِّبُونِ", 't': "«قال» موسى «ربِ إني أخاف أن يكذّبون»."},
  {'n': '13', 'v': "وَيَضِيقُ صَدْرِى وَلَا يَنطَلِقُ لِسَانِى فَأَرْسِلْ إِلَىٰ هَٰرُونَ", 't': "«ويضيق صدري» من تكذيبهم لي «ولا ينطلق لساني» بأداء الرسالة للعقدة التي فيه «فأرسل إلى» أخي «هارون» معي."},
  {'n': '14', 'v': "وَلَهُمْ عَلَىَّ ذَنۢبٌۭ فَأَخَافُ أَن يَقْتُلُونِ", 't': "«ولهم عليَّ ذنبٌ» بقتل القبطي منهم «فأخاف أن يقتلون» به."},
  {'n': '15', 'v': "قَالَ كَلَّا ۖ فَٱذْهَبَا بِـَٔايَٰتِنَآ ۖ إِنَّا مَعَكُم مُّسْتَمِعُونَ", 't': "«قال» تعالى: «كلا» لا يقتلونك «فاذهبا» أي أنت وأخوك، ففيه تغليب الحاضر على الغائب «بآياتنا إنا معكم مستمعون» ما تقولون وما يقال لكم، أجريا مجرى الجماعة."},
  {'n': '16', 'v': "فَأْتِيَا فِرْعَوْنَ فَقُولَآ إِنَّا رَسُولُ رَبِّ ٱلْعَٰلَمِينَ", 't': "«فأتِيَا فرعون فقولا إنا» كلاً منا «رسول رب العالمين» إليك."},
  {'n': '17', 'v': "أَنْ أَرْسِلْ مَعَنَا بَنِىٓ إِسْرَٰٓءِيلَ", 't': "«أن» أي: بأن «أرسل معنا» إلى الشام «بني إسرائيل» فأتياه فقالا له ما ذكر."},
  {'n': '18', 'v': "قَالَ أَلَمْ نُرَبِّكَ فِينَا وَلِيدًۭا وَلَبِثْتَ فِينَا مِنْ عُمُرِكَ سِنِينَ", 't': "«قال» فرعون لموسى «ألم نربِّك فينا» في منازلنا «وليدا» صغيرا قريبا من الولادة بعد فطامه «ولبثت فينا من عمرك سنين» ثلاثين سنة يلبس من ملابس فرعون ويركب من مراكبه وكان يسمى ابنه."},
  {'n': '19', 'v': "وَفَعَلْتَ فَعْلَتَكَ ٱلَّتِى فَعَلْتَ وَأَنتَ مِنَ ٱلْكَٰفِرِينَ", 't': "«وفعلت فعلتك التي فعلت» هي قتله القبطي «وأنت من الكافرين» الجاحدين لنعمتي عليك بالتربية وعدم الاستعباد."},
  {'n': '20', 'v': "قَالَ فَعَلْتُهَآ إِذًۭا وَأَنَا۠ مِنَ ٱلضَّآلِّينَ", 't': "«قال» موسى «فعلتها إذاً» أي حينئذ «وأنا من الضالين» عما آتاني الله بعدها من العلم والرسالة."},
  {'n': '21', 'v': "فَفَرَرْتُ مِنكُمْ لَمَّا خِفْتُكُمْ فَوَهَبَ لِى رَبِّى حُكْمًۭا وَجَعَلَنِى مِنَ ٱلْمُرْسَلِينَ", 't': "«ففررتُ منكم لما خفتكم فوهب لي ربي حكما» علما «وجعلني من المرسلين»."},
  {'n': '22', 'v': "وَتِلْكَ نِعْمَةٌۭ تَمُنُّهَا عَلَىَّ أَنْ عَبَّدتَّ بَنِىٓ إِسْرَٰٓءِيلَ", 't': "«وتلك نعمةٌ تمنُّها عليَّ» أصله تمن بها عليَّ «أن عبدت بني إسرائيل» بيان لتلك: أي اتخذتهم عبيدا ولم تستعبدني لا نعمة لك بذلك لظلمك باستعبادهم وقدر بعضهم أول الكلام همزة استفهام للإنكار."},
  {'n': '23', 'v': "قَالَ فِرْعَوْنُ وَمَا رَبُّ ٱلْعَٰلَمِينَ", 't': "«قال فرعون» لموسى «وما رب العالمين» الذي قلت إنك رسوله أي: أي شيء هو ولما لم يكن سبيل للخلق إلى معرفة حقيقته تعالى وإنما يعرفونه بصفاته أجابه موسى عليه الصلاة والسلام ببعضها."},
  {'n': '24', 'v': "قَالَ رَبُّ ٱلسَّمَٰوَٰتِ وَٱلْأَرْضِ وَمَا بَيْنَهُمَآ ۖ إِن كُنتُم مُّوقِنِينَ", 't': "«قال ربُّ السماوات والأرض وما بينهما» أي خالق ذلك «إن كنتم موقنين» بأنه تعالى خالقه فآمنوا به وحده."},
  {'n': '25', 'v': "قَالَ لِمَنْ حَوْلَهُۥٓ أَلَا تَسْتَمِعُونَ", 't': "«قال» فرعون «لمن حوله» من أشراف قومه «ألا تستمعون» جوابه الذي لم يطابق السؤال."},
  {'n': '26', 'v': "قَالَ رَبُّكُمْ وَرَبُّ ءَابَآئِكُمُ ٱلْأَوَّلِينَ", 't': "«قال» موسى «ربكم ورب آبائكم الأولين» وهذا وإن كان داخلا فيما قبله يغيظ فرعون ولذلك."},
  {'n': '27', 'v': "قَالَ إِنَّ رَسُولَكُمُ ٱلَّذِىٓ أُرْسِلَ إِلَيْكُمْ لَمَجْنُونٌۭ", 't': "«قال إنَّ رسولكم الذي أرسل إليكم لمجنون»."},
  {'n': '28', 'v': "قَالَ رَبُّ ٱلْمَشْرِقِ وَٱلْمَغْرِبِ وَمَا بَيْنَهُمَآ ۖ إِن كُنتُمْ تَعْقِلُونَ", 't': "«قال» موسى «ربُّ المشرق والمغرب وما بينهما إن كنتم تعقلون» إنه كذلك فآمنوا به وحده."},
  {'n': '29', 'v': "قَالَ لَئِنِ ٱتَّخَذْتَ إِلَٰهًا غَيْرِى لَأَجْعَلَنَّكَ مِنَ ٱلْمَسْجُونِينَ", 't': "«قال» فرعون لموسى «لئن اتخذت إلها غيري لأجعلنَّك من المسجونين» كان سجنه شديدا يحبس الشخص في مكان تحت الأرض وحده لا يبصر ولا يسمع فيه أحدا."},
  {'n': '30', 'v': "قَالَ أَوَلَوْ جِئْتُكَ بِشَىْءٍۢ مُّبِينٍۢ", 't': "«قال» له موسى «أوَلوْ» أي: أتفعل ذلك ولو «جئتك بشيءٍ مبينِ» برهان بيِّن على رسالتي."},
  {'n': '31', 'v': "قَالَ فَأْتِ بِهِۦٓ إِن كُنتَ مِنَ ٱلصَّٰدِقِينَ", 't': "«قال» فرعون له «فأتِ به إن كنت من الصادقين» فيه."},
  {'n': '32', 'v': "فَأَلْقَىٰ عَصَاهُ فَإِذَا هِىَ ثُعْبَانٌۭ مُّبِينٌۭ", 't': "«فألقى عصاه فإذا هي ثعبانٌ مبينٌ» حية عظيمة."},
  {'n': '33', 'v': "وَنَزَعَ يَدَهُۥ فَإِذَا هِىَ بَيْضَآءُ لِلنَّٰظِرِينَ", 't': "«ونزع يده» أخرجها من جيبه «فإذا هي بيضاء» ذات شعاع «للناظرين» خلاف ما كانت عليه من الأدمة."},
  {'n': '34', 'v': "قَالَ لِلْمَلَإِ حَوْلَهُۥٓ إِنَّ هَٰذَا لَسَٰحِرٌ عَلِيمٌۭ", 't': "«قال» فرعون «للملإ حوله إنَّ هذا لساحر عليم» فائق في علم السحر."},
  {'n': '35', 'v': "يُرِيدُ أَن يُخْرِجَكُم مِّنْ أَرْضِكُم بِسِحْرِهِۦ فَمَاذَا تَأْمُرُونَ", 't': "«يريد أن يخرجكم من أرضكم بسحره فماذا تأمرون»."},
  {'n': '36', 'v': "قَالُوٓا۟ أَرْجِهْ وَأَخَاهُ وَٱبْعَثْ فِى ٱلْمَدَآئِنِ حَٰشِرِينَ", 't': "«قالوا أرجه وأخاه» أخّر أمرهما «وابعث في المدائن حاشرين» جامعين."},
  {'n': '37', 'v': "يَأْتُوكَ بِكُلِّ سَحَّارٍ عَلِيمٍۢ", 't': "«يأتوك بكل سَحَّار عليم» يفضل موسى في علم السحر."},
  {'n': '38', 'v': "فَجُمِعَ ٱلسَّحَرَةُ لِمِيقَٰتِ يَوْمٍۢ مَّعْلُومٍۢ", 't': "«فجمع السحرة لميقات يوم معلوم» وهو وقت الضحى من يوم الزينة."},
  {'n': '39', 'v': "وَقِيلَ لِلنَّاسِ هَلْ أَنتُم مُّجْتَمِعُونَ", 't': "«وقيل للناس هل أنتم مجتمعون»."},
  {'n': '40', 'v': "لَعَلَّنَا نَتَّبِعُ ٱلسَّحَرَةَ إِن كَانُوا۟ هُمُ ٱلْغَٰلِبِينَ", 't': "«لعلنا نتبع السحرة إن كانوا هم الغالبين» الاستفهام للحث على الاجتماع والترجي على تقدير غلبتهم ليستمروا على دينهم فلا يتبعوا موسى."},
  {'n': '41', 'v': "فَلَمَّا جَآءَ ٱلسَّحَرَةُ قَالُوا۟ لِفِرْعَوْنَ أَئِنَّ لَنَا لَأَجْرًا إِن كُنَّا نَحْنُ ٱلْغَٰلِبِينَ", 't': "«فلما جاء السحرة قالوا لفرعون أئن» بتحقيق الهمزتين وتسهيل الثانية وإدخال ألف بينهما على الوجيهين «لنا لأجرا إن كنا نحن الغالبين»."},
  {'n': '42', 'v': "قَالَ نَعَمْ وَإِنَّكُمْ إِذًۭا لَّمِنَ ٱلْمُقَرَّبِينَ", 't': "«قال نعم وإنكم إذاً» أي حينئذ «لمن المقربين»."},
  {'n': '43', 'v': "قَالَ لَهُم مُّوسَىٰٓ أَلْقُوا۟ مَآ أَنتُم مُّلْقُونَ", 't': "«قال لهم موسى» بعد ما قالوا له (إما أن تُلقي وإما أن نكون نحن الملقين) «ألقوا ما أنتم ملقون» فالأمر فيه للإذن بتقديم إلقائهم توسلا به إلى إظهار الحق."},
  {'n': '44', 'v': "فَأَلْقَوْا۟ حِبَالَهُمْ وَعِصِيَّهُمْ وَقَالُوا۟ بِعِزَّةِ فِرْعَوْنَ إِنَّا لَنَحْنُ ٱلْغَٰلِبُونَ", 't': "«فألقوْا حبالهم وعصيهم وقالوا بعزة فرعون إنا لنحن الغالبون»."},
  {'n': '45', 'v': "فَأَلْقَىٰ مُوسَىٰ عَصَاهُ فَإِذَا هِىَ تَلْقَفُ مَا يَأْفِكُونَ", 't': "«فألقى موسى عصاه فإذا هي تلقف» بحذف إحدى التاءين من الأصل تبتلع «ما يأفكون» يقلبونه بتمويههم فيخيلون حبالهم وعصيهم أنها حيات تسعى."},
  {'n': '46', 'v': "فَأُلْقِىَ ٱلسَّحَرَةُ سَٰجِدِينَ", 't': "«فألقيَ السحرة ساجدين»."},
  {'n': '47', 'v': "قَالُوٓا۟ ءَامَنَّا بِرَبِّ ٱلْعَٰلَمِينَ", 't': "«قالوا آمنا برب العالمين»."},
  {'n': '48', 'v': "رَبِّ مُوسَىٰ وَهَٰرُونَ", 't': "«رب موسى وهارون» لعلمهم بأن ما شاهدوه من العصا لا يتأتى بالسحر."},
  {'n': '49', 'v': "قَالَ ءَامَنتُمْ لَهُۥ قَبْلَ أَنْ ءَاذَنَ لَكُمْ ۖ إِنَّهُۥ لَكَبِيرُكُمُ ٱلَّذِى عَلَّمَكُمُ ٱلسِّحْرَ فَلَسَوْفَ تَعْلَمُونَ ۚ لَأُقَطِّعَنَّ أَيْدِيَكُمْ وَأَرْجُلَكُم مِّنْ خِلَٰفٍۢ وَلَأُصَلِّبَنَّكُمْ أَجْمَعِينَ", 't': "«قال» فرعون «أآمنتم» بتحقيق الهمزتين وإبدال الثانية ألفا «له» لموسى «قبل أن آذن» أنا «لكم إنه لكبيركم الذي علمكم السحر» فعلَّمك شيئا منه وغلبكم بآخر «فلسوف تعلمون» ما ينالكم مني «لأقطعنَّ أيديكم وأرجلكم من خلاف» أي يد كل واحد اليمنى ورجله اليسرى «ولأصلبنكم أجمعين»."},
  {'n': '50', 'v': "قَالُوا۟ لَا ضَيْرَ ۖ إِنَّآ إِلَىٰ رَبِّنَا مُنقَلِبُونَ", 't': "«قالوا لا ضَيْرَ» لا ضرر علينا في ذلك «إنا إلى ربنا» بعد موتنا بأي وجه كان «منقلبون» راجعون في الآخرة."},
  {'n': '51', 'v': "إِنَّا نَطْمَعُ أَن يَغْفِرَ لَنَا رَبُّنَا خَطَٰيَٰنَآ أَن كُنَّآ أَوَّلَ ٱلْمُؤْمِنِينَ", 't': "«إنا نطمع» نرجوا «أن يغفر لنا ربنا خطايانا أن» أي بأن «كنَّا أول المؤمنين» في زماننا."},
  {'n': '52', 'v': "۞ وَأَوْحَيْنَآ إِلَىٰ مُوسَىٰٓ أَنْ أَسْرِ بِعِبَادِىٓ إِنَّكُم مُّتَّبَعُونَ", 't': "«وأوحينا إلى موسى» بعد سنين أقامها بينهم يدعوهم بآيات الله إلى الحق فلم يزيدوا إلا عتوا «أن أسر بعبادي» بني إسرائيل وفي قراءة بكسر النون ووصل همزة أسر من سرى لغة في أسرى أي سر بهم ليلا إلى البحر «إنكم مُتَّبعون» يتبعكم فرعون وجنوده فيلجون وراءكم البحر فأنجيكم وأغرقهم."},
  {'n': '53', 'v': "فَأَرْسَلَ فِرْعَوْنُ فِى ٱلْمَدَآئِنِ حَٰشِرِينَ", 't': "«فأرسل فرعون» حين أخبر بسيرهم «في المدائن» قيل كان له ألف مدينة واثنا عشر ألف قرية «حاشرين» جامعين الجيش قائلا."},
  {'n': '54', 'v': "إِنَّ هَٰٓؤُلَآءِ لَشِرْذِمَةٌۭ قَلِيلُونَ", 't': "«إن هؤلاء لشرذمةٌ» طائفة «قليلون» قيل كانوا ستمائة ألف وسبعين ومقدمة جيشه سبعمائة ألف فقللهم بالنظر إلى كثرة جيشه."},
  {'n': '55', 'v': "وَإِنَّهُمْ لَنَا لَغَآئِظُونَ", 't': "«وإنهم لنا لغائظون» فاعلون ما يغيظنا."},
  {'n': '56', 'v': "وَإِنَّا لَجَمِيعٌ حَٰذِرُونَ", 't': "«وإنا لجميعٌ حذرون» مستعدون وفي قراءة حاذرون متيقظون."},
  {'n': '57', 'v': "فَأَخْرَجْنَٰهُم مِّن جَنَّٰتٍۢ وَعُيُونٍۢ", 't': "قال تعالى: «فأخرجناهم» أي فرعون وقومه من مصر ليلحقوا موسى وقومه «من جنات» بساتين كانت على جانبي النيل «وعيون» أنهار جارية في الدور من النيل."},
  {'n': '58', 'v': "وَكُنُوزٍۢ وَمَقَامٍۢ كَرِيمٍۢ", 't': "«وكنوز» أموال ظاهرة من الذهب والفضة، وسميت كنوزا لأنه لم يعط حق الله تعالى منها «ومقامٍ كريمٍ» مجلس حسن للأمراء والوزراء يحفه أتباعهم."},
  {'n': '59', 'v': "كَذَٰلِكَ وَأَوْرَثْنَٰهَا بَنِىٓ إِسْرَٰٓءِيلَ", 't': "«كذلك» أي إخراجنا كما وصفنا «وأورثناها بني إسرائيل» بعد إغراق فرعون وقومه."},
  {'n': '60', 'v': "فَأَتْبَعُوهُم مُّشْرِقِينَ", 't': "«فأتبعوهم» لحقوهم «مشرقين» وقت شروق الشمس."},
  {'n': '61', 'v': "فَلَمَّا تَرَٰٓءَا ٱلْجَمْعَانِ قَالَ أَصْحَٰبُ مُوسَىٰٓ إِنَّا لَمُدْرَكُونَ", 't': "«فلما تراءى الجمعان» رأى كل منهما الآخر «قال أصحاب موسى إنا لمدركون» يدركنا جمع فرعون ولا طاقة لنا به."},
  {'n': '62', 'v': "قَالَ كَلَّآ ۖ إِنَّ مَعِىَ رَبِّى سَيَهْدِينِ", 't': "«قال» موسى «كلا» أي لن يدركونا «إن معي ربي» ينصره «سيهدين» طريق النجاة."},
  {'n': '63', 'v': "فَأَوْحَيْنَآ إِلَىٰ مُوسَىٰٓ أَنِ ٱضْرِب بِّعَصَاكَ ٱلْبَحْرَ ۖ فَٱنفَلَقَ فَكَانَ كُلُّ فِرْقٍۢ كَٱلطَّوْدِ ٱلْعَظِيمِ", 't': "قال تعالى: «فأوحينا إلى موسى أن اضرب بعصاك البحر» فضربه «فانفلق» فانشق اثنى عشر فرقا «فكان كل فرق كالطود العظيم» الجبل الضخم بينهما مسالك سلكوها لم يبتل منها سرج الراكب ولا لبده."},
  {'n': '64', 'v': "وَأَزْلَفْنَا ثَمَّ ٱلْءَاخَرِينَ", 't': "«وأزلفنا» قرَّبنا «ثمَّ» هناك «الآخرين» فرعون وقومه حتى سلكوا مسالكهم."},
  {'n': '65', 'v': "وَأَنجَيْنَا مُوسَىٰ وَمَن مَّعَهُۥٓ أَجْمَعِينَ", 't': "«وأنجينا موسى ومن معه أجمعين» بإخراجهم من البحر على هيئته المذكورة."},
  {'n': '66', 'v': "ثُمَّ أَغْرَقْنَا ٱلْءَاخَرِينَ", 't': "«ثم أغرقنا الآخرين» فرعون وقومه بإطباق البحر عليهم لما تم دخولهم في البحر وخروج بني إسرائيل منه."},
  {'n': '67', 'v': "إِنَّ فِى ذَٰلِكَ لَءَايَةًۭ ۖ وَمَا كَانَ أَكْثَرُهُم مُّؤْمِنِينَ", 't': "«إن في ذلك» إغراق فرعون وقومه «لآيةٌ» عبرة لمن بعدهم «وما كان أكثرهم مؤمنين» بالله لم يؤمن منهم غير آسية امرأة فرعون وحزقيل مؤمن آل فرعون ومريم بنت ناموصى التي دلت على عظام يوسف عليه السلام."},
  {'n': '68', 'v': "وَإِنَّ رَبَّكَ لَهُوَ ٱلْعَزِيزُ ٱلرَّحِيمُ", 't': "«وإن ربك لهو العزيز» فانتقم من الكافرين بإغراقهم «الرحيم» بالمؤمنين فأنجاهم من الغرق."},
  {'n': '69', 'v': "وَٱتْلُ عَلَيْهِمْ نَبَأَ إِبْرَٰهِيمَ", 't': "«واتل عليهم» أي كفار مكة «نبأ» خبر «إبراهيم» ويبدل منه."},
  {'n': '70', 'v': "إِذْ قَالَ لِأَبِيهِ وَقَوْمِهِۦ مَا تَعْبُدُونَ", 't': "«إذا قال لأبيه وقومه ما تعبدون»."},
  {'n': '71', 'v': "قَالُوا۟ نَعْبُدُ أَصْنَامًۭا فَنَظَلُّ لَهَا عَٰكِفِينَ", 't': "«قالوا نعبد أصناما» صرحوا بالفعل ليعطفوا عليه «فنظل لها عاكفين» نقيم نهارا على عبادتها زادوه في الجواب افتخارا به."},
  {'n': '72', 'v': "قَالَ هَلْ يَسْمَعُونَكُمْ إِذْ تَدْعُونَ", 't': "«قال هل يسمعونكم إذ» حين «تدعون»."},
  {'n': '73', 'v': "أَوْ يَنفَعُونَكُمْ أَوْ يَضُرُّونَ", 't': "«أو ينفعونكم» إن عبدتموهم «أو يضرونـ» كم إن لم تعبدوهم."},
  {'n': '74', 'v': "قَالُوا۟ بَلْ وَجَدْنَآ ءَابَآءَنَا كَذَٰلِكَ يَفْعَلُونَ", 't': "«قالوا بل وجدنا آباءنا كذلك يفعلون» أي مثل فعلنا."},
  {'n': '75', 'v': "قَالَ أَفَرَءَيْتُم مَّا كُنتُمْ تَعْبُدُونَ", 't': "«قال أفرآيتم ما كنتم تعبدون»."},
  {'n': '76', 'v': "أَنتُمْ وَءَابَآؤُكُمُ ٱلْأَقْدَمُونَ", 't': "«أنتم وآبائكم الأقدمون»."},
  {'n': '77', 'v': "فَإِنَّهُمْ عَدُوٌّۭ لِّىٓ إِلَّا رَبَّ ٱلْعَٰلَمِينَ", 't': "«فإنهم عدو لي» لا أعبدهم «إلا» لكن «ربَّ العالمين» فإني أعبده."},
  {'n': '78', 'v': "ٱلَّذِى خَلَقَنِى فَهُوَ يَهْدِينِ", 't': "«الذي خلقني فهو يهدين» إلى الدين."},
  {'n': '79', 'v': "وَٱلَّذِى هُوَ يُطْعِمُنِى وَيَسْقِينِ", 't': "«والذي هو يطعمني ويسقين»."},
  {'n': '80', 'v': "وَإِذَا مَرِضْتُ فَهُوَ يَشْفِينِ", 't': "«وإذا مرضت فهو يشفين»."},
  {'n': '81', 'v': "وَٱلَّذِى يُمِيتُنِى ثُمَّ يُحْيِينِ", 't': "«والذي يُميتني ثم يحيين»."},
  {'n': '82', 'v': "وَٱلَّذِىٓ أَطْمَعُ أَن يَغْفِرَ لِى خَطِيٓـَٔتِى يَوْمَ ٱلدِّينِ", 't': "«والذي أطمع» أرجو «أن يغفر لي خطيئتي يوم الدين» الجزاء."},
  {'n': '83', 'v': "رَبِّ هَبْ لِى حُكْمًۭا وَأَلْحِقْنِى بِٱلصَّٰلِحِينَ", 't': "«رب هب لي حكما» علما «وألحقني بالصالحين» النبيين."},
  {'n': '84', 'v': "وَٱجْعَل لِّى لِسَانَ صِدْقٍۢ فِى ٱلْءَاخِرِينَ", 't': "«واجعل لي لسان صدق» ثناء حسنا «في الآخرين» الذين يأتون بعدي إلى يوم القيامة."},
  {'n': '85', 'v': "وَٱجْعَلْنِى مِن وَرَثَةِ جَنَّةِ ٱلنَّعِيمِ", 't': "«واجعلني من ورثة جنة النعيم» ممن يعطاها."},
  {'n': '86', 'v': "وَٱغْفِرْ لِأَبِىٓ إِنَّهُۥ كَانَ مِنَ ٱلضَّآلِّينَ", 't': "«واغفر لأبي إنه كان من الضالين» بأن تتوب عليه فتغفر له وهذا قبل أن يتبين له أنه عدو لله كما ذكر في سورة براءة."},
  {'n': '87', 'v': "وَلَا تُخْزِنِى يَوْمَ يُبْعَثُونَ", 't': "«ولا تخزني» تفضحني «يوم يُبعثون» الناس."},
  {'n': '88', 'v': "يَوْمَ لَا يَنفَعُ مَالٌۭ وَلَا بَنُونَ", 't': "قال تعالى فيه: «يوم لا ينفع مال ولا بنون» أحدا"},
  {'n': '89', 'v': "إِلَّا مَنْ أَتَى ٱللَّهَ بِقَلْبٍۢ سَلِيمٍۢ", 't': "«إلا» لكن «من أتى الله بقلب سليم» من الشرك والنفاق وهو قلب المؤمن فإنه ينفعه ذلك."},
  {'n': '90', 'v': "وَأُزْلِفَتِ ٱلْجَنَّةُ لِلْمُتَّقِينَ", 't': "«وأُزلفت الجنة» قربت «للمتقين» فيرونها."},
  {'n': '91', 'v': "وَبُرِّزَتِ ٱلْجَحِيمُ لِلْغَاوِينَ", 't': "«وبرزت الجحيم» أظهرت «للغاوين» الكافرين."},
  {'n': '92', 'v': "وَقِيلَ لَهُمْ أَيْنَ مَا كُنتُمْ تَعْبُدُونَ", 't': "«وقيل لهم أين ما كنتم تعبدون»."},
  {'n': '93', 'v': "مِن دُونِ ٱللَّهِ هَلْ يَنصُرُونَكُمْ أَوْ يَنتَصِرُونَ", 't': "«من دون الله» أي غيره من الأصنام «هل ينصرونكم» بدفع العذاب عنكم «أو ينتصرون» بدفعه عن أنفسهم، لا."},
  {'n': '94', 'v': "فَكُبْكِبُوا۟ فِيهَا هُمْ وَٱلْغَاوُۥنَ", 't': "«فكُبْكِبوا» ألقوا «فيها هم والغاوون»."},
  {'n': '95', 'v': "وَجُنُودُ إِبْلِيسَ أَجْمَعُونَ", 't': "«وجنود إبليس» أتباعه، ومن أطاعه من الجن والإنس «أجمعون»."},
  {'n': '96', 'v': "قَالُوا۟ وَهُمْ فِيهَا يَخْتَصِمُونَ", 't': "«قالوا» أي الغاوون «وهم فيها يختصمون» مع معبوديهم."},
  {'n': '97', 'v': "تَٱللَّهِ إِن كُنَّا لَفِى ضَلَٰلٍۢ مُّبِينٍ", 't': "«تالله إن» مخففة من الثقلية واسمها محذوف أي إنه «كنا لفي ضلال مبين» بين."},
  {'n': '98', 'v': "إِذْ نُسَوِّيكُم بِرَبِّ ٱلْعَٰلَمِينَ", 't': "«إذ» حيث «نسويكم برب العالمين» في العبادة."},
  {'n': '99', 'v': "وَمَآ أَضَلَّنَآ إِلَّا ٱلْمُجْرِمُونَ", 't': "«وما أضلنا» عن الهدى «إلا المجرمون» أي الشياطين أو أوّلونا الذين اقتدينا بهم."},
  {'n': '100', 'v': "فَمَا لَنَا مِن شَٰفِعِينَ", 't': "«فما لنا من شافعين» كما للمؤمنين من الملائكة والنبيين والمؤمنين."},
  {'n': '101', 'v': "وَلَا صَدِيقٍ حَمِيمٍۢ", 't': "«ولا صديق حميم» يهمه أمرنا."},
  {'n': '102', 'v': "فَلَوْ أَنَّ لَنَا كَرَّةًۭ فَنَكُونَ مِنَ ٱلْمُؤْمِنِينَ", 't': "«فلو أن لنا كرَّة» رجعة إلى الدنيا «فنكون من المؤمنين» لو هنا للتمني ونكون جوابه."},
  {'n': '103', 'v': "إِنَّ فِى ذَٰلِكَ لَءَايَةًۭ ۖ وَمَا كَانَ أَكْثَرُهُم مُّؤْمِنِينَ", 't': "«إن في ذلك» المذكور من قصة إبراهيم وقومه «لآية وما كان أكثرهم مؤمنين»."},
  {'n': '104', 'v': "وَإِنَّ رَبَّكَ لَهُوَ ٱلْعَزِيزُ ٱلرَّحِيمُ", 't': "«وإن ربك لهم العزيز الرحيم»."},
  {'n': '105', 'v': "كَذَّبَتْ قَوْمُ نُوحٍ ٱلْمُرْسَلِينَ", 't': "«كذبت قوم نوح المرسلين» بتكذيبهم له لاشتراكهم في المجيء بالتوحيد، أو لأنه لطول لبثه فيهم كأنه رسل وتأنيث قوم باعتبار معناه وتذكيره باعتبار لفظه."},
  {'n': '106', 'v': "إِذْ قَالَ لَهُمْ أَخُوهُمْ نُوحٌ أَلَا تَتَّقُونَ", 't': "«إذ قال لهم أخوهم» نسبا «نوح ألا تتقون» الله."},
  {'n': '107', 'v': "إِنِّى لَكُمْ رَسُولٌ أَمِينٌۭ", 't': "«إني لكم رسول أمين» على تبليغ ما أرسلت به."},
  {'n': '108', 'v': "فَٱتَّقُوا۟ ٱللَّهَ وَأَطِيعُونِ", 't': "«فاتقوا الله وأطيعون» فيما آمركم به من توحيد الله وطاعته."},
  {'n': '109', 'v': "وَمَآ أَسْـَٔلُكُمْ عَلَيْهِ مِنْ أَجْرٍ ۖ إِنْ أَجْرِىَ إِلَّا عَلَىٰ رَبِّ ٱلْعَٰلَمِينَ", 't': "«وما أسألكم عليه» على تبليغه «من أجر إن» ما «أجريَ» أي ثوابي «إلا على رب العالمين»."},
  {'n': '110', 'v': "فَٱتَّقُوا۟ ٱللَّهَ وَأَطِيعُونِ", 't': "«فاتقوا الله وأطيعون» كرره تأكيدا."},
