  {'n': '12', 'v': "وَقَالَ ٱلَّذِينَ كَفَرُوا۟ لِلَّذِينَ ءَامَنُوا۟ ٱتَّبِعُوا۟ سَبِيلَنَا وَلْنَحْمِلْ خَطَٰيَٰكُمْ وَمَا هُم بِحَٰمِلِينَ مِنْ خَطَٰيَٰهُم مِّن شَىْءٍ ۖ إِنَّهُمْ لَكَٰذِبُونَ", 't': "«وقال الذين كفروا للذين آمنوا اتبعوا سبيلنا» ديننا «ولنحمل خطاياكم» في اتباعنا إن كانت والأمر بمعنى الخبر، قال تعالى: «وما هم بحاملين من خطاياهم من شيءٍ إنهم لكاذبون» في ذلك."},
  {'n': '13', 'v': "وَلَيَحْمِلُنَّ أَثْقَالَهُمْ وَأَثْقَالًۭا مَّعَ أَثْقَالِهِمْ ۖ وَلَيُسْـَٔلُنَّ يَوْمَ ٱلْقِيَٰمَةِ عَمَّا كَانُوا۟ يَفْتَرُونَ", 't': "(وليحملن أثقالهم) أوزارهم (وأثقالاً مع أثقالهم) بقولهم للمؤمنين \"اتبعوا سبيلنا\" وإضلالهم مقلديهم (وليسألن يوم القيامة عما كانوا يفترون) يكذبون على الله سؤال توبيخ واللام في الفعلين لام قسم، وحذف فاعلهما الواو ونون الرفع."},
  {'n': '14', 'v': "وَلَقَدْ أَرْسَلْنَا نُوحًا إِلَىٰ قَوْمِهِۦ فَلَبِثَ فِيهِمْ أَلْفَ سَنَةٍ إِلَّا خَمْسِينَ عَامًۭا فَأَخَذَهُمُ ٱلطُّوفَانُ وَهُمْ ظَٰلِمُونَ", 't': "«ولقد أرسلنا نوحاً إلى قومه» وعمره أربعون سنة أو أكثر «فلبس فيهم ألف سنة إلا خمسين عاماً» يدعوهم إلى توحيد الله فكذبوه «فأخذهم الطوفان» أي الماء الكثير طاف بهم وعلاهم فغرقوا «وهم ظالمون» مشركون."},
  {'n': '15', 'v': "فَأَنجَيْنَٰهُ وَأَصْحَٰبَ ٱلسَّفِينَةِ وَجَعَلْنَٰهَآ ءَايَةًۭ لِّلْعَٰلَمِينَ", 't': "«فأنجيناه» أي نوحا «وأصحاب السفينة» الذين كانوا معه فيها «وجعلناها آية» عبرة «للعالمين» لمن بعدهم من الناس إن عصوا رسلهم وعاش نوح بعد الطوفان ستين سنة أو أكثر حتى كثر الناس."},
  {'n': '16', 'v': "وَإِبْرَٰهِيمَ إِذْ قَالَ لِقَوْمِهِ ٱعْبُدُوا۟ ٱللَّهَ وَٱتَّقُوهُ ۖ ذَٰلِكُمْ خَيْرٌۭ لَّكُمْ إِن كُنتُمْ تَعْلَمُونَ", 't': "«و» اذكر «إبراهيم إذ قال لقومه اعبدوا الله واتقوه» خافوا عقابه «ذلكم خير لكم» مما أنتم عليه من عبادة الأصنام «إن كنتم تعلمون» الخير من غيره."},
  {'n': '17', 'v': "إِنَّمَا تَعْبُدُونَ مِن دُونِ ٱللَّهِ أَوْثَٰنًۭا وَتَخْلُقُونَ إِفْكًا ۚ إِنَّ ٱلَّذِينَ تَعْبُدُونَ مِن دُونِ ٱللَّهِ لَا يَمْلِكُونَ لَكُمْ رِزْقًۭا فَٱبْتَغُوا۟ عِندَ ٱللَّهِ ٱلرِّزْقَ وَٱعْبُدُوهُ وَٱشْكُرُوا۟ لَهُۥٓ ۖ إِلَيْهِ تُرْجَعُونَ", 't': "«إنما تعبدون من دون الله» أي غيره «أوثاناً وتخلقون إفكا» تقولون كذباً إن الأوثان شركاء الله «إن الذين تعبدون من دون الله لا يملكون لكم رزقا» لا يقدرون أن يرزقوكم «فابتغوا عند الله الرزق» اطلبوه منه «واعبدوه واشكروا له إليه ترجعون»."},
  {'n': '18', 'v': "وَإِن تُكَذِّبُوا۟ فَقَدْ كَذَّبَ أُمَمٌۭ مِّن قَبْلِكُمْ ۖ وَمَا عَلَى ٱلرَّسُولِ إِلَّا ٱلْبَلَٰغُ ٱلْمُبِينُ", 't': "«إنما تعبدون من دون الله» أي غيره «أوثانا وتخلقون إفكا» تقولون كذبا إن الأوثان شركاء الله «إن الذين تعبدون من دون الله لا يملكون لكم رزقا» لا يقدرون أن يرزقوكم «فابتغوا عند الله الرزق» اطلبوه منه «واعبدوه واشكروا له إليه ترجعون»."},
  {'n': '19', 'v': "أَوَلَمْ يَرَوْا۟ كَيْفَ يُبْدِئُ ٱللَّهُ ٱلْخَلْقَ ثُمَّ يُعِيدُهُۥٓ ۚ إِنَّ ذَٰلِكَ عَلَى ٱللَّهِ يَسِيرٌۭ", 't': "«أَو لم يروْا» بالياء والتاء ينظروا «كيف يُبدئ الله الخلق» هو بضم أوله وقرأ بفتحة من بدأ وأبدأ بمعنى أي يخلقهم ابتداءً «ثم» هو «يعيده» أي الخلق كما بدأه «إن ذلك» المذكور من الخلق الأول والثاني «على الله يسير» فكيف ينكرون الثاني."},
  {'n': '20', 'v': "قُلْ سِيرُوا۟ فِى ٱلْأَرْضِ فَٱنظُرُوا۟ كَيْفَ بَدَأَ ٱلْخَلْقَ ۚ ثُمَّ ٱللَّهُ يُنشِئُ ٱلنَّشْأَةَ ٱلْءَاخِرَةَ ۚ إِنَّ ٱللَّهَ عَلَىٰ كُلِّ شَىْءٍۢ قَدِيرٌۭ", 't': "«قل سيروا في الأرض فانظروا كيف بدأ الخلق» لمن كان قبلكم وأماتهم «ثم الله ينشئ النَّشأةَ الآخرة» مداً وقصراً مع سكون الشين «إن الله على كل شيءٍ قدير» ومنه البدء والإعادة."},
  {'n': '21', 'v': "يُعَذِّبُ مَن يَشَآءُ وَيَرْحَمُ مَن يَشَآءُ ۖ وَإِلَيْهِ تُقْلَبُونَ", 't': "«يعذِّب من يشاء» تعذيبه «ويرحم من يشاء» رحمته «وإليه تقبلون» تردون."},
  {'n': '22', 'v': "وَمَآ أَنتُم بِمُعْجِزِينَ فِى ٱلْأَرْضِ وَلَا فِى ٱلسَّمَآءِ ۖ وَمَا لَكُم مِّن دُونِ ٱللَّهِ مِن وَلِىٍّۢ وَلَا نَصِيرٍۢ", 't': "«وما أنتم بمعجزين» ربكم عن إدراككم «في الأرض ولا في السماء» لو كنتم فيها: أي لا تفوتونه «وما لكم من دون الله» أي غيره «من ولي» يمنعكم منه «ولا نصير» ينصركم من عذابه."},
  {'n': '23', 'v': "وَٱلَّذِينَ كَفَرُوا۟ بِـَٔايَٰتِ ٱللَّهِ وَلِقَآئِهِۦٓ أُو۟لَٰٓئِكَ يَئِسُوا۟ مِن رَّحْمَتِى وَأُو۟لَٰٓئِكَ لَهُمْ عَذَابٌ أَلِيمٌۭ", 't': "«والذين كفروا بآيات الله ولقائه» أي القرآن والبعث «أولئك يئسوا من رحمتي» أي جنتي «وأولئك لهم عذاب أليم» مؤلم."},
  {'n': '24', 'v': "فَمَا كَانَ جَوَابَ قَوْمِهِۦٓ إِلَّآ أَن قَالُوا۟ ٱقْتُلُوهُ أَوْ حَرِّقُوهُ فَأَنجَىٰهُ ٱللَّهُ مِنَ ٱلنَّارِ ۚ إِنَّ فِى ذَٰلِكَ لَءَايَٰتٍۢ لِّقَوْمٍۢ يُؤْمِنُونَ", 't': "قال تعالى في قصة إبراهيم عليه السلام: «فما كان جواب قومه إلا أن قالوا اقتلوه أو حرّقوه فأنجاه الله من النار» التي قذفوه فيها بأن جعلها برداً وسلاماً «إن في ذلك» أي إنجائه منها «لآيات» هي عدم تأثيرها فيه مع عظمها وإخمادها وإنشاء روض مكانها في زمن يسير «لقوم يؤمنون» يصدقون بتوحيد الله وقدرته لأنهم المنتفعون بها."},
  {'n': '25', 'v': "وَقَالَ إِنَّمَا ٱتَّخَذْتُم مِّن دُونِ ٱللَّهِ أَوْثَٰنًۭا مَّوَدَّةَ بَيْنِكُمْ فِى ٱلْحَيَوٰةِ ٱلدُّنْيَا ۖ ثُمَّ يَوْمَ ٱلْقِيَٰمَةِ يَكْفُرُ بَعْضُكُم بِبَعْضٍۢ وَيَلْعَنُ بَعْضُكُم بَعْضًۭا وَمَأْوَىٰكُمُ ٱلنَّارُ وَمَا لَكُم مِّن نَّٰصِرِينَ", 't': "«وقال» إبراهيم «إنما اتخذتم من دون الله أوثانا» تعبدونها وما مصدرية «مودةُ بينكم» خبر إن، وعلى قراءة النصب مفعول له وما كافة المعنى تواددتم على عبادتها «في الحياة الدنيا ثم يوم القيامة يكفر بعضكم ببعض» يتبرأ القادة من الأتباع «ويلعن بعضكم بعضاً» يلعن الأتباع القادة «ومأواكم» مصيركم جميعاً «النار وما لكم من ناصرين» مانعين منها."},
  {'n': '26', 'v': "۞ فَـَٔامَنَ لَهُۥ لُوطٌۭ ۘ وَقَالَ إِنِّى مُهَاجِرٌ إِلَىٰ رَبِّىٓ ۖ إِنَّهُۥ هُوَ ٱلْعَزِيزُ ٱلْحَكِيمُ", 't': "«فآمن له» صدق إبراهيم «لوط» وهو ابن أخيه هاران «وقال» إبراهيم «إني مهاجر» من قومي «إلى ربي» إلى حيث أمرني ربي وهجر قومه وهاجر من سواد العراق إلى الشام «إنه هو العزيز» في ملكه «الحكيم» في صنعه."},
  {'n': '27', 'v': "وَوَهَبْنَا لَهُۥٓ إِسْحَٰقَ وَيَعْقُوبَ وَجَعَلْنَا فِى ذُرِّيَّتِهِ ٱلنُّبُوَّةَ وَٱلْكِتَٰبَ وَءَاتَيْنَٰهُ أَجْرَهُۥ فِى ٱلدُّنْيَا ۖ وَإِنَّهُۥ فِى ٱلْءَاخِرَةِ لَمِنَ ٱلصَّٰلِحِينَ", 't': "«ووهبنا له» بعد إسماعيل «إسحاق ويعقوب» بعد إسحاق «وجعلنا في ذريته النبوة» فكل الأنبياء بعد إبراهيم من ذريته «والكتاب» بمعنى الكتب أي التوراة والإنجيل، والزبور والفرقان «وآتيناه أجره في الدنيا» وهو الثناء الحسن في كل أهل الأديان «وإنه في الآخرة لمن الصالحين» الذين لهم الدرجات العلى."},
  {'n': '28', 'v': "وَلُوطًا إِذْ قَالَ لِقَوْمِهِۦٓ إِنَّكُمْ لَتَأْتُونَ ٱلْفَٰحِشَةَ مَا سَبَقَكُم بِهَا مِنْ أَحَدٍۢ مِّنَ ٱلْعَٰلَمِينَ", 't': "«و» اذكر «لوطاً إذ قال لقومه أإنكم» بتحقيق الهمزتين وتسهيل الثانية وإدخال ألف بينهما على الوجهين في الموضعين «لتأتون الفاحشة» أي: أدبار الرجال «ما سبقكم بها من أحد من العالمين» الإنس والجن."},
  {'n': '29', 'v': "أَئِنَّكُمْ لَتَأْتُونَ ٱلرِّجَالَ وَتَقْطَعُونَ ٱلسَّبِيلَ وَتَأْتُونَ فِى نَادِيكُمُ ٱلْمُنكَرَ ۖ فَمَا كَانَ جَوَابَ قَوْمِهِۦٓ إِلَّآ أَن قَالُوا۟ ٱئْتِنَا بِعَذَابِ ٱللَّهِ إِن كُنتَ مِنَ ٱلصَّٰدِقِينَ", 't': "«أإنكم لتأتون الرجال وتقطعون السبيل» طريق المارة بفعلكم الفاحشة بمن يمر بكم فترك الناس الممر بكم «وتأتون في ناديكم» أي متحدَّثِكم «المنكر» فعل الفاحشة بعضكم ببعض «فما كان جواب قومه إلا أن قالوا ائتنا بعذاب الله إن كنت من الصادقين» في استقباح ذلك وأن العذاب نازل بفاعليه."},
  {'n': '30', 'v': "قَالَ رَبِّ ٱنصُرْنِى عَلَى ٱلْقَوْمِ ٱلْمُفْسِدِينَ", 't': "«قال رب انصرني» بتحقيق قولي في إنزال العذاب «على القوم المفسدين» العاصين بإتيان الرجال فاستجاب الله دعاءه."},
  {'n': '31', 'v': "وَلَمَّا جَآءَتْ رُسُلُنَآ إِبْرَٰهِيمَ بِٱلْبُشْرَىٰ قَالُوٓا۟ إِنَّا مُهْلِكُوٓا۟ أَهْلِ هَٰذِهِ ٱلْقَرْيَةِ ۖ إِنَّ أَهْلَهَا كَانُوا۟ ظَٰلِمِينَ", 't': "«ولما جاءت رسلنا إبراهيم بالبشرى» بإسحاق ويعقوب بعده «قالوا إنا مهلكوا أهل هذه القرية» أي قرية لوط «إن أهلها كانوا ظالمين» كافرين."},
  {'n': '32', 'v': "قَالَ إِنَّ فِيهَا لُوطًۭا ۚ قَالُوا۟ نَحْنُ أَعْلَمُ بِمَن فِيهَا ۖ لَنُنَجِّيَنَّهُۥ وَأَهْلَهُۥٓ إِلَّا ٱمْرَأَتَهُۥ كَانَتْ مِنَ ٱلْغَٰبِرِينَ", 't': "«قال» إبراهيم «إن فيها لوطا قالوا» أي الرسل «نحن أعلم بمن فيها لنُنجينَّه» بالتخفيف والتشديد «وأهله إلا امرأته كانت من الغابرين» الباقين في العذاب."},
  {'n': '33', 'v': "وَلَمَّآ أَن جَآءَتْ رُسُلُنَا لُوطًۭا سِىٓءَ بِهِمْ وَضَاقَ بِهِمْ ذَرْعًۭا وَقَالُوا۟ لَا تَخَفْ وَلَا تَحْزَنْ ۖ إِنَّا مُنَجُّوكَ وَأَهْلَكَ إِلَّا ٱمْرَأَتَكَ كَانَتْ مِنَ ٱلْغَٰبِرِينَ", 't': "«ولما أن جاءت رسلنا لوطا سيء بهم» حزن بسببهم «وضاق بهم ذرعا» صدرا لأنهم حسان الوجوه في صورة أضياف فخاف عليهم قومه فأعلموه أنهم رسل ربه «وقالوا لا تخف ولا تحزن إنا منجُّوك» بالتشديد والتخفيف «وأهلك إلا امرأتك كانت من الغابرين» ونصب أهلك عطف على محل الكاف."},
  {'n': '34', 'v': "إِنَّا مُنزِلُونَ عَلَىٰٓ أَهْلِ هَٰذِهِ ٱلْقَرْيَةِ رِجْزًۭا مِّنَ ٱلسَّمَآءِ بِمَا كَانُوا۟ يَفْسُقُونَ", 't': "«إنا منزلون» بالتخفيف والتشديد «على أهل هذه القرية رجزا» عذابا «من السماء بما» بالفعل الذي «كانوا يفسقون» به أي بسبب فسقهم."},
  {'n': '35', 'v': "وَلَقَد تَّرَكْنَا مِنْهَآ ءَايَةًۢ بَيِّنَةًۭ لِّقَوْمٍۢ يَعْقِلُونَ", 't': "«ولقد تركنا منها آية بينة» ظاهرة هي آثار خرابها «لقوم يعقلون» يتدبرون."},
  {'n': '36', 'v': "وَإِلَىٰ مَدْيَنَ أَخَاهُمْ شُعَيْبًۭا فَقَالَ يَٰقَوْمِ ٱعْبُدُوا۟ ٱللَّهَ وَٱرْجُوا۟ ٱلْيَوْمَ ٱلْءَاخِرَ وَلَا تَعْثَوْا۟ فِى ٱلْأَرْضِ مُفْسِدِينَ", 't': "«و» أَرسلنا «إلى مدْين أخاهم شعيبا فقال يا قوم اعبدوا الله وارجوا اليوم الآخر» اخشوه، هو يوم القيامة «ولا تعثوْا في الأرض مفسدين» حال مؤكدة لعاملها من عثي بكسر المثلثة أفسد."},
  {'n': '37', 'v': "فَكَذَّبُوهُ فَأَخَذَتْهُمُ ٱلرَّجْفَةُ فَأَصْبَحُوا۟ فِى دَارِهِمْ جَٰثِمِينَ", 't': "«فكذبوه فأخذتهم الرجفة» الزلزلة الشديدة «فأصبحوا في دارهم جاثمين» باركين على الركب ميّتين."},
  {'n': '38', 'v': "وَعَادًۭا وَثَمُودَا۟ وَقَد تَّبَيَّنَ لَكُم مِّن مَّسَٰكِنِهِمْ ۖ وَزَيَّنَ لَهُمُ ٱلشَّيْطَٰنُ أَعْمَٰلَهُمْ فَصَدَّهُمْ عَنِ ٱلسَّبِيلِ وَكَانُوا۟ مُسْتَبْصِرِينَ", 't': "«و» أهلكنا «عادا وثمودا» بالصرف وتركه بمعنى الحي والقبيلة «وقد تبيّن لكم» إهلاكهم «من مساكنهم» بالحجر واليمن «وزيَّن لهم الشيطان أعمالهم» من الكفر والمعاصي «فصدهم عن السبيل» سبيل الحق «وكانوا مستبصرين» ذوي بصائر."},
  {'n': '39', 'v': "وَقَٰرُونَ وَفِرْعَوْنَ وَهَٰمَٰنَ ۖ وَلَقَدْ جَآءَهُم مُّوسَىٰ بِٱلْبَيِّنَٰتِ فَٱسْتَكْبَرُوا۟ فِى ٱلْأَرْضِ وَمَا كَانُوا۟ سَٰبِقِينَ", 't': "«و» أهلكنا «قارون وفرعون وهامان ولقد جاءهم» من قبل «موسى بالبيّنات» الحجج الظاهرات «فاستكبروا في الأرض وما كانوا سابقين» فائتين عذابنا."},
  {'n': '40', 'v': "فَكُلًّا أَخَذْنَا بِذَنۢبِهِۦ ۖ فَمِنْهُم مَّنْ أَرْسَلْنَا عَلَيْهِ حَاصِبًۭا وَمِنْهُم مَّنْ أَخَذَتْهُ ٱلصَّيْحَةُ وَمِنْهُم مَّنْ خَسَفْنَا بِهِ ٱلْأَرْضَ وَمِنْهُم مَّنْ أَغْرَقْنَا ۚ وَمَا كَانَ ٱللَّهُ لِيَظْلِمَهُمْ وَلَٰكِن كَانُوٓا۟ أَنفُسَهُمْ يَظْلِمُونَ", 't': "«فكلا» من المذكورين «أخذنا بذنبه فمنهم من أرسلنا عليه حاصبا» ريحاً عاصفة فيها حصباء كقوم لوط «ومنهم من أخذته الصيحة» كثمود «ومنهم من خسفنا به الأرض» كقارون «ومنهم من أغرقنا» كقوم نوح وفرعون وقومه «وما كان الله ليظلمهم» فيعذبهم بغير ذنب «ولكن كانوا أنفسهم يظلمون» بارتكاب الذنب."},
  {'n': '41', 'v': "مَثَلُ ٱلَّذِينَ ٱتَّخَذُوا۟ مِن دُونِ ٱللَّهِ أَوْلِيَآءَ كَمَثَلِ ٱلْعَنكَبُوتِ ٱتَّخَذَتْ بَيْتًۭا ۖ وَإِنَّ أَوْهَنَ ٱلْبُيُوتِ لَبَيْتُ ٱلْعَنكَبُوتِ ۖ لَوْ كَانُوا۟ يَعْلَمُونَ", 't': "«مثل الذين اتخذوا من دون الله أولياء» أي أصناماً يرجون نفعها «كمثل العنكبوت اتخذت بيتاً» لنفسها تأوي إليه «وإن أوهن» أضعف «البيوت لبيت العنكبوت» لا يدفع عنها حراً ولا برداً كذلك الأصنام لا تنفع عابديها «لو كانوا يعلمون» ذلك ما عبدوها."},
  {'n': '42', 'v': "إِنَّ ٱللَّهَ يَعْلَمُ مَا يَدْعُونَ مِن دُونِهِۦ مِن شَىْءٍۢ ۚ وَهُوَ ٱلْعَزِيزُ ٱلْحَكِيمُ", 't': "«إن الله يعلم ما» بمعنى الذي «يدعون» يعبدون بالياء والتاء «من دونه» غيره «من شيء وهو العزيز» في ملكه «الحكيم» في صنعه."},
  {'n': '43', 'v': "وَتِلْكَ ٱلْأَمْثَٰلُ نَضْرِبُهَا لِلنَّاسِ ۖ وَمَا يَعْقِلُهَآ إِلَّا ٱلْعَٰلِمُونَ", 't': "«وتلك الأمثال» في القرآن «نضربها» نجعلها «للناس وما يعقلها» أي يفهمها «إلا العالمون» المتدبرون."},
  {'n': '44', 'v': "خَلَقَ ٱللَّهُ ٱلسَّمَٰوَٰتِ وَٱلْأَرْضَ بِٱلْحَقِّ ۚ إِنَّ فِى ذَٰلِكَ لَءَايَةًۭ لِّلْمُؤْمِنِينَ", 't': "«خلقَ الله السماوات والأرض بالحق» أي محقا «إن في ذلك لآيةً» دالة على قدرته تعالى «للمؤمنين» خصّوا بالذكر لأنهم المنتفعون بها في الإيمان بخلاف الكافرين."},
  {'n': '45', 'v': "ٱتْلُ مَآ أُوحِىَ إِلَيْكَ مِنَ ٱلْكِتَٰبِ وَأَقِمِ ٱلصَّلَوٰةَ ۖ إِنَّ ٱلصَّلَوٰةَ تَنْهَىٰ عَنِ ٱلْفَحْشَآءِ وَٱلْمُنكَرِ ۗ وَلَذِكْرُ ٱللَّهِ أَكْبَرُ ۗ وَٱللَّهُ يَعْلَمُ مَا تَصْنَعُونَ", 't': "«اتل ما أوحي إليك من الكتاب» القرآن «وأقم الصلاة إن الصلاة تنهى عن الفحشاء والمنكر» شرعا أي من شأنها ذلك ما دام المرء فيها «ولذكر الله أكبر» من غيره من الطاعات «والله يعلم ما تصنعون» فيجازيكم به."},
  {'n': '46', 'v': "۞ وَلَا تُجَٰدِلُوٓا۟ أَهْلَ ٱلْكِتَٰبِ إِلَّا بِٱلَّتِى هِىَ أَحْسَنُ إِلَّا ٱلَّذِينَ ظَلَمُوا۟ مِنْهُمْ ۖ وَقُولُوٓا۟ ءَامَنَّا بِٱلَّذِىٓ أُنزِلَ إِلَيْنَا وَأُنزِلَ إِلَيْكُمْ وَإِلَٰهُنَا وَإِلَٰهُكُمْ وَٰحِدٌۭ وَنَحْنُ لَهُۥ مُسْلِمُونَ", 't': "«ولا تجادلوا أهل الكتاب إلا بالتي» أي: المجادلة التي «هي أحسن» كالدعاء إلى الله بآياته والتنبيه على حججه «إلا الذين ظلموا منهم» بأن حاربوا وأبوا أن يقرّوا بالجزية فجادلوهم بالسيف حتى يسلموا أو يعطوا الجزية «وقولوا» لمن قبل الإقرار بالجزية إذا أخبروكم بشيء مما في كتبهم «آمنا بالذي أنزل إلينا وأنزل إليكم» ولا تصدقوهم ولا تكذبوهم في ذلك «وإلهنا وإلهكم واحدٌ ونحن مسلمون» مطيعون."},
  {'n': '47', 'v': "وَكَذَٰلِكَ أَنزَلْنَآ إِلَيْكَ ٱلْكِتَٰبَ ۚ فَٱلَّذِينَ ءَاتَيْنَٰهُمُ ٱلْكِتَٰبَ يُؤْمِنُونَ بِهِۦ ۖ وَمِنْ هَٰٓؤُلَآءِ مَن يُؤْمِنُ بِهِۦ ۚ وَمَا يَجْحَدُ بِـَٔايَٰتِنَآ إِلَّا ٱلْكَٰفِرُونَ", 't': "«وكذلك أنزلنا إليك الكتاب» القرآن كما أنزلنا إليهم التوراة وغيرها «فالذين آتيناهم الكتاب» التوراة كعبد الله بن سلام وغيره «يؤمنون به» بالقرآن «ومن هؤلاء» أهل مكة «من يؤمن به وما يجحد بآياتنا» بعد ظهورها «إلا الكافرون» أي اليهود وظهر لهم أن القرآن حق والجائي به محق وجحدوا ذلك."},
  {'n': '48', 'v': "وَمَا كُنتَ تَتْلُوا۟ مِن قَبْلِهِۦ مِن كِتَٰبٍۢ وَلَا تَخُطُّهُۥ بِيَمِينِكَ ۖ إِذًۭا لَّٱرْتَابَ ٱلْمُبْطِلُونَ", 't': "«وما كنت تتلوا من قبله» أي القرآن «من كتاب ولا تخطه بيمينك إذا» أي لو كنت قارئا كتابا «لارتاب» شك «المبطلون» اليهود فيك وقالوا الذي في التوراة أنه أمي لا يقرأ ولا يكتب."},
  {'n': '49', 'v': "بَلْ هُوَ ءَايَٰتٌۢ بَيِّنَٰتٌۭ فِى صُدُورِ ٱلَّذِينَ أُوتُوا۟ ٱلْعِلْمَ ۚ وَمَا يَجْحَدُ بِـَٔايَٰتِنَآ إِلَّا ٱلظَّٰلِمُونَ", 't': "«بل هو» أي القرآن الذي جئت به «آيات بينات في صدور الذين أوتوا العلم» أي المؤمنون يحفظونه «وما يجحد بآياتنا إلا الظالمون» أي: اليهود وجحدوها بعد ظهورها لهم."},
  {'n': '50', 'v': "وَقَالُوا۟ لَوْلَآ أُنزِلَ عَلَيْهِ ءَايَٰتٌۭ مِّن رَّبِّهِۦ ۖ قُلْ إِنَّمَا ٱلْءَايَٰتُ عِندَ ٱللَّهِ وَإِنَّمَآ أَنَا۠ نَذِيرٌۭ مُّبِينٌ", 't': "«وقالوا» أي كفار مكة «لولا» هلا «أنزل عليه» أي محمد «آية من ربه» وفي قراءة آيات كناقة صالح وعصا موسى ومائدة عيسى «قل» لهم «إنما الآيات عند الله» ينزلها كيف يشاء «وإنما أنا نذير مبين» مظهر إنذاري بالنار أهل المعصية."},
  {'n': '51', 'v': "أَوَلَمْ يَكْفِهِمْ أَنَّآ أَنزَلْنَا عَلَيْكَ ٱلْكِتَٰبَ يُتْلَىٰ عَلَيْهِمْ ۚ إِنَّ فِى ذَٰلِكَ لَرَحْمَةًۭ وَذِكْرَىٰ لِقَوْمٍۢ يُؤْمِنُونَ", 't': "«أو لم يكفهم» فيما طلبوا «أنَّا أنزلنا عليك الكتاب» القرآن «يتلى عليهم» فهو آية مستمرة لا انقضاء لها بخلاف ما ذكر من الآيات «إن في ذلك» الكتاب «لرحمةً وذكرى» عظة «لقوم يؤمنون»."},
  {'n': '52', 'v': "قُلْ كَفَىٰ بِٱللَّهِ بَيْنِى وَبَيْنَكُمْ شَهِيدًۭا ۖ يَعْلَمُ مَا فِى ٱلسَّمَٰوَٰتِ وَٱلْأَرْضِ ۗ وَٱلَّذِينَ ءَامَنُوا۟ بِٱلْبَٰطِلِ وَكَفَرُوا۟ بِٱللَّهِ أُو۟لَٰٓئِكَ هُمُ ٱلْخَٰسِرُونَ", 't': "«قل كفى بالله بيني وبينكم شهيدا» بصدقي «يعلم ما في السماوات والأرض» ومنه حالي وحالكم «والذين آمنوا بالباطل» وهو ما يعبد من دون الله «وكفروا بالله» منكم «أولئك هم الخاسرون» في صفقتهم حيث اشتروا الكفر بالإيمان."},
  {'n': '53', 'v': "وَيَسْتَعْجِلُونَكَ بِٱلْعَذَابِ ۚ وَلَوْلَآ أَجَلٌۭ مُّسَمًّۭى لَّجَآءَهُمُ ٱلْعَذَابُ وَلَيَأْتِيَنَّهُم بَغْتَةًۭ وَهُمْ لَا يَشْعُرُونَ", 't': "«ويستعجلونك بالعذاب ولولا أجل مسمى» له «لجاءَهم العذاب» عاجلاً «ولياتينَّهم بغتةً وهم لا يشعرون» بوقت إتيانه."},
  {'n': '54', 'v': "يَسْتَعْجِلُونَكَ بِٱلْعَذَابِ وَإِنَّ جَهَنَّمَ لَمُحِيطَةٌۢ بِٱلْكَٰفِرِينَ", 't': "«يستعجلونك بالعذاب» في الدنيا «وإن جهنم لمحيطه بالكافرين»."},
  {'n': '55', 'v': "يَوْمَ يَغْشَىٰهُمُ ٱلْعَذَابُ مِن فَوْقِهِمْ وَمِن تَحْتِ أَرْجُلِهِمْ وَيَقُولُ ذُوقُوا۟ مَا كُنتُمْ تَعْمَلُونَ", 't': "«يوم يغشاهم العذاب من فوقهم ومن تحت أرجلهم ونقول» فيه بالنون أي نأمر بالقول، وبالياء يقول أي الموكل بالعذاب «ذوقوا ما كنتم تعلمون» أي جزاءه فلا تفوتوننا."},
  {'n': '56', 'v': "يَٰعِبَادِىَ ٱلَّذِينَ ءَامَنُوٓا۟ إِنَّ أَرْضِى وَٰسِعَةٌۭ فَإِيَّٰىَ فَٱعْبُدُونِ", 't': "«يا عباديَ الذين آمنوا إنَّ أرضي واسعة فإياي فاعبدون» في أي أرض تيسَّرت فيها العبادة، بأن تهاجروا إليها من أرض لم تتيسر فيها نزل في ضعفاء مسلمي مكة كانوا في ضيق من إظهار الإسلام بها."},
  {'n': '57', 'v': "كُلُّ نَفْسٍۢ ذَآئِقَةُ ٱلْمَوْتِ ۖ ثُمَّ إِلَيْنَا تُرْجَعُونَ", 't': "«كلُّ نفسٍ ذائقة الموت ثم إلينا ترجعون» بالتاء والياء بعد البعث."},
  {'n': '58', 'v': "وَٱلَّذِينَ ءَامَنُوا۟ وَعَمِلُوا۟ ٱلصَّٰلِحَٰتِ لَنُبَوِّئَنَّهُم مِّنَ ٱلْجَنَّةِ غُرَفًۭا تَجْرِى مِن تَحْتِهَا ٱلْأَنْهَٰرُ خَٰلِدِينَ فِيهَا ۚ نِعْمَ أَجْرُ ٱلْعَٰمِلِينَ", 't': "«والذين آمنوا وعملوا الصالحات لنُبوئنَّهم» ننزلنهم، وفي قراءة بالمثلثة بعد النون من الثواء: الإقامة وتعديته إلى غرفا بحذف في «من الجنة غرفا تجري من تحتها الأنهار خالدين» مقدّرين الخلود «فيها نِعم أجر العاملين» هذا الأجر."},
  {'n': '59', 'v': "ٱلَّذِينَ صَبَرُوا۟ وَعَلَىٰ رَبِّهِمْ يَتَوَكَّلُونَ", 't': "هم «الذين صبروا» أي على أذى المشركين والهجرة لإظهار الدين «وعلى ربهم يتوكلون» فيرزقهم من حيث لا يحتسبون."},
  {'n': '60', 'v': "وَكَأَيِّن مِّن دَآبَّةٍۢ لَّا تَحْمِلُ رِزْقَهَا ٱللَّهُ يَرْزُقُهَا وَإِيَّاكُمْ ۚ وَهُوَ ٱلسَّمِيعُ ٱلْعَلِيمُ", 't': "«وكأين» كم «من دابة لا تحمل رزقها» لضعفها «الله يرزقها وإياكم» أيها المهاجرون وإن لم يكن معكم زاد ولا نفقة «وهو السميع» لأقوالكم «العليم» بضمائركم."},
  {'n': '61', 'v': "وَلَئِن سَأَلْتَهُم مَّنْ خَلَقَ ٱلسَّمَٰوَٰتِ وَٱلْأَرْضَ وَسَخَّرَ ٱلشَّمْسَ وَٱلْقَمَرَ لَيَقُولُنَّ ٱللَّهُ ۖ فَأَنَّىٰ يُؤْفَكُونَ", 't': "«ولئن» لام قسم «سألتهم» أي: الكفار «من خلق السماوات والأرض وسخَّر الشمس والقمر ليقولُنَّ الله فأنّى يؤفكون» يصرفون عن توحيده بعد إقرارهم بذلك."},
