  {'n': '16', 'v': "فَأَعْرَضُوا۟ فَأَرْسَلْنَا عَلَيْهِمْ سَيْلَ ٱلْعَرِمِ وَبَدَّلْنَٰهُم بِجَنَّتَيْهِمْ جَنَّتَيْنِ ذَوَاتَىْ أُكُلٍ خَمْطٍۢ وَأَثْلٍۢ وَشَىْءٍۢ مِّن سِدْرٍۢ قَلِيلٍۢ", 't': "«فأعرضوا» عن شكره وكفروا «فأرسلنا عليهم سيل العرم» جمع عرمة وهو ما يمسك الماء من بناء وغيره إلى وقت حاجته، أي سيل واديهم الممسوك بما ذكر فأغرق جنتيهم وأموالهم «وبدلناهم بجنتيهم جنتين ذواتي» تثنية ذوات مفرد على الأصل «أُكُلٍ خَمْطِ» مرِّ بشع بإضافة أكل بمعنى مأكول وتركها ويعطف عليه «وأثل وشيء من سدر قليل»."},
  {'n': '17', 'v': "ذَٰلِكَ جَزَيْنَٰهُم بِمَا كَفَرُوا۟ ۖ وَهَلْ نُجَٰزِىٓ إِلَّا ٱلْكَفُورَ", 't': "«ذلك» التبديل «جزيناهم بما كفرواْ» بكفرهم «وهل يجازِى إلا الكفور» بالياء والنون مع كسر الزاي ونصب الكفور، أي ما يناقش إلا هو."},
  {'n': '18', 'v': "وَجَعَلْنَا بَيْنَهُمْ وَبَيْنَ ٱلْقُرَى ٱلَّتِى بَٰرَكْنَا فِيهَا قُرًۭى ظَٰهِرَةًۭ وَقَدَّرْنَا فِيهَا ٱلسَّيْرَ ۖ سِيرُوا۟ فِيهَا لَيَالِىَ وَأَيَّامًا ءَامِنِينَ", 't': "«وجعلنا بينهم» بين سبأ، وهم باليمن «وبين القرى التي باركنا فيها» بالماء والشجر وهي قرى الشام التي يسيرون إليها للتجارة «قرى ظاهرة» متواصلة من اليمن إلى الشام «وقدرنا فيها السير» بحيث يقيلون في واحدة ويبيتون في أخرى إلى انتهاء سفرهم ولا يحتاجون فيه إلى حمل زاد وماء أي وقلنا «سيروا فيها ليالي وأياما آمنين» لا تخافون في ليل ولا في نهار."},
  {'n': '19', 'v': "فَقَالُوا۟ رَبَّنَا بَٰعِدْ بَيْنَ أَسْفَارِنَا وَظَلَمُوٓا۟ أَنفُسَهُمْ فَجَعَلْنَٰهُمْ أَحَادِيثَ وَمَزَّقْنَٰهُمْ كُلَّ مُمَزَّقٍ ۚ إِنَّ فِى ذَٰلِكَ لَءَايَٰتٍۢ لِّكُلِّ صَبَّارٍۢ شَكُورٍۢ", 't': "«فقالوا ربنا بَعِّدْ» وفي قراءة باعد «بين أسفارنا» إلى الشام اجعلها مفاوز ليتطاولوا على الفقراء بركوب الرواحل وحمل الزاد والماء فبطروا النعمة «وظلموا أنفسهم» بالكفر «فجعلناهم أحاديث» لمن بعدهم في ذلك «ومزقناهم كل ممزق» فرقناهم في البلاد كل التفريق «إن في ذلك» المذكور «لآيات» عبر «لكل صبَّار» عن المعاصي «شكور» على النعم."},
  {'n': '20', 'v': "وَلَقَدْ صَدَّقَ عَلَيْهِمْ إِبْلِيسُ ظَنَّهُۥ فَٱتَّبَعُوهُ إِلَّا فَرِيقًۭا مِّنَ ٱلْمُؤْمِنِينَ", 't': "«ولقد صدق» بالتخفيف والتشديد «عليهم» أي الكفار منهم سبأ «إبليس ظنه» أنهم بإغوائه يتبعونه «فاتبعوه» فصدق بالتخفيف في ظنه أو صدق بالشديد ظنه أي وجده صادقا «إلا» بمعنى لكن «فريقا من المؤمنين» لبيان أي هم المؤمنون لم يتبعوه."},
  {'n': '21', 'v': "وَمَا كَانَ لَهُۥ عَلَيْهِم مِّن سُلْطَٰنٍ إِلَّا لِنَعْلَمَ مَن يُؤْمِنُ بِٱلْءَاخِرَةِ مِمَّنْ هُوَ مِنْهَا فِى شَكٍّۢ ۗ وَرَبُّكَ عَلَىٰ كُلِّ شَىْءٍ حَفِيظٌۭ", 't': "«وما كان له عليهم من سلطان» تسليط «إلا لنعلم» علم ظهور «من يؤمن بالآخرة ممن هو منها في شك» فنجازي كلا منهما «وربك على شيء حفيظ» رقيب."},
  {'n': '22', 'v': "قُلِ ٱدْعُوا۟ ٱلَّذِينَ زَعَمْتُم مِّن دُونِ ٱللَّهِ ۖ لَا يَمْلِكُونَ مِثْقَالَ ذَرَّةٍۢ فِى ٱلسَّمَٰوَٰتِ وَلَا فِى ٱلْأَرْضِ وَمَا لَهُمْ فِيهِمَا مِن شِرْكٍۢ وَمَا لَهُۥ مِنْهُم مِّن ظَهِيرٍۢ", 't': "«قل» يا محمد لكفار مكة «ادعوا الذين زعمتم» أي زعمتموهم آلهة «من دون الله» أي غيره لينفعوكم بزعمكم قال تعالى فيهم: «لا يملكون مثقال» وزن «ذرة» من خير أو شر «في السماوات ولا في الأرض وما لهم فيهما من شرك» شركة «وما له» تعالى «منهم» من الآلهة «من ظهير» معين."},
  {'n': '23', 'v': "وَلَا تَنفَعُ ٱلشَّفَٰعَةُ عِندَهُۥٓ إِلَّا لِمَنْ أَذِنَ لَهُۥ ۚ حَتَّىٰٓ إِذَا فُزِّعَ عَن قُلُوبِهِمْ قَالُوا۟ مَاذَا قَالَ رَبُّكُمْ ۖ قَالُوا۟ ٱلْحَقَّ ۖ وَهُوَ ٱلْعَلِىُّ ٱلْكَبِيرُ", 't': "«ولا تنفع الشفاعة عنده» تعالى ردا لقولهم إن آلهتهم تشفع عنده «إلا لمن أذن» بفتح الهمزة وضمها «له» فيها «حتى إذا فَزَّع» بالبناء والمفعول «عن قلوبهم» كشف عنها الفزع بالإذن فيها «قالوا» قال بعضهم لبعض استبشارا «ماذا قال ربكم» فيها «قالوا» القول «الحق» أي قد أذن فيها «وهو العليّ» فوق خلقه بالقهر «الكبير» العظيم."},
  {'n': '24', 'v': "۞ قُلْ مَن يَرْزُقُكُم مِّنَ ٱلسَّمَٰوَٰتِ وَٱلْأَرْضِ ۖ قُلِ ٱللَّهُ ۖ وَإِنَّآ أَوْ إِيَّاكُمْ لَعَلَىٰ هُدًى أَوْ فِى ضَلَٰلٍۢ مُّبِينٍۢ", 't': "«قل من يرزقكم من السماوات» المطر «والأرض» النبات «قل الله» إن لم يقولوه، لا جواب غيره «وإنا أو إياكم» أي أحد الفريقين «لعلى هدى أو في ضلال مبين» بين، في الإبهام إذا وفقوا له."},
  {'n': '25', 'v': "قُل لَّا تُسْـَٔلُونَ عَمَّآ أَجْرَمْنَا وَلَا نُسْـَٔلُ عَمَّا تَعْمَلُونَ", 't': "«قل لا تسألون عما أجرمنا» أذنبنا «ولا نسأل عما تعملون» لأنا بريئون منكم."},
  {'n': '26', 'v': "قُلْ يَجْمَعُ بَيْنَنَا رَبُّنَا ثُمَّ يَفْتَحُ بَيْنَنَا بِٱلْحَقِّ وَهُوَ ٱلْفَتَّاحُ ٱلْعَلِيمُ", 't': "«قل يجمع بينا ربنا» يوم القيامة «ثم يفتح» يحكم «بيننا بالحق» فيدخل المحقين الجنة والمبطلين النار «وهو الفتاح» الحاكم «العليم» بما يحكم به."},
  {'n': '27', 'v': "قُلْ أَرُونِىَ ٱلَّذِينَ أَلْحَقْتُم بِهِۦ شُرَكَآءَ ۖ كَلَّا ۚ بَلْ هُوَ ٱللَّهُ ٱلْعَزِيزُ ٱلْحَكِيمُ", 't': "«قل أروني» أعلموني «الذين ألحقتم به شركاء» في العبادة «كلا» ردع لهم عن اعتقاد شريك له «بل هو الله العزيز» الغالب على أمره «الحكيم» في تدبيره لخلقه فلا يكون له شريك في ملكه."},
  {'n': '28', 'v': "وَمَآ أَرْسَلْنَٰكَ إِلَّا كَآفَّةًۭ لِّلنَّاسِ بَشِيرًۭا وَنَذِيرًۭا وَلَٰكِنَّ أَكْثَرَ ٱلنَّاسِ لَا يَعْلَمُونَ", 't': "«وما أرسلناك إلا كافة» حال من الناس قدم للاهتمام «للناس بشيرا» مبشرا للمؤمنين بالجنة «ونذيرا» منذرا للكافرين بالعذاب «ولكن أكثر الناس» أي كفار مكة «لا يعلمون» ذلك."},
  {'n': '29', 'v': "وَيَقُولُونَ مَتَىٰ هَٰذَا ٱلْوَعْدُ إِن كُنتُمْ صَٰدِقِينَ", 't': "«ويقولون متى هذا الوعد» بالعذاب «إن كنتم صادقين» فيه."},
  {'n': '30', 'v': "قُل لَّكُم مِّيعَادُ يَوْمٍۢ لَّا تَسْتَـْٔخِرُونَ عَنْهُ سَاعَةًۭ وَلَا تَسْتَقْدِمُونَ", 't': "«قل لكم ميعاد يوم لا تستأخرون عنه ساعة ولا تستقدمون» عليه وهو يوم القيامة."},
  {'n': '31', 'v': "وَقَالَ ٱلَّذِينَ كَفَرُوا۟ لَن نُّؤْمِنَ بِهَٰذَا ٱلْقُرْءَانِ وَلَا بِٱلَّذِى بَيْنَ يَدَيْهِ ۗ وَلَوْ تَرَىٰٓ إِذِ ٱلظَّٰلِمُونَ مَوْقُوفُونَ عِندَ رَبِّهِمْ يَرْجِعُ بَعْضُهُمْ إِلَىٰ بَعْضٍ ٱلْقَوْلَ يَقُولُ ٱلَّذِينَ ٱسْتُضْعِفُوا۟ لِلَّذِينَ ٱسْتَكْبَرُوا۟ لَوْلَآ أَنتُمْ لَكُنَّا مُؤْمِنِينَ", 't': "«وقال الذين كفروا» من أهل مكة «لن نؤمن بهذا القرآن ولا بالذي بين يديه» أي تقدمه كالتوراة والإنجيل الدالين على البعث لإنكارهم له قال تعالى فيهم «ولو ترى» يا محمد «إذ الظالمون» الكافرون «موقوفون عند ربهم يرجع بعضهم إلى بعض القول يقول الذين استضعفوا» الأتباع «للذين استكبروا» الرؤساء «لولا أنتم» صددتمونا عن الإيمان «لكنا مؤمنين» بالنبي."},
  {'n': '32', 'v': "قَالَ ٱلَّذِينَ ٱسْتَكْبَرُوا۟ لِلَّذِينَ ٱسْتُضْعِفُوٓا۟ أَنَحْنُ صَدَدْنَٰكُمْ عَنِ ٱلْهُدَىٰ بَعْدَ إِذْ جَآءَكُم ۖ بَلْ كُنتُم مُّجْرِمِينَ", 't': "«قال الذين استكبروا للذين استضعفوا أنحن صددناكم عن الهدى بعد إذ جاءكم» لا «بل كنتم مجرمين» في أنفسكم."},
  {'n': '33', 'v': "وَقَالَ ٱلَّذِينَ ٱسْتُضْعِفُوا۟ لِلَّذِينَ ٱسْتَكْبَرُوا۟ بَلْ مَكْرُ ٱلَّيْلِ وَٱلنَّهَارِ إِذْ تَأْمُرُونَنَآ أَن نَّكْفُرَ بِٱللَّهِ وَنَجْعَلَ لَهُۥٓ أَندَادًۭا ۚ وَأَسَرُّوا۟ ٱلنَّدَامَةَ لَمَّا رَأَوُا۟ ٱلْعَذَابَ وَجَعَلْنَا ٱلْأَغْلَٰلَ فِىٓ أَعْنَاقِ ٱلَّذِينَ كَفَرُوا۟ ۚ هَلْ يُجْزَوْنَ إِلَّا مَا كَانُوا۟ يَعْمَلُونَ", 't': "«وقال الذين استضعفوا للذين استكبروا بل مكر الليل والنهار» أي مكر فيهما منكم بنا «إذ تأمروننا أن نكفر بالله ونجعل له أندادا» شركاء «وأسرُّوا» أي الفريقين «الندامة» على ترك الإيمان به «لما رأوا العذاب» أي أخفاها كل عن رفيقه مخافة التعيير «وجعلنا الأغلال في أعناق الذين كفروا» في النار «هل» ما «يجزون إلا» جزاء «ما كانوا يعملون» في الدنيا."},
  {'n': '34', 'v': "وَمَآ أَرْسَلْنَا فِى قَرْيَةٍۢ مِّن نَّذِيرٍ إِلَّا قَالَ مُتْرَفُوهَآ إِنَّا بِمَآ أُرْسِلْتُم بِهِۦ كَٰفِرُونَ", 't': "«وما أرسلنا في قرية من نذير إلا قال مترفوها» رؤساؤها المتنعمون «إنا بما أرسلتم به كافرون»."},
  {'n': '35', 'v': "وَقَالُوا۟ نَحْنُ أَكْثَرُ أَمْوَٰلًۭا وَأَوْلَٰدًۭا وَمَا نَحْنُ بِمُعَذَّبِينَ", 't': "«وقالوا نحن أكثر أموالا وأولادا» ممن آمن «وما نحن بمعذبين»."},
  {'n': '36', 'v': "قُلْ إِنَّ رَبِّى يَبْسُطُ ٱلرِّزْقَ لِمَن يَشَآءُ وَيَقْدِرُ وَلَٰكِنَّ أَكْثَرَ ٱلنَّاسِ لَا يَعْلَمُونَ", 't': "«قل إن ربي يبسط الرزق» يوسعه «لمن يشاء» امتحانا «ويقدر» يضيقه لمن يشاء ابتلاءً «ولكن أكثر الناس» أي كفار مكة «لا يعلمون» ذلك."},
  {'n': '37', 'v': "وَمَآ أَمْوَٰلُكُمْ وَلَآ أَوْلَٰدُكُم بِٱلَّتِى تُقَرِّبُكُمْ عِندَنَا زُلْفَىٰٓ إِلَّا مَنْ ءَامَنَ وَعَمِلَ صَٰلِحًۭا فَأُو۟لَٰٓئِكَ لَهُمْ جَزَآءُ ٱلضِّعْفِ بِمَا عَمِلُوا۟ وَهُمْ فِى ٱلْغُرُفَٰتِ ءَامِنُونَ", 't': "«وما أموالكم ولا أولادكم بالتي تقربكم عندنا زلفى» قربى، أي تقريبا «إلا» لكن «من آمن وعمل صالحا فأولئك لهم جزاءُ الضعف بما عملوا» أي جزاء العمل: الحسنة مثلا بعشر فأكثر «وهم في الغرفات» من الجنة «آمنون» من الموت وغيره، وفي قراءة الغرفة بمعنى الجمع."},
  {'n': '38', 'v': "وَٱلَّذِينَ يَسْعَوْنَ فِىٓ ءَايَٰتِنَا مُعَٰجِزِينَ أُو۟لَٰٓئِكَ فِى ٱلْعَذَابِ مُحْضَرُونَ", 't': "«والذين يسعوْن في آياتنا» القرآن بالإبطال «معجِّزين» لنا مقدّرين عجزنا وأنهم يفوتوننا «أولئك في العذاب محضرون»."},
  {'n': '39', 'v': "قُلْ إِنَّ رَبِّى يَبْسُطُ ٱلرِّزْقَ لِمَن يَشَآءُ مِنْ عِبَادِهِۦ وَيَقْدِرُ لَهُۥ ۚ وَمَآ أَنفَقْتُم مِّن شَىْءٍۢ فَهُوَ يُخْلِفُهُۥ ۖ وَهُوَ خَيْرُ ٱلرَّٰزِقِينَ", 't': "«قل إن ربي يبسط الرزق» يوسعه «لمن يشاء من عباده» امتحانا «ويقدر» يضيقه «له» بعد البسط أو لمن يشاء ابتلاءً «وما أنفقتم من شيء» في الخير «فهو يخلفه وهو خير الرازقين» يقال: كل إنسان يرزق عائلته، أي من رزق الله."},
  {'n': '40', 'v': "وَيَوْمَ يَحْشُرُهُمْ جَمِيعًۭا ثُمَّ يَقُولُ لِلْمَلَٰٓئِكَةِ أَهَٰٓؤُلَآءِ إِيَّاكُمْ كَانُوا۟ يَعْبُدُونَ", 't': "«و» اذكر «يوم نحشرهم جميعا» أي المشركين «ثم نقول للملائكة أهؤلاء إياكم» بتحقيق الهمزتين وإبدال الأولى ياء وإسقاطها «كانوا يعبدون»."},
