  {'n': '108', 'v': "وَتَرَكْنَا عَلَيْهِ فِى ٱلْءَاخِرِينَ", 't': "«وتركنا» أبقينا «عليه في الآخرين» ثناءً حسنا."},
  {'n': '109', 'v': "سَلَٰمٌ عَلَىٰٓ إِبْرَٰهِيمَ", 't': "«سلام» منا «على إبراهيم»."},
