  {'n': '26', 'v': "يَٰدَاوُۥدُ إِنَّا جَعَلْنَٰكَ خَلِيفَةًۭ فِى ٱلْأَرْضِ فَٱحْكُم بَيْنَ ٱلنَّاسِ بِٱلْحَقِّ وَلَا تَتَّبِعِ ٱلْهَوَىٰ فَيُضِلَّكَ عَن سَبِيلِ ٱللَّهِ ۚ إِنَّ ٱلَّذِينَ يَضِلُّونَ عَن سَبِيلِ ٱللَّهِ لَهُمْ عَذَابٌۭ شَدِيدٌۢ بِمَا نَسُوا۟ يَوْمَ ٱلْحِسَابِ", 't': "«يا داود إنا جعلناك خليفة في الأرض» تدبر أمر الناس «فاحكم بين الناس بالحق ولا تتبع الهوى» أي هوى النفس «فيضلك عن سبيل الله» أي عن الدلائل الدالة على توحيده «إن الذين يضلون عن سبيل الله» أي عن الإيمان بالله «لهم عذاب شديد بما نسوا» بنسيانهم «يوم الحساب» المرتب عليه تركهم الإيمان، وقالوا أيقنوا بيوم الحساب لآمنوا في الدنيا."},
  {'n': '27', 'v': "وَمَا خَلَقْنَا ٱلسَّمَآءَ وَٱلْأَرْضَ وَمَا بَيْنَهُمَا بَٰطِلًۭا ۚ ذَٰلِكَ ظَنُّ ٱلَّذِينَ كَفَرُوا۟ ۚ فَوَيْلٌۭ لِّلَّذِينَ كَفَرُوا۟ مِنَ ٱلنَّارِ", 't': "«وما خلقنا السماء والأرض وما بينهما باطلا» عبثا «ذلك» أي خلق ما ذكر لا لشيء «ظن الذين كفروا» من أهل مكة «فويل» وادِ «للذين كفروا من النار»."},
  {'n': '28', 'v': "أَمْ نَجْعَلُ ٱلَّذِينَ ءَامَنُوا۟ وَعَمِلُوا۟ ٱلصَّٰلِحَٰتِ كَٱلْمُفْسِدِينَ فِى ٱلْأَرْضِ أَمْ نَجْعَلُ ٱلْمُتَّقِينَ كَٱلْفُجَّارِ", 't': "«أم نجعل الذين آمنوا وعملوا الصالحات كالمفسدين في الأرض أم نجعل المتقين كالفجار» نزل لما قال كفار مكة للمؤمنين إنا نعطى في الآخرة مثل ما تعطون، وأم بمعنى همزة الإنكار."},
  {'n': '29', 'v': "كِتَٰبٌ أَنزَلْنَٰهُ إِلَيْكَ مُبَٰرَكٌۭ لِّيَدَّبَّرُوٓا۟ ءَايَٰتِهِۦ وَلِيَتَذَكَّرَ أُو۟لُوا۟ ٱلْأَلْبَٰبِ", 't': "«كتاب» خبر مبتدأ محذوف أي هذا «أنزلناه إليك مبارك ليدَّبروا» أصله يتدبروا أدغمت التاء في الدال «آياته» ينظروا في معانيها فيؤمنوا «وليتذكر» يتعظ «أولوا الألباب» أصحاب العقول."},
  {'n': '30', 'v': "وَوَهَبْنَا لِدَاوُۥدَ سُلَيْمَٰنَ ۚ نِعْمَ ٱلْعَبْدُ ۖ إِنَّهُۥٓ أَوَّابٌ", 't': "«ووهبنا لداود سلمان» ابنه «نعم العبد» أي سليمان «إنه أوَّاب» رجّاع في التسبيح والذكر في جميع الأوقات."},
  {'n': '31', 'v': "إِذْ عُرِضَ عَلَيْهِ بِٱلْعَشِىِّ ٱلصَّٰفِنَٰتُ ٱلْجِيَادُ", 't': "«إذ عرض عليه بالعشي» هو ما بعد الزوال «الصافنات» الخيل جمع صافنة وهي القائمة على ثلاث وإقامة الأخرى على طرف الحافر وهو من صفن يصفن صفونا «الجياد» الخيل جمع جواد وهو السابق، المعنى أنها إذا استوقفت سكنت وإن ركضت سبقت وكانت ألف فرس عرضت عليه بعد ان صلى الظهر لإرادته الجهاد عليها لعدو فعند بلوغ العرض منها تسعمائة غربت الشمس ولم يكن صلى العصر فاغتم."},
  {'n': '32', 'v': "فَقَالَ إِنِّىٓ أَحْبَبْتُ حُبَّ ٱلْخَيْرِ عَن ذِكْرِ رَبِّى حَتَّىٰ تَوَارَتْ بِٱلْحِجَابِ", 't': "«فقال إني أحببت» أي أردت «حب الخير» أي الخيل «عن ذكر ربي» أي صلاة العصر «حتى توارت» أي الشمس «بالحجاب» أي استترت بما يحجبها عن الأبصار."},
  {'n': '33', 'v': "رُدُّوهَا عَلَىَّ ۖ فَطَفِقَ مَسْحًۢا بِٱلسُّوقِ وَٱلْأَعْنَاقِ", 't': "«ردُّوها عليَّ» أي الخيل المعروضة فردوها «فطفق مسحا» بالسيف «بالسوق» جمع ساق «والأعناق» أي ذبحها وقطع أرجلها تقربا إلى الله تعالى حيث اشتغل بها عن الصلاة بلحمها فعوضه الله خيرا منها وأسرع، وهي الريح تجري بأمره كيف شاء."},
  {'n': '34', 'v': "وَلَقَدْ فَتَنَّا سُلَيْمَٰنَ وَأَلْقَيْنَا عَلَىٰ كُرْسِيِّهِۦ جَسَدًۭا ثُمَّ أَنَابَ", 't': "«ولقد فتنا سليمان» ابتليناه بسلب ملكه وذلك لتزوجه بامرأة هواها وكانت تعبد الصنم في داره من غير علمه وكان ملكه في خاتمه فنزعه مرة عند إرادة الخلاء ووضعه عند امرأته المسماة بالأمينة على عادته فجاءها جني في صورة سليمان فأخذه منها «وألقينا على كرسيه جسدا» هو ذلك الجني وهو صخر أو غيره جلس على كرسي سليمان وعكفت عليه الطير وغيرها فخرج سليمان في غير هيئته فرآه على كرسيه وقال للناس أنا سليمان فأنكره «ثم أناب» رجع سليمان إلى ملكه بعد أيام بأن وصل إلى الخاتم فلبسه وجلس على كرسيه."},
  {'n': '35', 'v': "قَالَ رَبِّ ٱغْفِرْ لِى وَهَبْ لِى مُلْكًۭا لَّا يَنۢبَغِى لِأَحَدٍۢ مِّنۢ بَعْدِىٓ ۖ إِنَّكَ أَنتَ ٱلْوَهَّابُ", 't': "«قال رب اغفر لي وهب لي ملكا لا ينبغي» لا يكون «لأحد من بعدي» أي سواي نحو (فمن يهديه من بعد الله) أي سوى الله «إنك أنت الوهاب»."},
  {'n': '36', 'v': "فَسَخَّرْنَا لَهُ ٱلرِّيحَ تَجْرِى بِأَمْرِهِۦ رُخَآءً حَيْثُ أَصَابَ", 't': "«فسخرنا له الريح تجري بأمره رُخاء» لينة «حيث أصاب» أراد."},
  {'n': '37', 'v': "وَٱلشَّيَٰطِينَ كُلَّ بَنَّآءٍۢ وَغَوَّاصٍۢ", 't': "«والشياطين كل بناءٍ» يبني الأبنية العجيبة «وغوَّاص» في البحر يستخرج اللؤلؤ."},
  {'n': '38', 'v': "وَءَاخَرِينَ مُقَرَّنِينَ فِى ٱلْأَصْفَادِ", 't': "«وآخرين» منهم «مقرنين» مشدودين «في الأصفاد» القيود بجمع أيديهم إلى أعناقهم."},
  {'n': '39', 'v': "هَٰذَا عَطَآؤُنَا فَٱمْنُنْ أَوْ أَمْسِكْ بِغَيْرِ حِسَابٍۢ", 't': "وقلنا له «هذا عطاؤنا فامنن» أعط منه من شئت «أو أمسك» عن الإعطاء «بغير حساب» أي لا حساب عليك في ذلك."},
  {'n': '40', 'v': "وَإِنَّ لَهُۥ عِندَنَا لَزُلْفَىٰ وَحُسْنَ مَـَٔابٍۢ", 't': "«وإن له عندنا لزلفى وحسن مآب» تقدم مثله."},
  {'n': '41', 'v': "وَٱذْكُرْ عَبْدَنَآ أَيُّوبَ إِذْ نَادَىٰ رَبَّهُۥٓ أَنِّى مَسَّنِىَ ٱلشَّيْطَٰنُ بِنُصْبٍۢ وَعَذَابٍ", 't': "«واذكر عبدنا أيوب إذ نادى ربه أني» أي بأني «مسنيَ الشيطان بنصب» ضر «وعذاب» ألم، ونسب ذلك إلى الشيطان وإن كانت الأشياء كلها من الله تأدبا معه تعالى."},
  {'n': '42', 'v': "ٱرْكُضْ بِرِجْلِكَ ۖ هَٰذَا مُغْتَسَلٌۢ بَارِدٌۭ وَشَرَابٌۭ", 't': "وقيل له «اركض» اضرب «برجلك» الأرض فضرب فنبعت عين ماء فقيل: «هذا مغتسل» ماء تغتسل به «بارد وشراب» تشرب منه، فاغتسل وشرب فذهب عنه كل داء كان بباطنه وظاهره."},
  {'n': '43', 'v': "وَوَهَبْنَا لَهُۥٓ أَهْلَهُۥ وَمِثْلَهُم مَّعَهُمْ رَحْمَةًۭ مِّنَّا وَذِكْرَىٰ لِأُو۟لِى ٱلْأَلْبَٰبِ", 't': "«ووهبنا له أهله ومثلهم معهم» أي أحيا الله له من مات من أولاده ورزقه مثلهم «رحمة» نعمة «منا وذكرى» عظة «لأولي الألباب» لأصحاب العقول."},
  {'n': '44', 'v': "وَخُذْ بِيَدِكَ ضِغْثًۭا فَٱضْرِب بِّهِۦ وَلَا تَحْنَثْ ۗ إِنَّا وَجَدْنَٰهُ صَابِرًۭا ۚ نِّعْمَ ٱلْعَبْدُ ۖ إِنَّهُۥٓ أَوَّابٌۭ", 't': "«وخذ بيدك ضغثا» هو حزمة من حشيش أو قضبان «فاضرب به» زوجتك وكان قد حلف ليضربها مائة ضربة لإبطائها عليه يوما «ولا تحنث» بترك ضربها فأخذ مائة عود من الإذخر أو غيره فضربها به ضربة واحدة «إنا وجدناه صابرا نعم العبد» أيوب «إنه أوَّاب» رجّاع إلى الله تعالى."},
  {'n': '45', 'v': "وَٱذْكُرْ عِبَٰدَنَآ إِبْرَٰهِيمَ وَإِسْحَٰقَ وَيَعْقُوبَ أُو۟لِى ٱلْأَيْدِى وَٱلْأَبْصَٰرِ", 't': "«واذكر عبادنا إبراهيم وإسحاق ويعقوب أولي الأيدى» أصحاب القوى في العبادة «والأبصار» البصائر في الدين، وفي قراءة عبدنا وإبراهيم بيان له وما بعده عطف على عبدنا."},
  {'n': '46', 'v': "إِنَّآ أَخْلَصْنَٰهُم بِخَالِصَةٍۢ ذِكْرَى ٱلدَّارِ", 't': "«إنا أخلصناهم بخالصة» هي «ذكرى الدار» الآخرة، أي ذكرها والعمل لها، وفي قراءة بالإضافة وهي للبيان."},
  {'n': '47', 'v': "وَإِنَّهُمْ عِندَنَا لَمِنَ ٱلْمُصْطَفَيْنَ ٱلْأَخْيَارِ", 't': "«وإنهم عندنا لمن المصطفين» المختارين «الأخيار» جمع خيّر بالتشديد."},
  {'n': '48', 'v': "وَٱذْكُرْ إِسْمَٰعِيلَ وَٱلْيَسَعَ وَذَا ٱلْكِفْلِ ۖ وَكُلٌّۭ مِّنَ ٱلْأَخْيَارِ", 't': "«واذكر إسماعيل واليسع» وهو نبيّ واللام زائدة «وذا الكفل» اختلف في نبوَّته، قيل كفل مائة نبي فروا إليه من القتل «وكل» أي كلهم «من الأخيار» جمع خيّر بالتثقيل."},
  {'n': '49', 'v': "هَٰذَا ذِكْرٌۭ ۚ وَإِنَّ لِلْمُتَّقِينَ لَحُسْنَ مَـَٔابٍۢ", 't': "«هذا ذكر» لهم بالثناء الجميل هنا «وإن للمتقين» الشاملين لهم «لحسن مآب» مرجع في الآخرة."},
  {'n': '50', 'v': "جَنَّٰتِ عَدْنٍۢ مُّفَتَّحَةًۭ لَّهُمُ ٱلْأَبْوَٰبُ", 't': "«جنات عدن» بدل أو عطف بيان لحسن مآب «مفتتحة لهم الأبواب» منها."},
  {'n': '51', 'v': "مُتَّكِـِٔينَ فِيهَا يَدْعُونَ فِيهَا بِفَٰكِهَةٍۢ كَثِيرَةٍۢ وَشَرَابٍۢ", 't': "«متكئين فيها» على الأرائك «يدعون فيها بفاكهة كثيرة وشراب»."},
  {'n': '52', 'v': "۞ وَعِندَهُمْ قَٰصِرَٰتُ ٱلطَّرْفِ أَتْرَابٌ", 't': "«وعندهم قاصرات الطرف» حابسات العين على أزواجهن «أتراب» أسنانهن واحدة وهن بنات ثلاث وثلاثين سنة جمع ترب."},
  {'n': '53', 'v': "هَٰذَا مَا تُوعَدُونَ لِيَوْمِ ٱلْحِسَابِ", 't': "«هذا» المذكور «ما يوعدون» بالغيبة وبالخطاب التفافا «ليوم الحساب» أي لأجله."},
  {'n': '54', 'v': "إِنَّ هَٰذَا لَرِزْقُنَا مَا لَهُۥ مِن نَّفَادٍ", 't': "«إن هذا لرزقنا ما له من نفاد» أي انقطاع والجملة حال من رزقنا أو خبر ثان لإن، أي دائما أو دائم."},
  {'n': '55', 'v': "هَٰذَا ۚ وَإِنَّ لِلطَّٰغِينَ لَشَرَّ مَـَٔابٍۢ", 't': "«هذا» المذكور للمؤمنين «وإن للطاغين» مستأنف «لشر مآب»."},
  {'n': '56', 'v': "جَهَنَّمَ يَصْلَوْنَهَا فَبِئْسَ ٱلْمِهَادُ", 't': "«جهنم يصلونها» يدخلونها «فبئس المهاد» الفراش."},
  {'n': '57', 'v': "هَٰذَا فَلْيَذُوقُوهُ حَمِيمٌۭ وَغَسَّاقٌۭ", 't': "«هذا» أي العذاب المفهوم مما بعده «فليذوقوه حميم» أي ماء حار محرق «وغسَّاق» بالتخفيف والتشديد: ما يسيل من صديد أهل النار."},
  {'n': '58', 'v': "وَءَاخَرُ مِن شَكْلِهِۦٓ أَزْوَٰجٌ", 't': "«وآخر» بالجمع والإفراد «من شكله» أي مثل المذكور من الحميم والغساق «أزواج» أصناف، أي عذابهم من أنواع مختلفة."},
  {'n': '59', 'v': "هَٰذَا فَوْجٌۭ مُّقْتَحِمٌۭ مَّعَكُمْ ۖ لَا مَرْحَبًۢا بِهِمْ ۚ إِنَّهُمْ صَالُوا۟ ٱلنَّارِ", 't': "ويقال لهم عند دخولهم النار بأتباعهم «هذا فوج» جمع «مقتحم» داخل «معكم» النار بشدة فيقول المتبعون «لا مرحبا بهم» أي لا سعة عليهم «إنهم صالوا النار»."},
  {'n': '60', 'v': "قَالُوا۟ بَلْ أَنتُمْ لَا مَرْحَبًۢا بِكُمْ ۖ أَنتُمْ قَدَّمْتُمُوهُ لَنَا ۖ فَبِئْسَ ٱلْقَرَارُ", 't': "«قالوا» أي الأتباع «بل أنتم لا مرحبا بكم أنتم قدمتموه» أي الكفر «لنا فبئس القرار» لنا ولكم النار."},
  {'n': '61', 'v': "قَالُوا۟ رَبَّنَا مَن قَدَّمَ لَنَا هَٰذَا فَزِدْهُ عَذَابًۭا ضِعْفًۭا فِى ٱلنَّارِ", 't': "«قالوا» أيضا «ربنا من قدم لنا هذا فزده عذابا ضعفا» أي مثل عذابه على كفره «في النار»."},
  {'n': '62', 'v': "وَقَالُوا۟ مَا لَنَا لَا نَرَىٰ رِجَالًۭا كُنَّا نَعُدُّهُم مِّنَ ٱلْأَشْرَارِ", 't': "«وقالوا» أي كفار مكة وهم في النار «ما لنا لا نرى رجالا كنا نعدهم» في الدنيا «من الأشرار»."},
  {'n': '63', 'v': "أَتَّخَذْنَٰهُمْ سِخْرِيًّا أَمْ زَاغَتْ عَنْهُمُ ٱلْأَبْصَٰرُ", 't': "«اتَّخذناهم سخريا» بضم السين وكسرها: كنا نسخر بهم في الدنيا، والياء للنسب: أي أمفقودون هم «أم زاغت» مالت «عنهم الأبصار» فلم ترهم، وهم فقراء المسلمين كعمار وبلال وصهيب وسليمان."},
  {'n': '64', 'v': "إِنَّ ذَٰلِكَ لَحَقٌّۭ تَخَاصُمُ أَهْلِ ٱلنَّارِ", 't': "«إن ذلك لحق» واجب وقوعه وهو «تخاصم أهل النار» كما تقدم."},
