  {'n': '10', 'v': "إِنَّ ٱلَّذِينَ كَفَرُوا۟ يُنَادَوْنَ لَمَقْتُ ٱللَّهِ أَكْبَرُ مِن مَّقْتِكُمْ أَنفُسَكُمْ إِذْ تُدْعَوْنَ إِلَى ٱلْإِيمَٰنِ فَتَكْفُرُونَ", 't': "«إن الذين كفروا ينادوْن» من قبل الملائكة وهم يمقتون أنفسهم عند دخولهم النار «لمقت الله» إياكم «أكبر من مقتكم أنفسكم إذ تدعوْن» في الدنيا «إلى الإيمان فتكفرون»."},
  {'n': '11', 'v': "قَالُوا۟ رَبَّنَآ أَمَتَّنَا ٱثْنَتَيْنِ وَأَحْيَيْتَنَا ٱثْنَتَيْنِ فَٱعْتَرَفْنَا بِذُنُوبِنَا فَهَلْ إِلَىٰ خُرُوجٍۢ مِّن سَبِيلٍۢ", 't': "«قالوا ربنا أمتَّنا اثنتين» إماتتين «وأحييتنا اثنتين» إحياءتين لأنهم نطفٌ أموات فأحيوا ثم أميتوا ثم أحيوا للبعث «فاعترفنا بذنوبنا» بكفرنا بالبعث «فهل إلى خروج» من النار والرجوع إلى الدنيا لنطيع ربنا «من سبيل» طريق وجوابهم: لا."},
  {'n': '12', 'v': "ذَٰلِكُم بِأَنَّهُۥٓ إِذَا دُعِىَ ٱللَّهُ وَحْدَهُۥ كَفَرْتُمْ ۖ وَإِن يُشْرَكْ بِهِۦ تُؤْمِنُوا۟ ۚ فَٱلْحُكْمُ لِلَّهِ ٱلْعَلِىِّ ٱلْكَبِيرِ", 't': "«ذلكم» أي العذاب أنتم فيه «بأنه» أي بسبب أنه في الدنيا «إذا دعي الله وحده كفرتم» بتوحيده «وإن يُشرَك به» يجعل له شريك «تؤمنوا» تصدقوا بالإشراك «فالحكم» في تعذيبكم «لله العليِّ» على خلقه «الكبير» العظيم."},
  {'n': '13', 'v': "هُوَ ٱلَّذِى يُرِيكُمْ ءَايَٰتِهِۦ وَيُنَزِّلُ لَكُم مِّنَ ٱلسَّمَآءِ رِزْقًۭا ۚ وَمَا يَتَذَكَّرُ إِلَّا مَن يُنِيبُ", 't': "«هو الذي يريكم آياته» دلائل توحيده «وينزل لكم من السماء رزقا» بالمطر «وما يتذكر» يتعظ «إلا من ينيب» يرجع عن الشرك."},
  {'n': '14', 'v': "فَٱدْعُوا۟ ٱللَّهَ مُخْلِصِينَ لَهُ ٱلدِّينَ وَلَوْ كَرِهَ ٱلْكَٰفِرُونَ", 't': "«فادعوا الله» اعبدوه «مخلصين له الدين» من الشرك «ولو كره الكافرون» إخلاصكم منه."},
  {'n': '15', 'v': "رَفِيعُ ٱلدَّرَجَٰتِ ذُو ٱلْعَرْشِ يُلْقِى ٱلرُّوحَ مِنْ أَمْرِهِۦ عَلَىٰ مَن يَشَآءُ مِنْ عِبَادِهِۦ لِيُنذِرَ يَوْمَ ٱلتَّلَاقِ", 't': "«رفيع الدرجات» أي الله عظيم الصفات، أو رافع درجات المؤمنين في الجنة «ذو العرش» خالقه «يلقي الروح» الوحي «من أمره» أي قوله «على من يشاء من عباده لينذر» يخوَّف الملقى عليه الناس «يوم التلاق» بحذف الياء وإثباتها يوم القيامة لتلاقي أهل السماء والأرض، والعابد والمعبود، والظالم والمظلوم فيه."},
  {'n': '16', 'v': "يَوْمَ هُم بَٰرِزُونَ ۖ لَا يَخْفَىٰ عَلَى ٱللَّهِ مِنْهُمْ شَىْءٌۭ ۚ لِّمَنِ ٱلْمُلْكُ ٱلْيَوْمَ ۖ لِلَّهِ ٱلْوَٰحِدِ ٱلْقَهَّارِ", 't': "«يوم هم بارزون» خارجون من قبورهم «لا يخفى على الله منهم شيءٌ لمن الملك اليوم» بقوله تعالى، ويجيب نفسه «لله الواحد القهار» أي لخلقه."},
  {'n': '17', 'v': "ٱلْيَوْمَ تُجْزَىٰ كُلُّ نَفْسٍۭ بِمَا كَسَبَتْ ۚ لَا ظُلْمَ ٱلْيَوْمَ ۚ إِنَّ ٱللَّهَ سَرِيعُ ٱلْحِسَابِ", 't': "«اليوم تجزى كل نفس بما كسبت لا ظلم اليوم إن الله سريع الحساب» يحاسب جميع الخلق في قدر نصف نهار من أيام الدنيا لحديث بذلك."},
  {'n': '18', 'v': "وَأَنذِرْهُمْ يَوْمَ ٱلْءَازِفَةِ إِذِ ٱلْقُلُوبُ لَدَى ٱلْحَنَاجِرِ كَٰظِمِينَ ۚ مَا لِلظَّٰلِمِينَ مِنْ حَمِيمٍۢ وَلَا شَفِيعٍۢ يُطَاعُ", 't': "(وأنذرهم يوم الآزفة) يوم القيامة من أزف الرحيل: قرب (إذ القلوب) ترتفع خوفا (لدى) عند (الحناجر كاظمين) ممتلئين غما حال من القلوب عوملت بالجمع بالياء والنون معاملة أصحابها (ما للظالمين من حميم) محب (ولا شفيع يطاع) لا مفهوم للوصف إذ لا شفيع لهم أصلا \"\" فما لنا من شافعين \"\" أوله مفهوم بناء على زعمهم أن لهم شفعاء، أي لو شفعوا فرضا لم يقبلوا."},
  {'n': '19', 'v': "يَعْلَمُ خَآئِنَةَ ٱلْأَعْيُنِ وَمَا تُخْفِى ٱلصُّدُورُ", 't': "«يعلم أي الله «خائنة الأعين» بمارقتها النظر إلى محرَّم «وما تخفي الصدور» القلوب."},
  {'n': '20', 'v': "وَٱللَّهُ يَقْضِى بِٱلْحَقِّ ۖ وَٱلَّذِينَ يَدْعُونَ مِن دُونِهِۦ لَا يَقْضُونَ بِشَىْءٍ ۗ إِنَّ ٱللَّهَ هُوَ ٱلسَّمِيعُ ٱلْبَصِيرُ", 't': "«والله يقضي بالحق والذين يدعون» يعبدون، أي كفار مكة بالياء والتاء «من دونه» وهم الأصنام «لا يقضون بشيءٍ» فكيف يكونون شركاء لله «إن الله هو السميع» لأقوالهم «البصير» بأفعالهم."},
  {'n': '21', 'v': "۞ أَوَلَمْ يَسِيرُوا۟ فِى ٱلْأَرْضِ فَيَنظُرُوا۟ كَيْفَ كَانَ عَٰقِبَةُ ٱلَّذِينَ كَانُوا۟ مِن قَبْلِهِمْ ۚ كَانُوا۟ هُمْ أَشَدَّ مِنْهُمْ قُوَّةًۭ وَءَاثَارًۭا فِى ٱلْأَرْضِ فَأَخَذَهُمُ ٱللَّهُ بِذُنُوبِهِمْ وَمَا كَانَ لَهُم مِّنَ ٱللَّهِ مِن وَاقٍۢ", 't': "«أوَ لم يسيروا في الأرض فينظروا كيف كان عاقبة الذين كانوا من قبلهم كانوا هم أشد منهم» وفي قراءة: منكم «قوة وآثارا في الأرض» من مصانع وقصور «فأخذهم الله» أهلكهم «بذنوبهم وما كان لهم من الله من واق» عذابه."},
  {'n': '22', 'v': "ذَٰلِكَ بِأَنَّهُمْ كَانَت تَّأْتِيهِمْ رُسُلُهُم بِٱلْبَيِّنَٰتِ فَكَفَرُوا۟ فَأَخَذَهُمُ ٱللَّهُ ۚ إِنَّهُۥ قَوِىٌّۭ شَدِيدُ ٱلْعِقَابِ", 't': "«ذلك بأنهم كانت تأتيهم رسلهم بالبينات» بالمعجزات الظاهرات «فكفروا فأخذهم الله إنه قويٌ شديد العقاب»."},
  {'n': '23', 'v': "وَلَقَدْ أَرْسَلْنَا مُوسَىٰ بِـَٔايَٰتِنَا وَسُلْطَٰنٍۢ مُّبِينٍ", 't': "«ولقد أرسلنا موسى بآياتنا وسلطان مبين» برهان بيَّن ظاهر."},
  {'n': '24', 'v': "إِلَىٰ فِرْعَوْنَ وَهَٰمَٰنَ وَقَٰرُونَ فَقَالُوا۟ سَٰحِرٌۭ كَذَّابٌۭ", 't': "«إلى فرعون وهامان وقارون فقالوا» هو «ساحرٌ كذاب»."},
  {'n': '25', 'v': "فَلَمَّا جَآءَهُم بِٱلْحَقِّ مِنْ عِندِنَا قَالُوا۟ ٱقْتُلُوٓا۟ أَبْنَآءَ ٱلَّذِينَ ءَامَنُوا۟ مَعَهُۥ وَٱسْتَحْيُوا۟ نِسَآءَهُمْ ۚ وَمَا كَيْدُ ٱلْكَٰفِرِينَ إِلَّا فِى ضَلَٰلٍۢ", 't': "«فلما جاءهم بالحق» بالصدق «من عندنا «قالوا اقتلوا أبناء الذين آمنوا معه واستحيوا» استبقوا «نساءهم وما كيْد الكافرين إلا في ضلال» هلاك."},
  {'n': '26', 'v': "وَقَالَ فِرْعَوْنُ ذَرُونِىٓ أَقْتُلْ مُوسَىٰ وَلْيَدْعُ رَبَّهُۥٓ ۖ إِنِّىٓ أَخَافُ أَن يُبَدِّلَ دِينَكُمْ أَوْ أَن يُظْهِرَ فِى ٱلْأَرْضِ ٱلْفَسَادَ", 't': "«وقال فرعون ذروني أقتل موسى» لأنهم كانوا يكفونه عن قتله «وليدع ربه» ليمنعه مني «إني أخاف أن يبدل دينكم» من عبادتكم إياي فتتبعوه «وأن يُظهر في الأرض الفساد» من قتل وغيره، وفي قراءة: أو، وفي أخرى بفتح الياء والهاء وضم الدال."},
  {'n': '27', 'v': "وَقَالَ مُوسَىٰٓ إِنِّى عُذْتُ بِرَبِّى وَرَبِّكُم مِّن كُلِّ مُتَكَبِّرٍۢ لَّا يُؤْمِنُ بِيَوْمِ ٱلْحِسَابِ", 't': "«وقال موسى» لقومه وقد سمع ذلك إني عذت بربي وربكم من كل متكبر لا يؤمن بيوم الحساب»."},
  {'n': '28', 'v': "وَقَالَ رَجُلٌۭ مُّؤْمِنٌۭ مِّنْ ءَالِ فِرْعَوْنَ يَكْتُمُ إِيمَٰنَهُۥٓ أَتَقْتُلُونَ رَجُلًا أَن يَقُولَ رَبِّىَ ٱللَّهُ وَقَدْ جَآءَكُم بِٱلْبَيِّنَٰتِ مِن رَّبِّكُمْ ۖ وَإِن يَكُ كَٰذِبًۭا فَعَلَيْهِ كَذِبُهُۥ ۖ وَإِن يَكُ صَادِقًۭا يُصِبْكُم بَعْضُ ٱلَّذِى يَعِدُكُمْ ۖ إِنَّ ٱللَّهَ لَا يَهْدِى مَنْ هُوَ مُسْرِفٌۭ كَذَّابٌۭ", 't': "«وقال رجل مؤمن من آل فرعون» قيل: هو ابن عمه «يكتم إيمانه أتقتلون رجلا أن» أي لأن «يقول ربيَ الله وقد جاءَكم بالبينات» بالمعجزات الظاهرات «من ربكم وإن يك كاذبا فعليه كذبه» أي ضرر كذبه «وإن يك صادقا يصبكم بعض الذي يعدكم» به من العذاب عاجلا «إن الله لا يهدي من هو مسرف» مشرك «كذاب» مفتر."},
  {'n': '29', 'v': "يَٰقَوْمِ لَكُمُ ٱلْمُلْكُ ٱلْيَوْمَ ظَٰهِرِينَ فِى ٱلْأَرْضِ فَمَن يَنصُرُنَا مِنۢ بَأْسِ ٱللَّهِ إِن جَآءَنَا ۚ قَالَ فِرْعَوْنُ مَآ أُرِيكُمْ إِلَّا مَآ أَرَىٰ وَمَآ أَهْدِيكُمْ إِلَّا سَبِيلَ ٱلرَّشَادِ", 't': "«يا قوم لكم الملك اليوم ظاهرين» غالبين حال «في الأرض» أرض مصر «فمن ينصرنا من بأس الله» عذابه إن قتلتم أولياءه «إن جاءنا» أي لا ناصر لنا «قال فرعون ما أريكم إلا ما أرى» أي ما أشير عليكم إلا بما أشير به على نفسي وهو قتل موسى «وما أهديكم إلا سبيل الرشاد» طريق الصواب."},
  {'n': '30', 'v': "وَقَالَ ٱلَّذِىٓ ءَامَنَ يَٰقَوْمِ إِنِّىٓ أَخَافُ عَلَيْكُم مِّثْلَ يَوْمِ ٱلْأَحْزَابِ", 't': "«وقال الذي آمن يا قوم إنِّي أخاف عليكم مثل يوم الأحزاب» أي يوم حزب بعد حزب."},
  {'n': '31', 'v': "مِثْلَ دَأْبِ قَوْمِ نُوحٍۢ وَعَادٍۢ وَثَمُودَ وَٱلَّذِينَ مِنۢ بَعْدِهِمْ ۚ وَمَا ٱللَّهُ يُرِيدُ ظُلْمًۭا لِّلْعِبَادِ", 't': "«مثل دأب قوم نوح وعاد وثمود والذين من بعدهم» مثل بدل من مثل قبله، أي مثل جزاء عادة من كفر قبلكم من تعذيبهم في الدنيا «وما الله يريد ظلما لعباد»."},
  {'n': '32', 'v': "وَيَٰقَوْمِ إِنِّىٓ أَخَافُ عَلَيْكُمْ يَوْمَ ٱلتَّنَادِ", 't': "«ويا قوم إني أخاف عليكم يوم التناد» بحذف الياء وإثباتها، أي يوم القيامة يكثر فيه نداء أصحاب الجنة أصحاب النار وبالعكس، والنداء بالسعادة لأهلها وبالشقاوة لأهلها وغير ذلك."},
  {'n': '33', 'v': "يَوْمَ تُوَلُّونَ مُدْبِرِينَ مَا لَكُم مِّنَ ٱللَّهِ مِنْ عَاصِمٍۢ ۗ وَمَن يُضْلِلِ ٱللَّهُ فَمَا لَهُۥ مِنْ هَادٍۢ", 't': "«يوم تولون مدبرين» عن موقف الحساب إلى النار «ما لكم من الله» أي من عذابه «من عاصم» مانع «ومن يضلل الله فما له من هادِ»."},
  {'n': '34', 'v': "وَلَقَدْ جَآءَكُمْ يُوسُفُ مِن قَبْلُ بِٱلْبَيِّنَٰتِ فَمَا زِلْتُمْ فِى شَكٍّۢ مِّمَّا جَآءَكُم بِهِۦ ۖ حَتَّىٰٓ إِذَا هَلَكَ قُلْتُمْ لَن يَبْعَثَ ٱللَّهُ مِنۢ بَعْدِهِۦ رَسُولًۭا ۚ كَذَٰلِكَ يُضِلُّ ٱللَّهُ مَنْ هُوَ مُسْرِفٌۭ مُّرْتَابٌ", 't': "«ولقد جاءكم يوسف من قبل» أي قبل موسى وهو يوسف بن يعقوب في قول، عمَّر إلى زمن موسى، أو يوسف بن إبراهيم بن يوسف بن يعقوب في قول «بالبينات» بالمعجزات الظاهرات «فما زلتم في شك مما جاءكم به حتى إذا هلك قلتم» من غير برهان «لن يبعث الله من بعده رسولا» أي فلن تزالوا كافرين بيوسف وغيره «كذلك» أي مثل إضلالكم «يضل الله من هو مسرف» مشرك «مرتاب» شاك فيما شهدت به البينات."},
  {'n': '35', 'v': "ٱلَّذِينَ يُجَٰدِلُونَ فِىٓ ءَايَٰتِ ٱللَّهِ بِغَيْرِ سُلْطَٰنٍ أَتَىٰهُمْ ۖ كَبُرَ مَقْتًا عِندَ ٱللَّهِ وَعِندَ ٱلَّذِينَ ءَامَنُوا۟ ۚ كَذَٰلِكَ يَطْبَعُ ٱللَّهُ عَلَىٰ كُلِّ قَلْبِ مُتَكَبِّرٍۢ جَبَّارٍۢ", 't': "«الذين يجادلون في آيات الله» معجزاته مبتدأ «بغير سلطان» برهان «أتاهم كَبُر» جدالهم خبر المبتدأ «مقتا عند الله وعند الذين آمنوا كذلك» مثل إضلالهم «يطبع» يختم «الله» بالضلال «على كل قلب متكبَّرِ جبار» بتنوين قلب ودونه، ومتى تكبَّر القلب، تكبَّر صاحبه وبالعكس، وكل على القراءتين لعموم الضلال جميع القلب لا لعموم القلب."},
  {'n': '36', 'v': "وَقَالَ فِرْعَوْنُ يَٰهَٰمَٰنُ ٱبْنِ لِى صَرْحًۭا لَّعَلِّىٓ أَبْلُغُ ٱلْأَسْبَٰبَ", 't': "«وقال فرعون يا هامان ابن لي صرحا» بناءً عاليا «لعلي أبلغ الأسباب»."},
  {'n': '37', 'v': "أَسْبَٰبَ ٱلسَّمَٰوَٰتِ فَأَطَّلِعَ إِلَىٰٓ إِلَٰهِ مُوسَىٰ وَإِنِّى لَأَظُنُّهُۥ كَٰذِبًۭا ۚ وَكَذَٰلِكَ زُيِّنَ لِفِرْعَوْنَ سُوٓءُ عَمَلِهِۦ وَصُدَّ عَنِ ٱلسَّبِيلِ ۚ وَمَا كَيْدُ فِرْعَوْنَ إِلَّا فِى تَبَابٍۢ", 't': "«أسباب السماوات» طرقها الموصولة إليها «فأطلع» بالرفع عطفا على أبلغ وبالنصب جوابا لابنِ «إلى إله موسى وإني لأظنه» أي موسى «كاذبا» في أن له إلها غيري قال فرعون ذلك تمويها «وكذلك زيَّن لفرعون سوء عمله وصدَّ عن السبيل» طريق الهدي بفتح الصاد وضمها «وما كيد فرعون إلا في تباب» خسار."},
  {'n': '38', 'v': "وَقَالَ ٱلَّذِىٓ ءَامَنَ يَٰقَوْمِ ٱتَّبِعُونِ أَهْدِكُمْ سَبِيلَ ٱلرَّشَادِ", 't': "«وقال الذي آمن يا قوم اتَّبعون» بإثبات الياء وحذفها «أهدكم سبيل الرشاد» تقدم."},
  {'n': '39', 'v': "يَٰقَوْمِ إِنَّمَا هَٰذِهِ ٱلْحَيَوٰةُ ٱلدُّنْيَا مَتَٰعٌۭ وَإِنَّ ٱلْءَاخِرَةَ هِىَ دَارُ ٱلْقَرَارِ", 't': "«يا قوم إنما هذه الحياة الدنيا متاع» تمتع يزول «وإن الآخرة هي دار القرار»."},
  {'n': '40', 'v': "مَنْ عَمِلَ سَيِّئَةًۭ فَلَا يُجْزَىٰٓ إِلَّا مِثْلَهَا ۖ وَمَنْ عَمِلَ صَٰلِحًۭا مِّن ذَكَرٍ أَوْ أُنثَىٰ وَهُوَ مُؤْمِنٌۭ فَأُو۟لَٰٓئِكَ يَدْخُلُونَ ٱلْجَنَّةَ يُرْزَقُونَ فِيهَا بِغَيْرِ حِسَابٍۢ", 't': "«من عمل سيئة فلا يُجزى إلا مثلها ومن عمل صالحا من ذكر أو أنثى وهو مؤمن فأولئك يدخلون الجنة» بضم الياء وفتح الخاء وبالعكس «يرزقون فيها بغير حساب» رزقا واسعا بلا تبعة."},
  {'n': '41', 'v': "۞ وَيَٰقَوْمِ مَا لِىٓ أَدْعُوكُمْ إِلَى ٱلنَّجَوٰةِ وَتَدْعُونَنِىٓ إِلَى ٱلنَّارِ", 't': "«ويا قوم مالي أدعوكم إلى النجاة وتدعونني إلى النار»."},
  {'n': '42', 'v': "تَدْعُونَنِى لِأَكْفُرَ بِٱللَّهِ وَأُشْرِكَ بِهِۦ مَا لَيْسَ لِى بِهِۦ عِلْمٌۭ وَأَنَا۠ أَدْعُوكُمْ إِلَى ٱلْعَزِيزِ ٱلْغَفَّٰرِ", 't': "«تدعونني لأكفر بالله وأشرك به ما ليس لي به علم وأنا أدعوكم إلى العزيز» الغالب على أمره «الغفار» لمن تاب."},
  {'n': '43', 'v': "لَا جَرَمَ أَنَّمَا تَدْعُونَنِىٓ إِلَيْهِ لَيْسَ لَهُۥ دَعْوَةٌۭ فِى ٱلدُّنْيَا وَلَا فِى ٱلْءَاخِرَةِ وَأَنَّ مَرَدَّنَآ إِلَى ٱللَّهِ وَأَنَّ ٱلْمُسْرِفِينَ هُمْ أَصْحَٰبُ ٱلنَّارِ", 't': "«لا جرم» حقا «أنما تدعونني إليه» لأعبده «ليس له دعوة» أي استجابة دعوة «في الدنيا ولا في الآخرة وأن مردنا» مرجعنا «إلى الله وأن المسرفين» الكافرين «هم أصحاب النار»."},
  {'n': '44', 'v': "فَسَتَذْكُرُونَ مَآ أَقُولُ لَكُمْ ۚ وَأُفَوِّضُ أَمْرِىٓ إِلَى ٱللَّهِ ۚ إِنَّ ٱللَّهَ بَصِيرٌۢ بِٱلْعِبَادِ", 't': "«فستذكرون» إذا عاينتم العذاب «ما أقول لكم وأفوض أمري إلى الله إن الله بصير بالعباد» قال ذلك لما توعدوه بمخالفة دينهم."},
  {'n': '45', 'v': "فَوَقَىٰهُ ٱللَّهُ سَيِّـَٔاتِ مَا مَكَرُوا۟ ۖ وَحَاقَ بِـَٔالِ فِرْعَوْنَ سُوٓءُ ٱلْعَذَابِ", 't': "«فوقاه الله سيئات ما مكروا» به من القتل «وحاق» نزل «بآل فرعون» قومه معه «سوء العذاب» الغرق."},
  {'n': '46', 'v': "ٱلنَّارُ يُعْرَضُونَ عَلَيْهَا غُدُوًّۭا وَعَشِيًّۭا ۖ وَيَوْمَ تَقُومُ ٱلسَّاعَةُ أَدْخِلُوٓا۟ ءَالَ فِرْعَوْنَ أَشَدَّ ٱلْعَذَابِ", 't': "ثم (النار يعرضون عليها) يحرقون بها «غدوا وعشيا» صباحا ومساءً «ويوم تقوم الساعة» يقال «ادخلُوا» يا «آل فرعون» وفي قراءة: بفتح الهمزة وكسر الخاء أمر للملائكة «أشد العذاب» عذاب جهنم."},
  {'n': '47', 'v': "وَإِذْ يَتَحَآجُّونَ فِى ٱلنَّارِ فَيَقُولُ ٱلضُّعَفَٰٓؤُا۟ لِلَّذِينَ ٱسْتَكْبَرُوٓا۟ إِنَّا كُنَّا لَكُمْ تَبَعًۭا فَهَلْ أَنتُم مُّغْنُونَ عَنَّا نَصِيبًۭا مِّنَ ٱلنَّارِ", 't': "«و» اذكر «إذ يتحاجون» يتخاصم الكفار «في النار فيقول الضعفاء للذين استكبروا إنا كنا لكم تبعا» جمع تابع «فهل أنتم مغنون» دافعون «عنا نصيبا» جزاءً «من النار»."},
  {'n': '48', 'v': "قَالَ ٱلَّذِينَ ٱسْتَكْبَرُوٓا۟ إِنَّا كُلٌّۭ فِيهَآ إِنَّ ٱللَّهَ قَدْ حَكَمَ بَيْنَ ٱلْعِبَادِ", 't': "«قال الذين استكبروا إنا كلَّ فيها إن الله قد حكم بين العباد» فأدخل المؤمنين الجنة والكافرين النار."},
  {'n': '49', 'v': "وَقَالَ ٱلَّذِينَ فِى ٱلنَّارِ لِخَزَنَةِ جَهَنَّمَ ٱدْعُوا۟ رَبَّكُمْ يُخَفِّفْ عَنَّا يَوْمًۭا مِّنَ ٱلْعَذَابِ", 't': "«وقال الذين في النار لخزنة جهنم ادعوا ربكم يخفف عنا يوما» أي قدر يوم «من العذاب»."},
  {'n': '50', 'v': "قَالُوٓا۟ أَوَلَمْ تَكُ تَأْتِيكُمْ رُسُلُكُم بِٱلْبَيِّنَٰتِ ۖ قَالُوا۟ بَلَىٰ ۚ قَالُوا۟ فَٱدْعُوا۟ ۗ وَمَا دُعَٰٓؤُا۟ ٱلْكَٰفِرِينَ إِلَّا فِى ضَلَٰلٍ", 't': "«قالوا» أي الخزنة تهكما «أوَ لم تك تأتيكم رسلكم بالبينات» بالمعجزات الظاهرات «قالوا بلى» أي فكفروا بهم «قالوا فادعوا» أنتم فإنا لا نشفع للكافرين، قال تعالى: «وما دعاءُ الكافرين إلا في ضلال» انعدام."},
  {'n': '51', 'v': "إِنَّا لَنَنصُرُ رُسُلَنَا وَٱلَّذِينَ ءَامَنُوا۟ فِى ٱلْحَيَوٰةِ ٱلدُّنْيَا وَيَوْمَ يَقُومُ ٱلْأَشْهَٰدُ", 't': "«إنا لننصر رسلنا والذين آمنوا في الحياة الدنيا ويوم يقوم الأشهاد» جمع شاهد، وهم الملائكة يشهدون للرسل بالبلاغ وعلى الكفار بالتكذيب."},
  {'n': '52', 'v': "يَوْمَ لَا يَنفَعُ ٱلظَّٰلِمِينَ مَعْذِرَتُهُمْ ۖ وَلَهُمُ ٱللَّعْنَةُ وَلَهُمْ سُوٓءُ ٱلدَّارِ", 't': "«يوم لا ينفع» بالياء والتاء «الظالمين معذرتهم» عذرهم لو اعتذروا «ولهم اللعنة» أي البعد من الرحمة «ولهم سوءُ الدار» الآخرة، أي شدة عذابها."},
  {'n': '53', 'v': "وَلَقَدْ ءَاتَيْنَا مُوسَى ٱلْهُدَىٰ وَأَوْرَثْنَا بَنِىٓ إِسْرَٰٓءِيلَ ٱلْكِتَٰبَ", 't': "«ولقد آتينا موسى الهدى» التوراة والمعجزات «وأورثنا بني إسرائيل» من بعد موسى «الكتاب» التوراة."},
  {'n': '54', 'v': "هُدًۭى وَذِكْرَىٰ لِأُو۟لِى ٱلْأَلْبَٰبِ", 't': "«هدىّ» هاديا «وذكرى لأولي الألباب» تذكرة لأصحاب العقول."},
  {'n': '55', 'v': "فَٱصْبِرْ إِنَّ وَعْدَ ٱللَّهِ حَقٌّۭ وَٱسْتَغْفِرْ لِذَنۢبِكَ وَسَبِّحْ بِحَمْدِ رَبِّكَ بِٱلْعَشِىِّ وَٱلْإِبْكَٰرِ", 't': "«فاصبر» يا محمد «إن وعد الله» بنصر أوليائه «حق» وأنت ومن تبعك منهم «واستغفر لذنبك» ليستن بك «وسبِّح» صل متلبساً «بحمد ربك بالعشي» وهو من بعد الزوال «والإبكار» الصلوات الخمس."},
  {'n': '56', 'v': "إِنَّ ٱلَّذِينَ يُجَٰدِلُونَ فِىٓ ءَايَٰتِ ٱللَّهِ بِغَيْرِ سُلْطَٰنٍ أَتَىٰهُمْ ۙ إِن فِى صُدُورِهِمْ إِلَّا كِبْرٌۭ مَّا هُم بِبَٰلِغِيهِ ۚ فَٱسْتَعِذْ بِٱللَّهِ ۖ إِنَّهُۥ هُوَ ٱلسَّمِيعُ ٱلْبَصِيرُ", 't': "«إن الذين يجادلون في آيات الله» القرآن «بغير سلطان» برهان «أتاهم إن» ما «في صدورهم إلا كبْر» تكبّر وطمع أن يعلوا عليك «ما هم ببالغيه فاستعذ» من شرِّهم «بالله إنه هو السميع» لأقوالهم «البصير» بأحوالهم، ونزل في منكري البعث."},
  {'n': '57', 'v': "لَخَلْقُ ٱلسَّمَٰوَٰتِ وَٱلْأَرْضِ أَكْبَرُ مِنْ خَلْقِ ٱلنَّاسِ وَلَٰكِنَّ أَكْثَرَ ٱلنَّاسِ لَا يَعْلَمُونَ", 't': "«لخلق السماوات والأرض» ابتداءً «أكبر من خلق الناس» مرة ثانية، وهي الإعادة «ولكن أكثر الناس» أي كفار مكة «لا يعلمون» ذلك فهم كالأعمى، ومن يعلمه كالبصير."},
  {'n': '58', 'v': "وَمَا يَسْتَوِى ٱلْأَعْمَىٰ وَٱلْبَصِيرُ وَٱلَّذِينَ ءَامَنُوا۟ وَعَمِلُوا۟ ٱلصَّٰلِحَٰتِ وَلَا ٱلْمُسِىٓءُ ۚ قَلِيلًۭا مَّا تَتَذَكَّرُونَ", 't': "«وما يستوي الأعمى والبصير و» لا «الذين آمنوا وعملوا الصالحات» وهو المحسن «ولا المسيء» فيه زيادة لا «قليلا ما يتذكرون» يتعظون بالياء والتاء، أي تذكرهم قليل جدا."},
  {'n': '59', 'v': "إِنَّ ٱلسَّاعَةَ لَءَاتِيَةٌۭ لَّا رَيْبَ فِيهَا وَلَٰكِنَّ أَكْثَرَ ٱلنَّاسِ لَا يُؤْمِنُونَ", 't': "«إن الساعة لآتية لا ريب» شك «فيها ولكن أكثر الناس لا يؤمنون» بها."},
  {'n': '60', 'v': "وَقَالَ رَبُّكُمُ ٱدْعُونِىٓ أَسْتَجِبْ لَكُمْ ۚ إِنَّ ٱلَّذِينَ يَسْتَكْبِرُونَ عَنْ عِبَادَتِى سَيَدْخُلُونَ جَهَنَّمَ دَاخِرِينَ", 't': "«وقال ربكم ادعوني أستجب لكم» أي اعبدوني أثبكم بقرينة ما بعده «إن الذين يستكبرون عن عبادتي سيدخلون» بفتح الياء وضم الخاء وبالعكس «جهنم داخرين» صاغرين."},
  {'n': '61', 'v': "ٱللَّهُ ٱلَّذِى جَعَلَ لَكُمُ ٱلَّيْلَ لِتَسْكُنُوا۟ فِيهِ وَٱلنَّهَارَ مُبْصِرًا ۚ إِنَّ ٱللَّهَ لَذُو فَضْلٍ عَلَى ٱلنَّاسِ وَلَٰكِنَّ أَكْثَرَ ٱلنَّاسِ لَا يَشْكُرُونَ", 't': "«الله الذي جعل لكم الليل لتسكنوا فيه والنهار مبصرا» إسناد الإبصار إليه مجازيّ لأنه يبصر فيه «إن الله لذو فضل على الناس ولكن أكثر الناس لا يشكرون» الله فلا يؤمنون."},
  {'n': '62', 'v': "ذَٰلِكُمُ ٱللَّهُ رَبُّكُمْ خَٰلِقُ كُلِّ شَىْءٍۢ لَّآ إِلَٰهَ إِلَّا هُوَ ۖ فَأَنَّىٰ تُؤْفَكُونَ", 't': "«ذلكم الله ربكم خالق كل شيء لا إله إلا هوَ فأنّى تؤفكون» فكيف تصرفون عن الإيمان مع قيام البرهان."},
