  {'n': '20', 'v': "وَعَدَكُمُ ٱللَّهُ مَغَانِمَ كَثِيرَةًۭ تَأْخُذُونَهَا فَعَجَّلَ لَكُمْ هَٰذِهِۦ وَكَفَّ أَيْدِىَ ٱلنَّاسِ عَنكُمْ وَلِتَكُونَ ءَايَةًۭ لِّلْمُؤْمِنِينَ وَيَهْدِيَكُمْ صِرَٰطًۭا مُّسْتَقِيمًۭا", 't': "«وعدكم الله مغانم كثيرة تأخذونها» من الفتوحات «فعجَّل لكم هذه» غنيمة خيبر «وكفَّ أيدي الناس عنكم» في عيالكم لما خرجتم وهمت بهم اليهود فقذف الله في قلوبهم الرعب «ولتكون» أي المعجلة عطف على مقدر، أي لتشكروه «آية للمؤمنين» في نصرهم «ويهديكم صراطا مستقيما» أي طريق التوكل عليه وتفويض الأمر إليه تعالى."},
  {'n': '21', 'v': "وَأُخْرَىٰ لَمْ تَقْدِرُوا۟ عَلَيْهَا قَدْ أَحَاطَ ٱللَّهُ بِهَا ۚ وَكَانَ ٱللَّهُ عَلَىٰ كُلِّ شَىْءٍۢ قَدِيرًۭا", 't': "«وأخرى» صفة مغانم مقدرا مبتدأ «لم تقدروا عليها» هي من فارس والروم «قد أحاط الله بها» علم أنها ستكون لكم «وكان الله على كل شيء قديرا» أي لم يزل متصفا بذلك."},
  {'n': '22', 'v': "وَلَوْ قَٰتَلَكُمُ ٱلَّذِينَ كَفَرُوا۟ لَوَلَّوُا۟ ٱلْأَدْبَٰرَ ثُمَّ لَا يَجِدُونَ وَلِيًّۭا وَلَا نَصِيرًۭا", 't': "«ولو قاتلكم الذين كفروا» بالحديبية «لولّوا الأدبار ثم لا يجدون وليا» يحرسهم «ولا نصيرا»."},
  {'n': '23', 'v': "سُنَّةَ ٱللَّهِ ٱلَّتِى قَدْ خَلَتْ مِن قَبْلُ ۖ وَلَن تَجِدَ لِسُنَّةِ ٱللَّهِ تَبْدِيلًۭا", 't': "«سنة الله» مصدر مؤكد لمضمون الجملة قبله من هزيمة الكافرين ونصر المؤمنين، أي سَنَّ الله ذلك سُنَّة «التي قد خلت من قبل ولن تجد لسنة الله تبديلا» منه."},
  {'n': '24', 'v': "وَهُوَ ٱلَّذِى كَفَّ أَيْدِيَهُمْ عَنكُمْ وَأَيْدِيَكُمْ عَنْهُم بِبَطْنِ مَكَّةَ مِنۢ بَعْدِ أَنْ أَظْفَرَكُمْ عَلَيْهِمْ ۚ وَكَانَ ٱللَّهُ بِمَا تَعْمَلُونَ بَصِيرًا", 't': "«وهو الذي كف أيديهم عنكم وأيديكم عنهم ببطن مكة» بالحديبية «من بعد أن أظفركم عليهم» فإن ثمانين منهم طافوا بعسكركم ليصيبوا منكم فأخذوا وأتي بهم إلى رسول الله صلى الله عليه وسلم فعفا عنهم وخلى سبيلهم فكان ذلك سبب الصلح «وكان الله بما يعملون بصيرا» بالياء والتاء، أي لم يزل متصفا بذلك."},
  {'n': '25', 'v': "هُمُ ٱلَّذِينَ كَفَرُوا۟ وَصَدُّوكُمْ عَنِ ٱلْمَسْجِدِ ٱلْحَرَامِ وَٱلْهَدْىَ مَعْكُوفًا أَن يَبْلُغَ مَحِلَّهُۥ ۚ وَلَوْلَا رِجَالٌۭ مُّؤْمِنُونَ وَنِسَآءٌۭ مُّؤْمِنَٰتٌۭ لَّمْ تَعْلَمُوهُمْ أَن تَطَـُٔوهُمْ فَتُصِيبَكُم مِّنْهُم مَّعَرَّةٌۢ بِغَيْرِ عِلْمٍۢ ۖ لِّيُدْخِلَ ٱللَّهُ فِى رَحْمَتِهِۦ مَن يَشَآءُ ۚ لَوْ تَزَيَّلُوا۟ لَعَذَّبْنَا ٱلَّذِينَ كَفَرُوا۟ مِنْهُمْ عَذَابًا أَلِيمًا", 't': "«هم الذين كفروا وصدوكم عن المسجد الحرام» أي عن الوصول إليه «والهدي» معطوف على كم «معكوفا» محبوسا حال «أن يبلغ محله» أي مكانه الذي ينحر فيه عادة وهو الحرم بدل اشتمال «ولولا رجال مؤمنون ونساء مؤمنات» موجودون بمكة مع الكفار «لم تعلموهم» بصفة الإيمان «أن تطئوهم» أي تقتلوهم مع الكفار لو أذن لكم في الفتح بدل اشتمال من هم «فتصيبكم منهم معرة» أي إثم «بغير علم» منكم به وضمائر الغيبة للصنفين بتغليب الذكور، وجواب لولا محذوف، أي لأذن لكم في الفتح لكن لم يؤذن فيه حينئذ «ليدخل الله في رحمته من يشاء» كالمؤمنين المذكورين «لو تزيَّلوا» تميزوا عن الكفار «لعذَّبنا الذين كفروا منهم» من أهل مكة حينئذ بأن نأذن لكم في فتحها «عذابا أليما» مؤلما."},
  {'n': '26', 'v': "إِذْ جَعَلَ ٱلَّذِينَ كَفَرُوا۟ فِى قُلُوبِهِمُ ٱلْحَمِيَّةَ حَمِيَّةَ ٱلْجَٰهِلِيَّةِ فَأَنزَلَ ٱللَّهُ سَكِينَتَهُۥ عَلَىٰ رَسُولِهِۦ وَعَلَى ٱلْمُؤْمِنِينَ وَأَلْزَمَهُمْ كَلِمَةَ ٱلتَّقْوَىٰ وَكَانُوٓا۟ أَحَقَّ بِهَا وَأَهْلَهَا ۚ وَكَانَ ٱللَّهُ بِكُلِّ شَىْءٍ عَلِيمًۭا", 't': "«إذ جعل» متعلق بعذبنا «الذين كفروا» فاعل «في قلوبهم الحمية» الأنفة من الشيء «حمية الجاهلية» بدل من الحمية وهي صدهم النبي وأصحابه عن المسجد الحرام «فأنزل الله سكينته على رسول وعلى المؤمنين» فصالحوهم على أن يعودوا من قابل ولم يلحقهم من الحمية ما لحق الكفار حتى يقاتلوهم «وألزمهم» أي المؤمنين «كلمة التقوى» لا إله إلا الله محمد رسول الله وأضيفت إلى التقوى لأنها سببها «وكانوا أحق بها» بالكلمة من الكفار «وأهلها» عطف تفسيري «وكان الله بكل شيء عليما» أي لم يزل منصفا بذلك ومن معلومة تعالى أنهم أهلها."},
  {'n': '27', 'v': "لَّقَدْ صَدَقَ ٱللَّهُ رَسُولَهُ ٱلرُّءْيَا بِٱلْحَقِّ ۖ لَتَدْخُلُنَّ ٱلْمَسْجِدَ ٱلْحَرَامَ إِن شَآءَ ٱللَّهُ ءَامِنِينَ مُحَلِّقِينَ رُءُوسَكُمْ وَمُقَصِّرِينَ لَا تَخَافُونَ ۖ فَعَلِمَ مَا لَمْ تَعْلَمُوا۟ فَجَعَلَ مِن دُونِ ذَٰلِكَ فَتْحًۭا قَرِيبًا", 't': "«لقد صدق الله رسوله الرؤيا بالحقِّ» رأى رسول الله صلى الله عليه وسلم في النوم عام الحديبية قبل خروجه أنه يدخل مكة هو وأصحابه آمنين ويحلقون ويقصرون فأخبر بذلك أصحابه ففرحوا فلما خرجوا معه وصدهم الكفار بالحديبية ورجعوا وشق عليهم ذلك وراب بعض المنافقين نزلت، وقوله بالحق متعلق بصدق أو حال من الرؤيا وما بعدها تفسيرها «لتدخلنِّ المسجد الحرام إنْ شاء الله» للتبرك «آمنين محلقين رءوسكم» أي جميع شعورها «ومقصرين» بعض شعورها وهما حالان مقدرتان «لا تخافون» أبدا «فعلم» في الصلح «ما لم تعلموا» من الصلاح «فجعل من دون ذلك» أي الدخول «فتحا قريبا» هو فتح خيبر وتحققت الرؤيا في العام القابل."},
  {'n': '28', 'v': "هُوَ ٱلَّذِىٓ أَرْسَلَ رَسُولَهُۥ بِٱلْهُدَىٰ وَدِينِ ٱلْحَقِّ لِيُظْهِرَهُۥ عَلَى ٱلدِّينِ كُلِّهِۦ ۚ وَكَفَىٰ بِٱللَّهِ شَهِيدًۭا", 't': "«هو الذي أرسل رسوله بالهدى ودين الحقّ ليظهره» أي دين الحق «على الدين كله» على جميع باقي الأديان «وكفى بالله شهيدا» أنك مرسل بما ذكر كما قال الله تعالى."},
  {'n': '29', 'v': "مُّحَمَّدٌۭ رَّسُولُ ٱللَّهِ ۚ وَٱلَّذِينَ مَعَهُۥٓ أَشِدَّآءُ عَلَى ٱلْكُفَّارِ رُحَمَآءُ بَيْنَهُمْ ۖ تَرَىٰهُمْ رُكَّعًۭا سُجَّدًۭا يَبْتَغُونَ فَضْلًۭا مِّنَ ٱللَّهِ وَرِضْوَٰنًۭا ۖ سِيمَاهُمْ فِى وُجُوهِهِم مِّنْ أَثَرِ ٱلسُّجُودِ ۚ ذَٰلِكَ مَثَلُهُمْ فِى ٱلتَّوْرَىٰةِ ۚ وَمَثَلُهُمْ فِى ٱلْإِنجِيلِ كَزَرْعٍ أَخْرَجَ شَطْـَٔهُۥ فَـَٔازَرَهُۥ فَٱسْتَغْلَظَ فَٱسْتَوَىٰ عَلَىٰ سُوقِهِۦ يُعْجِبُ ٱلزُّرَّاعَ لِيَغِيظَ بِهِمُ ٱلْكُفَّارَ ۗ وَعَدَ ٱللَّهُ ٱلَّذِينَ ءَامَنُوا۟ وَعَمِلُوا۟ ٱلصَّٰلِحَٰتِ مِنْهُم مَّغْفِرَةًۭ وَأَجْرًا عَظِيمًۢا", 't': "«محمد» مبتدأ «رسول الله» خبره والذين معه» أي أصحابه من المؤمنين مبتدأ خبره «أشداء» غلاظ «على الكفار» لا يرحمونهم «رحماء بينهم» خبر ثان، أي متعاطفون متوادون كالوالد مع الولد «تراهم» تبصرهم «ركعا سجدا» حالان «يبتغون» مستأنف يطلبون «فضلا من الله ورضوانا سيماهم» علامتهم مبتدأ «في وجوههم» خبره وهو نور وبياض يُعرفون به في الآخرة أنهم سجدوا في الدنيا «من أثر السجود» متعلق بما تعلق به الخبر، أي كائنة وأعرب حالا من ضميره المنتقل إلى الخبر «ذلك» الوصف المذكور «مثلهم» صفتهم مبتدأ «في التوراة» خبره «ومثلهم في الإنجيل» مبتدأ خبره «كزرع أخرج شطأه» بسكون الطاء وفتحها: فراخه «فآزره» بالمد والقصر قواه وأعانه «فاستغلظ» غلظ «فاستوى» قوي واستقام «على سوقه» أصوله جمع ساق «يعجب الزراع» أي زرَّاعه لحسنه، مثل الصحابة رضي الله عنهم بذلك لأنهم بدأوا في قلة وضعف فكثروا وقووا على أحسن الوجوه «ليغيظ بهم الكفار» متعلق بمحذوف دل عليه ما قبله، أي شبهوا بذلك «وعد الله الذين آمنوا وعملوا الصالحات منهم» الصحابة ومن لبيان الجنس لا للتبعيض لأنهم كلهم بالصفة المذكورة «مغفرة وأجرا عظيما» الجنة وهما لمن بعدهم أيضا في آيات."},
